INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (1, 1, 'בְּאוּלְפָּן', 'В ульпане', 'שָׁלוֹם! אֲנִי דָּנִי. אֲנִי לוֹמֵד עִבְרִית בְּאוּלְפָּן. הַמּוֹרָה שֶׁלָּנוּ שְׁמָהּ רוּת. הִיא מְדַבֶּרֶת עִבְרִית וְאַנְגְלִית. בַּכִּתָּה יֵשׁ עֲשָׂרָה תַּלְמִידִים. אֲנַחְנוּ לוֹמְדִים מִלִּים חֲדָשׁוֹת כָּל יוֹם. אֲנִי אוֹהֵב לִלְמֹד עִבְרִית!', 'Привет! Я Дэни. Я учу иврит в ульпане. Нашу учительницу зовут Рут. Она говорит на иврите и английском. В классе десять учеников. Мы учим новые слова каждый день. Я люблю учить иврит!', '[{"he": "אוּלְפָּן", "ru": "ульпан (школа иврита)", "translit": "ульпАн"}, {"he": "מוֹרָה", "ru": "учительница", "translit": "морА"}, {"he": "כִּתָּה", "ru": "класс", "translit": "китА"}, {"he": "תַּלְמִידִים", "ru": "ученики", "translit": "талмидИм"}, {"he": "מִלִּים", "ru": "слова", "translit": "милИм"}, {"he": "חֲדָשׁוֹת", "ru": "новые (ж.р.)", "translit": "хадашОт"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (2, 1, 'הַמִּשְׁפָּחָה', 'Семья', 'יֵשׁ לִי מִשְׁפָּחָה גְּדוֹלָה. אַבָּא שֶׁלִּי רוֹפֵא וְאִמָּא שֶׁלִּי מוֹרָה. יֵשׁ לִי אָח גָּדוֹל וְאָחוֹת קְטַנָּה. הָאָח שֶׁלִּי סְטוּדֶנְט בָּאוּנִיבֶרְסִיטָה. הָאָחוֹת שֶׁלִּי לוֹמֶדֶת בְּבֵית סֵפֶר. אֲנַחְנוּ גָּרִים בְּתֵל אָבִיב.', 'У меня большая семья. Мой папа — врач, а мама — учительница. У меня есть старший брат и младшая сестра. Мой брат — студент в университете. Моя сестра учится в школе. Мы живём в Тель-Авиве.', '[{"he": "מִשְׁפָּחָה", "ru": "семья", "translit": "мишпахА"}, {"he": "אַבָּא", "ru": "папа", "translit": "Абба"}, {"he": "אִמָּא", "ru": "мама", "translit": "Имма"}, {"he": "אָח", "ru": "брат", "translit": "ах"}, {"he": "אָחוֹת", "ru": "сестра", "translit": "ахОт"}, {"he": "רוֹפֵא", "ru": "врач", "translit": "рофЕ"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (3, 1, 'בַּשּׁוּק', 'На рынке', 'הַיּוֹם אֲנִי הוֹלֵךְ לַשּׁוּק. אֲנִי קוֹנֶה יְרָקוֹת וּפֵרוֹת. עַגְבָנִיּוֹת, מְלַפְפוֹנִים, תַּפּוּחִים וּתְפוּזִים. הַמּוֹכֵר אוֹמֵר: "הַכֹּל טָרִי!" אֲנִי מְשַׁלֵּם וְהוֹלֵךְ הַבַּיְתָה.', 'Сегодня я иду на рынок. Я покупаю овощи и фрукты. Помидоры, огурцы, яблоки и апельсины. Продавец говорит: «Всё свежее!» Я плачу и иду домой.', '[{"he": "שׁוּק", "ru": "рынок", "translit": "шук"}, {"he": "יְרָקוֹת", "ru": "овощи", "translit": "еракОт"}, {"he": "פֵּרוֹת", "ru": "фрукты", "translit": "перОт"}, {"he": "מוֹכֵר", "ru": "продавец", "translit": "мохЕр"}, {"he": "טָרִי", "ru": "свежий", "translit": "тарИ"}]', NULL, 'dialog');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (4, 2, 'בַּחֲנוּת', 'В магазине', 'רוּת נִכְנְסָה לַחֲנוּת. הִיא רָצְתָה לִקְנוֹת לֶחֶם וְחָלָב. הִיא שָׁאֲלָה אֶת הַמּוֹכֵר: "סְלִיחָה, אֵיפֹה הַלֶּחֶם?" הַמּוֹכֵר עָנָה: "בַּמַּדָּף הַשְּׁלִישִׁי מִיָּמִין." רוּת מָצְאָה אֶת הַלֶּחֶם, לָקְחָה גַּם חָלָב וְגְבִינָה, וְהָלְכָה לַקֻּפָּה. הִיא שִׁלְּמָה וְיָצְאָה מֵהַחֲנוּת.', 'Рут зашла в магазин. Она хотела купить хлеб и молоко. Она спросила продавца: «Извините, где хлеб?» Продавец ответил: «На третьей полке справа.» Рут нашла хлеб, взяла также молоко и сыр, и пошла к кассе. Она заплатила и вышла из магазина.', '[{"he": "חֲנוּת", "ru": "магазин", "translit": "ханУт"}, {"he": "לֶחֶם", "ru": "хлеб", "translit": "лЕхем"}, {"he": "חָלָב", "ru": "молоко", "translit": "халАв"}, {"he": "מַדָּף", "ru": "полка", "translit": "мадАф"}, {"he": "קֻפָּה", "ru": "касса", "translit": "купА"}]', NULL, 'dialog');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (5, 2, 'הַמִּשְׁפָּחָה שֶׁלִּי', 'Моя семья', 'שְׁמִי יוֹסֵף וַאֲנִי בֶּן שְׁלוֹשִׁים. אֲנִי גָּר בִּירוּשָׁלַיִם עִם הַמִּשְׁפָּחָה שֶׁלִּי. אִשְׁתִּי שְׁמָהּ מִיכַל וְהִיא עוֹבֶדֶת כְּעוֹרֶכֶת דִּין. יֵשׁ לָנוּ שְׁנֵי יְלָדִים: בֵּן בֶּן שֵׁשׁ וּבַת בַּת שָׁלוֹשׁ. בְּסוֹפֵי שָׁבוּעַ אֲנַחְנוּ אוֹהֲבִים לָלֶכֶת לַפַּארְק אוֹ לְבַקֵּר אֶת הַסַּבָּא וְהַסָּבְתָא.', 'Меня зовут Йосеф, мне тридцать лет. Я живу в Иерусалиме со своей семьёй. Мою жену зовут Михаль, она работает адвокатом. У нас двое детей: сын шести лет и дочь трёх лет. По выходным мы любим ходить в парк или навещать дедушку и бабушку.', '[{"he": "אִשְׁתִּי", "ru": "моя жена", "translit": "иштИ"}, {"he": "עוֹרֶכֶת דִּין", "ru": "адвокат (ж.р.)", "translit": "орЕхет дин"}, {"he": "סוֹפֵי שָׁבוּעַ", "ru": "выходные", "translit": "софЕй шавУа"}, {"he": "סַבָּא", "ru": "дедушка", "translit": "сАба"}, {"he": "סָבְתָא", "ru": "бабушка", "translit": "сАвта"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (93, 3, 'שירות צבאי בישראל', 'Служба в армии', 'בישראל כל צעיר וצעירה חייבים לשרת בצבא. הגברים משרתים שלוש שנים והנשים שנתיים. השירות מתחיל בגיל שמונה עשרה, מיד אחרי התיכון. יש אנשים שמקבלים פטור מסיבות רפואיות או דתיות.
בתחילת השירות כל חייל עובר טירונות שבה לומדים את הבסיס של החיים הצבאיים. אחרי הטירונות כל חייל נשלח ליחידה שלו. יש יחידות קרביות, מודיעין וטכנולוגיה. חיילים רבים רוצים להגיע ליחידות עילית כי זה יתרון בחיים האזרחיים.
השירות הצבאי משפיע מאוד על החברה. חברויות שנוצרות בצבא נשמרות שנים רבות. אנשים אומרים שהצבא לימד אותם אחריות ועבודת צוות. מצד שני, יש ביקורת על השנים שהולכות לאיבוד.', 'В Израиле каждый юноша и каждая девушка обязаны служить в армии. Мужчины служат три года, а женщины — два. Служба начинается в восемнадцать лет, сразу после окончания школы. Некоторые люди получают освобождение по медицинским, религиозным или другим причинам.
В начале службы каждый солдат проходит курс молодого бойца — период в несколько недель, когда изучают основы армейской жизни. После этого каждый солдат направляется в своё подразделение. Есть боевые, разведывательные, технологические и вспомогательные подразделения. Многие солдаты хотят попасть в элитные подразделения, потому что это считается большим преимуществом в гражданской жизни.
Военная служба сильно влияет на израильское общество. Дружба, завязавшаяся в армии, сохраняется долгие годы. Многие говорят, что армия научила их ответственности, командной работе и умению справляться с трудными ситуациями. С другой стороны, есть критика за потерянные годы.', '[{"he": "שירות צבאי", "ru": "военная служба", "translit": "шерУт цваИ"}, {"he": "טירונות", "ru": "курс молодого бойца", "translit": "тиронУт"}, {"he": "חייל", "ru": "солдат", "translit": "хаяль"}, {"he": "יחידה", "ru": "подразделение", "translit": "йехидА"}, {"he": "פטור", "ru": "освобождение", "translit": "патУр"}, {"he": "קרבי", "ru": "боевой", "translit": "кравИ"}, {"he": "מודיעין", "ru": "разведка", "translit": "модиИн"}, {"he": "עבודת צוות", "ru": "командная работа", "translit": "аводАт цЕвет"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (6, 3, 'טיול בגליל', 'Путешествие по Галилее', 'בקיץ האחרון נסעתי לטיול בצפון הארץ. התחלנו בטבריה, עיר קטנה על שפת הכינרת. הכינרת היא האגם הכי גדול בישראל. המים היו כחולים ונקיים. אחרי יום בטבריה, נסענו לצפת. צפת היא עיר עתיקה על הר גבוה. שם יש גלריות אמנות ובתי כנסת ישנים מאוד. האוויר בצפת קריר ונעים. ביום האחרון ביקרנו ברמת הגולן. ראינו נופים מדהימים וכרמי יין. הטיול הזה היה חוויה נהדרת. אני ממליץ לכל מי שרוצה להכיר את ישראל.', 'Прошлым летом я поехал в путешествие по северу страны. Начали в Тверии — маленьком городе на берегу Кинерета. Кинерет — самое большое озеро в Израиле. Вода была голубой и чистой. После дня в Тверии мы поехали в Цфат. Цфат — древний город на высокой горе. Там есть художественные галереи и очень старые синагоги. Воздух в Цфате прохладный и приятный. В последний день мы посетили Голанские высоты. Видели потрясающие пейзажи и виноградники. Это путешествие было замечательным опытом. Рекомендую всем, кто хочет узнать Израиль.', '[{"he": "טיול", "ru": "путешествие", "translit": "тиУль"}, {"he": "כינרת", "ru": "Кинерет (озеро)", "translit": "кинЕрет"}, {"he": "עתיקה", "ru": "древняя", "translit": "атикА"}, {"he": "נופים", "ru": "пейзажи", "translit": "нофИм"}, {"he": "חוויה", "ru": "переживание/опыт", "translit": "хавайА"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (7, 3, 'באוניברסיטה', 'В университете', 'שמי נטלי ואני סטודנטית באוניברסיטה העברית בירושלים. אני לומדת מדעי המחשב. הלימודים קשים אבל מעניינים מאוד. בכל יום יש לי הרצאות ותרגולים. הפרופסורים שלנו מומחים בתחומם. יש גם פרויקטים קבוצתיים שדורשים עבודת צוות. אני גרה במעונות הסטודנטים עם שתי שותפות. אחת מהן מברזיל והשנייה מצרפת. אנחנו מדברות עברית ביחד כי זו השפה המשותפת שלנו. אחרי הלימודים אני רוצה לעבוד בחברת הייטק בתל אביב.', 'Меня зовут Натали, я студентка Еврейского университета в Иерусалиме. Я изучаю компьютерные науки. Учёба трудная, но очень интересная. Каждый день у меня лекции и практические занятия. Наши профессора — эксперты в своих областях. Есть также групповые проекты, требующие командной работы. Я живу в студенческом общежитии с двумя соседками. Одна из Бразилии, вторая из Франции. Мы говорим на иврите, потому что это наш общий язык. После учёбы я хочу работать в хайтек-компании в Тель-Авиве.', '[{"he": "אוניברסיטה", "ru": "университет", "translit": "университА"}, {"he": "הרצאות", "ru": "лекции", "translit": "hарцаОт"}, {"he": "מומחים", "ru": "эксперты", "translit": "мумхИм"}, {"he": "מעונות", "ru": "общежития", "translit": "меонОт"}, {"he": "הייטק", "ru": "хай-тек", "translit": "hАйтек"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (8, 4, 'אומת הסטארט-אפ', 'Нация стартапов', 'ישראל ידועה בשם ''אומת הסטארט-אפ''. למרות שהיא מדינה קטנה עם פחות מעשרה מיליון תושבים, יש בה יותר חברות סטארט-אפ לנפש מבכל מדינה אחרת בעולם. הסיבות להצלחה הטכנולוגית של ישראל מגוונות. ראשית, צה"ל משמש כמעבדה טכנולוגית: יחידות כמו 8200 מכשירות צעירים בתחומי הסייבר והטכנולוגיה. שנית, התרבות הישראלית מעודדת חדשנות וחוצפה — אין פחד מכישלון. שלישית, הממשלה משקיעה רבות במחקר ופיתוח. כיום חברות ישראליות רבות נרכשות על ידי חברות ענק בינלאומיות, ותל אביב נחשבת למרכז טכנולוגי מוביל בעולם.', 'Израиль известен как ''нация стартапов''. Несмотря на то что это маленькая страна с населением менее 10 миллионов, в ней больше стартапов на душу населения, чем в любой другой стране мира. Причины технологического успеха Израиля разнообразны. Во-первых, ЦАХАЛ служит технологической лабораторией: подразделения вроде 8200 готовят молодёжь в сфере кибербезопасности и технологий. Во-вторых, израильская культура поощряет инновации и дерзость — нет страха перед неудачей. В-третьих, правительство много инвестирует в исследования и разработки. Сегодня многие израильские компании приобретаются международными гигантами, а Тель-Авив считается ведущим технологическим центром мира.', '[{"he": "סטארט-אפ", "ru": "стартап", "translit": "стАрт-ап"}, {"he": "חדשנות", "ru": "инновации", "translit": "хадшанУт"}, {"he": "חוצפה", "ru": "дерзость/наглость", "translit": "хуцпА"}, {"he": "מחקר ופיתוח", "ru": "исследования и разработки", "translit": "мехкАр уфитУах"}, {"he": "נרכשות", "ru": "приобретаются", "translit": "нирхасОт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (9, 4, 'מערכת המשפט בישראל', 'Судебная система Израиля', 'מערכת המשפט בישראל מבוססת על שלושה דרגות. בית המשפט העליון, הנקרא גם בג"ץ, הוא הגוף השיפוטי העליון במדינה. הוא דן בעתירות נגד החלטות ממשלתיות ובערעורים. בדרגה האמצעית נמצאים בתי המשפט המחוזיים, הדנים בתיקים פליליים ואזרחיים מורכבים. בית משפט השלום, בדרגה הנמוכה ביותר, מטפל בתיקים יומיומיים. שופטי בית המשפט העליון ממונים על ידי ועדה מיוחדת הכוללת שופטים, פוליטיקאים ונציגי לשכת עורכי הדין. מערכת המשפט הישראלית נחשבת לעצמאית ובלתי תלויה.', 'Судебная система Израиля основана на трёх уровнях. Верховный суд, называемый также БАГАЦ, является высшим судебным органом страны. Он рассматривает петиции против правительственных решений и апелляции. На среднем уровне находятся окружные суды, рассматривающие сложные уголовные и гражданские дела. Мировой суд, на нижнем уровне, занимается повседневными делами. Судьи Верховного суда назначаются специальной комиссией, включающей судей, политиков и представителей коллегии адвокатов. Израильская судебная система считается независимой и самостоятельной.', '[{"he": "בית המשפט העליון", "ru": "Верховный суд", "translit": "бейт hа-мишпАт hа-эльйОн"}, {"he": "עתירות", "ru": "петиции", "translit": "атирОт"}, {"he": "ערעורים", "ru": "апелляции", "translit": "ирурИм"}, {"he": "שופט", "ru": "судья", "translit": "шофЕт"}, {"he": "עצמאית", "ru": "независимая", "translit": "ацмаИт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (10, 5, 'קטע מתוך ''סיפור פשוט'' של ש"י עגנון', 'Отрывок: ''Простая история'' Агнона', 'הירשל הורוויץ היה בחור שקט ומתון. הוא גדל בעיירה קטנה בגליציה, בין הרים ויערות. אביו היה סוחר מכובד, ואמו אישה חכמה וטובת לב. הירשל אהב לקרוא ספרים ולחלום על עולמות רחוקים. כשמלאו לו שמונה עשרה, שלחו אותו ההורים ללמוד בעיר הגדולה. העיר הייתה שונה מכל מה שהכיר. רחובות רחבים, חנויות גדולות, ואנשים ממהרים לכל הכיוונים. הירשל הרגיש בודד, אבל ידע שזו ההזדמנות שלו.', 'Хиршл Горовиц был тихим и сдержанным юношей. Он вырос в маленьком местечке в Галиции, среди гор и лесов. Его отец был уважаемым торговцем, а мать — умной и доброй женщиной. Хиршл любил читать книги и мечтать о далёких мирах. Когда ему исполнилось восемнадцать, родители отправили его учиться в большой город. Город был не похож ни на что из того, что он знал. Широкие улицы, большие магазины и люди, спешащие во все стороны. Хиршл чувствовал себя одиноким, но знал, что это его шанс.', '[{"he": "מתון", "ru": "сдержанный", "translit": "матУн"}, {"he": "סוחר", "ru": "торговец", "translit": "сохЕр"}, {"he": "מכובד", "ru": "уважаемый", "translit": "мехубАд"}, {"he": "ההזדמנות", "ru": "возможность", "translit": "hа-hиздамнУт"}, {"he": "בודד", "ru": "одинокий", "translit": "бодЕд"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (11, 6, 'כתבה: עליית מחירי הדיור בישראל', 'Статья: Рост цен на жильё в Израиле', 'מחירי הדיור בישראל ממשיכים לעלות בקצב מדאיג. על פי נתוני הלשכה המרכזית לסטטיסטיקה, מחירי הדירות עלו בכעשרה אחוזים בשנה האחרונה. מומחים בתחום הנדל"ן מצביעים על מספר גורמים: מחסור בקרקעות זמינות לבנייה, ביורוקרטיה מסורבלת בתהליכי התכנון, וביקוש גובר מצד זוגות צעירים ומשקיעים. הממשלה הכריזה על תוכניות שונות להתמודדות עם המשבר, כולל בניית ערים חדשות בנגב ובגליל, מתן הטבות מס לרוכשי דירה ראשונה, וקידום פרויקטים של התחדשות עירונית. עם זאת, מבקרים טוענים כי הצעדים אינם מספיקים וכי נדרשת רפורמה מקיפה במדיניות הדיור.', 'Цены на жильё в Израиле продолжают расти тревожными темпами. По данным Центрального бюро статистики, цены на квартиры выросли примерно на десять процентов за последний год. Эксперты в области недвижимости указывают на несколько факторов: нехватка доступных для застройки земель, громоздкая бюрократия в процессах планирования и растущий спрос со стороны молодых пар и инвесторов. Правительство объявило о различных планах борьбы с кризисом, включая строительство новых городов в Негеве и Галилее, предоставление налоговых льгот покупателям первого жилья и продвижение проектов городского обновления. Тем не менее, критики утверждают, что принятых мер недостаточно и что необходима комплексная реформа жилищной политики.', '[{"he": "דיור", "ru": "жильё", "translit": "диюр"}, {"he": "נדל\"ן", "ru": "недвижимость", "translit": "надлАн"}, {"he": "מחסור", "ru": "нехватка", "translit": "махсОр"}, {"he": "רפורמה", "ru": "реформа", "translit": "рефОрма"}, {"he": "התחדשות עירונית", "ru": "городское обновление", "translit": "hитхадшУт иронИт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (12, 3, 'בריאות בישראל', 'Здоровье в Израиле: как устроена система', 'מערכת הבריאות בישראל היא אחת הטובות בעולם. כל תושב ישראל חייב להיות חבר באחת מארבע קופות החולים: כללית, מכבי, מאוחדת או לאומית.
כשאתה חולה, אתה הולך לקופת החולים שלך. שם יש רופא משפחה שמכיר אותך ואת ההיסטוריה הרפואית שלך. הרופא בודק אותך, ואם צריך — נותן מרשם לתרופות. את התרופות קונים בבית מרקחת.
אם צריך רופא מומחה — למשל, רופא עיניים או רופא עור — רופא המשפחה נותן הפניה. לפעמים צריך לחכות כמה שבועות לתור אצל מומחה. אפשר לבדוק תורים באפליקציה של קופת החולים.
במקרה חירום אפשר לנסוע לחדר מיון בבית החולים. חשוב לדעת: ביקור בחדר מיון עולה כסף, אלא אם יש הפניה מרופא או שמדובר במצב מסכן חיים.
כל חודש חלק מהמשכורת הולך לביטוח בריאות — זה נקרא "מס בריאות". בזכות המס הזה כל תושבי ישראל מקבלים שירותי בריאות בסיסיים.', 'Система здравоохранения в Израиле — одна из лучших в мире. Каждый житель обязан быть членом одной из четырёх больничных касс: Клалит, Маккаби, Меухедет или Леумит.
Когда вы болеете, вы идёте в свою больничную кассу. Там есть семейный врач, который знает вас и вашу медицинскую историю. Врач осматривает вас и, если нужно, даёт рецепт на лекарства. Лекарства покупают в аптеке.
Если нужен врач-специалист — например, окулист или дерматолог — семейный врач даёт направление. Иногда приходится ждать несколько недель до приёма у специалиста. Можно проверить очередь в приложении больничной кассы.
В экстренном случае можно поехать в приёмный покой больницы. Важно знать: визит в приёмный покой платный, если только нет направления от врача или ситуация угрожает жизни.
Каждый месяц часть зарплаты идёт на медицинскую страховку — это называется «налог на здоровье». Благодаря этому все жители Израиля получают базовые медицинские услуги.', '[{"he": "קופת חולים", "ru": "больничная касса", "translit": "купАт холИм"}, {"he": "רופא משפחה", "ru": "семейный врач", "translit": "рофЕ мишпахА"}, {"he": "מרשם", "ru": "рецепт", "translit": "миршАм"}, {"he": "בית מרקחת", "ru": "аптека", "translit": "бейт миркАхат"}, {"he": "רופא מומחה", "ru": "врач-специалист", "translit": "рофЕ мумхЕ"}, {"he": "הפניה", "ru": "направление", "translit": "hафнайА"}, {"he": "תור", "ru": "очередь / запись на приём", "translit": "тор"}, {"he": "חדר מיון", "ru": "приёмный покой", "translit": "хЕдер миюн"}, {"he": "מצב חירום", "ru": "экстренная ситуация", "translit": "мацАв херУм"}, {"he": "ביטוח בריאות", "ru": "медицинская страховка", "translit": "битУах бриЮт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (13, 3, 'לשכור דירה בישראל', 'Снимаем квартиру в Израиле', 'למצוא דירה להשכרה בישראל — זו משימה לא פשוטה. המחירים גבוהים, במיוחד בתל אביב, בירושלים ובאזור המרכז. אבל אם יודעים איך לחפש, אפשר למצוא דירה טובה במחיר סביר.
רוב האנשים מחפשים דירות באינטרנט — באתר "יד 2" או בקבוצות פייסבוק. אפשר גם לפנות למתווך, אבל המתווך לוקח עמלה — בדרך כלל חודש שכירות.
כשמוצאים דירה, חשוב לבדוק כמה דברים: האם הדירה במצב טוב? האם יש חניה? כמה עולה הארנונה? האם יש ועד בית ומה העלות?
לפני שנכנסים לדירה, חותמים על חוזה שכירות. בחוזה כתוב כמה עולה השכירות, לכמה זמן החוזה ומה התנאים. בדרך כלל צריך לתת שלושה שיקים לביטחון ופיקדון של חודש או חודשיים.
השוכר משלם ארנונה, חשמל, מים, גז ואינטרנט. ועד הבית — תשלום חודשי לניקיון ותחזוקה של הבניין.', 'Найти квартиру в аренду в Израиле — задача не из простых. Цены высокие, особенно в Тель-Авиве, Иерусалиме и центральном районе. Но если знать, как искать, можно найти хорошую квартиру по разумной цене.
Большинство людей ищут квартиры в интернете — на сайте «Яд 2» или в группах Facebook. Можно обратиться к риелтору, но он берёт комиссию — обычно месячную арендную плату.
Когда находят квартиру, важно проверить несколько вещей: в хорошем ли состоянии квартира? Есть ли парковка? Сколько стоит арнона? Есть ли домовой комитет и какова плата?
Перед заселением подписывают договор аренды. В договоре указано: стоимость аренды, срок договора и условия. Обычно нужно предоставить три чека для гарантии и залог в размере одного-двух месяцев.
Арендатор оплачивает арнону, электричество, воду, газ и интернет. Домовой комитет — ежемесячный платёж за уборку и обслуживание здания.', '[{"he": "שכירות", "ru": "аренда", "translit": "схирУт"}, {"he": "מתווך", "ru": "риелтор", "translit": "метавЕх"}, {"he": "עמלה", "ru": "комиссия", "translit": "амлА"}, {"he": "ארנונה", "ru": "муниципальный налог", "translit": "арнонА"}, {"he": "ועד בית", "ru": "домовой комитет", "translit": "ваАд бАйит"}, {"he": "חוזה", "ru": "договор", "translit": "хозЕ"}, {"he": "ערבות", "ru": "гарантия / поручительство", "translit": "аревУт"}, {"he": "פיקדון", "ru": "залог / депозит", "translit": "пикадОн"}, {"he": "חניה", "ru": "парковка", "translit": "ханайА"}, {"he": "תחזוקה", "ru": "обслуживание здания", "translit": "тахзукА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (19, 5, 'מהי זהות?', 'Что такое идентичность: философский взгляд', 'מהי זהות? השאלה הזו מלווה את המחשבה האנושית מאז ומתמיד. האם אנחנו מוגדרים על ידי המקום שנולדנו בו? השפה שלנו? הזיכרונות שלנו?
הפילוסוף היהודי-גרמני מרטין בובר כתב על היחס בין "אני" ל"אתה". לדעתו, הזהות שלנו נבנית דרך המפגש עם האחר. אני מגלה מי אני רק כשאני פוגש מישהו שונה ממני.
בהקשר הישראלי, שאלת הזהות מורכבת במיוחד. ישראלי יכול להיות יהודי-חילוני-אשכנזי-תל-אביבי, או דרוזי-חיפאי, או ערבי-נוצרי-נצרתי. כל אחד נושא זהויות מרובות שלפעמים משלימות ולפעמים סותרות זו את זו.
העברית עצמה היא שאלה של זהות. השפה שהייתה מתה כמעט אלפיים שנה חזרה לחיים והפכה לשפת אם של מיליונים. בכך היא מגשרת בין עבר עתיק להווה חי ונושם.', 'Что такое идентичность? Этот вопрос сопровождает человеческую мысль извечно. Определяемся ли мы местом рождения? Языком? Воспоминаниями?
Еврейско-немецкий философ Мартин Бубер писал об отношении между «Я» и «Ты». По его мнению, наша идентичность строится через встречу с Другим. Я узнаю, кто я, лишь встречая кого-то отличного от меня.
В израильском контексте вопрос идентичности особенно сложен. Израильтянин может быть евреем-светским-ашкеназом-тельавивцем, друзом из Хайфы или арабом-христианином из Назарета. Каждый несёт множественные идентичности, которые иногда дополняют, а иногда противоречат друг другу.
Сам иврит — это вопрос идентичности. Язык, бывший мёртвым почти две тысячи лет, вернулся к жизни и стал родным для миллионов. Тем самым он перебрасывает мост между древним прошлым и живым настоящим.', '[{"he": "זהות", "ru": "идентичность", "translit": "зеhУт"}, {"he": "פילוסופיה", "ru": "философия", "translit": "филосОфия"}, {"he": "זיכרונות", "ru": "воспоминания", "translit": "зихронОт"}, {"he": "מורכב", "ru": "сложный", "translit": "муркАв"}, {"he": "סותרות", "ru": "противоречат", "translit": "сотрОт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (14, 3, 'חגי ישראל', 'Израильские праздники: годовой круг', 'לישראלים יש הרבה חגים במהלך השנה. בחגים רוב העסקים סגורים ואנשים חוגגים עם המשפחה.
ראש השנה (ספטמבר-אוקטובר) — השנה החדשה העברית. אוכלים תפוחים בדבש לשנה מתוקה ואומרים "שנה טובה!". עשרה ימים אחרי ראש השנה בא יום כיפור — היום הכי קדוש בשנה. צמים עשרים וארבע שעות, לא נוהגים ברכב, והילדים רוכבים על אופניים בכבישים הריקים.
סוכות בא חמישה ימים אחרי יום כיפור. בונים סוכה — מין בית קטן מעץ — ואוכלים בה שבוע שלם. חנוכה (דצמבר) — חג האורות. מדליקים נרות בחנוכייה כל ערב, ואוכלים סופגניות ולביבות.
פורים (מרץ) — החג הכי שמח! ילדים ומבוגרים מתחפשים, נותנים משלוח מנות לחברים ואוכלים "אוזני המן" — עוגיות מתוקות עם מילוי. פסח (אפריל) — חג החירות. שבוע שלם לא אוכלים לחם, רק מצות. בליל הסדר כל המשפחה יושבת סביב השולחן וקוראת את ההגדה.
יום העצמאות (אפריל-מאי) — יום הולדת המדינה. חוגגים עם מנגלים, מופעים וזיקוקים. שבועות (מאי-יוני) — חג מתן תורה. אוכלים מאכלי חלב — עוגת גבינה, בלינצ''ס ומלבי.', 'У израильтян много праздников в течение года. В праздники большинство предприятий закрыты, люди отмечают с семьёй.
Рош ха-Шана (сентябрь–октябрь) — еврейский Новый год. Едят яблоки в мёду на сладкий год и говорят «Шана това!». Через десять дней — Йом Кипур, самый святой день в году. Постятся двадцать четыре часа, не ездят на машинах, а дети катаются на велосипедах по пустым дорогам.
Суккот наступает через пять дней после Йом Кипура. Строят сукку — маленький домик из дерева — и едят в ней целую неделю. Ханука (декабрь) — праздник огней. Каждый вечер зажигают свечи в ханукие, едят пончики и латкес.
Пурим (март) — самый весёлый праздник! Дети и взрослые наряжаются, дарят друзьям «мишлоах манот» и едят «уши Амана» — сладкое печенье с начинкой. Песах (апрель) — праздник свободы. Целую неделю не едят хлеб, только мацу. В ночь Седера вся семья садится за стол и читает Агаду.
День независимости (апрель–май) — день рождения государства. Празднуют с барбекю, концертами и фейерверками. Шавуот (май–июнь) — праздник дарования Торы. Едят молочные блюда — чизкейк, блинчики и малаби.', '[{"he": "חג", "ru": "праздник", "translit": "хаг"}, {"he": "ראש השנה", "ru": "Рош ха-Шана (Новый год)", "translit": "рош hа-шанА"}, {"he": "יום כיפור", "ru": "Йом Кипур (День искупления)", "translit": "йом кипУр"}, {"he": "צום", "ru": "пост", "translit": "цом"}, {"he": "סוכה", "ru": "сукка (шалаш)", "translit": "суккА"}, {"he": "חנוכייה", "ru": "ханукия (подсвечник)", "translit": "ханукийА"}, {"he": "תחפושת", "ru": "костюм / маскарад", "translit": "тахпОсет"}, {"he": "מצות", "ru": "маца (пресный хлеб)", "translit": "мацОт"}, {"he": "הגדה", "ru": "Агада (пасхальный рассказ)", "translit": "hагадА"}, {"he": "יום העצמאות", "ru": "День независимости", "translit": "йом hа-ацмаУт"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (15, 4, 'התקשורת הישראלית', 'Израильские СМИ: как страна потребляет новости', 'ישראלים צורכים חדשות בכמויות אדירות. בבוקר — רדיו ברכב בדרך לעבודה. בצהריים — כותרות באפליקציית החדשות. בערב — מהדורת חדשות בטלוויזיה.
בישראל יש שני ערוצי חדשות מרכזיים: ערוץ 12 (חדשות 12) וערוץ 13 (חדשות 13). הם מתחרים על הרייטינג כל ערב. ערוץ "כאן" (תאגיד השידור הישראלי) הוא ערוץ ציבורי — ללא פרסומות, עם דגש על תרבות וחדשות.
העיתונות הכתובה נמצאת במשבר, כמו בכל העולם. "הארץ" ו"ידיעות אחרונות" הם העיתונים הגדולים. "ישראל היום" מחולק בחינם ויש לו את התפוצה הגדולה ביותר.
אבל הכוח האמיתי עבר לרשתות החברתיות ולאתרי אינטרנט. Ynet, וואלה ו-N12 הם האתרים הפופולריים ביותר. פודקאסטים הפכו לפורמט חדש ופופולרי — "עושים היסטוריה" ו"עושים חשבון" הם מהמובילים.
ישראלים אוהבים לדון בפוליטיקה. בכל בית קפה אפשר לשמוע ויכוח נלהב על הממשלה, הכלכלה או הביטחון. החופש לבקר את השלטון נחשב לערך יסוד בדמוקרטיה הישראלית.', 'Израильтяне потребляют новости в огромных количествах. Утром — радио в машине по дороге на работу. В обед — заголовки в новостном приложении. Вечером — выпуск новостей по телевизору.
В Израиле два основных новостных канала: Канал 12 и Канал 13. Они соревнуются за рейтинг каждый вечер. Канал «Кан» (Израильская вещательная корпорация) — общественный: без рекламы, с акцентом на культуру и новости.
Печатная пресса в кризисе, как и во всём мире. «Гаарец» и «Едиот Ахронот» — крупнейшие газеты. «Исраэль ха-йом» раздаётся бесплатно и имеет самый большой тираж.
Но реальная сила перешла к соцсетям и интернет-порталам. Ynet, Walla и N12 — самые популярные сайты. Подкасты стали новым популярным форматом — «Осим историа» и «Осим хешбон» входят в число лидеров.
Израильтяне любят обсуждать политику. В любом кафе можно услышать горячий спор о правительстве, экономике или безопасности. Свобода критиковать власть считается основополагающей ценностью израильской демократии.', '[{"he": "חדשות", "ru": "новости", "translit": "хадашОт"}, {"he": "ערוץ", "ru": "канал", "translit": "арУц"}, {"he": "עיתון", "ru": "газета", "translit": "итОн"}, {"he": "עיתונאי", "ru": "журналист", "translit": "итонАй"}, {"he": "פרסומת", "ru": "реклама", "translit": "пирсОмет"}, {"he": "תפוצה", "ru": "тираж", "translit": "тфуцА"}, {"he": "רשתות חברתיות", "ru": "социальные сети", "translit": "решатОт хевратийОт"}, {"he": "ויכוח", "ru": "спор/дискуссия", "translit": "викУах"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (16, 4, 'אקולוגיה בישראל', 'Экология Израиля: пустыня, вода, технологии', 'ישראל היא מדינה קטנה עם אתגרים סביבתיים גדולים. יותר ממחצית השטח הוא מדבר — הנגב. הגשם יורד בעיקר בחורף, וגם אז — לא הרבה.
בעיית המים תמיד הייתה המאתגרת ביותר. בעבר שאבו מים מהכינרת ומאגרים טבעיים, אבל הצריכה הגוברת גרמה למשבר. הפתרון: התפלת מי ים. היום חמישה מתקני התפלה לאורך החוף מספקים כשבעים אחוז מהמים.
ישראל גם מובילה בטכנולוגיית השקיה. ההשקיה בטפטוף — המצאה ישראלית מקיבוץ חצרים — חוסכת עד שבעים אחוז מים לעומת השקיה רגילה. היום הטכנולוגיה הזו משמשת חקלאים בכל העולם.
אנרגיה סולארית היא תחום נוסף. באר שבע היא עיר עם הכי הרבה ימי שמש בישראל, ואוניברסיטת בן גוריון מובילה מחקר באנרגיה ירוקה. הממשלה הציבה יעד של שלושים אחוז אנרגיה מתחדשת עד 2030.
אבל יש גם בעיות: זיהום אוויר בערים גדולות, הצפות אחרי גשמים חזקים, ופסולת פלסטיק בים התיכון. ארגוני סביבה כמו "אדם, טבע ודין" נלחמים על שמירת הטבע.', 'Израиль — маленькая страна с большими экологическими вызовами. Более половины территории — пустыня Негев. Дожди идут в основном зимой, и даже тогда — немного.
Проблема воды всегда была самой острой. Раньше воду качали из Кинерета и естественных водохранилищ, но растущее потребление привело к кризису. Решение: опреснение морской воды. Сегодня пять заводов вдоль побережья дают около 70% воды.
Израиль также лидирует в технологиях орошения. Капельное орошение — израильское изобретение из кибуца Хацерим — экономит до 70% воды по сравнению с обычным поливом. Сегодня эта технология используется фермерами по всему миру.
Солнечная энергия — ещё одна область. Беэр-Шева — город с наибольшим количеством солнечных дней в Израиле, а Университет Бен-Гуриона ведёт исследования в области зелёной энергии. Правительство поставило цель — 30% возобновляемой энергии к 2030 году.
Но есть и проблемы: загрязнение воздуха в крупных городах, наводнения после сильных дождей, пластиковый мусор в Средиземном море. Экологические организации вроде «Адам, тева ве-дин» борются за сохранение природы.', '[{"he": "מדבר", "ru": "пустыня", "translit": "мидбАр"}, {"he": "התפלה", "ru": "опреснение", "translit": "hатпалА"}, {"he": "השקיה בטפטוף", "ru": "капельное орошение", "translit": "hашкайА бе-тифтУф"}, {"he": "אנרגיה סולארית", "ru": "солнечная энергия", "translit": "энергийА соларИт"}, {"he": "מתחדשת", "ru": "возобновляемая", "translit": "митхадЕшет"}, {"he": "זיהום", "ru": "загрязнение", "translit": "зиhУм"}, {"he": "פסולת", "ru": "отходы/мусор", "translit": "псОлет"}, {"he": "שמירת הטבע", "ru": "охрана природы", "translit": "шмирАт hа-тЕва"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (17, 4, 'תל אביב: עיר שלא עוצרת', 'Тель-Авив: город, который не останавливается', 'תל אביב היא לא רק עיר — היא מצב רוח. עיר שחיה עשרים וארבע שעות ביממה, שבעה ימים בשבוע.
בבוקר — יוגיסטים על חוף פרישמן, רצים על הטיילת, ואנשי עסקים שותים קפה בשדרות רוטשילד. בצהריים — השווקים פתוחים: שוק הכרמל מלא צבעים, ריחות ורעש. בערב — המסעדות מתמלאות, הברים נפתחים, המוזיקה מתחילה.
תל אביב היא גם בירת ההייטק. אלפי סטארט-אפים מפוזרים ברחבי העיר, ומשקיעים מכל העולם מגיעים לחפש את הדבר הגדול הבא. שכונת פלורנטין הפכה ממחסנים לאזור היצירתי הכי חם.
אבל תל אביב גם יקרה מאוד. מחירי הדירות בין הגבוהים בעולם, וצעירים רבים מתקשים לשכור דירה. בכל זאת, רבים בוחרים להישאר — בגלל האווירה, החופש והתרבות.
תל אביב קיבלה את הכינוי "העיר הלבנה" בזכות מבני הבאוהאוס מתקופת שנות השלושים, שהוכרזו כאתר מורשת עולמי של אונסקו.', 'Тель-Авив — не просто город, а состояние души. Город, живущий двадцать четыре часа в сутки, семь дней в неделю.
Утром — йоги на пляже Фришман, бегуны на набережной, бизнесмены пьют кофе на бульваре Ротшильда. В обед — рынки открыты: Кармель полон красок, запахов и шума. Вечером — рестораны наполняются, бары открываются, начинается музыка.
Тель-Авив — также столица хай-тека. Тысячи стартапов разбросаны по городу, а инвесторы со всего мира приезжают искать «следующую большую вещь». Район Флорентин превратился из складов в самый горячий креативный квартал.
Но Тель-Авив также очень дорогой. Цены на квартиры — одни из самых высоких в мире, многим молодым трудно снять жильё. И всё же многие решают остаться — ради атмосферы, свободы и культуры.
Тель-Авив получил прозвище «Белый город» благодаря зданиям в стиле Баухаус 1930-х годов, которые признаны объектом Всемирного наследия ЮНЕСКО.', '[{"he": "טיילת", "ru": "набережная / променад", "translit": "таелЕт"}, {"he": "שדרה", "ru": "бульвар", "translit": "сдерА"}, {"he": "שוק", "ru": "рынок", "translit": "шук"}, {"he": "סטארט-אפ", "ru": "стартап", "translit": "стАрт-ап"}, {"he": "משקיע", "ru": "инвестор", "translit": "машкИа"}, {"he": "כינוי", "ru": "прозвище", "translit": "кинУй"}, {"he": "מורשת עולמית", "ru": "мировое наследие", "translit": "морЕшет оламИт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (18, 5, 'עלייה לישראל: מבט אקדמי', 'Миграция в Израиль: академический взгляд', 'תופעת העלייה לישראל היא ייחודית בהיסטוריה של תנועות הגירה. בניגוד להגירה כלכלית רגילה, העלייה מונעת בעיקר ממניעים אידיאולוגיים, דתיים וזהותיים.
הגל הראשון (העלייה הראשונה, 1882-1903) הביא בעיקר צעירים מרוסיה שהושפעו מרעיונות הציונות. הם הקימו את המושבות הראשונות — ראשון לציון, פתח תקווה, זכרון יעקב.
העלייה הגדולה ביותר הייתה אחרי קום המדינה (1948-1951). בשלוש שנים הוכפל אוכלוסיית ישראל. הגיעו ניצולי שואה מאירופה, יהודים מעיראק, תימן ומרוקו. קליטת עלייה כה מסיבית הייתה אתגר חסר תקדים.
בשנות התשעים הגיעו כמיליון עולים מברית המועצות לשעבר. גל זה שינה את פני החברה הישראלית — בתחומי המדע, המוזיקה, הספורט והטכנולוגיה.
היום העלייה ממשיכה, אם כי בקצב מתון יותר. עולים מצרפת, מאמריקה הלטינית ומאתיופיה ממשיכים להגיע. השאלה כיצד לשלב אוכלוסיות מגוונות נותרת מרכזית בשיח הישראלי.', 'Феномен алии (репатриации в Израиль) уникален в истории миграционных движений. В отличие от обычной экономической миграции, алия движима прежде всего идеологическими, религиозными и идентитарными мотивами.
Первая волна (Первая алия, 1882–1903) привезла молодёжь из России, вдохновлённую идеями сионизма. Они основали первые поселения — Ришон ле-Цион, Петах-Тикву, Зихрон-Яаков.
Крупнейшая алия произошла после создания государства (1948–1951). За три года население Израиля удвоилось. Приехали пережившие Холокост из Европы, евреи из Ирака, Йемена и Марокко. Абсорбция столь массовой алии была беспрецедентным вызовом.
В девяностые годы прибыл около миллиона репатриантов из бывшего СССР. Эта волна изменила лицо израильского общества — в науке, музыке, спорте и технологиях.
Сегодня алия продолжается, хотя и в более умеренном темпе. Репатрианты из Франции, Латинской Америки и Эфиопии продолжают приезжать. Вопрос интеграции разнообразных групп населения остаётся центральным в израильском дискурсе.', '[{"he": "עלייה", "ru": "алия / репатриация", "translit": "алийА"}, {"he": "הגירה", "ru": "миграция", "translit": "hагирА"}, {"he": "ציונות", "ru": "сионизм", "translit": "циёнУт"}, {"he": "קליטה", "ru": "абсорбция / интеграция", "translit": "клитА"}, {"he": "אוכלוסייה", "ru": "население", "translit": "ухлусийА"}, {"he": "חסר תקדים", "ru": "беспрецедентный", "translit": "хасАр такдИм"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (20, 5, 'קטע מאתגר כרת', 'Отрывок из Этгара Керета: «Трубы»', 'בלילה שאחרי הלוויה של סבא, אבא ישב במטבח ועישן. הוא לא בכה, כי אבא שלי אף פעם לא בוכה. הוא פשוט ישב שם ועישן סיגריה אחרי סיגריה.
"אתה יודע," הוא אמר לי בלי להסתכל, "סבא שלך היה האיש הכי חזק שהכרתי. כשהוא הגיע לארץ, הוא לא ידע אף מילה בעברית. הוא עבד בבניין, בניקיון, בכל מה שהיה. ואחרי עשר שנים היה לו עסק משלו."
"ומה היה העסק?" שאלתי, למרות שידעתי את התשובה.
"שרברבות," אמר אבא וחייך. "הוא היה השרברב הכי טוב בפתח תקווה. אנשים היו מחכים שבועות בשביל שהוא יבוא לתקן להם. כי כשסבא שלך תיקן משהו — זה היה מתוקן לנצח."', 'В ночь после похорон дедушки папа сидел на кухне и курил. Он не плакал — мой папа никогда не плачет. Он просто сидел там и курил сигарету за сигаретой.
«Знаешь, — сказал он мне, не глядя, — твой дедушка был самым сильным человеком, которого я знал. Когда он приехал в страну, он не знал ни слова на иврите. Работал на стройке, на уборке, на всём что было. А через десять лет у него был свой бизнес.»
«А что за бизнес?» — спросил я, хотя знал ответ.
«Водопровод, — сказал папа и улыбнулся. — Он был лучшим сантехником в Петах-Тикве. Люди ждали неделями, чтобы он пришёл чинить. Потому что когда твой дедушка чинил что-то — это было починено навсегда.»', '[{"he": "הלוויה", "ru": "похороны", "translit": "hалвайА"}, {"he": "עישן", "ru": "курил", "translit": "ишЕн"}, {"he": "שרברב", "ru": "сантехник", "translit": "шравравОт"}, {"he": "לתקן", "ru": "чинить", "translit": "летакЕн"}, {"he": "לנצח", "ru": "навсегда", "translit": "ле-нЕцах"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (21, 5, 'שירו של עמיחי', 'Стихи Иегуды Амихая', 'יהודה עמיחי (1924-2000) נחשב למשורר הלאומי של ישראל. הוא כתב שירה פשוטה ועמוקה, שמדברת אל כל אדם.
מתוך "אלוהים מרחם על ילדי הגן":
אלוהים מרחם על ילדי הגן.
פחות מזה על ילדי בית הספר.
ועל הגדולים לא ירחם עוד.
הם לבדם.
ולפעמים הם יצטרכו לזחול על ארבע
בחול הלוהט של המדבר.
***
הפשטות של עמיחי מטעה. מאחורי מילים יומיומיות מסתתר עומק פילוסופי: ככל שאנחנו גדלים, אנחנו מאבדים את ההגנה — ונאלצים להתמודד לבד עם מדבר החיים.
שפת השירה של עמיחי שינתה את העברית: הוא הראשון שהכניס שפה יומיומית לשירה, בניגוד לשפה הגבוהה של המשוררים לפניו.', 'Иегуда Амихай (1924–2000) считается национальным поэтом Израиля. Он писал простую и глубокую поэзию, обращённую к каждому.
Из стихотворения «Бог жалеет детей детского сада»:
Бог жалеет детей детского сада.
Чуть меньше — детей школы.
А взрослых уже не пожалеет.
Они — одни.
И иногда им придётся ползти на четвереньках
по раскалённому песку пустыни.
***
Простота Амихая обманчива. За повседневными словами скрывается философская глубина: чем больше мы взрослеем, тем больше теряем защиту — и вынуждены сами справляться с пустыней жизни.
Поэтический язык Амихая изменил иврит: он первый ввёл разговорный язык в поэзию, в противовес высокому стилю поэтов до него.', '[{"he": "משורר", "ru": "поэт", "translit": "мешорЕр"}, {"he": "שירה", "ru": "поэзия", "translit": "ширА"}, {"he": "מרחם", "ru": "жалеет", "translit": "мерахЕм"}, {"he": "לזחול", "ru": "ползти", "translit": "лизхОль"}, {"he": "עומק", "ru": "глубина", "translit": "Омек"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (22, 6, 'חוזה שכירות', 'Арендный договор', 'חוזה שכירות בלתי מוגנת
שנערך ונחתם ביום ___ בחודש ___ שנת ___
בין:
מר/גב'' ___ ת.ז. ___ (להלן: "המשכיר")
לבין:
מר/גב'' ___ ת.ז. ___ (להלן: "השוכר")
הואיל והמשכיר הינו הבעלים של הדירה ברחוב ___ מס'' ___ בעיר ___ (להלן: "המושכר");
והואיל והשוכר מעוניין לשכור את המושכר למטרת מגורים;
לפיכך הוסכם, הותנה והוצהר בין הצדדים כדלקמן:
1. תקופת השכירות: השכירות תחל ביום ___ ותסתיים ביום ___.
2. דמי השכירות: השוכר ישלם למשכיר דמי שכירות חודשיים בסך ___ ש"ח, עד ליום הראשון בכל חודש קלנדרי.
3. פיקדון: עם חתימת חוזה זה, יפקיד השוכר בידי המשכיר סכום של ___ ש"ח כפיקדון להבטחת מילוי התחייבויותיו.
4. שימוש במושכר: השוכר מתחייב להשתמש במושכר למטרת מגורים בלבד ולא להעביר את זכות השכירות לצד שלישי.
5. תיקונים: תיקונים קלים יהיו על חשבון השוכר. תיקונים מבניים יהיו על חשבון המשכיר.
ולראיה באו הצדדים על החתום:
המשכיר: ___          השוכר: ___', 'Договор незащищённой аренды
Составлен и подписан ___ числа месяца ___ года ___
Между:
Г-н/г-жа ___ уд. личн. ___ (далее: «Арендодатель»)
и:
Г-н/г-жа ___ уд. личн. ___ (далее: «Арендатор»)
Ввиду того что Арендодатель является собственником квартиры по адресу: ул. ___ д. ___ в городе ___ (далее: «Объект аренды»);
и ввиду того что Арендатор заинтересован в аренде Объекта для проживания;
Посему стороны согласились, обусловили и заявили нижеследующее:
1. Срок аренды: аренда начнётся ___ и завершится ___.
2. Арендная плата: Арендатор будет выплачивать Арендодателю ежемесячную арендную плату в размере ___ шек. до первого числа каждого календарного месяца.
3. Залог: при подписании настоящего договора Арендатор внесёт Арендодателю сумму в размере ___ шек. в качестве залога для обеспечения выполнения обязательств.
4. Использование Объекта: Арендатор обязуется использовать Объект исключительно для проживания и не передавать право аренды третьим лицам.
5. Ремонт: мелкий ремонт — за счёт Арендатора. Капитальный ремонт — за счёт Арендодателя.
В удостоверение чего стороны поставили свои подписи:
Арендодатель: ___          Арендатор: ___', '[{"he": "חוזה", "ru": "договор / контракт", "translit": "хозЕ"}, {"he": "שכירות", "ru": "аренда", "translit": "схирУт"}, {"he": "המשכיר", "ru": "арендодатель", "translit": "hа-масхИр"}, {"he": "השוכר", "ru": "арендатор", "translit": "hа-сохЕр"}, {"he": "הואיל", "ru": "ввиду того что", "translit": "hоИль"}, {"he": "לפיכך", "ru": "посему / поэтому", "translit": "лефихАх"}, {"he": "פיקדון", "ru": "залог / депозит", "translit": "пикадОн"}, {"he": "התחייבות", "ru": "обязательство", "translit": "hитхайвУт"}, {"he": "מושכר", "ru": "объект аренды", "translit": "мускАр"}, {"he": "ולראיה", "ru": "в удостоверение чего", "translit": "у-ле-раайА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (23, 6, 'ביקורת אקדמית', 'Академическая рецензия', 'ביקורת ספרים
על הספר: "זהות ישראלית: בין מיתוס למציאות" מאת פרופ'' דנה ברקוביץ, הוצאת האוניברסיטה העברית, 2025. 342 עמודים.
בספרה החדש והמרתק מנסה פרופ'' ברקוביץ לפרק את המיתוסים המכוננים של הזהות הישראלית. באמצעות ניתוח שיח ביקורתי של טקסטים תרבותיים — מספרי לימוד ועד סדרות טלוויזיה — היא מראה כיצד הנרטיב הלאומי עוצב ושוּנה לאורך העשורים.
הפרק המרכזי, "חלוצים ולוחמים", חושף את הפער בין הייצוג התרבותי של דור המייסדים לבין המציאות ההיסטורית המורכבת. ברקוביץ טוענת, ובצדק, כי האידיאליזציה של ה"צבר" החדש הדחיקה קולות אחרים — נשים, מזרחים, ערבים.
יתרה מזאת, הפרקים העוסקים בשינוי הזהות בעידן הגלובליזציה מציעים תובנות חדשניות. המעבר מזהות קולקטיבית לאינדיווידואלית, כך טוענת המחברת, אינו ייחודי לישראל, אך מקבל כאן גוון מיוחד לאור הקונפליקט המתמשך.
אולם, יש להעיר כי הספר אינו נותן מספיק מקום לקולות של קהילות מוחלשות. הפרק על הזהות האתיופית-ישראלית קצר מדי, והקולות הבדואים נעדרים כמעט לחלוטין.
לסיכום, מדובר בתרומה משמעותית לשיח האקדמי על זהות ישראלית. הספר מומלץ לחוקרים, סטודנטים וכל מי שמתעניין בשאלה "מהי ישראליות?".
דירוג: ★★★★☆', 'Рецензия на книгу
О книге: «Израильская идентичность: между мифом и реальностью», автор — проф. Дана Беркович, издательство Еврейского университета, 2025. 342 стр.
В своей новой и увлекательной книге проф. Беркович предпринимает попытку деконструировать основополагающие мифы израильской идентичности. С помощью критического дискурс-анализа культурных текстов — от школьных учебников до телесериалов — она показывает, как национальный нарратив формировался и менялся на протяжении десятилетий.
Центральная глава, «Первопроходцы и воины», обнажает разрыв между культурным представлением о поколении основателей и сложной исторической реальностью. Беркович убедительно утверждает, что идеализация нового «сабры» вытеснила иные голоса — женщин, мизрахим, арабов.
Более того, главы, посвящённые трансформации идентичности в эпоху глобализации, предлагают новаторские идеи. Переход от коллективной идентичности к индивидуальной, утверждает автор, не уникален для Израиля, но приобретает здесь особый оттенок в свете продолжающегося конфликта.
Тем не менее следует заметить, что книга не уделяет достаточно места голосам маргинализированных сообществ. Глава об эфиопско-израильской идентичности слишком коротка, а голоса бедуинов практически отсутствуют.
В заключение, речь идёт о значительном вкладе в академический дискурс об израильской идентичности. Книга рекомендована исследователям, студентам и всем, кого интересует вопрос «Что такое израильскость?».
Оценка: ★★★★☆', '[{"he": "ביקורת ספרים", "ru": "книжная рецензия", "translit": "бикОрет сфарИм"}, {"he": "מיתוס", "ru": "миф", "translit": "мИтос"}, {"he": "נרטיב", "ru": "нарратив", "translit": "наратИв"}, {"he": "שיח ביקורתי", "ru": "критический дискурс", "translit": "сИах бикортИ"}, {"he": "תובנה", "ru": "инсайт / глубокая мысль", "translit": "тованА"}, {"he": "מוחלש", "ru": "маргинализированный", "translit": "мухлАш"}, {"he": "דירוג", "ru": "рейтинг / оценка", "translit": "дирУг"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (124, 4, 'דת ומסורת בישראל', 'Религия и традиции', 'ישראל הוגדרה כמדינה יהודית ודמוקרטית, אך היחס בין דת למדינה מורכב ושנוי במחלוקת. "הסטטוס קוו" שנקבע עם הקמת המדינה קובע כללים בנושאי שבת, כשרות, נישואין וגיור.
בשבת, התחבורה הציבורית אינה פועלת ברוב הערים, חנויות רבות סגורות, ומרכזי הבידור שקטים. בתל אביב המצב שונה — בתי קפה פתוחים והחיים ממשיכים. מתח זה בין דתיים לחילונים הוא חלק מהנוף הישראלי.
מערכת הכשרות נמצאת בפיקוח הרבנות הראשית. מסעדות רבות שומרות על כשרות כדי למשוך לקוחות מכל המגזרים. אך בשנים האחרונות גדל מספר המסעדות שבוחרות שלא להיות כשרות.
נישואין בישראל מתבצעים רק דרך מוסדות דתיים. אין נישואים אזרחיים, מה שמוביל זוגות רבים להתחתן בחו"ל. זהו אחד הנושאים הרגישים ביותר בוויכוח על יחסי דת ומדינה.', 'Израиль определён как еврейское и демократическое государство, но отношения между религией и государством сложны и спорны. «Статус-кво», установленный при создании государства, определяет правила в вопросах субботы, кашрута, бракосочетания и гиюра.
В субботу общественный транспорт не работает в большинстве городов, многие магазины закрыты, а развлекательные центры пустеют. В Тель-Авиве ситуация иная — кафе открыты и жизнь продолжается. Это напряжение между религиозными и светскими — часть израильского пейзажа.
Система кашрута находится под контролем Главного раввината. Многие рестораны соблюдают кашрут, чтобы привлечь клиентов из всех секторов. Однако в последние годы растёт число ресторанов, отказывающихся от сертификации.
Бракосочетания в Израиле проводятся только через религиозные институты. Гражданского брака нет, что побуждает многие пары жениться за границей. Это один из самых чувствительных вопросов в дебатах о религии и государстве.', '[{"he": "דת", "ru": "религия", "translit": "дат"}, {"he": "סטטוס קוו", "ru": "статус-кво", "translit": "стАтус кво"}, {"he": "כשרות", "ru": "кашрут", "translit": "кашрУт"}, {"he": "נישואין", "ru": "бракосочетание", "translit": "нисуИн"}, {"he": "רבנות", "ru": "раввинат", "translit": "рабанУт"}, {"he": "חילוני", "ru": "светский", "translit": "хилонИ"}, {"he": "גיור", "ru": "гиюр", "translit": "гиЮр"}, {"he": "מחלוקת", "ru": "разногласие", "translit": "махлОкет"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (24, 6, 'טור דעה: חינוך', 'Газетная колонка: образование', 'מערכת החינוך צריכה מהפכה — לא עוד רפורמה
שוב מדברים על רפורמה בחינוך. שוב מקימים ועדה. שוב כותבים דוחות שאף אחד לא קורא. הגיע הזמן לומר את האמת: מערכת החינוך הישראלית לא צריכה עוד רפורמה — היא צריכה מהפכה.
הבעיות ידועות: כיתות עמוסות, שכר מורים נמוך, תוכניות לימודים מיושנות, פערים בין מרכז לפריפריה. על כל אלה נכתבו מאמרים, נאמרו נאומים, הובטחו הבטחות. ושום דבר לא השתנה באמת.
מה צריך להשתנות?
ראשית, שכר המורים. מדינה שמשלמת למורים פחות ממה שמשלמים למהנדס מתחיל, לא יכולה להתלונן שהמוכשרים ביותר לא בוחרים בהוראה.
שנית, תוכנית הלימודים. ילדים לומדים עדיין את אותו חומר שאני למדתי לפני שלושים שנה. בעולם של בינה מלאכותית ושינויי אקלים, אנחנו עדיין מלמדים כאילו אנחנו ב-1995.
שלישית, הפריפריה. ילד בדימונה ראוי לאותה רמת חינוך כמו ילד ברמת אביב. זה לא עניין של תקציב — זה עניין של סדר עדיפויות לאומי.
אני יודע, כולם מסכימים. אבל בין ההסכמה לבין המעשה — תהום. ובתוך התהום הזו גדלים ילדים שלא מקבלים את מה שמגיע להם.', 'Системе образования нужна революция — а не очередная реформа
Снова говорят о реформе образования. Снова создают комиссию. Снова пишут отчёты, которые никто не читает. Пора сказать правду: израильская система образования не нуждается в ещё одной реформе — ей нужна революция.
Проблемы известны: переполненные классы, низкая зарплата учителей, устаревшие учебные программы, разрыв между центром и периферией. Обо всём этом писали статьи, произносили речи, давали обещания. И ничего по-настоящему не изменилось.
Что должно измениться?
Во-первых, зарплата учителей. Страна, которая платит учителям меньше, чем начинающему инженеру, не может жаловаться, что самые одарённые не идут в педагогику.
Во-вторых, учебная программа. Дети до сих пор учат тот же материал, что я учил тридцать лет назад. В мире искусственного интеллекта и климатических изменений мы по-прежнему преподаём так, будто на дворе 1995 год.
В-третьих, периферия. Ребёнок в Димоне заслуживает такого же уровня образования, как ребёнок в Рамат-Авив. Это не вопрос бюджета — это вопрос национальных приоритетов.
Я знаю, все согласны. Но между согласием и действием — пропасть. И в этой пропасти растут дети, не получающие того, что им положено.', '[{"he": "מהפכה", "ru": "революция", "translit": "маhапехА"}, {"he": "רפורמה", "ru": "реформа", "translit": "рефОрма"}, {"he": "פריפריה", "ru": "периферия", "translit": "перифЕрия"}, {"he": "סדר עדיפויות", "ru": "порядок приоритетов", "translit": "сЕдер адифуйОт"}, {"he": "תהום", "ru": "пропасть", "translit": "теhОм"}, {"he": "מוכשר", "ru": "одарённый / талантливый", "translit": "мухшАр"}, {"he": "ועדה", "ru": "комиссия", "translit": "ваадА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (25, 1, 'הַיּוֹם שֶׁלִּי', 'Мой день', 'בַּבֹּקֶר אֲנִי קָם בְּשֵׁשׁ. אֲנִי שׁוֹתֶה קָפֶה וְאוֹכֵל לֶחֶם עִם גְּבִינָה. אַחַר כָּךְ אֲנִי הוֹלֵךְ לָעֲבוֹדָה בָּאוֹטוֹבּוּס. אֲנִי עוֹבֵד בְּמִשְׂרָד. בַּצָּהֳרַיִם אֲנִי אוֹכֵל אֲרוּחַת צָהֳרַיִם בְּמִסְעָדָה קְטַנָּה. אַחֲרֵי הָעֲבוֹדָה אֲנִי חוֹזֵר הַבַּיְתָה. בָּעֶרֶב אֲנִי קוֹרֵא סֵפֶר אוֹ רוֹאֶה סֶרֶט. בְּעֶשֶׂר אֲנִי הוֹלֵךְ לִישׁוֹן. זֶה הַיּוֹם שֶׁלִּי.', 'Утром я встаю в шесть. Я пью кофе и ем хлеб с сыром. Потом я еду на работу на автобусе. Я работаю в офисе. В полдень я обедаю в маленьком ресторане. После работы я возвращаюсь домой. Вечером я читаю книгу или смотрю фильм. В десять я иду спать. Это мой день.', '[{"he": "בֹּקֶר", "ru": "утро", "translit": "бОкер"}, {"he": "קָפֶה", "ru": "кофе", "translit": "кафЭ"}, {"he": "עֲבוֹדָה", "ru": "работа", "translit": "аводА"}, {"he": "מִשְׂרָד", "ru": "офис", "translit": "мисрАд"}, {"he": "צָהֳרַיִם", "ru": "полдень", "translit": "цоhорАим"}, {"he": "עֶרֶב", "ru": "вечер", "translit": "Эрев"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (26, 1, 'בַּפַּארְק', 'В парке', 'הַיּוֹם יוֹם שַׁבָּת. הַמִּזָּג אֲוִיר יָפֶה. אֲנִי וְהַחֲבֵרָה שֶׁלִּי הוֹלְכִים לַפַּארְק. בַּפַּארְק יֵשׁ עֵצִים גְּדוֹלִים וּפְרָחִים יָפִים. יְלָדִים מְשַׂחֲקִים בַּמַּגְרָשׁ. אֲנַחְנוּ יוֹשְׁבִים עַל הַדֶּשֶׁא וְאוֹכְלִים כָּרִיכִים. אֲנַחְנוּ רוֹאִים כֶּלֶב גָּדוֹל וְחָתוּל קָטָן. הַכֶּלֶב רָץ וְהַחָתוּל יָשֵׁן. אֲנַחְנוּ אוֹהֲבִים אֶת הַפַּארְק.', 'Сегодня суббота. Погода хорошая. Я и моя подруга идём в парк. В парке есть большие деревья и красивые цветы. Дети играют на площадке. Мы сидим на траве и едим бутерброды. Мы видим большую собаку и маленькую кошку. Собака бегает, а кошка спит. Мы любим парк.', '[{"he": "שַׁבָּת", "ru": "суббота", "translit": "шабАт"}, {"he": "עֵצִים", "ru": "деревья", "translit": "эцИм"}, {"he": "פְּרָחִים", "ru": "цветы", "translit": "прахИм"}, {"he": "דֶּשֶׁא", "ru": "трава / газон", "translit": "дЕше"}, {"he": "כֶּלֶב", "ru": "собака", "translit": "кЕлев"}, {"he": "חָתוּל", "ru": "кошка / кот", "translit": "хатУль"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (27, 1, 'בְּבֵית קָפֶה', 'В кафе', 'מֶלְצָר: שָׁלוֹם! מָה תִּרְצוּ לִשְׁתּוֹת?
דָּן: אֲנִי רוֹצֶה קָפֶה עִם חָלָב, בְּבַקָּשָׁה.
מִירָב: וַאֲנִי רוֹצָה תֵּה עִם לִימוֹן.
מֶלְצָר: וּמָה לֶאֱכֹל?
דָּן: יֵשׁ לָכֶם עוּגָה?
מֶלְצָר: כֵּן, יֵשׁ לָנוּ עוּגַת שׁוֹקוֹלָד וְעוּגַת גְּבִינָה.
מִירָב: עוּגַת גְּבִינָה, בְּבַקָּשָׁה.
דָּן: גַּם לִי. תּוֹדָה!
מֶלְצָר: בְּבַקָּשָׁה. רֶגַע אֶחָד.', 'Официант: Здравствуйте! Что будете пить?
Дан: Я хочу кофе с молоком, пожалуйста.
Мирав: А я хочу чай с лимоном.
Официант: А что покушать?
Дан: У вас есть торт?
Официант: Да, у нас есть шоколадный торт и чизкейк.
Мирав: Чизкейк, пожалуйста.
Дан: Мне тоже. Спасибо!
Официант: Пожалуйста. Одну минуту.', '[{"he": "מֶלְצָר", "ru": "официант", "translit": "мельцАр"}, {"he": "לִשְׁתּוֹת", "ru": "пить", "translit": "лиштОт"}, {"he": "תֵּה", "ru": "чай", "translit": "те"}, {"he": "עוּגָה", "ru": "торт / пирог", "translit": "угА"}, {"he": "שׁוֹקוֹלָד", "ru": "шоколад", "translit": "шоколАд"}, {"he": "בְּבַקָּשָׁה", "ru": "пожалуйста", "translit": "бевакашА"}]', NULL, 'dialog');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (136, 4, 'קליטת עולים בישראל', 'Интеграция иммигрантов', 'ישראל היא מדינת הגירה מיום הקמתה. חוק השבות מעניק לכל יהודי בעולם את הזכות לעלות לישראל ולקבל אזרחות. מאז 1948 הגיעו לישראל כארבעה מיליון עולים מכל קצוות תבל.
גלי העלייה הגדולים כללו: יהודי ארצות ערב בשנות החמישים, יהודי אתיופיה בשנות השמונים והתשעים, ומיליון עולים מברית המועצות לשעבר בשנות התשעים. כל גל הביא אתגרי קליטה ייחודיים.
מערכת האולפן — קורסי עברית אינטנסיביים — הוקמה כדי ללמד עולים חדשים את השפה. האולפן הראשון נפתח בירושלים בשנת 1949 ומאז למדו בו מאות אלפי עולים.
שילוב מקצועי הוא אחד האתגרים הקשים ביותר. רופאים, מהנדסים ומורים שעלו לישראל נאלצים לעבור הכשרה מחדש ולעתים לעבוד בתחומים אחרים. עם הזמן, רוב העולים מצליחים להשתלב, אך התהליך כואב ולוקח שנים.', 'Израиль — страна иммиграции с самого своего основания. Закон о возвращении даёт каждому еврею в мире право репатриироваться в Израиль и получить гражданство. С 1948 года в Израиль прибыли около четырёх миллионов репатриантов со всего мира.
Крупные волны репатриации включали: евреев из арабских стран в пятидесятых, евреев Эфиопии в восьмидесятых-девяностых и миллион выходцев из бывшего СССР в девяностых. Каждая волна принесла уникальные проблемы интеграции.
Система ульпанов — интенсивных курсов иврита — была создана для обучения новых репатриантов языку. Первый ульпан открылся в Иерусалиме в 1949 году, и с тех пор в нём учились сотни тысяч репатриантов.
Профессиональная интеграция — одна из самых сложных задач. Врачи, инженеры и учителя, репатриировавшиеся в Израиль, вынуждены проходить переподготовку и порой работать в других областях. Со временем большинство репатриантов успешно интегрируются, но процесс болезненный и занимает годы.', '[{"he": "עלייה", "ru": "репатриация", "translit": "алийА"}, {"he": "קליטה", "ru": "абсорбция/интеграция", "translit": "клитА"}, {"he": "אולפן", "ru": "ульпан", "translit": "ульпАн"}, {"he": "חוק השבות", "ru": "Закон о возвращении", "translit": "хок hа-швУт"}, {"he": "אזרחות", "ru": "гражданство", "translit": "эзрахУт"}, {"he": "הכשרה", "ru": "подготовка", "translit": "hахшарА"}, {"he": "שילוב", "ru": "интеграция", "translit": "шилУв"}, {"he": "עולה חדש", "ru": "новый репатриант", "translit": "олЕ хадАш"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (28, 1, 'הַחָבֵר שֶׁלִּי', 'Мой друг', 'יֵשׁ לִי חָבֵר טוֹב. הַשֵּׁם שֶׁלּוֹ מִיכָאֵל. הוּא גָּר בְּחֵיפָה. מִיכָאֵל עוֹבֵד בְּבֵית חוֹלִים. הוּא רוֹפֵא טוֹב מְאוֹד. בַּזְּמַן הַחוֹפְשִׁי הוּא אוֹהֵב לְנַגֵּן גִּיטָרָה וְלָרוּץ בַּבֹּקֶר. כָּל שָׁבוּעַ אֲנַחְנוּ נִפְגָּשִׁים בְּבֵית קָפֶה. אֲנַחְנוּ שׁוֹתִים קָפֶה וּמְדַבְּרִים. מִיכָאֵל חָבֵר נֶהְדָּר.', 'У меня есть хороший друг. Его зовут Михаэль. Он живёт в Хайфе. Михаэль работает в больнице. Он очень хороший врач. В свободное время он любит играть на гитаре и бегать по утрам. Каждую неделю мы встречаемся в кафе. Мы пьём кофе и разговариваем. Михаэль замечательный друг.', '[{"he": "חָבֵר", "ru": "друг", "translit": "хавЕр"}, {"he": "בֵּית חוֹלִים", "ru": "больница", "translit": "бет холИм"}, {"he": "זְמַן חוֹפְשִׁי", "ru": "свободное время", "translit": "зман хофшИ"}, {"he": "לְנַגֵּן", "ru": "играть (на инструменте)", "translit": "ленагЕн"}, {"he": "לָרוּץ", "ru": "бегать", "translit": "ларУц"}, {"he": "נִפְגָּשִׁים", "ru": "встречаемся", "translit": "нифгашИм"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (29, 2, 'טִיּוּל לִירוּשָׁלַיִם', 'Поездка в Иерусалим', 'בְּיוֹם שִׁשִּׁי הָאַחֲרוֹן נָסַעְנוּ לִירוּשָׁלַיִם. יָצָאנוּ מִתֵּל אָבִיב בְּשֶׁבַע בַּבֹּקֶר. הַנְּסִיעָה לָקְחָה שָׁעָה אַחַת. כְּשֶׁהִגַּעְנוּ, הָלַכְנוּ לָעִיר הָעַתִּיקָה. רָאִינוּ אֶת הַכֹּתֶל הַמַּעֲרָבִי. הָיוּ שָׁם הַרְבֵּה אֲנָשִׁים. אַחַר כָּךְ טִיַּלְנוּ בַּשּׁוּק וְקָנִינוּ מַתָּנוֹת. אָכַלְנוּ פְלָאפֶל בְּמִסְעָדָה קְטַנָּה. הַפְּלָאפֶל הָיָה טָעִים מְאוֹד! חָזַרְנוּ הַבַּיְתָה בָּעֶרֶב, עֲיֵפִים אֲבָל מְרוּצִים.', 'В прошлую пятницу мы поехали в Иерусалим. Мы выехали из Тель-Авива в семь утра. Поездка заняла один час. Когда приехали, пошли в Старый город. Мы увидели Стену Плача. Там было много людей. Потом мы гуляли по рынку и купили подарки. Мы поели фалафель в маленьком ресторане. Фалафель был очень вкусный! Мы вернулись домой вечером, усталые, но довольные.', '[{"he": "טִיּוּל", "ru": "поездка / прогулка", "translit": "тиЮль"}, {"he": "נְסִיעָה", "ru": "поездка (на транспорте)", "translit": "несиА"}, {"he": "עִיר עַתִּיקָה", "ru": "Старый город", "translit": "ир атикА"}, {"he": "כֹּתֶל מַעֲרָבִי", "ru": "Стена Плача", "translit": "кОтель мааравИ"}, {"he": "מַתָּנוֹת", "ru": "подарки", "translit": "матанОт"}, {"he": "עֲיֵפִים", "ru": "усталые", "translit": "аефИм"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (30, 2, 'אֵצֶל הָרוֹפֵא', 'У врача', 'רוֹפֵא: בֹּקֶר טוֹב. מָה קוֹרֶה? אֵיךְ אַתָּה מַרְגִּישׁ?
דָּוִד: בֹּקֶר טוֹב, דּוֹקְטוֹר. יֵשׁ לִי כְּאֵב רֹאשׁ חָזָק וּמְעַט חוֹם.
רוֹפֵא: מָתַי הִתְחִיל הַכְּאֵב?
דָּוִד: אֶתְמוֹל בָּעֶרֶב. גַּם הַגָּרוֹן שֶׁלִּי כּוֹאֵב.
רוֹפֵא: בּוֹא נִבְדֹּק. תִּפְתַּח אֶת הַפֶּה, בְּבַקָּשָׁה. כֵּן, הַגָּרוֹן אָדוֹם. נִרְאֶה שֶׁיֵּשׁ לְךָ הַצְטַנְּנוּת. אֲנִי כּוֹתֵב לְךָ מִרְשָׁם לִתְרוּפָה.
דָּוִד: תּוֹדָה, דּוֹקְטוֹר. כַּמָּה יָמִים אֲנִי צָרִיךְ לָשֶׁבֶת בַּבַּיִת?
רוֹפֵא: יוֹמַיִם-שְׁלוֹשָׁה. תִּשְׁתֶּה הַרְבֵּה מַיִם וְתָנוּחַ.', 'Врач: Доброе утро. Что случилось? Как вы себя чувствуете?
Давид: Доброе утро, доктор. У меня сильная головная боль и немного температура.
Врач: Когда началась боль?
Давид: Вчера вечером. И ещё у меня болит горло.
Врач: Давайте проверим. Откройте рот, пожалуйста. Да, горло красное. Похоже, у вас простуда. Я выпишу вам рецепт на лекарство.
Давид: Спасибо, доктор. Сколько дней мне нужно сидеть дома?
Врач: Два-три дня. Пейте много воды и отдыхайте.', '[{"he": "כְּאֵב רֹאשׁ", "ru": "головная боль", "translit": "кеЭв рош"}, {"he": "חוֹם", "ru": "температура / жар", "translit": "хом"}, {"he": "גָּרוֹן", "ru": "горло", "translit": "гарОн"}, {"he": "הַצְטַנְּנוּת", "ru": "простуда", "translit": "hицтаненУт"}, {"he": "מִרְשָׁם", "ru": "рецепт", "translit": "миршАм"}, {"he": "תְּרוּפָה", "ru": "лекарство", "translit": "труфА"}]', NULL, 'dialog');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (31, 2, 'הַדִּירָה הַחֲדָשָׁה', 'Новая квартира', 'הַשָּׁבוּעַ עָבַרְנוּ לְדִירָה חֲדָשָׁה. הַדִּירָה נִמְצֵאת בְּקוֹמָה הַשְּׁלִישִׁית. יֵשׁ בָּהּ שְׁלוֹשָׁה חֲדָרִים, מִטְבָּח, סָלוֹן וְחֲדַר אַמְבַּטְיָה. הַסָּלוֹן גָּדוֹל וְיֵשׁ בּוֹ חַלּוֹן גָּדוֹל עִם נוֹף יָפֶה. הַמִּטְבָּח קָטָן אֲבָל נוֹחַ. שָׂמְנוּ שׁוּלְחָן חָדָשׁ וְאַרְבָּעָה כִּסְאוֹת. הַחֶדֶר שֶׁלִּי צָבוּעַ בְּכָחוֹל. הִכְנַסְתִּי לְשָׁם מִיטָה, שׁוּלְחָן כְּתִיבָה וַאֲרוֹן בְּגָדִים. אֲנִי מְאוֹד אוֹהֵב אֶת הַדִּירָה הַחֲדָשָׁה!', 'На этой неделе мы переехали в новую квартиру. Квартира находится на третьем этаже. В ней три комнаты, кухня, гостиная и ванная. Гостиная большая, в ней большое окно с красивым видом. Кухня маленькая, но удобная. Мы поставили новый стол и четыре стула. Моя комната покрашена в голубой цвет. Я поставил туда кровать, письменный стол и шкаф для одежды. Мне очень нравится новая квартира!', '[{"he": "דִּירָה", "ru": "квартира", "translit": "дирА"}, {"he": "קוֹמָה", "ru": "этаж", "translit": "комА"}, {"he": "מִטְבָּח", "ru": "кухня", "translit": "митбАх"}, {"he": "סָלוֹן", "ru": "гостиная", "translit": "салОн"}, {"he": "חַלּוֹן", "ru": "окно", "translit": "халОн"}, {"he": "אֲרוֹן בְּגָדִים", "ru": "шкаф для одежды", "translit": "арОн бгадИм"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (32, 2, 'בַּחוֹף הַיָּם', 'На пляже', 'אֶתְמוֹל הָלַכְנוּ לַחוֹף הַיָּם בְּתֵל אָבִיב. הַמִּזָּג אֲוִיר הָיָה חַם מְאוֹד. לָקַחְנוּ אִתָּנוּ מַגָּבוֹת, קְרֶם שֶׁמֶשׁ וְאֹכֶל. הַיָּם הָיָה כָּחוֹל וְנָקִי. הַגַּלִּים הָיוּ קְטַנִּים. שָׂחִינוּ בַּיָּם וְשִׂחַקְנוּ בְּכַדּוּר עַל הַחוֹל. אַחַר כָּךְ אָכַלְנוּ אֲבַטִּיחַ קָר וְשָׁתִינוּ מַיִם. בַּשָּׁעָה חָמֵשׁ רָאִינוּ שְׁקִיעָה יָפָה. הַשָּׁמַיִם הָיוּ כְּתוּמִּים וּוְרוּדִים. זֶה הָיָה יוֹם נֶהְדָּר.', 'Вчера мы ходили на пляж в Тель-Авиве. Погода была очень жаркая. Мы взяли с собой полотенца, солнцезащитный крем и еду. Море было синее и чистое. Волны были маленькие. Мы плавали в море и играли в мяч на песке. Потом мы ели холодный арбуз и пили воду. В пять часов мы увидели красивый закат. Небо было оранжевым и розовым. Это был замечательный день.', '[{"he": "חוֹף הַיָּם", "ru": "пляж", "translit": "хоф hаЯм"}, {"he": "מַגָּבוֹת", "ru": "полотенца", "translit": "магавОт"}, {"he": "גַּלִּים", "ru": "волны", "translit": "галИм"}, {"he": "חוֹל", "ru": "песок", "translit": "холь"}, {"he": "שְׁקִיעָה", "ru": "закат", "translit": "шкиА"}, {"he": "אֲבַטִּיחַ", "ru": "арбуз", "translit": "аватИах"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (33, 3, 'הַמִּטְבָּח הַיִּשְׂרְאֵלִי', 'Израильская кухня', 'הַמִּטְבָּח הַיִּשְׂרְאֵלִי הוּא שִׁלּוּב מְרַתֵּק שֶׁל מִטְבְּחֵי עוֹלָם רַבִּים. כְּמָדִינָה שֶׁל עוֹלִים, יִשְׂרָאֵל קִבְּלָה הַשְׁפָּעוֹת מִכָּל מָקוֹם: מֵאֵירוֹפָּה, מִצְּפוֹן אַפְרִיקָה, מֵהַמִּזְרָח הַתִּיכוֹן וּמֵאַסְיָה. הַמָּנוֹת הַפּוֹפוּלָרִיּוֹת בְּיוֹתֵר הֵן חוּמוּס, פְלָאפֶל, שַׁקְשׁוּקָה וּסָלָט יִשְׂרְאֵלִי. ארוּחַת הַבֹּקֶר הַיִּשְׂרְאֵלִית מְפוּרְסֶמֶת בְּכָל הָעוֹלָם. הִיא כּוֹלֶלֶת בֵּיצִים, סָלָט יְרָקוֹת, לֶחֶם, גְּבִינוֹת וְזֵיתִים. בִּשְׁנוֹת הָאַחֲרוֹנוֹת, יֵשׁ גַּם הַרְבֵּה מִסְעָדוֹת טִבְעוֹנִיּוֹת. תֵּל אָבִיב נֶחְשֶׁבֶת לְאַחַת מֵעָרֵי הַטִּבְעוֹנוּת הַמּוֹבִילוֹת בָּעוֹלָם. הַמִּטְבָּח הַיִּשְׂרְאֵלִי מְשַׁקֵּף אֶת הַגִּוּוּן הַתַּרְבּוּתִי שֶׁל הַמְּדִינָה.', 'Израильская кухня -- это увлекательное сочетание кухонь разных стран мира. Как страна иммигрантов, Израиль получил влияние отовсюду: из Европы, Северной Африки, Ближнего Востока и Азии. Самые популярные блюда -- хумус, фалафель, шакшука и израильский салат. Израильский завтрак знаменит во всём мире. Он включает яйца, салат из овощей, хлеб, сыры и оливки. В последние годы появилось много веганских ресторанов. Тель-Авив считается одним из ведущих веганских городов мира. Израильская кухня отражает культурное разнообразие страны.', '[{"he": "שִׁלּוּב", "ru": "сочетание", "translit": "шилУв"}, {"he": "עוֹלִים", "ru": "иммигранты (в Израиль)", "translit": "олИм"}, {"he": "הַשְׁפָּעוֹת", "ru": "влияния", "translit": "hашпаОт"}, {"he": "מָנוֹת", "ru": "блюда", "translit": "манОт"}, {"he": "טִבְעוֹנִיּוֹת", "ru": "веганские", "translit": "тивъонийОт"}, {"he": "גִּוּוּן", "ru": "разнообразие", "translit": "гивУн"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (34, 3, 'לִלְמֹד בְּיִשְׂרָאֵל', 'Учёба в Израиле', 'כְּשֶׁהִגַּעְתִּי לְיִשְׂרָאֵל לִפְנֵי שְׁלוֹשׁ שָׁנִים, לֹא יָדַעְתִּי עִבְרִית בִּכְלָל. הִתְחַלְתִּי לִלְמֹד בְּאוּלְפָּן. בַּהַתְחָלָה הָיָה קָשֶׁה מְאוֹד. לֹא הֵבַנְתִּי אֶת הַמּוֹרָה וְלֹא יָכֹלְתִּי לִקְרֹא אֶת הָאוֹתִיּוֹת. אֲבָל כָּל יוֹם תִּרְגַּלְתִּי. קָרָאתִי עִתּוֹנִים, שָׁמַעְתִּי שִׁירִים בְּעִבְרִית וְנִסִּיתִי לְדַבֵּר עִם אֲנָשִׁים בַּחֲנוּת וּבָרְחוֹב. אַחֲרֵי שָׁנָה הִרְגַּשְׁתִּי שֶׁאֲנִי מַתְחִיל לְהָבִין. הַיּוֹם אֲנִי לוֹמֵד בָּאוּנִיבֶרְסִיטָה וְכוֹתֵב עֲבוֹדוֹת בְּעִבְרִית. זֶה לֹא הָיָה קַל, אֲבָל הַמַּסָּע הָיָה שָׁוֶה.', 'Когда я приехал в Израиль три года назад, я совсем не знал иврит. Я начал учиться в ульпане. В начале было очень трудно. Я не понимал учительницу и не мог читать буквы. Но каждый день я практиковался. Я читал газеты, слушал песни на иврите и пытался разговаривать с людьми в магазине и на улице. Через год я почувствовал, что начинаю понимать. Сегодня я учусь в университете и пишу работы на иврите. Это было нелегко, но путь того стоил.', '[{"he": "בִּכְלָל", "ru": "вообще / совсем", "translit": "бихлАль"}, {"he": "הַתְחָלָה", "ru": "начало", "translit": "hатхалА"}, {"he": "אוֹתִיּוֹת", "ru": "буквы", "translit": "отийОт"}, {"he": "תִּרְגַּלְתִּי", "ru": "я практиковался", "translit": "тиргАльти"}, {"he": "עִתּוֹנִים", "ru": "газеты", "translit": "итонИм"}, {"he": "מַסָּע", "ru": "путешествие / путь", "translit": "масА"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (35, 3, 'חַגִּים בְּיִשְׂרָאֵל', 'Праздники в Израиле', 'בְּיִשְׂרָאֵל חוֹגְגִים חַגִּים רַבִּים לְאוֹרֶךְ הַשָּׁנָה. רֹאשׁ הַשָּׁנָה הוּא הַחַג שֶׁפּוֹתֵחַ אֶת הַשָּׁנָה הָעִבְרִית. אוֹכְלִים תַּפּוּחַ בִּדְבַשׁ וּמְאַחֲלִים שָׁנָה טוֹבָה. עֲשָׂרָה יָמִים אַחַר כָּךְ מַגִּיעַ יוֹם כִּפּוּר, יוֹם הַצּוֹם. הַכְּבִישִׁים רֵיקִים וְהָאֲוִירָה שֶׁקֵטָה. סוּכּוֹת הוּא חַג שָׂמֵחַ שֶׁבּוֹ בּוֹנִים סוּכָּה וְאוֹכְלִים בָּהּ. חֲנוּכָּה הוּא חַג הָאוֹרוֹת. מַדְלִיקִים נֵרוֹת וְאוֹכְלִים סוּפְגָּנִיּוֹת. פּוּרִים הוּא חַג שֶׁבּוֹ מִתְחַפְּשִׂים. הַיְּלָדִים שְׂמֵחִים בְּמִיוּחָד בַּחַג הַזֶּה. פֶּסַח הוּא חַג הַחֵרוּת. הַמִּשְׁפָּחָה מִתְאַסֶּפֶת לְסֵדֶר פֶּסַח וּמְסַפֶּרֶת אֶת סִפּוּר יְצִיאַת מִצְרָיִם.', 'В Израиле отмечают много праздников в течение года. Рош а-Шана -- это праздник, который открывает еврейский новый год. Едят яблоко с мёдом и желают хорошего года. Через десять дней наступает Йом Кипур, день поста. Дороги пустые и атмосфера тихая. Суккот -- весёлый праздник, когда строят шалаш и едят в нём. Ханука -- праздник огней. Зажигают свечи и едят пончики. Пурим -- праздник, когда наряжаются в костюмы. Дети особенно радуются этому празднику. Песах -- праздник свободы. Семья собирается на пасхальный седер и рассказывает историю исхода из Египта.', '[{"he": "חַגִּים", "ru": "праздники", "translit": "хагИм"}, {"he": "דְבַשׁ", "ru": "мёд", "translit": "двАш"}, {"he": "צוֹם", "ru": "пост", "translit": "цом"}, {"he": "סוּכָּה", "ru": "шалаш (сукка)", "translit": "сукА"}, {"he": "נֵרוֹת", "ru": "свечи", "translit": "нерОт"}, {"he": "חֵרוּת", "ru": "свобода", "translit": "херУт"}, {"he": "יְצִיאַת מִצְרָיִם", "ru": "исход из Египта", "translit": "ециАт мицрАим"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (36, 4, 'הַהַיְטֶק הַיִּשְׂרְאֵלִי', 'Высокие технологии в Израиле', 'יִשְׂרָאֵל מוּכֶּרֶת בְּכָל הָעוֹלָם כְּ"אוּמַּת הַסְטָארְטְאַפּ". לְמֶדִינָה קְטַנָּה עִם תִּשְׁעָה מִילְיוֹן תּוֹשָׁבִים יֵשׁ אֶחָד מֵהַרִּכּוּזִים הַגְּדוֹלִים בְּיוֹתֵר שֶׁל חֶבְרוֹת הַיְטֶק בָּעוֹלָם. הַתְּעַשְׂיָה הַטֶּכְנוֹלוֹגִית הִתְפַּתְּחָה בִּזְכוּת מִסְפַּר גּוֹרְמִים: מַעֲרֶכֶת חִנּוּךְ חֲזָקָה, שֵׁרוּת צְבָאִי שֶׁמְּפַתֵּחַ מְיוּמָנוּיוֹת טֶכְנוֹלוֹגִיּוֹת וְתַרְבּוּת שֶׁל יְזָמוּת וְחִדּוּשׁ. חֶבְרוֹת בֵּינְלְאוּמִיּוֹת גְּדוֹלוֹת כְּמוֹ גּוּגְל, מַיְקְרוֹסוֹפְט וְאַפֶּל פָּתְחוּ מֶרְכְּזֵי פִּיתּוּחַ בְּיִשְׂרָאֵל. הָעִיר תֵּל אָבִיב הִיא הַמֶּרְכָּז הָעִקָּרִי שֶׁל תַּעֲשִׂיַּת הַהַיְטֶק. אֲזוֹר "עֵמֶק הַסִּילִיקוֹן" הַיִּשְׂרְאֵלִי, הַיָּדוּעַ גַּם כְּ"וָאדִי סִילִיקוֹן", מְרַכֵּז אֶלְפֵי חֶבְרוֹת סְטָארְטְאַפּ. בַּתְּחוּמִים שֶׁל סֵייבֶּר, בִּינָה מְלַאכּוּתִית וְטֶכְנוֹלוֹגִיָּה רְפוּאִית יִשְׂרָאֵל נִמְצֵאת בַּחֲזִית הַעוֹלָמִית.', 'Израиль известен во всём мире как "стартап-нация". У маленькой страны с девятью миллионами жителей одна из крупнейших концентраций высокотехнологичных компаний в мире. Технологическая отрасль развилась благодаря нескольким факторам: сильная система образования, военная служба, которая развивает технологические навыки, и культура предпринимательства и инноваций. Крупные международные компании, такие как Google, Microsoft и Apple, открыли центры разработки в Израиле. Город Тель-Авив является главным центром хайтек-индустрии. Израильская "Кремниевая долина", известная также как "Кремниевое вади", объединяет тысячи стартап-компаний. В областях кибербезопасности, искусственного интеллекта и медицинских технологий Израиль находится на мировом передовом крае.', '[{"he": "סְטָארְטְאַפּ", "ru": "стартап", "translit": "стартАп"}, {"he": "רִכּוּז", "ru": "концентрация", "translit": "рикУз"}, {"he": "תְּעַשְׂיָה", "ru": "промышленность", "translit": "теасиА"}, {"he": "יְזָמוּת", "ru": "предпринимательство", "translit": "езамУт"}, {"he": "חִדּוּשׁ", "ru": "инновация", "translit": "хидУш"}, {"he": "בִּינָה מְלַאכּוּתִית", "ru": "искусственный интеллект", "translit": "бинА мелахутИт"}, {"he": "חֲזִית", "ru": "передовой край / фронт", "translit": "хазИт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (37, 4, 'מַשְׁבַּר הַמַּיִם וְהַפִּתְרוֹנוֹת', 'Водный кризис и решения', 'יִשְׂרָאֵל הִיא מְדִינָה שֶׁנִּמְצֵאת בֵּאֵזוֹר צָחִיחַ לְמַדָּי. מָשַׁבַּר הַמַּיִם הִתְחִיל כְּבָר בִּשְׁנוֹת הַחֲמִשִּׁים שֶׁל הַמֵּאָה הָעֶשְׂרִים. הָאֻכְלוֹסִיָּה גָּדְלָה, אֲבָל מְקוֹרוֹת הַמַּיִם נִשְׁאֲרוּ מוּגְבָּלִים. כְּדֵי לְהִתְמוֹדֵד עִם הַבְּעָיָה, יִשְׂרָאֵל פִּתְּחָה טֶכְנוֹלוֹגִיּוֹת מַיִם חֲדָשָׁנִיּוֹת. הַטַּפְטֵפֶת, שֶׁהוּמְצְאָה בְּיִשְׂרָאֵל, חוֹלְלָה מַהְפֵּכָה בְּהַשְׁקָאָה חַקְלָאִית בְּכָל הָעוֹלָם. הִיא מְאַפְשֶׁרֶת לְהַשְׁקוֹת צְמָחִים בִּכְמוּת מַיִם מִינִימָלִית. בְּנוֹסָף, יִשְׂרָאֵל בָּנְתָה מַתְקְנֵי הַתְפָּלָה גְּדוֹלִים שֶׁמְּמִירִים מֵי יָם לְמֵי שְׁתִיָּה. כַּיּוֹם, יוֹתֵר מִשִּׁשִּׁים אָחוּז מִמֵּי הַשְּׁתִיָּה בְּיִשְׂרָאֵל מַגִּיעִים מֵהַתְפָּלָה. גַּם מַיִם מְמוּחְזָרִים מְשַׁמְּשִׁים לְהַשְׁקָאָה חַקְלָאִית.', 'Израиль -- страна, расположенная в довольно засушливом регионе. Водный кризис начался ещё в пятидесятых годах двадцатого века. Население росло, но источники воды оставались ограниченными. Чтобы справиться с проблемой, Израиль разработал инновационные водные технологии. Капельное орошение, изобретённое в Израиле, произвело революцию в сельскохозяйственном поливе во всём мире. Оно позволяет поливать растения минимальным количеством воды. Кроме того, Израиль построил крупные опреснительные установки, которые превращают морскую воду в питьевую. Сегодня более шестидесяти процентов питьевой воды в Израиле получают из опреснения. Также переработанная вода используется для сельскохозяйственного полива.', '[{"he": "צָחִיחַ", "ru": "засушливый", "translit": "цахИах"}, {"he": "מַשְׁבָּר", "ru": "кризис", "translit": "машбАр"}, {"he": "טַפְטֵפֶת", "ru": "капельное орошение", "translit": "тафтЕфет"}, {"he": "הַשְׁקָאָה", "ru": "орошение / полив", "translit": "hашкаА"}, {"he": "הַתְפָּלָה", "ru": "опреснение", "translit": "hатпалА"}, {"he": "מְמוּחְזָרִים", "ru": "переработанные", "translit": "мемухзарИм"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (38, 4, 'תַּחְבּוּרָה צִיבּוּרִית בְּיִשְׂרָאֵל', 'Общественный транспорт в Израиле', 'מַעֲרֶכֶת הַתַּחְבּוּרָה הַצִּיבּוּרִית בְּיִשְׂרָאֵל עוֹבֶרֶת שִׁנּוּיִים מַשְׁמָעוּתִיִּים בַּשָּׁנִים הָאַחֲרוֹנוֹת. הָאוֹטוֹבּוּסִים הֵם עֲדַיִין אֶמְצָעִי הַתַּחְבּוּרָה הַמֶּרְכָּזִי בְּרֹב הָעָרִים. חֶבְרוֹת כְּמוֹ "אֶגֶד" וְ"דַּן" מְפָעִילוֹת קַוִּים בְּכָל הָאָרֶץ. הָרַכֶּבֶת חוֹצָה אֶת הָאָרֶץ מִצָּפוֹן לְדָרוֹם וּמְחַבֶּרֶת אֶת הֶעָרִים הָעִקָּרִיּוֹת. בִּירוּשָׁלַיִם פּוֹעֵל קַו רַכֶּבֶת קַלָּה שֶׁעוֹבֵר בְּמֶרְכַּז הָעִיר. בַּגּוּשׁ דָּן הוּשְׁקָה הָרַכֶּבֶת הַקַּלָּה הַחֲדָשָׁה, הַקַּו הָאָדֹם. מֵידָה חֲשׁוּבָה שֶׁצָּרִיךְ לָדַעַת: בְּשַׁבָּת הַתַּחְבּוּרָה הַצִּיבּוּרִית אֵינָהּ פּוֹעֶלֶת בְּרוֹב חֲלָקֵי הָאָרֶץ, אִם כִּי בַּשָּׁנִים הָאַחֲרוֹנוֹת הוּחַל בְּהַפְעָלַת קַוִּים בְּשַׁבָּת בְּעָרִים מְסוּיָּמוֹת. כַּרְטִיס "רַב-קַו" מְשַׁמֵּשׁ לְתַשְׁלוּם בְּכָל אֶמְצָעֵי הַתַּחְבּוּרָה.', 'Система общественного транспорта в Израиле переживает значительные изменения в последние годы. Автобусы по-прежнему являются основным средством транспорта в большинстве городов. Компании вроде "Эгед" и "Дан" обслуживают маршруты по всей стране. Поезд пересекает страну с севера на юг и соединяет основные города. В Иерусалиме работает линия легкорельсового транспорта, проходящая через центр города. В районе Гуш-Дан запущен новый легкорельсовый транспорт, Красная линия. Важная деталь, которую нужно знать: по субботам общественный транспорт не работает в большинстве районов страны, хотя в последние годы начали запускать субботние маршруты в некоторых городах. Карта "Рав-Кав" используется для оплаты во всех видах транспорта.', '[{"he": "תַּחְבּוּרָה צִיבּוּרִית", "ru": "общественный транспорт", "translit": "тахбурА цибурИт"}, {"he": "שִׁנּוּיִים", "ru": "изменения", "translit": "шинуйИм"}, {"he": "רַכֶּבֶת", "ru": "поезд", "translit": "ракЕвет"}, {"he": "רַכֶּבֶת קַלָּה", "ru": "легкорельсовый транспорт", "translit": "ракЕвет калА"}, {"he": "כַּרְטִיס", "ru": "билет / карта", "translit": "картИс"}, {"he": "תַשְׁלוּם", "ru": "оплата", "translit": "ташлУм"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (39, 5, 'תְּחִיַּת הַלָּשׁוֹן הָעִבְרִית', 'Возрождение иврита', 'תְּחִיַּת הַלָּשׁוֹן הָעִבְרִית הִיא אַחַד הָאֵרוּעִים הַמַּפְלִיאִים בְּתוֹלְדוֹת הַלְּשׁוֹנוֹת הָאֱנוֹשִׁיּוֹת. בְּמֶשֶׁךְ כְּאֶלְפַּיִם שָׁנָה, הָעִבְרִית שִׁמְּשָׁה בְּעִקָּר כִּלְשׁוֹן תְּפִלָּה וְסִפְרוּת, בְּעוֹד שֶׁהַיְּהוּדִים דִּבְּרוּ שְׂפוֹת מָקוֹמִיּוֹת כְּמוֹ יִדִּישׁ, לָאדִינוֹ וַעֲרָבִית. אֱלִיעֶזֶר בֶּן־יְהוּדָה, שֶׁעָלָה לְאֶרֶץ יִשְׂרָאֵל בְּ-1881, הִקְדִּישׁ אֶת חַיָּיו לְהָפְכָהּ שֶׁל הָעִבְרִית לִשְׂפַת דִּבּוּר יוֹמְיוֹמִית. הוּא יָצַר אֲלָפֵי מִלִּים חֲדָשׁוֹת עֲבוּר מוּשָׂגִים מוֹדֶרְנִיִּים שֶׁלֹּא הָיוּ קַיָּמִים בַּלָּשׁוֹן הָעַתִּיקָה. בְּנוֹ, בֶּן צִיּוֹן בֶּן־יְהוּדָה, הָיָה הַיֶּלֶד הָרִאשׁוֹן שֶׁגָּדַל עִם עִבְרִית כִּשְׂפַת אֵם. הָאוּלְפָּנִים שֶׁהוּקְמוּ בְּתְקוּפַת הָעֲלִיּוֹת סִיְּעוּ לְעוֹלִים רַבִּים לִרְכֹּשׁ אֶת הַשָּׂפָה. הַיּוֹם הָעִבְרִית הִיא שְׂפָתָם שֶׁל כְּעִשְׂרָה מִילְיוֹן דּוֹבְרִים, וְהָאָקָדֶמְיָה לַלָּשׁוֹן הָעִבְרִית מַמְשִׁיכָה לִפְתֵּחַ אֶת הַלָּשׁוֹן וּלְהַתְאִימָהּ לַעוֹלָם הַמּוֹדֶרְנִי.', 'Возрождение иврита -- одно из самых поразительных событий в истории человеческих языков. В течение примерно двух тысяч лет иврит служил в основном языком молитвы и литературы, в то время как евреи говорили на местных языках: идише, ладино, арабском. Элиэзер Бен-Иегуда, приехавший в Эрец-Исраэль в 1881 году, посвятил свою жизнь превращению иврита в повседневный разговорный язык. Он создал тысячи новых слов для современных понятий, которых не существовало в древнем языке. Его сын, Бен-Цион Бен-Иегуда, стал первым ребёнком, выросшим с ивритом как родным языком. Ульпаны, созданные в период алии, помогли многим иммигрантам освоить язык. Сегодня иврит является языком примерно десяти миллионов носителей, а Академия языка иврит продолжает развивать язык и адаптировать его к современному миру.', '[{"he": "תְּחִיָּה", "ru": "возрождение", "translit": "тхиЯ"}, {"he": "מַפְלִיא", "ru": "поразительный", "translit": "мафлИ"}, {"he": "תְּפִלָּה", "ru": "молитва", "translit": "тфилА"}, {"he": "הִקְדִּישׁ", "ru": "посвятил", "translit": "hикдИш"}, {"he": "מוּשָׂגִים", "ru": "понятия / концепции", "translit": "мусагИм"}, {"he": "רָכַשׁ", "ru": "приобрёл / освоил", "translit": "рахАш"}, {"he": "אָקָדֶמְיָה", "ru": "академия", "translit": "академИя"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (40, 5, 'יָם הַמֶּלַח — פֶּלֶא הַטֶּבַע', 'Мёртвое море -- чудо природы', 'יָם הַמֶּלַח הוּא הַנְּקוּדָה הַנְּמוּכָה בְּיוֹתֵר עַל פְּנֵי כַּדּוּר הָאָרֶץ, כְּאַרְבַּע מֵאוֹת שְׁלוֹשִׁים מֶטֶר מִתַּחַת לְפְנֵי הַיָּם. שִׁמְעוֹ בְּעִבְרִית, "יָם הַמֶּלַח", רוֹמֵז עַל הַמֶּלַח הָרַב שֶׁבְּמֵימָיו. רִכּוּז הַמֶּלַח בְּיָם הַמֶּלַח גָּבוֹהַּ פִּי עֲשָׂרָה מֵהַיָּם הַתִּיכוֹן, מָה שֶׁמְּאַפְשֵׁר לְכָל אָדָם לִצּוּף עַל פְּנֵי הַמַּיִם בְּלִי מַאֲמָץ. הַמִּינֵרָלִים שֶׁבְּיָם הַמֶּלַח מְשַׁמְּשִׁים בִּתְעַשְׂיַּת הַקּוֹסְמֵטִיקָה, וּמוּצְרֵי יָם הַמֶּלַח מְיוּצָּאִים לְכָל הָעוֹלָם. עִם זֹאת, יָם הַמֶּלַח מִתְכַּוְּוץ בִּקְצָב מַדְאִיג. מִפְלַס הַמַּיִם יוֹרֵד כְּמֶטֶר בְּכָל שָׁנָה, בְּעִקָּר בִּגְלַל הַפְנָיַת מֵי הַיַּרְדֵּן לְצָרְכֵי חַקְלָאוּת. בּוֹלְעָנִים מַגִּיחִים לְאוֹרֶךְ הַחוֹפִים. מָדְעָנִים וּמְדִינַיִם מְחַפְּשִׂים פִּתְרוֹנוֹת לְשִׁמּוּר הַמָּקוֹם הַמַּפְלִיא הַזֶּה לַדּוֹרוֹת הַבָּאִים.', 'Мёртвое море -- самая низкая точка на поверхности Земли, примерно четыреста тридцать метров ниже уровня моря. Его название на иврите, "Ям а-Мелах" (Солёное море), указывает на высокое содержание соли. Концентрация соли в Мёртвом море в десять раз выше, чем в Средиземном, что позволяет любому человеку без усилий держаться на поверхности воды. Минералы Мёртвого моря используются в косметической промышленности, и продукция Мёртвого моря экспортируется по всему миру. Однако Мёртвое море сокращается с тревожной скоростью. Уровень воды падает примерно на метр каждый год, главным образом из-за отвода вод Иордана для нужд сельского хозяйства. Вдоль берегов появляются провалы грунта. Учёные и политики ищут решения для сохранения этого удивительного места для будущих поколений.', '[{"he": "נְקוּדָה", "ru": "точка", "translit": "некудА"}, {"he": "רִכּוּז", "ru": "концентрация", "translit": "рикУз"}, {"he": "לִצּוּף", "ru": "плавать на поверхности", "translit": "лицУф"}, {"he": "מִינֵרָלִים", "ru": "минералы", "translit": "минералИм"}, {"he": "מִתְכַּוְּוץ", "ru": "сокращается", "translit": "миткавЕц"}, {"he": "בּוֹלְעָנִים", "ru": "провалы грунта", "translit": "больанИм"}, {"he": "שִׁמּוּר", "ru": "сохранение", "translit": "шимУр"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (41, 5, 'רַב־לְשׁוֹנִיּוּת בְּיִשְׂרָאֵל', 'Многоязычие в Израиле', 'לְמָרוֹת שֶׁהָעִבְרִית הִיא הַשָּׂפָה הָרִשְׁמִית הָעִקָּרִית שֶׁל מְדִינַת יִשְׂרָאֵל, הַמְּצִיאוּת הַלְּשׁוֹנִית בָּאָרֶץ הִיא מוּרְכֶּבֶת הַרְבֵּה יוֹתֵר. כִּמְעַט עֶשְׂרִים אָחוּז מֵהָאוּכְלוֹסִיָּה הֵם עֲרָבִים יִשְׂרְאֵלִים שֶׁדּוֹבְרִים עֲרָבִית כִּשְׂפַת אֵם. עַד 2018, הָעֲרָבִית הָיְתָה שָׂפָה רִשְׁמִית לְצַד הָעִבְרִית. גַּלֵּי הָעֲלִיָּה הֵבִיאוּ אִתָּם שְׂפוֹת מִכָּל הָעוֹלָם. הָרוּסִית הִיא הַשָּׂפָה הַנְּפוּצָה בְּיוֹתֵר אַחֲרֵי עִבְרִית וַעֲרָבִית, עִם כְּמִילְיוֹן דּוֹבְרִים שֶׁהִגִּיעוּ בְּעֶשְׂרִים הַשָּׁנִים הָאַחֲרוֹנוֹת. אַמְהָרִית מְדוּבֶּרֶת בְּקֶרֶב יוֹצְאֵי אֶתְיוֹפְּיָה, וְצָרְפָתִית נְפוּצָה בֵּין עוֹלֵי צָרְפַת וְצְפוֹן אַפְרִיקָה. הָאַנְגְלִית מְמַלֵּאת תַּפְקִיד חָשׁוּב כִּשְׂפָה בֵּינְלְאוּמִית וּמְלוּוָּה אֶת הַחַיִּים הַצִּבּוּרִיִּים: שְׁלָטִים, הוֹדָעוֹת וּמִסְמָכִים רִשְׁמִיִּים לְעִתִּים קְרוֹבוֹת מוֹפִיעִים בִּשְׁלוֹשׁ שְׂפוֹת: עִבְרִית, עֲרָבִית וְאַנְגְלִית. רַב־לְשׁוֹנִיּוּת זוֹ מַעֲשִׁירָה אֶת הַתַּרְבּוּת אַךְ גַּם מַצִּיבָה אֶתְגָּרִים חִנּוּכִיִּים.', 'Несмотря на то что иврит является основным официальным языком государства Израиль, языковая реальность в стране гораздо сложнее. Почти двадцать процентов населения -- израильские арабы, для которых арабский язык является родным. До 2018 года арабский был официальным языком наряду с ивритом. Волны иммиграции принесли с собой языки со всего мира. Русский -- самый распространённый язык после иврита и арабского, с примерно миллионом носителей, приехавших за последние двадцать лет. Амхарский распространён среди выходцев из Эфиопии, а французский -- среди иммигрантов из Франции и Северной Африки. Английский играет важную роль как международный язык и сопровождает общественную жизнь: вывески, объявления и официальные документы часто появляются на трёх языках: иврите, арабском и английском. Это многоязычие обогащает культуру, но также ставит образовательные вызовы.', '[{"he": "רַב־לְשׁוֹנִיּוּת", "ru": "многоязычие", "translit": "рав-лешонийУт"}, {"he": "רִשְׁמִית", "ru": "официальная", "translit": "ришмИт"}, {"he": "מוּרְכֶּבֶת", "ru": "сложная", "translit": "муркЕвет"}, {"he": "גַּלֵּי עֲלִיָּה", "ru": "волны иммиграции", "translit": "галЕй алиЯ"}, {"he": "נְפוּצָה", "ru": "распространённая", "translit": "нефуцА"}, {"he": "שְׁלָטִים", "ru": "вывески / знаки", "translit": "шлатИм"}, {"he": "אֶתְגָּרִים", "ru": "вызовы", "translit": "этгарИм"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (42, 6, 'פִילוֹסוֹפְיַת הַדּוּ-שִׂיחַ שֶׁל מַרְטִין בּוּבֶּר', 'Философия диалога Мартина Бубера', 'מַרְטִין בּוּבֶּר (1878-1965) הָיָה פִילוֹסוֹף יְהוּדִי-אוֹסְטְרִי שֶׁנֶּחְשָׁב לְאַחַד מֵהוֹגֵי הַדֵּעוֹת הַמַּשְׁפִּיעִים בְּיוֹתֵר שֶׁל הַמֵּאָה הָעֶשְׂרִים. סִפְרוֹ הַמַּכּוֹנֵן, "אֲנִי וְאַתָּה" (Ich und Du), שֶׁפּוּרְסָם בְּ-1923, הִצִּיג אֶת הָרַעְיוֹן שֶׁל יַחֲסֵי "אֲנִי-אַתָּה" מוּל "אֲנִי-זֶה". לְפִי בּוּבֶּר, כַּאֲשֶׁר אָדָם פּוֹנֶה לְזוּלָתוֹ כְּ"אַתָּה" — כְּלוֹמַר, בִּשְׁלֵמוּתוֹ כְּסוּבְּיֶקְט — נוֹצָר מָרְחָב שֶׁל פְּגִישָׁה אוֹתֶנְטִית. לְעוּמַּת זֹאת, כַּאֲשֶׁר אָדָם מִתְיַחֵס לְזוּלָתוֹ כְּ"זֶה" — כְּעֶצֶם שֶׁאֶפְשָׁר לְנַתְּחוֹ, לְסַוְּגוֹ וּלְנַצְּלוֹ — הַקֶּשֶׁר מִתְרוֹקֵן מִתָּכְנוֹ הָאֱנוֹשִׁי. בּוּבֶּר טָעַן שֶׁגַּם הַמִּפְגָּשׁ עִם הָאֱלֹהִי הוּא מִפְגָּשׁ שֶׁל "אֲנִי-אַתָּה": אֵין לְהַשִּׂיג אֶת הָאֱלֹהִים בְּאֶמְצָעוּת מַחֲשָׁבָה מוּפְשֶׁטֶת אֶלָּא בִּפְגִישָׁה חַיָּה. בּוּבֶּר עָלָה לְאֶרֶץ יִשְׂרָאֵל בְּ-1938 וְלִמֵּד בָּאוּנִיבֶרְסִיטָה הָעִבְרִית. הוּא תָּמַךְ בְּדּוּ-קִיּוּם יְהוּדִי-עֲרָבִי וּבַהֲקָמַת מְדִינָה דּוּ-לְאוּמִית, עֶמְדָּה שֶׁעוֹרְרָה מַחֲלוֹקֶת רַבָּה. הַגוּתוֹ מַמְשִׁיכָה לְהַשְׁפִּיעַ עַל תְּחוּמֵי הַחִנּוּךְ, הַפְּסִיכוֹלוֹגְיָה וְהַתֵּאוֹלוֹגְיָה.', 'Мартин Бубер (1878-1965) был еврейско-австрийским философом, считающимся одним из самых влиятельных мыслителей двадцатого века. Его основополагающая книга "Я и Ты" (Ich und Du), опубликованная в 1923 году, представила идею отношений "Я-Ты" в противовес "Я-Оно". По Буберу, когда человек обращается к другому как к "Ты" -- то есть в его целостности как субъекта -- возникает пространство подлинной встречи. Напротив, когда человек относится к другому как к "Оно" -- как к объекту, который можно анализировать, классифицировать и использовать -- связь лишается человеческого содержания. Бубер утверждал, что и встреча с Божественным есть встреча "Я-Ты": Бога нельзя постичь посредством абстрактного мышления, но лишь в живой встрече. Бубер переехал в Эрец-Исраэль в 1938 году и преподавал в Еврейском университете. Он выступал за еврейско-арабское сосуществование и создание двунационального государства -- позиция, вызвавшая немалые споры. Его идеи продолжают влиять на педагогику, психологию и теологию.', '[{"he": "פִילוֹסוֹף", "ru": "философ", "translit": "филОсоф"}, {"he": "הוֹגֵי דֵּעוֹת", "ru": "мыслители", "translit": "hогЕй деОт"}, {"he": "זוּלָתוֹ", "ru": "другой / ближний", "translit": "зулатО"}, {"he": "אוֹתֶנְטִית", "ru": "подлинная", "translit": "отентИт"}, {"he": "דּוּ-קִיּוּם", "ru": "сосуществование", "translit": "ду-киЮм"}, {"he": "מַחֲלוֹקֶת", "ru": "спор / разногласие", "translit": "махлОкет"}, {"he": "הַגוּת", "ru": "учение / мысль", "translit": "hагУт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (43, 6, 'הַסִּפְרוּת הָעִבְרִית הַמּוֹדֶרְנִית', 'Современная ивритская литература', 'הַסִּפְרוּת הָעִבְרִית הַמּוֹדֶרְנִית הִתְחִילָה לְהִתְגַּבֵּשׁ בְּסוֹף הַמֵּאָה הַתְּשַׁע עֶשְׂרֵה כְּחֵלֶק מִתְּנוּעַת הַהַשְׂכָּלָה הַיְּהוּדִית. סוֹפְרִים כְּמוֹ מֶנְדֶּלֶה מוֹכֵר סְפָרִים וְחַיִּים נַחְמָן בְּיָאלִיק הִנִּיחוּ אֶת הַיְסוֹדוֹת לְסִפְרוּת עִבְרִית חִלּוֹנִית. שַׁי עַגְנוֹן, שֶׁזָּכָה בְּפֶרֶס נוֹבֵל לְסִפְרוּת בְּ-1966, יָצַר יְצִירוֹת שֶׁשּׁוֹזְרוֹת מָסוֹרֶת יְהוּדִית עִם מוֹדֶרְנִיזְם. "דּוֹר הַמְּדִינָה" — סוֹפְרִים כְּמוֹ עָמוֹס עוֹז, א. ב. יְהוֹשֻׁעַ וְיוֹרָם קָנִיּוּק — חָקְרוּ אֶת הַמֶּתָחִים שֶׁבֵּין הַפְּרָט לַחֶבְרָה הַיִּשְׂרְאֵלִית הַצְּעִירָה. עָמוֹס עוֹז, בְּרוֹמָנָיו כְּמוֹ "סִפּוּר עַל אַהֲבָה וְחוֹשֶׁךְ", הֶאֱרָה אֶת חַיֵּי הַמִּשְׁפָּחָה הַיִּשְׂרְאֵלִית עַל רֶקַע הַהִיסְטוֹרְיָה. דּוֹר חָדָשׁ שֶׁל סוֹפְרִים, בֵּינֵיהֶם אֶתְגַּר קֶרֶת וַאַיֶּלֶת גּוּנְדַּר גוֹשֶׁן, מַמְשִׁיכִים לְחַדֵּשׁ אֶת הַפְּרוֹזָה הָעִבְרִית. קֶרֶת, בְּסִפּוּרָיו הַקְּצָרִים, יָצַר סִגְנוֹן מְזוּהֶה מִיָּד: לָקוֹנִי, הוּמוֹרִיסְטִי וּמַפְתִּיעַ. הַסִּפְרוּת הָעִבְרִית שֶׁל הַיּוֹם מְשַׁקֶּפֶת חֶבְרָה מוּרְכֶּבֶת וּמְגוּוֶּנֶת וְזוֹכָה לְהַכָּרָה בֵּינְלְאוּמִית גּוֹבֶרֶת.', 'Современная ивритская литература начала формироваться в конце девятнадцатого века как часть еврейского просветительского движения (Хаскала). Писатели, такие как Менделе Мойхер Сфорим и Хаим Нахман Бялик, заложили основы светской ивритской литературы. Шай Агнон, получивший Нобелевскую премию по литературе в 1966 году, создал произведения, переплетающие еврейскую традицию с модернизмом. "Поколение государства" -- писатели вроде Амоса Оза, А. Б. Иегошуа и Йорама Каниука -- исследовали напряжение между личностью и молодым израильским обществом. Амос Оз в своих романах, таких как "Повесть о любви и тьме", освещал жизнь израильской семьи на фоне истории. Новое поколение писателей, среди них Этгар Керет и Айелет Гундар-Гошен, продолжает обновлять ивритскую прозу. Керет в своих коротких рассказах создал мгновенно узнаваемый стиль: лаконичный, юмористический и неожиданный. Современная ивритская литература отражает сложное и многообразное общество и получает всё большее международное признание.', '[{"he": "סִפְרוּת", "ru": "литература", "translit": "сифрУт"}, {"he": "הַשְׂכָּלָה", "ru": "просвещение (Хаскала)", "translit": "hаскалА"}, {"he": "חִלּוֹנִית", "ru": "светская", "translit": "хилонИт"}, {"he": "מוֹדֶרְנִיזְם", "ru": "модернизм", "translit": "модернИзм"}, {"he": "פְּרוֹזָה", "ru": "проза", "translit": "прОза"}, {"he": "לָקוֹנִי", "ru": "лаконичный", "translit": "лаконИ"}, {"he": "הַכָּרָה", "ru": "признание", "translit": "hакарА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (44, 6, 'הַמַּעֲרֶכֶת הַמִּשְׁפָּטִית בְּיִשְׂרָאֵל', 'Правовая система Израиля', 'הַמַּעֲרֶכֶת הַמִּשְׁפָּטִית בְּיִשְׂרָאֵל מְבוּסֶּסֶת עַל שִׁלּוּב שֶׁל מָקוֹרוֹת מִשְׁפָּטִיִּים מְגוּוָּנִים. מֵאָחוֹר שֶׁלְּיִשְׂרָאֵל אֵין חוּקָּה אַחַת מְקִיפָה, תַּפְקִיד זֶה מְמוּלָּא עַל יְדֵי חוּקֵי הַיְסוֹד שֶׁנֶּחְקְקוּ בִּתְקוּפוֹת שׁוֹנוֹת. בֵּית הַמִּשְׁפָּט הָעֶלְיוֹן, הַיּוֹשֵׁב בִּירוּשָׁלַיִם, מְשַׁמֵּשׁ גַּם כְּבֵית מִשְׁפָּט גָּבוֹהַּ לְצֶדֶק, הַדָּן בַּעֲתִירוֹת שֶׁל אֶזְרָחִים נֶגֶד רְשׁוּיוֹת הַמְּדִינָה. זְכוּת הָעֲתִירָה הַזֹּאת הִיא מִיוּחֶדֶת לְיִשְׂרָאֵל וּמְאַפְשֶׁרֶת לְכָל אֶזְרָח לִפְנוֹת יְשִׁירוֹת לַמִּשְׁפָּט הָעֶלְיוֹן. בְּמַהְפְּכַת הַחוּקָּה שֶׁל שְׁנוֹת הַתִּשְׁעִים, הַנָּשִׂיא אַהֲרֹן בָּרַק הִרְחִיב אֶת סַמְכוּת הַבִּיקוֹרֶת הַשִּׁפּוּטִית, מָה שֶׁאִפְשֵׁר לְבֵית הַמִּשְׁפָּט לִפְסֹל חוּקִים שֶׁסּוֹתְרִים אֶת חוּקֵי הַיְסוֹד. צַעַד זֶה עוֹרֵר וִיכּוּחַ צִבּוּרִי שֶׁלֹּא שָׁכַךְ עַד הַיּוֹם: חֲסִידֵי הָאַקְטִיבִיזְם הַשִּׁפּוּטִי רוֹאִים בּוֹ מָגֵן שֶׁל זְכוּיוֹת הָאָדָם, בְּעוֹד שֶׁמְּבַקְּרִים טוֹעֲנִים שֶׁבֵּית הַמִּשְׁפָּט חוֹרֵג מִסַּמְכוּתוֹ וּפוֹגֵעַ בְּעִקָּרוֹן הַהַפְרָדָה בֵּין הָרְשֻׁיּוֹת. הַדִּיּוּן סְבִיב מָקוֹם בֵּית הַמִּשְׁפָּט בַּדֶּמוֹקְרָטְיָה הַיִּשְׂרְאֵלִית נוֹתָר אַחַד הַנּוֹשְׂאִים הַמֶּרְכָּזִיִּים בְּשִׂיחַ הַצִּבּוּרִי.', 'Правовая система Израиля основана на сочетании разнообразных правовых источников. Поскольку у Израиля нет единой всеобъемлющей конституции, эту роль выполняют Основные законы, принятые в разные периоды. Верховный суд, заседающий в Иерусалиме, служит также Высшим судом справедливости (БАГАЦ), рассматривающим жалобы граждан против государственных органов. Это право на подачу жалобы уникально для Израиля и позволяет любому гражданину обращаться напрямую в Верховный суд. В ходе конституционной революции девяностых годов председатель суда Аарон Барак расширил полномочия судебного контроля, что позволило суду отменять законы, противоречащие Основным законам. Этот шаг вызвал общественную дискуссию, не утихающую по сей день: сторонники судебного активизма видят в нём защиту прав человека, тогда как критики утверждают, что суд выходит за пределы своих полномочий и нарушает принцип разделения властей. Дискуссия о месте суда в израильской демократии остаётся одной из центральных тем общественного дискурса.', '[{"he": "מַעֲרֶכֶת מִשְׁפָּטִית", "ru": "правовая система", "translit": "маарЕхет мишпатИт"}, {"he": "חוּקָּה", "ru": "конституция", "translit": "хукА"}, {"he": "חוּקֵי יְסוֹד", "ru": "Основные законы", "translit": "хукЕй есОд"}, {"he": "עֲתִירָה", "ru": "жалоба / петиция", "translit": "атирА"}, {"he": "בִּיקוֹרֶת שִׁפּוּטִית", "ru": "судебный контроль", "translit": "бикОрет шипутИт"}, {"he": "הַפְרָדַת רְשֻׁיּוֹת", "ru": "разделение властей", "translit": "hафрадАт решуйОт"}, {"he": "שִׂיחַ צִבּוּרִי", "ru": "общественный дискурс", "translit": "сИах цибурИ"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (91, 3, 'המטבח הישראלי', 'Израильская кухня', 'המטבח הישראלי הוא שילוב של מסורות אוכל מכל העולם. עולים מארצות שונות הביאו את המתכונים שלהם וכך נוצר מטבח עשיר ומגוון. המאכלים הפופולריים הם חומוס, פלאפל, שקשוקה וסלט ישראלי.
ארוחת הבוקר הישראלית מפורסמת בעולם. היא כוללת ביצים, סלטים, גבינות לבנות, לחם טרי וירקות חתוכים. בבתי מלון מגישים ארוחת בוקר עשירה עם עשרות מנות. הישראלים אוהבים לאכול בחוץ ובערים הגדולות יש מסעדות מכל הסוגים.
השוק הוא מקום מרכזי בתרבות האוכל. בשוק הכרמל ובשוק מחנה יהודה אפשר למצוא פירות טריים, תבלינים ואוכל מוכן. ישראלים רבים קונים בשוק כל שבוע ומעדיפים אותו על סופרמרקט כי המחירים טובים והאווירה שמחה.', 'Израильская кухня — это особое сочетание кулинарных традиций со всего мира. Репатрианты из разных стран привезли свои рецепты, и так появилась богатая и разнообразная кухня. Самые популярные блюда — хумус, фалафель, шакшука и израильский салат.
Израильский завтрак знаменит во всём мире. Он включает яйца, салаты, белые сыры, свежий хлеб и нарезанные овощи. В гостиницах подают особенно богатый завтрак с десятками различных блюд. Израильтяне очень любят есть на улице, и в крупных городах есть рестораны всех видов.
Рынок — центральное место в культуре еды. На рынке Кармель в Тель-Авиве и на рынке Махане Иегуда в Иерусалиме можно найти свежие фрукты, специи, сладости и готовую еду. Многие израильтяне покупают на рынке каждую неделю и предпочитают его супермаркету, потому что цены лучше, а атмосфера живая и радостная.', '[{"he": "מטבח", "ru": "кухня", "translit": "митбАх"}, {"he": "מתכון", "ru": "рецепт", "translit": "маткОн"}, {"he": "חומוס", "ru": "хумус", "translit": "хУмус"}, {"he": "פלאפל", "ru": "фалафель", "translit": "фалАфель"}, {"he": "שקשוקה", "ru": "шакшука", "translit": "шакшУка"}, {"he": "תבלין", "ru": "специя / приправа", "translit": "тавлИн"}, {"he": "ארוחת בוקר", "ru": "завтрак", "translit": "арухАт бОкер"}, {"he": "שוק", "ru": "рынок", "translit": "шук"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (119, 4, 'מערכת המשפט', 'Правовая система', 'מערכת המשפט בישראל מבוססת על שלושה דרגות: בתי משפט שלום, מחוזיים ועליון. בית המשפט העליון משמש גם כבג"ץ — בית המשפט הגבוה לצדק. שופטים ממונים על ידי ועדת מינויים. לכל אזרח זכות ייצוג משפטי. מערכת המשפט מהווה את אחד מעמודי התווך של הדמוקרטיה הישראלית. היא אחראית על שמירת חוקי היסוד.', 'Правовая система Израиля основана на трёх инстанциях: мировые суды, окружные и Верховный. Верховный суд также служит как БАГАЦ — Высший суд справедливости. Судьи назначаются комиссией по назначениям. Каждый гражданин имеет право на юридическое представительство. Судебная система — один из столпов израильской демократии. Она отвечает за соблюдение основных законов.', '[{"word": "מערכת המשפט", "translation": "судебная система", "transliteration": "маарЕхет hа-мишпАт"}, {"word": "שופטים", "translation": "судьи", "transliteration": "шофтИм"}, {"word": "דמוקרטיה", "translation": "демократия", "transliteration": "демокрАтия"}, {"word": "ייצוג", "translation": "представительство", "transliteration": "ицУг"}, {"word": "בג\"ץ", "translation": "БАГАЦ", "transliteration": "бАгац"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (120, 4, 'נוף התקשורת', 'Медиа-ландшафт', 'התקשורת בישראל מגוונת ודינאמית. יש ערוצי טלוויזיה ממלכתיים ומסחריים. רדיו גלי צה"ל הוא הפופולרי ביותר. עיתונים כמו הארץ וידיעות אחרונות משפיעים על דעת הקהל. בשנים האחרונות, תקשורת דיגיטלית צומחת במהירות. אתרי חדשות ופודקאסטים הפכו למקורות מידע עיקריים.', 'Медиа в Израиле разнообразны и динамичны. Есть государственные и коммерческие телеканалы. Радио Галей ЦАХАЛ — самое популярное. Газеты как Haaretz и Yediot Aharonot влияют на общественное мнение. В последние годы цифровые медиа быстро растут. Новостные сайты и подкасты стали основными источниками информации.', '[{"word": "תקשורת", "translation": "СМИ/коммуникация", "transliteration": "тикшОрет"}, {"word": "ערוצים", "translation": "каналы", "transliteration": "аруцИм"}, {"word": "עיתונים", "translation": "газеты", "transliteration": "итонИм"}, {"word": "דיגיטלית", "translation": "цифровой", "transliteration": "дигитАлит"}, {"word": "דעת הקהל", "translation": "общественное мнение", "transliteration": "даАт hа-каhАль"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (121, 4, 'פסיכולוגיה ורגשות בישראל', 'Психология и эмоции', 'הפסיכולוגיה תופסת מקום מרכזי בחברה הישראלית. בארץ שבה כל אזרח חייב בשירות צבאי, ורבים חווים מתחים ביטחוניים מתמשכים, הצורך בתמיכה נפשית הוא עניין של יומיום.
תופעת הפוסט-טראומה זוכה בשנים האחרונות לתשומת לב רבה. מחקרים מראים כי כעשרים אחוז מהחיילים המשוחררים חווים תסמינים של חרדה או דיכאון. הצבא פיתח מערכות תמיכה, אך הסטיגמה עדיין מונעת מרבים לפנות לעזרה.
בעשור האחרון חל שינוי תרבותי: הליכה לפסיכולוג כבר לא נתפסת כחולשה. סדרות טלוויזיה כמו "בטיפול" הפכו את הטיפול הנפשי לנושא לגיטימי. בתי ספר משלבים תוכניות לפיתוח אינטליגנציה רגשית.
עם זאת, נותרו פערים משמעותיים. בפריפריה יש מחסור בפסיכולוגים, וזמני ההמתנה בקופות החולים ארוכים. ארגונים כמו "ער"ן" מספקים קו חירום, אך המומחים דורשים השקעה גדולה יותר בבריאות הנפש.', 'Психология занимает центральное место в израильском обществе. В стране, где каждый гражданин обязан пройти военную службу, а многие испытывают постоянное напряжение в сфере безопасности, потребность в психологической поддержке — дело повседневное.
Посттравматическое расстройство привлекает в последние годы особое внимание. Исследования показывают, что около двадцати процентов демобилизованных солдат испытывают симптомы тревоги или депрессии. Армия создала системы поддержки, но стигма по-прежнему мешает многим обращаться за помощью.
За последнее десятилетие произошёл культурный сдвиг: поход к психологу уже не воспринимается как слабость. Телесериалы вроде «В терапии» сделали тему психического здоровья легитимной. Школы внедряют программы развития эмоционального интеллекта.
Тем не менее остаются значительные пробелы. На периферии не хватает психологов, а очереди в больничных кассах длинные. Организации вроде «Эран» обеспечивают линию экстренной помощи, но специалисты требуют большего вложения в психическое здоровье.', '[{"he": "פסיכולוגיה", "ru": "психология", "translit": "психологИя"}, {"he": "חרדה", "ru": "тревога", "translit": "харадА"}, {"he": "דיכאון", "ru": "депрессия", "translit": "дикаОн"}, {"he": "סטיגמה", "ru": "стигма", "translit": "стИгма"}, {"he": "פוסט-טראומה", "ru": "посттравма", "translit": "пост-трАума"}, {"he": "בריאות הנפש", "ru": "психическое здоровье", "translit": "бриУт hа-нЕфеш"}, {"he": "אינטליגנציה רגשית", "ru": "эмоциональный интеллект", "translit": "интелигЕнция ригшИт"}, {"he": "תמיכה", "ru": "поддержка", "translit": "тмихА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (122, 4, 'ההיסטוריה של התנועה הציונית', 'История сионизма', 'התנועה הציונית נולדה בסוף המאה התשע-עשרה כתגובה לאנטישמיות באירופה. תיאודור הרצל, עיתונאי יהודי-אוסטרי, פרסם בשנת 1896 את חיבורו "מדינת היהודים" והפך למנהיג התנועה.
בקונגרס הציוני הראשון בבאזל נקבע כי המטרה היא הקמת בית לאומי לעם היהודי בארץ ישראל. לאורך השנים הגיעו גלי עלייה שונים: עולים מרוסיה, מפולין, מתימן ומארצות ערב.
הצהרת בלפור משנת 1917 הכירה בזכות היהודים לבית לאומי. אך הדרך למדינה הייתה ארוכה ומלאת קשיים: מאבקים עם הבריטים, מתחים עם ערביי הארץ, והשואה שהשמידה שליש מהעם.
בכ"ט בנובמבר 1947 החליטה עצרת האו"ם על חלוקת ארץ ישראל. בי"ד באייר תש"ח, ה-14 במאי 1948, הכריז דוד בן-גוריון על הקמת מדינת ישראל. באותו לילה פלשו חמישה צבאות ערב, ומלחמת העצמאות החלה.', 'Сионистское движение зародилось в конце XIX века как реакция на антисемитизм в Европе. Теодор Герцль, австро-еврейский журналист, опубликовал в 1896 году свой труд «Еврейское государство» и стал лидером движения.
На первом Сионистском конгрессе в Базеле было решено, что целью является создание национального дома для еврейского народа на Земле Израиля. На протяжении лет прибывали различные волны репатриации: из России, Польши, Йемена и арабских стран.
Декларация Бальфура 1917 года признала право евреев на национальный дом. Но путь к государству был долгим и полным трудностей: борьба с британцами, напряжённость с арабским населением и Холокост, уничтоживший треть народа.
29 ноября 1947 года Генеральная Ассамблея ООН приняла решение о разделе Земли Израиля. 14 мая 1948 года Давид Бен-Гурион провозгласил создание государства Израиль. В ту же ночь вторглись пять арабских армий, и началась Война за независимость.', '[{"he": "ציונות", "ru": "сионизм", "translit": "циёнУт"}, {"he": "אנטישמיות", "ru": "антисемитизм", "translit": "антишемиЮт"}, {"he": "עלייה", "ru": "репатриация", "translit": "алийА"}, {"he": "הצהרה", "ru": "декларация", "translit": "hацhарА"}, {"he": "עצמאות", "ru": "независимость", "translit": "ацмаУт"}, {"he": "שואה", "ru": "Холокост", "translit": "шоА"}, {"he": "קונגרס", "ru": "конгресс", "translit": "конгрЕс"}, {"he": "חלוקה", "ru": "раздел", "translit": "халукА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (123, 4, 'צה"ל והחברה הישראלית', 'ЦАХАЛ и общество', 'צה"ל הוא צבא העם של ישראל. כל אזרח, גבר ונקבה, מחויב בשירות צבאי: שלוש שנים לגברים ושנתיים לנשים. ערבים ישראלים וחרדים בדרך כלל פטורים, נושא שיוצר ויכוח ציבורי מתמשך.
הצבא משמש ככור היתוך חברתי. חיילים מרקעים שונים — עולים חדשים, יוצאי קיבוצים, תושבי פריפריה — משרתים יחד ויוצרים קשרים לכל החיים. יחידות עילית כמו שמונה מאתיים הפכו למנוע של תעשיית ההייטק.
אך השירות הצבאי מעלה גם שאלות מוסריות. חיילים צעירים מתמודדים עם דילמות אתיות, ותנועות כמו "יש גבול" ו"שוברים שתיקה" מעלות ביקורת על פעולות הצבא בשטחים.
מערכת המילואים מחזקת את הקשר בין צה"ל לחברה. גברים משרתים במילואים עד גיל ארבעים, ובזמני חירום המדינה כולה מתגייסת. קשר זה הופך את הצבא לנושא מרכזי בשיח הציבורי.', 'ЦАХАЛ — народная армия Израиля. Каждый гражданин, мужчина и женщина, обязан служить: три года для мужчин и два года для женщин. Израильские арабы и ультраортодоксы обычно освобождены, что порождает постоянную общественную дискуссию.
Армия служит социальным плавильным котлом. Солдаты из разных слоёв — новые репатрианты, выходцы из кибуцев, жители периферии — служат вместе и создают связи на всю жизнь. Элитные подразделения вроде 8200 стали двигателем хайтек-индустрии.
Однако военная служба поднимает и моральные вопросы. Молодые солдаты сталкиваются с этическими дилеммами, а движения вроде «Еш Гвуль» и «Шоврим Штика» критикуют действия армии на территориях.
Система резервистов укрепляет связь между ЦАХАЛом и обществом. Мужчины служат в резерве до сорока лет, а в чрезвычайных ситуациях мобилизуется вся страна. Эта связь делает армию центральной темой общественного дискурса.', '[{"he": "צבא", "ru": "армия", "translit": "цавА"}, {"he": "שירות צבאי", "ru": "военная служба", "translit": "шерУт цваИ"}, {"he": "מילואים", "ru": "резерв", "translit": "милуИм"}, {"he": "כור היתוך", "ru": "плавильный котёл", "translit": "кур hа-итУх"}, {"he": "דילמה אתית", "ru": "этическая дилемма", "translit": "дилЕма этИт"}, {"he": "פטור", "ru": "освобождение", "translit": "патУр"}, {"he": "יחידה", "ru": "подразделение", "translit": "йехидА"}, {"he": "חירום", "ru": "чрезвычайная ситуация", "translit": "херУм"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (125, 4, 'המחקר האקדמי בישראל', 'Академические исследования', 'ישראל היא מעצמת מחקר. לפי מספר הפרסומים המדעיים ליחידת אוכלוסייה, היא בין המדינות המובילות בעולם. שמונה אוניברסיטאות מחקר, בראשן האוניברסיטה העברית, הטכניון ומכון ויצמן, מובילות מחקר חדשני.
הטכניון בחיפה ידוע כ"MIT של ישראל". בוגריו ייסדו חברות הייטק רבות ותרמו לכלכלת המדינה. מכון ויצמן למדע ברחובות הוא ממוסדות המחקר היוקרתיים בעולם, ומתמקד במדעים מדויקים ובמדעי החיים.
ישראל זכתה בשנים-עשר פרסי נובל. רובם בתחומי הכימיה והכלכלה. דניאל כהנמן זכה בפרס נובל לכלכלה על מחקרו בפסיכולוגיה של קבלת החלטות, מחקר שביצע בירושלים.
המדינה משקיעה כחמישה אחוזים מהתמ"ג במחקר ופיתוח — מהשיעורים הגבוהים בעולם. אך האקדמיה מתמודדת עם אתגרים: שכר נמוך, בריחת מוחות לחו"ל, ותחרות גוברת מאוניברסיטאות באסיה.', 'Израиль — научная сверхдержава. По числу научных публикаций на душу населения он входит в число мировых лидеров. Восемь исследовательских университетов, во главе с Еврейским университетом, Технионом и Институтом Вейцмана, ведут передовые исследования.
Технион в Хайфе известен как «израильский MIT». Его выпускники основали множество хайтек-компаний и внесли вклад в экономику страны. Институт Вейцмана в Реховоте — один из самых престижных исследовательских центров мира, специализирующийся на точных и естественных науках.
Израиль получил двенадцать Нобелевских премий, в основном в области химии и экономики. Даниэль Канеман получил Нобелевскую премию по экономике за исследования психологии принятия решений, проведённые в Иерусалиме.
Государство инвестирует около пяти процентов ВВП в исследования и разработки — один из самых высоких показателей в мире. Однако академия сталкивается с вызовами: низкие зарплаты, утечка мозгов за рубеж и растущая конкуренция со стороны азиатских университетов.', '[{"he": "מחקר", "ru": "исследование", "translit": "мехкАр"}, {"he": "אוניברסיטה", "ru": "университет", "translit": "университА"}, {"he": "פרסום מדעי", "ru": "научная публикация", "translit": "пирсУм мадаИ"}, {"he": "פרס נובל", "ru": "Нобелевская премия", "translit": "прас нОбель"}, {"he": "בריחת מוחות", "ru": "утечка мозгов", "translit": "брихАт мохОт"}, {"he": "תמ\"ג", "ru": "ВВП", "translit": "тамАг"}, {"he": "מדעים מדויקים", "ru": "точные науки", "translit": "мадаИм медуякИм"}, {"he": "חדשני", "ru": "инновационный", "translit": "хидушнИ"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (126, 4, 'משא ומתן עסקי בישראל', 'Деловые переговоры', 'התרבות העסקית בישראל שונה מאוד מזו שבמדינות אחרות. ישראלים ידועים בגישה הישירה שלהם — "דוגרי" — שלעתים נתפסת כגסות על ידי זרים. אך בעולם העסקים הישראלי, ישירות נחשבת ליתרון.
במשא ומתן ישראלי, ההיררכיה פחות חשובה. עובד זוטר יכול לחלוק על מנהל בכיר מבלי שזה ייחשב לחוצפה. החופש להביע דעה ולאתגר סמכות נחשב לאחד היתרונות של תרבות הסטארט-אפ.
פגישות עסקיות בישראל לרוב אינן פורמליות. אנשי עסקים מגיעים בלבוש קז''ואלי, עוברים מהר לשם הפרטי, ולא מהססים לדבר על נושאים אישיים. הקשר האישי חשוב יותר מחוזים ומסמכים.
עם זאת, כדאי לזכור כמה כללים: אל תקבעו פגישות בשישי אחר הצהריים או בשבת. היו מוכנים לשינויים ברגע האחרון. ואל תתפלאו אם הצד השני מנהל כמה שיחות טלפון באמצע הפגישה.', 'Деловая культура в Израиле сильно отличается от других стран. Израильтяне известны своей прямотой — «дугри» — которая порой воспринимается иностранцами как грубость. Но в израильском деловом мире прямолинейность считается преимуществом.
В израильских переговорах иерархия менее важна. Младший сотрудник может возразить старшему руководителю, и это не считается дерзостью. Свобода высказывать мнение и оспаривать авторитет считается одним из преимуществ стартап-культуры.
Деловые встречи в Израиле обычно неформальны. Бизнесмены приходят в повседневной одежде, быстро переходят на имена и не стесняются обсуждать личные темы. Личные отношения важнее контрактов и документов.
Тем не менее стоит помнить несколько правил: не назначайте встреч в пятницу после обеда или в субботу. Будьте готовы к изменениям в последний момент. И не удивляйтесь, если другая сторона ведёт несколько телефонных разговоров прямо посреди встречи.', '[{"he": "משא ומתן", "ru": "переговоры", "translit": "масА у-матАн"}, {"he": "דוגרי", "ru": "начистоту", "translit": "дУгри"}, {"he": "היררכיה", "ru": "иерархия", "translit": "hиерархИя"}, {"he": "חוצפה", "ru": "дерзость", "translit": "хуцпА"}, {"he": "סטארט-אפ", "ru": "стартап", "translit": "стартАп"}, {"he": "חוזה", "ru": "контракт", "translit": "хозЕ"}, {"he": "פגישה", "ru": "встреча", "translit": "пгишА"}, {"he": "סמכות", "ru": "полномочия", "translit": "самхУт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (127, 4, 'אקולוגיה ומשאבי מים בישראל', 'Экология и водные ресурсы', 'ים המלח, הנקודה הנמוכה ביותר על פני כדור הארץ, מתכווץ בקצב מדאיג. מפלס המים יורד בכמטר בשנה, ובולענים מסוכנים נפתחים לאורך חופיו. הסיבה העיקרית: הפניית מי הירדן להשקיה ולצריכה ביתית.
ישראל מובילה עולמית במיחזור מים. כשמונים וחמישה אחוז מהשפכים עוברים טיפול ומשמשים להשקיה חקלאית. שום מדינה אחרת לא מגיעה לשיעור כזה. הטכנולוגיה הישראלית בתחום זה מיוצאת לעשרות מדינות.
קרן קיימת לישראל נטעה מאות מיליוני עצים מאז הקמתה. יער בן-שמן ויער ירושלים הם דוגמאות לייעור מוצלח. אך מבקרים טוענים כי נטיעת אורנים פגעה במערכות אקולוגיות מקומיות ובצמחייה הטבעית.
עמק החולה הוא סיפור הצלחה סביבתי. האגם יובש בשנות החמישים לצורך חקלאות, אך חלקו שוקם בשנות התשעים כשמורת טבע. היום הוא אתר ציפרות בינלאומי שאליו מגיעים מאות מיליוני ציפורים נודדות.', 'Мёртвое море, самая низкая точка на Земле, сокращается с тревожной скоростью. Уровень воды падает примерно на метр в год, а вдоль берегов открываются опасные провалы. Главная причина: отвод воды Иордана на орошение и бытовое потребление.
Израиль — мировой лидер по переработке воды. Около 85% сточных вод проходят очистку и используются для сельскохозяйственного орошения. Ни одна другая страна не достигает такого показателя. Израильские технологии в этой области экспортируются в десятки стран.
Еврейский национальный фонд (ЕНФ) посадил сотни миллионов деревьев с момента основания. Лес Бен-Шемен и Иерусалимский лес — примеры успешного лесоразведения. Однако критики утверждают, что посадка сосен нанесла ущерб местным экосистемам и природной растительности.
Долина Хула — экологическая история успеха. Озеро было осушено в пятидесятых годах для сельского хозяйства, но частично восстановлено в девяностых как природный заповедник. Сегодня это международный орнитологический объект, куда прилетают сотни миллионов перелётных птиц.', '[{"he": "ים המלח", "ru": "Мёртвое море", "translit": "ям hа-мЕлах"}, {"he": "בולענים", "ru": "провалы", "translit": "болъанИм"}, {"he": "מיחזור", "ru": "переработка", "translit": "михзУр"}, {"he": "שפכים", "ru": "сточные воды", "translit": "шфахИм"}, {"he": "ייעור", "ru": "лесоразведение", "translit": "йиУр"}, {"he": "שמורת טבע", "ru": "заповедник", "translit": "шморАт тЕва"}, {"he": "ציפורים נודדות", "ru": "перелётные птицы", "translit": "ципорИм нодедОт"}, {"he": "מפלס", "ru": "уровень воды", "translit": "мифлАс"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (128, 4, 'הפוליטיקה הישראלית', 'Израильская политика', 'הכנסת, בית הנבחרים של ישראל, מונה מאה עשרים חברי כנסת. שיטת הבחירות היחסית מובילה לריבוי מפלגות: בדרך כלל עשר עד חמש-עשרה מפלגות מיוצגות בכנסת. שום מפלגה מעולם לא זכתה ברוב של שישים ואחת מנדטים.
המציאות הזו מחייבת הקמת קואליציות. ראש הממשלה חייב להרכיב קואליציה מלפחות שישים ואחד חברי כנסת, תהליך שכולל משא ומתן עם מפלגות קטנות ומתן תפקידים וסכומים תקציביים.
המפה הפוליטית מחולקת למחנות: ימין, שמאל ומרכז. אך בישראל, הימין והשמאל מוגדרים בעיקר לפי עמדות ביטחוניות ולא כלכליות. מפלגות דתיות ומפלגות ערביות יוצרות ממד נוסף.
בשנים האחרונות עברה ישראל חמש מערכות בחירות בתוך ארבע שנים. חוסר היציבות הפוליטית הוביל לקיטוב חברתי ולוויכוח על הצורך ברפורמה בשיטת הממשל.', 'Кнессет, парламент Израиля, насчитывает сто двадцать депутатов. Пропорциональная система выборов ведёт к многопартийности: обычно десять-пятнадцать партий представлены в Кнессете. Ни одна партия никогда не получала большинства в шестьдесят один мандат.
Эта реальность требует создания коалиций. Премьер-министр обязан сформировать коалицию минимум из шестидесяти одного депутата — процесс, включающий переговоры с малыми партиями и распределение должностей и бюджетов.
Политическая карта делится на лагеря: правый, левый и центр. Но в Израиле правые и левые определяются главным образом по позициям в сфере безопасности, а не экономики. Религиозные и арабские партии создают дополнительное измерение.
В последние годы Израиль прошёл через пять избирательных кампаний за четыре года. Политическая нестабильность привела к поляризации общества и дискуссии о необходимости реформы системы управления.', '[{"he": "כנסת", "ru": "Кнессет", "translit": "кнЕсет"}, {"he": "מפלגה", "ru": "партия", "translit": "мифлагА"}, {"he": "קואליציה", "ru": "коалиция", "translit": "коалИция"}, {"he": "מנדט", "ru": "мандат", "translit": "мандАт"}, {"he": "ימין", "ru": "правые", "translit": "ямИн"}, {"he": "שמאל", "ru": "левые", "translit": "смоль"}, {"he": "בחירות", "ru": "выборы", "translit": "бхирОт"}, {"he": "קיטוב", "ru": "поляризация", "translit": "китУв"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (129, 4, 'מערכת הבריאות בישראל', 'Медицинская система', 'חוק ביטוח בריאות ממלכתי משנת 1995 מבטיח כיסוי רפואי לכל תושבי ישראל. כל אזרח חייב להיות חבר באחת מארבע קופות החולים: כללית, מכבי, מאוחדת ולאומית. כללית היא הגדולה ביותר, עם כארבעה מיליון מבוטחים.
סל הבריאות הממלכתי כולל מגוון רחב של שירותים: ביקורים אצל רופאים, בדיקות מעבדה, אשפוז בבתי חולים, ותרופות בסיסיות. אך שירותים רבים, כמו טיפולי שיניים למבוגרים, אינם נכללים בסל.
ישראל ידועה בחדשנות רפואית. בית החולים הדסה בירושלים ובית החולים שיבא בתל השומר נמנים עם בתי החולים המובילים בעולם. תיירות רפואית מביאה אלפי חולים מחו"ל מדי שנה.
עם זאת, המערכת מתמודדת עם אתגרים: עומס על חדרי מיון, מחסור באחיות, ותורים ארוכים לרופאים מומחים. בפריפריה, הפערים בשירותי הבריאות בולטים במיוחד.', 'Закон о государственном медицинском страховании 1995 года гарантирует медицинское обслуживание всем жителям Израиля. Каждый гражданин обязан состоять в одной из четырёх больничных касс: Клалит, Маккаби, Меухедет и Леумит. Клалит — крупнейшая, с примерно четырьмя миллионами застрахованных.
Государственная корзина здоровья включает широкий спектр услуг: визиты к врачам, лабораторные анализы, госпитализацию и базовые лекарства. Но многие услуги, такие как стоматология для взрослых, не входят в корзину.
Израиль известен медицинскими инновациями. Больница Хадасса в Иерусалиме и больница Шиба в Тель-ха-Шомер входят в число мировых лидеров. Медицинский туризм привлекает тысячи пациентов из-за рубежа ежегодно.
Тем не менее система сталкивается с вызовами: перегрузка приёмных покоев, нехватка медсестёр и длинные очереди к специалистам. На периферии неравенство в медицинских услугах особенно заметно.', '[{"he": "ביטוח בריאות", "ru": "мед. страховка", "translit": "битУах бриУт"}, {"he": "קופת חולים", "ru": "больничная касса", "translit": "купАт холИм"}, {"he": "סל בריאות", "ru": "корзина здоровья", "translit": "саль бриУт"}, {"he": "אשפוז", "ru": "госпитализация", "translit": "ишпУз"}, {"he": "חדר מיון", "ru": "приёмный покой", "translit": "хЕдер миЮн"}, {"he": "חדשנות", "ru": "инновации", "translit": "хидашнУт"}, {"he": "מבוטח", "ru": "застрахованный", "translit": "мевутАх"}, {"he": "רופא מומחה", "ru": "врач-специалист", "translit": "рофЕ мумхЕ"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (100, 3, 'התנדבות בישראל', 'Волонтёрство', 'ההתנדבות היא חלק חשוב מהחברה הישראלית. ישראלים רבים מתנדבים בזמנם הפנוי בארגונים שונים כדי לעזור לאנשים ולתרום לקהילה. יש התנדבות עם קשישים, ילדים בסיכון, בעלי חיים ואנשים שגרים ברחוב.
אחד הארגונים הגדולים הוא מגן דוד אדום שמספק שירותי הצלה רפואית. מתנדבים צעירים לומדים עזרה ראשונה ונוסעים באמבולנסים להציל חיים. ארגון נוסף הוא לקט ישראל שאוסף אוכל עודף ומחלק למשפחות נזקקות.
גם בצבא יש מתנדבים. צעירים מחוץ לארץ באים להתנדב בבסיסים צבאיים. אחרי אסונות בעולם ישראל שולחת צוותי חילוץ עם מתנדבים רבים. ההתנדבות מחזקת את תחושת השייכות ועוזרת לבנות חברה טובה יותר.', 'Волонтёрство — важная часть израильского общества. Многие израильтяне добровольно помогают в свободное время в различных организациях, чтобы помочь другим людям и внести вклад в общество. Есть волонтёрство с пожилыми людьми, с детьми в группе риска, с животными и с бездомными.
Одна из крупнейших организаций — Маген Давид Адом, которая предоставляет службу скорой медицинской помощи. Молодые добровольцы учатся оказывать первую помощь и ездят на машинах скорой помощи, чтобы спасать жизни. Ещё одна организация — Лекет Исраэль, которая собирает излишки еды из ресторанов и раздаёт их нуждающимся семьям.
Добровольцы есть и в армии. Молодые люди из-за рубежа приезжают в Израиль на короткий срок, чтобы помогать на военных базах. Кроме того, после землетрясений или катастроф в мире Израиль отправляет спасательные группы, включающие многих добровольцев. Волонтёрство укрепляет чувство принадлежности и помогает строить лучшее общество.', '[{"he": "התנדבות", "ru": "волонтёрство", "translit": "hитнадвУт"}, {"he": "מתנדב", "ru": "доброволец", "translit": "митнадЕв"}, {"he": "ארגון", "ru": "организация", "translit": "иргУн"}, {"he": "עזרה ראשונה", "ru": "первая помощь", "translit": "эзрА ришонА"}, {"he": "קשיש", "ru": "пожилой человек", "translit": "кашИш"}, {"he": "לתרום", "ru": "пожертвовать / внести вклад", "translit": "литрОм"}, {"he": "נזקק", "ru": "нуждающийся", "translit": "низкАк"}, {"he": "חילוץ", "ru": "спасение / эвакуация", "translit": "хилУц"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (130, 4, 'האדריכלות של תל אביב', 'Архитектура Тель-Авива', 'תל אביב ידועה בעולם כ"עיר לבנה". למעלה מארבעת אלפים מבנים בסגנון באוהאוס נבנו בשנות השלושים והארבעים על ידי אדריכלים יהודים שברחו מגרמניה. אוסף זה הוכרז כאתר מורשת עולמית של אונסק"ו בשנת 2003.
הסגנון הבינלאומי הותאם לאקלים המקומי: מרפסות רחבות, חלונות צרים, ועמודים שמרימים את המבנה מעל הקרקע לאוורור. צבעם המקורי היה לבן, אם כי רבים מהם הזדקנו ונצבעו מחדש.
בניגוד למבנים ההיסטוריים, מרכז העיר מתאפיין גם במגדלים מודרניים. מגדלי עזריאלי, שנבנו בשנות התשעים, הפכו לסמל של תל אביב העסקית. פרויקט שרונה, ששילב מבנים טמפלריים עם מרכז מסחרי, מדגים שימור לצד פיתוח.
שדרות רוטשילד, עם עצי הפיקוס העתיקים והמבנים המשוחזרים, מייצגות את הניגוד בין הישן לחדש. זהו הלב התרבותי של העיר — מקום למחאות, לאירועים ולטיולים.', 'Тель-Авив известен во всём мире как «Белый город». Более четырёх тысяч зданий в стиле Баухаус были построены в тридцатых-сороковых годах еврейскими архитекторами, бежавшими из Германии. Эта коллекция признана объектом Всемирного наследия ЮНЕСКО в 2003 году.
Интернациональный стиль был адаптирован к местному климату: широкие балконы, узкие окна и колонны, приподнимающие здание для вентиляции. Изначально они были белого цвета, хотя многие постарели и были перекрашены.
В отличие от исторических зданий, центр города характеризуется и современными небоскрёбами. Башни Азриэли, построенные в девяностых, стали символом делового Тель-Авива. Проект Сарона, объединивший темплерские здания с торговым центром, демонстрирует сочетание сохранения и развития.
Бульвар Ротшильда с вековыми фикусами и отреставрированными зданиями воплощает контраст старого и нового. Это культурное сердце города — место протестов, мероприятий и прогулок.', '[{"he": "אדריכלות", "ru": "архитектура", "translit": "адрихалУт"}, {"he": "באוהאוס", "ru": "Баухаус", "translit": "бАухаус"}, {"he": "מורשת עולמית", "ru": "Всемирное наследие", "translit": "морЕшет оламИт"}, {"he": "מרפסת", "ru": "балкон", "translit": "мирпЕсет"}, {"he": "מגדל", "ru": "башня", "translit": "мигдАль"}, {"he": "שימור", "ru": "сохранение", "translit": "шимУр"}, {"he": "שדרות", "ru": "бульвар", "translit": "сдерОт"}, {"he": "שחזור", "ru": "реставрация", "translit": "шихзУр"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (131, 4, 'פילוסופיה של השפה העברית', 'Философия языка', 'תחיית השפה העברית היא תופעה ייחודית בהיסטוריה האנושית. שום שפה אחרת לא חזרה לשימוש יומיומי אחרי אלפיים שנה של שינה. אליעזר בן-יהודה הקדיש את חייו למשימה הזאת והפך לאבי העברית המודרנית.
בן-יהודה היה הראשון שגידל את בנו, בן-ציון, כדובר עברית יחיד. הוא יצר אלפי מילים חדשות: עיתון, מילון, גלידה, אופניים. חלק מהמילים נלקחו מהערבית, חלק הומצאו משורשים עבריים קדומים.
הוויכוח הלשוני לא נגמר. האקדמיה ללשון העברית ממשיכה להמליץ על מילים עבריות במקום לועזיות: מחשב במקום קומפיוטר, מסוק במקום הליקופטר. אך הציבור לא תמיד מקבל את ההמלצות.
העברית המודרנית שונה מאוד מעברית המקרא. המבנה הדקדוקי פשוט יותר, האוצר מילוני מגוון יותר, וההשפעות של יידיש, ערבית, רוסית ואנגלית ניכרות בכל רמות השפה.', 'Возрождение иврита — уникальное явление в истории человечества. Ни один другой язык не вернулся к повседневному использованию после двух тысяч лет молчания. Элиэзер Бен-Йехуда посвятил свою жизнь этой миссии и стал отцом современного иврита.
Бен-Йехуда первым воспитал своего сына, Бен-Циона, как единственного носителя иврита. Он создал тысячи новых слов: газета, словарь, мороженое, велосипед. Часть слов была заимствована из арабского, часть изобретена из древнееврейских корней.
Языковая дискуссия не окончена. Академия языка иврит продолжает рекомендовать ивритские слова вместо иностранных: махшев вместо «компьютер», масок вместо «вертолёт». Но публика не всегда принимает рекомендации.
Современный иврит сильно отличается от библейского. Грамматическая структура проще, словарный запас разнообразнее, а влияние идиша, арабского, русского и английского ощущается на всех уровнях языка.', '[{"he": "תחייה", "ru": "возрождение", "translit": "тхийА"}, {"he": "שפה", "ru": "язык", "translit": "сафА"}, {"he": "מילון", "ru": "словарь", "translit": "милОн"}, {"he": "שורש", "ru": "корень", "translit": "шОреш"}, {"he": "דקדוק", "ru": "грамматика", "translit": "дикдУк"}, {"he": "אוצר מילוני", "ru": "лексикон", "translit": "оцАр милонИ"}, {"he": "האקדמיה ללשון", "ru": "Академия языка", "translit": "hа-акадЕмия ле-лашОн"}, {"he": "לועזי", "ru": "иностранный", "translit": "лоазИ"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (132, 4, 'כתיבת מכתבים רשמיים בעברית', 'Формальные письма', 'מכתב רשמי בעברית מתחיל תמיד בפנייה "לכבוד" ולאחריה שם הנמען או התואר שלו. שורת הנושא פותחת ב"הנדון:" ומתארת בקצרה את מטרת המכתב. הגוף נכתב בשפה פורמלית ומנומסת.
ביטויי פתיחה נפוצים כוללים: "הריני פונה אליכם בעניין...", "בהמשך לשיחתנו מיום...", ו"אני מבקש להביא לידיעתכם...". יש להימנע מסלנג ומקיצורים.
את המכתב מסיימים בנוסחת סיום: "בכבוד רב", "בברכה", או "בתודה מראש". לאחר מכן רושמים את השם המלא, מספר הטלפון וכתובת הדואר האלקטרוני.
בעידן הדיגיטלי, מכתבים רשמיים נשלחים לרוב בדואר אלקטרוני. אך הכללים נשארים דומים: שפה מכובדת, מבנה ברור, ותוכן ממוקד. טעויות כתיב בעברית רשמית נחשבות לחוסר מקצועיות.', 'Официальное письмо на иврите всегда начинается с обращения «лихвод» (букв. «в честь») и имени или должности адресата. Строка темы открывается словом «hа-нидон:» и кратко описывает цель письма. Текст пишется формальным и вежливым языком.
Распространённые вводные фразы включают: «Настоящим обращаюсь к вам по вопросу…», «В продолжение нашего разговора от…» и «Прошу довести до вашего сведения…». Следует избегать сленга и сокращений.
Письмо завершается формулой закрытия: «С уважением», «С благословением» или «Заранее благодарю». Затем указываются полное имя, номер телефона и адрес электронной почты.
В цифровую эпоху официальные письма обычно отправляются по электронной почте. Но правила остаются схожими: уважительный язык, чёткая структура и сфокусированное содержание. Орфографические ошибки в официальном иврите считаются признаком непрофессионализма.', '[{"he": "לכבוד", "ru": "уважаемый (обращение)", "translit": "лихвОд"}, {"he": "הנדון", "ru": "тема/предмет", "translit": "hа-нидОн"}, {"he": "בכבוד רב", "ru": "с уважением", "translit": "бе-кавОд рав"}, {"he": "פנייה", "ru": "обращение", "translit": "пнийА"}, {"he": "נמען", "ru": "адресат", "translit": "нимъАн"}, {"he": "נוסחה", "ru": "формула", "translit": "нусхА"}, {"he": "כתיב", "ru": "орфография", "translit": "ктив"}, {"he": "רשמי", "ru": "официальный", "translit": "ришмИ"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (133, 4, 'תרבות הוויכוח בישראל', 'Культура дебатов', 'ישראלים אוהבים להתווכח. "דוגרי" — מילה שמקורה בערבית — מתארת את הגישה הישירה שאופיינית לתרבות הישראלית. בניגוד לתרבויות אחרות, ישראלים לא נוהגים לעטוף את דבריהם בנימוסים.
שורשי תרבות הוויכוח נמצאים בלימוד התלמוד. במשך אלפי שנים, יהודים למדו בחברותא — זוגות שמתווכחים על פירושים שונים. השאלה והפרכה הם כלים מרכזיים בלמידה היהודית המסורתית.
בכנסת, הוויכוחים לעתים סוערים. חברי כנסת צועקים, קוטעים ומאשימים זה את זה. למי שלא רגיל, זה נראה כמו כאוס, אך זהו חלק מהתרבות הפרלמנטרית הישראלית.
גם בטלוויזיה, פאנלים פוליטיים מאופיינים בצעקות ובדיבור בו-זמני. עיתונאים לא מהססים לשאול שאלות קשות ולהפריע לפוליטיקאים. הישירות הזו נתפסת על ידי ישראלים כערך דמוקרטי חשוב.', 'Израильтяне любят спорить. «Дугри» — слово арабского происхождения — описывает прямоту, характерную для израильской культуры. В отличие от других культур, израильтяне не склонны облекать свои слова в вежливые формы.
Корни культуры дебатов лежат в изучении Талмуда. На протяжении тысячелетий евреи учились в хеврута — парах, которые спорят о различных толкованиях. Вопрос и опровержение — центральные инструменты традиционного еврейского обучения.
В Кнессете дебаты порой бурные. Депутаты кричат, перебивают и обвиняют друг друга. Для непривычных это выглядит как хаос, но это часть израильской парламентской культуры.
На телевидении политические панели характеризуются криками и одновременной речью. Журналисты не стесняются задавать жёсткие вопросы и перебивать политиков. Эта прямота воспринимается израильтянами как важная демократическая ценность.', '[{"he": "וויכוח", "ru": "спор/дебаты", "translit": "викУах"}, {"he": "דוגרי", "ru": "прямо/начистоту", "translit": "дУгри"}, {"he": "תלמוד", "ru": "Талмуд", "translit": "талмУд"}, {"he": "חברותא", "ru": "хеврута (парное обучение)", "translit": "хеврутА"}, {"he": "הפרכה", "ru": "опровержение", "translit": "hафрахА"}, {"he": "פרלמנטרי", "ru": "парламентский", "translit": "парламентАри"}, {"he": "ישירות", "ru": "прямота", "translit": "йеширУт"}, {"he": "דמוקרטי", "ru": "демократический", "translit": "демокрАти"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (134, 4, 'תעשיית ההייטק הישראלית', 'Хайтек-индустрия', 'ישראל מכונה "אומת הסטארט-אפ". עם יותר משבעת אלפים חברות סטארט-אפ, יש בישראל את הריכוז הגבוה ביותר של חברות טכנולוגיה בעולם ביחס לאוכלוסייה.
יחידה שמונה מאתיים של צה"ל נחשבת לאחד המנועים של ההייטק. חיילים שמשרתים ביחידה רוכשים מיומנויות טכנולוגיות מתקדמות, ולאחר השחרור רבים מהם מקימים חברות. גם יחידות מודיעין אחרות מספקות כוח אדם מיומן.
חברות בינלאומיות כמו גוגל, מיקרוסופט ואפל הקימו מרכזי פיתוח בישראל. התרבות הישראלית של חשיבה עצמאית, נכונות לקחת סיכונים, וקשרים צבאיים — כל אלה תורמים להצלחה.
אך יש גם אתגרים: פער גדל בין עובדי הייטק לשאר השכירים, בריחת מוחות לסיליקון ואלי, ובעיית הגיוון — נשים ומיעוטים עדיין מיוצגים בחסר בתעשייה.', 'Израиль называют «стартап-нацией». С более чем семью тысячами стартап-компаний здесь самая высокая концентрация технологических компаний в мире относительно населения.
Подразделение 8200 ЦАХАЛа считается одним из двигателей хайтека. Солдаты, служащие в подразделении, приобретают продвинутые технологические навыки, и после демобилизации многие из них основывают компании. Другие разведывательные подразделения также поставляют квалифицированные кадры.
Международные компании вроде Google, Microsoft и Apple открыли центры разработки в Израиле. Израильская культура самостоятельного мышления, готовности рисковать и армейских связей — всё это способствует успеху.
Но есть и вызовы: растущий разрыв между работниками хайтека и остальными наёмными работниками, утечка мозгов в Кремниевую долину и проблема разнообразия — женщины и меньшинства по-прежнему недостаточно представлены в отрасли.', '[{"he": "הייטק", "ru": "хайтек", "translit": "hайтЕк"}, {"he": "סטארט-אפ", "ru": "стартап", "translit": "стартАп"}, {"he": "מיומנות", "ru": "навык", "translit": "меюманУт"}, {"he": "מודיעין", "ru": "разведка", "translit": "модиИн"}, {"he": "סיכון", "ru": "риск", "translit": "сикУн"}, {"he": "פיתוח", "ru": "разработка", "translit": "питУах"}, {"he": "גיוון", "ru": "разнообразие", "translit": "гивУн"}, {"he": "שכיר", "ru": "наёмный работник", "translit": "сахИр"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (135, 4, 'מערכת החינוך בישראל', 'Система образования', 'מערכת החינוך בישראל מחולקת לארבעה שלבים: גן ילדים, בית ספר יסודי, חטיבת ביניים ותיכון. בתיכון, תלמידים נבחנים בבחינות הבגרות — מערכת מבחנים ארצית שקובעת את הכניסה לאוניברסיטה.
תעודת הבגרות דורשת הצלחה בלפחות עשרים ואחת יחידות לימוד. מקצועות חובה כוללים עברית, אנגלית, מתמטיקה, תנ"ך וספרות. תלמידים בוחרים גם מקצועות העמקה לפי תחומי העניין שלהם.
אחרי הצבא, רבים עושים שנת מכינה או טיולים בחו"ל לפני הלימודים. גיל הכניסה לאוניברסיטה בישראל גבוה יחסית — עשרים ושלוש עד עשרים וחמש — בגלל השירות הצבאי.
פערים בחינוך הם בעיה מרכזית. בתי ספר במרכז מצוידים יותר ומשיגים תוצאות גבוהות יותר מבתי ספר בפריפריה. המגזר הערבי והחרדי מתמודדים עם אתגרים נוספים בתוכניות הלימודים.', 'Система образования в Израиле делится на четыре этапа: детский сад, начальная школа, средняя школа и старшая школа. В старшей школе ученики сдают экзамены на аттестат зрелости (багрут) — национальную систему экзаменов, определяющую поступление в университет.
Аттестат зрелости требует успешной сдачи минимум двадцати одной учебной единицы. Обязательные предметы включают иврит, английский, математику, ТАНАХ и литературу. Ученики также выбирают углублённые предметы по интересам.
После армии многие проходят подготовительный год (мехина) или путешествуют за границей перед учёбой. Возраст поступления в университет в Израиле относительно высок — 23-25 лет — из-за военной службы.
Неравенство в образовании — центральная проблема. Школы в центре лучше оснащены и показывают более высокие результаты, чем школы на периферии. Арабский и ультраортодоксальный секторы сталкиваются с дополнительными проблемами в учебных программах.', '[{"he": "חינוך", "ru": "образование", "translit": "хинУх"}, {"he": "בגרות", "ru": "аттестат зрелости", "translit": "багрУт"}, {"he": "תיכון", "ru": "старшая школа", "translit": "тихОн"}, {"he": "מכינה", "ru": "подготовительный курс", "translit": "мехинА"}, {"he": "יחידת לימוד", "ru": "учебная единица", "translit": "йехидАт лимУд"}, {"he": "פריפריה", "ru": "периферия", "translit": "перифЕрия"}, {"he": "תוכנית לימודים", "ru": "учебная программа", "translit": "тохнИт лимудИм"}, {"he": "מגזר", "ru": "сектор", "translit": "мигзАр"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (137, 4, 'המגוון התרבותי בישראל', 'Культурное разнообразие', 'ישראל היא פסיפס של תרבויות. ההבחנה המסורתית בין אשכנזים — יהודים ממוצא אירופי — לבין מזרחים — יהודים ממוצא ערבי ואסייתי — עדיין משפיעה על החברה, אם כי פחות מבעבר.
העדה האתיופית, שהגיעה בעיקר במבצעי משה ושלמה, מתמודדת עם אתגרים ייחודיים של שילוב. גזענות, פערים בחינוך ועוני פוגעים בקהילה, אך הדור הצעיר מתחיל לתפוס מקום משמעותי בחברה.
מיליון דוברי רוסית שעלו בשנות התשעים שינו את פני המדינה. הם הביאו תרבות מוזיקלית, מדעית וספרותית עשירה. עיתונים ברוסית, תיאטרון רוסי וחנויות בסגנון "קולוניאלי" הפכו לחלק מהנוף.
המיזוג התרבותי ניכר בעיקר במוזיקה ובאוכל. מוזיקה מזרחית, שפעם נחשבה לפחות יוקרתית, הפכה לז''אנר הפופולרי ביותר. חומוס, שקשוקה ופלאפל — מאכלים ממקורות שונים — הפכו לסמלים של התרבות הישראלית.', 'Израиль — мозаика культур. Традиционное разделение между ашкеназами — евреями европейского происхождения — и мизрахим — евреями арабского и азиатского происхождения — по-прежнему влияет на общество, хотя и меньше, чем раньше.
Эфиопская община, прибывшая в основном в ходе операций «Моше» и «Шломо», сталкивается с уникальными проблемами интеграции. Расизм, образовательные пробелы и бедность затрагивают общину, но молодое поколение начинает занимать значимое место в обществе.
Миллион русскоязычных, репатриировавшихся в девяностых, изменили облик страны. Они принесли богатую музыкальную, научную и литературную культуру. Русскоязычные газеты, русский театр и магазины в «колониальном» стиле стали частью ландшафта.
Культурное слияние особенно заметно в музыке и еде. Восточная музыка, когда-то считавшаяся менее престижной, стала самым популярным жанром. Хумус, шакшука и фалафель — блюда разного происхождения — стали символами израильской культуры.', '[{"he": "מגוון", "ru": "разнообразие", "translit": "мигвАн"}, {"he": "אשכנזי", "ru": "ашкеназ", "translit": "ашкенАзи"}, {"he": "מזרחי", "ru": "мизрахи/восточный", "translit": "мизрахИ"}, {"he": "עדה", "ru": "община/этническая группа", "translit": "эдА"}, {"he": "גזענות", "ru": "расизм", "translit": "газъанУт"}, {"he": "מיזוג", "ru": "слияние", "translit": "мизУг"}, {"he": "פסיפס", "ru": "мозаика", "translit": "псифАс"}, {"he": "קהילה", "ru": "община", "translit": "кеhилА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (138, 4, 'יחסי ערבים-יהודים בישראל', 'Арабо-еврейские отношения', 'כעשרים ואחד אחוז מאזרחי ישראל הם ערבים. הם חיים בעיקר בגליל, במשולש ובנגב. מספר ערים מעורבות — חיפה, יפו, עכו, לוד ורמלה — משמשות מרחבים של מגע יומיומי בין ערבים ליהודים.
חיפה נחשבת לדגם של דו-קיום. ערבים ויהודים גרים בשכונות סמוכות, קונים באותם מרכזים מסחריים, ולומדים באותן אוניברסיטאות. פסטיבל החג של החגים מדגים את החיים המשותפים.
בתי ספר דו-לשוניים כמו "יד ביד" מלמדים ילדים ערבים ויהודים יחד בעברית ובערבית. הרעיון הוא שהכרות מגיל צעיר תפחית דעות קדומות ותבנה אמון.
אך האתגרים רבים. ערבים ישראלים מתלוננים על הפליה בתקציבים, בתעסוקה ובתכנון. מתחים ביטחוניים מחריפים את הפערים. למרות הקשיים, ארגונים רבים עובדים לקדם שוויון ושותפות.', 'Около 21% граждан Израиля — арабы. Они живут в основном в Галилее, в Треугольнике и в Негеве. Несколько смешанных городов — Хайфа, Яффо, Акко, Лод и Рамле — служат пространствами ежедневного контакта между арабами и евреями.
Хайфа считается моделью сосуществования. Арабы и евреи живут в соседних кварталах, покупают в одних торговых центрах и учатся в одних университетах. Фестиваль «Праздник праздников» демонстрирует совместную жизнь.
Двуязычные школы вроде «Яд бе-яд» обучают арабских и еврейских детей вместе на иврите и арабском. Идея в том, что знакомство с раннего возраста уменьшит предрассудки и построит доверие.
Однако вызовов немало. Израильские арабы жалуются на дискриминацию в бюджетах, занятости и планировании. Обострения безопасности усугубляют разрывы. Несмотря на трудности, многие организации работают над продвижением равенства и партнёрства.', '[{"he": "דו-קיום", "ru": "сосуществование", "translit": "ду-киЮм"}, {"he": "ערבים", "ru": "арабы", "translit": "аравИм"}, {"he": "עיר מעורבת", "ru": "смешанный город", "translit": "ир меурЕвет"}, {"he": "דו-לשוני", "ru": "двуязычный", "translit": "ду-лешонИ"}, {"he": "דעות קדומות", "ru": "предрассудки", "translit": "деОт кдумОт"}, {"he": "הפליה", "ru": "дискриминация", "translit": "hафлайА"}, {"he": "שותפות", "ru": "партнёрство", "translit": "шутафУт"}, {"he": "שוויון", "ru": "равенство", "translit": "шивйОн"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (139, 4, 'שינוי הקיבוצים בישראל', 'Трансформация кибуцев', 'הקיבוץ נולד מתוך רעיון סוציאליסטי: חיים קולקטיביים, עבודה משותפת, וחלוקה שוויונית של משאבים. בקיבוצים הראשונים, אפילו ילדים גדלו בבתי ילדים ולא עם הוריהם. הקיבוץ היה סמל של החלוץ הציוני.
אך בשנות התשעים החל תהליך של הפרטה. קיבוצים רבים עברו ממודל שוויוני למודל דיפרנציאלי: חברים מקבלים משכורות שונות לפי תפקידם, משלמים על שירותים, ויכולים לרכוש דירות.
היום, קיבוצים רבים הפכו למעשה לקהילות פרבריות מבוססות. בתי המגורים שופצו, נפתחו מלונות בוטיק ומסעדות, וחברים חדשים מצטרפים בזכות איכות החיים ולא בגלל האידיאולוגיה.
עם זאת, רוח הקהילתיות לא נעלמה לגמרי. אירועים משותפים, חדר אוכל לארוחות חג, ותחושת ביטחון קהילתי עדיין מאפיינים את החיים בקיבוץ. זהו מודל ייחודי שממשיך להתפתח.', 'Кибуц родился из социалистической идеи: коллективная жизнь, совместный труд и равное распределение ресурсов. В первых кибуцах даже дети росли в детских домах, а не с родителями. Кибуц был символом сионистского первопроходца.
Но в девяностых начался процесс приватизации. Многие кибуцы перешли от эгалитарной модели к дифференциальной: члены получают разные зарплаты по должности, платят за услуги и могут покупать квартиры.
Сегодня многие кибуцы фактически превратились в состоятельные пригородные общины. Дома отремонтированы, открылись бутик-отели и рестораны, новые члены присоединяются ради качества жизни, а не идеологии.
Тем не менее дух общинности не исчез полностью. Совместные мероприятия, общая столовая на праздники и чувство общинной безопасности по-прежнему характеризуют жизнь в кибуце. Это уникальная модель, которая продолжает развиваться.', '[{"he": "קיבוץ", "ru": "кибуц", "translit": "кибУц"}, {"he": "סוציאליסטי", "ru": "социалистический", "translit": "социалИсти"}, {"he": "קולקטיבי", "ru": "коллективный", "translit": "колектИви"}, {"he": "הפרטה", "ru": "приватизация", "translit": "hафратА"}, {"he": "שוויוני", "ru": "эгалитарный", "translit": "шивйонИ"}, {"he": "משכורת", "ru": "зарплата", "translit": "маскОрет"}, {"he": "קהילתיות", "ru": "общинность", "translit": "кеhилатиЮт"}, {"he": "חלוץ", "ru": "первопроходец", "translit": "халУц"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (140, 4, 'שוויון מגדרי בישראל', 'Гендерное равенство', 'ישראל הייתה מהמדינות הראשונות בעולם שנתנו לנשים את הזכות להצביע. גולדה מאיר כיהנה כראש ממשלה כבר בשנת 1969 — הרביעית בעולם. נשים חייבות בשירות צבאי, והן משרתות גם ביחידות קרביות.
עם זאת, פערים מגדריים עדיין קיימים. בתעשיית ההייטק, נשים מהוות רק כשלושים וחמישה אחוז מהעובדים, ובתפקידים בכירים אחוז נמוך עוד יותר. פער השכר בין גברים לנשים עומד על כעשרים ושניים אחוז.
במגזר הדתי, שוויון מגדרי הוא נושא רגיש במיוחד. נשים אינן יכולות לשמש כרבניות בזרם האורתודוקסי, ובבתי הדין הרבניים הן לעתים מופלות בהליכי גירושין.
מאידך, ישראל מובילה בתחום חופשת הלידה ומעונות היום. חוקי הטרדה מינית נחשבים למתקדמים, ותנועת הפמיניזם הישראלית פועלת לצמצום פערים בכל תחומי החיים.', 'Израиль был одним из первых государств, давших женщинам право голоса. Голда Меир стала премьер-министром ещё в 1969 году — четвёртой в мире женщиной на этом посту. Женщины обязаны проходить военную службу и служат даже в боевых подразделениях.
Тем не менее гендерные разрывы сохраняются. В хайтек-индустрии женщины составляют лишь около 35% работников, а на руководящих должностях ещё меньше. Разрыв в зарплатах между мужчинами и женщинами составляет около 22%.
В религиозном секторе гендерное равенство — особенно чувствительная тема. Женщины не могут быть раввинами в ортодоксальном течении, а в раввинских судах они порой подвергаются дискриминации при разводе.
С другой стороны, Израиль лидирует в области декретного отпуска и детских учреждений. Законы о сексуальных домогательствах считаются прогрессивными, а израильское феминистское движение работает над сокращением разрывов во всех сферах жизни.', '[{"he": "שוויון מגדרי", "ru": "гендерное равенство", "translit": "шивйОн мигдарИ"}, {"he": "פער שכר", "ru": "разрыв в зарплатах", "translit": "пЕар сахАр"}, {"he": "הטרדה מינית", "ru": "сексуальное домогательство", "translit": "hатрадА минИт"}, {"he": "חופשת לידה", "ru": "декретный отпуск", "translit": "хуфшАт лейдА"}, {"he": "פמיניזם", "ru": "феминизм", "translit": "феминИзм"}, {"he": "קרבי", "ru": "боевой", "translit": "кравИ"}, {"he": "גירושין", "ru": "развод", "translit": "герушИн"}, {"he": "בכיר", "ru": "руководящий/старший", "translit": "бахИр"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (146, 4, 'מסורת התיאטרון בישראל', 'Театральная традиция', 'התיאטרון הישראלי נולד עוד לפני המדינה. תיאטרון הבימה הוקם במוסקבה בשנת 1917 ועלה לארץ ישראל בשנת 1928. הוא הפך לתיאטרון הלאומי ונשאר פעיל עד היום.
תיאטרון הכמרי בתל אביב, שנוסד בשנת 1944, ידוע בהצגות עכשוויות ופרובוקטיביות. הוא מציג יצירות ישראליות מקוריות לצד קלאסיקות עולמיות, ונחשב למוביל בתיאטרון העברי.
תיאטרון השוליים צמח מאוד בעשורים האחרונים. להקות קטנות ביפו, בחיפה ובבאר שבע יוצרות הצגות ניסיוניות שעוסקות בנושאים חברתיים-פוליטיים: הכיבוש, הפערים, וזכויות מיעוטים.
פסטיבל עכו — פסטיבל תיאטרון אלטרנטיבי בעיר העתיקה — הוא אחד האירועים התרבותיים החשובים בישראל. שם מתרחשות הצגות באתרים היסטוריים, וגבולות התיאטרון המסורתי מיטשטשים.', 'Израильский театр родился ещё до государства. Театр Габима был основан в Москве в 1917 году и переехал в Землю Израиля в 1928 году. Он стал национальным театром и действует по сей день.
Театр Камери в Тель-Авиве, основанный в 1944 году, известен современными и провокационными постановками. Он представляет оригинальные израильские произведения наряду с мировой классикой и считается лидером ивритского театра.
Маргинальный театр значительно вырос за последние десятилетия. Небольшие труппы в Яффо, Хайфе и Беэр-Шеве создают экспериментальные постановки на социально-политические темы: оккупация, разрывы и права меньшинств.
Фестиваль в Акко — фестиваль альтернативного театра в старом городе — одно из важнейших культурных событий Израиля. Там спектакли проходят на исторических площадках, и границы традиционного театра размываются.', '[{"he": "תיאטרון", "ru": "театр", "translit": "теАтрон"}, {"he": "הצגה", "ru": "спектакль/постановка", "translit": "hацагА"}, {"he": "במאי", "ru": "режиссёр", "translit": "бамАй"}, {"he": "להקה", "ru": "труппа", "translit": "лаhакА"}, {"he": "ניסיוני", "ru": "экспериментальный", "translit": "нисйонИ"}, {"he": "פסטיבל", "ru": "фестиваль", "translit": "фестивАль"}, {"he": "קלאסיקה", "ru": "классика", "translit": "клАсика"}, {"he": "שוליים", "ru": "маргинальный", "translit": "шулАйим"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (147, 4, 'פרסי ספרות בישראל', 'Литературные премии', 'הספרות העברית המודרנית היא אחת העשירות בעולם ביחס לגודל האוכלוסייה. שמואל יוסף עגנון זכה בפרס נובל לספרות בשנת 1966 — היהודי הראשון שזכה בפרס זה על יצירה בעברית.
פרס ספיר, שהוקם בשנת 2000, הוא הפרס הספרותי החשוב ביותר בישראל. הוא מוענק מדי שנה ליצירת פרוזה מצטיינת ונושא פרס כספי של מאה אלף שקלים. הזכייה בפרס מבטיחה מכירות גבוהות.
סופרים ישראלים בולטים כמו עמוס עוז, א.ב. יהושע ודוד גרוסמן הפכו לקולות מובילים לא רק בספרות אלא גם בשיח הציבורי. יצירותיהם תורגמו לעשרות שפות.
הדור החדש של סופרים — ביניהם אתגר קרת, רונית מטלון ועיאד ברגותי — מביא קולות מגוונים יותר. ספרות מזרחית, ספרות ערבית-ישראלית וספרות נשים תופסות מקום מרכזי בזירה הספרותית.', 'Современная ивритская литература — одна из богатейших в мире относительно размера населения. Шмуэль Йосеф Агнон получил Нобелевскую премию по литературе в 1966 году — первый еврей, получивший эту премию за произведение на иврите.
Премия Сапир, учреждённая в 2000 году, — важнейшая литературная премия Израиля. Она ежегодно вручается за лучшее прозаическое произведение и составляет 100 тысяч шекелей. Победа гарантирует высокие продажи.
Выдающиеся израильские писатели — Амос Оз, А.Б. Йеhошуа и Давид Гроссман — стали ведущими голосами не только в литературе, но и в общественном дискурсе. Их произведения переведены на десятки языков.
Новое поколение писателей — среди них Этгар Керет, Ронит Маталон и Ияд Бургути — привносит более разнообразные голоса. Восточная литература, арабо-израильская литература и женская литература занимают центральное место на литературной арене.', '[{"he": "ספרות", "ru": "литература", "translit": "сифрУт"}, {"he": "פרוזה", "ru": "проза", "translit": "прОза"}, {"he": "סופר", "ru": "писатель", "translit": "софЕр"}, {"he": "יצירה", "ru": "произведение", "translit": "ецирА"}, {"he": "תרגום", "ru": "перевод", "translit": "тиргУм"}, {"he": "זכייה", "ru": "победа/получение", "translit": "зхийА"}, {"he": "שיח ציבורי", "ru": "общественный дискурс", "translit": "сИах цибурИ"}, {"he": "ספרות מזרחית", "ru": "восточная литература", "translit": "сифрУт мизрахИт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (141, 4, 'זכויות אנשים עם מוגבלות בישראל', 'Права людей с инвалидностью', 'חוק שוויון זכויות לאנשים עם מוגבלויות משנת 1998 היה מהפכה בישראל. החוק קבע כי אנשים עם מוגבלות זכאים לשוויון הזדמנויות בתעסוקה, בחינוך ובגישה למקומות ציבוריים.
נגישות פיזית השתפרה מאוד. אוטובוסים חדשים מצוידים ברמפות, מדרכות כוללות אבני כיוון לעיוורים, ומבנים ציבוריים חייבים לכלול מעליות ושירותים נגישים. אך בפועל, אכיפת החוק אינה מושלמת.
חינוך מכליל הוא עיקרון מרכזי. ילדים עם מוגבלויות לומדים בבתי ספר רגילים עם סיוע פרטני כשצריך. עם זאת, הורים רבים מתלוננים על חוסר במשאבים ובכוח אדם מקצועי.
שילוב בתעסוקה נשאר אתגר. שיעור התעסוקה של אנשים עם מוגבלות נמוך משמעותית מהאוכלוסייה הכללית. ארגונים כמו "בזכות" ונציבות שוויון זכויות פועלים לשיפור המצב.', 'Закон о равных правах людей с инвалидностью 1998 года стал революцией в Израиле. Закон установил, что люди с инвалидностью имеют право на равные возможности в трудоустройстве, образовании и доступе к общественным местам.
Физическая доступность значительно улучшилась. Новые автобусы оснащены пандусами, тротуары включают направляющие плитки для слепых, а общественные здания обязаны иметь лифты и доступные туалеты. Но на практике исполнение закона не идеально.
Инклюзивное образование — центральный принцип. Дети с инвалидностью учатся в обычных школах с индивидуальной поддержкой по необходимости. Тем не менее многие родители жалуются на нехватку ресурсов и профессиональных кадров.
Интеграция в занятость остаётся вызовом. Уровень занятости людей с инвалидностью значительно ниже, чем у населения в целом. Организации вроде «Бизхут» и Комиссия по равным правам работают над улучшением ситуации.', '[{"he": "מוגבלות", "ru": "инвалидность", "translit": "мугбалУт"}, {"he": "נגישות", "ru": "доступность", "translit": "нгишУт"}, {"he": "רמפה", "ru": "пандус", "translit": "рАмпа"}, {"he": "חינוך מכליל", "ru": "инклюзивное образование", "translit": "хинУх махлИль"}, {"he": "שוויון הזדמנויות", "ru": "равные возможности", "translit": "шивйОн hиздамнуЙот"}, {"he": "אכיפה", "ru": "правоприменение", "translit": "ахифА"}, {"he": "סיוע", "ru": "помощь/поддержка", "translit": "сиЮа"}, {"he": "מעלית", "ru": "лифт", "translit": "маалИт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (142, 4, 'זכויות בעלי חיים בישראל', 'Права животных', 'ישראל נחשבת ל"בירת הטבעונות העולמית". כחמישה אחוז מהאוכלוסייה הם טבעוניים — השיעור הגבוה ביותר בעולם. מסעדות טבעוניות פזורות בכל עיר גדולה, והצבא אפילו מספק מדים ומגפיים ללא עור לחיילים טבעוניים.
ישראל הייתה מהמדינות הראשונות שאסרו שימוש בבעלי חיים בקרקסים. חוק צער בעלי חיים אוסר התעללות ומחייב טיפול הולם. בשנת 2021 נאסרה מכירת פרוות בישראל — הראשונה בעולם.
ארגונים כמו "תנו לחיות לחיות" ו"אנונימוס לזכויות בעלי חיים" פועלים להעלאת המודעות. הם מקיימים הפגנות, מציעים שירותי אימוץ, ומפעילים לחץ על הממשלה לחקיקה מחמירה.
עם זאת, תעשיית הבשר בישראל עדיין ענפה. לולי תרנגולות ורפתות נתונים לביקורת על תנאים קשים. הוויכוח בין חקלאים לפעילים ממשיך, כשהציבור נמצא איפשהו באמצע.', 'Израиль считается «веганской столицей мира». Около 5% населения — веганы, самый высокий показатель в мире. Веганские рестораны разбросаны по каждому крупному городу, а армия даже предоставляет форму и ботинки без кожи солдатам-веганам.
Израиль был одним из первых государств, запретивших использование животных в цирках. Закон о жестоком обращении с животными запрещает издевательства и требует надлежащего ухода. В 2021 году в Израиле была запрещена продажа меха — впервые в мире.
Организации вроде «Дайте животным жить» и «Анонимус за права животных» работают над повышением осведомлённости. Они проводят демонстрации, предлагают услуги усыновления и оказывают давление на правительство для принятия более строгих законов.
Тем не менее мясная промышленность в Израиле по-прежнему обширна. Птицефабрики и молочные фермы подвергаются критике за тяжёлые условия. Спор между фермерами и активистами продолжается, а общество — где-то посередине.', '[{"he": "טבעונות", "ru": "веганство", "translit": "тивъонУт"}, {"he": "צער בעלי חיים", "ru": "жестокость к животным", "translit": "цАар баалЕй хайИм"}, {"he": "פרווה", "ru": "мех", "translit": "парвА"}, {"he": "אימוץ", "ru": "усыновление/удочерение", "translit": "имУц"}, {"he": "תעשייה", "ru": "промышленность", "translit": "таасийА"}, {"he": "לול", "ru": "курятник/птицефабрика", "translit": "лул"}, {"he": "חקיקה", "ru": "законодательство", "translit": "хакикА"}, {"he": "מודעות", "ru": "осведомлённость", "translit": "мудаУт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (143, 4, 'תכנון עירוני בישראל', 'Городское планирование', 'אוכלוסיית ישראל צומחת בקצב מהיר — כשני אחוזים בשנה. עד 2050, היא צפויה להגיע לחמישה-עשר מיליון תושבים. הגידול הזה יוצר לחץ עצום על תשתיות, דיור ושטחים פתוחים.
מחירי הדירות בישראל מהגבוהים בעולם. זוגות צעירים אינם יכולים לרכוש דירה במרכז, ורבים עוברים לפריפריה. הממשלה מנסה להגיב בבנייה מואצת, אך הביקוש עולה על ההיצע.
תוכנית ישראל 2040 מציעה פיזור אוכלוסייה לנגב ולגליל. פיתוח תחבורה ציבורית מהירה — כמו הרכבת הקלה בתל אביב — אמור לאפשר מגורים רחוקים ממרכזי התעסוקה.
בנייה ירוקה ותכנון חכם הם חלק מהחזון. ערים כמו חריש נבנו מאפס עם דגש על קיימות: פאנלים סולאריים, גנים ציבוריים, ותשתית לרכבים חשמליים. אך המבקרים טוענים שזה לא מספיק.', 'Население Израиля растёт быстрыми темпами — около 2% в год. К 2050 году ожидается 15 миллионов жителей. Этот рост создаёт огромное давление на инфраструктуру, жильё и открытые пространства.
Цены на квартиры в Израиле — одни из самых высоких в мире. Молодые пары не могут купить жильё в центре и многие переезжают на периферию. Правительство пытается реагировать ускоренным строительством, но спрос превышает предложение.
План «Израиль 2040» предлагает рассредоточение населения в Негев и Галилею. Развитие скоростного общественного транспорта — вроде лёгкого метро в Тель-Авиве — должно позволить проживание вдали от центров занятости.
Зелёное строительство и умное планирование — часть видения. Города вроде Хариша построены с нуля с акцентом на устойчивость: солнечные панели, общественные парки и инфраструктура для электромобилей. Но критики утверждают, что этого недостаточно.', '[{"he": "תכנון עירוני", "ru": "градостроительство", "translit": "тихнУн иронИ"}, {"he": "תשתית", "ru": "инфраструктура", "translit": "таштИт"}, {"he": "דיור", "ru": "жильё", "translit": "диЮр"}, {"he": "קיימות", "ru": "устойчивость", "translit": "кайамУт"}, {"he": "היצע", "ru": "предложение (экон.)", "translit": "hицА"}, {"he": "ביקוש", "ru": "спрос", "translit": "бикУш"}, {"he": "בנייה ירוקה", "ru": "зелёное строительство", "translit": "бнийА йерукА"}, {"he": "פיזור אוכלוסייה", "ru": "рассредоточение населения", "translit": "пизУр ухлусийА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (144, 4, 'מחאות חברתיות בישראל', 'Социальные протесты', 'בקיץ 2011 פרצה בישראל מחאה חברתית שהפתיעה את כולם. דפני ליף, סטודנטית צעירה, הקימה אוהל בשדרות רוטשילד במחאה על מחירי הדיור. תוך שבועות, עשרות אלפי אוהלים כיסו את מרכזי הערים.
ההפגנה הגדולה ביותר משכה כארבע מאות אלף משתתפים — יותר מחמישה אחוז מהאוכלוסייה. הסיסמה "העם דורש צדק חברתי" הפכה לסמל של התנועה. המחאה עסקה ביוקר המחיה, בפערים חברתיים, ובהעדר דיור בר-השגה.
לפני כן, בשנת 2011, פרצה גם "מחאת הקוטג''". צרכנים החרימו גבינת קוטג'' שמחירה עלה בחדות, והחרם הצליח — המחיר ירד. זו הייתה הדוגמה הראשונה לכוח של צרכנים מאורגנים ברשתות חברתיות.
התוצאות של המחאות היו מעורבות. ועדת טרכטנברג המליצה על רפורמות בחינוך ובדיור, אך רבים טוענים שהשינוי לא הספיק. הרוח של 2011 ממשיכה להשפיע על השיח הציבורי.', 'Летом 2011 года в Израиле вспыхнул социальный протест, удививший всех. Дафни Лиф, молодая студентка, поставила палатку на бульваре Ротшильда в знак протеста против цен на жильё. За несколько недель десятки тысяч палаток покрыли центры городов.
Крупнейшая демонстрация собрала около 400 тысяч участников — более 5% населения. Лозунг «Народ требует социальной справедливости» стал символом движения. Протест касался дороговизны жизни, социальных разрывов и отсутствия доступного жилья.
Ещё раньше, в 2011 году, вспыхнул «коттеджный протест». Потребители бойкотировали творог коттедж, цена которого резко выросла, и бойкот удался — цена снизилась. Это стало первым примером силы потребителей, организованных через соцсети.
Результаты протестов были неоднозначными. Комиссия Трахтенберга рекомендовала реформы в образовании и жилье, но многие считают, что изменений недостаточно. Дух 2011 года продолжает влиять на общественный дискурс.', '[{"he": "מחאה", "ru": "протест", "translit": "мехаА"}, {"he": "צדק חברתי", "ru": "социальная справедливость", "translit": "цЕдек хевратИ"}, {"he": "יוקר המחיה", "ru": "дороговизна жизни", "translit": "Йокер hа-михйА"}, {"he": "דיור בר-השגה", "ru": "доступное жильё", "translit": "диЮр бар-hасагА"}, {"he": "חרם", "ru": "бойкот", "translit": "хЕрем"}, {"he": "הפגנה", "ru": "демонстрация", "translit": "hафганА"}, {"he": "רפורמה", "ru": "реформа", "translit": "рефОрма"}, {"he": "פערים", "ru": "разрывы/пробелы", "translit": "пеарИм"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (145, 4, 'הקולנוע הישראלי', 'Израильское кино', 'הקולנוע הישראלי עבר מהפכה בעשרים השנים האחרונות. סרטים ישראליים זוכים להכרה בינלאומית ומתחרים בפסטיבלים מובילים בקאן, ברלין ובוונציה.
"וואלס עם באשיר" של ארי פולמן היה סרט אנימציה תיעודי פורץ דרך שעסק בזיכרונות ממלחמת לבנון הראשונה. "ביופורט" ו"לבנון" בחנו את חוויית הלחימה מזוויות שונות. סרטים אלה הפכו את הטראומה הצבאית לנושא מרכזי.
מעבר לנושאי ביטחון, הקולנוע הישראלי עוסק גם בזהות, בעדתיות ובמתחים חברתיים. סרטים כמו "אור" של כרן ידעיה ו"עג''מי" של סקנדר קופטי חשפו צדדים אפלים של החברה הישראלית.
טקס פרסי אופיר, המקבילה הישראלית לאוסקר, הפך לאירוע תרבותי חשוב. התעשייה נתמכת על ידי קרנות ממשלתיות, אך התקציבים עדיין נמוכים בהשוואה לאירופה.', 'Израильское кино пережило революцию за последние двадцать лет. Израильские фильмы получают международное признание и соревнуются на ведущих фестивалях в Каннах, Берлине и Венеции.
«Вальс с Баширом» Ари Фольмана стал прорывным анимационным документальным фильмом о воспоминаниях Первой ливанской войны. «Бофор» и «Ливан» исследовали боевой опыт под разными углами. Эти фильмы сделали военную травму центральной темой.
Помимо тем безопасности, израильское кино затрагивает вопросы идентичности, этничности и социальных напряжений. Фильмы вроде «Ор» Керен Едая и «Аджами» Скандара Копти обнажили тёмные стороны израильского общества.
Церемония премии Офир, израильского аналога Оскара, стала важным культурным событием. Индустрия поддерживается государственными фондами, но бюджеты по-прежнему невелики по сравнению с Европой.', '[{"he": "קולנוע", "ru": "кино", "translit": "колнОа"}, {"he": "סרט תיעודי", "ru": "документальный фильм", "translit": "сЕрет тиудИ"}, {"he": "פסטיבל", "ru": "фестиваль", "translit": "фестивАль"}, {"he": "אנימציה", "ru": "анимация", "translit": "анимАция"}, {"he": "טראומה", "ru": "травма", "translit": "трАума"}, {"he": "זהות", "ru": "идентичность", "translit": "зеhУт"}, {"he": "תעשייה", "ru": "индустрия", "translit": "таасийА"}, {"he": "פרס", "ru": "премия", "translit": "прас"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (148, 4, 'מדיניות לשונית בישראל', 'Языковая политика', 'עברית היא השפה הרשמית של ישראל. לערבית היה מעמד של שפה רשמית מאז ימי המנדט הבריטי, אך בשנת 2018 שונה מעמדה ל"שפה בעלת מעמד מיוחד". השינוי עורר ויכוח נוקב.
בפועל, השלטים בישראל כתובים בשלוש שפות: עברית, ערבית ואנגלית. בערים מעורבות ובאזורים ערביים, ערבית נוכחת בחיי היומיום. אך במערכת החינוך היהודית, הוראת הערבית מצומצמת.
האקדמיה ללשון העברית, שהוקמה בשנת 1953, אחראית על קביעת כללי הדקדוק, יצירת מילים חדשות ושמירה על טוהר השפה. אך הציבור לא תמיד מקבל את החלטותיה — מילים לועזיות כמו "אינטרנט" ו"טלוויזיה" נשארו בשימוש.
השפעת האנגלית על העברית הולכת וגוברת. בהייטק, בפרסום ובתרבות הפופ, מילים אנגליות חודרות לשפת היומיום. בני נוער משתמשים בסלנג מעורב עברית-אנגלית שמבהיל פוריסטים.', 'Иврит — официальный язык Израиля. Арабский имел статус официального языка со времён британского мандата, но в 2018 году его статус изменился на «язык с особым статусом». Это изменение вызвало острую дискуссию.
На практике вывески в Израиле написаны на трёх языках: иврите, арабском и английском. В смешанных городах и арабских районах арабский присутствует в повседневной жизни. Но в еврейской системе образования преподавание арабского ограничено.
Академия языка иврит, основанная в 1953 году, отвечает за установление грамматических правил, создание новых слов и сохранение чистоты языка. Но публика не всегда принимает её решения — иностранные слова вроде «интернет» и «телевидение» остались в употреблении.
Влияние английского на иврит растёт. В хайтеке, рекламе и поп-культуре английские слова проникают в повседневную речь. Подростки используют смешанный иврито-английский сленг, который пугает пуристов.', '[{"he": "מדיניות לשונית", "ru": "языковая политика", "translit": "мединиЮт лешонИт"}, {"he": "שפה רשמית", "ru": "официальный язык", "translit": "сафА ришмИт"}, {"he": "מעמד", "ru": "статус", "translit": "маамАд"}, {"he": "שלט", "ru": "вывеска", "translit": "шЕлет"}, {"he": "דקדוק", "ru": "грамматика", "translit": "дикдУк"}, {"he": "טוהר השפה", "ru": "чистота языка", "translit": "тОhар hа-сафА"}, {"he": "לועזי", "ru": "иностранный", "translit": "лоазИ"}, {"he": "סלנג", "ru": "сленг", "translit": "слЕнг"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (149, 4, 'פסיקות בג"ץ', 'Решения Верховного суда', 'בית המשפט העליון של ישראל, הידוע גם כבג"ץ — בית הדין הגבוה לצדק — ממלא תפקיד ייחודי. בניגוד למדינות אחרות, כל אזרח יכול לעתור ישירות לבג"ץ נגד רשות ממשלתית, ללא צורך בייצוג עורך דין.
פסיקות בג"ץ עיצבו את החברה הישראלית. פסק דין קול העם קבע את חופש הביטוי כזכות יסוד. פסיקת מזרחי נ'' בנק הפועלים הניחה את היסודות לחוקה הבלתי כתובה של ישראל.
בג"ץ גם התערב בנושאים ביטחוניים. הוא הגביל את השימוש בעינויים בחקירות שב"כ, ופסק כנגד מסלולים מסוימים של גדר ההפרדה. פסיקות אלה יצרו מתח בין הממשלה לבית המשפט.
הוויכוח על הרפורמה המשפטית הציף את השאלה המרכזית: כמה כוח צריך להיות לבית המשפט? תומכי הרפורמה טוענים שהשופטים חרגו מסמכותם, בעוד מתנגדיה רואים בבג"ץ את המגן האחרון של הדמוקרטיה.', 'Верховный суд Израиля, известный также как БАГАЦ (Высший суд справедливости), выполняет уникальную роль. В отличие от других стран, любой гражданин может подать петицию напрямую в БАГАЦ против государственного органа без необходимости адвокатского представительства.
Решения БАГАЦа сформировали израильское общество. Решение «Коль hа-Ам» установило свободу слова как основное право. Решение «Мизрахи против Банка Поалим» заложило основы неписаной конституции Израиля.
БАГАЦ вмешивался и в вопросы безопасности. Он ограничил применение пыток при допросах ШАБАКа и вынес решения против определённых маршрутов разделительного барьера. Эти решения создали напряжённость между правительством и судом.
Дебаты о судебной реформе обнажили центральный вопрос: сколько власти должно быть у суда? Сторонники реформы утверждают, что судьи превысили полномочия, тогда как противники видят в БАГАЦе последнего защитника демократии.', '[{"he": "בג\"ץ", "ru": "БАГАЦ (Верховный суд)", "translit": "бАгац"}, {"he": "עתירה", "ru": "петиция", "translit": "атирА"}, {"he": "פסק דין", "ru": "судебное решение", "translit": "псак дин"}, {"he": "חופש הביטוי", "ru": "свобода слова", "translit": "хОфеш hа-битуй"}, {"he": "רפורמה משפטית", "ru": "судебная реформа", "translit": "рефОрма мишпатИт"}, {"he": "סמכות", "ru": "полномочия", "translit": "самхУт"}, {"he": "חוקה", "ru": "конституция", "translit": "хукА"}, {"he": "עורך דין", "ru": "адвокат", "translit": "орЕх дин"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (150, 4, 'הכלכלה הישראלית אחרי 2020', 'Экономика после 2020', 'מגפת הקורונה פגעה קשות בכלכלה הישראלית. אבטלה זינקה לכעשרים וחמישה אחוז, עסקים קטנים נסגרו, ותעשיית התיירות קרסה. הממשלה הזרימה מיליארדי שקלים במענקים והלוואות כדי למנוע קריסה.
אך ההתאוששות הייתה מהירה. תעשיית ההייטק דווקא פרחה: עבודה מרחוק הפכה לנורמה, והביקוש לטכנולוגיה עלה. בשנת 2021 הושקעו בסטארט-אפים ישראליים כעשרים וחמישה מיליארד דולר — שיא היסטורי.
האינפלציה, שנעלמה כמעט לעשור, חזרה בשנת 2022. מחירי המזון והדיור עלו בחדות, ובנק ישראל העלה את הריבית כדי להילחם בעליית המחירים. אזרחים מהמעמד הבינוני הרגישו את הלחץ.
האי-שוויון הכלכלי נשאר אתגר מרכזי. הפער בין עובדי הייטק מרוויחים לבין עובדים בשכר מינימום ממשיך לגדול. הממשלה מנסה לאזן בין צמיחה כלכלית לבין שוויון חברתי.', 'Пандемия коронавируса тяжело ударила по израильской экономике. Безработица подскочила до ~25%, малые бизнесы закрылись, а туристическая отрасль обрушилась. Правительство направило миллиарды шекелей в виде грантов и кредитов для предотвращения коллапса.
Но восстановление было быстрым. Хайтек-индустрия, наоборот, расцвела: удалённая работа стала нормой, а спрос на технологии вырос. В 2021 году в израильские стартапы было инвестировано ~25 миллиардов долларов — исторический рекорд.
Инфляция, почти исчезнувшая на десятилетие, вернулась в 2022 году. Цены на продукты и жильё резко выросли, и Банк Израиля повысил процентную ставку для борьбы с ростом цен. Средний класс ощутил давление.
Экономическое неравенство остаётся центральным вызовом. Разрыв между высокооплачиваемыми работниками хайтека и работниками с минимальной зарплатой продолжает расти. Правительство пытается балансировать между экономическим ростом и социальным равенством.', '[{"he": "כלכלה", "ru": "экономика", "translit": "калкалА"}, {"he": "אבטלה", "ru": "безработица", "translit": "автолА"}, {"he": "אינפלציה", "ru": "инфляция", "translit": "инфлАция"}, {"he": "ריבית", "ru": "процентная ставка", "translit": "рибИт"}, {"he": "מענק", "ru": "грант", "translit": "маанАк"}, {"he": "התאוששות", "ru": "восстановление", "translit": "hитошешУт"}, {"he": "אי-שוויון", "ru": "неравенство", "translit": "и-шивйОн"}, {"he": "צמיחה", "ru": "рост", "translit": "цмихА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (151, 5, 'מחקר אקדמי על הגירה', 'Академическое исследование миграции', 'מחקר ההגירה העכשווי מבקש לבחון את גלי העלייה לישראל דרך פריזמה רב-תחומית, המשלבת ניתוח דמוגרפי, כלכלי וחברתי. בהינתן שמדינת ישראל קלטה מאז הקמתה למעלה משלושה מיליון עולים ממאה ושלושים מדינות, ניתן לטעון כי מדובר בתופעת הגירה חסרת תקדים בהיקפה היחסי.
הגורמים הדוחפים להגירה כללו רדיפות אנטישמיות, משטרים טוטליטריים ומצוקה כלכלית, בעוד הגורמים המושכים כללו זיקה לאומית-דתית, הבטחת אזרחות מיידית מכוח חוק השבות, ותפיסת ישראל כמקלט בטוח. אף על פי כן, מחקרים מצביעים על כך שהמוטיבציה לעלייה לעולם אינה חד-ממדית.
השפעתם הדמוגרפית של גלי העלייה הייתה מכרעת. עליית יהודי אתיופיה בשנות השמונים והתשעים, ועליית מיליון העולים מחבר העמים לשעבר, שינו את ההרכב האתני-תרבותי של החברה הישראלית מן היסוד.
נוכח העובדה שתהליכי קליטה מוצלחים דורשים השקעה ממשלתית מסיבית בדיור, תעסוקה והכשרה מקצועית, נותר האתגר של שילוב העולים אחת הסוגיות המרכזיות במדיניות החברתית של ישראל. חוקרים מדגישים כי ההצלחה נמדדת לא רק בנתונים כלכליים אלא גם במידת השתלבותם התרבותית של העולים.', 'Современное исследование иммиграции стремится рассмотреть волны репатриации в Израиль через мультидисциплинарную призму, сочетающую демографический, экономический и социальный анализ. Учитывая, что государство Израиль приняло с момента основания более трёх миллионов репатриантов из ста тридцати стран, можно утверждать, что речь идёт о беспрецедентном по относительному масштабу миграционном феномене.
Выталкивающие факторы включали антисемитские преследования, тоталитарные режимы и экономические бедствия, тогда как притягивающие факторы включали национально-религиозную связь, гарантию немедленного гражданства в силу Закона о возвращении и восприятие Израиля как безопасного убежища. Тем не менее исследования указывают, что мотивация к репатриации никогда не является одномерной.
Демографическое влияние волн репатриации было решающим. Репатриация эфиопских евреев в восьмидесятых-девяностых годах и миллион репатриантов из бывшего СССР коренным образом изменили этнокультурный состав израильского общества.
Учитывая, что успешные процессы абсорбции требуют масштабных государственных инвестиций в жильё, занятость и профессиональную подготовку, проблема интеграции репатриантов остаётся одной из ключевых в социальной политике Израиля. Исследователи подчёркивают, что успех измеряется не только экономическими показателями, но и степенью культурной интеграции репатриантов.', '[{"he": "הגירה", "ru": "иммиграция", "translit": "hагирА"}, {"he": "דמוגרפי", "ru": "демографический", "translit": "демогрАфи"}, {"he": "חסר תקדים", "ru": "беспрецедентный", "translit": "хасАр такдИм"}, {"he": "גורם דוחף", "ru": "выталкивающий фактор", "translit": "горЕм дохЕф"}, {"he": "גורם מושך", "ru": "притягивающий фактор", "translit": "горЕм мошЕх"}, {"he": "קליטה", "ru": "абсорбция", "translit": "клитА"}, {"he": "השתלבות", "ru": "интеграция", "translit": "hиштальвУт"}, {"he": "פריזמה רב-תחומית", "ru": "мультидисциплинарная призма", "translit": "прИзма рав-тхумИт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (152, 5, 'מסה על זהות', 'Эссе об идентичности', 'שאלת הזהות הישראלית נותרת אחת הסוגיות הסבוכות ביותר בשיח הציבורי. במדינה שבה מתקיימים זה לצד זה מסורות מזרחיות ומערביות, חילוניות ודתיות, נרטיבים לאומיים ופוסט-לאומיים, ההגדרה העצמית של הקולקטיב הישראלי מעולם לא הייתה מובנת מאליה.
המתח בין מזרח למערב, שנחשב לאחד הקווים המכוננים של החברה הישראלית, בא לידי ביטוי בכל תחומי החיים: מהמטבח דרך המוזיקה ועד לפוליטיקה. אף על פי שהשסע העדתי התמתן בעשורים האחרונים בזכות נישואי תערובת וניעות חברתית, הוא עדיין מהדהד בזיכרון הקולקטיבי.
שאלת "מיהו יהודי" חורגת מן הממד ההלכתי ונוגעת בלב הדמוקרטיה הישראלית. המחלוקת סביב גיור, נישואין אזרחיים וזכויות המיעוטים חושפת את הפער בין חזונה של מדינה יהודית לבין עקרונותיה הדמוקרטיים.
ייתכן שדווקא הפלורליזם המובנה הזה, על כל מתחיו, הוא שמעניק לזהות הישראלית את חיוניותה. כפי שטען הפילוסוף אבישי מרגלית, זהות אינה תכונה קבועה אלא תהליך מתמשך של משא ומתן בין הפרט לכלל.', 'Вопрос израильской идентичности остаётся одним из самых сложных в общественном дискурсе. В государстве, где бок о бок существуют восточные и западные традиции, светскость и религиозность, национальные и постнациональные нарративы, самоопределение израильского коллектива никогда не было само собой разумеющимся.
Напряжение между Востоком и Западом, считающееся одной из определяющих линий израильского общества, проявляется во всех сферах жизни: от кухни через музыку до политики. Хотя этнический раскол смягчился в последние десятилетия благодаря смешанным бракам и социальной мобильности, он по-прежнему отзывается в коллективной памяти.
Вопрос «кто является евреем» выходит за рамки галахического измерения и затрагивает сердце израильской демократии. Споры вокруг гиюра, гражданского брака и прав меньшинств обнажают разрыв между видением еврейского государства и его демократическими принципами.
Возможно, именно этот встроенный плюрализм со всеми его противоречиями и придаёт израильской идентичности её жизненную силу. Как утверждал философ Авишай Маргалит, идентичность — не фиксированное свойство, а непрерывный процесс переговоров между индивидом и коллективом.', '[{"he": "זהות", "ru": "идентичность", "translit": "зеhУт"}, {"he": "שסע עדתי", "ru": "этнический раскол", "translit": "сЭса адатИ"}, {"he": "פלורליזם", "ru": "плюрализм", "translit": "плуралИзм"}, {"he": "חילוניות", "ru": "светскость", "translit": "хилониЮт"}, {"he": "נרטיב", "ru": "нарратив", "translit": "наратИв"}, {"he": "גיור", "ru": "гиюр (принятие иудаизма)", "translit": "гиЮр"}, {"he": "ניעות חברתית", "ru": "социальная мобильность", "translit": "ниУт хевратИт"}, {"he": "קולקטיב", "ru": "коллектив", "translit": "колектИв"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (153, 5, 'סיפור קצר בסגנון קרת', 'Отрывок из Керета', 'הבחור שעמד לפניי בתור לקופה החזיק שלושה דברים: חבילת חיתולים, בקבוק ויסקי ושקית גדולה של חטיפי במבה. הוא נראה כאילו לא ישן שלושה ימים, ומשהו בעיניים שלו גרם לי לחשוב שאולי ההורות הזאת בכלל לא הייתה בתוכניות.
הקופאית שאלה אותו אם יש לו כרטיס מועדון. הוא הביט בה כאילו היא שאלה אותו מה הטעם של הקיום, ואז אמר בקול שקט שהוא חושב שהכרטיס נשאר אצל אשתו לשעבר. המילה ״לשעבר״ נשמעה כמו מכת פטיש על זכוכית דקה.
פתאום הבחנתי שהתינוק שלו, שישב בעגלה ליד הכניסה, התחיל לבכות. והנה הדבר המוזר: ברגע שהבכי התחיל, משהו בפנים של הבחור השתנה לגמרי. החלפתי מקום איתו בתור, והוא חייך אליי חיוך קטן ורץ אל העגלה.
כשיצאתי מהסופר ראיתי אותו יושב על הספסל בחוץ, מחזיק את התינוק בזרוע אחת ואוכל במבה בשנייה. התינוק נרגע. הוויסקי בלט מתוך השקית. חשבתי שזה אולי הדבר הכי ישראלי שראיתי בחיים: בלגן מוחלט, ובכל זאת איכשהו הכול מסתדר.', 'Парень, стоявший передо мной в очереди к кассе, держал три вещи: упаковку подгузников, бутылку виски и большой пакет снеков «Бамба». Он выглядел так, будто не спал три дня, и что-то в его глазах заставило меня подумать, что, возможно, это отцовство вообще не входило в планы.
Кассирша спросила, есть ли у него клубная карта. Он посмотрел на неё так, будто она спросила, в чём смысл бытия, а потом тихо сказал, что карта, кажется, осталась у бывшей жены. Слово «бывшей» прозвучало как удар молота по тонкому стеклу.
Вдруг я заметил, что его младенец, сидевший в коляске у входа, начал плакать. И вот что странно: в тот момент, когда раздался плач, что-то в лице парня полностью изменилось. Я поменялся с ним местами в очереди, и он улыбнулся мне маленькой улыбкой и побежал к коляске.
Выходя из магазина, я увидел его сидящим на скамейке снаружи: в одной руке младенец, в другой — Бамба. Младенец успокоился. Виски торчало из пакета. Я подумал, что это, пожалуй, самое израильское, что я видел в жизни: полный бардак, и всё равно как-то всё устраивается.', '[{"he": "תור", "ru": "очередь", "translit": "тор"}, {"he": "קופאית", "ru": "кассирша", "translit": "купаИт"}, {"he": "חיתולים", "ru": "подгузники", "translit": "хитулИм"}, {"he": "עגלה", "ru": "коляска", "translit": "агалА"}, {"he": "לשעבר", "ru": "бывший", "translit": "лешеавАр"}, {"he": "בלגן", "ru": "бардак/хаос", "translit": "балагАн"}, {"he": "כרטיס מועדון", "ru": "клубная карта", "translit": "картИс моадОн"}, {"he": "ספסל", "ru": "скамейка", "translit": "сафсАль"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (154, 5, 'שירה בסגנון עמיחי', 'Стихи Амихая', 'ירושלים היא עיר שבה כל אבן נושאת את משקלן של תפילות עתיקות, ובכל זאת הילדים משחקים בסמטאות כאילו ההיסטוריה היא רק רקע למשחק הכדורגל שלהם. המתח בין הקדוש לחולין, בין הנצחי לרגע החולף, הוא עצם נשימתה של העיר הזאת.
אני חושב על אבי שהיה רגיל לומר שירושלים היא אישה שכולם אוהבים אותה ואף אחד לא באמת מכיר אותה. הוא עלה לכאן מעיירה קטנה באירופה, וכל חייו ניסה להבין למה האבנים כאן חמות גם בלילה. אולי בגלל כל התפילות שנספגו בהן.
במרחק של שני קילומטרים מהכותל המערבי יש מכולת שבעליה, אבו-חאלד, מוכר קפה שחור לתיירים מבולבלים. הוא אומר שאלוהים גר בעיר הזאת אבל משלם שכר דירה רק לפעמים. יש בכך חוכמה שאני עדיין מנסה לפענח.
ירושלים לא נותנת תשובות. היא שואלת שאלות ומחכה שתגיע לבד למסקנה שאין מסקנות. אולי זה מה שהופך אותה לכל כך אנושית: היא העיר היחידה בעולם שבה אפילו האבנים בוכות, ודווקא בגלל זה אנשים לא מפסיקים לשיר.', 'Иерусалим — город, в котором каждый камень несёт тяжесть древних молитв, и всё же дети играют в переулках, словно история — лишь фон для их футбольного матча. Напряжение между священным и будничным, между вечным и мимолётным мгновением — сама суть дыхания этого города.
Я думаю о своём отце, который любил говорить, что Иерусалим — женщина, которую все любят, но никто по-настоящему не знает. Он приехал сюда из маленького европейского местечка и всю жизнь пытался понять, почему камни здесь тёплые даже ночью. Может быть, из-за всех впитавшихся в них молитв.
В двух километрах от Стены Плача есть лавка, хозяин которой, Абу-Халед, продаёт чёрный кофе растерянным туристам. Он говорит, что Бог живёт в этом городе, но платит за квартиру лишь иногда. В этом есть мудрость, которую я до сих пор пытаюсь разгадать.
Иерусалим не даёт ответов. Он задаёт вопросы и ждёт, пока ты сам придёшь к выводу, что выводов нет. Может быть, именно это делает его таким человечным: это единственный город в мире, где даже камни плачут, и именно поэтому люди не перестают петь.', '[{"he": "סמטה", "ru": "переулок", "translit": "симтА"}, {"he": "חולין", "ru": "будничное/повседневное", "translit": "хулИн"}, {"he": "נצחי", "ru": "вечный", "translit": "ницхИ"}, {"he": "כותל מערבי", "ru": "Стена Плача", "translit": "кОтель мааравИ"}, {"he": "מכולת", "ru": "лавка/магазинчик", "translit": "маколЕт"}, {"he": "תייר", "ru": "турист", "translit": "таяр"}, {"he": "לפענח", "ru": "разгадывать", "translit": "лефаанЕах"}, {"he": "מסקנה", "ru": "вывод/заключение", "translit": "маскенА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (155, 5, 'ניתוח לשוני של העברית המודרנית', 'Лингвистический анализ', 'העברית המודרנית מהווה תופעה ייחודית בלשנות: שפה שעברה תחייה מלאה לאחר שלא שימשה כשפת יומיום במשך כאלפיים שנה. תהליך התחייה, שיוחס במידה רבה לאליעזר בן-יהודה, היה בפועל מאמץ קולקטיבי של קהילות דוברים שעיצבו את השפה במהלך דורות.
השפעות הסובסטרט על העברית המודרנית ניכרות במספר רבדים. במישור הפונולוגי, מערכת ההגאים הושפעה מהיידיש, הרוסית והערבית. במישור התחבירי, ניתן לזהות מבנים המקבילים לשפות הסלאביות, ואילו בלקסיקון חדרו שאילות מהערבית, מהאנגלית ומשפות נוספות.
שונות הרגיסטרים בעברית בת-ימינו היא תחום מחקר מרתק. הפער בין העברית האקדמית-ספרותית לבין העברית המדוברת, ובמיוחד סלנג הנוער, מייצר רצף סוציולינגוויסטי עשיר. דוברים עוברים בין רגיסטרים בהתאם להקשר החברתי, ויכולת זו נתפסת כסמן של שליטה בשפה.
לסיכום, העברית המודרנית אינה סתם המשך ישיר של העברית המקראית או המשנאית, אלא שפה חדשה במהותה, שצמחה על מצע של מסורות לשוניות מגוונות. חקר השפה הזאת מאפשר הבנה עמוקה של הקשר בין שפה, חברה ולאומיות.', 'Современный иврит представляет собой уникальный феномен в лингвистике: язык, прошедший полное возрождение после того, как примерно две тысячи лет не использовался в повседневной речи. Процесс возрождения, приписываемый во многом Элиэзеру Бен-Йехуде, в действительности был коллективным усилием языковых сообществ, формировавших язык на протяжении поколений.
Влияние субстратов на современный иврит заметно на нескольких уровнях. На фонологическом уровне система звуков испытала влияние идиша, русского и арабского. На синтаксическом уровне можно выявить конструкции, параллельные славянским языкам, тогда как в лексиконе закрепились заимствования из арабского, английского и других языков.
Вариативность регистров в современном иврите — увлекательная область исследований. Разрыв между академическо-литературным ивритом и разговорным языком, особенно молодёжным сленгом, порождает богатый социолингвистический континуум. Носители переключаются между регистрами в зависимости от социального контекста, и эта способность воспринимается как маркер языковой компетенции.
Подводя итог, современный иврит — не просто прямое продолжение библейского или мишнаитского иврита, а по сути новый язык, выросший на основе разнообразных языковых традиций. Изучение этого языка позволяет глубже понять связь между языком, обществом и национализмом.', '[{"he": "תחייה", "ru": "возрождение", "translit": "тхийА"}, {"he": "סובסטרט", "ru": "субстрат", "translit": "субстрАт"}, {"he": "פונולוגי", "ru": "фонологический", "translit": "фонолОги"}, {"he": "תחבירי", "ru": "синтаксический", "translit": "тахбирИ"}, {"he": "רגיסטר", "ru": "регистр", "translit": "регИстер"}, {"he": "שאילה", "ru": "заимствование", "translit": "шеилА"}, {"he": "סוציולינגוויסטי", "ru": "социолингвистический", "translit": "соцьолингвИсти"}, {"he": "לקסיקון", "ru": "лексикон", "translit": "лексикОн"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (156, 5, 'פילוסופיה של חינוך', 'Философия образования', 'מרטין בובר, הפילוסוף היהודי-אוסטרי שהיגר לירושלים בשנת 1938, הציג גישה חינוכית שמרכזה הדיאלוג בין המחנך לתלמיד. בהינתן שהחינוך המסורתי נשען על יחסי סמכות חד-כיווניים, הגישה הדיאלוגית של בובר הייתה מהפכנית בזמנה.
לפי בובר, יחסי ״אני-אתה״ הם הבסיס לכל מפגש חינוכי אותנטי. המחנך אינו מכלי ידע ריק שיש למלאו, אלא מכיר בתלמיד כישות שלמה, בעלת עולם פנימי עשיר. תפקיד המורה הוא לא להעביר מידע אלא ליצור מרחב שבו הלומד מגלה את הידע מתוך עצמו.
בישראל של ימינו, תנועת החינוך הדמוקרטי אימצה עקרונות דומים. בתי ספר דמוקרטיים כמו אלה שהוקמו על פי מודל יעקב הכט מאפשרים לתלמידים להשתתף בקבלת החלטות, לבחור את תחומי הלמידה שלהם ולפתח אחריות עצמית.
אף על פי כן, המתח בין חופש לבין מבנה נותר אתגר מרכזי. מבקרים טוענים כי חינוך חסר גבולות עלול ליצור בוגרים חסרי משמעת, בעוד התומכים משיבים כי דווקא החופש מטפח יצירתיות ומוטיבציה פנימית. הוויכוח הזה משקף את השאלה הרחבה יותר של חברה המנסה לאזן בין ערכי הפרט לצרכי הכלל.', 'Мартин Бубер, австро-еврейский философ, эмигрировавший в Иерусалим в 1938 году, представил педагогический подход, в центре которого — диалог между воспитателем и учеником. Учитывая, что традиционное образование опиралось на односторонние отношения власти, диалогический подход Бубера был революционным для своего времени.
По Буберу, отношения «Я-Ты» — основа любой подлинной образовательной встречи. Воспитатель видит не пустой сосуд знаний, подлежащий наполнению, а признаёт ученика как целостную сущность с богатым внутренним миром. Роль учителя — не передавать информацию, а создавать пространство, в котором учащийся открывает знание изнутри себя.
В современном Израиле движение демократического образования приняло схожие принципы. Демократические школы, основанные по модели Яакова Хехта, позволяют ученикам участвовать в принятии решений, выбирать области обучения и развивать личную ответственность.
Тем не менее напряжение между свободой и структурой остаётся ключевым вызовом. Критики утверждают, что безграничное образование может породить выпускников без дисциплины, тогда как сторонники отвечают, что именно свобода воспитывает креативность и внутреннюю мотивацию. Эта дискуссия отражает более широкий вопрос общества, пытающегося балансировать между ценностями личности и потребностями коллектива.', '[{"he": "דיאלוג", "ru": "диалог", "translit": "диалОг"}, {"he": "מחנך", "ru": "воспитатель", "translit": "мехаНех"}, {"he": "סמכות", "ru": "авторитет/власть", "translit": "самхУт"}, {"he": "אותנטי", "ru": "подлинный", "translit": "отЕнти"}, {"he": "חינוך דמוקרטי", "ru": "демократическое образование", "translit": "хинУх демокрАти"}, {"he": "אחריות עצמית", "ru": "личная ответственность", "translit": "ахраюТ ацмИт"}, {"he": "יצירתיות", "ru": "креативность", "translit": "ецирутиЮт"}, {"he": "מוטיבציה פנימית", "ru": "внутренняя мотивация", "translit": "мотивАция пнимИт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (157, 5, 'ביקורת קולנוע ישראלי', 'Критика израильского кино', 'הקולנוע הישראלי עבר מהפך של ממש בעשורים האחרונים. אם בשנות החמישים והשישים שלטו סרטי הגבורה הלאומיים, הרי שמאז שנות השמונים חל מעבר לקולנוע אישי, רפלקטיבי ולעיתים פרובוקטיבי, שאינו נרתע מעיסוק בנושאים כואבים.
נושא הטראומה תופס מקום מרכזי בקולנוע הישראלי העכשווי. סרטים כמו ״ואלס עם באשיר״ של ארי פולמן ו״לבנון״ של שמואל מאוז חקרו את חוויית הלחימה דרך שפה קולנועית חדשנית. העובדה שסרטים אלה זכו להכרה בינלאומית מעידה על האוניברסליות שבסיפור המקומי.
סוגיית הזהות, על גווניה הרבים, מהווה ציר נוסף. סרטים שעוסקים ביחסי יהודים-ערבים, בפערים עדתיים ובמתחים בין חילונים לדתיים זוכים לעניין רב בפסטיבלים בינלאומיים, אולי משום שהם מציעים מבט מורכב על חברה מורכבת.
הצלחת הקולנוע הישראלי בפסטיבלים כמו קאן, ונציה וברלין העלתה שאלות על הקשר בין מימון ממשלתי לחופש אמנותי. נוכח העובדה שרוב הסרטים מתוקצבים בסיוע קרנות ציבוריות, הוויכוח על צנזורה לעומת חופש ביטוי אינו אקדמי גרידא אלא נוגע בלב הפרקטיקה הקולנועית.', 'Израильское кино пережило настоящую революцию в последние десятилетия. Если в пятидесятые-шестидесятые годы доминировали фильмы о национальном героизме, то с восьмидесятых произошёл переход к личному, рефлексивному и порой провокативному кинематографу, не уклоняющемуся от болезненных тем.
Тема травмы занимает центральное место в современном израильском кино. Фильмы вроде «Вальса с Баширом» Ари Фольмана и «Ливана» Шмуэля Маоза исследовали опыт войны через новаторский кинематографический язык. Тот факт, что эти фильмы получили международное признание, свидетельствует об универсальности местной истории.
Проблема идентичности во всех её оттенках составляет ещё одну ось. Фильмы о еврейско-арабских отношениях, этнических разрывах и напряжении между светскими и религиозными вызывают большой интерес на международных фестивалях — возможно, потому что предлагают сложный взгляд на сложное общество.
Успех израильского кино на фестивалях в Каннах, Венеции и Берлине поднял вопросы о связи между государственным финансированием и художественной свободой. Учитывая, что большинство фильмов финансируются при поддержке государственных фондов, дискуссия о цензуре и свободе самовыражения носит не просто академический, а вполне практический характер.', '[{"he": "קולנוע", "ru": "кинематограф", "translit": "колнОа"}, {"he": "טראומה", "ru": "травма", "translit": "трАума"}, {"he": "פסטיבל", "ru": "фестиваль", "translit": "фестивАль"}, {"he": "מימון", "ru": "финансирование", "translit": "мимУн"}, {"he": "צנזורה", "ru": "цензура", "translit": "цензУра"}, {"he": "חופש ביטוי", "ru": "свобода выражения", "translit": "хОфеш битуй"}, {"he": "רפלקטיבי", "ru": "рефлексивный", "translit": "рефлектИви"}, {"he": "פרובוקטיבי", "ru": "провокативный", "translit": "провокатИви"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (158, 5, 'התפתחות הסלנג העברי', 'Эволюция сленга', 'הסלנג העברי מהווה שדה מחקר מרתק עבור חוקרי לשון, שכן הוא משקף תהליכים חברתיים ותרבותיים עמוקים. בהינתן שהעברית החדשה היא שפה צעירה יחסית, הסלנג שלה מתפתח בקצב מהיר במיוחד ומשמש כמעין מראה לשינויים בחברה.
מקורותיו של הסלנג הישראלי מגוונים. הצבא, בתור מוסד שמרכז צעירים מכל שכבות האוכלוסייה, תרם ביטויים רבים ללשון היומיום: ״יאללה״ מהערבית, ״סבבה״ שהפכה לסמן של תרבות הקלילות הישראלית, ו״פדיחה״ שמציינת רגע של מבוכה חברתית.
השפעת הערבית על הסלנג העברי היא תופעה סוציולינגוויסטית מורכבת. מצד אחד, השאלות מהערבית מעידות על מגע תרבותי ושפתי; מצד אחר, הן לעיתים מנותקות מהקשרן המקורי ומקבלות משמעויות חדשות לגמרי בעברית.
בעידן הרשתות החברתיות, הסלנג העברי חווה האצה חסרת תקדים. ביטויים חדשים נולדים ומתים בתוך שבועות, ממים הופכים לביטויים מדוברים, והשפה הכתובה ברשתות מטשטשת את הגבולות בין דיבור לכתיבה. חוקרים מצביעים על כך שהתופעה הזאת מאתגרת את ההבחנה המסורתית בין רגיסטרים.', 'Ивритский сленг представляет собой увлекательное поле исследования для лингвистов, поскольку отражает глубокие социальные и культурные процессы. Учитывая, что новый иврит — относительно молодой язык, его сленг развивается особенно стремительно и служит своего рода зеркалом изменений в обществе.
Источники израильского сленга разнообразны. Армия, как институт, собирающий молодёжь из всех слоёв населения, привнесла множество выражений в повседневную речь: «ялла» из арабского, «сабаба», ставшая маркером израильской культуры лёгкости, и «падиха», обозначающая момент социальной неловкости.
Влияние арабского на ивритский сленг — сложный социолингвистический феномен. С одной стороны, заимствования из арабского свидетельствуют о культурном и языковом контакте; с другой — они порой оторваны от исходного контекста и приобретают в иврите совершенно новые значения.
В эпоху социальных сетей ивритский сленг переживает беспрецедентное ускорение. Новые выражения рождаются и умирают в течение недель, мемы становятся разговорными выражениями, а письменный язык в сетях размывает границы между речью и письмом. Исследователи отмечают, что это явление ставит под сомнение традиционное различение регистров.', '[{"he": "סלנג", "ru": "сленг", "translit": "слЕнг"}, {"he": "שאילה", "ru": "заимствование", "translit": "шеилА"}, {"he": "רשת חברתית", "ru": "социальная сеть", "translit": "рЕшет хевратИт"}, {"he": "ביטוי", "ru": "выражение", "translit": "битуй"}, {"he": "קלילות", "ru": "лёгкость", "translit": "калилУт"}, {"he": "מבוכה", "ru": "смущение/неловкость", "translit": "мевухА"}, {"he": "האצה", "ru": "ускорение", "translit": "hаацА"}, {"he": "ממים", "ru": "мемы", "translit": "мемИм"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (159, 5, 'תקציר מדעי', 'Научный абстракт', 'רקע: תופעת האי-ביטחון התזונתי בקרב קשישים בישראל מהווה בעיה בריאותית וחברתית הולכת וגוברת. מחקרים קודמים הצביעו על קשר בין מצב סוציו-אקונומי נמוך לבין תזונה לקויה, אולם המנגנונים המתווכים טרם נחקרו דיים בהקשר הישראלי.
שיטות: נערך מחקר חתך רוחב בקרב 1,240 נבדקים מעל גיל שבעים בשלוש ערים פריפריאליות. הנבדקים מילאו שאלונים מתוקפים להערכת ביטחון תזונתי, מצב בריאותי ורשת תמיכה חברתית. נתונים דמוגרפיים וכלכליים נאספו מקבצי הביטוח הלאומי.
ממצאים: שיעור האי-ביטחון התזונתי עמד על 23.4 אחוז, עם שונות מובהקת בין קבוצות אתניות. ניתוח רגרסיה רב-משתנית הראה כי בדידות חברתית, מוגבלות תפקודית והכנסה נמוכה היו הגורמים המנבאים החזקים ביותר. תפקידה של הרשת החברתית כגורם מגן היה מובהק סטטיסטית.
מסקנות: הממצאים מצביעים על כך שהתערבות יעילה חייבת לשלב בין סיוע תזונתי ישיר לבין חיזוק הקשרים החברתיים של האוכלוסייה המבוגרת. מומלץ לפתח תוכניות קהילתיות המשלבות ארוחות משותפות עם פעילות חברתית, על מנת להתמודד עם שני הגורמים במקביל.', 'Предпосылки: проблема продовольственной небезопасности среди пожилых людей в Израиле представляет собой нарастающую медико-социальную проблему. Предыдущие исследования указывали на связь между низким социально-экономическим статусом и неполноценным питанием, однако опосредующие механизмы в израильском контексте изучены недостаточно.
Методы: проведено поперечное исследование среди 1240 испытуемых старше семидесяти лет в трёх периферийных городах. Испытуемые заполнили валидированные опросники для оценки продовольственной безопасности, состояния здоровья и сети социальной поддержки. Демографические и экономические данные получены из файлов Национального страхования.
Результаты: уровень продовольственной небезопасности составил 23,4 процента со значимой вариативностью между этническими группами. Многофакторный регрессионный анализ показал, что социальная изоляция, функциональные ограничения и низкий доход были наиболее сильными предикторами. Роль социальной сети как защитного фактора была статистически значимой.
Выводы: результаты указывают на то, что эффективное вмешательство должно сочетать прямую продовольственную помощь с укреплением социальных связей пожилого населения. Рекомендуется разработать общинные программы, сочетающие совместные приёмы пищи с социальной активностью, чтобы одновременно воздействовать на оба фактора.', '[{"he": "ביטחון תזונתי", "ru": "продовольственная безопасность", "translit": "битахОн тзунатИ"}, {"he": "מחקר חתך", "ru": "поперечное исследование", "translit": "мехкАр хатАх"}, {"he": "רגרסיה", "ru": "регрессия", "translit": "рэгрЕсия"}, {"he": "בדידות", "ru": "одиночество", "translit": "бдидУт"}, {"he": "מוגבלות", "ru": "ограничение/инвалидность", "translit": "мугбалУт"}, {"he": "התערבות", "ru": "вмешательство", "translit": "hитарвУт"}, {"he": "גורם מנבא", "ru": "предиктор", "translit": "горЕм менабЕ"}, {"he": "שאלון", "ru": "опросник", "translit": "шеэлОн"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (160, 5, 'פרשנות פוליטית', 'Политический комментарий', 'הדינמיקה הקואליציונית בישראל מהווה אחד המאפיינים הבולטים ביותר של המערכת הפוליטית. בהינתן שמאז הקמת המדינה לא הצליחה אף מפלגה להשיג רוב מוחלט בכנסת, כל ממשלה נאלצת לבנות קואליציה רחבה שלעיתים כוללת מפלגות בעלות אידיאולוגיות סותרות.
המעבר מהדומיננטיות של מפלגת העבודה בעשורים הראשונים למערכת רב-מפלגתית מקוטבת משקף שינויים עמוקים בחברה הישראלית. עליית הליכוד בשנת 1977 סימנה לא רק מהפך פוליטי אלא גם שינוי דמוגרפי ותרבותי, עם ביטוי פוליטי לקולות שנדחקו לשוליים.
בשנים האחרונות, ההסטות האידיאולוגיות מורכבות עוד יותר. המחנה הימני התרחב לכלול רכיבים דתיים-לאומיים, חרדיים וליברטריאנים, בעוד השמאל מתמודד עם משבר זהות. מפלגות מרכז חדשות צצו ונעלמו בקצב מסחרר, מה שמעיד על חוסר יציבות מבנית.
נוכח העובדה שהמערכת הפוליטית הישראלית מושפעת גם מסוגיות ביטחוניות, דתיות ועדתיות בו-זמנית, ניתוח פוליטי מחייב גישה רב-ממדית. הטענה שהקונפליקט הישראלי-פלסטיני הוא הציר היחיד של הפוליטיקה הישראלית כבר אינה מספקת כדי להסביר את מפת הכוחות העכשווית.', 'Коалиционная динамика в Израиле составляет одну из наиболее характерных черт политической системы. Учитывая, что с момента основания государства ни одна партия не получила абсолютного большинства в Кнессете, каждое правительство вынуждено строить широкую коалицию, порой включающую партии с противоречащими идеологиями.
Переход от доминирования партии Труда в первые десятилетия к поляризованной многопартийной системе отражает глубокие изменения в израильском обществе. Приход Ликуда к власти в 1977 году ознаменовал не только политический переворот, но и демографический и культурный сдвиг, давший политическое выражение голосам, оттеснённым на обочину.
В последние годы идеологические сдвиги стали ещё сложнее. Правый лагерь расширился, включив национально-религиозные, ультраортодоксальные и либертарианские элементы, тогда как левый лагерь переживает кризис идентичности. Новые центристские партии появляются и исчезают с головокружительной скоростью, что свидетельствует о структурной нестабильности.
Учитывая, что израильская политическая система одновременно подвержена влиянию вопросов безопасности, религии и этничности, политический анализ требует многомерного подхода. Утверждение, что израильско-палестинский конфликт является единственной осью израильской политики, уже недостаточно для объяснения современной расстановки сил.', '[{"he": "קואליציה", "ru": "коалиция", "translit": "коалИция"}, {"he": "אידיאולוגיה", "ru": "идеология", "translit": "идеолОгия"}, {"he": "מהפך", "ru": "переворот", "translit": "маhапАх"}, {"he": "קיטוב", "ru": "поляризация", "translit": "китУв"}, {"he": "ליברטריאני", "ru": "либертарианский", "translit": "либертариАни"}, {"he": "שוליים", "ru": "периферия/обочина", "translit": "шулАим"}, {"he": "יציבות", "ru": "стабильность", "translit": "яцивУт"}, {"he": "ציר", "ru": "ось", "translit": "цир"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (161, 5, 'ניתוח משפטי', 'Правовой анализ', 'המשפט החוקתי הישראלי מתאפיין במבנה ייחודי: בהיעדר חוקה כתובה אחת, שימשו חוקי היסוד כתחליף חוקתי, במיוחד לאחר המהפכה החוקתית שהוביל הנשיא אהרן ברק בשנות התשעים. מהפכה זו העניקה לבית המשפט העליון סמכות לבטל חוקים הסותרים את חוקי היסוד.
עקרון הביקורת השיפוטית עומד במרכז הוויכוח על מאזן הכוחות בין הרשויות. התומכים טוענים כי בג"ץ מהווה מגן הכרחי של זכויות הפרט ושל עקרונות דמוקרטיים בסיסיים; המתנגדים משיבים כי בית המשפט חרג מסמכותו והפך לגוף מחוקק למעשה, תוך פגיעה בריבונות הכנסת.
הניסיונות לרפורמה במערכת המשפט חשפו קווי שבר עמוקים בחברה הישראלית. השאלה אינה טכנית-משפטית בלבד אלא נוגעת בשאלות יסוד של זהות: האם ישראל היא דמוקרטיה ליברלית, דמוקרטיה יהודית, או שילוב ייחודי שטרם גובש.
אף על פי כן, רוב המומחים מסכימים כי מנגנון כלשהו של ביקורת שיפוטית הוא הכרחי בכל דמוקרטיה. האתגר הוא למצוא את האיזון הנכון בין הגנה על זכויות לבין כיבוד רצון הרוב, מתח שאינו ייחודי לישראל אך מקבל כאן ביטוי חריף במיוחד.', 'Израильское конституционное право отличается уникальной структурой: при отсутствии единой писаной конституции Основные законы служили конституционной заменой, особенно после конституционной революции, осуществлённой председателем Верховного суда Аароном Бараком в девяностых годах. Эта революция наделила Верховный суд полномочиями отменять законы, противоречащие Основным законам.
Принцип судебного надзора стоит в центре спора о балансе властей. Сторонники утверждают, что БАГАЦ является необходимым защитником прав личности и базовых демократических принципов; противники отвечают, что суд вышел за пределы своих полномочий и превратился де-факто в законодательный орган, подрывая суверенитет Кнессета.
Попытки реформирования судебной системы обнажили глубокие линии разлома в израильском обществе. Вопрос носит не только технико-юридический характер, но и затрагивает фундаментальные проблемы идентичности: является ли Израиль либеральной демократией, еврейской демократией или уникальным сочетанием, которое ещё не оформилось.
Тем не менее большинство экспертов согласны, что некий механизм судебного надзора необходим в любой демократии. Задача — найти правильный баланс между защитой прав и уважением воли большинства, напряжение, не уникальное для Израиля, но приобретающее здесь особенно острое выражение.', '[{"he": "חוקה", "ru": "конституция", "translit": "хукА"}, {"he": "ביקורת שיפוטית", "ru": "судебный надзор", "translit": "бикОрет шифутИт"}, {"he": "חוק יסוד", "ru": "Основной закон", "translit": "хок есОд"}, {"he": "ריבונות", "ru": "суверенитет", "translit": "рибонУт"}, {"he": "רפורמה", "ru": "реформа", "translit": "рефОрма"}, {"he": "זכויות הפרט", "ru": "права личности", "translit": "зхуЁт hа-прАт"}, {"he": "רשות", "ru": "ветвь власти", "translit": "решУт"}, {"he": "בית משפט עליון", "ru": "Верховный суд", "translit": "бейт мишпАт эльОн"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (162, 5, 'ביקורת ספרותית', 'Литературная критика', 'הספרות העברית המודרנית עברה תמורות מהותיות מאז ראשיתה בתקופת ההשכלה. אם בתחילת הדרך שלטו נרטיבים לאומיים-קולקטיביים, הרי שבעשורים האחרונים חל מעבר מובהק לכתיבה אישית, מגוונת ופלורליסטית, המאתגרת את הקאנון הספרותי המבוסס.
אחד ההתפתחויות המשמעותיות ביותר הוא עלייתה של הספרות המזרחית. סופרים כמו סמי מיכאל, אלברט סוויסה וסמי שלום שטרית נתנו ביטוי ספרותי לחוויה שנדחקה לשוליים בספרות הישראלית הדומיננטית. יצירותיהם חשפו את הפער בין סיפור ההגמוניה האשכנזית לבין המציאות הרב-תרבותית.
בד בבד, סופרים צעירים מתנסים בז''אנרים חדשים: מדע בדיוני, פנטזיה, גרפיקה נובלה וספרות דיגיטלית. גבולות הקאנון מיטשטשים, והשאלה מה נחשב ל״ספרות רצינית״ מעוררת דיון ער בחוגי האקדמיה והביקורת.
נוכח העובדה שהספרות משמשת כמראה לחברה, ניתן לקרוא את השינויים בספרות העברית כשיקוף של תהליכי פלורליזציה ודמוקרטיזציה תרבותית. הקולות שהיו מושתקים בעבר — נשים, מזרחים, ערבים, להט"בים — תובעים ומקבלים מקום הולך וגדל בנוף הספרותי.', 'Современная ивритская литература претерпела существенные трансформации с момента своего зарождения в эпоху Хаскалы. Если в начале пути доминировали национально-коллективные нарративы, то в последние десятилетия произошёл отчётливый переход к личному, разнообразному и плюралистичному письму, бросающему вызов устоявшемуся литературному канону.
Одно из наиболее значимых явлений — подъём мизрахийской литературы. Писатели вроде Сами Михаэля, Альберта Свиссы и Сами Шалом Шетрита дали литературное выражение опыту, оттеснённому на обочину доминирующей израильской литературы. Их произведения обнажили разрыв между нарративом ашкеназской гегемонии и мультикультурной реальностью.
Параллельно молодые авторы экспериментируют с новыми жанрами: научная фантастика, фэнтези, графический роман и цифровая литература. Границы канона размываются, и вопрос о том, что считать «серьёзной литературой», вызывает оживлённую дискуссию в академических и критических кругах.
Учитывая, что литература служит зеркалом общества, изменения в ивритской литературе можно рассматривать как отражение процессов плюрализации и культурной демократизации. Голоса, замалчивавшиеся в прошлом, — женщин, мизрахим, арабов, ЛГБТ — требуют и получают всё больше места в литературном пространстве.', '[{"he": "קאנון", "ru": "канон", "translit": "кАнон"}, {"he": "ביקורת ספרותית", "ru": "литературная критика", "translit": "бикОрет сифрутИт"}, {"he": "הגמוניה", "ru": "гегемония", "translit": "hегемОния"}, {"he": "פלורליזציה", "ru": "плюрализация", "translit": "плурализАция"}, {"he": "ז''אנר", "ru": "жанр", "translit": "жАнр"}, {"he": "כתיבה", "ru": "писательство/письмо", "translit": "ктивА"}, {"he": "תמורה", "ru": "трансформация", "translit": "тмурА"}, {"he": "שוליים", "ru": "обочина/периферия", "translit": "шулАим"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (163, 5, 'ניתוח כלכלי', 'Экономическая теория', 'אקוסיסטם הסטארט-אפ הישראלי זכה לכינוי ״אומת הסטארט-אפ״ ולא בכדי: מדינה קטנה עם תשעה מיליון תושבים מייצרת מספר חברות הזנק לנפש הגבוה בעולם. אולם מאחורי הנתון המרשים הזה מסתתרת מציאות כלכלית מורכבת.
ריכוזיות השוק הישראלי מהווה בעיה מבנית. מספר מצומצם של קבוצות עסקיות שולט בענפי התשתית, הבנקאות והתקשורת, מה שמגביל את התחרות ומעלה את יוקר המחיה. הניסיונות לפרק ריכוזיות זו באמצעות חקיקה נתקלו בהתנגדות פוליטית וכלכלית.
יוקר המחיה, ובמיוחד מחירי הדיור, הפכו לסוגיה חברתית מרכזית. המחאה החברתית של קיץ 2011 חשפה את הפער ההולך וגדל בין מגזר ההייטק המשגשג לבין שאר המשק. העובדה שעובד הייטק ממוצע מרוויח פי שלושה מהשכר הממוצע במשק מייצרת כלכלה דו-מסלולית.
אף על פי כן, ההישגים הטכנולוגיים של ישראל אינם מקריים. שילוב של שירות צבאי ביחידות טכנולוגיות, תרבות יזמית, מוסדות אקדמיים חזקים והון סיכון זמין יצרו תנאים ייחודיים. האתגר הוא להפוך את ההצלחה הטכנולוגית למנוע צמיחה שמיטיב עם כלל האוכלוסייה.', 'Израильская стартап-экосистема заслужила прозвище «нация стартапов» не случайно: маленькое государство с девятью миллионами жителей производит наибольшее количество стартапов на душу населения в мире. Однако за этим впечатляющим показателем скрывается сложная экономическая реальность.
Концентрация израильского рынка представляет собой структурную проблему. Небольшое число бизнес-групп контролирует инфраструктурные отрасли, банковский сектор и телекоммуникации, что ограничивает конкуренцию и повышает стоимость жизни. Попытки демонтировать эту концентрацию посредством законодательства встретили политическое и экономическое сопротивление.
Стоимость жизни, особенно цены на жильё, стала ключевой социальной проблемой. Социальный протест лета 2011 года обнажил растущий разрыв между процветающим хайтек-сектором и остальной экономикой. Тот факт, что средний работник хайтека зарабатывает втрое больше средней зарплаты по экономике, порождает двухколейную экономику.
Тем не менее технологические достижения Израиля не случайны. Сочетание военной службы в технологических подразделениях, предпринимательской культуры, сильных академических институтов и доступного венчурного капитала создало уникальные условия. Задача — превратить технологический успех в двигатель роста, приносящий пользу всему населению.', '[{"he": "ריכוזיות", "ru": "концентрация", "translit": "рихузиЮт"}, {"he": "תחרות", "ru": "конкуренция", "translit": "тахарУт"}, {"he": "יוקר המחיה", "ru": "стоимость жизни", "translit": "Ёкер hа-махъЯ"}, {"he": "יזמות", "ru": "предпринимательство", "translit": "язамУт"}, {"he": "הון סיכון", "ru": "венчурный капитал", "translit": "hон сикУн"}, {"he": "חברת הזנק", "ru": "стартап-компания", "translit": "хеврАт hазнАк"}, {"he": "מגזר", "ru": "сектор", "translit": "мигзАр"}, {"he": "צמיחה", "ru": "рост", "translit": "цмихА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (164, 5, 'מחקר סוציולוגי', 'Социологическое исследование', 'מבנה המעמדות בישראל מציג דפוסים ייחודיים שאינם מתאימים בהכרח למודלים סוציולוגיים מערביים מובהקים. בהינתן שהחברה הישראלית נבנתה מגלי הגירה שונים, הפערים החברתיים נושאים ממד אתני-תרבותי מובהק שאי-אפשר להתעלם ממנו.
הפער בין אשכנזים למזרחים, שהיה ציר מרכזי בסוציולוגיה הישראלית, עבר שינויים משמעותיים. מצד אחד, נישואי תערובת ועליות בניעות החברתית צמצמו את הפער; מצד אחר, מחקרים מראים כי הרקע העדתי עדיין משפיע על הישגים חינוכיים והזדמנויות תעסוקה, אם כי באופן עקיף יותר מבעבר.
אי-השוויון בחינוך מהווה גורם משכפל של פערים חברתיים. המערכת החינוכית בישראל מחולקת לזרמים — ממלכתי, ממלכתי-דתי, חרדי וערבי — ולכל זרם רמת מימון ותוצאות שונות. הפער בציוני הבגרות ובשיעורי הנגישות להשכלה גבוהה משקף חלוקה מעמדית ואתנית.
נוכח העובדה שישראל היא גם חברת הגירה וגם חברה עם קונפליקט מתמשך, המחקר הסוציולוגי מחייב התייחסות למשתנים ייחודיים. השירות הצבאי, למשל, משמש גורם ממיין חברתי: מי שמשרת ביחידות יוקרתיות מקבל יתרון בשוק העבודה, מה שמנציח דפוסי אי-שוויון קיימים.', 'Классовая структура Израиля демонстрирует уникальные паттерны, не обязательно вписывающиеся в классические западные социологические модели. Учитывая, что израильское общество построено из различных иммиграционных волн, социальные разрывы несут выраженное этнокультурное измерение, которое невозможно игнорировать.
Разрыв между ашкеназами и мизрахим, бывший центральной осью израильской социологии, претерпел существенные изменения. С одной стороны, смешанные браки и рост социальной мобильности сократили разрыв; с другой — исследования показывают, что этническое происхождение по-прежнему влияет на образовательные достижения и трудовые возможности, хотя и более косвенно, чем раньше.
Неравенство в образовании служит фактором воспроизводства социальных разрывов. Образовательная система Израиля разделена на потоки — государственный, государственно-религиозный, ультраортодоксальный и арабский — каждый с разным уровнем финансирования и результатов. Разрыв в баллах аттестата зрелости и доступности высшего образования отражает классовое и этническое разделение.
Учитывая, что Израиль является одновременно иммиграционным обществом и обществом с продолжающимся конфликтом, социологическое исследование требует учёта уникальных переменных. Военная служба, например, выступает социальным сортирующим фактором: отслужившие в престижных подразделениях получают преимущество на рынке труда, что увековечивает существующие модели неравенства.', '[{"he": "מעמד", "ru": "класс/статус", "translit": "маамАд"}, {"he": "אי-שוויון", "ru": "неравенство", "translit": "и-шивьОн"}, {"he": "ניעות חברתית", "ru": "социальная мобильность", "translit": "ниУт хевратИт"}, {"he": "הישג חינוכי", "ru": "образовательное достижение", "translit": "hесЕг хинухИ"}, {"he": "בגרות", "ru": "аттестат зрелости", "translit": "багрУт"}, {"he": "השכלה גבוהה", "ru": "высшее образование", "translit": "hаскалА гвоhА"}, {"he": "משתנה", "ru": "переменная", "translit": "миштанЕ"}, {"he": "דפוס", "ru": "паттерн/модель", "translit": "дфУс"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (165, 5, 'אנתרופולוגיה תרבותית', 'Культурная антропология', 'המטבח הישראלי מהווה מקרה מבחן מרתק עבור חוקרי אנתרופולוגיה של המזון. בהינתן שאוכלוסיית ישראל מורכבת מקהילות עולים ממאות מדינות, המטבח המקומי הוא תוצר של מיזוג תרבותי חסר תקדים: מנות מרוקאיות לצד פולניות, יימניות לצד רומניות, ועל כולן השפעה פלסטינית מקומית.
מסורות החג מספקות חלון ייחודי להבנת מגוון הקהילות. ליל הסדר, למשל, מתנהל באופן שונה מהותית במשפחה יימנית לעומת משפחה אשכנזית: מהתפריט דרך המנגינות ועד לאורך הטקס. ההבדלים הללו, רחוקים מלהיות פולקלור בלבד, משקפים מערכות ערכים ויחסים חברתיים שונים.
תופעת המיזוג התרבותי בולטת במיוחד ברחוב הישראלי. מסעדות מציעות ״חומוס עם ג''חנון״ או ״שקשוקה אסייתית״ — שילובים שהיו בלתי נתפסים בארצות המוצא. חוקרים מכנים זאת ״קריאוליזציה קולינרית״ — תהליך שבו מטבחים שונים מתמזגים ליצירה חדשה שאינה ניתנת לצמצום למרכיביה.
אף על פי כן, הפוליטיקה של המזון אינה תמימה. ויכוחים על ״בעלות״ על מנות כמו חומוס או פלאפל חושפים מתחים לאומיים ותרבותיים עמוקים. השאלה מי מייצג את המטבח ״האותנטי״ היא שאלה על כוח, זיכרון והגמוניה תרבותית.', 'Израильская кухня представляет собой увлекательный кейс для исследователей антропологии питания. Учитывая, что население Израиля состоит из общин репатриантов из сотен стран, местная кухня — продукт беспрецедентного культурного синтеза: марокканские блюда соседствуют с польскими, йеменские — с румынскими, а над всем этим — местное палестинское влияние.
Праздничные традиции предоставляют уникальное окно для понимания разнообразия общин. Пасхальный седер, например, проводится принципиально по-разному в йеменской и ашкеназской семьях: от меню через мелодии до длительности церемонии. Эти различия, далеко не только фольклорные, отражают разные системы ценностей и социальных отношений.
Феномен культурного синтеза особенно заметен на израильской улице. Рестораны предлагают «хумус с джахнуном» или «азиатскую шакшуку» — сочетания, немыслимые в странах происхождения. Исследователи называют это «кулинарной креолизацией» — процессом, при котором разные кухни сливаются в новое творение, не сводимое к его компонентам.
Тем не менее политика еды не так невинна. Споры о «принадлежности» таких блюд, как хумус или фалафель, обнажают глубокие национальные и культурные противоречия. Вопрос о том, кто представляет «аутентичную» кухню, — это вопрос о власти, памяти и культурной гегемонии.', '[{"he": "אנתרופולוגיה", "ru": "антропология", "translit": "антрополОгия"}, {"he": "מיזוג תרבותי", "ru": "культурный синтез", "translit": "мизУг тарбутИ"}, {"he": "קריאוליזציה", "ru": "креолизация", "translit": "криолизАция"}, {"he": "מסורת", "ru": "традиция", "translit": "масОрет"}, {"he": "ליל הסדר", "ru": "пасхальный седер", "translit": "лейль hа-сЕдер"}, {"he": "פולקלור", "ru": "фольклор", "translit": "фольклОр"}, {"he": "אותנטי", "ru": "аутентичный", "translit": "отЕнти"}, {"he": "הגמוניה תרבותית", "ru": "культурная гегемония", "translit": "hегемОния тарбутИт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (166, 5, 'ניתוח מדיה', 'Анализ медиа', 'נוף המדיה הישראלי עבר שינויים דרמטיים בעשורים האחרונים. ריכוזיות הבעלות על אמצעי התקשורת מעוררת חשש בקרב חוקרי תקשורת, שכן מספר מצומצם של קבוצות עסקיות שולט הן בעיתונות הכתובה והן בערוצי הטלוויזיה המסחריים.
השידור הציבורי בישראל עבר טלטלות. סגירת הרשות השנייה והקמת תאגיד השידור הישראלי ״כאן״ לוו בוויכוחים פוליטיים סוערים. השאלה האם שידור ציבורי יכול להיות עצמאי באמת כשהוא ממומן על ידי הממשלה נותרת פתוחה, ומעוררת דיון דומה לזה המתנהל בדמוקרטיות אחרות.
השפעת הרשתות החברתיות על השיח הציבורי בישראל היא עמוקה במיוחד. בחברה קטנה ומקוטבת, פלטפורמות כמו טוויטר ופייסבוק הפכו לזירות המרכזיות של הוויכוח הפוליטי. תופעת החדשות המזויפות והתעמולה הדיגיטלית מאתגרת את יכולת האזרחים להבחין בין עובדות לדעות.
נוכח העובדה שהתקשורת המסורתית מאבדת קוראים וצופים לטובת מדיה דיגיטלית, האתגר של שמירה על עיתונאות איכותית ועצמאית הופך לקריטי. מומחים מזהירים כי ללא תקשורת חזקה ועצמאית, הדמוקרטיה הישראלית עלולה להיפגע.', 'Медиаландшафт Израиля претерпел драматические изменения в последние десятилетия. Концентрация собственности на средства массовой информации вызывает обеспокоенность исследователей коммуникаций, поскольку небольшое число бизнес-групп контролирует и печатную прессу, и коммерческие телеканалы.
Общественное вещание в Израиле пережило потрясения. Закрытие Второго управления и создание Израильской вещательной корпорации «Кан» сопровождались бурными политическими спорами. Вопрос о том, может ли общественное вещание быть по-настоящему независимым при государственном финансировании, остаётся открытым и вызывает дискуссию, аналогичную ведущимся в других демократиях.
Влияние социальных сетей на общественный дискурс в Израиле особенно глубоко. В маленьком и поляризованном обществе платформы вроде Твиттера и Фейсбука стали основными аренами политического спора. Феномен фейковых новостей и цифровой пропаганды ставит под сомнение способность граждан отличать факты от мнений.
Учитывая, что традиционные СМИ теряют читателей и зрителей в пользу цифровых медиа, задача сохранения качественной и независимой журналистики становится критической. Эксперты предупреждают, что без сильных и независимых СМИ израильская демократия может пострадать.', '[{"he": "תקשורת", "ru": "СМИ/коммуникации", "translit": "тикшОрет"}, {"he": "שידור ציבורי", "ru": "общественное вещание", "translit": "шидУр цибурИ"}, {"he": "ריכוזיות", "ru": "концентрация", "translit": "рихузиЮт"}, {"he": "חדשות מזויפות", "ru": "фейковые новости", "translit": "хадашОт мезуяфОт"}, {"he": "תעמולה", "ru": "пропаганда", "translit": "тааумулА"}, {"he": "פלטפורמה", "ru": "платформа", "translit": "платфОрма"}, {"he": "עיתונאות", "ru": "журналистика", "translit": "итонаУт"}, {"he": "שיח ציבורי", "ru": "общественный дискурс", "translit": "сИах цибурИ"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (172, 5, 'מחקרי מגדר', 'Гендерные исследования', 'הפמיניזם בהקשר הדתי-ישראלי מציג אתגרים ייחודיים שאינם מתקיימים באותה צורה בחברות מערביות חילוניות. הניסיון לשלב בין מחויבות להלכה לבין שוויון מגדרי יוצר מתח מתמיד שמניע חשיבה יצירתית הן מבפנים והן מבחוץ.
ארגונים כמו ״נשות הכותל״ הפכו את המאבק על זכות הנשים להתפלל בכותל המערבי לסמל של הוויכוח הרחב יותר על מקומה של האישה בחיים הדתיים. ההתנגדות מצד הממסד הרבני חושפת את הפער בין הלכה מסורתית לבין תפיסות מודרניות של שוויון.
התפתחות זכויות הקהילה הגאה בישראל מציגה תמונה מורכבת. מצד אחד, תל אביב נחשבת לאחת הערים הידידותיות ביותר בעולם לקהילת הלהט"ב; מצד אחר, אין הכרה רשמית בנישואין חד-מיניים, ובזירה הפוליטית הנושא עדיין שנוי במחלוקת.
אף על פי כן, השינוי ניכר. נשים ישראליות מכהנות בתפקידים בכירים בצבא, בפוליטיקה ובמשפט. חוקרות מגדר מציינות כי ההתקדמות אינה ליניארית: בתחומים מסוימים ישראל מתקדמת, בעוד בתחומים אחרים — בעיקר בממשק שבין דת למדינה — הפערים המגדריים נותרו עמוקים.', 'Феминизм в израильском религиозном контексте представляет уникальные вызовы, не существующие в той же форме в западных светских обществах. Попытка совместить приверженность Галахе с гендерным равенством создаёт постоянное напряжение, стимулирующее креативное мышление как изнутри, так и извне.
Организации вроде «Женщин Стены» превратили борьбу за право женщин молиться у Стены Плача в символ более широкой дискуссии о месте женщины в религиозной жизни. Сопротивление раввинского истеблишмента обнажает разрыв между традиционной Галахой и современными представлениями о равенстве.
Развитие прав ЛГБТ-сообщества в Израиле рисует сложную картину. С одной стороны, Тель-Авив считается одним из самых дружелюбных городов мира для ЛГБТ-сообщества; с другой — нет официального признания однополых браков, и на политической арене тема остаётся предметом споров.
Тем не менее перемены заметны. Израильские женщины занимают высокие посты в армии, политике и юриспруденции. Гендерные исследовательницы отмечают, что прогресс не линеен: в некоторых сферах Израиль продвигается вперёд, тогда как в других — особенно на стыке религии и государства — гендерные разрывы остаются глубокими.', '[{"he": "פמיניזם", "ru": "феминизм", "translit": "феминИзм"}, {"he": "מגדר", "ru": "гендер", "translit": "мигдАр"}, {"he": "הלכה", "ru": "Галаха (еврейский закон)", "translit": "hалахА"}, {"he": "שוויון מגדרי", "ru": "гендерное равенство", "translit": "шивьОн мигдарИ"}, {"he": "ממסד", "ru": "истеблишмент", "translit": "мимсАд"}, {"he": "להט\"ב", "ru": "ЛГБТ", "translit": "лаhатАв"}, {"he": "נישואין חד-מיניים", "ru": "однополые браки", "translit": "нисуИн хад-миниИм"}, {"he": "פער מגדרי", "ru": "гендерный разрыв", "translit": "пЕэр мигдарИ"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (167, 5, 'ניתוח מסמך היסטורי', 'Исторический документ', 'מגילת העצמאות של מדינת ישראל, שהוכרזה בי"ד באייר תש"ח, מהווה מסמך מכונן שהשפתו והבטחותיו נותרים נושא לפרשנות מתמשכת. ניתוח לשוני של המגילה חושף בחירות מילוליות מדוקדקות שנועדו לאזן בין אידיאולוגיות מתחרות.
המגילה מתארת את הקמת המדינה כזכות טבעית והיסטורית של העם היהודי, תוך שימוש בשפה המשלבת מסורת דתית עם שיח זכויות מודרני. הביטוי ״מכוח הזכות הטבעית וההיסטורית״ נמנע מאזכור אלוהי מפורש, אך מהדהד רבדים תיאולוגיים עמוקים.
ההבטחות החברתיות של המגילה — שוויון מלא ללא הבדל דת, גזע ומין; חופש דת ומצפון; חינוך ותרבות — יצרו מתח מתמיד עם המציאות. חוקרי משפט מציינים כי למרות שהמגילה אינה חוקה במובן המשפטי הפורמלי, היא משמשת כמקור השראה פרשני בפסיקות בג"ץ.
נוכח העובדה שהמגילה נכתבה בתנאי לחץ ביטחוני קיצוני, ניתן להעריך את חשיבותה כמסמך שביקש לקבוע עקרונות יסוד לדורות. המתח בין הגדרת המדינה כ״מדינה יהודית״ לבין ההבטחה לשוויון זכויות מלא לכל תושביה מלווה את השיח הישראלי עד עצם היום הזה.', 'Декларация независимости государства Израиль, провозглашённая 14 мая 1948 года, представляет собой основополагающий документ, язык и обещания которого остаются предметом непрекращающейся интерпретации. Лингвистический анализ Декларации обнаруживает тщательно выверенные лексические выборы, призванные балансировать между конкурирующими идеологиями.
Декларация описывает создание государства как естественное и историческое право еврейского народа, используя язык, сочетающий религиозную традицию с современным дискурсом прав. Выражение «в силу естественного и исторического права» избегает прямого упоминания Бога, но отзывается глубокими теологическими пластами.
Социальные обещания Декларации — полное равенство вне зависимости от религии, расы и пола; свобода вероисповедания и совести; образование и культура — создали постоянное напряжение с реальностью. Правоведы отмечают, что хотя Декларация не является конституцией в формально-юридическом смысле, она служит источником интерпретационного вдохновения в решениях Верховного суда.
Учитывая, что Декларация писалась в условиях чрезвычайного давления в сфере безопасности, можно оценить её значимость как документа, стремившегося установить основополагающие принципы для поколений. Напряжение между определением государства как «еврейского» и обещанием полного равенства всем его жителям сопровождает израильский дискурс по сей день.', '[{"he": "מגילת העצמאות", "ru": "Декларация независимости", "translit": "мегилАт hа-ацмаУт"}, {"he": "מסמך מכונן", "ru": "основополагающий документ", "translit": "мисмАх мехонЕн"}, {"he": "פרשנות", "ru": "интерпретация", "translit": "паршанУт"}, {"he": "זכות טבעית", "ru": "естественное право", "translit": "зхУт тивИт"}, {"he": "תיאולוגי", "ru": "теологический", "translit": "теолОги"}, {"he": "חופש מצפון", "ru": "свобода совести", "translit": "хОфеш мацпУн"}, {"he": "פסיקה", "ru": "судебное решение", "translit": "псикА"}, {"he": "עקרון יסוד", "ru": "основополагающий принцип", "translit": "икарОн есОд"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (168, 5, 'תורת התרגום', 'Теория перевода', 'תרגום ספרות עברית לשפות אחרות מציב אתגרים ייחודיים הנובעים ממאפייניה של השפה ומהקשרה התרבותי. העברית, כשפה שמית עם מערכת שורשים תלת-עיצורית, מאפשרת משחקי מילים ואסוציאציות שלעיתים בלתי ניתנים לתרגום.
האתגר המרכזי נעוץ בכפל המשמעויות הטבוע בעברית. מילה אחת יכולה להדהד בו-זמנית את הרובד המקראי, המשנאי, הספרותי והסלנגי. כאשר סופר כמו עמוס עוז משתמש במילה ״שלום״, הוא מפעיל את כל הרבדים הללו — משמעות שאין לה מקבילה מדויקת באף שפה.
בהינתן שהספרות הישראלית עמוסה בהתייחסויות לטקסטים דתיים ותרבותיים, המתרגם נדרש להכריע בין נאמנות לטקסט המקור לבין נגישות לקורא היעד. האם להוסיף הערות שוליים שמסבירות רקע תרבותי? האם לתרגם ביטויים אידיומטיים מילולית או למצוא מקבילות בשפת היעד?
תורת התרגום העכשווית מציעה מודלים שונים להתמודדות עם בעיות אלו. גישת ההתאמה התרבותית מדגישה את הצורך לייצר חוויה מקבילה בשפת היעד, ואילו גישת הנכור מבקשת לשמר את הזרות של הטקסט המקורי. בתרגום ספרות עברית, שני הקטבים הללו מופעלים לסירוגין, בהתאם להקשר ולכוונת המתרגם.', 'Перевод ивритской литературы на другие языки ставит уникальные задачи, обусловленные свойствами языка и его культурным контекстом. Иврит как семитский язык с трёхбуквенной корневой системой допускает языковую игру и ассоциации, порой не поддающиеся переводу.
Центральная проблема коренится в присущей ивриту многозначности. Одно слово может одновременно отзываться библейским, мишнаитским, литературным и сленговым пластами. Когда писатель вроде Амоса Оза использует слово «шалом», он активирует все эти пласты — значение, не имеющее точного эквивалента ни в одном языке.
Учитывая, что израильская литература насыщена отсылками к религиозным и культурным текстам, переводчик вынужден выбирать между верностью оригинальному тексту и доступностью для целевого читателя. Добавлять сноски с объяснением культурного контекста? Переводить идиоматические выражения буквально или искать эквиваленты в целевом языке?
Современная теория перевода предлагает различные модели решения этих проблем. Подход культурной адаптации подчёркивает необходимость создать параллельный опыт на целевом языке, тогда как подход отчуждения стремится сохранить чуждость оригинального текста. В переводе ивритской литературы оба полюса задействуются попеременно в зависимости от контекста и намерений переводчика.', '[{"he": "תרגום", "ru": "перевод", "translit": "таргУм"}, {"he": "שורש", "ru": "корень (грамматический)", "translit": "шОреш"}, {"he": "כפל משמעות", "ru": "многозначность", "translit": "кЕфель машмаУт"}, {"he": "נאמנות", "ru": "верность", "translit": "нээманУт"}, {"he": "הערת שוליים", "ru": "сноска", "translit": "hеарАт шулАим"}, {"he": "אידיומטי", "ru": "идиоматический", "translit": "идиомАти"}, {"he": "שפת יעד", "ru": "целевой язык", "translit": "сфАт яАд"}, {"he": "נכור", "ru": "отчуждение", "translit": "нихУр"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (169, 5, 'ניתוח רטורי', 'Анализ риторики', 'הנאום הפוליטי בישראל מהווה שדה מחקר פורה עבור חוקרי רטוריקה. בהינתן שהתרבות הפוליטית הישראלית מאופיינת בישירות ובלתי-פורמליות, הנאום מאלץ את הפוליטיקאים לאמץ רגיסטר שונה מהדיבור היומיומי, ובכך נוצר מתח ייחודי בין אותנטיות לפאתוס.
נאומיו של מנחם בגין מהווים דוגמה לשימוש ברטוריקה מקראית-היסטורית. בגין שזר ביטויים מן המקורות לתוך נאומיו, וייצר שפה פוליטית עשירה באסוציאציות היסטוריות. אסטרטגיה רטורית זו ביקשה לקשר את ההווה הפוליטי אל עומק ההיסטוריה היהודית.
לעומתו, יצחק רבין אימץ סגנון צבאי, ענייני וחסר פאתוס. נאום ״כאן עם פניי אליכם״ בעצרת בכיכר מלכי ישראל ביטא גישה רטורית שונה: הפנייה לשכל הישר, שימוש בגוף ראשון יחיד ובוידוי אישי. הניגוד בין שני סגנונות הנאום משקף פערים אידיאולוגיים ותרבותיים עמוקים.
בעידן התקשורת הדיגיטלית, אמנות הנאום עוברת שינוי. הודעות טוויטר ומשפטי תקיעה מחליפים את הנאום המסורתי, וטכניקות שכנוע מותאמות לקהלים מפולחים. אף על פי כן, ברגעי משבר לאומיים, כוחו של הנאום הישיר עדיין אינו ניתן להמעטה.', 'Политическая речь в Израиле представляет собой плодотворное поле для исследователей риторики. Учитывая, что израильская политическая культура отличается прямотой и неформальностью, речь вынуждает политиков принимать регистр, отличный от повседневной речи, создавая уникальное напряжение между аутентичностью и пафосом.
Речи Менахема Бегина — пример использования библейско-исторической риторики. Бегин вплетал выражения из первоисточников в свои речи, создавая политический язык, богатый историческими ассоциациями. Эта риторическая стратегия стремилась связать политическое настоящее с глубиной еврейской истории.
В отличие от него, Ицхак Рабин принял военный, деловой стиль, лишённый пафоса. Речь «Здесь, лицом к вам» на митинге на площади Царей Израиля выразила иной риторический подход: обращение к здравому смыслу, использование первого лица единственного числа и личная исповедь. Контраст между двумя стилями отражает глубокие идеологические и культурные различия.
В эпоху цифровых коммуникаций искусство речи трансформируется. Твиты и слоганы заменяют традиционную речь, а техники убеждения адаптируются под сегментированную аудиторию. Тем не менее в моменты национального кризиса сила прямой речи по-прежнему не может быть преуменьшена.', '[{"he": "רטוריקה", "ru": "риторика", "translit": "реторИка"}, {"he": "נאום", "ru": "речь (публичная)", "translit": "неУм"}, {"he": "פאתוס", "ru": "пафос", "translit": "пАтос"}, {"he": "שכנוע", "ru": "убеждение", "translit": "шихнУа"}, {"he": "אסטרטגיה", "ru": "стратегия", "translit": "астратЕгия"}, {"he": "אסוציאציה", "ru": "ассоциация", "translit": "асоциАция"}, {"he": "רגיסטר", "ru": "регистр (речевой)", "translit": "регИстер"}, {"he": "וידוי", "ru": "исповедь", "translit": "видУй"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (170, 5, 'מדיניות סביבתית', 'Экологическая политика', 'החקיקה הסביבתית בישראל התפתחה באופן משמעותי בעשורים האחרונים, אולם האתגרים נותרים עצומים. בהינתן שישראל ממוקמת באזור יבש למחצה, שינויי האקלים מהווים איום ישיר על משאבי המים, החקלאות והמגוון הביולוגי.
סוגיית ים המלח מדגימה את המורכבות של מדיניות סביבתית במזרח התיכון. מפלס הים יורד בכמטר בשנה כתוצאה מהפניית מקורות מים מנהר הירדן ומפעילות תעשיית האשלג. תוכניות לחפירת תעלה מהים האדום עוררו ויכוח בין סביבתנים, כלכלנים ומדינאים, כשכל צד מציג ניתוח שונה של עלויות מול תועלות.
ישראל מתמודדת גם עם אתגרים סביבתיים פנים-ארציים: זיהום אוויר באזורי תעשייה, ניהול פסולת בהיקף שאינו עומד בתקנים האירופיים, ובנייה מואצת הפוגעת בשטחים פתוחים. נוכח העובדה שהאוכלוסייה צומחת בקצב מהיר, הלחץ על משאבי הטבע הולך ומתגבר.
אף על פי כן, ישראל מצטיינת בתחומים מסוימים: טכנולוגיות התפלה, שימוש חוזר במים ואנרגיה סולארית. היכולת ליישם את החדשנות הטכנולוגית הזאת במדיניות כוללת ועקבית תקבע אם ישראל תצליח להתמודד עם משבר האקלים.', 'Экологическое законодательство Израиля значительно развилось в последние десятилетия, однако вызовы остаются колоссальными. Учитывая, что Израиль расположен в полузасушливом регионе, изменение климата представляет прямую угрозу водным ресурсам, сельскому хозяйству и биоразнообразию.
Проблема Мёртвого моря демонстрирует сложность экологической политики на Ближнем Востоке. Уровень моря снижается примерно на метр в год из-за отвода водных источников из реки Иордан и деятельности калийной промышленности. Планы прокладки канала из Красного моря вызвали дискуссию между экологами, экономистами и политиками, каждый из которых предлагает свой анализ соотношения затрат и выгод.
Израиль сталкивается и с внутренними экологическими вызовами: загрязнение воздуха в промышленных зонах, управление отходами в объёме, не соответствующем европейским стандартам, и ускоренное строительство, наносящее ущерб открытым пространствам. Учитывая, что население растёт быстрыми темпами, давление на природные ресурсы неуклонно усиливается.
Тем не менее Израиль отличается в определённых областях: технологии опреснения, повторное использование воды и солнечная энергетика. Способность применить этот технологический инновационный потенциал в комплексной и последовательной политике определит, сумеет ли Израиль справиться с климатическим кризисом.', '[{"he": "חקיקה סביבתית", "ru": "экологическое законодательство", "translit": "хакикА свиватИт"}, {"he": "שינויי אקלים", "ru": "изменение климата", "translit": "шинуЕй аклИм"}, {"he": "מגוון ביולוגי", "ru": "биоразнообразие", "translit": "мигвАн биолОги"}, {"he": "התפלה", "ru": "опреснение", "translit": "hатпалА"}, {"he": "פסולת", "ru": "отходы", "translit": "псОлет"}, {"he": "משאבי טבע", "ru": "природные ресурсы", "translit": "машавЕй тЕва"}, {"he": "אנרגיה סולארית", "ru": "солнечная энергия", "translit": "энЕргия солАрит"}, {"he": "תעלה", "ru": "канал", "translit": "теалА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (171, 5, 'אתיקה של טכנולוגיה', 'Этика технологий', 'ישראל כמעצמת סייבר ומודיעין מציבה שאלות אתיות חריפות הנוגעות ליחס בין טכנולוגיה לזכויות אדם. ייצוא טכנולוגיות מעקב לממשלות ברחבי העולם, כולל משטרים סמכותניים, מעורר ביקורת בינלאומית הולכת וגוברת.
פרשת תוכנת הריגול ״פגסוס״ של חברת NSO חשפה את הדילמה במלוא חריפותה. מצד אחד, טכנולוגיית מעקב מתקדמת משמשת למלחמה בטרור ובפשיעה חמורה; מצד אחר, הוכח כי כלים אלה שימשו למעקב אחר עיתונאים, פעילי זכויות אדם ומתנגדי משטר. המתח בין ביטחון לפרטיות אינו תיאורטי אלא מעשי.
הוויכוח על בינה מלאכותית ושימושיה הצבאיים מתחדד בישראל יותר מבכל מקום אחר. פיתוח מערכות נשק אוטונומיות, שימוש באלגוריתמים לזיהוי פנים בשטחים הכבושים ואיסוף מידע ביומטרי מעלים שאלות על גבולות המותר.
נוכח העובדה שישראל מובילה בפיתוח טכנולוגיות אלו, היא נושאת אחריות מיוחדת בעיצוב הנורמות הבינלאומיות. מומחי אתיקה קוראים לפיתוח מסגרת רגולטורית מקיפה שתאזן בין האינטרסים הביטחוניים והכלכליים לבין ההגנה על זכויות הפרט. האתגר הוא להבטיח שהחדשנות הטכנולוגית לא תבוא על חשבון ערכים דמוקרטיים.', 'Израиль как кибер- и разведывательная держава ставит острые этические вопросы, касающиеся соотношения технологий и прав человека. Экспорт технологий наблюдения правительствам по всему миру, включая авторитарные режимы, вызывает нарастающую международную критику.
Скандал вокруг шпионского ПО «Пегас» компании NSO обнажил дилемму во всей её остроте. С одной стороны, передовые технологии наблюдения служат борьбе с терроризмом и тяжкой преступностью; с другой — доказано, что эти инструменты использовались для слежки за журналистами, правозащитниками и оппозиционерами. Напряжение между безопасностью и конфиденциальностью носит не теоретический, а практический характер.
Дискуссия об искусственном интеллекте и его военном применении обостряется в Израиле более, чем где бы то ни было. Разработка автономных систем вооружения, использование алгоритмов распознавания лиц на оккупированных территориях и сбор биометрических данных поднимают вопросы о границах допустимого.
Учитывая, что Израиль лидирует в разработке этих технологий, он несёт особую ответственность за формирование международных норм. Эксперты по этике призывают к разработке всеобъемлющей регуляторной базы, которая уравновесит интересы безопасности и экономики с защитой прав личности. Задача — обеспечить, чтобы технологические инновации не были реализованы за счёт демократических ценностей.', '[{"he": "מעקב", "ru": "слежка/наблюдение", "translit": "маакАв"}, {"he": "בינה מלאכותית", "ru": "искусственный интеллект", "translit": "бинА мелахутИт"}, {"he": "פרטיות", "ru": "конфиденциальность", "translit": "пратиЮт"}, {"he": "ריגול", "ru": "шпионаж", "translit": "ригУль"}, {"he": "אוטונומי", "ru": "автономный", "translit": "отонОми"}, {"he": "ביומטרי", "ru": "биометрический", "translit": "биомЕтри"}, {"he": "רגולטורי", "ru": "регуляторный", "translit": "регулатОри"}, {"he": "סמכותני", "ru": "авторитарный", "translit": "самхутанИ"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (173, 5, 'פילוסופיה דתית', 'Религиозная философия', 'הפילוסופיה הדתית-יהודית חוותה במאה העשרים פריחה אינטלקטואלית שהולידה הוגים מכוננים. הרב יוסף דב סולובייצ''יק, מייסד הזרם המודרני-אורתודוקסי באמריקה, ניסח מודל של ״איש ההלכה״ — דמות דתית המשלבת מחויבות הלכתית עם מודעות פילוסופית.
ישעיהו ליבוביץ'', מנגד, הציג גישה רדיקלית אחרת. הוא דרש הפרדה מוחלטת בין דת למדינה וטען כי שימוש בדת למטרות לאומיות הוא חילול השם. ביקורתו על הכיבוש מנקודת מבט דתית-מוסרית הפכה אותו לדמות שנויה במחלוקת אך משפיעה ביותר.
השאלה כיצד לקיים הלכה במדינה מודרנית נותרת מרכזית. האם חוקי שבת צריכים לחול על המרחב הציבורי? האם הרבנות הראשית צריכה לשלוט בענייני נישואין? האם גיוס יהודים חרדים לצבא הוא חובה דתית או פגיעה בעולם התורה?
נוכח העובדה שישראל היא המדינה היחידה בעולם שבה היהדות היא דת הרוב, שאלות אלו אינן תיאורטיות. ההכרעות בנושאים הללו מעצבות את חייהם של מיליוני אנשים ומשפיעות על אופייה של המדינה. הפילוסופיה הדתית, בהקשר זה, אינה תרגיל אקדמי אלא כלי לעיצוב מדיניות ציבורית.', 'Еврейская религиозная философия пережила в двадцатом веке интеллектуальный расцвет, породивший основополагающих мыслителей. Рав Йосеф Дов Соловейчик, основатель современного ортодоксального направления в Америке, сформулировал модель «человека Галахи» — религиозной фигуры, сочетающей галахическую приверженность с философским сознанием.
Йешаягу Лейбовиц, напротив, представил радикально иной подход. Он требовал полного разделения религии и государства и утверждал, что использование религии в национальных целях — осквернение Имени. Его критика оккупации с религиозно-нравственной позиции сделала его фигурой спорной, но чрезвычайно влиятельной.
Вопрос о том, как соблюдать Галаху в современном государстве, остаётся центральным. Должны ли законы Шаббата распространяться на общественное пространство? Должен ли Главный раввинат контролировать вопросы бракосочетания? Является ли призыв ультраортодоксов в армию религиозным долгом или ударом по миру Торы?
Учитывая, что Израиль — единственное государство в мире, где иудаизм является религией большинства, эти вопросы не теоретические. Решения по ним формируют жизни миллионов людей и влияют на характер государства. Религиозная философия в этом контексте — не академическое упражнение, а инструмент формирования публичной политики.', '[{"he": "פילוסופיה דתית", "ru": "религиозная философия", "translit": "филосОфия датИт"}, {"he": "הלכה", "ru": "Галаха", "translit": "hалахА"}, {"he": "חילול השם", "ru": "осквернение Имени", "translit": "хилУль hа-шЕм"}, {"he": "אורתודוקסי", "ru": "ортодоксальный", "translit": "ортодОкси"}, {"he": "רבנות ראשית", "ru": "Главный раввинат", "translit": "рабанУт рашИт"}, {"he": "הפרדה", "ru": "разделение", "translit": "hафрадА"}, {"he": "חובה דתית", "ru": "религиозный долг", "translit": "ховА датИт"}, {"he": "הוגה", "ru": "мыслитель", "translit": "hогЕ"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (174, 5, 'ביקורת אמנות', 'Критика искусства', 'זירת האמנות הישראלית מציגה דינמיקה ייחודית הנובעת מהמפגש בין מסורות אמנותיות אירופיות לבין זהויות מקומיות מגוונות. אקדמיית בצלאל, שנוסדה בשנת 1906, הייתה מאז ומתמיד זירה שבה נרקם הדיאלוג בין אמנות ולאום, בין אסתטיקה לפוליטיקה.
האמנות הפוליטית בישראל מתמודדת עם מתח מתמיד. אמנים שעוסקים בכיבוש, בזכויות אדם או בביקורת חברתית נתקלים לעיתים בלחץ ציבורי ובאיומי קיצוץ תקציבי. השאלה האם מימון ציבורי מחייב הגבלה על תכנים אמנותיים מהדהדת בכל דיון על חופש הביטוי האמנותי.
בעשורים האחרונים, אמנים ישראלים זכו להכרה בינלאומית נרחבת. מיצגים בביינאלה של ונציה, תערוכות בגלריות מובילות באירופה ובארצות הברית, ושיתופי פעולה בינלאומיים מעידים על בשלות ורלוונטיות של סצנת האמנות המקומית.
אף על פי כן, שוק האמנות הישראלי נותר קטן ומוגבל. רוב האמנים מתקיימים מהוראה או ממקצועות אחרים, והפער בין ההכרה הבינלאומית לבין התמיכה המקומית ניכר. ביקורת האמנות, בהקשר זה, נדרשת לא רק לנתח יצירות אלא גם לחשוף את התנאים החברתיים-כלכליים שבהם נוצרת אמנות בישראל.', 'Израильская арт-сцена демонстрирует уникальную динамику, обусловленную встречей европейских художественных традиций с разнообразными местными идентичностями. Академия Бецалель, основанная в 1906 году, всегда была ареной диалога между искусством и нацией, между эстетикой и политикой.
Политическое искусство в Израиле сталкивается с постоянным напряжением. Художники, обращающиеся к теме оккупации, прав человека или социальной критики, порой подвергаются общественному давлению и угрозам бюджетных сокращений. Вопрос о том, обязывает ли государственное финансирование ограничивать художественное содержание, звучит в каждой дискуссии о свободе художественного выражения.
В последние десятилетия израильские художники получили широкое международное признание. Инсталляции на Венецианской биеннале, выставки в ведущих галереях Европы и США и международные коллаборации свидетельствуют о зрелости и релевантности местной арт-сцены.
Тем не менее израильский арт-рынок остаётся маленьким и ограниченным. Большинство художников живут за счёт преподавания или других профессий, и разрыв между международным признанием и местной поддержкой очевиден. Художественная критика в этом контексте должна не только анализировать произведения, но и раскрывать социально-экономические условия, в которых создаётся искусство в Израиле.', '[{"he": "אמנות", "ru": "искусство", "translit": "оманУт"}, {"he": "ביינאלה", "ru": "биеннале", "translit": "биенАле"}, {"he": "אסתטיקה", "ru": "эстетика", "translit": "эстЕтика"}, {"he": "מיצג", "ru": "инсталляция", "translit": "мицАг"}, {"he": "גלריה", "ru": "галерея", "translit": "галерИя"}, {"he": "חופש ביטוי", "ru": "свобода выражения", "translit": "хОфеш битуй"}, {"he": "תקציב", "ru": "бюджет", "translit": "такцИв"}, {"he": "סצנה", "ru": "сцена (арт-сцена)", "translit": "сцЕна"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (175, 5, 'ניתוח מוזיקלי', 'Теория музыки', 'הנוף המוזיקלי הישראלי מציג מורכבות שמשקפת את ריבוי הזהויות בחברה. מאז ימיה הראשונים של המדינה, כאשר השירים הארצישראליים שימשו ככלי לבניית זהות לאומית, ועד לעידן הנוכחי של גלובליזציה מוזיקלית, המוזיקה הישראלית עברה מהפכות של ממש.
תחיית המוזיקה המזרחית היא אחת התופעות המשמעותיות בתרבות הישראלית העכשווית. אמנים כמו עומר אדם וסטטיק ונפתלי שילבו מקצבים מזרחיים עם פופ מערבי ויצרו ז''אנר שמושך מיליוני מאזינים. תהליך זה, שכונה ״תחיית המזרחית״, משקף את ההכרה ההולכת וגדלה בתרומתה של התרבות המזרחית לזהות הישראלית.
האירוויזיון מהווה נקודת מפגש מרתקת בין מוזיקה, זהות לאומית ופוליטיקה בינלאומית. הניצחונות של ישראל בתחרות, ובמיוחד הביצוע של נטע ברזילי בשנת 2018, עוררו דיון על ייצוג לאומי ועל השימוש בתרבות ככלי דיפלומטי.
נוכח העובדה שהמוזיקה הישראלית מושפעת בו-זמנית ממסורות מזרחיות, מערביות ואפריקאיות, היא מציעה מודל מרתק של יצירתיות בין-תרבותית. חוקרי מוזיקולוגיה מצביעים על כך שדווקא המתח בין המסורות השונות הוא שמייצר את האנרגיה היצירתית הייחודית של המוזיקה הישראלית.', 'Израильский музыкальный ландшафт демонстрирует сложность, отражающую множественность идентичностей в обществе. С первых дней государства, когда эрец-исраэльские песни служили инструментом формирования национальной идентичности, до нынешней эпохи музыкальной глобализации израильская музыка прошла через настоящие революции.
Возрождение восточной музыки — одно из наиболее значимых явлений в современной израильской культуре. Артисты вроде Омера Адама и Static & Ben-El соединили восточные ритмы с западным попом и создали жанр, привлекающий миллионы слушателей. Этот процесс, названный «восточным возрождением», отражает растущее признание вклада восточной культуры в израильскую идентичность.
Евровидение представляет собой увлекательную точку пересечения музыки, национальной идентичности и международной политики. Победы Израиля на конкурсе, особенно выступление Нетты Барзилай в 2018 году, вызвали дискуссию о национальном представительстве и об использовании культуры как дипломатического инструмента.
Учитывая, что израильская музыка одновременно испытывает влияние восточных, западных и африканских традиций, она предлагает увлекательную модель межкультурного творчества. Музыковеды отмечают, что именно напряжение между различными традициями порождает уникальную творческую энергию израильской музыки.', '[{"he": "מוזיקה", "ru": "музыка", "translit": "мУзика"}, {"he": "מקצב", "ru": "ритм", "translit": "микцАв"}, {"he": "ז''אנר", "ru": "жанр", "translit": "жАнр"}, {"he": "מוזיקולוגיה", "ru": "музыковедение", "translit": "музиколОгия"}, {"he": "דיפלומטיה", "ru": "дипломатия", "translit": "диплоМатия"}, {"he": "גלובליזציה", "ru": "глобализация", "translit": "глобализАция"}, {"he": "תחייה", "ru": "возрождение", "translit": "тхийА"}, {"he": "ייצוג", "ru": "представительство", "translit": "ицУг"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (176, 5, 'דוגמה לכתיבה יוצרת', 'Образец творческого письма', 'היא חושבת שתל אביב היא עיר שלא ישנה אף פעם, אבל זה לא נכון. תל אביב ישנה כל הזמן — רק שהיא חולמת בקול רם. בלילות היא שומעת את הים נושם מאחורי הבניינים, ואת הרכבת הקלה שטרם נבנתה כבר רועשת בדמיונה של העיר הזאת שתמיד מבטיחה את העתיד ומעכלת את ההווה.
בבוקר היא יושבת בבית הקפה ברוטשילד וצופה באנשים שעוברים. כולם ממהרים, כולם מדברים בטלפון, כולם בטוחים שהם הולכים למקום חשוב. היא חושבת שאולי זאת המהות של להיות ישראלי: לרוץ מהר מאוד אל משהו שאף אחד לא יכול להגדיר בדיוק.
אבא שלה היה רגיל לומר שישראלים הם אנשים שקיבלו ארץ בלי הוראות הפעלה. היא חשבה שזה מצחיק, אבל עכשיו, בגיל שלושים ושבע, אחרי גירושין אחד ושלוש החלפות קריירה, היא מבינה שאולי הוא דיבר גם עליה. גם היא חיה בלי הוראות הפעלה, ואולי דווקא בזה יש משהו משחרר.
הים שם, בסוף הרחוב. הוא לא הולך לשום מקום. ואולי זה מספיק: לדעת שיש משהו שלא ישתנה, בתוך עיר שמשנה את עורה כל חמש שנים. היא שותה את הקפה האחרון, משאירה טיפ נדיב מדי, ויוצאת לתוך האור.', 'Она думает, что Тель-Авив — город, который никогда не спит, но это неправда. Тель-Авив спит всё время — просто он видит сны вслух. По ночам она слышит, как море дышит за зданиями, и как лёгкое метро, ещё не построенное, уже шумит в воображении этого города, который вечно обещает будущее и переваривает настоящее.
Утром она сидит в кафе на Ротшильде и наблюдает за прохожими. Все спешат, все говорят по телефону, все уверены, что идут куда-то важно. Она думает, что, возможно, в этом и есть суть быть израильтянином: бежать очень быстро к чему-то, что никто не может точно определить.
Её папа любил говорить, что израильтяне — люди, получившие страну без инструкции по применению. Она думала, что это смешно, но сейчас, в тридцать семь, после одного развода и трёх смен карьеры, она понимает, что, возможно, он говорил и о ней тоже. Она тоже живёт без инструкции, и, может быть, именно в этом есть что-то освобождающее.
Море там, в конце улицы. Оно никуда не уходит. И, может быть, этого достаточно: знать, что есть что-то неизменное в городе, который меняет свою кожу каждые пять лет. Она допивает последний кофе, оставляет слишком щедрые чаевые и выходит на свет.', '[{"he": "זרם תודעה", "ru": "поток сознания", "translit": "зЕрем тодаА"}, {"he": "דמיון", "ru": "воображение", "translit": "димьОн"}, {"he": "גירושין", "ru": "развод", "translit": "гирушИн"}, {"he": "משחרר", "ru": "освобождающий", "translit": "мешахрЕр"}, {"he": "מהות", "ru": "суть/сущность", "translit": "маhУт"}, {"he": "הוראות הפעלה", "ru": "инструкция по применению", "translit": "hораОт hафаалА"}, {"he": "נדיב", "ru": "щедрый", "translit": "надИв"}, {"he": "עור", "ru": "кожа", "translit": "ор"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (177, 5, 'סקירת רמת C1', 'Обзор C1', 'הגעתם לרמה המתקדמת ביותר בתוכנית זו, ועם זאת חשוב להבין כי שליטה בשפה היא תהליך מתמשך שאינו מגיע לנקודת סיום מוגדרת. ברמת C1, הדובר מסוגל להשתתף בשיח אקדמי ומקצועי, להבין טקסטים מורכבים ולהביע רעיונות מופשטים בבהירות ובדייקנות.
אחד המאפיינים המרכזיים של רמה זו הוא היכולת לעבור בין רגיסטרים שונים בצורה טבעית. דובר ברמת C1 מבחין בין עברית אקדמית-ספרותית לבין עברית מדוברת, ויודע מתי להשתמש בכל אחת מהן. מיומנות זו כוללת הבנה של הנימות הסוציולינגוויסטיות הדקות שמבדילות בין רשמיות לחברתיות.
בהינתן שהעברית המודרנית עשירה בשכבות היסטוריות — מן המקרא דרך המשנה ועד לסלנג בן-ימינו — דובר מתקדם נדרש לפתח רגישות לרבדי המשמעות הללו. מילה אחת בעברית יכולה לשאת עמה אלפי שנים של הקשרים, וההבנה הזאת מעשירה את חוויית הקריאה והשיחה.
לסיכום, המסע ללמידת העברית ברמה גבוהה הוא גם מסע להבנת התרבות הישראלית על מורכבויותיה. השפה אינה רק כלי תקשורת אלא מפתח להבנת חברה, היסטוריה ועולם ערכים. אנו מקווים שהתכנים שלמדתם ברמה זו העניקו לכם את הכלים להמשיך ולהעמיק את הידע שלכם בעברית.', 'Вы достигли самого продвинутого уровня в этой программе, и тем не менее важно понимать, что владение языком — непрерывный процесс, не имеющий определённой конечной точки. На уровне C1 говорящий способен участвовать в академическом и профессиональном дискурсе, понимать сложные тексты и выражать абстрактные идеи ясно и точно.
Одна из ключевых характеристик этого уровня — способность естественно переключаться между различными регистрами. Говорящий на уровне C1 различает академическо-литературный иврит и разговорный и знает, когда использовать каждый из них. Этот навык включает понимание тонких социолингвистических оттенков, отличающих формальное от дружеского.
Учитывая, что современный иврит богат историческими слоями — от Библии через Мишну до современного сленга, — продвинутый говорящий должен развить чувствительность к этим пластам значений. Одно слово на иврите может нести в себе тысячи лет контекстов, и это понимание обогащает опыт чтения и беседы.
Подводя итог, путь к изучению иврита на высоком уровне — это одновременно путь к пониманию израильской культуры во всей её сложности. Язык — не просто средство общения, а ключ к пониманию общества, истории и системы ценностей. Мы надеемся, что материалы, изученные на этом уровне, дали вам инструменты для дальнейшего углубления знаний иврита.', '[{"he": "שליטה בשפה", "ru": "владение языком", "translit": "шлитА ба-сафА"}, {"he": "רגיסטר", "ru": "регистр (речевой)", "translit": "регИстер"}, {"he": "מופשט", "ru": "абстрактный", "translit": "муфшАт"}, {"he": "דייקנות", "ru": "точность", "translit": "дайканУт"}, {"he": "נימה", "ru": "оттенок/нюанс", "translit": "нимА"}, {"he": "רובד", "ru": "пласт/слой", "translit": "рОвед"}, {"he": "רשמיות", "ru": "формальность", "translit": "ришмиЮт"}, {"he": "מיומנות", "ru": "навык/компетенция", "translit": "меюманУт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (178, 6, 'ניתוח חוזה שכירות דירה', 'Арендный договор', 'חוזה השכירות הסטנדרטי בישראל כולל סעיפים מהותיים שנועדו להגן הן על המשכיר והן על השוכר. בראש ובראשונה, על החוזה לפרט את תקופת השכירות, את דמי השכירות החודשיים ואת מועד תשלומם. נהוג לקבוע כי האיחור בתשלום יגרור פיצוי מוסכם, אשר שיעורו נקבע מראש בהסכמת הצדדים.
סעיף הערבות מהווה נדבך מרכזי בחוזה. המשכיר רשאי לדרוש ערבות בנקאית אוטונומית, שטר חוב או ערבים אישיים. בפסיקת בתי המשפט נקבע כי גובה הערבות צריך לעמוד ביחס סביר לדמי השכירות, ואין להפעילה אלא בנסיבות המפורטות בחוזה.
תשלומי הארנונה מוטלים על פי חוק על המחזיק בנכס, כלומר על השוכר. עם זאת, חשוב לוודא שהנכס רשום כראוי בעירייה ושסיווגו נכון — שכן סיווג שגוי עלול להביא לחיובי יתר. השוכר זכאי לפנות לוועדת ערר על שומת הארנונה.
חוק השכירות והשאילה, התשל"א-1971, מעניק לשוכר זכויות בסיסיות שאין להתנות עליהן. בין היתר, חובת המשכיר לתקן ליקויים מהותיים המונעים מגורים תקינים. הפרת חובה זו מקנה לשוכר עילה לביטול החוזה.
לסיכום, חוזה שכירות ראוי צריך להיות מאוזן, ברור ומפורט. מומלץ להיעזר בעורך דין הבקיא בדיני מקרקעין בטרם חתימה, שכן הזנחת סעיפים מהותיים עלולה לגרום לנזקים כספיים ומשפטיים כאחד.', 'Стандартный договор аренды жилья в Израиле включает существенные пункты, призванные защитить как арендодателя, так и арендатора. Прежде всего, договор должен определять срок аренды, ежемесячную арендную плату и даты платежей. Принято устанавливать, что задержка оплаты повлечёт заранее согласованную неустойку, размер которой определяется по соглашению сторон.
Пункт о гарантии является центральным элементом договора. Арендодатель вправе потребовать автономную банковскую гарантию, долговое обязательство или личных поручителей. В судебной практике установлено, что размер гарантии должен находиться в разумном соотношении с арендной платой и не может быть реализован за пределами обстоятельств, указанных в договоре.
Платежи по арноне возлагаются по закону на владельца (то есть арендатора). Тем не менее важно убедиться, что объект надлежащим образом зарегистрирован в муниципалитете и правильно классифицирован — неверная классификация может привести к переплатам. Арендатор вправе обратиться в апелляционную комиссию по оценке арноны.
Закон об аренде и безвозмездном пользовании 1971 года предоставляет арендатору базовые права, от которых нельзя отказаться по договору. В частности, арендодатель обязан устранять существенные дефекты, препятствующие нормальному проживанию. Нарушение этой обязанности даёт арендатору основание для расторжения договора.
Подводя итог, надлежащий договор аренды должен быть сбалансированным, ясным и детальным. Рекомендуется обратиться к адвокату, специализирующемуся в земельном праве, перед подписанием, поскольку пренебрежение существенными пунктами может повлечь как финансовый, так и юридический ущерб.', '[{"he": "חוזה שכירות", "ru": "договор аренды", "translit": "хозЭ схирУт"}, {"he": "ערבות בנקאית", "ru": "банковская гарантия", "translit": "аравУт банкаИт"}, {"he": "ארנונה", "ru": "муниципальный налог", "translit": "арнонА"}, {"he": "פיצוי מוסכם", "ru": "согласованная неустойка", "translit": "пицУй мускАм"}, {"he": "שטר חוב", "ru": "долговое обязательство", "translit": "штар хов"}, {"he": "משכיר", "ru": "арендодатель", "translit": "масхИр"}, {"he": "שוכר", "ru": "арендатор", "translit": "сохЭр"}, {"he": "דיני מקרקעין", "ru": "земельное право", "translit": "динЭй мекаркеИн"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (179, 6, 'רצנזיה אקדמית: מתודולוגיה ומסגרת תאורטית', 'Академическая рецензия', 'הספר הנדון מציע תרומה משמעותית לשדה המחקר, אולם אינו חף מחולשות מתודולוגיות המחייבות בחינה ביקורתית. המחבר מבקש לפרוץ דרך חדשה בחקר הזהות התרבותית בישראל, תוך שימוש בגישה אינטרדיסציפלינרית המשלבת סוציולוגיה, אנתרופולוגיה ובלשנות.
המסגרת התאורטית נשענת בעיקרה על תורתו של בורדייה בדבר ההון התרבותי, תוך הרחבתה לבחינת מרחבים חברתיים ייחודיים לחברה הישראלית. גישה זו פורייה, אך המחבר אינו מתמודד דיו עם הביקורת שנמתחה על מושג ההביטוס בהקשרים פוסט-קולוניאליים.
מבחינה מתודולוגית, המחקר מבוסס על ראיונות עומק עם שמונים משתתפים מרקעים אתניים שונים. הדגימה מגוונת, אך נראה כי ייצוג קבוצות מיעוט מסוימות — בפרט יוצאי אתיופיה — לוקה בחסר. כמו כן, המחבר אינו מסביר את שיטת הקידוד של הנתונים האיכותניים בפירוט מספק.
הפרקים האמפיריים מציגים ממצאים מעניינים, ובפרט הניתוח של שינויי הרגיסטר הלשוני בין בני הדור השני לבין הוריהם. עם זאת, הפער בין הממצאים לבין המסקנות רחב מדי: המחבר נוטה להכללות שאינן נתמכות דיין בנתונים.
חרף ההסתייגויות, מדובר בחיבור חשוב התורם לשיח האקדמי. ממליץ על פרסומו לאחר תיקונים מתודולוגיים ועריכה מחודשת של פרק הדיון.', 'Рецензируемая книга представляет значительный вклад в данную область исследований, однако не лишена методологических слабостей, требующих критического рассмотрения. Автор стремится проложить новый путь в изучении культурной идентичности в Израиле, используя междисциплинарный подход, сочетающий социологию, антропологию и лингвистику.
Теоретическая рамка опирается главным образом на теорию культурного капитала Бурдьё с расширением её для анализа социальных пространств, уникальных для израильского общества. Подход плодотворный, однако автор недостаточно учитывает критику понятия габитуса в постколониальных контекстах.
С методологической точки зрения исследование основано на глубинных интервью с восемьюдесятью участниками различного этнического происхождения. Выборка разнообразна, но представительство некоторых групп меньшинств — в частности выходцев из Эфиопии — недостаточно. Кроме того, автор не объясняет метод кодирования качественных данных в достаточной степени.
Эмпирические главы представляют интересные результаты, в особенности анализ смены языкового регистра между вторым поколением и их родителями. Тем не менее разрыв между данными и выводами слишком велик: автор склонен к обобщениям, недостаточно подкреплённым данными.
Несмотря на оговорки, это важная работа, вносящая вклад в академическую дискуссию. Рекомендую к публикации после методологических исправлений и переработки раздела обсуждения.', '[{"he": "מתודולוגיה", "ru": "методология", "translit": "методологИя"}, {"he": "מסגרת תאורטית", "ru": "теоретическая рамка", "translit": "мисгЭрет теорЭтит"}, {"he": "דגימה", "ru": "выборка", "translit": "дгимА"}, {"he": "ממצאים", "ru": "результаты / данные", "translit": "мамцаИм"}, {"he": "הון תרבותי", "ru": "культурный капитал", "translit": "hон тарбутИ"}, {"he": "ראיונות עומק", "ru": "глубинные интервью", "translit": "реайонОт Омек"}, {"he": "נתונים איכותניים", "ru": "качественные данные", "translit": "нетунИм эйхутаниИм"}, {"he": "הביטוס", "ru": "габитус", "translit": "hабИтус"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (180, 6, 'טור דעה: על הפער בין מילים למעשים', 'Газетная колонка мнений', 'שוב ושוב אנחנו שומעים את אותן הצהרות נדושות מפיהם של נבחרי הציבור. "נפעל בנחישות", "נמגר את התופעה", "לא נשלים עם המצב". אבל מאחורי מילים גדולות מסתתרת מציאות עגומה: הפער החברתי בישראל הולך ומעמיק, והפוליטיקאים עסוקים בהישרדות קואליציונית.
נתוני הלשכה המרכזית לסטטיסטיקה מדברים בעד עצמם. החמישון העליון מרוויח פי שמונה מהחמישון התחתון. מחירי הדיור זינקו בחמישים אחוז בעשור האחרון, בעוד שהשכר הריאלי כמעט לא זז. צעירים רבים מתייאשים מעצם האפשרות לרכוש דירה.
הפריפריה, כרגיל, סופגת את המכה הקשה ביותר. שם התשתיות רעועות, מערכת החינוך מקופחת, ושירותי הבריאות דלים. תושב באר שבע ממתין שלושה חודשים לתור רופא מומחה — תושב תל אביב ממתין שלושה שבועות.
אלא שהשיח הציבורי נשבה בידי ענייני הביטחון. כל משבר ביטחוני דוחק את הנושאים החברתיים לשוליים. זוהי דינמיקה מוכרת ומתסכלת: כאשר הרקטות משתתקות, הממשלה חוזרת לעסקים כרגיל.
הגיע הזמן לתבוע אחריות אמיתית. לא עוד ועדות חקירה שמסקנותיהן נגנזות, לא עוד הבטחות בוחרות. מה שנדרש הוא שינוי מבני, אמיץ ומכאיב — ודווקא בכך טמונה הסיבה שהוא לא יתרחש בקרוב.', 'Снова и снова мы слышим одни и те же избитые заявления из уст избранных представителей. «Будем действовать решительно», «искореним это явление», «не смиримся с положением дел». Но за громкими словами скрывается удручающая реальность: социальный разрыв в Израиле углубляется, а политики заняты коалиционным выживанием.
Данные Центрального статистического бюро говорят сами за себя. Верхний квинтиль зарабатывает в восемь раз больше нижнего. Цены на жильё подскочили на пятьдесят процентов за последнее десятилетие, тогда как реальная зарплата почти не изменилась. Многие молодые люди теряют надежду на возможность приобрести квартиру.
Периферия, как обычно, получает самый тяжёлый удар. Там ветхая инфраструктура, ущемлённая система образования и скудные медицинские услуги. Житель Беэр-Шевы ждёт три месяца записи к специалисту — житель Тель-Авива ждёт три недели.
Между тем публичный дискурс захвачен вопросами безопасности. Каждый кризис в сфере безопасности оттесняет социальные вопросы на обочину. Это знакомая и разочаровывающая динамика: когда ракеты замолкают, правительство возвращается к обычному порядку дел.
Пришло время потребовать реальной ответственности. Больше никаких комиссий по расследованию, чьи заключения пылятся на полках, никаких предвыборных обещаний. Необходимы структурные изменения, смелые и болезненные — и именно поэтому они не произойдут в ближайшее время.', '[{"he": "נבחרי ציבור", "ru": "избранные представители", "translit": "нивхарЭй цибУр"}, {"he": "פער חברתי", "ru": "социальный разрыв", "translit": "пАар хевратИ"}, {"he": "חמישון", "ru": "квинтиль", "translit": "хамишОн"}, {"he": "פריפריה", "ru": "периферия", "translit": "перифЕрия"}, {"he": "ועדת חקירה", "ru": "следственная комиссия", "translit": "ваадАт хакирА"}, {"he": "שכר ריאלי", "ru": "реальная зарплата", "translit": "сахАр реалИ"}, {"he": "קואליציה", "ru": "коалиция", "translit": "коалИция"}, {"he": "שינוי מבני", "ru": "структурное изменение", "translit": "шинУй мивнИ"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (181, 6, 'פסק דין של בית המשפט העליון', 'Решение Верховного суда', 'בבית המשפט העליון בשבתו כבית משפט גבוה לצדק. השופטים: כבוד הנשיאה, כבוד השופט א׳ וכבוד השופטת ב׳. העתירה הוגשה כנגד החלטת שר הפנים שלא להעניק מעמד של תושב קבע למבקש, אזרח זר השוהה בישראל למעלה מעשר שנים מכוח נישואיו לאזרחית ישראלית.
העותר טוען כי ההחלטה פוגעת בזכותו החוקתית לחיי משפחה, המעוגנת בחוק יסוד: כבוד האדם וחירותו. לטענתו, השר הפעיל את שיקול דעתו באופן בלתי סביר ובניגוד להנחיות היועץ המשפטי לממשלה.
מנגד, המדינה טוענת כי סמכות השר בענייני הגירה היא סמכות רחבה, וכי ההחלטה התקבלה לאחר בחינה מדוקדקת של נסיבות המקרה, לרבות ממצאי חקירה המצביעים על ספק בכנות הקשר הזוגי.
לאחר שמיעת טענות הצדדים ועיון בחומר הראיות, אנו סבורים כי החלטת השר אינה עומדת במבחן המידתיות. הפגיעה בזכות לחיי משפחה חמורה, ולא הוכח כי לא ניתן להשיג את התכלית הראויה באמצעים פוגעניים פחות.
לפיכך, העתירה מתקבלת. ההחלטה מבוטלת, והעניין מוחזר לשר לבחינה מחודשת בהתאם לאמות המידה שנקבעו בפסיקה זו. אין צו להוצאות.', 'В Верховном суде, заседающем в качестве Высшего суда справедливости. Судьи: председатель суда, судья А. и судья Б. Ходатайство подано против решения министра внутренних дел об отказе в предоставлении статуса постоянного резидента заявителю — иностранному гражданину, проживающему в Израиле более десяти лет на основании брака с гражданкой Израиля.
Заявитель утверждает, что решение нарушает его конституционное право на семейную жизнь, закреплённое в Основном законе: о достоинстве и свободе человека. По его мнению, министр применил своё дискреционное полномочие неразумно и вопреки директивам юридического советника правительства.
Государство, напротив, утверждает, что полномочия министра в вопросах иммиграции широки, и решение было принято после тщательного изучения обстоятельств дела, включая результаты расследования, ставящие под сомнение подлинность супружеских отношений.
Выслушав доводы сторон и изучив доказательства, мы полагаем, что решение министра не выдерживает проверки на соразмерность. Нарушение права на семейную жизнь серьёзно, и не доказано, что легитимная цель не может быть достигнута менее ущемляющими средствами.
Ходатайство удовлетворяется. Решение отменяется, дело возвращается министру для повторного рассмотрения в соответствии с критериями, установленными настоящим постановлением. Судебные расходы не взыскиваются.', '[{"he": "עתירה", "ru": "ходатайство / петиция", "translit": "атирА"}, {"he": "בג\"ץ", "ru": "Высший суд справедливости", "translit": "бАгац"}, {"he": "שיקול דעת", "ru": "дискреционное полномочие", "translit": "шикУль дАат"}, {"he": "מידתיות", "ru": "соразмерность", "translit": "мидатиЮт"}, {"he": "תושב קבע", "ru": "постоянный резидент", "translit": "тошАв кЕва"}, {"he": "חוק יסוד", "ru": "основной закон", "translit": "хок есОд"}, {"he": "יועץ משפטי", "ru": "юридический советник", "translit": "йоЭц мишпатИ"}, {"he": "פסיקה", "ru": "судебное постановление", "translit": "псикА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (182, 6, 'שירת הקודש של שלמה אבן גבירול', 'Средневековая поэзия пиют', 'שלמה בן יהודה אבן גבירול, מגדולי משוררי ספרד במאה האחת-עשרה, חיבר פיוטים שניצבים בצומת שבין מסורת הפיוט הקלאסי לבין ההשפעה הערבית. יצירתו "כתר מלכות" נחשבת לאחת מפסגות השירה העברית בימי הביניים.
בשירתו הליטורגית שזר אבן גבירול לשון מקראית עם חידושים לשוניים. הוא נטל ביטויים מספר תהילים ומספר איוב ועיבדם ברוח הפילוסופיה הניאו-אפלטונית. כך נוצר שיח ייחודי שבו הנשמה כמהה לבוראה בלשון של געגועים ארציים.
המשקל השירי בפיוטיו מושפע מחוקי המשקל הערביים, אולם מותאם לדקדוק העברי. השימוש בחרוז הקבוע ובמבנה הבתים המסודר מעניק לשירה מוזיקליות שנועדה לשירה בציבור, במסגרת תפילות שבת וחגים.
התמות המרכזיות בשירתו כוללות את גדולת הבורא, את שפלות האדם מול האינסוף, ואת הכיסופים לגאולה. במקומות רבים ניכרת השפעתו של ספר יצירה על דימוייו, ובפרט בתיאורי הספירות והאורות האלוהיים.
מורשתו של אבן גבירול חצתה גבולות דת ותרבות. חיבורו הפילוסופי "מקור חיים" תורגם ללטינית והשפיע על הוגים נוצרים, שכלל לא ידעו כי מחברו יהודי. כך הפך לגשר בין עולמות.', 'Шломо бен Йеhуда ибн Габироль, один из величайших поэтов Испании XI века, создавал литургические поэмы (пиюты), стоящие на стыке классической традиции пиюта и арабского влияния. Его произведение «Царский венец» считается одной из вершин средневековой ивритской поэзии.
В своей литургической поэзии ибн Габироль переплетал библейский язык с языковыми новшествами. Он заимствовал выражения из книг Псалмов и Иова и перерабатывал их в духе неоплатонической философии. Так возник уникальный дискурс, в котором душа тоскует по Творцу языком земной тоски.
Стихотворный размер его пиютов подвержен влиянию арабской просодии, но адаптирован к грамматике иврита. Использование постоянной рифмы и упорядоченной строфической структуры придаёт поэзии музыкальность, предназначенную для общественного пения в рамках субботних и праздничных молитв.
Центральные темы его поэзии включают величие Творца, ничтожность человека перед бесконечностью и стремление к избавлению. Во многих местах заметно влияние «Книги Творения» на его образность, в особенности в описаниях сефирот и божественных светов.
Наследие ибн Габироля пересекло границы религий и культур. Его философский труд «Источник жизни» был переведён на латынь и повлиял на христианских мыслителей, которые даже не подозревали, что его автор — иудей. Так он стал мостом между мирами.', '[{"he": "פיוט", "ru": "литургическая поэма", "translit": "пиЮт"}, {"he": "כתר מלכות", "ru": "Царский венец", "translit": "кЭтер малхУт"}, {"he": "חרוז", "ru": "рифма", "translit": "харУз"}, {"he": "ניאו-אפלטוני", "ru": "неоплатонический", "translit": "нео-афлатонИ"}, {"he": "ספירות", "ru": "сефирот", "translit": "сфирОт"}, {"he": "ליטורגי", "ru": "литургический", "translit": "литургИ"}, {"he": "גאולה", "ru": "избавление / искупление", "translit": "геулА"}, {"he": "משקל שירי", "ru": "стихотворный размер", "translit": "мишкАль ширИ"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (183, 6, 'שיטת הפרשנות של רש"י', 'Комментарий Раши', 'רבי שלמה יצחקי, הידוע בכינויו רש"י, פעל בצרפת במאה האחת-עשרה ונחשב לפרשן המקרא והתלמוד המשפיע ביותר בתולדות היהדות. שיטתו מצטיינת בקיצור לשון מופלג ובדיוק פרשני שאין כמותו.
עיקרון מנחה בפירושו הוא "אני לא באתי אלא לפשוטו של מקרא". רש"י מבכר את הפירוש הפשטני על פני הדרש, אולם כאשר הפשט אינו מספק — הוא נזקק למדרשי חז"ל, תוך בחירה קפדנית של המדרש ההולם ביותר את ההקשר.
השפה שבה כתב רש"י ייחודית: עברית תמציתית, לעיתים עד כדי חידתיות, עם שיבוצים מלשון חז"ל. במקומות שבהם נזקק לבאר מילה עברית, הוא משתמש בתרגום ללעז — כלומר לצרפתית עתיקה בכתב עברי — מקור יקר ערך לבלשנות הרומאנית.
השפעתו של רש"י חצתה את גבולות העולם היהודי. הפרשנים הנוצרים של ימי הביניים, ובראשם ניקולאוס דה לירא, הכירו בפירושו והשתמשו בו. דרך דה לירא הגיעה השפעתו של רש"י עד למרטין לותר ולתרגום הפרוטסטנטי של המקרא.
עד היום נלמד פירוש רש"י בכל בית מדרש, והוא המלווה הראשון של כל תלמיד הפותח חומש או גמרא. שיטתו הקצרה והמדויקת הפכה לאבן יסוד של הפרשנות היהודית לדורותיה.', 'Рабби Шломо Ицхаки, известный под акронимом Раши, действовал во Франции в XI веке и считается самым влиятельным комментатором Библии и Талмуда в истории иудаизма. Его метод отличается исключительной лаконичностью и непревзойдённой экзегетической точностью.
Руководящий принцип его комментария: «Я пришёл лишь ради простого смысла Писания». Раши предпочитает буквальное толкование аллегорическому, однако когда прямой смысл недостаточен, он обращается к мидрашам мудрецов, тщательно отбирая наиболее соответствующий контексту.
Язык, которым пишет Раши, уникален: предельно сжатый иврит, порой до загадочности, с вкраплениями талмудического языка. Когда ему нужно объяснить ивритское слово, он использует перевод на «лааз» — старофранцузский, записанный еврейскими буквами, — ценнейший источник для романской лингвистики.
Влияние Раши вышло за пределы еврейского мира. Христианские комментаторы Средневековья, прежде всего Николай де Лира, признавали его толкование и пользовались им. Через де Лира влияние Раши дошло до Мартина Лютера и протестантского перевода Библии.
По сей день комментарий Раши изучается в каждом бейт-мидраше и является первым спутником всякого ученика, открывающего Пятикнижие или Гемару. Его лаконичный и точный метод стал краеугольным камнем еврейской экзегетики на все поколения.', '[{"he": "פרשנות", "ru": "экзегетика / комментирование", "translit": "паршанУт"}, {"he": "פשוטו של מקרא", "ru": "буквальный смысл Писания", "translit": "пшутО шель микрА"}, {"he": "מדרש", "ru": "мидраш", "translit": "мидрАш"}, {"he": "לעז", "ru": "старофранцузский (глосс)", "translit": "лаАз"}, {"he": "חומש", "ru": "Пятикнижие", "translit": "хумАш"}, {"he": "גמרא", "ru": "Гемара", "translit": "гмарА"}, {"he": "בית מדרש", "ru": "дом учения", "translit": "бейт мидрАш"}, {"he": "חז\"ל", "ru": "мудрецы Талмуда", "translit": "хазАль"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (184, 6, 'קריאה פוסט-קולוניאלית בספרות העברית', 'Современная литературная критика', 'הביקורת הפוסט-קולוניאלית חדרה לשיח הספרותי בישראל באיחור ניכר לעומת האקדמיה האנגלו-אמריקנית. רק משנות התשעים החלו חוקרים ישראלים ליישם את כלי הניתוח של סעיד, ספיבק ובאבא על הקורפוס העברי.
שדה מחקר מרתק במיוחד הוא הקול המזרחי בספרות. יצירותיהם של סמי מיכאל, שמעון בלס ואלי עמיר מציגות נרטיב חלופי לסיפור הציוני ההגמוני. הם חושפים את מנגנוני ההדרה שפעלו כלפי יהודי ארצות האסלאם בעשורים הראשונים של המדינה.
עמיר, בספרו "תרנגול כפרות", בונה דיאלקטיקה בין המרכז האשכנזי לפריפריה המזרחית. הגיבור, ילד מוצא עירקי הגדל בשכונת מעברה, מנווט בין שתי מערכות ערכים סותרות. השפה עצמה הופכת לזירת מאבק: העברית ה"תקנית" מול הערבית-יהודית שנותרה בפי הדור הראשון.
הקריאה הפוסט-קולוניאלית מאפשרת לזהות מנגנוני כוח שהביקורת המסורתית התעלמה מהם. מושגים כגון מיקום-משנה, היברידיות ומרחב שלישי מאירים את המורכבות של זהויות שנכפה עליהן מיזוג גלויות.
עם זאת, יש להיזהר מיישום מכני של תיאוריות שנולדו בהקשר שונה. הניסיון הקולוניאלי של מזרחי ישראל אינו זהה לזה של עמי אפריקה או דרום אסיה, ונדרשת התאמה תיאורטית רגישה לייחודו של המקרה הישראלי.', 'Постколониальная критика проникла в литературоведческий дискурс Израиля со значительным опозданием по сравнению с англо-американской академией. Лишь с девяностых годов израильские исследователи начали применять аналитические инструменты Саида, Спивак и Бабы к ивритскому корпусу.
Особенно увлекательная область исследований — восточный (мизрахийский) голос в литературе. Произведения Сами Михаэля, Шимона Бласа и Эли Амира представляют альтернативный нарратив гегемонному сионистскому повествованию. Они обнажают механизмы исключения, действовавшие в отношении евреев исламских стран в первые десятилетия государства.
Амир в романе «Козёл отпущения» выстраивает диалектику между ашкеназским центром и мизрахийской периферией. Герой, мальчик иракского происхождения, растущий в транзитном лагере, лавирует между двумя противоречивыми системами ценностей. Сам язык становится полем борьбы: «нормативный» иврит против еврейско-арабского языка первого поколения.
Постколониальное прочтение позволяет выявить властные механизмы, которые традиционная критика игнорировала. Такие понятия, как субалтерность, гибридность и третье пространство, освещают сложность идентичностей, которым было навязано «слияние диаспор».
Вместе с тем следует избегать механического применения теорий, рождённых в ином контексте. Колониальный опыт мизрахим в Израиле не тождествен опыту народов Африки или Южной Азии, и требуется чуткая теоретическая адаптация к уникальности израильского случая.', '[{"he": "פוסט-קולוניאלי", "ru": "постколониальный", "translit": "пост-колониАли"}, {"he": "הגמוני", "ru": "гегемонный", "translit": "hегемонИ"}, {"he": "היברידיות", "ru": "гибридность", "translit": "hибридиЮт"}, {"he": "מיקום-משנה", "ru": "субалтерность", "translit": "микУм-мишнЭ"}, {"he": "נרטיב", "ru": "нарратив", "translit": "наратИв"}, {"he": "הדרה", "ru": "исключение / маргинализация", "translit": "hадарА"}, {"he": "מזרחי", "ru": "восточный / мизрахийский", "translit": "мизрахИ"}, {"he": "מיזוג גלויות", "ru": "слияние диаспор", "translit": "мизУг галуйОт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (96, 3, 'ים המלח', 'Мёртвое море', 'ים המלח הוא המקום הנמוך ביותר על כדור הארץ ואחד הפלאים של הטבע. הוא נמצא בגבול בין ישראל לירדן, כארבע מאות מטר מתחת לפני הים. המים מלוחים פי עשר מהים הרגיל, ולכן שום דג או צמח לא יכול לחיות בהם.
התכונה המפורסמת ביותר היא שאפשר לצוף במים בלי מאמץ. תיירים מכל העולם באים לחוות את החוויה ולמרוח בוץ שחור על הגוף. הבוץ והמינרלים ידועים כטובים לעור ולבריאות.
אבל ים המלח בסכנה. כל שנה מפלס המים יורד בכמטר בגלל שימוש רב במי הירדן ומפעלי כימיקלים. בולענים מסוכנים נפתחים בחוף ובכבישים. מדענים מחפשים פתרונות כדי להציל את ים המלח לפני שיהיה מאוחר מדי.', 'Мёртвое море — самое низкое место на Земле и одно из чудес природы. Оно находится на границе между Израилем и Иорданией, примерно на четыреста метров ниже уровня моря. Его вода в десять раз солонее обычного моря, и поэтому ни одна рыба или растение не может в ней жить.
Самое известное свойство Мёртвого моря — возможность плавать на поверхности без всяких усилий. Туристы со всего мира приезжают испытать это ощущение и намазаться чёрной грязью. Грязь и минералы Мёртвого моря считаются очень полезными для кожи и здоровья.
Но Мёртвое море в опасности. Каждый год уровень воды падает примерно на метр из-за чрезмерного использования вод Иордана и химических предприятий. На побережье и на дорогах возле моря открываются опасные провалы. Учёные и политики ищут решения, чтобы спасти Мёртвое море, пока не стало слишком поздно.', '[{"he": "ים המלח", "ru": "Мёртвое море", "translit": "ям hа-мЕлах"}, {"he": "לצוף", "ru": "плавать на поверхности", "translit": "лацУф"}, {"he": "בוץ", "ru": "грязь (лечебная)", "translit": "боц"}, {"he": "מינרל", "ru": "минерал", "translit": "минерАль"}, {"he": "מפלס", "ru": "уровень (воды)", "translit": "мифлАс"}, {"he": "בולען", "ru": "провал / карстовая воронка", "translit": "болАн"}, {"he": "מלוח", "ru": "солёный", "translit": "малУах"}, {"he": "תייר", "ru": "турист", "translit": "таяр"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (185, 6, 'מאמר מדעי: נוירופלסטיות וזיכרון', 'Научная статья', 'מחקר זה בוחן את מנגנוני הנוירופלסטיות המעורבים בגיבוש זיכרון ארוך טווח באזור ההיפוקמפוס של מוח האדם. שאלת המחקר המרכזית: כיצד חיזוק סינפטי תורם ליצירת עקבות זיכרון יציבים?
המתודולוגיה כללה הדמיה תפקודית באמצעות אף-אם-אר-אי של שלושים נבדקים בריאים בגילאי עשרים עד ארבעים. הנבדקים ביצעו משימות קידוד זיכרוני בעת סריקה, ונבדקו שנית לאחר עשרים וארבע שעות ולאחר שבוע.
הממצאים מראים מתאם מובהק סטטיסטית בין רמת ההפעלה בהיפוקמפוס בשלב הקידוד לבין הצלחת השליפה לאחר שבוע. בפרט, אזור CA1 הראה את המתאם החזק ביותר, ממצא התואם את המודל התיאורטי של חיזוק סינפטי ארוך טווח.
תוצאות אלו תומכות בהשערה כי תהליכי קונסולידציה מתחילים כבר בשלב הקידוד ואינם מוגבלים לשלב השינה, כפי שסברו חוקרים קודמים. ממצא זה מאתגר את הפרדיגמה הרווחת בתחום.
מגבלות המחקר כוללות את גודל המדגם המצומצם ואת ההסתמכות על משימות מעבדתיות שאינן משקפות בהכרח תהליכי זיכרון טבעיים. מחקרים עתידיים צריכים לשלב פרדיגמות אקולוגיות ולהרחיב את המדגם לאוכלוסיות גיל מבוגר.', 'Данное исследование изучает механизмы нейропластичности, вовлечённые в формирование долговременной памяти в области гиппокампа человеческого мозга. Центральный исследовательский вопрос: каким образом синаптическое усиление способствует созданию устойчивых следов памяти?
Методология включала функциональную визуализацию посредством фМРТ тридцати здоровых испытуемых в возрасте от двадцати до сорока лет. Испытуемые выполняли задания на кодирование памяти во время сканирования и были повторно обследованы через двадцать четыре часа и через неделю.
Результаты показывают статистически значимую корреляцию между уровнем активации гиппокампа на этапе кодирования и успешностью извлечения через неделю. В частности, зона CA1 показала наиболее сильную корреляцию — результат, согласующийся с теоретической моделью долговременного синаптического усиления.
Эти результаты поддерживают гипотезу о том, что процессы консолидации начинаются уже на этапе кодирования и не ограничиваются фазой сна, как полагали предыдущие исследователи. Данный вывод бросает вызов доминирующей парадигме в этой области.
Ограничения исследования включают небольшой размер выборки и опору на лабораторные задания, не обязательно отражающие естественные процессы запоминания. Будущие исследования должны включать экологические парадигмы и расширить выборку на старшие возрастные группы.', '[{"he": "נוירופלסטיות", "ru": "нейропластичность", "translit": "нейропластиЮт"}, {"he": "היפוקמפוס", "ru": "гиппокамп", "translit": "hипокАмпус"}, {"he": "חיזוק סינפטי", "ru": "синаптическое усиление", "translit": "хизУк синАпти"}, {"he": "קידוד", "ru": "кодирование", "translit": "кидУд"}, {"he": "קונסולידציה", "ru": "консолидация", "translit": "консолидАция"}, {"he": "הדמיה תפקודית", "ru": "функциональная визуализация", "translit": "hадамА тифкудИт"}, {"he": "מדגם", "ru": "выборка", "translit": "мидгАм"}, {"he": "פרדיגמה", "ru": "парадигма", "translit": "парадИгма"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (186, 6, 'פרוטוקול דיון בכנסת ישראל', 'Стенограмма парламента', 'יו"ר הכנסת: הישיבה נפתחת. על סדר היום הצעת חוק הרשויות המקומיות (תיקון), התשפ"ו-2026. חבר הכנסת דוד כהן, בבקשה.
ח"כ כהן: אדוני היושב-ראש, חברות וחברי הכנסת. הצעת החוק שלפנינו מבקשת לתקן עיוות היסטורי בחלוקת תקציבים לרשויות המקומיות. כפי שהראיתי בדברי ההסבר, הפורמולה הנוכחית מפלה לרעה רשויות בפריפריה, ובפרט את הרשויות הערביות. הגיע הזמן לתקן את המעוות.
ח"כ מרים לוי: הערת סדר, אדוני היושב-ראש. חבר הכנסת כהן מטעה את הבית. הנתונים שהציג אינם מעודכנים, והפורמולה שונתה כבר בשנת 2021.
יו"ר הכנסת: חברת הכנסת לוי, זו אינה הערת סדר אלא התייחסות לגוף העניין. תוכלי לדבר כשיגיע תורך. חבר הכנסת כהן, המשך בבקשה.
ח"כ כהן: תודה, אדוני. כאמור, עמדת משרד הפנים תומכת בהצעה. הוגשה חוות דעת של הלשכה המשפטית הקובעת כי התיקון חוקתי ואינו מחייב רוב מיוחד. אני מציע להעביר להצבעה.
יו"ר הכנסת: תודה. המליאה תצביע לאחר דברי ההתנגדות. הישיבה נדחית לשעה שלוש.', 'Председатель Кнессета: Заседание открывается. На повестке дня — законопроект о местных органах власти (поправка), 2026. Депутат Давид Коэн, пожалуйста.
Депутат Коэн: Господин председатель, уважаемые коллеги. Представленный законопроект стремится исправить историческое искажение в распределении бюджетов между местными органами власти. Как я показал в пояснительной записке, нынешняя формула дискриминирует муниципалитеты периферии, и в особенности арабские муниципалитеты. Пришло время исправить несправедливость.
Депутат Мирьям Леви: Замечание по порядку ведения, господин председатель. Депутат Коэн вводит палату в заблуждение. Представленные данные не актуальны, а формула уже была изменена в 2021 году.
Председатель Кнессета: Депутат Леви, это не замечание по порядку, а обращение по существу дела. Вы сможете выступить, когда подойдёт ваша очередь. Депутат Коэн, продолжайте.
Депутат Коэн: Благодарю, господин председатель. Как уже было сказано, позиция Министерства внутренних дел поддерживает законопроект. Представлено заключение юридического департамента, устанавливающее, что поправка конституционна и не требует особого большинства. Предлагаю перейти к голосованию.
Председатель Кнессета: Благодарю. Пленум проголосует после выступлений оппозиции. Заседание откладывается до трёх часов.', '[{"he": "יו\"ר הכנסת", "ru": "председатель Кнессета", "translit": "йошЭв-рош hа-кнЕсет"}, {"he": "הצעת חוק", "ru": "законопроект", "translit": "hацаАт хок"}, {"he": "הערת סדר", "ru": "замечание по порядку", "translit": "hеарАт сЭдер"}, {"he": "מליאה", "ru": "пленум", "translit": "мелеА"}, {"he": "חוות דעת", "ru": "экспертное заключение", "translit": "хавАт дАат"}, {"he": "רוב מיוחד", "ru": "особое большинство", "translit": "ров меюхАд"}, {"he": "דברי הסבר", "ru": "пояснительная записка", "translit": "диврЭй hесбЭр"}, {"he": "פורמולה", "ru": "формула (распределения)", "translit": "формУла"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (187, 6, 'התכתבות דיפלומטית: נוסח רשמי', 'Дипломатическая переписка', 'לכבוד שר החוץ של הרפובליקה הצרפתית, מר ז׳אן דיפון. הנדון: חיזוק שיתוף הפעולה הדו-צדדי בתחום המחקר המדעי. מכתב זה מוגש בשם ממשלת ישראל כהמשך לשיחה שנערכה בין ראשי הממשלות בפסגת האו"ם האחרונה.
ממשלת ישראל מייחסת חשיבות עליונה ליחסים ההיסטוריים והאסטרטגיים עם צרפת. שתי המדינות חולקות מחויבות לערכי הדמוקרטיה, לזכויות האדם ולקידום הידע המדעי. שיתוף הפעולה בתחום המחקר, שראשיתו בהסכם הגג משנת 1994, הניב פירות מבורכים.
ברצוננו להציע הרחבה של ההסכם הקיים לתחומים נוספים: אינטליגנציה מלאכותית, אנרגיה מתחדשת וביוטכנולוגיה רפואית. אנו מוכנים להקצות תקציב שנתי של עשרים מיליון אירו לתוכניות מחקר משותפות.
נבקש לקיים פגישת עבודה ברמת סגני שרים בתוך שישים יום, לגיבוש מתווה מוסכם. משלחת ישראלית בראשות המנהל הכללי של משרד המדע תהיה מוכנה להגיע לפריז במועד הנוח לכם.
אנו מצפים להמשך שיתוף פעולה פורה בין שתי המדינות, ומודים על תשומת הלב שהוקדשה לפנייה זו. בכבוד רב ובברכת שלום, שר החוץ של מדינת ישראל.', 'Его превосходительству министру иностранных дел Французской Республики господину Жану Дюпону. Касательно: укрепление двустороннего сотрудничества в области научных исследований. Настоящее письмо направляется от имени правительства Израиля в продолжение беседы глав правительств на последнем саммите ООН.
Правительство Израиля придаёт первостепенное значение историческим и стратегическим отношениям с Францией. Оба государства разделяют приверженность демократическим ценностям, правам человека и продвижению научного знания. Сотрудничество в области исследований, берущее начало от рамочного соглашения 1994 года, принесло благотворные плоды.
Мы хотели бы предложить расширение действующего соглашения на дополнительные области: искусственный интеллект, возобновляемую энергию и медицинскую биотехнологию. Мы готовы выделить годовой бюджет в двадцать миллионов евро на совместные исследовательские программы.
Просим организовать рабочую встречу на уровне заместителей министров в течение шестидесяти дней для выработки согласованного плана. Израильская делегация во главе с генеральным директором Министерства науки будет готова прибыть в Париж в удобное для вас время.
Мы рассчитываем на продолжение плодотворного сотрудничества между двумя государствами и благодарим за внимание к данному обращению. С глубоким уважением и пожеланием мира, министр иностранных дел Государства Израиль.', '[{"he": "שר החוץ", "ru": "министр иностранных дел", "translit": "сар hа-хуц"}, {"he": "שיתוף פעולה דו-צדדי", "ru": "двустороннее сотрудничество", "translit": "шитУф пеулА ду-цдадИ"}, {"he": "הסכם גג", "ru": "рамочное соглашение", "translit": "hескЭм гаг"}, {"he": "מנהל כללי", "ru": "генеральный директор", "translit": "менаhЭль клалИ"}, {"he": "משלחת", "ru": "делегация", "translit": "мишлАхат"}, {"he": "מתווה", "ru": "план / схема", "translit": "матвЕ"}, {"he": "סגני שרים", "ru": "заместители министров", "translit": "сганЭй сарИм"}, {"he": "פנייה", "ru": "обращение", "translit": "пнийА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (188, 6, 'על הצדק: עיון פילוסופי במסורת היהודית', 'Философский трактат', 'מושג הצדק תופס מקום יסודי בהגות היהודית, מן המקרא ועד ההוגים בני זמננו. הציווי "צדק צדק תרדוף" אינו מסתפק באזכור יחיד של המילה, אלא כופלה — ופרשנים רבים ראו בכפילות זו דרישה לצדק מוחלט, שאינו מתפשר.
הרמב"ם, בהלכות דעות, מציג את הצדק כמידה שבין שני קצוות. בניגוד לגישה האריסטוטלית הטהורה, הרמב"ם מוסיף ממד דתי: האדם נדרש להידמות לבוראו, שהוא "חנון ורחום". הצדק הרמב"מי אינו רק מידה חברתית, אלא שאיפה מטאפיזית.
לוינס, ההוגה היהודי-צרפתי, הציע קריאה אחרת. לטענתו, הצדק מתחיל בפנים של האחר. המפגש הבלתי אמצעי עם הזולת מחייב אותי בחובה אינסופית, קודמת לכל חוק ולכל חוזה חברתי. הצדק, אם כן, אינו עיקרון מופשט אלא חוויה קונקרטית.
המתח בין צדק לרחמים מלווה את ההגות היהודית מאז ומתמיד. המסורת הקבלית מתארת שתי מידות אלוהיות — מידת הדין ומידת הרחמים — שביניהן מתקיים דיאלוג מתמיד. העולם, על פי הזוהר, אינו יכול להתקיים במידת הדין בלבד.
בימינו, השאלה מקבלת ממד אקטואלי. כיצד מיישמים צדק בחברה מפולגת, שבה קבוצות שונות מחזיקות בתפיסות מנוגדות של צדק? ההגות היהודית, על רבדיה השונים, מציעה לא תשובה אחת אלא מסגרת לדיון — וזוהי אולי תרומתה הגדולה ביותר.', 'Понятие справедливости занимает фундаментальное место в еврейской мысли — от Библии до современных мыслителей. Заповедь «Справедливости, справедливости ищи» не ограничивается однократным упоминанием слова, а удваивает его — и многие комментаторы усмотрели в этом удвоении требование абсолютной, бескомпромиссной справедливости.
Маймонид в «Законах о качествах характера» представляет справедливость как среднюю меру между двумя крайностями. В отличие от чистого аристотелевского подхода, Маймонид добавляет религиозное измерение: человек призван уподобиться Творцу, который «милостив и милосерд». Маймонидова справедливость — не только социальная добродетель, но метафизическое стремление.
Левинас, еврейско-французский мыслитель, предложил иное прочтение. По его мнению, справедливость начинается с лица Другого. Непосредственная встреча с ближним обязывает меня бесконечной ответственностью, предшествующей любому закону и любому общественному договору. Справедливость, таким образом, не абстрактный принцип, а конкретный опыт.
Напряжение между справедливостью и милосердием сопровождает еврейскую мысль извечно. Каббалистическая традиция описывает две божественные меры — меру суда и меру милосердия, — между которыми ведётся непрерывный диалог. Мир, согласно Зоhару, не может существовать лишь мерой суда.
В наши дни вопрос приобретает актуальное измерение. Как осуществлять справедливость в расколотом обществе, где разные группы придерживаются противоположных представлений о справедливости? Еврейская мысль, во всех своих пластах, предлагает не единственный ответ, а рамку для дискуссии — и в этом, быть может, её величайший вклад.', '[{"he": "צדק", "ru": "справедливость", "translit": "цЕдек"}, {"he": "הרמב\"ם", "ru": "Маймонид", "translit": "hа-рамбАм"}, {"he": "מידת הדין", "ru": "мера суда", "translit": "мидАт hа-дин"}, {"he": "מידת הרחמים", "ru": "мера милосердия", "translit": "мидАт hа-рахамИм"}, {"he": "קבלה", "ru": "каббала", "translit": "кабалА"}, {"he": "זוהר", "ru": "Зоhар", "translit": "зОhар"}, {"he": "הידמות", "ru": "уподобление", "translit": "hидамУт"}, {"he": "הגות", "ru": "философская мысль", "translit": "hагУт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (97, 3, 'המוזיקה הישראלית', 'Израильская музыка', 'המוזיקה הישראלית היא עולם מגוון שמשלב השפעות ממזרח וממערב. בשנים הראשונות של המדינה שירי ארץ ישראל היו פופולריים מאוד, שירים על הארץ, הטבע והבניין של המדינה החדשה.
בשנות השבעים והשמונים המוזיקה המזרחית, שהגיעה מקהילות יהודי ארצות ערב, נכנסה לזרם המרכזי. זמרים כמו זוהר ארגוב הפכו לאגדה. היום המוזיקה המזרחית היא הפופולרית ביותר בישראל ומושמעת בכל מקום, מחתונות ועד לרדיו.
לצד המזרחית יש רוק ישראלי, היפ הופ ומוזיקה אלקטרונית. אירוויזיון הוא אירוע חשוב בישראל ואנשים רבים עוקבים אחריו כל שנה. ישראל זכתה בתחרות כמה פעמים וזה גורם לגאווה לאומית. פסטיבלי מוזיקה מושכים קהל גדול.', 'Израильская музыка — это разнообразный и увлекательный мир, сочетающий восточные и западные влияния. В первые годы государства очень популярны были песни Эрец-Исраэль — песни о стране, природе и строительстве нового государства.
В семидесятые и восьмидесятые годы восточная музыка, пришедшая от выходцев из арабских стран, начала входить в мейнстрим. Певцы вроде Зоара Аргова стали легендой. Сегодня восточная музыка — самая популярная в Израиле, она звучит повсюду, от свадеб до радио.
Наряду с восточной музыкой есть израильский рок, хип-хоп, электронная и классическая музыка. Евровидение — важное событие в Израиле, и многие люди следят за ним каждый год. Израиль побеждал в конкурсе несколько раз, и это вызывает большую национальную гордость. Музыкальные фестивали вроде Инди-Негев привлекают большую аудиторию со всей страны.', '[{"he": "מוזיקה", "ru": "музыка", "translit": "мУзика"}, {"he": "זמר", "ru": "певец", "translit": "замАр"}, {"he": "שיר", "ru": "песня", "translit": "шир"}, {"he": "מזרחי", "ru": "восточный", "translit": "мизрахИ"}, {"he": "פסטיבל", "ru": "фестиваль", "translit": "фестивАль"}, {"he": "גאווה", "ru": "гордость", "translit": "гаавА"}, {"he": "תחרות", "ru": "конкурс / соревнование", "translit": "тахарУт"}, {"he": "רדיו", "ru": "радио", "translit": "рАдио"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (189, 6, 'רבדי העברית: חקר מצע לשוני ומגע שפות', 'Лингвистическое исследование', 'העברית המודרנית היא תופעה חריגה בבלשנות: שפה שעברה תחייה מלאכותית ושימשה במשך מאות שנים כשפת כתיבה בלבד. תהליך התחייה, שהחל בסוף המאה התשע-עשרה, הותיר בשפה רבדים רבים שמקורם בשפות המצע של דובריה.
הרובד הסלאבי ניכר בתחביר ובפרוזודיה. מבנים כגון "יש לי" במקום הצורה השמית הקלאסית, וכן הטעמת מילים על ההברה שלפני האחרונה — כולם משקפים השפעה יידית-סלאבית שנטמעה בדור המייסדים.
הרובד הערבי, לעומת זאת, בולט במיוחד בלקסיקון הדיבורי ובסלנג. מילים כגון "יאללה", "סחתיין" ו"אחלה" חדרו לעברית הדבורה והפכו לחלק אינטגרלי ממנה, ללא קשר למוצא האתני של הדובר.
מגע השפות בישראל יוצר גם תופעות מורפולוגיות מעניינות. למשל, הסיומת "-ינג" המיובאת מאנגלית (כגון "פארקינג", "שופינג") התבססה כתבנית פרודוקטיבית ביצירת שמות פעולה חדשים, תופעה חסרת תקדים בשפות שמיות.
ניתוח סוציולינגוויסטי מראה כי דובריה של העברית מפגינים מודעות רבה לרבדים השונים של השפה. בחירת הרגיסטר — פורמלי, בינוני או דיבורי — משקפת לא רק הקשר תקשורתי אלא גם זהות חברתית וערכים תרבותיים.', 'Современный иврит представляет собой уникальное явление в лингвистике: язык, прошедший искусственное возрождение и служивший на протяжении столетий исключительно письменным языком. Процесс возрождения, начавшийся в конце XIX века, оставил в языке множество пластов, восходящих к субстратным языкам его носителей.
Славянский пласт заметен в синтаксисе и просодии. Конструкции вроде «есть у меня» вместо классической семитской формы, а также ударение на предпоследний слог — всё это отражает идишско-славянское влияние, усвоенное поколением основателей.
Арабский пласт, напротив, особенно заметен в разговорной лексике и сленге. Слова вроде «яалла», «сахтейн» и «ахла» проникли в разговорный иврит и стали его неотъемлемой частью вне зависимости от этнического происхождения говорящего.
Языковой контакт в Израиле порождает и интересные морфологические явления. Например, заимствованный из английского суффикс «-инг» (как в «паркинг», «шопинг») утвердился как продуктивная модель для образования новых отглагольных существительных — явление, не имеющее прецедента в семитских языках.
Социолингвистический анализ показывает, что носители иврита проявляют высокую осознанность различных языковых пластов. Выбор регистра — формального, среднего или разговорного — отражает не только коммуникативный контекст, но и социальную идентичность и культурные ценности.', '[{"he": "מצע לשוני", "ru": "языковой субстрат", "translit": "мацА лешонИ"}, {"he": "מגע שפות", "ru": "языковой контакт", "translit": "магА сфатОт"}, {"he": "פרוזודיה", "ru": "просодия", "translit": "прозОдия"}, {"he": "רגיסטר", "ru": "регистр", "translit": "регИстер"}, {"he": "מורפולוגי", "ru": "морфологический", "translit": "морфолОги"}, {"he": "סוציולינגוויסטי", "ru": "социолингвистический", "translit": "социолингвИсти"}, {"he": "תבנית פרודוקטיבית", "ru": "продуктивная модель", "translit": "тавнИт продуктИвит"}, {"he": "לקסיקון", "ru": "лексикон", "translit": "лексикОн"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (190, 6, 'מודרניזציה של טקסט עברי עתיק', 'Модернизация архаичного текста', 'הטקסט המקורי, לקוח ממגילת בן סירא, נכתב בעברית של ראשית התקופה ההלניסטית ומעלה שאלות מרתקות בדבר התפתחות השפה. ניסיון ההתאמה למודרנית חושף את הפער העצום בין שני הרבדים.
בטקסט המקורי נכתב: "בני, אם תבוא לעבוד את ה׳, הכן נפשך לנסיון." ההתאמה המודרנית תהיה: "אם אתה מתחייב לדרך רוחנית, תתכונן להתמודדויות." שים לב: צורת הפועל "תבוא" במשמעות הווליציונלית נעלמה מהעברית המודרנית, ו"נסיון" שינה משמעות מ"מבחן" ל"ניסיון חיים".
דוגמה נוספת: "ישר לבך ותתאמץ" — משפט צווי בשני פעלים. בעברית העתיקה הוו"ו ההיפוכית הופכת את הזמן מעבר לעתיד. במודרנית: "חזק את ליבך והשקע מאמץ." המבנה התחבירי העתיק אינו שקוף עוד לדובר המודרני.
המעבר מהצורה הארכאית למודרנית כרוך גם באובדן. הפואטיקה של הטקסט המקורי — המשקל, הצלילים, האסונאנס — נאבדת בהכרח. הדובר העתיק שמע בביטוי "הכן נפשך" הדים של טקסים פולחניים; הדובר המודרני שומע ביטוי שחוק.
בחינה זו מלמדת כי "עברית" אינה ישות אחת רציפה, אלא רצף של שפות הקשורות זו לזו אך שונות מהותית. ההמשכיות הלשונית היא גם אשליה וגם מציאות — ודווקא מתח זה מעניק לעברית את עומקה הייחודי.', 'Оригинальный текст, взятый из свитка Бен-Сиры, написан на иврите начала эллинистического периода и ставит увлекательные вопросы о развитии языка. Попытка адаптации к современному ивриту обнажает огромный разрыв между двумя языковыми пластами.
В оригинале написано: «Сын мой, если приступишь служить Господу, приготовь душу свою к испытанию». Современная адаптация: «Если берёшь на себя духовное обязательство, готовься к трудностям». Обратите внимание: глагольная форма «приступишь» в волитивном значении исчезла из современного иврита, а «испытание» сменило значение с «проверки» на «жизненный опыт».
Другой пример: «Выпрями сердце твоё и укрепись» — повелительное предложение с двумя глаголами. В древнем иврите перевёрнутый вав меняет время с прошедшего на будущее. В современном: «Укрепи своё сердце и приложи усилия». Древняя синтаксическая конструкция уже непрозрачна для современного носителя.
Переход от архаической формы к современной сопряжён и с потерями. Поэтика оригинала — ритм, звучание, ассонанс — неизбежно утрачивается. Древний носитель слышал в выражении «приготовь душу свою» отголоски ритуальных обрядов; современный — слышит расхожее выражение.
Это исследование показывает, что «иврит» — не единая непрерывная сущность, а последовательность связанных, но существенно различных языков. Языковая преемственность — одновременно иллюзия и реальность, и именно это напряжение придаёт ивриту его уникальную глубину.', '[{"he": "וו\"ו ההיפוכית", "ru": "перевёрнутый вав", "translit": "вав hа-hипухИт"}, {"he": "ארכאי", "ru": "архаический", "translit": "архаИ"}, {"he": "פולחני", "ru": "ритуальный / культовый", "translit": "пульханИ"}, {"he": "אסונאנס", "ru": "ассонанс", "translit": "асонАнс"}, {"he": "רבדים", "ru": "пласты / слои", "translit": "ревадИм"}, {"he": "וולציונלי", "ru": "волитивный", "translit": "волиционАли"}, {"he": "המשכיות לשונית", "ru": "языковая преемственность", "translit": "hемшехиЮт лешонИт"}, {"he": "מגילת בן סירא", "ru": "свиток Бен-Сиры", "translit": "мегилАт бен сирА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (191, 6, 'מעבר בין רגיסטרים: ניתוח סוציולינגוויסטי', 'Анализ code-switching', 'תופעת החלפת הקוד הלשוני — המעבר בין שפות או רגיסטרים באמצע שיחה — מעסיקה חוקרים רבים. בישראל, שבה רוב האוכלוסייה דו-לשונית לפחות, התופעה עשירה ומגוונת במיוחד.
מחקרים מראים כי המעבר בין רגיסטרים אינו אקראי. דוברים בוחרים ברגיסטר גבוה כאשר הם מבקשים להשיג יוקרה חברתית, וברגיסטר נמוך כאשר הם מבקשים ליצור אינטימיות. למשל, מנהל הפונה לעובדיו בשפה גבוהה ועובר לסלנג כדי לספר בדיחה.
גורמים סוציולינגוויסטיים מרכזיים כוללים מעמד חברתי, רקע אתני, מגדר וגיל. צעירים ישראלים, למשל, משלבים אנגלית בשיחת יומיום בתדירות גבוהה בהרבה מבני הדור הקודם. שילוב זה אינו עדות לעניות לשונית, אלא אסטרטגיה תקשורתית מתוחכמת.
בהקשר של עברית-ערבית, החלפת הקוד נושאת גם מטען פוליטי. דוברים ערבים-ישראלים מדווחים כי הם עוברים לעברית בנושאים רשמיים ולערבית בנושאים רגשיים ומשפחתיים — חלוקה המשקפת יחסי כוח בין הקבוצות.
ניתוח שיחות מוקלטות חושף כי הנקודות שבהן מתרחש המעבר אינן מקריות: הן חופפות לגבולות תחביריים, לשינויי נושא ולרגעי מתח רגשי. ממצא זה מחזק את הטענה כי החלפת קוד היא כשירות לשונית, לא חולשה.', 'Явление переключения кодов — перехода между языками или регистрами посреди разговора — занимает многих исследователей. В Израиле, где большинство населения как минимум двуязычно, это явление особенно богато и разнообразно.
Исследования показывают, что переключение между регистрами не случайно. Говорящие выбирают высокий регистр, стремясь к социальному престижу, и низкий — когда хотят создать интимность. Например, руководитель, обращающийся к подчинённым на высоком языке и переходящий на сленг, чтобы рассказать шутку.
Ключевые социолингвистические факторы включают социальный статус, этническое происхождение, гендер и возраст. Молодые израильтяне, к примеру, вкрапляют английский в повседневную речь гораздо чаще предыдущего поколения. Это не свидетельство языковой бедности, а изощрённая коммуникативная стратегия.
В контексте иврита и арабского переключение кодов несёт и политический заряд. Арабо-израильские говорящие сообщают, что переходят на иврит в формальных темах и на арабский — в эмоциональных и семейных, что отражает властные отношения между группами.
Анализ записанных разговоров обнаруживает, что точки переключения не случайны: они совпадают с синтаксическими границами, сменой тем и моментами эмоционального напряжения. Этот вывод подкрепляет тезис о том, что переключение кодов — языковая компетенция, а не слабость.', '[{"he": "החלפת קוד", "ru": "переключение кодов", "translit": "hахлафАт код"}, {"he": "רגיסטר גבוה", "ru": "высокий регистр", "translit": "регИстер гавОа"}, {"he": "דו-לשוני", "ru": "двуязычный", "translit": "ду-лешонИ"}, {"he": "כשירות לשונית", "ru": "языковая компетенция", "translit": "кширУт лешонИт"}, {"he": "מטען פוליטי", "ru": "политический заряд", "translit": "митАн полИти"}, {"he": "אסטרטגיה תקשורתית", "ru": "коммуникативная стратегия", "translit": "стратЕгия тикшортИт"}, {"he": "גבולות תחביריים", "ru": "синтаксические границы", "translit": "гвулОт тахбирийИм"}, {"he": "יחסי כוח", "ru": "властные отношения", "translit": "яхасЭй кОах"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (192, 6, 'חקירה עיתונאית: עקבות הכסף', 'Журналистское расследование', 'חקירה בת שישה חודשים שערך צוות הכתבים שלנו חושפת רשת מורכבת של העברות כספים בין עמותות ציבוריות לחברות פרטיות הקשורות לפוליטיקאים בכירים. המסמכים שהשגנו מצביעים על דפוס שיטתי של ניגוד עניינים.
הכול החל בתלונה אנונימית שהגיעה למערכת. מקור שביקש לשמור על חיסיונו סיפק אלפי מסמכים פנימיים של עמותת "אופק חדש", הפועלת לכאורה בתחום החינוך. הגענו לממצאים מטרידים: כשלושים אחוז מתקציב העמותה הועבר לחברת ייעוץ שבעליה הוא קרוב משפחה של חבר כנסת.
פנינו לגורמים הנוגעים בדבר לקבלת תגובה. חבר הכנסת הכחיש כל קשר ואיים בתביעת דיבה. עורך דינו הבהיר כי "מדובר בעסקאות לגיטימיות שעברו את כל האישורים הנדרשים". אלא שבדיקה ברשם העמותות מעלה כי חלק מהאישורים ניתנו בדיעבד.
שלושה מקורות נוספים, בלתי תלויים זה בזה, אישרו את עיקרי הממצאים. אחד מהם, עובד לשעבר בעמותה, העיד כי הונחה להכין דו"חות כוזבים לרשויות המס. "ידעתי שמשהו לא תקין", אמר, "אבל פחדתי לדבר".
עד לפרסום כתבה זו, רשות המסים ומבקר המדינה לא הגיבו לפניותינו. אנו ממשיכים לעקוב אחר ההתפתחויות ונעדכן את הקוראים ברגע שנקבל תגובות רשמיות.', 'Расследование, длившееся полгода, проведённое нашей журналистской группой, выявляет разветвлённую сеть денежных переводов между общественными организациями и частными компаниями, связанными с высокопоставленными политиками. Полученные документы указывают на систематическую модель конфликта интересов.
Всё началось с анонимной жалобы, поступившей в редакцию. Источник, пожелавший сохранить конфиденциальность, предоставил тысячи внутренних документов организации «Новый горизонт», якобы действующей в сфере образования. Мы пришли к тревожным выводам: около тридцати процентов бюджета организации были переведены консалтинговой компании, владелец которой — родственник депутата Кнессета.
Мы обратились к причастным лицам за комментариями. Депутат отрицал всякую связь и пригрозил иском о клевете. Его адвокат заявил, что «речь идёт о легитимных сделках, прошедших все необходимые согласования». Однако проверка в Реестре некоммерческих организаций показывает, что часть согласований была получена задним числом.
Три дополнительных независимых источника подтвердили основные выводы. Один из них, бывший сотрудник организации, показал, что его инструктировали готовить фиктивные отчёты для налоговых органов. «Я знал, что что-то не так, — сказал он, — но боялся говорить».
На момент публикации данного материала налоговое управление и государственный контролёр не ответили на наши запросы. Мы продолжаем следить за развитием событий и сообщим читателям, как только получим официальные ответы.', '[{"he": "חקירה עיתונאית", "ru": "журналистское расследование", "translit": "хакирА итонаИт"}, {"he": "ניגוד עניינים", "ru": "конфликт интересов", "translit": "нигУд иньянИм"}, {"he": "תביעת דיבה", "ru": "иск о клевете", "translit": "твиАт дибА"}, {"he": "רשם העמותות", "ru": "Реестр НКО", "translit": "рашАм hа-амутОт"}, {"he": "חיסיון", "ru": "конфиденциальность", "translit": "хисайОн"}, {"he": "מבקר המדינה", "ru": "государственный контролёр", "translit": "мевакЭр hа-мединА"}, {"he": "דו\"חות כוזבים", "ru": "фиктивные отчёты", "translit": "духОт козвИм"}, {"he": "עמותה", "ru": "некоммерческая организация", "translit": "амутА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (193, 6, 'פרק מתודולוגיה: סקירת ספרות ועיצוב מחקר', 'Отрывок диссертации', 'פרק זה מציג את המתודולוגיה שנבחרה לצורך המחקר ואת הרציונל העומד בבסיסה. סקירת הספרות שנערכה מצביעה על פער מחקרי משמעותי: מרבית המחקרים בתחום עסקו בניתוח כמותני, ומעטים יישמו גישה איכותנית-פרשנית.
המחקר הנוכחי מאמץ פרדיגמה קונסטרוקטיביסטית, הרואה במציאות החברתית תוצר של פרשנות אנושית. בהתאם לכך, שיטת המחקר העיקרית היא ניתוח תמטי של ראיונות עומק חצי-מובנים שנערכו עם עשרים וחמישה משתתפים.
אוכלוסיית המחקר נבחרה בדגימה מכוונת ובשיטת כדור השלג. הקריטריונים להכללה כללו: גיל מעל שמונה-עשרה, ניסיון של שנתיים לפחות בתחום הנחקר, והסכמה מדעת. אושר אתי התקבל מוועדת האתיקה של האוניברסיטה.
הנתונים נותחו בשלוש רמות: קידוד פתוח, קידוד צירי וקידוד סלקטיבי. מהימנות הניתוח נבדקה באמצעות טריאנגולציה — השוואת ממצאים ממקורות מידע שונים — ובאמצעות בדיקת חברים, שבה הוחזרו הממצאים למשתתפים לאימות.
מגבלות מתודולוגיות מרכזיות כוללות את חוסר האפשרות להכליל ממצאים איכותניים לאוכלוסייה רחבה, ואת ההטיה הפוטנציאלית הנובעת ממעורבות החוקר בשדה. מגבלות אלו נדונות בהרחבה בפרק הדיון.', 'В данной главе представлена выбранная методология исследования и обоснование, лежащее в её основе. Проведённый обзор литературы выявляет значительный исследовательский пробел: большинство работ в данной области использовали количественный анализ, и лишь немногие применяли качественно-интерпретативный подход.
Настоящее исследование принимает конструктивистскую парадигму, рассматривающую социальную реальность как продукт человеческой интерпретации. Соответственно, основным методом является тематический анализ полуструктурированных глубинных интервью с двадцатью пятью участниками.
Исследуемая популяция отобрана методом целевой выборки и методом снежного кома. Критерии включения: возраст старше восемнадцати лет, опыт не менее двух лет в исследуемой области и информированное согласие. Этическое одобрение получено от этического комитета университета.
Данные проанализированы на трёх уровнях: открытое кодирование, осевое кодирование и избирательное кодирование. Достоверность анализа проверена методом триангуляции — сопоставлением данных из различных источников — и методом проверки участниками, которым были возвращены выводы для верификации.
Основные методологические ограничения включают невозможность обобщения качественных выводов на широкую популяцию и потенциальную предвзятость, обусловленную вовлечённостью исследователя в поле. Эти ограничения подробно обсуждаются в главе дискуссии.', '[{"he": "סקירת ספרות", "ru": "обзор литературы", "translit": "скирАт сифрУт"}, {"he": "דגימה מכוונת", "ru": "целевая выборка", "translit": "дгимА мехувЭнет"}, {"he": "טריאנגולציה", "ru": "триангуляция", "translit": "триангулАция"}, {"he": "קידוד פתוח", "ru": "открытое кодирование", "translit": "кидУд патУах"}, {"he": "פרדיגמה קונסטרוקטיביסטית", "ru": "конструктивистская парадигма", "translit": "парадИгма конструктивИстит"}, {"he": "הסכמה מדעת", "ru": "информированное согласие", "translit": "hаскамА ми-дАат"}, {"he": "הטיה", "ru": "предвзятость / смещение", "translit": "hатайА"}, {"he": "שיטת כדור השלג", "ru": "метод снежного кома", "translit": "шитАт кадУр hа-шЕлег"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (194, 6, 'ניתוח שירתה של דליה רביקוביץ׳', 'Поэтический анализ', 'דליה רביקוביץ׳ נחשבת לאחת המשוררות החשובות ביותר בשירה העברית המודרנית. שירתה מצטיינת בשילוב בין רגישות לירית עדינה לבין עוצמה רגשית גולמית. הניתוח הפרוזודי של יצירותיה חושף מבנים מורכבים הנסתרים מאחורי פשטות מדומה.
בשיר "שעון מכני" מציגה רביקוביץ׳ דימוי מרכזי: גוף האישה כמנגנון. המטאפורה אינה חדשה, אך הטיפול בה ייחודי. הקצב האיאמבי הקבוע מדמה את תקתוקי השעון, ודווקא הסטיות ממנו — הפסקות באמצע שורה, מילים חריגות באורכן — מסמנות רגעי משבר.
הדימויים בשירתה שואבים ממקורות מגוונים: הטבע, האגדה, הפסיכואנליזה. בשיר "גאות" הים מתפקד כדימוי אמביוולנטי — מקור חיים ואיום בו-זמנית. הקריאה הפמיניסטית רואה בכך ביטוי לעמדת האישה בחברה הפטריארכלית: נמשכת אל המרחב הציבורי ומאוימת ממנו.
מבחינה פרוזודית, רביקוביץ׳ עושה שימוש מושכל בחרוזים עשירים ודלים לסירוגין. החרוז העשיר מעניק תחושת שלמות, בעוד שהחרוז הדל — המבוסס על עיצור בודד — יוצר אי-נוחות צלילית המשרתת את התוכן.
מורשתה של רביקוביץ׳ חורגת מתחום השירה. מחאתה הציבורית נגד מלחמת לבנון הראשונה, שבאה לידי ביטוי גם בשיריה, הפכה אותה לסמל של מחאה ספרותית פוליטית בישראל.', 'Далия Равикович считается одной из важнейших поэтесс современной ивритской поэзии. Её творчество отличается сочетанием тонкой лирической чувствительности и мощной эмоциональной силы. Просодический анализ её произведений обнаруживает сложные структуры, скрытые за кажущейся простотой.
В стихотворении «Механические часы» Равикович выстраивает центральный образ: женское тело как механизм. Метафора не нова, но её разработка уникальна. Ровный ямбический ритм имитирует тиканье часов, и именно отклонения от него — паузы посреди строки, слова необычной длины — маркируют моменты кризиса.
Образность её поэзии черпает из разнообразных источников: природы, сказки, психоанализа. В стихотворении «Прилив» море функционирует как амбивалентный образ — одновременно источник жизни и угроза. Феминистское прочтение видит в этом выражение позиции женщины в патриархальном обществе: притягиваемой к публичному пространству и им же угрожаемой.
С просодической точки зрения Равикович осознанно чередует богатые и бедные рифмы. Богатая рифма создаёт ощущение завершённости, тогда как бедная — основанная на одном согласном — создаёт звуковой дискомфорт, служащий содержанию.
Наследие Равикович выходит за пределы поэзии. Её публичный протест против первой Ливанской войны, нашедший выражение и в стихах, превратил её в символ литературно-политического протеста в Израиле.', '[{"he": "פרוזודיה", "ru": "просодия", "translit": "прозОдия"}, {"he": "דימוי", "ru": "образ / метафора", "translit": "димУй"}, {"he": "איאמבי", "ru": "ямбический", "translit": "иАмби"}, {"he": "חרוז עשיר", "ru": "богатая рифма", "translit": "харУз ашИр"}, {"he": "חרוז דל", "ru": "бедная рифма", "translit": "харУз даль"}, {"he": "אמביוולנטי", "ru": "амбивалентный", "translit": "амбивалЕнти"}, {"he": "פמיניסטי", "ru": "феминистский", "translit": "феминИсти"}, {"he": "פטריארכלי", "ru": "патриархальный", "translit": "патриархАли"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (195, 6, 'חוות דעת משפטית: פרשנות חקיקה', 'Юридическая записка', 'חוות דעת זו נערכה לבקשת הלקוח בעניין פרשנות סעיף 14 לחוק הגנת הצרכן, התשמ"א-1981. השאלה המשפטית: האם התנהלות הנתבע עולה כדי "הטעיה" כמשמעותה בחוק, והאם הסעד המבוקש — ביטול עסקה — מוצדק?
הוראות הדין הרלוונטיות קובעות כי "עוסק לא יטעה צרכן בדבר מהותי בעסקה". הפסיקה פירשה מושג זה בהרחבה, וכללה בו גם מחדלים — כלומר אי-גילוי מידע מהותי. בעניין כהן נ׳ אלקטרוניקס בע"מ נקבע כי "השתיקה עצמה עולה כדי הטעיה".
במקרה דנן, הנתבע מכר ללקוח מוצר אלקטרוני מבלי לגלות כי מדובר בפריט מחודש ולא חדש. עובדה זו מהווה "דבר מהותי" על פי כל אמת מידה. הנתבע היה מודע לכך ובחר שלא לגלות — התנהגות העולה כדי הטעיה אקטיבית.
באשר לסעד, סעיף 31 לחוק מעניק לצרכן שהוטעה זכות לביטול העסקה ולהשבת מלוא התמורה. בנוסף, סעיף 31א מאפשר לבית המשפט לפסוק פיצויים ללא הוכחת נזק, עד חמישה עשר אלף שקלים, כפיצוי עונשי.
לסיכום, עמדתנו כי סיכויי התביעה טובים. מומלץ לפנות בכתב התראה לנתבע בטרם הגשת תביעה, שכן ניסיון ליישוב מחלוקת מחוץ לבית המשפט עשוי לחסוך זמן ומשאבים.', 'Настоящее юридическое заключение подготовлено по просьбе клиента относительно толкования статьи 14 Закона о защите прав потребителей 1981 года. Правовой вопрос: является ли поведение ответчика «введением в заблуждение» по смыслу закона, и обоснована ли запрашиваемая мера — расторжение сделки?
Соответствующие нормы устанавливают, что «предприниматель не должен вводить потребителя в заблуждение относительно существенного элемента сделки». Судебная практика расширительно истолковала это понятие, включив в него и бездействие — то есть нераскрытие существенной информации. По делу Коэн против Электроникс Лтд. было установлено, что «само молчание составляет введение в заблуждение».
В рассматриваемом случае ответчик продал клиенту электронное изделие, не раскрыв, что речь идёт о восстановленном, а не новом товаре. Этот факт является «существенным элементом» по любому критерию. Ответчик знал об этом и предпочёл не раскрывать — поведение, составляющее активное введение в заблуждение.
Что касается средства защиты, статья 31 закона предоставляет обманутому потребителю право на расторжение сделки и полный возврат уплаченной суммы. Кроме того, статья 31а позволяет суду присудить компенсацию без доказательства ущерба, до пятнадцати тысяч шекелей, в качестве штрафной неустойки.
В заключение, наша позиция: шансы иска хорошие. Рекомендуем направить ответчику предупредительное письмо перед подачей иска, поскольку попытка досудебного урегулирования может сэкономить время и ресурсы.', '[{"he": "חוות דעת משפטית", "ru": "юридическое заключение", "translit": "хавАт дАат мишпатИт"}, {"he": "הטעיה", "ru": "введение в заблуждение", "translit": "hатаА"}, {"he": "סעד", "ru": "средство правовой защиты", "translit": "сАад"}, {"he": "פיצוי עונשי", "ru": "штрафная неустойка", "translit": "пицУй оншИ"}, {"he": "כתב התראה", "ru": "предупредительное письмо", "translit": "ктав hатраА"}, {"he": "ביטול עסקה", "ru": "расторжение сделки", "translit": "битУль искА"}, {"he": "הוראות הדין", "ru": "нормы закона", "translit": "hораОт hа-дин"}, {"he": "תמורה", "ru": "встречное исполнение / оплата", "translit": "тмурА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (196, 6, 'ביקורת ספרים: מוסף ספרותי', 'Книжная рецензия', 'הרומן החדש של עמוס עוז — אילו היה עדיין כותב — היה מעמיד שוב את השאלה שליוותה את כל יצירתו: האם אפשר לספר את ישראל מבלי להגן עליה או לתקוף אותה? ספרו של הסופר הצעיר נועם שקד, "חולות נודדים", מנסה בדיוק את זה.
שקד בונה עולם בדיוני שבו כפר ישראלי שוקע בחולות. המטאפורה שקופה ואולי מכוונת להיות כזו: החברה הישראלית שוקעת תחת משקלם של קונפליקטים שאינה מסוגלת לפתור. אלא ששקד, בניגוד לקודמיו, מסרב להציע תשובות.
השפה ראויה לציון מיוחד. שקד משלב רגיסטרים בחופשיות: משפטים ארוכים, פרוסטיאניים, ברגע שאחריהם משפט בן שלוש מילים בסלנג צבאי. הטכניקה מבלבלת בהתחלה, אך מתגלה כיעילה ביצירת קול ייחודי.
הדמויות בעייתיות יותר. הגיבורה הראשית, דקלה, נותרת דו-ממדית למרות מאמציו של המחבר. המוטיבציות שלה עמומות, ויחסיה עם אביה — שאמורים להיות ציר מרכזי — מתוארים בקווים גסים. דמויות המשנה, לעומת זאת, חיות ומפתיעות.
חרף חולשות אלו, "חולות נודדים" הוא ספר חשוב. שקד מוכיח כי יש עדיין מה לומר בפרוזה הישראלית, ושהדור הצעיר מסוגל למצוא קולות חדשים. ספר ביכורים ששווה לעקוב אחרי מחברו.', 'Новый роман Амоса Оза — если бы он ещё писал — снова поставил бы вопрос, сопровождавший всё его творчество: можно ли рассказать об Израиле, не защищая и не нападая? Книга молодого писателя Ноама Шакеда «Блуждающие пески» пытается именно это.
Шакед выстраивает вымышленный мир, в котором израильская деревня погружается в песок. Метафора прозрачна и, возможно, намеренно такова: израильское общество тонет под тяжестью конфликтов, которые неспособно разрешить. Но Шакед, в отличие от предшественников, отказывается предлагать ответы.
Язык заслуживает особого внимания. Шакед свободно смешивает регистры: длинные, прустовские предложения, за которыми следует фраза из трёх слов на армейском сленге. Техника поначалу сбивает с толку, но оказывается эффективной в создании уникального голоса.
Персонажи более проблематичны. Главная героиня Декла остаётся двумерной, несмотря на усилия автора. Её мотивации размыты, а отношения с отцом — которые должны быть центральной осью — описаны крупными мазками. Второстепенные персонажи, напротив, живые и удивляющие.
Несмотря на эти слабости, «Блуждающие пески» — важная книга. Шакед доказывает, что в израильской прозе ещё есть что сказать и что молодое поколение способно найти новые голоса. Дебютная книга, за автором которой стоит следить.', '[{"he": "ביקורת ספרים", "ru": "книжная критика", "translit": "бикОрет сфарИм"}, {"he": "מוסף ספרותי", "ru": "литературное приложение", "translit": "мусАф сифрутИ"}, {"he": "פרוזה", "ru": "проза", "translit": "прОза"}, {"he": "דו-ממדי", "ru": "двумерный", "translit": "ду-мимадИ"}, {"he": "ספר ביכורים", "ru": "дебютная книга", "translit": "сЭфер бикурИм"}, {"he": "קונפליקט", "ru": "конфликт", "translit": "конфлИкт"}, {"he": "רגיסטרים", "ru": "регистры", "translit": "регИстрим"}, {"he": "מטאפורה", "ru": "метафора", "translit": "метАфора"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (197, 6, 'תמלול ראיון רדיו: על תרבות ושפה', 'Радиотранскрипт', 'מגישה: בוקר טוב, איתנו באולפן הסופרת מיכל זמיר. מיכל, הספר החדש שלך עושה לא מעט רעש. ספרי לנו קצת.
מיכל: תשמעי, אני לא יודעת מה כל הבאלגן הזה. כתבתי ספר על משפחה מרוקאית בירושלים של שנות השישים. זה הכול. אבל אנשים, מה לעשות, מתרגשים כשנוגעים בעניינים של עדתיות. יש כאן עצב ישן ישן שלא מוכן להיעלם.
מגישה: את מתכוונת לביקורת שקיבלת מצד חלק מהמבקרים, שטענו שאת מנכסת סיפורים שאינם שלך?
מיכל: כן, בדיוק. תראי, אני אשכנזייה, ויש כאלה שחושבים שאסור לי לכתוב על מזרחים. אבל רגע, מה זאת אומרת? ספרות זה לא תעודת זהות. אם הייתי כותבת רק על מה שאני — היה יוצא ספר מאוד משעמם, תאמיני לי.
מגישה: ואיך הגיבו הקוראים עצמם?
מיכל: פה דווקא קיבלתי תגובות מדהימות. אנשים כתבו לי שזיהו את הסבתא שלהם בדמות הראשית. מישהי אחת התקשרה ובכתה בטלפון. אלה הרגעים שבשבילם שווה לכתוב, לא? כל הרעש הביקורתי — זה עניין של אקדמיה, לא של חיים.', 'Ведущая: Доброе утро, у нас в студии писательница Михаль Замир. Михаль, твоя новая книга наделала немало шуму. Расскажи нам немного.
Михаль: Послушай, я сама не понимаю, что за переполох. Написала книгу о марокканской семье в Иерусалиме шестидесятых годов. Вот и всё. Но люди, что поделаешь, волнуются, когда затрагиваешь вопросы этнической принадлежности. Тут есть старая-старая боль, которая не желает исчезнуть.
Ведущая: Ты имеешь в виду критику, которую получила от некоторых рецензентов, утверждавших, что ты присваиваешь чужие истории?
Михаль: Да, именно. Видишь ли, я ашкеназка, и есть такие, кто считает, что мне запрещено писать о мизрахим. Но подожди, что это значит? Литература — это не удостоверение личности. Если бы я писала только о себе — получилась бы очень скучная книга, поверь мне.
Ведущая: А как отреагировали сами читатели?
Михаль: Вот тут я как раз получила потрясающие отклики. Люди писали мне, что узнали свою бабушку в главной героине. Одна женщина позвонила и расплакалась по телефону. Это те моменты, ради которых стоит писать, нет? Весь критический шум — это дело академии, а не жизни.', '[{"he": "אולפן", "ru": "студия", "translit": "ульпАн"}, {"he": "באלגן", "ru": "беспорядок / переполох (сленг)", "translit": "балагАн"}, {"he": "עדתיות", "ru": "этническая принадлежность", "translit": "адатиЮт"}, {"he": "ניכוס", "ru": "присвоение (культурное)", "translit": "нихУс"}, {"he": "מגישה", "ru": "ведущая", "translit": "магишА"}, {"he": "תמלול", "ru": "транскрипт / расшифровка", "translit": "тамлУль"}, {"he": "מבקרים", "ru": "критики / рецензенты", "translit": "мевакрИм"}, {"he": "דמות ראשית", "ru": "главный персонаж", "translit": "дмУт решИт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (106, 3, 'מודעת דרושים', 'Объявление о работе', 'חברת תוכנה מובילה בתל אביב מחפשת מפתחת או מפתח לצוות הפיתוח. אנחנו חברה צעירה שמפתחת אפליקציה חדשנית בתחום הבריאות הדיגיטלית. המשרד ליד תחנת הרכבת ויש אווירה נעימה וצוות מעולה.
דרישות: ניסיון של שנתיים בפיתוח תוכנה, ידע בשפות תכנות מודרניות, יכולת עבודה בצוות, אנגלית ברמה גבוהה ונכונות ללמוד טכנולוגיות חדשות. יתרון לבעלי תואר במדעי המחשב או הנדסה.
מה אנחנו מציעים: משכורת תחרותית, אופציות, ימי חופשה נדיבים, ארוחת צהריים במשרד, גמישות בשעות העבודה ואפשרות לעבוד מהבית יומיים בשבוע. יש תקציב ללימודים מקצועיים. שלחו קורות חיים לכתובת המייל שלנו.', 'Ведущая компания-разработчик ПО в Тель-Авиве ищет разработчика или разработчицу в нашу команду. Мы молодая и динамичная компания, разрабатывающая инновационное приложение в области цифрового здравоохранения. Наш офис расположен рядом с железнодорожной станцией, у нас приятная атмосфера и отличная команда.
Требования: минимум два года опыта в разработке ПО, знание современных языков программирования, умение работать в команде, высокий уровень английского и готовность изучать новые технологии. Преимущество для обладателей степени в области информатики или инженерии.
Что мы предлагаем: конкурентная зарплата, опционы в компании, щедрые отпускные дни, обед в офисе каждый день, гибкий график работы и возможность работать из дома два дня в неделю. Есть также годовой бюджет на профессиональное обучение. Если вы подходите, отправьте резюме на наш электронный адрес.', '[{"he": "דרושים", "ru": "вакансии / требуются", "translit": "друшИм"}, {"he": "מפתח", "ru": "разработчик", "translit": "мефатЕах"}, {"he": "ניסיון", "ru": "опыт", "translit": "нисайОн"}, {"he": "משכורת", "ru": "зарплата", "translit": "маскОрет"}, {"he": "גמישות", "ru": "гибкость", "translit": "гмишУт"}, {"he": "קורות חיים", "ru": "резюме", "translit": "корОт хаИм"}, {"he": "תפקיד", "ru": "должность", "translit": "тафкИд"}, {"he": "תוכנה", "ru": "программное обеспечение", "translit": "тохнА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (198, 6, 'מילון סלנג: שורשים ושימושים', 'Сленговый словарь', 'הסלנג הישראלי הוא תופעה לשונית דינמית המשתנה בקצב מסחרר. כל דור מביא איתו מילים חדשות, וחלקן נטמעות בשפה הסטנדרטית בעוד אחרות נעלמות תוך שנים ספורות. להלן מספר ערכים לדוגמה.
"חבל על הזמן" — ביטוי שמשמעותו "מצוין" או "נהדר". האטימולוגיה שנויה במחלוקת: יש הטוענים שמקורו בערבית הדבורה, ויש הרואים בו קיצור של "חבל על הזמן שבזבזתי עד שגיליתי את זה". בשימוש מאז שנות השמונים.
"פראייר" — מי שמאפשרים לנצל אותו; תמים, מטופש. מקור המילה ביידיש-גרמנית, מהמילה Freier (גבר חופשי, לקוח של זונה). בישראל עברה הסטה סמנטית: הפראייר הוא מי שמקפיד על חוקים כשאחרים לא. הביטוי "לא להיות פראייר" הוא כמעט ערך תרבותי.
"יאללה" — מילת זירוז ממקור ערבי (يا الله, "הו אלוהים"). בעברית משמשת כ"בוא", "קדימה", "מהר". חדרה לשימוש כלל-ישראלי, ללא הבדל מגזרי. דוגמה לשאילה לשונית שהתנתקה לחלוטין ממשמעותה הדתית המקורית.
"אחי" — כינוי חיבה בין גברים, מילולית "אחי". מקביל ל-bro באנגלית. שימוש רווח בקרב צעירים מכל המגזרים. הגרסה הנשית "אחותי" קיימת אך פחות נפוצה, ממצא המעורר שאלות מגדריות מעניינות.', 'Израильский сленг — динамическое языковое явление, меняющееся с головокружительной скоростью. Каждое поколение приносит новые слова, часть которых усваивается стандартным языком, а другие исчезают за считанные годы. Ниже несколько примеров словарных статей.
«Хаваль аль hа-зман» — выражение, означающее «отлично» или «потрясающе». Этимология спорна: одни утверждают, что источник в разговорном арабском, другие видят сокращение фразы «жаль времени, что потратил, пока не обнаружил это». В употреблении с восьмидесятых годов.
«Фраер» — тот, кем позволяют себя использовать; наивный, глупый. Происхождение — идиш-немецкое, от Freier (свободный мужчина, клиент проститутки). В Израиле произошёл семантический сдвиг: фраер — тот, кто соблюдает правила, когда другие этого не делают. Выражение «не быть фраером» — почти культурная ценность.
«Яалла» — слово-побуждение арабского происхождения (يا الله, «о Боже»). В иврите используется как «давай», «вперёд», «быстрее». Вошло во всеизраильское употребление без секторальных различий. Пример языкового заимствования, полностью оторвавшегося от первоначального религиозного значения.
«Ахи» — обращение между мужчинами, буквально «брат мой». Аналог английского bro. Широко распространено среди молодёжи всех секторов. Женский вариант «ахоти» существует, но менее распространён — факт, вызывающий интересные гендерные вопросы.', '[{"he": "סלנג", "ru": "сленг", "translit": "слэнг"}, {"he": "אטימולוגיה", "ru": "этимология", "translit": "этимолОгия"}, {"he": "הסטה סמנטית", "ru": "семантический сдвиг", "translit": "hасатА семАнтит"}, {"he": "שאילה לשונית", "ru": "языковое заимствование", "translit": "шеилА лешонИт"}, {"he": "פראייר", "ru": "фраер / простофиля", "translit": "фрайЕр"}, {"he": "מגזרי", "ru": "секторальный", "translit": "мигзарИ"}, {"he": "כינוי חיבה", "ru": "ласковое обращение", "translit": "кинУй хибА"}, {"he": "דינמי", "ru": "динамический", "translit": "динАми"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (199, 6, 'חקר אטימולוגי: שורשים ותמורות משמעות', 'Этимологическое исследование', 'השורש ש-ל-מ הוא אחד הפוריים ביותר בשפות השמיות. מהשורש הזה נגזרים במקרא: שלום, שלם, שילם, השלמה. בערבית: סלאם, מוסלם, אסלאם. בארמית: שלמא. הגרעין הסמנטי המשותף — שלמות, תמימות, היעדר חיסרון.
התפתחות המשמעות מגלה דפוס מרתק. בעברית המקראית "שלום" פירושו בראש ובראשונה שלמות פיזית: "השלום לזקן?" — האם הוא בריא? המשמעות של היעדר מלחמה היא משנית ומאוחרת. באכדית הקרובה, šalāmu משמעו "להיות שלם" במובן חומרי.
באוגריתית, שלם מופיע כשם אל — אלוהות הדמדומים. הקשר בין שלמות לשקיעת השמש אינו מקרי: הערב הוא השלמת היום. שריד לכך נותר בשם ירושלים, שלפי פירוש אחד משמעו "יסודתו של שלם" — העיר שנוסדה על ידי האל שלם.
בעברית הרבנית עבר השורש הרחבה נוספת: "לשלם" במשמעות "לשלם כסף" — כלומר להשלים חוב, להגיע לשלמות כלכלית. כך מילה רוחנית הפכה למסחרית. בערבית קרה תהליך דומה: تسليم (תסלים) — מסירה, השלמה.
ניתוח השוואתי של שלוש השפות השמיות המרכזיות — עברית, ערבית וארמית — מראה כי השורש שמר על גרעינו הסמנטי למרות אלפי שנים של פיצול. עובדה זו מעידה על עומק השורש בתודעה התרבותית השמית.', 'Корень ш-л-м — один из наиболее продуктивных в семитских языках. В Библии от него образованы: шалом, шалем, шилем, hашлама. В арабском: салам, муслим, ислам. В арамейском: шлама. Общее семантическое ядро — целостность, полнота, отсутствие недостатка.
Развитие значения обнаруживает увлекательную закономерность. В библейском иврите «шалом» означает прежде всего физическую целостность: «Шалом старцу?» — здоров ли он? Значение отсутствия войны вторично и более позднее. В близкородственном аккадском šalāmu означает «быть целым» в материальном смысле.
В угаритском шалем фигурирует как имя бога — божества сумерек. Связь между целостностью и закатом солнца не случайна: вечер — это завершение дня. Следы этого сохранились в названии Иерусалима, который, по одному толкованию, означает «основание Шалема» — город, основанный богом Шалемом.
В раввинистическом иврите корень получил дополнительное расширение: «лешалем» в значении «платить деньги» — то есть завершить долг, достичь экономической целостности. Так духовное слово стало коммерческим. В арабском произошёл аналогичный процесс: تسليم (таслим) — передача, завершение.
Сравнительный анализ трёх основных семитских языков — иврита, арабского и арамейского — показывает, что корень сохранил своё семантическое ядро несмотря на тысячелетия расхождения. Этот факт свидетельствует о глубине корня в семитском культурном сознании.', '[{"he": "אטימולוגיה", "ru": "этимология", "translit": "этимолОгия"}, {"he": "גרעין סמנטי", "ru": "семантическое ядро", "translit": "гарИн семАнти"}, {"he": "אוגריתית", "ru": "угаритский", "translit": "угарИтит"}, {"he": "אכדית", "ru": "аккадский", "translit": "акадИт"}, {"he": "שפות שמיות", "ru": "семитские языки", "translit": "сфатОт шемиЮт"}, {"he": "תמורות משמעות", "ru": "семантические сдвиги", "translit": "тмурОт машмаУт"}, {"he": "עברית רבנית", "ru": "раввинистический иврит", "translit": "иврИт рабанИт"}, {"he": "ניתוח השוואתי", "ru": "сравнительный анализ", "translit": "нитУах hашваатИ"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (200, 6, 'שליטה בשפה: מהו רמת C2?', 'Текст о мастерстве языка', 'הרמה הגבוהה ביותר במסגרת ההתייחסות האירופית לשפות מכונה C2, ומתארת "שליטה" ברמת דובר ילידי משכיל. אך מה משמעותה של שליטה זו בפועל? ובמיוחד — מה משמעותה בהקשר של עברית?
דובר ברמת C2 אינו רק מי שמבין הכול ומדבר בשטף. הוא מי שמזהה ניואנסים דקים: את ההבדל בין "בהחלט" ל"ודאי" ל"בלי ספק"; את הרגיסטר המדויק הנדרש בכל מצב — מכתב לרופא, מייל לחבר, נאום בכנס. טעות ברגיסטר חמורה יותר מטעות דקדוקית.
בעברית, שליטה ברמת C2 כוללת גם מודעות לרבדים ההיסטוריים של השפה. דובר מתקדם מזהה ציטוט מקראי כשהוא שמוע, מבין אלוזיות תלמודיות בשיח המשפטי, וקולט שהביטוי "חלילה" שייך לרגיסטר גבוה ולא לשיחה יומיומית.
היבט נוסף הוא היכולת לקרוא בין השורות. התרבות הישראלית עשירה בסובטקסט, באירוניה ובהומור עצמי. דובר C2 מבין לא רק מה נאמר אלא גם מה לא נאמר — ולמה. הוא מזהה שהמשפט "מעניין, אבל..." הוא סירוב מנומס.
לבסוף, שליטה אמיתית בשפה כוללת את היכולת להיכשל בחן. דובר C2 יודע לצחוק על הטעויות שלו, לשחק עם השפה, להמציא משחקי מילים. פרדוקסלית, רק מי ששולט בחוקים יכול להרשות לעצמו לשבור אותם — וזוהי אולי ההגדרה הטובה ביותר לרמת C2.', 'Высший уровень в Европейской языковой рамке называется C2 и описывает «владение» на уровне образованного носителя. Но что означает это владение на практике? И в особенности — что оно означает в контексте иврита?
Говорящий на уровне C2 — это не просто тот, кто всё понимает и бегло говорит. Это тот, кто распознаёт тонкие нюансы: разницу между «безусловно», «разумеется» и «вне всякого сомнения»; точный регистр, требуемый в каждой ситуации — письмо врачу, электронное сообщение другу, выступление на конференции. Ошибка в регистре серьёзнее грамматической.
В иврите владение на уровне C2 включает также осознание исторических пластов языка. Продвинутый говорящий на слух узнаёт библейскую цитату, понимает талмудические аллюзии в юридическом дискурсе и улавливает, что выражение «халила» принадлежит к высокому регистру, а не к повседневной речи.
Ещё один аспект — умение читать между строк. Израильская культура богата подтекстом, иронией и самоиронией. Говорящий на уровне C2 понимает не только сказанное, но и несказанное — и почему. Он распознаёт, что фраза «интересно, но...» — это вежливый отказ.
Наконец, истинное владение языком включает способность изящно ошибаться. Говорящий на уровне C2 умеет смеяться над собственными ошибками, играть с языком, изобретать каламбуры. Парадоксально, лишь тот, кто владеет правилами, может позволить себе их нарушать — и это, пожалуй, лучшее определение уровня C2.', '[{"he": "שליטה בשפה", "ru": "владение языком", "translit": "шлитА ба-сафА"}, {"he": "רגיסטר", "ru": "регистр", "translit": "регИстер"}, {"he": "ניואנסים", "ru": "нюансы", "translit": "ниюансИм"}, {"he": "סובטקסט", "ru": "подтекст", "translit": "субтЕкст"}, {"he": "אלוזיה", "ru": "аллюзия", "translit": "алУзия"}, {"he": "אירוניה", "ru": "ирония", "translit": "ирОния"}, {"he": "משחקי מילים", "ru": "каламбуры / игра слов", "translit": "мисхакЭй милИм"}, {"he": "רבדים היסטוריים", "ru": "исторические пласты", "translit": "ревадИм hисториИм"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (98, 3, 'מיחזור בישראל', 'Переработка в Израиле', 'בשנים האחרונות ישראל עושה מאמצים בתחום המיחזור והשמירה על הסביבה. ברחובות הוצבו פחי מיחזור בצבעים שונים: כתום לאריזות, כחול לנייר, סגול לזכוכית וחום לפסולת אורגנית. האזרחים מתבקשים להפריד את הפסולת ולזרוק כל סוג לפח המתאים.
חוק הפיקדון על בקבוקים הוא הצלחה גדולה. על כל בקבוק פלסטיק או פחית יש פיקדון של שלושים אגורות. כשמחזירים את הבקבוק למכונה בסופר מקבלים את הכסף בחזרה. זה מעודד אנשים לא לזרוק בקבוקים לרחוב.
עם זאת, ישראל עדיין לא ממחזרת מספיק. רק כשלושים אחוז מהפסולת ממוחזרת, נמוך מאוד בהשוואה לאירופה. הממשלה מנסה לשפר את המצב עם חינוך סביבתי בבתי ספר וקנסות לעסקים שלא ממחזרים כראוי.', 'В последние годы Израиль прилагает большие усилия в области переработки отходов и охраны окружающей среды. На улицах установлены контейнеры для раздельного сбора разных цветов: оранжевые для упаковки, синие для бумаги, фиолетовые для стекла и коричневые для органических отходов. Граждан просят разделять мусор дома и выбрасывать каждый вид в подходящий контейнер.
Закон о залоговой стоимости бутылок — большой израильский успех. На каждую пластиковую бутылку или банку есть залог в тридцать агорот. Когда возвращаешь бутылку в специальный автомат в супермаркете, получаешь деньги обратно. Это стимулирует людей не выбрасывать бутылки на улицу.
Тем не менее Израиль всё ещё недостаточно перерабатывает. По данным, только около тридцати процентов отходов перерабатывается. По сравнению с европейскими странами это очень мало. Правительство пытается улучшить ситуацию с помощью экологического образования в школах и штрафов для бизнесов, которые не перерабатывают должным образом.', '[{"he": "מיחזור", "ru": "переработка (отходов)", "translit": "михзУр"}, {"he": "פסולת", "ru": "мусор / отходы", "translit": "псОлет"}, {"he": "פח", "ru": "контейнер / мусорный бак", "translit": "пах"}, {"he": "בקבוק", "ru": "бутылка", "translit": "бакбУк"}, {"he": "פיקדון", "ru": "залог (за бутылку)", "translit": "пикадОн"}, {"he": "סביבה", "ru": "окружающая среда", "translit": "свивА"}, {"he": "להפריד", "ru": "разделять", "translit": "леhафрИд"}, {"he": "קנס", "ru": "штраф", "translit": "кнас"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (107, 3, 'מודעת דירה להשכרה', 'Объявление о квартире', 'להשכרה דירת שלושה חדרים ברחוב דיזנגוף בתל אביב, קומה רביעית עם מעלית. הדירה משופצת ומוארת במיקום מצוין ליד חנויות, מסעדות ותחבורה ציבורית. בקרבת מקום יש גן ציבורי ובית ספר.
הדירה כוללת סלון מרווח, שני חדרי שינה, מטבח מאובזר, חדר אמבטיה עם מקלחון ושירותים נפרדים. יש מרפסת קטנה שמתאימה לשתייה בבוקר. הדירה מרוהטת חלקית, עם ארונות בחדרי השינה ומזגן בסלון.
דמי השכירות חמשת אלפים ושלוש מאות שקלים, לא כולל ארנונה ומים. נדרש פיקדון של שני חודשים. החוזה לשנה עם אפשרות הארכה. מתאים לזוג או לשותפים. מעוניינים מוזמנים ליצור קשר.', 'Сдаётся трёхкомнатная квартира на улице Дизенгоф в Тель-Авиве, четвёртый этаж с лифтом. Квартира отремонтирована, светлая и расположена в отличном месте рядом с магазинами, ресторанами и общественным транспортом. Поблизости есть публичный сад и начальная школа.
Квартира включает просторную гостиную, две спальни, оборудованную кухню со всей техникой, ванную комнату с душевой кабиной и отдельный туалет. Есть маленький солнечный балкон, подходящий для утреннего кофе или выращивания цветов. Квартира частично меблирована, со шкафами в спальнях и кондиционером в гостиной.
Арендная плата — пять тысяч триста шекелей в месяц, не включая муниципальный налог и счета за воду и электричество. Требуется залог за два месяца вперёд. Договор на год с возможностью продления. Подходит для пары или соседей. Заинтересованных просим связаться по телефону или Ватсапу.', '[{"he": "להשכרה", "ru": "сдаётся в аренду", "translit": "леhаскарА"}, {"he": "משופצת", "ru": "отремонтированная", "translit": "мешупЕцет"}, {"he": "מעלית", "ru": "лифт", "translit": "маалИт"}, {"he": "סלון", "ru": "гостиная", "translit": "салОн"}, {"he": "מרפסת", "ru": "балкон", "translit": "мирпЕсет"}, {"he": "מרוהט", "ru": "меблированный", "translit": "меруhАт"}, {"he": "מזגן", "ru": "кондиционер", "translit": "мазгАн"}, {"he": "חשבון", "ru": "счёт", "translit": "хешбОн"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (45, 1, 'בבית ספר', 'В школе', 'דני הולך לבית ספר כל יום. הוא לומד עברית, מתמטיקה ומדעים. המורה שלו טובה מאוד. היא מלמדת את התלמידים דברים חדשים. דני אוהב ללמוד. בהפסקה הוא משחק עם חברים בחצר. הם רצים ומשחקים כדורגל. אחרי ההפסקה הם חוזרים לכיתה. דני יושב ליד החלון ופותח את המחברת. הוא כותב יפה. בסוף היום דני חוזר הביתה ועושה שיעורי בית.', 'Дани ходит в школу каждый день. Он учит иврит, математику и науки. Его учительница очень хорошая. Она учит учеников новым вещам. Дани любит учиться. На перемене он играет с друзьями во дворе. Они бегают и играют в футбол. После перемены они возвращаются в класс. Дани сидит у окна и открывает тетрадь. Он пишет красиво. В конце дня Дани возвращается домой и делает домашнее задание.', '[{"he": "בית ספר", "ru": "школа", "translit": "бейт сЭфер"}, {"he": "מורה", "ru": "учитель/учительница", "translit": "морА"}, {"he": "תלמיד", "ru": "ученик", "translit": "талмИд"}, {"he": "הפסקה", "ru": "перемена", "translit": "hафсакА"}, {"he": "חצר", "ru": "двор", "translit": "хацЭр"}, {"he": "כיתה", "ru": "класс", "translit": "китА"}, {"he": "מחברת", "ru": "тетрадь", "translit": "махбЭрет"}, {"he": "שיעורי בית", "ru": "домашнее задание", "translit": "шиурЭй бАйт"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (46, 1, 'חיות מחמד', 'Домашние питомцы', 'לשרה יש חתול. החתול שלה לבן וגדול. הוא אוהב לשחק בגינה. שרה נותנת לו אוכל כל יום. החתול ישן על המיטה שלה. בבוקר החתול קם ורוצה לאכול. שרה נותנת לו חלב וגם אוכל. אחר כך החתול יוצא לגינה ומשחק עם פרפרים. לחבר של שרה יש כלב קטן. הכלב רץ מהר ואוהב לשחק. שרה והחבר שלה הולכים ביחד לפארק עם החיות.', 'У Сары есть кот. Её кот белый и большой. Он любит играть в саду. Сара даёт ему еду каждый день. Кот спит на её кровати. Утром кот встаёт и хочет есть. Сара даёт ему молоко и еду. Потом кот выходит в сад и играет с бабочками. У друга Сары есть маленькая собака. Собака бегает быстро и любит играть. Сара и её друг вместе идут в парк с животными.', '[{"he": "חתול", "ru": "кот", "translit": "хатУль"}, {"he": "כלב", "ru": "собака", "translit": "кЭлев"}, {"he": "גינה", "ru": "сад", "translit": "гинА"}, {"he": "אוכל", "ru": "еда", "translit": "Охель"}, {"he": "חלב", "ru": "молоко", "translit": "халАв"}, {"he": "פרפר", "ru": "бабочка", "translit": "парпАр"}, {"he": "מיטה", "ru": "кровать", "translit": "митА"}, {"he": "חיות מחמד", "ru": "домашние животные", "translit": "хайОт махмАд"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (47, 1, 'עונות השנה', 'Времена года', 'בישראל יש ארבע עונות. בקיץ חם מאוד. בחורף יורד גשם. באביב יש פרחים יפים. בסתיו העלים נופלים מהעצים. בקיץ ילדים הולכים לים ושוחים. השמש חזקה וצריך לשתות מים. בחורף אנשים לובשים מעיל וכובע. לפעמים יורד שלג בירושלים. באביב הכול ירוק ויפה. ציפורים שרות על העצים. כל עונה מיוחדת. אני אוהב את כל העונות.', 'В Израиле есть четыре сезона. Летом очень жарко. Зимой идёт дождь. Весной есть красивые цветы. Осенью листья падают с деревьев. Летом дети ходят на море и плавают. Солнце сильное и нужно пить воду. Зимой люди носят пальто и шапку. Иногда в Иерусалиме идёт снег. Весной всё зелёное и красивое. Птицы поют на деревьях. Каждый сезон особенный. Я люблю все сезоны.', '[{"he": "עונה", "ru": "сезон", "translit": "онА"}, {"he": "קיץ", "ru": "лето", "translit": "кАйиц"}, {"he": "חורף", "ru": "зима", "translit": "хОреф"}, {"he": "אביב", "ru": "весна", "translit": "авИв"}, {"he": "סתיו", "ru": "осень", "translit": "стАв"}, {"he": "גשם", "ru": "дождь", "translit": "гЭшем"}, {"he": "שלג", "ru": "снег", "translit": "шЭлег"}, {"he": "פרחים", "ru": "цветы", "translit": "прахИм"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (48, 1, 'יום הולדת', 'День рождения', 'היום יום ההולדת של רון. הוא בן שבע. המשפחה עושה מסיבה. יש עוגה גדולה עם נרות. רון מקבל מתנות מהחברים. אמא מכינה אוכל טעים. יש פיצה ושתייה. הילדים שרים ''יום הולדת שמח''. רון מכבה את הנרות. אחר כך כולם אוכלים עוגה. העוגה בטעם שוקולד וזה טעים מאוד. רון שמח. זה היום הכי טוב בשנה.', 'Сегодня день рождения Рона. Ему семь лет. Семья устраивает вечеринку. Есть большой торт со свечами. Рон получает подарки от друзей. Мама готовит вкусную еду. Есть пицца и напитки. Дети поют «С днём рождения». Рон задувает свечи. Потом все едят торт. Торт шоколадный и очень вкусный. Рон счастлив. Это лучший день в году.', '[{"he": "יום הולדת", "ru": "день рождения", "translit": "йом hуледЭт"}, {"he": "מסיבה", "ru": "вечеринка", "translit": "месибА"}, {"he": "עוגה", "ru": "торт", "translit": "угА"}, {"he": "נרות", "ru": "свечи", "translit": "нерОт"}, {"he": "מתנה", "ru": "подарок", "translit": "матанА"}, {"he": "שמח", "ru": "счастливый", "translit": "самЭах"}, {"he": "שוקולד", "ru": "шоколад", "translit": "шоколАд"}, {"he": "משפחה", "ru": "семья", "translit": "мишпахА"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (49, 1, 'החדר שלי', 'Моя комната', 'יש לי חדר קטן אבל יפה. יש שם מיטה, שולחן וכיסא. על הקיר יש תמונות. ליד החלון יש צמח ירוק. אני אוהב את החדר שלי. על השולחן יש מחשב ומנורה. בארון יש בגדים ונעליים. על המדף יש ספרים וצעצועים. בערב אני קורא ספר במיטה. המיטה שלי נוחה ורכה. החדר שלי הוא המקום האהוב עליי בבית.', 'У меня есть маленькая но красивая комната. Там есть кровать, стол и стул. На стене есть картины. У окна стоит зелёное растение. Я люблю свою комнату. На столе есть компьютер и лампа. В шкафу есть одежда и обувь. На полке есть книги и игрушки. Вечером я читаю книгу в кровати. Моя кровать удобная и мягкая. Моя комната — моё любимое место в доме.', '[{"he": "חדר", "ru": "комната", "translit": "хЭдер"}, {"he": "שולחן", "ru": "стол", "translit": "шульхАн"}, {"he": "כיסא", "ru": "стул", "translit": "кисЭ"}, {"he": "ארון", "ru": "шкаф", "translit": "арОн"}, {"he": "מדף", "ru": "полка", "translit": "мадАф"}, {"he": "מנורה", "ru": "лампа", "translit": "менорА"}, {"he": "חלון", "ru": "окно", "translit": "халОн"}, {"he": "תמונה", "ru": "картина", "translit": "тмунА"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (50, 1, 'בפארק', 'В парке', 'ביום שבת אנחנו הולכים לפארק. הילדים משחקים במגרש. אני רץ ומשחק כדורגל. אמא יושבת על הספסל וקוראת ספר. אבא מכין פיקניק. יש לחם, גבינה, פירות ומיץ. אנחנו יושבים על הדשא ואוכלים ביחד. יש גם כלבים בפארק. הילדים אוהבים לשחק עם הכלבים. יש עצים גדולים ופרחים יפים. אנחנו נשארים בפארק עד הערב. זה כיף.', 'В субботу мы идём в парк. Дети играют на площадке. Я бегу и играю в футбол. Мама сидит на скамейке и читает книгу. Папа готовит пикник. Есть хлеб, сыр, фрукты и сок. Мы сидим на траве и едим вместе. В парке есть и собаки. Дети любят играть с собаками. Есть большие деревья и красивые цветы. Мы остаёмся в парке до вечера. Это весело.', '[{"he": "פארק", "ru": "парк", "translit": "пАрк"}, {"he": "מגרש", "ru": "площадка", "translit": "мигрАш"}, {"he": "ספסל", "ru": "скамейка", "translit": "сафсАль"}, {"he": "דשא", "ru": "газон/трава", "translit": "дЭше"}, {"he": "פיקניק", "ru": "пикник", "translit": "пикнИк"}, {"he": "כדורגל", "ru": "футбол", "translit": "кадурЭгель"}, {"he": "פירות", "ru": "фрукты", "translit": "перОт"}, {"he": "שבת", "ru": "суббота", "translit": "шабАт"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (51, 1, 'בשוק', 'На рынке', 'אמא לוקחת אותי לשוק. יש שם הרבה פירות וירקות. אנחנו קונים תפוחים, בננות ועגבניות. המוכר נחמד ונותן לי תפוז. אני אוהב ללכת לשוק. בשוק יש ריחות טובים של אוכל. יש דוכנים עם לחם טרי וגבינות. אנשים מדברים ומתמקחים. אמא קונה גם ביצים וחלב. אנחנו שמים הכול בשקית גדולה. אחרי השוק אנחנו הולכים הביתה ואוכלים פירות טריים.', 'Мама берёт меня на рынок. Там много фруктов и овощей. Мы покупаем яблоки, бананы и помидоры. Продавец приятный и даёт мне апельсин. Я люблю ходить на рынок. На рынке хорошо пахнет едой. Есть прилавки со свежим хлебом и сырами. Люди разговаривают и торгуются. Мама покупает ещё яйца и молоко. Мы кладём всё в большой пакет. После рынка мы идём домой и едим свежие фрукты.', '[{"he": "שוק", "ru": "рынок", "translit": "шук"}, {"he": "ירקות", "ru": "овощи", "translit": "йеракОт"}, {"he": "מוכר", "ru": "продавец", "translit": "мохЭр"}, {"he": "דוכן", "ru": "прилавок", "translit": "духАн"}, {"he": "ביצים", "ru": "яйца", "translit": "бейцИм"}, {"he": "שקית", "ru": "пакет", "translit": "сакИт"}, {"he": "טרי", "ru": "свежий", "translit": "тарИ"}, {"he": "ריח", "ru": "запах", "translit": "рЭйах"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (52, 1, 'אצל הרופא', 'У врача', 'אני לא מרגיש טוב. יש לי כאב ראש וחום. אמא לוקחת אותי לרופא. הרופא בודק אותי ונותן לי תרופה. אחרי יום אני מרגיש יותר טוב. הרופא אומר שצריך לנוח ולשתות הרבה. אני שוכב במיטה ואמא מביאה לי מרק חם. אני גם שותה תה עם דבש. אחרי יומיים אני כבר בריא. אני חוזר לבית ספר ומשחק עם החברים. הרופא עזר לי.', 'Мне нехорошо. У меня болит голова и температура. Мама берёт меня к врачу. Врач осматривает меня и даёт мне лекарство. Через день мне лучше. Врач говорит, что нужно отдыхать и много пить. Я лежу в кровати, и мама приносит мне горячий суп. Я также пью чай с мёдом. Через два дня я уже здоров. Я возвращаюсь в школу и играю с друзьями. Врач мне помог.', '[{"he": "רופא", "ru": "врач", "translit": "рофЭ"}, {"he": "תרופה", "ru": "лекарство", "translit": "труфА"}, {"he": "כאב", "ru": "боль", "translit": "кеЭв"}, {"he": "חום", "ru": "температура/жар", "translit": "хом"}, {"he": "מרק", "ru": "суп", "translit": "марАк"}, {"he": "דבש", "ru": "мёд", "translit": "двАш"}, {"he": "בריא", "ru": "здоровый", "translit": "барИ"}, {"he": "לנוח", "ru": "отдыхать", "translit": "ланУах"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (53, 1, 'בוקר טוב', 'Доброе утро', 'אני קם בשבע בבוקר. אני מתלבש ואוכל ארוחת בוקר. אני שותה חלב ואוכל לחם עם גבינה. אחר כך אני הולך לבית ספר. אני אומר ''שלום'' לכולם. אני מצחצח שיניים לפני האוכל. אחרי ארוחת בוקר אני שם את הספרים בתיק. אני יוצא מהבית ופוגש את החבר שלי ברחוב. אנחנו הולכים ביחד לבית ספר. הבוקר שלי טוב ושמח.', 'Я встаю в семь утра. Я одеваюсь и завтракаю. Я пью молоко и ем хлеб с сыром. Потом я иду в школу. Я говорю «Привет» всем. Я чищу зубы перед едой. После завтрака я кладу книги в рюкзак. Я выхожу из дома и встречаю друга на улице. Мы вместе идём в школу. Моё утро хорошее и радостное.', '[{"he": "בוקר", "ru": "утро", "translit": "бОкер"}, {"he": "ארוחת בוקר", "ru": "завтрак", "translit": "арухАт бОкер"}, {"he": "לחם", "ru": "хлеб", "translit": "лЭхем"}, {"he": "גבינה", "ru": "сыр", "translit": "гвинА"}, {"he": "שיניים", "ru": "зубы", "translit": "шинАйим"}, {"he": "תיק", "ru": "рюкзак/сумка", "translit": "тик"}, {"he": "רחוב", "ru": "улица", "translit": "рехОв"}, {"he": "שמח", "ru": "радостный", "translit": "самЭах"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (54, 1, 'באוטובוס', 'В автобусе', 'אני נוסע באוטובוס לבית ספר. האוטובוס מגיע בשמונה. אני עולה ויושב ליד החלון. הנסיעה לוקחת עשרים דקות. אני יורד בתחנה ליד בית ספר. באוטובוס יש הרבה אנשים. יש ילדים ויש מבוגרים. הנהג נחמד ואומר בוקר טוב. אני רואה את הרחובות מהחלון. יש מכוניות, חנויות ועצים. כשאני מגיע לתחנה אני אומר תודה לנהג ויורד.', 'Я еду на автобусе в школу. Автобус приезжает в восемь. Я поднимаюсь и сажусь у окна. Поездка занимает двадцать минут. Я выхожу на остановке возле школы. В автобусе много людей. Есть дети и взрослые. Водитель приятный и говорит «Доброе утро». Я смотрю на улицы из окна. Есть машины, магазины и деревья. Когда я приезжаю на остановку, я говорю спасибо водителю и выхожу.', '[{"he": "אוטובוס", "ru": "автобус", "translit": "отобУс"}, {"he": "נסיעה", "ru": "поездка", "translit": "несиА"}, {"he": "תחנה", "ru": "остановка", "translit": "таханА"}, {"he": "נהג", "ru": "водитель", "translit": "наhАг"}, {"he": "חלון", "ru": "окно", "translit": "халОн"}, {"he": "דקות", "ru": "минуты", "translit": "дакОт"}, {"he": "מכונית", "ru": "машина", "translit": "мехонИт"}, {"he": "רחוב", "ru": "улица", "translit": "рехОв"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (55, 1, 'בספריה', 'В библиотеке', 'אני אוהב ללכת לספריה. יש שם הרבה ספרים. אני בוחר ספר ויושב לקרוא. הספרנית עוזרת לי למצוא ספרים. אני משאיל ספרים לשבוע. בספריה שקט ונעים. יש כיסאות נוחים ושולחנות גדולים. ילדים יושבים וקוראים סיפורים. אני אוהב סיפורים על חיות ועל הרפתקאות. אני מחזיר את הספרים בזמן ולוקח ספרים חדשים. הספריה מקום נהדר.', 'Я люблю ходить в библиотеку. Там много книг. Я выбираю книгу и сажусь читать. Библиотекарь помогает мне найти книги. Я беру книги на неделю. В библиотеке тихо и приятно. Есть удобные стулья и большие столы. Дети сидят и читают рассказы. Я люблю рассказы о животных и приключениях. Я возвращаю книги вовремя и беру новые. Библиотека — прекрасное место.', '[{"he": "ספריה", "ru": "библиотека", "translit": "сифриЯ"}, {"he": "ספר", "ru": "книга", "translit": "сЭфер"}, {"he": "ספרנית", "ru": "библиотекарь", "translit": "сафранИт"}, {"he": "סיפור", "ru": "рассказ", "translit": "сипУр"}, {"he": "שקט", "ru": "тихо", "translit": "шЭкет"}, {"he": "נוח", "ru": "удобный", "translit": "нОах"}, {"he": "הרפתקה", "ru": "приключение", "translit": "hарпаткА"}, {"he": "להשאיל", "ru": "брать на время", "translit": "леhашИль"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (56, 1, 'בחוף הים', 'На пляже', 'בקיץ אנחנו הולכים לחוף הים. המים כחולים ויפים. אני שוחה ומשחק בחול. אבא בונה ארמון חול. אמא שוכבת בשמש. הים נפלא. אנחנו שמים קרם שמש על הגוף. אני מוצא צדפים יפים על החוף. אחותי עושה עוגות מחול. אנחנו שותים מים קרים ואוכלים אבטיח. בערב השמש שוקעת בים. הצבעים בשמיים יפים מאוד. אנחנו חוזרים הביתה עייפים ושמחים.', 'Летом мы ходим на пляж. Вода голубая и красивая. Я плаваю и играю в песке. Папа строит замок из песка. Мама лежит на солнце. Море чудесное. Мы наносим солнцезащитный крем. Я нахожу красивые ракушки на берегу. Сестра делает куличики из песка. Мы пьём холодную воду и едим арбуз. Вечером солнце садится в море. Краски в небе очень красивые. Мы возвращаемся домой уставшие и довольные.', '[{"he": "חוף", "ru": "пляж/берег", "translit": "хоф"}, {"he": "ים", "ru": "море", "translit": "ям"}, {"he": "חול", "ru": "песок", "translit": "холь"}, {"he": "שמש", "ru": "солнце", "translit": "шЭмеш"}, {"he": "צדף", "ru": "ракушка", "translit": "цЭдеф"}, {"he": "אבטיח", "ru": "арбуз", "translit": "аватИах"}, {"he": "גוף", "ru": "тело", "translit": "гуф"}, {"he": "שמיים", "ru": "небо", "translit": "шамАйим"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (57, 1, 'במסעדה', 'В ресторане', 'אנחנו הולכים למסעדה. אני מזמין שניצל עם אורז. אבא אוכל סלט. אמא שותה מיץ תפוזים. האוכל טעים מאוד. אנחנו משלמים ויוצאים. המלצר מביא את התפריט. כולם בוחרים מה לאכול. אחותי מזמינה פסטה. אנחנו גם אוכלים לחם עם חומוס. בסוף המלצר מביא קינוח. אנחנו אוכלים גלידה. ערב נחמד במסעדה.', 'Мы идём в ресторан. Я заказываю шницель с рисом. Папа ест салат. Мама пьёт апельсиновый сок. Еда очень вкусная. Мы платим и выходим. Официант приносит меню. Все выбирают что есть. Сестра заказывает пасту. Мы также едим хлеб с хумусом. В конце официант приносит десерт. Мы едим мороженое. Приятный вечер в ресторане.', '[{"he": "מסעדה", "ru": "ресторан", "translit": "мисадА"}, {"he": "מלצר", "ru": "официант", "translit": "мельцАр"}, {"he": "תפריט", "ru": "меню", "translit": "тафрИт"}, {"he": "שניצל", "ru": "шницель", "translit": "шнИцель"}, {"he": "קינוח", "ru": "десерт", "translit": "кинУах"}, {"he": "גלידה", "ru": "мороженое", "translit": "глидА"}, {"he": "חומוס", "ru": "хумус", "translit": "хУмус"}, {"he": "טעים", "ru": "вкусный", "translit": "таИм"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (58, 1, 'חג פסח', 'Праздник Песах', 'פסח הוא חג חשוב בישראל. אנחנו עושים סדר. אנחנו אוכלים מצות. סבא מספר את הסיפור של יציאת מצרים. כל המשפחה ביחד. לפני החג אמא מנקה את כל הבית. אנחנו לא אוכלים לחם בפסח. על השולחן יש קערה עם אוכל מיוחד. הילדים שרים שירים ושואלים שאלות. סבתא מבשלת אוכל טעים. כולם שמחים. פסח הוא חג של חירות ומשפחה.', 'Песах — важный праздник в Израиле. Мы проводим седер. Мы едим мацу. Дедушка рассказывает историю исхода из Египта. Вся семья вместе. Перед праздником мама убирает весь дом. Мы не едим хлеб в Песах. На столе есть блюдо с особой едой. Дети поют песни и задают вопросы. Бабушка готовит вкусную еду. Все счастливы. Песах — праздник свободы и семьи.', '[{"he": "חג", "ru": "праздник", "translit": "хаг"}, {"he": "מצה", "ru": "маца", "translit": "мацА"}, {"he": "סדר", "ru": "седер", "translit": "сЭдер"}, {"he": "סבא", "ru": "дедушка", "translit": "сАба"}, {"he": "סבתא", "ru": "бабушка", "translit": "сАвта"}, {"he": "חירות", "ru": "свобода", "translit": "херУт"}, {"he": "קערה", "ru": "блюдо/миска", "translit": "кеарА"}, {"he": "לנקות", "ru": "убирать", "translit": "ленакОт"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (59, 1, 'החבר שלי', 'Мой друг', 'יש לי חבר טוב. שמו יוסי. אנחנו לומדים ביחד ומשחקים אחרי בית ספר. יוסי גר ליד הבית שלי. הוא אוהב כדורסל ואני אוהב כדורגל. אנחנו הולכים ביחד לפארק כל יום. לפעמים אנחנו אוכלים ביחד. אמא של יוסי מכינה עוגיות טעימות. אנחנו גם אוהבים לראות סרטים ולשחק משחקי מחשב. יוסי חבר נאמן וטוב. אני שמח שיש לי חבר כזה.', 'У меня есть хороший друг. Его зовут Йоси. Мы учимся вместе и играем после школы. Йоси живёт рядом с моим домом. Он любит баскетбол, а я люблю футбол. Мы вместе ходим в парк каждый день. Иногда мы едим вместе. Мама Йоси делает вкусное печенье. Мы также любим смотреть фильмы и играть в компьютерные игры. Йоси верный и хороший друг. Я рад, что у меня есть такой друг.', '[{"he": "חבר", "ru": "друг", "translit": "хавЭр"}, {"he": "ביחד", "ru": "вместе", "translit": "бейЯхад"}, {"he": "כדורסל", "ru": "баскетбол", "translit": "кадурсАль"}, {"he": "סרט", "ru": "фильм", "translit": "сЭрет"}, {"he": "משחק", "ru": "игра", "translit": "мисхАк"}, {"he": "עוגיות", "ru": "печенье", "translit": "угийОт"}, {"he": "נאמן", "ru": "верный", "translit": "нээмАн"}, {"he": "לפעמים", "ru": "иногда", "translit": "лифамИм"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (60, 1, 'ברחוב', 'На улице', 'אני הולך ברחוב. יש הרבה מכוניות ואנשים. אני רואה חנות עם צעצועים. ליד החנות יש בית קפה. אנשים יושבים ושותים קפה. ברחוב יש גם עצים גדולים. אני רואה חתול יושב על הגדר. ילדים רוכבים על אופניים. יש רמזור בפינה. כשהאור ירוק אני עובר את הכביש. אני אוהב לטייל ברחובות. תמיד יש מה לראות.', 'Я иду по улице. Есть много машин и людей. Я вижу магазин с игрушками. Возле магазина есть кафе. Люди сидят и пьют кофе. На улице есть также большие деревья. Я вижу кота, сидящего на заборе. Дети катаются на велосипедах. На углу есть светофор. Когда свет зелёный, я перехожу дорогу. Я люблю гулять по улицам. Всегда есть что посмотреть.', '[{"he": "רחוב", "ru": "улица", "translit": "рехОв"}, {"he": "חנות", "ru": "магазин", "translit": "ханУт"}, {"he": "צעצוע", "ru": "игрушка", "translit": "цаацУа"}, {"he": "רמזור", "ru": "светофор", "translit": "рамзОр"}, {"he": "אופניים", "ru": "велосипед", "translit": "офанАйим"}, {"he": "גדר", "ru": "забор", "translit": "гадЭр"}, {"he": "כביש", "ru": "дорога", "translit": "квИш"}, {"he": "פינה", "ru": "угол", "translit": "пинА"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (61, 1, 'מזג אוויר', 'Погода', 'היום חם בחוץ. השמש זורחת. אין עננים בשמיים. אני שם כובע על הראש. אני שותה הרבה מים כי חם. בערב יהיה קריר יותר. אתמול היה רוח חזקה. בחורף יורד גשם ולפעמים יש סערה. אני אוהב את הגשם. אחרי הגשם יש לפעמים קשת בשמיים. זה יפה מאוד. כל יום אני שומע את תחזית מזג האוויר ברדיו.', 'Сегодня жарко на улице. Солнце светит. Нет облаков на небе. Я надеваю шапку на голову. Я пью много воды, потому что жарко. Вечером будет прохладнее. Вчера был сильный ветер. Зимой идёт дождь и иногда бывает буря. Я люблю дождь. После дождя иногда появляется радуга на небе. Это очень красиво. Каждый день я слушаю прогноз погоды по радио.', '[{"he": "שמש", "ru": "солнце", "translit": "шЭмеш"}, {"he": "ענן", "ru": "облако", "translit": "анАн"}, {"he": "כובע", "ru": "шапка/шляпа", "translit": "ковА"}, {"he": "רוח", "ru": "ветер", "translit": "рУах"}, {"he": "סערה", "ru": "буря", "translit": "сеарА"}, {"he": "קשת", "ru": "радуга", "translit": "кЭшет"}, {"he": "תחזית", "ru": "прогноз", "translit": "тахазИт"}, {"he": "קריר", "ru": "прохладно", "translit": "карИр"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (62, 1, 'הגינה שלנו', 'Наш сад', 'לבית שלנו יש גינה. בגינה יש עצים ופרחים. אמא שותלת ירקות. יש עגבניות, מלפפונים וחסה. אנחנו משקים את הגינה כל יום. אבא גוזם את העצים בסתיו. יש לנו עץ לימון וגם עץ תפוזים. בגינה יש פרפרים יפים. אני עוזר לאמא לשתול פרחים חדשים. בערב אנחנו יושבים בגינה ומדברים. הגינה שלנו מקום ירוק ויפה.', 'У нашего дома есть сад. В саду есть деревья и цветы. Мама сажает овощи. Есть помидоры, огурцы и салат. Мы поливаем сад каждый день. Папа подрезает деревья осенью. У нас есть лимонное дерево и апельсиновое дерево. В саду есть красивые бабочки. Я помогаю маме сажать новые цветы. Вечером мы сидим в саду и разговариваем. Наш сад — зелёное и красивое место.', '[{"he": "גינה", "ru": "сад", "translit": "гинА"}, {"he": "לשתול", "ru": "сажать", "translit": "лиштОль"}, {"he": "להשקות", "ru": "поливать", "translit": "леhашкОт"}, {"he": "עץ", "ru": "дерево", "translit": "эц"}, {"he": "פרפר", "ru": "бабочка", "translit": "парпАр"}, {"he": "לימון", "ru": "лимон", "translit": "лимОн"}, {"he": "מלפפון", "ru": "огурец", "translit": "мелафефОн"}, {"he": "חסה", "ru": "салат (латук)", "translit": "хасА"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (63, 2, 'החופשה שלי', 'Мой отпуск', 'בקיץ שעבר נסעתי עם המשפחה לאילת. טסנו במטוס ושהינו במלון ליד הים. המלון היה גדול ויפה, עם בריכה ומסעדה. כל יום שחינו בבריכה ובים. המים היו חמים וצלולים. הילדים בנו ארמון חול על החוף ושיחקו כל היום. בערב אכלנו במסעדות שונות וטעמנו אוכל מיוחד. יום אחד עשינו טיול במדבר וראינו נוף יפה מאוד. גם ביקרנו באקווריום וראינו דגים צבעוניים. בלילה האחרון הלכנו לטיילת וקנינו מתנות למשפחה. זו היתה חופשה נהדרת ואנחנו רוצים לחזור שוב בקיץ הבא.', 'Прошлым летом я поехал с семьёй в Эйлат. Мы летели на самолёте и жили в отеле у моря. Отель был большой и красивый, с бассейном и рестораном. Каждый день мы плавали в бассейне и в море. Вода была тёплой и прозрачной. Дети строили замок из песка на пляже и играли целый день. Вечером мы ели в разных ресторанах и пробовали особую еду. Один день мы совершили поездку по пустыне и увидели очень красивый пейзаж. Также мы посетили аквариум и увидели цветных рыб. В последний вечер мы гуляли по набережной и купили подарки для семьи. Это был замечательный отпуск, и мы хотим вернуться снова следующим летом.', '[{"he": "חופשה", "ru": "отпуск", "translit": "хуфшА"}, {"he": "מלון", "ru": "отель", "translit": "малОн"}, {"he": "בריכה", "ru": "бассейн", "translit": "брехА"}, {"he": "חוף", "ru": "пляж", "translit": "хОф"}, {"he": "מדבר", "ru": "пустыня", "translit": "мидбАр"}, {"he": "טיול", "ru": "поездка, экскурсия", "translit": "тиЮль"}, {"he": "מתנה", "ru": "подарок", "translit": "матанА"}, {"he": "נוף", "ru": "пейзаж", "translit": "нОф"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (64, 2, 'הדירה החדשה', 'Новая квартира', 'עברנו לדירה חדשה בתל אביב. הדירה גדולה ויפה. יש שלושה חדרים, מטבח ומרפסת. מהמרפסת אפשר לראות את הרחוב ועצים ירוקים. המטבח חדש ויש בו תנור ומקרר גדול. השכנים נחמדים מאוד, הם באו לברך אותנו ביום הראשון. אנחנו עדיין מסדרים את הרהיטים. שמנו את הספה בסלון ואת השולחן במטבח. הילדים בחרו צבע לחדר שלהם, הם רצו כחול. גם קנינו מדפים חדשים לספרים. בערב ישבנו על המרפסת ושתינו קפה. הדירה קרובה לעבודה ולגן של הילדים. אנחנו מאוד שמחים בבית החדש.', 'Мы переехали в новую квартиру в Тель-Авиве. Квартира большая и красивая. Есть три комнаты, кухня и балкон. С балкона можно увидеть улицу и зелёные деревья. Кухня новая, в ней есть духовка и большой холодильник. Соседи очень приятные, они пришли поздравить нас в первый день. Мы ещё расставляем мебель. Мы поставили диван в гостиной и стол на кухне. Дети выбрали цвет для своей комнаты — они хотели голубой. Также мы купили новые полки для книг. Вечером мы сидели на балконе и пили кофе. Квартира близко к работе и к детскому саду. Мы очень рады новому дому.', '[{"he": "דירה", "ru": "квартира", "translit": "дирА"}, {"he": "מרפסת", "ru": "балкон", "translit": "мирпЕсет"}, {"he": "רהיטים", "ru": "мебель", "translit": "раhитИм"}, {"he": "שכנים", "ru": "соседи", "translit": "шхенИм"}, {"he": "מטבח", "ru": "кухня", "translit": "митбАх"}, {"he": "סלון", "ru": "гостиная", "translit": "салОн"}, {"he": "מדפים", "ru": "полки", "translit": "мадафИм"}, {"he": "תנור", "ru": "духовка", "translit": "танУр"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (65, 2, 'ראיון עבודה', 'Собеседование', 'אתמול הלכתי לראיון עבודה. הגעתי למשרד בזמן ולבשתי בגדים יפים. המנהלת שאלה אותי שאלות על הניסיון שלי ועל הלימודים. סיפרתי לה על העבודות הקודמות שלי ומה עשיתי שם. היא שאלה למה אני רוצה לעבוד בחברה הזאת, ואמרתי שזה תחום מעניין ושאני רוצה ללמוד דברים חדשים. הראיון נמשך ארבעים דקות. המנהלת היתה נחמדה ונתנה לי לשאול שאלות. שאלתי על שעות העבודה ועל השכר. היא אמרה שהם יתקשרו אליי בעוד שבוע. יצאתי מהמשרד והרגשתי שהראיון עבר טוב. אני מקווה שאקבל את העבודה.', 'Вчера я пошёл на собеседование. Я пришёл в офис вовремя и надел красивую одежду. Менеджер задавала мне вопросы о моём опыте и учёбе. Я рассказал ей о предыдущих работах и о том, что я там делал. Она спросила, почему я хочу работать в этой компании, и я сказал, что это интересная сфера и что я хочу учиться новому. Собеседование длилось сорок минут. Менеджер была приятной и дала мне возможность задать вопросы. Я спросил о рабочих часах и о зарплате. Она сказала, что они позвонят мне через неделю. Я вышел из офиса и почувствовал, что собеседование прошло хорошо. Надеюсь, что получу эту работу.', '[{"he": "ראיון", "ru": "собеседование", "translit": "реайОн"}, {"he": "ניסיון", "ru": "опыт", "translit": "нисайОн"}, {"he": "מנהלת", "ru": "менеджер (ж.)", "translit": "менаhЕлет"}, {"he": "שכר", "ru": "зарплата", "translit": "сахАр"}, {"he": "תחום", "ru": "сфера, область", "translit": "тхУм"}, {"he": "משרד", "ru": "офис", "translit": "мисрАд"}, {"he": "לימודים", "ru": "учёба", "translit": "лимудИм"}, {"he": "חברה", "ru": "компания", "translit": "хеврА"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (66, 2, 'בישול ביתי', 'Домашняя готовка', 'אני אוהב לבשל. היום הכנתי עוף עם ירקות. קודם קניתי ירקות טריים בשוק. בשוק היו הרבה אנשים והמוכרים צעקו על המחירים. חתכתי בצל, גזר ותפוחי אדמה לחתיכות קטנות. הוספתי מלח, פלפל ושמן זית. שמתי הכול בתנור ואחרי שעה האוכל היה מוכן. הריח בבית היה נהדר. כל המשפחה ישבה ליד השולחן ואכלנו ביחד. כולם אמרו שהאוכל טעים מאוד. הילדים ביקשו עוד. אחרי הארוחה שטפתי את הכלים ונחתי קצת. בישול ביתי יותר טעים ויותר בריא מאוכל מהמסעדה.', 'Я люблю готовить. Сегодня я приготовил курицу с овощами. Сначала я купил свежие овощи на рынке. На рынке было много людей, и продавцы кричали о ценах. Я нарезал лук, морковь и картошку на маленькие кусочки. Добавил соль, перец и оливковое масло. Положил всё в духовку, и через час еда была готова. Запах в доме был замечательный. Вся семья села за стол, и мы ели вместе. Все сказали, что еда очень вкусная. Дети попросили ещё. После еды я помыл посуду и немного отдохнул. Домашняя готовка вкуснее и полезнее еды из ресторана.', '[{"he": "בישול", "ru": "готовка", "translit": "бишУль"}, {"he": "ירקות", "ru": "овощи", "translit": "йеракОт"}, {"he": "תנור", "ru": "духовка", "translit": "танУр"}, {"he": "שוק", "ru": "рынок", "translit": "шУк"}, {"he": "מלח", "ru": "соль", "translit": "мЕлах"}, {"he": "שמן זית", "ru": "оливковое масло", "translit": "шЕмен зАйит"}, {"he": "כלים", "ru": "посуда", "translit": "келИм"}, {"he": "ארוחה", "ru": "еда, трапеза", "translit": "арухА"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (67, 2, 'ספורט וכושר', 'Спорт и фитнес', 'אני מתאמן שלוש פעמים בשבוע. הולך לחדר כושר ליד הבית. גם רץ בפארק בבקרים כשמזג האוויר נעים. ספורט חשוב לבריאות ולמצב הרוח. אחרי אימון אני מרגיש מלא אנרגיה ושמח. בחדר הכושר אני מרים משקולות ורץ על מסלול. יש שם גם מדריך שעוזר לי עם התרגילים. בשבוע שעבר התחלתי גם לשחות בבריכה. השחייה טובה לגב וליציבה. חבר שלי מתאמן איתי פעמיים בשבוע, וזה יותר כיף ביחד. אחרי האימון אנחנו שותים מים ואוכלים פרי. אני מרגיש שהספורט עוזר לי גם בעבודה ובשינה.', 'Я тренируюсь три раза в неделю. Хожу в спортзал рядом с домом. Также бегаю в парке по утрам, когда погода приятная. Спорт важен для здоровья и для настроения. После тренировки я чувствую себя полным энергии и радостным. В спортзале я поднимаю гантели и бегаю по дорожке. Там есть также инструктор, который помогает мне с упражнениями. На прошлой неделе я начал также плавать в бассейне. Плавание полезно для спины и осанки. Мой друг тренируется со мной дважды в неделю, и вместе веселее. После тренировки мы пьём воду и едим фрукты. Я чувствую, что спорт помогает мне также на работе и со сном.', '[{"he": "אימון", "ru": "тренировка", "translit": "имУн"}, {"he": "כושר", "ru": "фитнес", "translit": "кОшер"}, {"he": "בריאות", "ru": "здоровье", "translit": "бриУт"}, {"he": "משקולות", "ru": "гантели", "translit": "мишколОт"}, {"he": "מדריך", "ru": "инструктор", "translit": "мадрИх"}, {"he": "שחייה", "ru": "плавание", "translit": "схийА"}, {"he": "אנרגיה", "ru": "энергия", "translit": "энЕргия"}, {"he": "תרגיל", "ru": "упражнение", "translit": "таргИль"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (68, 2, 'ביקור במוזיאון', 'Поход в музей', 'ביום שישי ביקרנו במוזיאון ישראל בירושלים. הגענו בבוקר ועמדנו בתור קצר לכרטיסים. ראינו אוספים של אמנות עתיקה ומודרנית. היו שם ציורים יפים ופסלים מעניינים. הילדים התרגשו מאוד מהתערוכה של ממצאים ארכיאולוגיים. הם שאלו הרבה שאלות ורצו לדעת הכול. אחרי שעתיים הלכנו למסעדה של המוזיאון ואכלנו ארוחת צהריים. קנינו מזכרות בחנות של המוזיאון, כמו גלויות וספרים. בדרך הביתה הילדים דיברו על מה שראו. הם אמרו שרוצים לחזור שוב. ביקור במוזיאון זו דרך טובה ללמוד ולהנות.', 'В пятницу мы побывали в Музее Израиля в Иерусалиме. Мы приехали утром и стояли в короткой очереди за билетами. Мы видели коллекции древнего и современного искусства. Там были красивые картины и интересные скульптуры. Дети были в восторге от выставки археологических находок. Они задавали много вопросов и хотели знать всё. Через два часа мы пошли в ресторан музея и пообедали. Мы купили сувениры в магазине музея — открытки и книги. По дороге домой дети обсуждали увиденное. Они сказали, что хотят вернуться снова. Поход в музей — это хороший способ учиться и наслаждаться.', '[{"he": "מוזיאון", "ru": "музей", "translit": "музеОн"}, {"he": "תערוכה", "ru": "выставка", "translit": "таарухА"}, {"he": "אמנות", "ru": "искусство", "translit": "оманУт"}, {"he": "ציור", "ru": "картина", "translit": "циЮр"}, {"he": "פסל", "ru": "скульптура", "translit": "пЕсель"}, {"he": "מזכרת", "ru": "сувенир", "translit": "мазкЕрет"}, {"he": "כרטיס", "ru": "билет", "translit": "картИс"}, {"he": "אוסף", "ru": "коллекция", "translit": "Осеф"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (69, 2, 'יום גשום', 'Дождливый день', 'היום ירד גשם חזק מהבוקר. לקחתי מטריה ומעיל גשם לפני שיצאתי מהבית. ברחוב היו שלוליות מים גדולות. מכוניות נסעו לאט כי הכביש היה רטוב וחלקלק. אנשים רצו מהגשם ונכנסו לחנויות. ישבתי בבית קפה חם ושתיתי שוקו חם עם עוגה. מבחוץ ראיתי ילדים שקפצו בשלוליות וצחקו. הגשם לא הפסיק כל היום. בערב חזרתי הביתה רטוב קצת. החלפתי בגדים, הכנתי מרק חם וישבתי ליד החלון. שמעתי את הגשם על הגג. היום הגשום היה נעים בסוף, כי בבית היה חם ושקט.', 'Сегодня с утра шёл сильный дождь. Я взял зонт и дождевик перед тем, как вышел из дома. На улице были большие лужи. Машины ехали медленно, потому что дорога была мокрой и скользкой. Люди бежали от дождя и заходили в магазины. Я сел в тёплое кафе и выпил горячий шоколад с пирожным. Снаружи я видел детей, которые прыгали по лужам и смеялись. Дождь не прекращался весь день. Вечером я вернулся домой немного мокрый. Я переоделся, приготовил горячий суп и сел у окна. Я слышал дождь на крыше. Дождливый день оказался приятным в конце концов, потому что дома было тепло и тихо.', '[{"he": "גשם", "ru": "дождь", "translit": "гЕшем"}, {"he": "מטריה", "ru": "зонт", "translit": "митрийА"}, {"he": "שלולית", "ru": "лужа", "translit": "шлулИт"}, {"he": "מעיל", "ru": "пальто, куртка", "translit": "меИль"}, {"he": "רטוב", "ru": "мокрый", "translit": "ратОв"}, {"he": "חלון", "ru": "окно", "translit": "халОн"}, {"he": "מרק", "ru": "суп", "translit": "марАк"}, {"he": "גג", "ru": "крыша", "translit": "гАг"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (70, 2, 'חתונה', 'Свадьба', 'היינו בחתונה של חברה טובה שלנו. הטקס היה בגן אירועים יפה מחוץ לעיר. הכלה לבשה שמלה לבנה ארוכה ונראתה מדהימה. החתן חיכה לה מתחת לחופה עם חיוך גדול. הרב בירך אותם והם שברו כוס. כל האורחים צעקו מזל טוב. אחרי הטקס התחיל המסיבה. הם רקדו ושרו כל הלילה. הלהקה ניגנה שירים שמחים. האוכל היה מעולה, עם הרבה סוגים של בשר ודגים וסלטים. שמחנו איתם ורקדנו עד מאוחר. בסוף הערב נתנו להם מתנה וחיבקנו אותם. זו היתה חתונה יפה שלא נשכח.', 'Мы были на свадьбе нашей хорошей подруги. Церемония проходила в красивом банкетном зале за городом. Невеста была в длинном белом платье и выглядела потрясающе. Жених ждал её под хупой с широкой улыбкой. Раввин благословил их, и они разбили бокал. Все гости закричали «мазаль тов». После церемонии началась вечеринка. Они танцевали и пели всю ночь. Группа играла весёлые песни. Еда была отличная — много видов мяса, рыбы и салатов. Мы радовались с ними и танцевали до поздна. В конце вечера мы подарили им подарок и обняли их. Это была красивая свадьба, которую мы не забудем.', '[{"he": "חתונה", "ru": "свадьба", "translit": "хатунА"}, {"he": "כלה", "ru": "невеста", "translit": "калА"}, {"he": "חתן", "ru": "жених", "translit": "хатАн"}, {"he": "חופה", "ru": "хупа (свадебный балдахин)", "translit": "хупА"}, {"he": "אורחים", "ru": "гости", "translit": "орхИм"}, {"he": "להקה", "ru": "группа, ансамбль", "translit": "лаhакА"}, {"he": "מתנה", "ru": "подарок", "translit": "матанА"}, {"he": "טקס", "ru": "церемония", "translit": "тЕкес"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (71, 2, 'בקניון', 'В торговом центре', 'הלכנו לקניון ביום שישי אחרי הצהריים. הקניון היה מלא אנשים כי זה סוף שבוע. קניתי חולצה חדשה ונעליים בחנות גדולה. מצאתי מבצע טוב ושילמתי פחות ממה שחשבתי. אשתי בחרה תיק חום יפה מעור. הילדים רצו לחנות צעצועים ובחרו משחק לוח. אחרי הקניות עלינו לקומה השלישית ואכלנו ביחד. הילדים אכלו פיצה ואנחנו אכלנו סושי. אחרי האוכל הילדים שיחקו בפינת המשחקים. לפני שעזבנו קנינו גלידה. חזרנו הביתה עייפים אבל מרוצים, עם הרבה שקיות מלאות קניות חדשות.', 'В пятницу после обеда мы пошли в торговый центр. Было полно людей, потому что выходные. Я купил новую рубашку и обувь в большом магазине. Нашёл хорошую скидку и заплатил меньше, чем думал. Жена выбрала красивую коричневую кожаную сумку. Дети побежали в магазин игрушек и выбрали настольную игру. После покупок мы поднялись на третий этаж и поели вместе. Дети ели пиццу, а мы ели суши. После еды дети играли в игровом уголке. Перед уходом мы купили мороженое. Мы вернулись домой уставшие, но довольные, с множеством пакетов, полных новых покупок.', '[{"he": "קניון", "ru": "торговый центр", "translit": "каньОн"}, {"he": "מבצע", "ru": "скидка, акция", "translit": "мивцА"}, {"he": "נעליים", "ru": "обувь", "translit": "наалАйим"}, {"he": "צעצועים", "ru": "игрушки", "translit": "цаацуИм"}, {"he": "קומה", "ru": "этаж", "translit": "комА"}, {"he": "גלידה", "ru": "мороженое", "translit": "глидА"}, {"he": "שקית", "ru": "пакет", "translit": "сакИт"}, {"he": "חנות", "ru": "магазин", "translit": "ханУт"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (72, 2, 'נהיגה בישראל', 'Вождение в Израиле', 'קיבלתי רישיון נהיגה לפני חודש אחרי שלמדתי חצי שנה. נהגתי לראשונה לבד בכביש והיה מרגש. בהתחלה היה קשה כי פחדתי ממכוניות גדולות, אבל עכשיו אני מרגיש בטוח יותר. הכבישים בישראל עמוסים, בעיקר בבוקר ובערב. צריך להיות סבלני ולא לנסוע מהר. למדתי שחשוב לשמור מרחק מהמכונית שלפניי. גם חניה בעיר קשה, לפעמים מחפשים מקום עשר דקות. שבוע שעבר נסעתי לראשונה בכביש מהיר מתל אביב לחיפה. הנסיעה לקחה שעה וחצי. כשהגעתי הרגשתי גאה. כל יום אני נוהג יותר טוב ומרגיש יותר בטוח על הכביש.', 'Я получил водительские права месяц назад после полугода учёбы. Впервые я ехал один по дороге, и это было волнительно. Сначала было тяжело, потому что я боялся больших машин, но теперь я чувствую себя увереннее. Дороги в Израиле загруженные, особенно утром и вечером. Нужно быть терпеливым и не ехать быстро. Я понял, что важно держать дистанцию от машины впереди. Парковка в городе тоже сложная — иногда ищешь место десять минут. На прошлой неделе я впервые ехал по скоростному шоссе из Тель-Авива в Хайфу. Поездка заняла полтора часа. Когда я приехал, я почувствовал гордость. Каждый день я вожу лучше и чувствую себя увереннее на дороге.', '[{"he": "רישיון", "ru": "права, лицензия", "translit": "ришайОн"}, {"he": "נהיגה", "ru": "вождение", "translit": "неhигА"}, {"he": "כביש", "ru": "дорога, шоссе", "translit": "квИш"}, {"he": "חניה", "ru": "парковка", "translit": "ханайА"}, {"he": "סבלני", "ru": "терпеливый", "translit": "савланИ"}, {"he": "מהירות", "ru": "скорость", "translit": "меhирУт"}, {"he": "מרחק", "ru": "расстояние", "translit": "мерхАк"}, {"he": "עמוס", "ru": "загруженный", "translit": "амУс"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (73, 2, 'בגינה', 'В саду', 'אני מטפל בגינה שלי כל יום. שתלתי עגבניות ומלפפונים בתחילת האביב. גם שתלתי פלפלים ועשבי תיבול כמו נענע ובזיליקום. כל בוקר אני משקה את הצמחים לפני שאני הולך לעבודה. אחרי שבועיים ראיתי פרחים קטנים על העגבניות והתרגשתי. בעוד חודש יהיו ירקות טריים מהגינה שלי. השכנה שלי גם מגדלת ירקות ואנחנו מחליפים ביניינו. היא נותנת לי חסה ואני נותן לה עגבניות. לטפל בגינה זה שקט ונעים. אני אוהב לשבת בגינה בערב ולהסתכל על הצמחים שגדלים. זה מרגיע אחרי יום עבודה.', 'Я ухаживаю за своим садом каждый день. Я посадил помидоры и огурцы в начале весны. Также посадил перцы и пряные травы, такие как мята и базилик. Каждое утро я поливаю растения перед тем, как иду на работу. Через две недели я увидел маленькие цветочки на помидорах и обрадовался. Через месяц будут свежие овощи из моего сада. Моя соседка тоже выращивает овощи, и мы обмениваемся. Она даёт мне салат, а я даю ей помидоры. Ухаживать за садом — это тихо и приятно. Я люблю сидеть в саду вечером и смотреть на растения, которые растут. Это успокаивает после рабочего дня.', '[{"he": "גינה", "ru": "сад", "translit": "гинА"}, {"he": "צמח", "ru": "растение", "translit": "цЕмах"}, {"he": "שתילה", "ru": "посадка", "translit": "штилА"}, {"he": "השקיה", "ru": "полив", "translit": "ашкайА"}, {"he": "עגבניה", "ru": "помидор", "translit": "агванийА"}, {"he": "מלפפון", "ru": "огурец", "translit": "мелафефОн"}, {"he": "עשבי תיבול", "ru": "пряные травы", "translit": "исвЕй тибУль"}, {"he": "פרח", "ru": "цветок", "translit": "пЕрах"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (74, 2, 'בקולנוע', 'В кинотеатре', 'ביום חמישי הלכנו לקולנוע עם חברים. בחרנו סרט קומדיה ישראלי חדש. קנינו כרטיסים באינטרנט כדי שלא נצטרך לעמוד בתור. קנינו פופקורן גדול ושתייה קרה בכניסה. האולם היה כמעט מלא ומצאנו מקומות טובים באמצע. הסרט היה מצחיק מאוד וצחקנו כל הזמן. השחקנים היו מוכרים מטלוויזיה. הסרט סיפר על משפחה ישראלית מצחיקה שנסעה לחופשה בחוץ לארץ. אחרי הסרט דיברנו עליו בבית קפה ליד הקולנוע. כולם אמרו שנהנו מאוד. קבענו ללכת שוב לקולנוע בשבוע הבא לראות סרט אחר.', 'В четверг мы пошли в кино с друзьями. Мы выбрали новую израильскую комедию. Купили билеты онлайн, чтобы не стоять в очереди. Мы купили большой попкорн и холодные напитки при входе. Зал был почти полный, и мы нашли хорошие места посередине. Фильм был очень смешной, и мы смеялись всё время. Актёры были знакомые по телевидению. Фильм рассказывал о забавной израильской семье, которая поехала в отпуск за границу. После фильма мы обсуждали его в кафе рядом с кинотеатром. Все сказали, что получили большое удовольствие. Мы договорились пойти в кино снова на следующей неделе, чтобы посмотреть другой фильм.', '[{"he": "קולנוע", "ru": "кинотеатр", "translit": "колнОа"}, {"he": "סרט", "ru": "фильм", "translit": "сЕрет"}, {"he": "קומדיה", "ru": "комедия", "translit": "комЕдия"}, {"he": "שחקן", "ru": "актёр", "translit": "сахкАн"}, {"he": "פופקורן", "ru": "попкорн", "translit": "попкОрн"}, {"he": "אולם", "ru": "зал", "translit": "улАм"}, {"he": "כרטיס", "ru": "билет", "translit": "картИс"}, {"he": "מצחיק", "ru": "смешной", "translit": "мацхИк"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (75, 2, 'בבנק', 'В банке', 'הלכתי לבנק לפתוח חשבון חדש. הגעתי בבוקר ולקחתי מספר בתור. חיכיתי עשרים דקות עד שקראו לי. הפקידה היתה נחמדה והסבירה לי על סוגי החשבונות השונים. בחרתי חשבון עם כרטיס אשראי כי זה הכי נוח. מילאתי טפסים רבים ונתתי תעודת זהות ואישור מהעבודה. הפקידה הראתה לי איך להשתמש באפליקציה של הבנק בטלפון. עכשיו אני יכול לראות את היתרה ולשלם חשבונות מהבית. גם פתחתי תוכנית חיסכון קטנה לכל חודש. יצאתי מהבנק עם כרטיס חדש והרגשתי מסודר. עכשיו כל הכסף שלי במקום בטוח.', 'Я пошёл в банк открыть новый счёт. Я пришёл утром и взял номерок в очереди. Ждал двадцать минут, пока меня вызвали. Кассирша была приятной и объяснила мне о разных видах счетов. Я выбрал счёт с кредитной картой, потому что это самое удобное. Я заполнил много форм и дал удостоверение личности и справку с работы. Кассирша показала мне, как пользоваться банковским приложением на телефоне. Теперь я могу видеть остаток и оплачивать счета из дома. Также я открыл небольшой накопительный план на каждый месяц. Я вышел из банка с новой картой и почувствовал себя организованным. Теперь все мои деньги в надёжном месте.', '[{"he": "בנק", "ru": "банк", "translit": "бАнк"}, {"he": "חשבון", "ru": "счёт", "translit": "хешбОн"}, {"he": "פקידה", "ru": "кассирша, служащая", "translit": "пкидА"}, {"he": "כרטיס אשראי", "ru": "кредитная карта", "translit": "картИс ашрАй"}, {"he": "טופס", "ru": "бланк, форма", "translit": "тОфес"}, {"he": "תעודת זהות", "ru": "удостоверение личности", "translit": "теудАт зеhУт"}, {"he": "חיסכון", "ru": "сбережения", "translit": "хисахОн"}, {"he": "יתרה", "ru": "остаток (на счету)", "translit": "итрА"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (76, 2, 'בדואר', 'На почте', 'שלחתי חבילה לחברה שגרה בחוץ לארץ. הכנתי קופסה ושמתי בתוכה מתנה ומכתב קצר. הלכתי לסניף הדואר הקרוב לבית. עמדתי בתור עשר דקות כי היו כמה אנשים לפניי. הפקיד שקל את החבילה ואמר שהיא שוקלת קילו וחצי. שילמתי שישים שקלים על המשלוח. הוא שאל אם אני רוצה ביטוח על החבילה ואמרתי כן. מילאתי טופס עם הכתובת בחוץ לארץ. הפקיד נתן לי מספר מעקב כדי לבדוק איפה החבילה. החבילה תגיע בעוד שבוע עד עשרה ימים. קיבלתי קבלה ויצאתי. אני מקווה שהחברה שלי תשמח מהמתנה.', 'Я отправил посылку подруге, которая живёт за границей. Я подготовил коробку и положил в неё подарок и короткое письмо. Я пошёл в ближайшее к дому почтовое отделение. Я стоял в очереди десять минут, потому что передо мной было несколько человек. Служащий взвесил посылку и сказал, что она весит полтора килограмма. Я заплатил шестьдесят шекелей за пересылку. Он спросил, хочу ли я застраховать посылку, и я сказал да. Я заполнил бланк с адресом за границей. Служащий дал мне номер отслеживания, чтобы проверить, где посылка. Посылка прибудет через неделю или десять дней. Я получил квитанцию и вышел. Надеюсь, что подруга обрадуется подарку.', '[{"he": "דואר", "ru": "почта", "translit": "доАр"}, {"he": "חבילה", "ru": "посылка", "translit": "хавилА"}, {"he": "משלוח", "ru": "пересылка, доставка", "translit": "мишлОах"}, {"he": "פקיד", "ru": "служащий", "translit": "пакИд"}, {"he": "מכתב", "ru": "письмо", "translit": "михтАв"}, {"he": "כתובת", "ru": "адрес", "translit": "ктОвет"}, {"he": "ביטוח", "ru": "страховка", "translit": "битУах"}, {"he": "קבלה", "ru": "квитанция", "translit": "каблА"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (77, 2, 'הופעה', 'Концерт', 'הלכנו להופעה של זמר ישראלי מפורסם בתל אביב. קנינו כרטיסים חודש לפני כי ההופעה היתה פופולרית. האולם היה מלא ובחוץ חיכו עוד אנשים. הוא עלה לבמה בשמונה בערב והקהל מחא כפיים. הוא שר את כל השירים הידועים שלו ואנחנו שרנו איתו כל מילה. הוא גם ניגן על גיטרה ופסנתר. הקהל רקד ושר איתו כל הערב. באמצע ההופעה הוא סיפר סיפורים מצחיקים על החיים שלו. ההופעה נמשכה שעתיים ובסוף הוא חזר לבמה לשיר עוד שיר. היה מדהים. חזרנו הביתה ועדיין שרנו את השירים שלו במכונית.', 'Мы пошли на концерт знаменитого израильского певца в Тель-Авиве. Мы купили билеты за месяц, потому что концерт был популярный. Зал был полный, а на улице ждали ещё люди. Он вышел на сцену в восемь вечера, и публика захлопала. Он пел все свои известные песни, и мы подпевали каждое слово. Он также играл на гитаре и пианино. Публика танцевала и пела с ним весь вечер. В середине концерта он рассказал смешные истории из своей жизни. Концерт длился два часа, а в конце он вернулся на сцену, чтобы спеть ещё одну песню. Было потрясающе. Мы вернулись домой и всё ещё пели его песни в машине.', '[{"he": "הופעה", "ru": "концерт, выступление", "translit": "hофаА"}, {"he": "זמר", "ru": "певец", "translit": "замАр"}, {"he": "במה", "ru": "сцена", "translit": "бамА"}, {"he": "קהל", "ru": "публика", "translit": "каhАль"}, {"he": "שיר", "ru": "песня", "translit": "шИр"}, {"he": "גיטרה", "ru": "гитара", "translit": "гитАра"}, {"he": "פסנתר", "ru": "пианино", "translit": "псантЕр"}, {"he": "מפורסם", "ru": "знаменитый", "translit": "мефурсАм"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (78, 2, 'קמפינג', 'Кемпинг', 'בסוף שבוע נסענו לקמפינג בגליל עם חברים. הנסיעה מתל אביב לקחה שעתיים. הגענו למקום יפה ליד נחל וירוק. הקמנו אוהל גדול בין עצים ושמנו שקי שינה בפנים. בישלנו על מדורה ואכלנו בחוץ. האוכל מהמדורה טעים במיוחד. בלילה ישבנו סביב האש, שתינו תה ושרנו שירים. ראינו כוכבים רבים בשמיים, כי לא היה אור של עיר. בבוקר טיילנו בשביל ליד הנחל וראינו ציפורים ופרחים. המים בנחל היו קרים אבל כמה מאיתנו נכנסו למים. חזרנו הביתה עייפים אבל שמחים. קמפינג בטבע זה חופשה מעולה.', 'В выходные мы поехали в кемпинг в Галилее с друзьями. Дорога из Тель-Авива заняла два часа. Мы приехали на красивое зелёное место у ручья. Мы поставили большую палатку среди деревьев и положили внутрь спальные мешки. Мы готовили на костре и ели на улице. Еда с костра особенно вкусная. Вечером мы сидели вокруг огня, пили чай и пели песни. Мы видели много звёзд на небе, потому что не было городского света. Утром мы гуляли по тропинке у ручья и видели птиц и цветы. Вода в ручье была холодной, но некоторые из нас зашли в воду. Мы вернулись домой уставшие, но счастливые. Кемпинг на природе — отличный отдых.', '[{"he": "קמפינג", "ru": "кемпинг", "translit": "кЕмпинг"}, {"he": "אוהל", "ru": "палатка", "translit": "Оhель"}, {"he": "מדורה", "ru": "костёр", "translit": "медурА"}, {"he": "נחל", "ru": "ручей", "translit": "нАхаль"}, {"he": "כוכבים", "ru": "звёзды", "translit": "кохавИм"}, {"he": "שביל", "ru": "тропинка", "translit": "швИль"}, {"he": "שק שינה", "ru": "спальный мешок", "translit": "сАк шенА"}, {"he": "טבע", "ru": "природа", "translit": "тЕва"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (79, 2, 'בשדה התעופה', 'В аэропорту', 'הגענו לשדה התעופה שלוש שעות לפני הטיסה כמו שצריך. שדה התעופה היה מלא אנשים כי זה היה חופשת קיץ. עברנו ביקורת ביטחון ושאלו אותנו שאלות. הראינו דרכון וכרטיס טיסה. המזוודות נשלחו דרך הסרט ועלינו לקומה השנייה. חיכינו באולם ההמתנה שעה וחצי. הילדים שיחקו במגרש המשחקים הקטן, ואנחנו קראנו ספר. קנינו קפה ועוגה בחנות בשדה התעופה. כשהכריזו על הטיסה שלנו עמדנו בתור ועלינו למטוס. מצאנו את המקומות שלנו, שמנו את התיקים למעלה והתיישבנו. הטיסה יצאה בזמן.', 'Мы приехали в аэропорт за три часа до рейса, как положено. Аэропорт был полон людей, потому что были летние каникулы. Мы прошли проверку безопасности, нам задали вопросы. Мы показали паспорт и посадочный талон. Чемоданы были отправлены по ленте, и мы поднялись на второй этаж. Мы ждали в зале ожидания полтора часа. Дети играли на маленькой детской площадке, а мы читали книгу. Мы купили кофе и пирожное в магазине аэропорта. Когда объявили наш рейс, мы встали в очередь и поднялись в самолёт. Мы нашли свои места, положили сумки наверх и сели. Рейс вылетел вовремя.', '[{"he": "שדה תעופה", "ru": "аэропорт", "translit": "сдЕ теуфА"}, {"he": "טיסה", "ru": "рейс, полёт", "translit": "тисА"}, {"he": "דרכון", "ru": "паспорт", "translit": "даркОн"}, {"he": "מזוודה", "ru": "чемодан", "translit": "мизвадА"}, {"he": "ביקורת ביטחון", "ru": "проверка безопасности", "translit": "бикОрет битахОн"}, {"he": "אולם המתנה", "ru": "зал ожидания", "translit": "улАм hамтанА"}, {"he": "מטוס", "ru": "самолёт", "translit": "матОс"}, {"he": "כרטיס טיסה", "ru": "посадочный талон", "translit": "картИс тисА"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (80, 2, 'השכונה שלנו', 'Наш район', 'אנחנו גרים בשכונה שקטה ונעימה בצפון העיר. יש פארק קטן עם עצים ופרחים ליד הבית. בפארק יש גם מגרש משחקים לילדים ומגרש כדורסל. ליד הבית יש מכולת קטנה ובית מרקחת. גם יש מאפייה שמכינה לחם טרי כל בוקר. השכנים ידידותיים ותמיד אומרים שלום. בערב אנשים יוצאים לטייל עם הכלבים או לשבת על ספסל בפארק. פעם בשבוע יש שוק קטן ברחוב עם ירקות ופירות טריים. השכונה בטוחה, הילדים משחקים בחוץ ואנחנו לא דואגים. אני אוהב את השכונה שלנו כי היא כמו כפר בתוך העיר.', 'Мы живём в тихом и приятном районе на севере города. Рядом с домом есть маленький парк с деревьями и цветами. В парке также есть детская площадка и баскетбольная площадка. Рядом с домом есть продуктовый магазин и аптека. Есть ещё пекарня, которая печёт свежий хлеб каждое утро. Соседи дружелюбные и всегда говорят «шалом». Вечером люди выходят гулять с собаками или сидеть на скамейке в парке. Раз в неделю на улице бывает маленький рынок со свежими овощами и фруктами. Район безопасный, дети играют на улице, и мы не волнуемся. Я люблю наш район, потому что он как деревня внутри города.', '[{"he": "שכונה", "ru": "район", "translit": "шхунА"}, {"he": "מכולת", "ru": "продуктовый магазин", "translit": "маколЕт"}, {"he": "בית מרקחת", "ru": "аптека", "translit": "бЕйт миркАхат"}, {"he": "מאפייה", "ru": "пекарня", "translit": "маафийА"}, {"he": "ספסל", "ru": "скамейка", "translit": "сафсАль"}, {"he": "מגרש", "ru": "площадка", "translit": "мигрАш"}, {"he": "ידידותי", "ru": "дружелюбный", "translit": "йедидутИ"}, {"he": "בטוח", "ru": "безопасный", "translit": "батУах"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (81, 2, 'אבדה ומציאה', 'Потерянная вещь', 'אתמול איבדתי את הארנק שלי באוטובוס ונבהלתי מאוד. בארנק היו כסף, כרטיס אשראי ותעודת זהות. מיד התקשרתי לחברת האוטובוסים וסיפרתי מה קרה. הם אמרו לבדוק במשרד אבדות ומציאות ונתנו לי את הכתובת. נסעתי לשם מהר. בדרך חשבתי שאולי מישהו לקח את הארנק ולא אמצא אותו. הגעתי למשרד ואמרתי לפקיד את מספר הקו ואת השעה. הוא חיפש בארגז ומצא את הארנק שלי. בדקתי שהכול בפנים, הכסף והכרטיסים היו במקום. שמחתי מאוד והודיתי לפקיד. למדתי שתמיד צריך לבדוק את הכיסים לפני שיורדים מהאוטובוס.', 'Вчера я потерял кошелёк в автобусе и очень испугался. В кошельке были деньги, кредитная карта и удостоверение личности. Я сразу позвонил в автобусную компанию и рассказал, что случилось. Мне сказали проверить в бюро находок и дали адрес. Я быстро поехал туда. По дороге я думал, что, может, кто-то забрал кошелёк и я его не найду. Я пришёл в бюро и сказал служащему номер маршрута и время. Он поискал в ящике и нашёл мой кошелёк. Я проверил, что всё на месте — деньги и карточки были внутри. Я очень обрадовался и поблагодарил служащего. Я понял, что нужно всегда проверять карманы, прежде чем выходить из автобуса.', '[{"he": "ארנק", "ru": "кошелёк", "translit": "арнАк"}, {"he": "אבדות ומציאות", "ru": "бюро находок", "translit": "аведОт у-мециОт"}, {"he": "תעודת זהות", "ru": "удостоверение личности", "translit": "теудАт зеhУт"}, {"he": "פקיד", "ru": "служащий", "translit": "пакИд"}, {"he": "אוטובוס", "ru": "автобус", "translit": "отобУс"}, {"he": "כיס", "ru": "карман", "translit": "кИс"}, {"he": "נבהלתי", "ru": "я испугался", "translit": "нивhАльти"}, {"he": "הודיתי", "ru": "я поблагодарил", "translit": "hодЕйти"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (82, 2, 'ראש השנה', 'Новый год', 'ראש השנה הוא חג חשוב בישראל. זה ראש השנה העברי והוא מגיע בסתיו. אנחנו אוכלים תפוח בדבש לשנה מתוקה. גם אוכלים רימון כי יש בו הרבה גרעינים, וזה סמל לדברים טובים. הולכים לבית כנסת ושומעים תקיעת שופר. הקול של השופר חזק ומיוחד. אומרים שנה טובה לכולם, לחברים ולשכנים. בערב יש ארוחה גדולה עם כל המשפחה. סבא וסבתא באים, גם דודים ודודות. אמא מכינה אוכל מיוחד כמו דגים וירקות. אחרי הארוחה שרים שירים ומדברים על השנה החדשה. כולם מקווים לשנה טובה ושמחה.', 'Рош а-Шана — важный праздник в Израиле. Это еврейский Новый год, и он приходится на осень. Мы едим яблоко с мёдом для сладкого года. Также едим гранат, потому что в нём много зёрен, и это символ хороших вещей. Ходим в синагогу и слушаем звуки шофара. Звук шофара сильный и особенный. Говорим «шана това» всем — друзьям и соседям. Вечером устраивается большой ужин со всей семьёй. Приходят дедушка и бабушка, а также дяди и тёти. Мама готовит особую еду, например рыбу и овощи. После ужина поют песни и говорят о новом годе. Все надеются на хороший и счастливый год.', '[{"he": "ראש השנה", "ru": "Новый год", "translit": "рОш hа-шанА"}, {"he": "דבש", "ru": "мёд", "translit": "двАш"}, {"he": "שופר", "ru": "шофар (рог)", "translit": "шофАр"}, {"he": "בית כנסת", "ru": "синагога", "translit": "бЕйт кнЕсет"}, {"he": "רימון", "ru": "гранат", "translit": "римОн"}, {"he": "סמל", "ru": "символ", "translit": "сЕмель"}, {"he": "חג", "ru": "праздник", "translit": "хАг"}, {"he": "ארוחה", "ru": "ужин, трапеза", "translit": "арухА"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (83, 2, 'שיחת טלפון', 'Телефонный разговор', 'התקשרתי לחבר לשאול אם הוא רוצה לבוא לארוחת ערב אצלנו. הוא ענה ואמר שהוא עסוק היום כי יש לו פגישה בעבודה. קבענו להיפגש מחר בערב במקום זאת. דיברנו כמה דקות על העבודה ועל המשפחות שלנו. הוא סיפר לי חדשות, שהוא עבר לדירה חדשה. אמרתי לו מזל טוב ושאלתי איפה הדירה. הוא אמר שהיא בראשון לציון, קרוב לים. דיברנו גם על סוף שבוע, ואולי נצא ביחד לטיול. אמרתי שזה רעיון מעולה. אחרי עשר דקות סיימנו את השיחה. אמרנו להתראות ולהודיע על מחר. שיחות כאלה עם חברים טובים תמיד משמחות.', 'Я позвонил другу спросить, хочет ли он прийти к нам на ужин. Он ответил и сказал, что сегодня занят, потому что у него встреча на работе. Мы договорились встретиться завтра вечером вместо этого. Мы поговорили несколько минут о работе и о наших семьях. Он рассказал мне новости — что он переехал в новую квартиру. Я сказал ему «мазаль тов» и спросил, где квартира. Он сказал, что она в Ришон ле-Ционе, близко к морю. Мы поговорили также о выходных и, может быть, вместе поедем на прогулку. Я сказал, что это отличная идея. Через десять минут мы закончили разговор. Сказали «до встречи» и договорились сообщить насчёт завтра. Такие разговоры с хорошими друзьями всегда радуют.', '[{"he": "שיחה", "ru": "разговор", "translit": "сихА"}, {"he": "טלפון", "ru": "телефон", "translit": "тЕлефон"}, {"he": "פגישה", "ru": "встреча", "translit": "пгишА"}, {"he": "חדשות", "ru": "новости", "translit": "хадашОт"}, {"he": "רעיון", "ru": "идея", "translit": "раайОн"}, {"he": "עסוק", "ru": "занятой", "translit": "асУк"}, {"he": "להתראות", "ru": "до свидания", "translit": "леhитраОт"}, {"he": "להודיע", "ru": "сообщить", "translit": "леhодИа"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (84, 2, 'אוטובוס מאחר', 'Опоздавший автобус', 'חיכיתי לאוטובוס בתחנה חצי שעה בבוקר הקר. הוא איחר בגלל פקקים כבדים בכביש הראשי. כשהאוטובוס הגיע סוף סוף, הוא היה מלא אנשים ולא היו מקומות לשבת. עמדתי כל הדרך ואחזתי בידית. הנסיעה לקחה ארבעים דקות במקום עשרים. הגעתי לעבודה מאוחר בחצי שעה. המנהל שאל למה אני מאוחר ואמרתי שהאוטובוס איחר בגלל פקקים. הוא הבין ולא כעס. אבל החלטתי שמחר אצא מהבית מוקדם יותר. אולי גם אקנה אופניים כדי לא להיות תלוי באוטובוס. אוטובוסים מאחרים בישראל זו בעיה ידועה.', 'Я ждал автобус на остановке полчаса холодным утром. Он опоздал из-за сильных пробок на главной дороге. Когда автобус наконец приехал, он был полон людей и не было мест для сидения. Я стоял всю дорогу и держался за поручень. Поездка заняла сорок минут вместо двадцати. Я приехал на работу с опозданием в полчаса. Начальник спросил, почему я опаздываю, и я сказал, что автобус опоздал из-за пробок. Он понял и не разозлился. Но я решил, что завтра выйду из дома пораньше. Может, я также куплю велосипед, чтобы не зависеть от автобуса. Опаздывающие автобусы в Израиле — это известная проблема.', '[{"he": "תחנה", "ru": "остановка", "translit": "таханА"}, {"he": "פקק", "ru": "пробка", "translit": "пкАк"}, {"he": "מנהל", "ru": "начальник", "translit": "менаhЕль"}, {"he": "מאוחר", "ru": "поздно, с опозданием", "translit": "меухАр"}, {"he": "אופניים", "ru": "велосипед", "translit": "офанАйим"}, {"he": "ידית", "ru": "поручень, ручка", "translit": "ядИт"}, {"he": "מוקדם", "ru": "рано", "translit": "мукдАм"}, {"he": "תלוי", "ru": "зависимый", "translit": "талУй"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (85, 2, 'פגישה עם חבר', 'Встреча с другом', 'נפגשתי עם חבר ישן בבית קפה בתל אביב. לא ראינו אחד את השני שנתיים כי הוא גר בחוץ לארץ. הוא סיפר שהוא עובד בחברת הייטק גדולה ושהעבודה מעניינת. אני סיפרתי על המשפחה שלי ועל הילדים שגדלו. שתינו קפה ואכלנו עוגת שוקולד טעימה. הזכרנו סיפורים ישנים מהצבא ומהלימודים באוניברסיטה. צחקנו הרבה על דברים שקרו פעם. הוא הראה לי תמונות מהטיול שלו ביפן. אחרי שעתיים נפרדנו ואמרנו שלא נחכה עוד שנתיים לפגישה הבאה. קבענו להיפגש שוב בחודש הבא. טוב לראות חברים ישנים.', 'Я встретился со старым другом в кафе в Тель-Авиве. Мы не виделись два года, потому что он жил за границей. Он рассказал, что работает в большой хайтек-компании и что работа интересная. Я рассказал о своей семье и о детях, которые выросли. Мы пили кофе и ели вкусный шоколадный торт. Мы вспоминали старые истории из армии и из учёбы в университете. Мы много смеялись над вещами, которые случались когда-то. Он показал мне фотографии из поездки в Японию. Через два часа мы попрощались и сказали, что не будем ждать ещё два года до следующей встречи. Мы договорились встретиться снова в следующем месяце. Приятно видеть старых друзей.', '[{"he": "פגישה", "ru": "встреча", "translit": "пгишА"}, {"he": "חבר ישן", "ru": "старый друг", "translit": "хавЕр яшАн"}, {"he": "חברת הייטק", "ru": "хайтек-компания", "translit": "хеврАт hайтЕк"}, {"he": "תמונה", "ru": "фотография", "translit": "тмунА"}, {"he": "אוניברסיטה", "ru": "университет", "translit": "университА"}, {"he": "נפרדנו", "ru": "мы попрощались", "translit": "нифрАдну"}, {"he": "סיפורים", "ru": "истории", "translit": "сипурИм"}, {"he": "צבא", "ru": "армия", "translit": "цавА"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (86, 2, 'מזג אוויר משתנה', 'Переменчивая погода', 'הבוקר היה שמש יפה ויצאתי מהבית בלי מעיל. חשבתי שיהיה יום חם ונעים. אבל אחר הצהריים השמיים התכסו בעננים והתחיל גשם חזק פתאום. נרטבתי לגמרי כי לא היתה לי מטריה. רצתי לחנות קרובה ונכנסתי להתחבא מהגשם. חיכיתי עשר דקות אבל הגשם לא הפסיק. קניתי מטריה זולה בעשרים שקלים והמשכתי ללכת. כשהגעתי הביתה החלפתי בגדים רטובים לבגדים יבשים. הכנתי תה חם והסתכלתי בחדשות על מזג האוויר. למדתי שבישראל מזג האוויר משתנה מהר וצריך תמיד לקחת מטריה בחורף.', 'Утром было солнечно, и я вышел из дома без куртки. Я думал, что день будет тёплый и приятный. Но после обеда небо затянулось тучами и вдруг начался сильный дождь. Я промок насквозь, потому что у меня не было зонта. Я побежал в ближайший магазин и зашёл спрятаться от дождя. Я ждал десять минут, но дождь не прекращался. Я купил дешёвый зонт за двадцать шекелей и пошёл дальше. Когда я пришёл домой, я переоделся из мокрой одежды в сухую. Я приготовил горячий чай и посмотрел прогноз погоды в новостях. Я понял, что в Израиле погода меняется быстро и зимой нужно всегда брать с собой зонт.', '[{"he": "מזג אוויר", "ru": "погода", "translit": "мЕзег авИр"}, {"he": "שמש", "ru": "солнце", "translit": "шЕмеш"}, {"he": "עננים", "ru": "тучи, облака", "translit": "ананИм"}, {"he": "מטריה", "ru": "зонт", "translit": "митрийА"}, {"he": "רטוב", "ru": "мокрый", "translit": "ратОв"}, {"he": "יבש", "ru": "сухой", "translit": "явЕш"}, {"he": "חורף", "ru": "зима", "translit": "хОреф"}, {"he": "חדשות", "ru": "новости", "translit": "хадашОт"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (87, 3, 'חגים בישראל', 'Израильские праздники', 'ישראל היא מדינה עם חגים רבים לאורך כל השנה. החג החשוב ביותר הוא ראש השנה, שחל בתחילת הסתיו. במהלך החג המשפחות מתאספות לארוחת ערב חגיגית ואוכלות תפוח בדבש כדי לסמל שנה מתוקה. אחרי ראש השנה מגיע יום הכיפורים, היום הקדוש ביותר בלוח השנה היהודי. ביום הזה אנשים צמים ומתפללים, והכבישים ריקים לחלוטין ממכוניות.
חג הפסח הוא חג האביב. המשפחות עורכות סדר פסח וקוראות את ההגדה. בחנויות לא מוכרים לחם וחמץ במשך שבוע שלם. חג נוסף שאנשים אוהבים מאוד הוא חג הפורים, שבו ילדים ומבוגרים מתחפשים בתחפושות צבעוניות ושולחים מנות לחברים ולשכנים. כל חג מביא אווירה מיוחדת לרחובות ולבתים בישראל.', 'Израиль — страна с множеством праздников на протяжении всего года. Самый важный праздник — Рош ха-Шана, который приходится на начало осени. Во время праздника семьи собираются на праздничный ужин и едят яблоко с мёдом, чтобы символизировать сладкий год. После Рош ха-Шана наступает Йом Кипур — самый священный день в еврейском календаре. В этот день люди постятся и молятся, а дороги совершенно пусты от машин.
Песах — весенний праздник. Семьи проводят пасхальный седер и читают Агаду. В магазинах не продают хлеб и квасное целую неделю. Ещё один праздник, который люди очень любят, — Пурим, когда дети и взрослые надевают яркие костюмы и отправляют угощения друзьям и соседям. Каждый праздник приносит особую атмосферу на улицы и в дома Израиля.', '[{"he": "חג", "ru": "праздник", "translit": "хаг"}, {"he": "ראש השנה", "ru": "Рош ха-Шана (Новый год)", "translit": "рош hа-шанА"}, {"he": "צום", "ru": "пост", "translit": "цом"}, {"he": "סדר פסח", "ru": "пасхальный седер", "translit": "сЕдер пЕсах"}, {"he": "הגדה", "ru": "Агада (пасхальное повествование)", "translit": "hагадА"}, {"he": "תחפושת", "ru": "костюм (маскарадный)", "translit": "тахпОсет"}, {"he": "חגיגי", "ru": "праздничный", "translit": "хагигИ"}, {"he": "מתוק", "ru": "сладкий", "translit": "матОк"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (88, 3, 'מערכת הבריאות בישראל', 'Система здравоохранения', 'מערכת הבריאות בישראל נחשבת לאחת הטובות בעולם. כל תושב חייב להיות חבר בקופת חולים, ויש ארבע קופות חולים גדולות. הקופות מספקות שירותי רפואה בסיסיים שכוללים ביקור אצל רופא משפחה, בדיקות דם ותרופות במחיר מוזל.
כאשר אדם מרגיש לא טוב, הוא קובע תור לרופא דרך האפליקציה או בטלפון. הרופא בודק אותו ויכול להפנות אותו למומחה אם צריך. בבתי החולים יש מחלקות שונות כמו פנימית, ילדים וכירורגיה. אנשים עם ביטוח נוסף יכולים לבחור מומחה ולקבל תור מהיר יותר.
אחת הבעיות הגדולות היא זמני ההמתנה הארוכים. לפעמים צריך לחכות חודשים לתור אצל מומחה. עם זאת, במקרי חירום כל אדם מקבל טיפול מיידי בחדר המיון.', 'Система здравоохранения в Израиле считается одной из лучших в мире. Каждый житель обязан быть членом больничной кассы, и в стране есть четыре крупные больничные кассы. Кассы предоставляют базовые медицинские услуги, включая визит к семейному врачу, анализы крови и лекарства по сниженной цене.
Когда человек чувствует себя нехорошо, он записывается к семейному врачу через приложение или по телефону. Врач осматривает его и может направить к специалисту при необходимости. В больницах есть различные отделения: терапевтическое, педиатрическое и хирургическое. Люди с дополнительной страховкой могут выбрать специалиста и получить приём быстрее.
Одна из главных проблем системы — длительное время ожидания. Иногда приходится ждать месяцами приёма у специалиста. Тем не менее, в экстренных случаях любой человек получает немедленную помощь бесплатно в приёмном покое.', '[{"he": "קופת חולים", "ru": "больничная касса", "translit": "купАт холИм"}, {"he": "רופא משפחה", "ru": "семейный врач", "translit": "рофЕ мишпахА"}, {"he": "תור", "ru": "очередь / запись на приём", "translit": "тор"}, {"he": "רופא מומחה", "ru": "врач-специалист", "translit": "рофЕ мумхЕ"}, {"he": "ביטוח", "ru": "страховка", "translit": "битУах"}, {"he": "בדיקת דם", "ru": "анализ крови", "translit": "бдикАт дам"}, {"he": "חדר מיון", "ru": "приёмный покой", "translit": "хЕдер миюн"}, {"he": "תרופה", "ru": "лекарство", "translit": "труфА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (99, 3, 'רשתות חברתיות בישראל', 'Соцсети в Израиле', 'ישראלים הם בין המשתמשים הפעילים ביותר ברשתות חברתיות בעולם. כמעט כל אדם משתמש בטלפון חכם ובכמה רשתות במקביל. הרשתות הפופולריות הן ווטסאפ, אינסטגרם, פייסבוק וטיקטוק.
ווטסאפ הוא כלי התקשורת החשוב ביותר. כמעט כל תקשורת יומיומית עוברת דרכו: קבוצות משפחה, עבודה, הורים מבית הספר ואפילו תקשורת עם רופאים. ישראלים שולחים הודעות קוליות רבות ומשתפים תמונות וסרטונים בקבוצות.
הרשתות החברתיות משפיעות מאוד על החיים בישראל. אנשים מחפשים עבודה, קונים ומוכרים מוצרים ועוקבים אחרי חדשות. מצד שני, יש דאגה לגבי התמכרות למסכים אצל ילדים ונוער. בתי ספר רבים מנסים להגביל את השימוש בטלפונים בשיעורים.', 'Израильтяне — одни из самых активных пользователей социальных сетей в мире. Почти каждый человек в Израиле пользуется смартфоном и несколькими социальными сетями одновременно. Самые популярные — Ватсап, Инстаграм, Фейсбук и ТикТок.
Ватсап — главное средство общения в Израиле. Почти вся ежедневная коммуникация проходит через него: семейные группы, рабочие группы, родительские группы из школы и даже общение с врачами и учителями. Израильтяне отправляют много голосовых сообщений и делятся фотографиями и видео в своих группах.
Социальные сети сильно влияют на жизнь в Израиле. Люди ищут работу через Линкедин, покупают и продают товары в группах Фейсбука и следят за новостями в Инстаграме. С другой стороны, есть беспокойство по поводу зависимости от экранов, особенно у детей и подростков. Многие школы пытаются ограничить использование телефонов во время уроков.', '[{"he": "רשת חברתית", "ru": "социальная сеть", "translit": "рЕшет хевратИт"}, {"he": "טלפון חכם", "ru": "смартфон", "translit": "телефОн хахАм"}, {"he": "הודעה", "ru": "сообщение", "translit": "hодаА"}, {"he": "קבוצה", "ru": "группа", "translit": "квуцА"}, {"he": "סרטון", "ru": "видеоролик", "translit": "сартОн"}, {"he": "התמכרות", "ru": "зависимость", "translit": "hитмахрУт"}, {"he": "מסך", "ru": "экран", "translit": "масАх"}, {"he": "לשתף", "ru": "делиться / расшаривать", "translit": "лешатЕф"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (89, 3, 'שכירת דירה בישראל', 'Аренда квартиры', 'למצוא דירה להשכרה בישראל זה לא פשוט, במיוחד בתל אביב ובירושלים. המחירים עלו מאוד ודירה קטנה בתל אביב עולה לפחות ארבעת אלפים שקלים בחודש. סטודנטים רבים מחפשים שותפים לדירה כדי לחלק את ההוצאות.
כשמוצאים דירה מתאימה, חותמים על חוזה שכירות לשנה. בדרך כלל משלמים פיקדון של חודש עד שלושה חודשים מראש. בחוזה כתוב מה כולל השכירות ומה לא, למשל ארנונה ומים. השוכר אחראי לשמור על הדירה ולהודיע לבעל הבית על תקלות.
אנשים רבים מחפשים דירות באתרי אינטרנט וברשתות חברתיות. חשוב לבדוק את הדירה לפני החתימה, לוודא שהכל עובד ושאין בעיות רטיבות. כדאי גם לבדוק את הסביבה.', 'Найти квартиру в аренду в Израиле непросто, особенно в Тель-Авиве и Иерусалиме. Цены значительно выросли в последние годы, и маленькая квартира в Тель-Авиве стоит минимум четыре тысячи шекелей в месяц. Многие студенты ищут соседей по квартире, чтобы разделить расходы.
Когда находят подходящую квартиру, подписывают договор аренды на год. Обычно платят залог от одного до трёх месяцев вперёд. В договоре указано, что включает аренда, а что нет, например муниципальный налог и воду. Арендатор обязан содержать квартиру в хорошем состоянии и сообщать хозяину о любых неполадках.
Многие ищут квартиры на сайтах и в группах в социальных сетях. Важно осмотреть квартиру перед подписанием договора, убедиться, что всё работает и нет проблем с влажностью. Стоит также проверить соседей и район, чтобы убедиться, что это тихое и удобное место.', '[{"he": "שכירות", "ru": "аренда", "translit": "схирУт"}, {"he": "חוזה", "ru": "договор", "translit": "хозЕ"}, {"he": "פיקדון", "ru": "залог", "translit": "пикадОн"}, {"he": "ארנונה", "ru": "муниципальный налог", "translit": "арнонА"}, {"he": "שוכר", "ru": "арендатор", "translit": "сохЕр"}, {"he": "בעל הבית", "ru": "хозяин квартиры", "translit": "бАаль hа-бАйит"}, {"he": "תקלה", "ru": "неполадка", "translit": "такалА"}, {"he": "רטיבות", "ru": "влажность / сырость", "translit": "ретивУт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (90, 3, 'תחבורה ציבורית בישראל', 'Общественный транспорт', 'התחבורה הציבורית בישראל כוללת אוטובוסים, רכבות, מוניות ומונית שירות. האוטובוס הוא האמצעי הנפוץ ביותר ויש קווים שמגיעים כמעט לכל מקום. כדי לנסוע באוטובוס צריך כרטיס רב-קו שאפשר לטעון בתחנות ובחנויות.
רכבת ישראל מחברת ערים רבות, מנהריה בצפון עד באר שבע בדרום. הנסיעה ברכבת נוחה ומהירה, אבל לא כל העיירות מחוברות לרכבת. בשנים האחרונות נפתחה הרכבת הקלה בירושלים שעוזרת לתושבים להגיע למקומות שונים בעיר.
אחת הבעיות היא שהתחבורה לא פועלת בשבת. מיום שישי אחר הצהריים עד מוצאי שבת אין אוטובוסים ורכבות, ואנשים צריכים מוניות או רכב פרטי. נושא זה יוצר ויכוח ציבורי בין דתיים לחילונים כבר שנים רבות.', 'Общественный транспорт в Израиле включает автобусы, поезда, такси и маршрутные такси. Автобус — самый распространённый вид транспорта, и есть маршруты почти в любую точку страны. Для проезда на автобусе нужна карта Рав-Кав, которую можно пополнить на остановках и в магазинах.
Израильская железная дорога соединяет многие города, от Нагарии на севере до Беэр-Шевы на юге. Поездка на поезде удобна и быстра, но не все города подключены к железнодорожной линии. В последние годы в Хайфе открылся фуникулёр, а в Иерусалиме — скоростной трамвай, которые помогают жителям добраться до разных мест в городе.
Одна из проблем общественного транспорта — он не работает в шаббат. С пятницы после обеда до исхода субботы нет автобусов и поездов, и люди должны пользоваться такси или частным автомобилем. Эта тема вызывает общественную дискуссию между религиозными и светскими людьми уже много лет.', '[{"he": "תחבורה ציבורית", "ru": "общественный транспорт", "translit": "тахбурА цибурИт"}, {"he": "אוטובוס", "ru": "автобус", "translit": "отобУс"}, {"he": "רכבת", "ru": "поезд", "translit": "ракЕвет"}, {"he": "רב-קו", "ru": "Рав-Кав (транспортная карта)", "translit": "рав-кав"}, {"he": "מונית", "ru": "такси", "translit": "монИт"}, {"he": "שבת", "ru": "суббота (шаббат)", "translit": "шабАт"}, {"he": "רכבת קלה", "ru": "скоростной трамвай", "translit": "ракЕвет калА"}, {"he": "קו", "ru": "маршрут / линия", "translit": "кав"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (92, 3, 'האוניברסיטה בישראל', 'Университет', 'בישראל יש שמונה אוניברסיטאות ומכללות רבות. רוב הסטודנטים מתחילים ללמוד אחרי השירות הצבאי, בגיל עשרים ואחת עד עשרים ושלוש. זה שונה מרוב המדינות בעולם שבהן לומדים מיד אחרי התיכון.
הלימודים כוללים תואר ראשון שנמשך שלוש עד ארבע שנים. הנושאים הפופולריים הם מדעי המחשב, משפטים, הנדסה ופסיכולוגיה. שכר הלימוד נמוך יחסית בהשוואה לארצות הברית, אבל הרבה סטודנטים עובדים במקביל כדי לממן את עצמם.
החיים באוניברסיטה הם לא רק לימודים. בקמפוס יש פעילות חברתית עשירה, אירועים תרבותיים ומסיבות. הרבה סטודנטים גרים בדירות שותפים ליד הקמפוס ומכירים חברים חדשים. תקופת הלימודים נחשבת לתקופה הכי כיפית בחיים.', 'В Израиле есть восемь университетов и множество колледжей. Большинство студентов начинают учиться после армейской службы, в возрасте 21-23 лет. Это отличается от большинства стран мира, где студенты начинают учёбу сразу после школы.
Учёба в университете включает степень бакалавра, которая длится три-четыре года. Популярные направления — информатика, юриспруденция, инженерия и психология. Стоимость обучения в Израиле относительно невысока по сравнению с США, но многие студенты работают параллельно с учёбой, чтобы обеспечить себя.
Жизнь в университете — это не только учёба. На кампусе кипит общественная жизнь, проходят культурные мероприятия и студенческие вечеринки. Многие студенты живут в совместных квартирах рядом с кампусом и заводят новых друзей. Период учёбы считается самым весёлым временем в жизни многих израильтян.', '[{"he": "אוניברסיטה", "ru": "университет", "translit": "университА"}, {"he": "סטודנט", "ru": "студент", "translit": "студЕнт"}, {"he": "תואר ראשון", "ru": "степень бакалавра", "translit": "тоАр ришОн"}, {"he": "שכר לימוד", "ru": "плата за обучение", "translit": "схар лимуд"}, {"he": "מכללה", "ru": "колледж", "translit": "михлалА"}, {"he": "קמפוס", "ru": "кампус", "translit": "кАмпус"}, {"he": "הנדסה", "ru": "инженерия", "translit": "hандасА"}, {"he": "משפטים", "ru": "юриспруденция", "translit": "мишпатИм"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (94, 3, 'חיים בקיבוץ', 'Жизнь в кибуце', 'הקיבוץ הוא אחד הסמלים של ישראל. הקיבוצים הראשונים הוקמו לפני יותר ממאה שנה על ידי צעירים שרצו לבנות חברה מבוססת על שוויון. בתחילה חברי הקיבוץ עבדו בחקלאות, אכלו בחדר אוכל משותף ושיתפו את כל הרכוש.
היום הקיבוצים השתנו מאוד. רוב הקיבוצים עברו הפרטה, וכל משפחה מקבלת משכורת ואחראית על ההוצאות שלה. הרבה קיבוצים פיתחו תעשייה ותיירות במקום חקלאות. יש קיבוצים שהפכו למפעלים מצליחים מאוד.
למרות השינויים, קיבוצים רבים שומרים על רוח הקהילה. עדיין יש חדר אוכל, פעילות תרבותית ועזרה הדדית. צעירים שרוצים חיים שקטים בטבע בוחרים לגור בקיבוץ, במיוחד אחרי שמקימים משפחה.', 'Кибуц — один из символов Израиля. Первые кибуцы были основаны более ста лет назад молодыми людьми, которые хотели построить новое общество, основанное на равенстве и совместном труде. Вначале члены кибуца работали в сельском хозяйстве, ели вместе в общей столовой и делили всё имущество.
Сегодня кибуцы сильно изменились. Большинство прошли процесс приватизации, и теперь каждая семья получает зарплату и отвечает за свои расходы. Многие кибуцы развили промышленность и туризм вместо сельского хозяйства. Есть кибуцы, которые превратились в крупные и очень успешные предприятия.
Несмотря на изменения, многие кибуцы сохраняют дух общины. По-прежнему есть общая столовая, культурные мероприятия и взаимопомощь между соседями. Молодые израильтяне, которые хотят спокойной жизни на природе с тёплой общиной, выбирают жить в кибуце, особенно после создания семьи.', '[{"he": "קיבוץ", "ru": "кибуц", "translit": "кибУц"}, {"he": "שוויון", "ru": "равенство", "translit": "шивайОн"}, {"he": "חקלאות", "ru": "сельское хозяйство", "translit": "хаклаУт"}, {"he": "הפרטה", "ru": "приватизация", "translit": "hафратА"}, {"he": "חדר אוכל", "ru": "столовая", "translit": "хадАр Охель"}, {"he": "קהילה", "ru": "община / сообщество", "translit": "кеhилА"}, {"he": "רכוש", "ru": "имущество", "translit": "рехУш"}, {"he": "תעשייה", "ru": "промышленность", "translit": "таасийА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (95, 3, 'חיי הלילה של תל אביב', 'Ночная жизнь Тель-Авива', 'תל אביב ידועה בכל העולם כעיר שלא ישנה. חיי הלילה מתחילים מאוחר, בסביבות חצות, ונמשכים עד הבוקר. ברחובות כמו רוטשילד, אלנבי ודיזנגוף יש עשרות ברים ומועדונים שפתוחים כל לילה.
הישראלים אוהבים לצאת לבלות בסוף השבוע, במיוחד בלילות שישי. הרבה אנשים מתחילים בשתייה בבר קטן ואחר כך עוברים למועדון לרקוד. המוזיקה במועדונים מגוונת, מטכנו ואלקטרוניקה ועד מוזיקה מזרחית. יש גם מופעי מוזיקה חיה בברים רבים.
מלבד ברים ומועדונים, תל אביב מציעה תרבות לילה עשירה. יש הצגות תיאטרון שמתחילות מאוחר ומופעי סטנדאפ. שוק הכרמל הפך גם למקום בילוי בלילה עם מסעדות ודוכני אוכל שפתוחים עד מאוחר. האווירה בעיר חמה ומזמינה.', 'Тель-Авив известен во всём мире как город, который не спит. Ночная жизнь начинается поздно, около полуночи, и продолжается до раннего утра. На улицах вроде Ротшильд, Алленби и Дизенгоф есть десятки баров и клубов, открытых каждую ночь.
Израильтяне любят выходить развлекаться в выходные, особенно в пятницу вечером. Многие начинают вечер с напитков в маленьком баре, а затем перемещаются в клуб потанцевать. Музыка в клубах разнообразная — от техно и электроники до израильской восточной музыки. Во многих барах также проходят живые выступления.
Помимо баров и клубов, Тель-Авив предлагает богатую ночную культуру. Есть театральные спектакли, которые начинаются поздно, стендап-шоу и уличные фестивали. Рынок Кармель в последние годы тоже стал местом ночных развлечений с ресторанами и прилавками с едой, открытыми допоздна. Атмосфера в городе тёплая, приятная и гостеприимная.', '[{"he": "חיי לילה", "ru": "ночная жизнь", "translit": "хаей лАйла"}, {"he": "מועדון", "ru": "клуб", "translit": "моадОн"}, {"he": "בר", "ru": "бар", "translit": "бар"}, {"he": "לרקוד", "ru": "танцевать", "translit": "лиркОд"}, {"he": "מופע", "ru": "представление / шоу", "translit": "мофА"}, {"he": "לבלות", "ru": "развлекаться / проводить время", "translit": "левалОт"}, {"he": "אווירה", "ru": "атмосфера", "translit": "авирА"}, {"he": "מוזיקה חיה", "ru": "живая музыка", "translit": "мУзика хайА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (101, 3, 'ספורט בישראל', 'Спорт в Израиле', 'הספורט הפופולרי ביותר בישראל הוא כדורגל. יש ליגה ישראלית עם קבוצות מכל הארץ, והמשחקים הגדולים הם בין מכבי תל אביב להפועל תל אביב. אוהדים רבים הולכים לאצטדיון לצפות במשחקים ומעודדים את הקבוצה שלהם בהתלהבות.
כדורסל פופולרי מאוד גם כן. מכבי תל אביב זכתה באליפות אירופה כמה פעמים ונחשבת לקבוצה מוכרת בעולם. שחקנים ישראלים הגיעו לליגה האמריקאית והביאו גאווה למדינה.
מלבד ספורט קבוצתי, ישראלים אוהבים ריצה, שחייה ורכיבה על אופניים. מרתון תל אביב מושך רצים מכל העולם. ספורט ימי פופולרי בגלל קו החוף הארוך ויש הרבה גולשים בחופים. הספורט בישראל מאחד אנשים ויוצר גאווה לאומית.', 'Самый популярный вид спорта в Израиле — футбол. Есть израильская лига с командами со всей страны, и главные матчи — между Маккаби Тель-Авив и Хапоэль Тель-Авив, а также между Бейтар Иерусалим и Хапоэль Иерусалим. Многие болельщики ходят на стадион смотреть матчи и болеют за свою команду с энтузиазмом.
Баскетбол тоже очень популярен. Маккаби Тель-Авив несколько раз побеждал в чемпионате Европы и считается известной командой в мире. Израильские баскетболисты попадали в американскую лигу и приносили гордость стране.
Помимо командных видов спорта, израильтяне любят бег, плавание и велоспорт. Тель-авивский марафон проходит каждый год и привлекает бегунов со всего мира. Водные виды спорта очень популярны из-за длинной береговой линии, и много сёрферов на пляжах Тель-Авива и Герцлии. Спорт в Израиле объединяет людей и создаёт чувство национальной гордости.', '[{"he": "כדורגל", "ru": "футбол", "translit": "кадурЕгель"}, {"he": "כדורסל", "ru": "баскетбол", "translit": "кадурсАль"}, {"he": "קבוצה", "ru": "команда", "translit": "квуцА"}, {"he": "אוהד", "ru": "болельщик", "translit": "оhЕд"}, {"he": "אצטדיון", "ru": "стадион", "translit": "ицтадьОн"}, {"he": "מרתון", "ru": "марафон", "translit": "маратОн"}, {"he": "גלישה", "ru": "сёрфинг", "translit": "глишА"}, {"he": "אליפות", "ru": "чемпионат", "translit": "алифУт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (102, 3, 'כתבה בעיתון', 'Газетная статья', 'בישראל יש כמה עיתונים גדולים ואתרי חדשות פופולריים. בעבר אנשים קראו עיתון מודפס כל בוקר, אבל היום רוב האנשים קוראים חדשות בטלפון או במחשב. העיתונים הגדולים עברו לפלטפורמה דיגיטלית.
כתבה אופיינית בעיתון ישראלי עוסקת בביטחון, פוליטיקה, כלכלה או תרבות. הכותרות נוטות להיות דרמטיות ומושכות תשומת לב. כתבי עיתון ופרשנים מופיעים גם בטלוויזיה וברדיו ואנשים רבים מכירים אותם.
חופש העיתונות חשוב מאוד לדמוקרטיה. עיתונאים חוקרים פרשיות שחיתות ומדווחים על בעיות חברתיות. עם זאת, יש ביקורת שהתקשורת מוטה לכיוונים פוליטיים שונים. אנשים רבים קוראים רק מקורות שמתאימים לדעותיהם וזה יוצר בועות מידע.', 'В Израиле есть несколько крупных газет и популярных новостных сайтов. Раньше люди читали печатную газету каждое утро, но сегодня большинство читает новости на телефоне или компьютере. Крупные газеты вроде «Едиот Ахронот» и «Гаарец» перешли на цифровую платформу.
Типичная газетная статья в Израиле посвящена темам безопасности, политики, экономики или культуры. Заголовки в Израиле обычно драматичные и привлекающие внимание. Журналисты и комментаторы появляются также на телевидении и радио, и многие люди их знают.
Свобода прессы в Израиле очень важна для демократии. Журналисты расследуют коррупционные дела и сообщают о социальных проблемах. Тем не менее есть критика того, что израильские СМИ имеют политическую предвзятость. Многие люди предпочитают читать только те источники новостей, которые совпадают с их взглядами, и это создаёт информационные пузыри.', '[{"he": "עיתון", "ru": "газета", "translit": "итОн"}, {"he": "כתבה", "ru": "статья / репортаж", "translit": "катавА"}, {"he": "כותרת", "ru": "заголовок", "translit": "котЕрет"}, {"he": "עיתונאי", "ru": "журналист", "translit": "итонАи"}, {"he": "חדשות", "ru": "новости", "translit": "хадашОт"}, {"he": "שחיתות", "ru": "коррупция", "translit": "шхитУт"}, {"he": "תקשורת", "ru": "СМИ / коммуникация", "translit": "тикшОрет"}, {"he": "חופש העיתונות", "ru": "свобода прессы", "translit": "хОфеш hа-итонУт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (103, 3, 'מתכון לשקשוקה', 'Рецепт шакшуки', 'שקשוקה היא אחת המנות האהובות ביותר בישראל. אוכלים אותה בארוחת בוקר, בצהריים ובערב. ההכנה פשוטה וכל אחד יכול להכין אותה בבית. המתכון דורש עגבניות, ביצים, בצל, שום, פלפל ותבלינים.
קודם כל מחממים שמן זית במחבת גדולה. חותכים בצל לקוביות ומטגנים עד שהוא שקוף. מוסיפים שום כתוש ופלפל חתוך ומטגנים עוד כמה דקות. אחר כך מוסיפים עגבניות חתוכות, כמון, פפריקה ומלח ומבשלים על אש נמוכה עד שהרוטב מתעבה.
בשלב האחרון עושים גומות ברוטב ושוברים ביצים לתוכן. מכסים את המחבת ומחכים עד שהביצים מתבשלות. מגישים את השקשוקה במחבת עם לחם טרי. ישראלים רבים מוסיפים גבינה מלוחה מעל או פלפל חריף.', 'Шакшука — одно из самых любимых блюд в Израиле. Его едят на завтрак, обед и даже на ужин. Приготовление простое, и каждый может приготовить его дома. Базовый рецепт требует помидоры, яйца, лук, чеснок, перец и специи.
Сначала нагревают оливковое масло в большой сковороде. Нарезают лук мелкими кубиками и обжаривают, пока он не станет прозрачным. Добавляют измельчённый чеснок и нарезанный перец и жарят ещё несколько минут. Затем добавляют нарезанные помидоры или томатный соус, кумин, паприку и соль и варят на медленном огне, пока соус не загустеет.
На последнем этапе делают углубления в соусе и разбивают в них яйца. Накрывают сковороду крышкой и ждут, пока яйца приготовятся. Шакшуку подают прямо в сковороде со свежим хлебом для макания. Многие израильтяне добавляют сверху солёный сыр или острый перец по вкусу.', '[{"he": "שקשוקה", "ru": "шакшука", "translit": "шакшУка"}, {"he": "מתכון", "ru": "рецепт", "translit": "маткОн"}, {"he": "מחבת", "ru": "сковорода", "translit": "махавАт"}, {"he": "עגבנייה", "ru": "помидор", "translit": "агванийА"}, {"he": "ביצה", "ru": "яйцо", "translit": "бейцА"}, {"he": "תבלין", "ru": "специя", "translit": "тавлИн"}, {"he": "שמן זית", "ru": "оливковое масло", "translit": "шЕмен зАйит"}, {"he": "רוטב", "ru": "соус", "translit": "рОтев"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (104, 3, 'בלוג טיולים בישראל', 'Блог о путешествии', 'שלום לכולם! השבוע יצאתי לטיול בצפון ואני רוצה לספר על החוויה. נסעתי עם חברים לגליל ובילינו שלושה ימים נפלאים בטבע. ישנו באוהלים ליד נחל ובישלנו אוכל על מדורה.
ביום הראשון טיילנו בנחל זוויתן שם יש מפל מים מרשים. השביל לא קשה ומתאים גם למשפחות. המים היו קרים אבל נכנסנו בכל זאת. ביום השני נסענו לצפת, עיר עתיקה עם סמטאות צרות ובתי אמנים. אכלנו במסעדה דרוזית עם אוכל מעולה.
ביום האחרון ביקרנו ביקב קטן וטעמנו יינות מקומיים. הגליל ידוע ביינות מעולים. חזרנו הביתה עייפים אבל מאושרים. אני ממליץ לכולם לטייל בצפון, במיוחד בסתיו ובאביב כשמזג האוויר נעים והטבע ירוק.', 'Привет всем! На этой неделе я отправился в поход по северу страны и хочу рассказать вам о впечатлениях. Мы поехали с друзьями в Галилею и провели три замечательных дня на природе. Ночевали в палатках у ручья и готовили еду на костре.
В первый день мы прошли по ручью Завитан, где есть впечатляющий водопад. Тропа не слишком сложная и подходит для семей с детьми. Вода была холодной, но мы всё равно зашли. Во второй день поехали в Цфат — древний красивый город с узкими переулками и мастерскими художников. Пообедали в друзском ресторане с отличной едой.
В последний день мы посетили маленькую винодельню и попробовали местные вина. Галилея славится отличными винами, и там много виноделен. Мы вернулись домой уставшие, но счастливые. Я рекомендую всем путешествовать по северу, особенно осенью и весной, когда погода приятная и природа зелёная.', '[{"he": "טיול", "ru": "поход / путешествие", "translit": "тиюль"}, {"he": "נחל", "ru": "ручей", "translit": "нАхаль"}, {"he": "מפל מים", "ru": "водопад", "translit": "мапАль мАим"}, {"he": "שביל", "ru": "тропа", "translit": "швиль"}, {"he": "אוהל", "ru": "палатка", "translit": "Оhель"}, {"he": "מדורה", "ru": "костёр", "translit": "медурА"}, {"he": "יקב", "ru": "винодельня", "translit": "йЕкев"}, {"he": "מזג אוויר", "ru": "погода", "translit": "мЕзег авИр"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (105, 3, 'מכתב לחבר', 'Письмо другу', 'חבר יקר שלי,
מה שלומך? כבר עבר הרבה זמן מאז שדיברנו ואני מתגעגע אליך. רציתי לספר לך מה קורה איתי בתקופה האחרונה. לפני חודשיים עברתי דירה חדשה בתל אביב ואני מאוד אוהב את השכונה. יש כאן בתי קפה נחמדים, פארק גדול ושכנים נעימים.
בעבודה הכל טוב. קיבלתי קידום וגם העלאה במשכורת. אני עובד כמנהל פרויקט בחברת הייטק ויש לי צוות של עשרה אנשים. העבודה מעניינת אבל לפעמים לוחצת. בזמן הפנוי אני רץ ומתאמן בחדר כושר, וגם התחלתי ללמוד גיטרה.
אני מקווה שתבוא לבקר אותי בקרוב. יש לי חדר אורחים והעיר מקסימה. אנחנו יכולים לצאת לאכול ולטייל על חוף הים. תכתוב לי מתי נוח לך ונתאם.
מחכה לשמוע ממך,
אוהב, דני', 'Дорогой друг,
Как дела? Прошло уже много времени с тех пор, как мы разговаривали, и я скучаю по тебе. Хотел рассказать, что у меня происходит в последнее время. Два месяца назад я переехал в новую квартиру в Тель-Авиве, и мне очень нравится район. Здесь уютные кафе, большой парк и приятные соседи.
На работе всё хорошо. Я получил повышение и прибавку к зарплате. Я работаю менеджером проектов в хайтек-компании, и у меня команда из десяти человек. Работа интересная, но иногда напряжённая. В свободное время я бегаю и занимаюсь в спортзале, а ещё начал учиться играть на гитаре.
Надеюсь, ты приедешь навестить меня в ближайшее время. У меня есть гостевая комната, а город прекрасен. Мы можем сходить поужинать и погулять по берегу моря. Напиши, когда тебе удобно, и мы договоримся.
Жду ответа,
С любовью, Дани', '[{"he": "מכתב", "ru": "письмо", "translit": "михтАв"}, {"he": "להתגעגע", "ru": "скучать", "translit": "леhитгаагЕа"}, {"he": "שכונה", "ru": "район", "translit": "шхунА"}, {"he": "קידום", "ru": "повышение", "translit": "кидУм"}, {"he": "משכורת", "ru": "зарплата", "translit": "маскОрет"}, {"he": "חדר כושר", "ru": "спортзал", "translit": "хЕдер кОшер"}, {"he": "חדר אורחים", "ru": "гостевая комната", "translit": "хЕдер орхИм"}, {"he": "לתאם", "ru": "согласовать / договориться", "translit": "летаЕм"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (108, 3, 'הודעת בית ספר', 'Объявление школы', 'הורים יקרים, שלום רב.
אנו שמחים להודיע על אירועים חשובים בחודש הקרוב. ביום שלישי הבא יתקיים יום ספורט לכל התלמידים. הילדים מתבקשים להגיע עם בגדי ספורט, כובע ובקבוק מים. ההורים מוזמנים לבוא ולעודד.
בסוף החודש תתקיים הצגת סוף שנה של כיתות ד וה. התלמידים מתרגלים כבר כמה שבועות. ההצגה תתחיל בשעה שש בערב באולם בית הספר. כל הורה יקבל שני כרטיסים. נבקש להגיע בזמן כי אין מקומות שמורים.
בשבוע הבא יהיו אסיפות הורים אישיות עם המחנכים. אפשר לקבוע תור דרך האפליקציה. כל פגישה נמשכת עשר דקות. אם יש נושא דחוף, פנו ישירות למחנך הכיתה. תודה על שיתוף הפעולה.', 'Уважаемые родители, здравствуйте.
Мы рады сообщить о важных мероприятиях, которые состоятся в ближайшем месяце в школе. В следующий вторник пройдёт спортивный день для всех учеников. Детей просят прийти в спортивной одежде, с кепкой и бутылкой воды. Родители приглашены прийти и поболеть.
Кроме того, в конце месяца состоится итоговый спектакль четвёртых и пятых классов. Ученики репетируют уже несколько недель и очень волнуются. Спектакль начнётся в шесть вечера в школьном зале. Каждый родитель получит два билета. Просьба приходить вовремя, так как места не зарезервированы.
Ещё одна тема: на следующей неделе пройдут индивидуальные родительские собрания с классными руководителями. Записаться можно через школьное приложение. Каждая встреча длится десять минут. Если есть срочный вопрос, можно обратиться напрямую к классному руководителю. Спасибо за сотрудничество.', '[{"he": "הודעה", "ru": "объявление / сообщение", "translit": "hодаА"}, {"he": "תלמיד", "ru": "ученик", "translit": "тальмИд"}, {"he": "הצגה", "ru": "спектакль / представление", "translit": "hацагА"}, {"he": "מחנך", "ru": "классный руководитель", "translit": "мехонЕх"}, {"he": "אסיפת הורים", "ru": "родительское собрание", "translit": "асифАт hорИм"}, {"he": "אולם", "ru": "зал", "translit": "улАм"}, {"he": "כרטיס", "ru": "билет", "translit": "картИс"}, {"he": "שיתוף פעולה", "ru": "сотрудничество", "translit": "шитУф пеулА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (109, 3, 'תור לרופא', 'Визит к врачу', 'הבוקר הלכתי לרופא המשפחה כי לא הרגשתי טוב כמה ימים. היה לי כאב ראש חזק, חום גבוה וכאב גרון. קבעתי תור דרך האפליקציה של קופת החולים ובאתי למרפאה בשעה תשע בבוקר.
במרפאה נתנו לי מספר וחיכיתי עשרים דקות. כשנכנסתי הרופא שאל מה כואב לי ומתי התחילו הסימפטומים. הוא בדק את הגרון, מדד לחץ דם והאזין לנשימה. אחרי הבדיקה אמר שכנראה זו דלקת גרון ורשם לי אנטיביוטיקה לשבוע.
הרופא הסביר שצריך לקחת את התרופה שלוש פעמים ביום אחרי אוכל, לשתות הרבה מים ולנוח. הוא נתן לי גם מכתב לעבודה כדי שאוכל להישאר בבית שלושה ימים. הלכתי לבית מרקחת, קניתי תרופות וחזרתי הביתה.', 'Утром я пошёл к семейному врачу, потому что уже несколько дней чувствовал себя плохо. У меня была сильная головная боль, высокая температура и боль в горле. Я записался на приём через приложение больничной кассы на следующий день и пришёл в поликлинику в девять утра.
В поликлинике мне дали номер, и я ждал около двадцати минут. Когда я зашёл в кабинет, врач спросил, что у меня болит и когда начались симптомы. Он осмотрел горло, измерил давление и прослушал дыхание. После осмотра он сказал, что вероятно это воспаление горла, и выписал антибиотик на неделю.
Врач объяснил, что нужно принимать лекарство три раза в день после еды, пить много воды и отдыхать. Он дал мне также справку для работы, чтобы я мог остаться дома три дня. Я пошёл в аптеку, купил лекарства и вернулся домой отдыхать.', '[{"he": "רופא משפחה", "ru": "семейный врач", "translit": "рофЕ мишпахА"}, {"he": "תור", "ru": "очередь / запись", "translit": "тор"}, {"he": "מרפאה", "ru": "поликлиника", "translit": "мирпаА"}, {"he": "כאב ראש", "ru": "головная боль", "translit": "кеЕв рош"}, {"he": "דלקת", "ru": "воспаление", "translit": "далЕкет"}, {"he": "תרופה", "ru": "лекарство", "translit": "труфА"}, {"he": "מרשם", "ru": "рецепт (медицинский)", "translit": "миршАм"}, {"he": "בית מרקחת", "ru": "аптека", "translit": "бейт миркАхат"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (110, 3, 'בבנק', 'В банке', 'אתמול הלכתי לסניף הבנק לפתוח חשבון חדש. לקחתי תעודת זהות ואישור כתובת כמו שביקשו ממני. כשהגעתי, לקחתי מספר ממכונה וישבתי לחכות. אחרי עשרים דקות קראו לי לגשת לפקיד.
הפקיד היה נחמד והסביר לי את סוגי החשבונות. בחרתי חשבון עובר ושב עם כרטיס אשראי. הוא הסביר על העמלות, הריבית והאפשרות לקבל הלוואה בעתיד. מילאתי טפסים וחתמתי על החוזה.
אחרי פתיחת החשבון הפקיד עזר לי להתקין את אפליקציית הבנק בטלפון. באפליקציה אפשר לראות את היתרה, להעביר כסף ולשלם חשבונות. הוא גם הסביר איך להגדיר הוראת קבע לתשלומים חודשיים. עכשיו הכל מסודר ואני מנהל את הכסף שלי בקלות.', 'Вчера я пошёл в отделение банка, чтобы открыть новый счёт. Я взял с собой удостоверение личности и подтверждение адреса, как меня попросили по телефону. Когда пришёл, взял номерок из автомата и сел ждать. Примерно через двадцать минут меня вызвали к клерку.
Клерк был очень приятным и объяснил все виды счетов. В итоге я выбрал обычный текущий счёт с кредитной картой. Он рассказал о комиссиях, процентах и возможности получить кредит в будущем. Я заполнил несколько бланков и подписал договор.
После открытия счёта клерк помог мне установить банковское приложение на телефон. В приложении можно видеть баланс, переводить деньги и оплачивать счета. Он также объяснил, как вносить чеки через телефон и как настроить постоянное поручение для ежемесячных платежей. Теперь я чувствую, что всё в порядке и могу легко управлять своими финансами.', '[{"he": "בנק", "ru": "банк", "translit": "банк"}, {"he": "חשבון", "ru": "счёт", "translit": "хешбОн"}, {"he": "כרטיס אשראי", "ru": "кредитная карта", "translit": "картИс ашрАи"}, {"he": "עמלה", "ru": "комиссия", "translit": "амлА"}, {"he": "הלוואה", "ru": "кредит / ссуда", "translit": "hалваА"}, {"he": "יתרה", "ru": "баланс (на счёте)", "translit": "йитрА"}, {"he": "הוראת קבע", "ru": "постоянное поручение", "translit": "hораАт кЕва"}, {"he": "פקיד", "ru": "клерк / служащий", "translit": "пакИд"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (111, 3, 'באוטובוס', 'В автобусе', 'כל בוקר אני נוסע באוטובוס מהבית לעבודה. אני עולה על קו חמש מאות בתחנה שליד הבית בשבע וחצי. הנסיעה לוקחת כארבעים דקות תלוי בפקקים. בבוקר האוטובוסים מלאים ולפעמים אין מקום לשבת.
בשבוע שעבר קרה משהו מצחיק. עליתי לאוטובוס וגיליתי שאין כסף בכרטיס רב-קו. הנהג אמר שאפשר לטעון אצלו במזומן. חיפשתי בארנק ומצאתי רק עשרים שקלים. טענתי את הכרטיס ונסעתי. בדרך אישה מבוגרת עלתה ולא היו מקומות. קמתי ונתתי לה את המקום שלי.
הנסיעה באוטובוס היא הזדמנות לקרוא ספר או להאזין למוזיקה. אני מכיר כמה נוסעים קבועים ולפעמים אנחנו מדברים. למרות הפקקים, אני מעדיף אוטובוס על מכונית כי לא צריך לחפש חנייה.', 'Каждое утро я еду на автобусе из дома на работу. Я сажусь на маршрут пятьсот на остановке рядом с домом в половине восьмого. Поездка занимает около сорока минут, в зависимости от пробок. В утренние часы автобусы очень переполнены, и иногда нет места сесть.
В понедельник на прошлой неделе произошло кое-что смешное. Я сел в автобус и обнаружил, что на карте Рав-Кав нет денег. Водитель сказал, что можно пополнить карту у него за наличные. Я поискал в кошельке и нашёл только двадцать шекелей. Пополнил карту и поехал. По дороге вошла пожилая женщина, и свободных мест не было. Я встал и уступил ей своё место.
Поездка на автобусе — хорошая возможность почитать книгу, послушать музыку или просто смотреть в окно и думать. Я уже знаю нескольких постоянных пассажиров, и иногда мы разговариваем. Несмотря на пробки, я предпочитаю автобус машине, потому что не нужно искать парковку.', '[{"he": "אוטובוס", "ru": "автобус", "translit": "отобУс"}, {"he": "תחנה", "ru": "остановка", "translit": "таханА"}, {"he": "נהג", "ru": "водитель", "translit": "наhАг"}, {"he": "פקק", "ru": "пробка (на дороге)", "translit": "пкак"}, {"he": "נוסע", "ru": "пассажир", "translit": "носЕа"}, {"he": "מזומן", "ru": "наличные", "translit": "мезумАн"}, {"he": "ארנק", "ru": "кошелёк", "translit": "арнАк"}, {"he": "חנייה", "ru": "парковка", "translit": "ханайА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (112, 3, 'בסופרמרקט', 'В супермаркете', 'כל שישי אני הולך לסופרמרקט לקנות אוכל לסוף השבוע. אני מכין רשימת קניות לפני שיוצא מהבית כדי לא לשכוח כלום. ברשימה יש ירקות, פירות, לחם, חלב, גבינה ובשר.
בסופרמרקט שליד הבית יש מבצעים כל שבוע. לפעמים אפשר לקנות אחד ולקבל את השני בחצי מחיר. אני בודק את העלונים לפני כדי לדעת מה בהנחה. בחלק הירקות אני בוחר עגבניות, מלפפונים, בצל ופלפלים. בחלק המקרר לוקח חלב, יוגורט וגבינה צהובה.
בקופה תמיד יש תור, במיוחד ביום שישי. אני מעדיף את הקופה האוטומטית כי זה מהיר יותר. סורק את המוצרים, שם בשקית, משלם בכרטיס אשראי ויוצא. לפני שעוזב אני בודק את הקבלה כדי לוודא שלא חייבו אותי יותר מדי.', 'Каждую пятницу я хожу в супермаркет покупать еду на выходные. Перед выходом из дома я составляю список покупок, чтобы ничего не забыть. В списке обычно овощи, фрукты, хлеб, молоко, сыр, мясо и чистящие средства.
В супермаркете рядом с домом каждую неделю проходят акции. Иногда можно купить один товар и получить второй за полцены. Я всегда проверяю листовки перед походом, чтобы знать, что по скидке. В отделе овощей я выбираю помидоры, огурцы, лук и перцы. В отделе холодильника беру молоко, йогурт и жёлтый сыр.
На кассе всегда очередь, особенно в пятницу. Я предпочитаю пользоваться кассой самообслуживания, потому что так быстрее. Сканирую товары, кладу в пакет, плачу кредитной картой и выхожу. Перед уходом я проверяю чек, чтобы убедиться, что с меня не взяли лишнего. Так каждую пятницу я обеспечиваю еду на всю неделю.', '[{"he": "סופרמרקט", "ru": "супермаркет", "translit": "суперМаркет"}, {"he": "רשימת קניות", "ru": "список покупок", "translit": "решимАт книйОт"}, {"he": "מבצע", "ru": "акция / скидка", "translit": "мивцА"}, {"he": "קופה", "ru": "касса", "translit": "купА"}, {"he": "שקית", "ru": "пакет", "translit": "сакИт"}, {"he": "קבלה", "ru": "чек / квитанция", "translit": "кабалА"}, {"he": "הנחה", "ru": "скидка", "translit": "hанахА"}, {"he": "מוצר", "ru": "продукт / товар", "translit": "моцАр"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (118, 3, 'הייטק בישראל', 'Текст 32: Израиль', 'ישראל ידועה בכל העולם כאומת הסטארט-אפ. למרות שהיא מדינה קטנה, יש בה אלפי חברות הייטק שמפתחים טכנולוגיות חדשניות. תל אביב נחשבת למרכז ההייטק עם מאות חברות, ממשרדים קטנים ועד מגדלים ענקיים.
הרבה ישראלים עובדים בהייטק והמשכורות גבוהות. מהנדסים ומפתחים יכולים להרוויח עשרים עד ארבעים אלף שקלים בחודש. בגלל זה הרבה צעירים לומדים מדעי המחשב כדי להיכנס לתחום.
חברות בינלאומיות פתחו מרכזי פיתוח בישראל בגלל הכישרון המקומי. הצבא תורם גם לתעשייה כי חיילים ביחידות טכנולוגיות רוכשים ניסיון שימושי. יזמים ישראלים הקימו חברות שנמכרו במיליארדי דולרים. ההייטק שינה את הכלכלה הישראלית ויצר מעמד ביניים חדש.', 'Израиль известен во всём мире как нация стартапов. Несмотря на то что это маленькая страна, в ней тысячи хайтек-компаний и стартапов, разрабатывающих инновационные технологии. Тель-Авив считается хайтек-центром Израиля, и в нём сотни компаний — от маленьких офисов до гигантских башен.
Многие израильтяне работают в хайтеке, и зарплаты в этой сфере высокие. Программисты, разработчики и менеджеры продуктов могут зарабатывать от двадцати до сорока тысяч шекелей в месяц. Поэтому многие молодые люди изучают информатику в университете или на специальных курсах, чтобы войти в отрасль.
Крупные международные компании открыли центры разработки в Израиле благодаря местным талантам. Армия тоже вносит вклад в индустрию, так как солдаты в технологических подразделениях приобретают практический опыт. Израильские предприниматели создали компании, проданные за миллиарды долларов. Хайтек изменил израильскую экономику и общество, создав новый процветающий средний класс.', '[{"he": "הייטק", "ru": "хайтек", "translit": "hайтЕк"}, {"he": "סטארט-אפ", "ru": "стартап", "translit": "стАрт-ап"}, {"he": "מהנדס", "ru": "инженер", "translit": "меhандЕс"}, {"he": "טכנולוגיה", "ru": "технология", "translit": "технолОгия"}, {"he": "יזם", "ru": "предприниматель", "translit": "язАм"}, {"he": "פיתוח", "ru": "разработка", "translit": "питУах"}, {"he": "כלכלה", "ru": "экономика", "translit": "калкалА"}, {"he": "כישרון", "ru": "талант", "translit": "кишарОн"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (113, 3, 'אסיפת דיירים', 'Собрание жителей', 'אתמול בערב התקיימה אסיפת דיירים בבניין שלנו. נציג ועד הבית שלח הודעה לכל הדיירים וביקש מכולם להגיע. הנושא המרכזי היה תיקון הגג שדולף כבר כמה חודשים ותחזוקה כללית של הבניין.
עשרה דיירים הגיעו לאסיפה בלובי. הנציג הסביר שתיקון הגג יעלה כעשרים אלף שקלים וכל דירה תשלם חלק שווה. חלק מהדיירים התנגדו ורצו הצעות מחיר מקבלנים אחרים. אחרי דיון ארוך הצביעו והחליטו לקבל עוד שתי הצעות.
נושא נוסף היה ניקיון חדר המדרגות. כמה דיירים התלוננו שהמדרגות לא נקיות מספיק. החליטו להחליף את חברת הניקיון ולמצוא חברה חדשה במחיר סביר. גם דנו על מצלמות אבטחה בכניסה. האסיפה נגמרה מאוחר אבל הרגשנו שקידמנו נושאים חשובים.', 'Вчера вечером в нашем доме прошло собрание жильцов. Представитель домового комитета отправил сообщение всем жильцам в Ватсапе и попросил всех прийти. Главная тема — ремонт протекающей крыши, которая течёт уже несколько месяцев, и общее обслуживание здания.
Десять из двенадцати жильцов пришли на собрание, которое прошло в вестибюле дома. Представитель объяснил, что ремонт крыши обойдётся примерно в двадцать тысяч шекелей, и каждая квартира должна будет заплатить равную часть. Некоторые жильцы возразили против цены и хотели получить дополнительные сметы от других подрядчиков. После долгого обсуждения проголосовали и решили получить ещё два предложения.
Ещё одна тема, поднятая на собрании, — уборка подъезда. Несколько жильцов пожаловались, что лестница недостаточно чистая. Решили сменить клининговую компанию и найти новую по разумной цене. Также обсудили установку камер наблюдения у входа. Собрание закончилось поздно, но мы чувствовали, что продвинули важные вопросы.', '[{"he": "אסיפת דיירים", "ru": "собрание жильцов", "translit": "асифАт даярИм"}, {"he": "ועד הבית", "ru": "домовой комитет", "translit": "ваАд hа-бАйит"}, {"he": "דייר", "ru": "жилец", "translit": "даяр"}, {"he": "תחזוקה", "ru": "обслуживание / содержание", "translit": "тахзакА"}, {"he": "קבלן", "ru": "подрядчик", "translit": "каблАн"}, {"he": "הצעת מחיר", "ru": "ценовое предложение / смета", "translit": "hацаАт мехИр"}, {"he": "להצביע", "ru": "голосовать", "translit": "леhацбИа"}, {"he": "מצלמת אבטחה", "ru": "камера наблюдения", "translit": "мацлемАт автахА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (114, 3, 'חתונה ישראלית', 'Израильская свадьба', 'חתונה ישראלית היא אירוע גדול ושמח שמגיעים אליו מאות אורחים. החתונה מתקיימת באולם או בגן אירועים. האורחים מגיעים בערב, לובשים בגדים יפים ומביאים מתנה או מעטפה עם כסף לזוג.
טקס החופה הוא החלק המרכזי. החתן והכלה עומדים מתחת לחופה, הרב מברך שבע ברכות, החתן שם טבעת על אצבע הכלה ובסוף שובר כוס זכוכית ברגלו. כל האורחים צועקים מזל טוב. אחרי הטקס מתחילה המסיבה עם אוכל וריקודים.
הריקודים הם החלק הכי כיפי. מוזיקה שמחה מתנגנת והאורחים רוקדים במעגלים. מרימים את החתן והכלה על כיסאות ורוקדים איתם. האוכל עשיר ומגוון עם תחנות שונות כמו בשר, דגים, סלטים וקינוחים. החגיגה נמשכת עד מאוחר בלילה.', 'Израильская свадьба — это большое и радостное событие, на которое приходят сотни гостей. Свадьба обычно проходит в банкетном зале или саду для мероприятий. Гости приходят вечером, одеваются нарядно и приносят подарок или конверт с деньгами для молодожёнов.
Церемония хупы — центральная часть свадьбы. Жених и невеста стоят под хупой, раввин произносит семь благословений, жених надевает кольцо на палец невесте, а в конце разбивает стеклянный бокал ногой. Все гости кричат «мазаль тов» и радуются. После церемонии начинается вечеринка с едой, напитками и танцами.
Танцы — самая весёлая часть. Оркестр или записанная музыка играет весёлые песни, и гости танцуют в кругах. Жениха и невесту поднимают на стульях и танцуют с ними. Еда на израильских свадьбах богатая и разнообразная, с разными станциями: мясо, рыба, салаты и десерты. Празднование продолжается до поздней ночи.', '[{"he": "חתונה", "ru": "свадьба", "translit": "хатунА"}, {"he": "חתן", "ru": "жених", "translit": "хатАн"}, {"he": "כלה", "ru": "невеста", "translit": "калА"}, {"he": "חופה", "ru": "хупа (свадебный балдахин)", "translit": "хупА"}, {"he": "טבעת", "ru": "кольцо", "translit": "табАат"}, {"he": "ברכה", "ru": "благословение", "translit": "брахА"}, {"he": "מזל טוב", "ru": "поздравляю (букв. удачи)", "translit": "мазАль тов"}, {"he": "ריקוד", "ru": "танец", "translit": "рикУд"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (115, 3, 'שוק הכרמל בתל אביב', 'Текст 29: Израиль', 'שוק הכרמל הוא השוק הגדול והמפורסם ביותר בתל אביב. הוא נמצא ליד שכונת נווה צדק ופתוח כל יום חוץ משבת. בשוק יש מאות דוכנים שמוכרים פירות, ירקות, תבלינים, בשר, דגים, בגדים ומזכרות.
האווירה בשוק חיה וצבעונית. המוכרים צועקים ומציעים את הסחורה, ריחות של תבלינים ואוכל טרי ממלאים את האוויר. ביום שישי השוק מלא כי כולם קונים לשבת. לקראת הסגירה המחירים יורדים ואפשר למצוא מציאות.
בשנים האחרונות השוק הפך גם למרכז בילוי. בסמטאות שמסביב נפתחו מסעדות, ברים ובתי קפה. בערב אפשר לאכול אוכל רחוב מעולה כמו סביח ושווארמה. שוק הכרמל הוא מקום שכל תייר ותושב חייבים להכיר.', 'Рынок Кармель — самый большой и известный рынок в Тель-Авиве. Он находится на улице Кармель рядом с районом Неве-Цедек и открыт каждый день, кроме субботы. На рынке сотни прилавков, где продают фрукты, овощи, специи, мясо, рыбу, одежду и сувениры.
Атмосфера на рынке живая и красочная. Продавцы кричат и предлагают свой товар, запахи специй и свежей еды наполняют воздух. В пятницу рынок особенно полон, потому что все покупают к субботе. Ближе к закрытию рынка в пятницу цены снижаются, и можно найти выгодные покупки.
В последние годы рынок стал также центром еды и развлечений. В переулках вокруг открылись маленькие рестораны, бары и кафе. Вечером можно сесть и поесть отличную уличную еду — сабих, шаварму или пиццу. Рынок Кармель — место, которое должен знать каждый турист и житель.', '[{"he": "שוק", "ru": "рынок", "translit": "шук"}, {"he": "דוכן", "ru": "прилавок / стенд", "translit": "духАн"}, {"he": "מוכר", "ru": "продавец", "translit": "мохЕр"}, {"he": "סחורה", "ru": "товар", "translit": "схорА"}, {"he": "מציאה", "ru": "выгодная покупка", "translit": "мециА"}, {"he": "סמטה", "ru": "переулок", "translit": "симтА"}, {"he": "אוכל רחוב", "ru": "уличная еда", "translit": "Охель рехОв"}, {"he": "מזכרת", "ru": "сувенир", "translit": "мазкЕрет"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (116, 3, 'טיול בנגב', 'Текст 30: Израиль', 'מדבר הנגב תופס יותר ממחצית שטח ישראל, אבל מעט אנשים גרים בו. הנגב הוא מקום מיוחד עם נופים מרהיבים, מכתשים ענקיים ושמיים זרועי כוכבים בלילה. כל שנה אלפי ישראלים ותיירים יוצאים לטיול במדבר.
המקום המפורסם ביותר הוא מכתש רמון, המכתש הגדול בעולם. אפשר לטייל בו ברגל, באופניים או בג''יפ. בעיירה מצפה רמון יש אכסניה ומלונות ומשם יוצאים לסיורים. בלילה אפשר לצפות בכוכבים כי אין כמעט זיהום אור.
עוד מקומות מומלצים הם עין אבדת, נחל ארוד ופארק תמנע ליד אילת. חשוב לקחת הרבה מים ולהתחיל מוקדם בבוקר כי החום חזק מאוד. הנגב הוא הוכחה שגם מדבר יכול להיות מלא חיים ויופי.', 'Пустыня Негев занимает более половины территории Израиля, но живёт в ней мало людей. Негев — особенное место с потрясающими пейзажами, огромными кратерами и усыпанным звёздами небом по ночам. Каждый год тысячи израильтян и туристов отправляются в поход по пустыне.
Самое известное место в Негеве — кратер Рамон, крупнейший кратер в мире. Там можно гулять пешком, на велосипедах или на джипе. В городке Мицпе-Рамон рядом с кратером есть хостел и гостиницы, откуда отправляются на экскурсии. Ночью можно наблюдать звёзды, потому что в районе почти нет светового загрязнения.
Другие рекомендуемые места в Негеве — Эйн-Авдат, ручей Арод и парк Тимна возле Эйлата. Важно брать много воды и начинать поход рано утром, потому что жара в пустыне очень сильная. Негев — доказательство того, что даже пустыня может быть полна жизни, красоты и сюрпризов.', '[{"he": "מדבר", "ru": "пустыня", "translit": "мидбАр"}, {"he": "נגב", "ru": "Негев", "translit": "нЕгев"}, {"he": "מכתש", "ru": "кратер", "translit": "махтЕш"}, {"he": "נוף", "ru": "пейзаж / вид", "translit": "ноф"}, {"he": "כוכבים", "ru": "звёзды", "translit": "кохавИм"}, {"he": "אכסניה", "ru": "хостел / гостиница", "translit": "ахсанийА"}, {"he": "זיהום אור", "ru": "световое загрязнение", "translit": "зиhУм ор"}, {"he": "מדברי", "ru": "пустынный", "translit": "мидбарИ"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (117, 3, 'חיי יום יום בירושלים', 'Текст 31: Израиль', 'ירושלים היא עיר מיוחדת שבה החיים שונים מכל מקום אחר. בעיר גרים יהודים, מוסלמים ונוצרים זה לצד זה. העיר העתיקה עם החומות היא הלב של ירושלים ובתוכה הכותל המערבי, כנסיית הקבר ומסגד אל-אקצא.
החיים מתחילים מוקדם. בבוקר הרחובות מתמלאים באנשים שהולכים לעבודה ותיירים שמטיילים. שוק מחנה יהודה שוקק חיים עם פירות, מאפים ותבלינים. הירושלמים אוהבים לשבת בבתי קפה ולדבר על פוליטיקה.
מזג האוויר שונה מתל אביב. בחורף קר ולפעמים יורד שלג, ובקיץ חם אבל יבש. הערבים נעימים ואנשים אוהבים לטייל בשכונות עתיקות כמו נחלאות ועין כרם. ירושלים היא עיר של היסטוריה ודת, אבל גם עיר מודרנית עם אוניברסיטאות ומוזיאונים.', 'Иерусалим — особый город, где жизнь отличается от любого другого места в Израиле. В городе живут евреи, мусульмане и христиане бок о бок. Старый город со своими стенами — сердце Иерусалима, и внутри него Стена Плача, Храм Гроба Господня и мечеть Аль-Акса.
Жизнь в Иерусалиме начинается рано. В утренние часы улицы наполняются людьми, идущими на работу, детьми, едущими в школу, и туристами на прогулке. Рынок Махане Иегуда кипит жизнью весь день — свежие фрукты, выпечка и специи. Жители Иерусалима любят сидеть в кафе и разговаривать о политике и жизни.
Погода в Иерусалиме отличается от Тель-Авива. Зимой холодно, иногда идёт снег, а летом жарко, но сухо. Вечера очень приятные, и люди любят гулять по старым районам — Нахлаот, Эйн-Керем и Мишкенот Шаананим. Иерусалим — город истории и религии, но также живой и современный город с университетами, театрами и музеями.', '[{"he": "ירושלים", "ru": "Иерусалим", "translit": "ерушалАим"}, {"he": "עיר עתיקה", "ru": "старый город", "translit": "ир атикА"}, {"he": "כותל", "ru": "Стена (Плача)", "translit": "кОтель"}, {"he": "מסגד", "ru": "мечеть", "translit": "мисгАд"}, {"he": "כנסייה", "ru": "церковь", "translit": "кнесийА"}, {"he": "שוקק חיים", "ru": "кипящий жизнью", "translit": "шокЕк хаИм"}, {"he": "מאפה", "ru": "выпечка", "translit": "маафЕ"}, {"he": "מוזיאון", "ru": "музей", "translit": "музеОн"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (201, 1, 'המשפחה שלי', 'Моя семья', 'שלום! אני דני. אני בן עשר. אני גר בתל אביב עם המשפחה שלי.
יש לי אמא ואבא. אמא שלי רופאה. היא עובדת בבית חולים. אבא שלי מורה. הוא מלמד מתמטיקה בבית ספר.
יש לי אחות קטנה. השם שלה מיכל. מיכל בת שלוש. היא מאוד מצחיקה. היא אוהבת לשחק עם בובות. לפעמים היא בוכה בלילה.
יש לי גם כלב. השם שלו שוקו. שוקו חום וקטן. הוא אוהב לרוץ בפארק.
בשבת כל המשפחה ביחד. אנחנו אוכלים ארוחת בוקר גדולה. אבא עושה ביצים. אמא עושה סלט. אחר כך אנחנו הולכים לפארק או לים. אני אוהב את המשפחה שלי מאוד!', 'Привет! Я Дони. Мне десять лет. Я живу в Тель-Авиве со своей семьёй.
У меня есть мама и папа. Моя мама — врач. Она работает в больнице. Мой папа — учитель. Он преподаёт математику в школе.
У меня есть младшая сестра. Её зовут Михаль. Михаль три года. Она очень смешная. Она любит играть с куклами. Иногда она плачет ночью.
У меня ещё есть собака. Её зовут Шоко. Шоко коричневый и маленький. Он любит бегать в парке.
В субботу вся семья вместе. Мы едим большой завтрак. Папа готовит яичницу. Мама делает салат. Потом мы идём в парк или на море. Я очень люблю свою семью!', '[{"he": "משפחה", "ru": "семья", "translit": "мишпахА"}, {"he": "אחות", "ru": "сестра", "translit": "ахОт"}, {"he": "קטנה", "ru": "маленькая", "translit": "ктанА"}, {"he": "גרים", "ru": "живём", "translit": "гарИм"}, {"he": "אוהב", "ru": "люблю", "translit": "оhЕв"}, {"he": "רופאה", "ru": "врач (ж.)", "translit": "рофаА"}, {"he": "מורה", "ru": "учитель", "translit": "морЕ"}, {"he": "בובות", "ru": "куклы", "translit": "бубОт"}, {"he": "ארוחת בוקר", "ru": "завтрак", "translit": "арухАт бОкер"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (202, 1, 'בבית', 'Дома', 'הבית שלי קטן אבל יפה מאוד. אני גר בקומה השנייה.
בבית יש סלון גדול. בסלון יש ספה ירוקה, שולחן וטלוויזיה. אנחנו אוהבים לשבת בסלון בערב ולראות סרטים.
המטבח ליד הסלון. במטבח יש שולחן עם ארבעה כיסאות. אמא מבשלת במטבח כל יום. אני אוהב את האוכל של אמא.
יש לי חדר קטן. בחדר יש מיטה, שולחן ומדפים עם ספרים. על הקיר יש תמונות של חברים. החלון גדול ואני רואה עצים בחוץ.
יש גם חדר אמבטיה עם מקלחת. בבוקר אני מתקלח במים חמים. אני אוהב את הבית שלי. הוא מקום טוב ושקט.', 'Мой дом маленький, но очень красивый. Я живу на втором этаже.
В доме есть большая гостиная. В гостиной зелёный диван, стол и телевизор. Мы любим сидеть в гостиной вечером и смотреть фильмы.
Кухня рядом с гостиной. На кухне стол с четырьмя стульями. Мама готовит на кухне каждый день. Мне нравится мамина еда.
У меня маленькая комната. В комнате есть кровать, стол и полки с книгами. На стене фотографии друзей. Окно большое, и я вижу деревья на улице.
Есть также ванная комната с душем. Утром я принимаю горячий душ. Я люблю свой дом. Это хорошее и тихое место.', '[{"he": "בית", "ru": "дом", "translit": "бАйит"}, {"he": "סלון", "ru": "гостиная", "translit": "салОн"}, {"he": "מטבח", "ru": "кухня", "translit": "митбАх"}, {"he": "ספה", "ru": "диван", "translit": "сапА"}, {"he": "לשבת", "ru": "сидеть", "translit": "лашЕвет"}, {"he": "קומה", "ru": "этаж", "translit": "комА"}, {"he": "מדפים", "ru": "полки", "translit": "мадафИм"}, {"he": "מקלחת", "ru": "душ", "translit": "миклАхат"}, {"he": "שקט", "ru": "тихий", "translit": "шакЕт"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (219, 1, 'באוטובוס', 'В автобусе', 'אני נוסע באוטובוס כל יום לבית ספר. האוטובוס מגיע בשבע וחצי.
אני עומד בתחנה ומחכה. יש עוד אנשים בתחנה — אישה עם תיק, סטודנט עם אוזניות, וזוג זקנים.
האוטובוס מגיע. אני עולה ומראה את הכרטיס לנהג. "בוקר טוב!" אני אומר. "בוקר טוב!" הנהג עונה.
אני מחפש מקום לשבת. יש מקום ליד החלון. מצוין! אני אוהב לשבת ליד החלון ולהסתכל החוצה.
האוטובוס נוסע ברחובות. אני רואה חנויות, עצים, מכוניות ואנשים שהולכים ברגל. אנחנו עוברים ליד פארק גדול עם עצים ירוקים.
אחרי עשרים דקות האוטובוס עוצר בתחנה ליד בית הספר. אני יורד ואומר: "תודה!" הנהג מחייך.
אני רץ לשער של בית הספר. עוד דקה ובית ספר מתחיל!', 'Я езжу на автобусе каждый день в школу. Автобус приходит в половине восьмого.
Я стою на остановке и жду. На остановке ещё люди — женщина с сумкой, студент в наушниках и пожилая пара.
Автобус приходит. Я захожу и показываю проездной водителю. «Доброе утро!» — говорю я. «Доброе утро!» — отвечает водитель.
Я ищу место. Есть место у окна. Отлично! Я люблю сидеть у окна и смотреть наружу.
Автобус едет по улицам. Я вижу магазины, деревья, машины и пешеходов. Мы проезжаем мимо большого парка с зелёными деревьями.
Через двадцать минут автобус останавливается рядом со школой. Я выхожу и говорю: «Спасибо!» Водитель улыбается.
Я бегу к воротам школы. Ещё минута — и занятия начнутся!', '[{"he": "אוטובוס", "ru": "автобус", "translit": "отобУс"}, {"he": "נוסע", "ru": "еду", "translit": "носЕа"}, {"he": "חלון", "ru": "окно", "translit": "халОн"}, {"he": "עוצר", "ru": "останавливается", "translit": "оцЕр"}, {"he": "נהג", "ru": "водитель", "translit": "наhАг"}, {"he": "תחנה", "ru": "остановка", "translit": "таханА"}, {"he": "כרטיס", "ru": "билет", "translit": "картИс"}, {"he": "מחייך", "ru": "улыбается", "translit": "мехайЕх"}, {"he": "שער", "ru": "ворота", "translit": "шаАр"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (203, 1, 'בוקר טוב', 'Доброе утро', 'בבוקר אני קם מוקדם. השעון מצלצל בשבע. אני לא אוהב לקום מוקדם, אבל צריך.
אני הולך לחדר האמבטיה. אני שוטף את הפנים ומצחצח שיניים. אחר כך אני לובש בגדים — חולצה, מכנסיים ונעליים.
במטבח אני אוכל ארוחת בוקר. אני שותה חלב ואוכל לחם עם גבינה. לפעמים אני אוכל גם ביצה. אמא אומרת: "תאכל! ארוחת בוקר חשובה."
אני שם את הספרים בתיק ויוצא מהבית. בדרך לבית ספר אני פוגש את החבר שלי יוסי. "בוקר טוב, יוסי!" אני אומר. "בוקר טוב, דני!" הוא אומר. אנחנו הולכים ביחד לבית ספר. השמש זורחת והיום יפה.', 'Утром я встаю рано. Будильник звонит в семь. Я не люблю вставать рано, но надо.
Я иду в ванную. Умываю лицо и чищу зубы. Потом я одеваюсь — рубашка, штаны и ботинки.
На кухне я ем завтрак. Я пью молоко и ем хлеб с сыром. Иногда я ем ещё яйцо. Мама говорит: «Ешь! Завтрак — это важно.»
Я кладу книги в рюкзак и выхожу из дома. По дороге в школу я встречаю друга Йоси. «Доброе утро, Йоси!» — говорю я. «Доброе утро, Дони!» — говорит он. Мы идём вместе в школу. Солнце светит, и день красивый.', '[{"he": "בוקר", "ru": "утро", "translit": "бОкер"}, {"he": "קם", "ru": "встаю", "translit": "кам"}, {"he": "שותה", "ru": "пью", "translit": "шотЕ"}, {"he": "חלב", "ru": "молоко", "translit": "халАв"}, {"he": "הולך", "ru": "иду", "translit": "олЕх"}, {"he": "שעון", "ru": "часы/будильник", "translit": "шаОн"}, {"he": "בגדים", "ru": "одежда", "translit": "бгадИм"}, {"he": "תיק", "ru": "рюкзак/сумка", "translit": "тик"}, {"he": "פוגש", "ru": "встречаю", "translit": "погЕш"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (204, 1, 'הכלב שלי', 'Моя собака', 'יש לי כלב. השם שלו רקס. רקס כלב גדול וחום. הוא בן שלוש.
בבוקר רקס קם ורוצה לאכול. אני נותן לו אוכל ומים. אחרי האוכל הוא רוצה לצאת. אני לוקח אותו לפארק ליד הבית.
בפארק רקס רץ מהר מאוד. הוא אוהב לרוץ אחרי כדור. אני זורק את הכדור והוא מביא אותו בחזרה. לפעמים הוא משחק עם כלבים אחרים.
רקס כלב חכם. הוא יודע לשבת, לתת יד ולשכב. כשאני אומר "שב!" הוא יושב. כשאני אומר "יד!" הוא נותן יד.
בערב רקס שוכב ליד הספה ושומר עלינו. הוא חבר טוב ונאמן. כל המשפחה אוהבת את רקס.', 'У меня есть собака. Его зовут Рекс. Рекс — большая коричневая собака. Ему три года.
Утром Рекс встаёт и хочет есть. Я даю ему еду и воду. После еды он хочет выйти. Я беру его в парк рядом с домом.
В парке Рекс бегает очень быстро. Он любит бегать за мячом. Я бросаю мяч, и он приносит его обратно. Иногда он играет с другими собаками.
Рекс — умная собака. Он умеет сидеть, давать лапу и ложиться. Когда я говорю «Сидеть!», он садится. Когда я говорю «Лапу!», он даёт лапу.
Вечером Рекс лежит рядом с диваном и охраняет нас. Он хороший и верный друг. Вся семья любит Рекса.', '[{"he": "כלב", "ru": "собака", "translit": "кЕлев"}, {"he": "גדול", "ru": "большой", "translit": "гадОль"}, {"he": "לרוץ", "ru": "бегать", "translit": "ларУц"}, {"he": "פארק", "ru": "парк", "translit": "парк"}, {"he": "משחק", "ru": "играю", "translit": "месахЕк"}, {"he": "כדור", "ru": "мяч", "translit": "кадУр"}, {"he": "חכם", "ru": "умный", "translit": "хахАм"}, {"he": "נאמן", "ru": "верный", "translit": "нээмАн"}, {"he": "זורק", "ru": "бросаю", "translit": "зорЕк"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (205, 1, 'בחנות', 'В магазине', 'היום אני הולך לחנות עם אמא. אנחנו צריכים לקנות אוכל לשבת.
בחנות אני לוקח עגלה. אמא אומרת: "אנחנו צריכים לחם, חלב, ביצים ופירות." אנחנו הולכים למדף הלחם. יש לחם לבן ולחם שחור. אמא לוקחת לחם לבן.
אחר כך אנחנו הולכים למדף הפירות. יש תפוחים, בננות, תפוזים וענבים. "אני רוצה תפוחים אדומים," אני אומר. אמא שמה תפוחים וענבים בעגלה.
אנחנו גם קונים גבינה, שוקולד ומיץ תפוזים.
בקופה אני שואל: "כמה זה עולה?" "מאה ועשרים שקלים," אומרת המוכרת. אמא משלמת בכרטיס אשראי. "תודה רבה!" אנחנו אומרים. אנחנו שמים את השקיות ברכב ונוסעים הביתה.', 'Сегодня я иду в магазин с мамой. Нам нужно купить еду к субботе.
В магазине я беру тележку. Мама говорит: «Нам нужны хлеб, молоко, яйца и фрукты.» Мы идём к полке с хлебом. Есть белый хлеб и чёрный хлеб. Мама берёт белый.
Потом мы идём к фруктам. Есть яблоки, бананы, апельсины и виноград. «Я хочу красные яблоки,» — говорю я. Мама кладёт яблоки и виноград в тележку.
Мы также покупаем сыр, шоколад и апельсиновый сок.
На кассе я спрашиваю: «Сколько это стоит?» «Сто двадцать шекелей,» — говорит продавщица. Мама платит кредитной картой. «Большое спасибо!» — говорим мы. Мы кладём пакеты в машину и едем домой.', '[{"he": "חנות", "ru": "магазин", "translit": "ханУт"}, {"he": "קונה", "ru": "покупаю", "translit": "конЕ"}, {"he": "ביצים", "ru": "яйца", "translit": "бейцИм"}, {"he": "פירות", "ru": "фрукты", "translit": "перОт"}, {"he": "שקלים", "ru": "шекели", "translit": "шкалИм"}, {"he": "עגלה", "ru": "тележка", "translit": "агалА"}, {"he": "מדף", "ru": "полка", "translit": "мадАф"}, {"he": "משלמת", "ru": "платит (ж.)", "translit": "мешалЕмет"}, {"he": "שקיות", "ru": "пакеты", "translit": "сакийОт"}]', NULL, 'dialogue');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (206, 1, 'מזג האוויר', 'Погода', 'בישראל יש ארבע עונות: אביב, קיץ, סתיו וחורף.
בקיץ חם מאוד. השמש זורחת כל יום. אין גשם. אנשים הולכים לים ושותים הרבה מים. בלילה גם חם. אנחנו פותחים את המזגן.
בחורף קר ויש גשם. לפעמים יש רוח חזקה. אנחנו לובשים מעיל, כובע וצעיף. בירושלים לפעמים יש שלג! ילדים שמחים כשיש שלג.
באביב מזג האוויר נעים. לא חם ולא קר. יש פרחים יפים בכל מקום. זו העונה הכי טובה לטיולים.
בסתיו הימים קצרים יותר. יש רוח קלה. העלים נופלים מהעצים. אני אוהב את כל העונות, אבל הכי אוהב את האביב.', 'В Израиле четыре времени года: весна, лето, осень и зима.
Летом очень жарко. Солнце светит каждый день. Дождя нет. Люди ходят на море и пьют много воды. Ночью тоже жарко. Мы включаем кондиционер.
Зимой холодно и идёт дождь. Иногда бывает сильный ветер. Мы надеваем куртку, шапку и шарф. В Иерусалиме иногда бывает снег! Дети радуются, когда идёт снег.
Весной погода приятная. Не жарко и не холодно. Везде красивые цветы. Это лучшее время года для прогулок.
Осенью дни становятся короче. Дует лёгкий ветер. Листья падают с деревьев. Мне нравятся все времена года, но больше всего — весна.', '[{"he": "חם", "ru": "жарко", "translit": "хам"}, {"he": "שמש", "ru": "солнце", "translit": "шЕмеш"}, {"he": "ים", "ru": "море", "translit": "ям"}, {"he": "קריר", "ru": "прохладно", "translit": "карИр"}, {"he": "גשם", "ru": "дождь", "translit": "гЕшем"}, {"he": "עונות", "ru": "времена года", "translit": "онОт"}, {"he": "מעיל", "ru": "куртка", "translit": "меИль"}, {"he": "שלג", "ru": "снег", "translit": "шЕлег"}, {"he": "פרחים", "ru": "цветы", "translit": "прахИм"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (207, 1, 'בבית הספר', 'В школе', 'אני לומד בבית ספר ליד הבית. אני בכיתה ד''. בכיתה יש עשרים וחמישה תלמידים.
בבוקר יש שלושה שיעורים. השיעור הראשון — עברית. המורה שלנו, גברת כהן, מלמדת אותנו לקרוא ולכתוב. אני אוהב עברית.
השיעור השני — מתמטיקה. אנחנו לומדים חיבור וחיסור. מתמטיקה קשה, אבל המורה מסביר טוב.
אחרי שני שיעורים יש הפסקה. בהפסקה אנחנו יוצאים לחצר. אני משחק כדורגל עם חברים. אנחנו גם אוכלים כריך ושותים מים.
אחרי ההפסקה יש עוד שיעור — אנגלית. אנחנו לומדים מילים חדשות.
בשתיים אני חוזר הביתה. אני אוכל ארוחת צהריים ואחר כך עושה שיעורי בית. אני אוהב את בית הספר!', 'Я учусь в школе рядом с домом. Я в четвёртом классе. В классе двадцать пять учеников.
Утром три урока. Первый урок — иврит. Наша учительница, госпожа Коэн, учит нас читать и писать. Мне нравится иврит.
Второй урок — математика. Мы учим сложение и вычитание. Математика трудная, но учитель хорошо объясняет.
После двух уроков — перемена. На перемене мы выходим во двор. Я играю в футбол с друзьями. Мы также едим бутерброды и пьём воду.
После перемены ещё один урок — английский. Мы учим новые слова.
В два часа я возвращаюсь домой. Ем обед и потом делаю домашние задания. Мне нравится моя школа!', '[{"he": "לומד", "ru": "учусь", "translit": "ломЕд"}, {"he": "מורה", "ru": "учитель", "translit": "морА/морЕ"}, {"he": "שיעורים", "ru": "уроки", "translit": "шиурИм"}, {"he": "חברים", "ru": "друзья", "translit": "хаверИм"}, {"he": "כיתה", "ru": "класс", "translit": "китА"}, {"he": "הפסקה", "ru": "перемена", "translit": "хафсакА"}, {"he": "חצר", "ru": "двор", "translit": "хацЕр"}, {"he": "כריך", "ru": "бутерброд", "translit": "карИх"}, {"he": "שיעורי בית", "ru": "домашние задания", "translit": "шиурЕй бАйит"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (208, 1, 'ארוחת ערב', 'Ужин', 'בערב כל המשפחה אוכלת ביחד. זה הזמן הכי טוב ביום.
אמא מבשלת במטבח. היום היא עושה אורז עם ירקות ודגים. הריח טוב מאוד. "אמא, מתי האוכל מוכן?" אני שואל. "עוד עשר דקות," היא עונה.
אבא חוזר מהעבודה. "שלום לכולם!" הוא אומר. הוא שוטף ידיים ובא לשולחן. אני עוזר — שם צלחות, כוסות ומזלגות על השולחן.
אנחנו יושבים ואוכלים. "האוכל טעים מאוד!" אומר אבא. "תודה, אמא!" אני אומר. אנחנו מדברים על היום — מה היה בבית ספר, מה היה בעבודה.
אחרי האוכל אני עוזר לאמא לשטוף כלים. אחר כך אנחנו שותים תה ואוכלים עוגה שסבתא שלחה.', 'Вечером вся семья ест вместе. Это лучшее время дня.
Мама готовит на кухне. Сегодня она делает рис с овощами и рыбу. Запах очень вкусный. «Мама, когда будет готово?» — спрашиваю я. «Ещё десять минут,» — отвечает она.
Папа возвращается с работы. «Привет всем!» — говорит он. Он моет руки и садится за стол. Я помогаю — кладу тарелки, стаканы и вилки на стол.
Мы сидим и едим. «Еда очень вкусная!» — говорит папа. «Спасибо, мама!» — говорю я. Мы разговариваем о прошедшем дне — что было в школе, что было на работе.
После еды я помогаю маме мыть посуду. Потом мы пьём чай и едим торт, который прислала бабушка.', '[{"he": "ארוחת ערב", "ru": "ужин", "translit": "арухАт Эрев"}, {"he": "מבשלת", "ru": "готовит", "translit": "мевашЕлет"}, {"he": "אורז", "ru": "рис", "translit": "Орез"}, {"he": "טעים", "ru": "вкусный", "translit": "таИм"}, {"he": "תה", "ru": "чай", "translit": "тэ"}, {"he": "צלחות", "ru": "тарелки", "translit": "цалахОт"}, {"he": "כוסות", "ru": "стаканы", "translit": "косОт"}, {"he": "לשטוף", "ru": "мыть", "translit": "лиштОф"}, {"he": "עוזר", "ru": "помогаю", "translit": "озЕр"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (209, 1, 'בגן החיות', 'В зоопарке', 'היום יום שישי. אנחנו הולכים לגן החיות. אני שמח מאוד!
בכניסה אבא קונה כרטיסים. "שני מבוגרים ושני ילדים, בבקשה." אנחנו מקבלים מפה של גן החיות.
קודם אנחנו רואים את האריות. יש אריה גדול עם רעמה. הוא שוכב בשמש. ליד האריות יש נמרים. הנמרים יפים מאוד.
אחר כך אנחנו הולכים לראות קופים. הקופים מצחיקים. הם קופצים מעץ לעץ ואוכלים בננות. אחותי צוחקת.
יש גם ג''ירפות גבוהות, פילים ענקיים ופינגווינים קטנים. הפינגווינים שוחים במים ואני מצלם אותם.
בסוף אנחנו אוכלים גלידה ויושבים על ספסל. "זה היה כיף!" אני אומר. "כן, נבוא שוב," אומר אבא.', 'Сегодня пятница. Мы идём в зоопарк. Я очень рад!
У входа папа покупает билеты. «Два взрослых и два детских, пожалуйста.» Мы получаем карту зоопарка.
Сначала мы смотрим на львов. Есть большой лев с гривой. Он лежит на солнце. Рядом со львами — леопарды. Леопарды очень красивые.
Потом мы идём смотреть на обезьян. Обезьяны смешные. Они прыгают с дерева на дерево и едят бананы. Моя сестра смеётся.
Есть ещё высокие жирафы, огромные слоны и маленькие пингвины. Пингвины плавают в воде, и я их фотографирую.
В конце мы едим мороженое и сидим на скамейке. «Было весело!» — говорю я. «Да, приедем ещё раз,» — говорит папа.', '[{"he": "גן חיות", "ru": "зоопарк", "translit": "ган хайОт"}, {"he": "אריה", "ru": "лев", "translit": "арьЕ"}, {"he": "קוף", "ru": "обезьяна", "translit": "коф"}, {"he": "מצחיק", "ru": "смешной", "translit": "мацхИк"}, {"he": "גבוהה", "ru": "высокая", "translit": "гвоhА"}, {"he": "כרטיסים", "ru": "билеты", "translit": "картисИм"}, {"he": "מפה", "ru": "карта", "translit": "мапА"}, {"he": "פילים", "ru": "слоны", "translit": "пилИм"}, {"he": "מצלם", "ru": "фотографирую", "translit": "мецалЕм"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (210, 1, 'יום שבת', 'Суббота', 'שבת הוא היום הכי טוב בשבוע. ביום שבת אנחנו לא עובדים ולא לומדים.
ביום שישי בערב אמא מדליקה נרות. אבא אומר קידוש על היין. אנחנו אוכלים חלה וארוחה טעימה — מרק, דגים, בשר ואורז.
בשבת בבוקר אנחנו ישנים הרבה. אני קם בעשר! אין בית ספר, אין שעון מעורר.
אחרי ארוחת בוקר אנחנו הולכים לסבא ולסבתא. הם גרים קרוב. סבא מספר סיפורים מצחיקים. סבתא מבשלת אוכל טעים — עוגת שוקולד, עוגיות ומרק.
אחר הצהריים אני משחק עם חברים בחצר. אנחנו משחקים כדורגל או רוכבים על אופניים.
בערב אנחנו חוזרים הביתה. אבא אומר הבדלה. "שבוע טוב!" כולם אומרים. שבת שלום!', 'Суббота — лучший день недели. В субботу мы не работаем и не учимся.
В пятницу вечером мама зажигает свечи. Папа произносит кидуш над вином. Мы едим халу и вкусный ужин — суп, рыбу, мясо и рис.
В субботу утром мы долго спим. Я встаю в десять! Нет школы, нет будильника.
После завтрака мы идём к дедушке и бабушке. Они живут близко. Дедушка рассказывает смешные истории. Бабушка готовит вкусную еду — шоколадный торт, печенье и суп.
После обеда я играю с друзьями во дворе. Мы играем в футбол или катаемся на велосипедах.
Вечером мы возвращаемся домой. Папа делает авдалу. «Хорошей недели!» — говорят все. Шабат Шалом!', '[{"he": "שבת", "ru": "суббота", "translit": "шабАт"}, {"he": "עובדים", "ru": "работаем", "translit": "овдИм"}, {"he": "ישנים", "ru": "спим", "translit": "йешенИм"}, {"he": "סבא", "ru": "дедушка", "translit": "сАба"}, {"he": "סבתא", "ru": "бабушка", "translit": "сАвта"}, {"he": "נרות", "ru": "свечи", "translit": "нерОт"}, {"he": "חלה", "ru": "хала (хлеб)", "translit": "халА"}, {"he": "אופניים", "ru": "велосипед", "translit": "офанАйим"}, {"he": "סיפורים", "ru": "рассказы", "translit": "сипурИм"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (211, 1, 'הצבעים', 'Цвета', 'העולם מלא צבעים יפים! אני רואה צבעים בכל מקום.
בבוקר אני מסתכל מהחלון. השמיים כחולים. העצים ירוקים. הפרחים בגינה אדומים, צהובים וסגולים. העננים לבנים.
בבית הספר אנחנו מציירים. המורה נותנת לנו צבעי מים. אני מצייר בית עם גג אדום, דלת חומה וחלונות צהובים. יש עץ ירוק ליד הבית ושמש כתומה.
החבר שלי דוד מצייר ים כחול עם דגים צבעוניים — כתומים, ירוקים ואדומים.
אני שואל את אמא: "מה הצבע האהוב עליך?" "כחול," היא עונה. "ומה שלך?" "ירוק!" אני עונה. "כי ירוק — זה צבע של עצים, של דשא, של טבע."
אבא אוהב את הצבע האדום. הרכב שלנו אדום!', 'Мир полон красивых цветов! Я вижу цвета повсюду.
Утром я смотрю из окна. Небо голубое. Деревья зелёные. Цветы в саду красные, жёлтые и фиолетовые. Облака белые.
В школе мы рисуем. Учительница даёт нам акварельные краски. Я рисую дом с красной крышей, коричневой дверью и жёлтыми окнами. Рядом с домом зелёное дерево и оранжевое солнце.
Мой друг Давид рисует голубое море с разноцветными рыбками — оранжевыми, зелёными и красными.
Я спрашиваю маму: «Какой твой любимый цвет?» «Голубой,» — отвечает она. «А твой?» «Зелёный!» — отвечаю я. «Потому что зелёный — это цвет деревьев, травы, природы.»
Папа любит красный цвет. Наша машина красная!', '[{"he": "צבעים", "ru": "цвета", "translit": "цваИм"}, {"he": "כחולים", "ru": "голубые", "translit": "кхулИм"}, {"he": "ירוקים", "ru": "зелёные", "translit": "ерукИм"}, {"he": "אדומים", "ru": "красные", "translit": "адумИм"}, {"he": "לבן", "ru": "белый", "translit": "лавАн"}, {"he": "מצייר", "ru": "рисую", "translit": "мецайЕр"}, {"he": "סגול", "ru": "фиолетовый", "translit": "сагОль"}, {"he": "כתום", "ru": "оранжевый", "translit": "катОм"}, {"he": "דשא", "ru": "трава", "translit": "дЕше"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (212, 1, 'מכתב לחבר', 'Письмо другу', 'שלום חבר יקר!
מה שלומך? אני מקווה שהכל בסדר. אני רוצה לספר לך על החיים שלי בחיפה.
אנחנו גרים עכשיו בדירה חדשה על הכרמל. מהחלון אני רואה את הים! העיר מאוד יפה. יש הר גדול, ויש ים כחול.
אני לומד בבית ספר חדש. בהתחלה היה קשה, כי לא הכרתי אף אחד. אבל עכשיו יש לי חברים חדשים. הם מאוד נחמדים.
אני גם לומד לשחות! אני הולך לבריכה שלוש פעמים בשבוע. המים קרים, אבל אני כבר שוחה טוב.
בוא לבקר אותי בקיץ! נלך ביחד לים ונאכל גלידה.
אני מתגעגע אליך.
שלך,
דני', 'Привет, дорогой друг!
Как у тебя дела? Надеюсь, что всё хорошо. Я хочу рассказать тебе о жизни в Хайфе.
Мы сейчас живём в новой квартире на Кармеле. Из окна я вижу море! Город очень красивый. Есть большая гора и голубое море.
Я учусь в новой школе. Вначале было трудно, потому что я никого не знал. Но сейчас у меня новые друзья. Они очень милые.
Я ещё учусь плавать! Хожу в бассейн три раза в неделю. Вода холодная, но я уже хорошо плаваю.
Приезжай ко мне летом! Пойдём вместе на море и поедим мороженое.
Скучаю по тебе.
Твой Дони', '[{"he": "מכתב", "ru": "письмо", "translit": "михтАв"}, {"he": "שלומך", "ru": "как дела (твои)", "translit": "шломхА"}, {"he": "עכשיו", "ru": "сейчас", "translit": "ахшАв"}, {"he": "הר", "ru": "гора", "translit": "hар"}, {"he": "לבקר", "ru": "навестить", "translit": "левакЕр"}, {"he": "בריכה", "ru": "бассейн", "translit": "брехА"}, {"he": "מתגעגע", "ru": "скучаю", "translit": "митгаагЕа"}, {"he": "לשחות", "ru": "плавать", "translit": "лисхОт"}]', NULL, 'letter');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (213, 1, 'בקפה', 'В кафе', 'ביום שישי אני ואמא הולכים לבית קפה ליד הבית. זה בית קפה קטן ונעים.
אנחנו נכנסים ויושבים ליד החלון. המלצרית באה ואומרת: "שלום! מה תרצו להזמין?"
אמא אומרת: "אני רוצה קפה עם חלב, בבקשה. ועוגת גבינה."
"ואתה, ילד?" שואלת המלצרית.
"אני רוצה שוקו חם וגלידת שוקולד, בבקשה!"
"בסדר! רגע אחד."
אנחנו מחכים. אני מסתכל על אנשים ברחוב. יש אישה עם כלב. יש ילדים על אופניים. יש זקן שקורא עיתון.
המלצרית מביאה את ההזמנה. הגלידה טעימה מאוד! "אמא, אפשר עוד גלידה?" "לא, מספיק שוקולד להיום," היא צוחקת.
אנחנו משלמים ויוצאים. "תודה, להתראות!" "להתראות, בואו שוב!"', 'В пятницу мы с мамой ходим в кафе рядом с домом. Это маленькое и уютное кафе.
Мы заходим и садимся у окна. Подходит официантка и говорит: «Здравствуйте! Что будете заказывать?»
Мама говорит: «Мне кофе с молоком, пожалуйста. И чизкейк.»
«А тебе, мальчик?» — спрашивает официантка.
«Я хочу горячий шоколад и шоколадное мороженое, пожалуйста!»
«Хорошо! Одну минутку.»
Мы ждём. Я смотрю на людей на улице. Вот женщина с собакой. Вот дети на велосипедах. Вот старик читает газету.
Официантка приносит заказ. Мороженое очень вкусное! «Мама, можно ещё мороженого?» «Нет, хватит шоколада на сегодня,» — смеётся она.
Мы платим и уходим. «Спасибо, до свидания!» «До свидания, приходите ещё!»', '[{"he": "קפה", "ru": "кофе", "translit": "кафЕ"}, {"he": "גלידה", "ru": "мороженое", "translit": "глидА"}, {"he": "טעם", "ru": "вкус", "translit": "тАам"}, {"he": "שוקולד", "ru": "шоколад", "translit": "шоколАд"}, {"he": "מלצרית", "ru": "официантка", "translit": "мельцарИт"}, {"he": "להזמין", "ru": "заказать", "translit": "леhазмИн"}, {"he": "מחכים", "ru": "ждём", "translit": "мехакИм"}, {"he": "רחוב", "ru": "улица", "translit": "рехОв"}, {"he": "עיתון", "ru": "газета", "translit": "итОн"}]', NULL, 'dialogue');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (214, 1, 'החדר שלי', 'Моя комната', 'יש לי חדר משלי. זה חדר קטן אבל אני אוהב אותו.
על הקיר הצבע כחול — זה הצבע האהוב עלי. יש פוסטרים של כדורגלנים ושל חלל.
בפינה יש מיטה עם שמיכה ירוקה. ליד המיטה יש שידה קטנה. על השידה יש מנורה וספר שאני קורא עכשיו.
מול המיטה יש שולחן כתיבה. על השולחן יש מחשב, עיפרון, מחברות וצבעים. אני עושה פה שיעורי בית.
יש גם ארון בגדים גדול. בארון יש חולצות, מכנסיים ונעליים. אמא אומרת שהארון שלי לא מסודר. היא צודקת.
על הרצפה יש שטיח רך. אני אוהב לשבת על השטיח ולשחק עם לגו. ליד החלון יש עציץ קטן עם צמח ירוק.
החדר שלי — המקום האהוב עלי בבית.', 'У меня есть своя комната. Она маленькая, но я её люблю.
Стены голубые — это мой любимый цвет. Есть постеры футболистов и космоса.
В углу кровать с зелёным одеялом. Рядом с кроватью маленькая тумбочка. На тумбочке лампа и книга, которую я сейчас читаю.
Напротив кровати письменный стол. На столе компьютер, карандаш, тетради и краски. Здесь я делаю домашние задания.
Ещё есть большой шкаф для одежды. В шкафу рубашки, штаны и ботинки. Мама говорит, что мой шкаф не в порядке. Она права.
На полу мягкий ковёр. Я люблю сидеть на ковре и играть с лего. У окна маленький горшок с зелёным растением.
Моя комната — моё любимое место в доме.', '[{"he": "חדר", "ru": "комната", "translit": "хЕдер"}, {"he": "מיטה", "ru": "кровать", "translit": "митА"}, {"he": "שולחן", "ru": "стол", "translit": "шульхАн"}, {"he": "מחשב", "ru": "компьютер", "translit": "махшЕв"}, {"he": "ארון", "ru": "шкаф", "translit": "арОн"}, {"he": "שטיח", "ru": "ковёр", "translit": "шатИах"}, {"he": "מנורה", "ru": "лампа", "translit": "менорА"}, {"he": "מסודר", "ru": "в порядке", "translit": "месудАр"}, {"he": "עציץ", "ru": "цветочный горшок", "translit": "ацИц"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (215, 1, 'הימים', 'Дни недели', 'בשבוע יש שבעה ימים. כל יום אני עושה דברים אחרים.
ביום ראשון אני קם מוקדם והולך לבית ספר. אחרי הלימודים יש לי חוג ציור.
ביום שני אני לומד ואחר הצהריים הולך לבריכה. אני לומד לשחות.
ביום שלישי יש הרבה שיעורים. אני עייף בסוף היום. בערב אני קורא ספר.
ביום רביעי יש לי שיעור מוסיקה. אני מנגן על פסנתר. המורה אומרת שאני מתקדם.
ביום חמישי אני משחק כדורגל אחרי הלימודים. זה היום האהוב עלי!
ביום שישי בית ספר נגמר מוקדם. אנחנו הולכים לשוק ומכינים אוכל לשבת. בערב כל המשפחה ביחד.
בשבת אני ישן הרבה, משחק ונח. שבת — יום מנוחה.
כל יום מיוחד בדרך שלו!', 'В неделе семь дней. Каждый день я делаю разные вещи.
В воскресенье я встаю рано и иду в школу. После учёбы у меня кружок рисования.
В понедельник я учусь, а после обеда иду в бассейн. Я учусь плавать.
Во вторник много уроков. В конце дня я устаю. Вечером читаю книгу.
В среду у меня урок музыки. Я играю на пианино. Учительница говорит, что я делаю успехи.
В четверг я играю в футбол после учёбы. Это мой любимый день!
В пятницу школа заканчивается рано. Мы ходим на рынок и готовим еду к субботе. Вечером вся семья вместе.
В субботу я долго сплю, играю и отдыхаю. Суббота — день отдыха.
Каждый день особенный по-своему!', '[{"he": "שבוע", "ru": "неделя", "translit": "шавУа"}, {"he": "ימים", "ru": "дни", "translit": "ямИм"}, {"he": "יום ראשון", "ru": "воскресенье", "translit": "йом ришОн"}, {"he": "יום שישי", "ru": "пятница", "translit": "йом шишИ"}, {"he": "נחים", "ru": "отдыхаем", "translit": "нахИм"}, {"he": "חוג", "ru": "кружок", "translit": "хуг"}, {"he": "מנגן", "ru": "играю (музыка)", "translit": "менагЕн"}, {"he": "פסנתר", "ru": "пианино", "translit": "псантЕр"}, {"he": "מנוחה", "ru": "отдых", "translit": "менухА"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (216, 1, 'בחוף הים', 'На пляже', 'היום חם מאוד ואנחנו הולכים לחוף הים. אני שם בגד ים, לוקח מגבת ומשקפי שמש.
בחוף הים יש הרבה אנשים. אנחנו מוצאים מקום ושמים מטרייה גדולה. אמא שמה קרם הגנה על הגב שלי. "השמש חזקה היום," היא אומרת.
אני רץ למים. המים כחולים וקרירים. אני שוחה ומשחק בגלים. אבא שוחה איתי ומלמד אותי לשחות על הגב.
אחותי בונה ארמון חול על החוף. היא משתמשת בדלי ובכף. הארמון גדול ויפה. היא שמחה מאוד.
אנחנו אוכלים אבטיח קר ושותים מים. "אפשר גלידה?" אני שואל. "כן, בוא נלך למוכר הגלידה," אומר אבא. אני לוקח גלידת מנגו.
בארבע אנחנו חוזרים הביתה. אני עייף ושמח. מחר נבוא שוב!', 'Сегодня очень жарко, и мы идём на пляж. Я надеваю купальник, беру полотенце и солнечные очки.
На пляже много людей. Мы находим место и ставим большой зонт. Мама мажет мне спину солнцезащитным кремом. «Солнце сегодня сильное,» — говорит она.
Я бегу к воде. Вода голубая и прохладная. Я плаваю и играю на волнах. Папа плавает со мной и учит меня плавать на спине.
Сестра строит замок из песка на берегу. Она использует ведёрко и лопатку. Замок большой и красивый. Она очень довольна.
Мы едим холодный арбуз и пьём воду. «Можно мороженое?» — спрашиваю я. «Да, пойдём к мороженщику,» — говорит папа. Я беру манговое мороженое.
В четыре мы возвращаемся домой. Я уставший и счастливый. Завтра придём снова!', '[{"he": "חוף הים", "ru": "пляж", "translit": "хоф хаЯм"}, {"he": "שוחה", "ru": "плаваю", "translit": "сохЕ"}, {"he": "ארמון חול", "ru": "замок из песка", "translit": "армОн холь"}, {"he": "מגבת", "ru": "полотенце", "translit": "магЕвет"}, {"he": "גלים", "ru": "волны", "translit": "галИм"}, {"he": "אבטיח", "ru": "арбуз", "translit": "аватИах"}, {"he": "מטרייה", "ru": "зонт", "translit": "митрийА"}, {"he": "בגד ים", "ru": "купальник", "translit": "бЕгед ям"}, {"he": "משקפי שמש", "ru": "солнечные очки", "translit": "мишкафЕй шЕмеш"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (217, 1, 'ברופא', 'У врача', 'היום אני לא מרגיש טוב. כואב לי הראש ויש לי חום. אמא אומרת: "אנחנו הולכים לרופא."
אנחנו באים למרפאה. בחדר המתנה יש כמה אנשים. אנחנו יושבים ומחכים.
אחרי עשר דקות הרופא קורא לנו. "שלום! מה קרה?" שואל הרופא.
"כואב לי הראש," אני אומר. "ויש לי חום. ואני מרגיש חלש."
הרופא בודק אותי. הוא מסתכל על הגרון שלי. "תפתח את הפה, בבקשה. תגיד אההה." הוא גם בודק את האוזניים ושומע את הלב עם סטטוסקופ.
"יש לך דלקת בגרון," אומר הרופא. "אתה צריך לנוח בבית שלושה ימים. תשתה הרבה מים ותיקח את התרופה הזאת שלוש פעמים ביום."
"תודה רבה, רופא!" אומרת אמא. אנחנו הולכים לבית מרקחת לקנות את התרופה. בבית אני שוכב במיטה ואמא מביאה לי מרק חם.', 'Сегодня я плохо себя чувствую. У меня болит голова и температура. Мама говорит: «Мы идём к врачу.»
Мы приходим в поликлинику. В приёмной несколько человек. Мы сидим и ждём.
Через десять минут врач вызывает нас. «Здравствуйте! Что случилось?» — спрашивает врач.
«У меня болит голова,» — говорю я. «И температура. И я чувствую слабость.»
Врач осматривает меня. Он смотрит горло. «Открой рот, пожалуйста. Скажи ааа.» Он также проверяет уши и слушает сердце стетоскопом.
«У тебя воспаление горла,» — говорит врач. «Тебе нужно лежать дома три дня. Пей много воды и принимай это лекарство три раза в день.»
«Большое спасибо, доктор!» — говорит мама. Мы идём в аптеку купить лекарство. Дома я ложусь в кровать, и мама приносит мне горячий суп.', '[{"he": "רופא", "ru": "врач", "translit": "рофЕ"}, {"he": "כואב", "ru": "болит", "translit": "коЭв"}, {"he": "ראש", "ru": "голова", "translit": "рош"}, {"he": "חום", "ru": "температура", "translit": "хом"}, {"he": "בודק", "ru": "проверяет", "translit": "бодЕк"}, {"he": "מרפאה", "ru": "поликлиника", "translit": "мирпаА"}, {"he": "גרון", "ru": "горло", "translit": "гарОн"}, {"he": "תרופה", "ru": "лекарство", "translit": "труфА"}, {"he": "לנוח", "ru": "отдыхать", "translit": "ланУах"}]', NULL, 'dialogue');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (218, 1, 'יום הולדת', 'День рождения', 'היום יום ההולדת שלי! אני בן שמונה! אני שמח מאוד.
בבוקר אמא ואבא אומרים: "יום הולדת שמח!" אני מקבל מתנה — אופניים חדשות! הן אדומות ויפות. "תודה רבה!" אני צועק.
אחר הצהריים חברים באים למסיבה. באים יוסי, דנה, עומר ונעמה. כל אחד מביא מתנה. יוסי נותן לי ספר. דנה נותנת לי משחק. עומר נותן לי כדור.
אנחנו משחקים בחצר. אנחנו רצים, משחקים מחבואים ויושבים על הדשא.
אחר כך אמא מביאה את העוגה. עוגת שוקולד גדולה עם שמונה נרות! כולם שרים: "יום הולדת שמח!" אני נושף על הנרות — פוף! כל הנרות כבים.
"מה ביקשת?" שואלת דנה. "סוד!" אני צוחק.
אנחנו אוכלים עוגה ושותים מיץ. בסוף כולם אומרים: "היה כיף!" זה היה יום הולדת מושלם!', 'Сегодня мой день рождения! Мне восемь лет! Я очень счастлив.
Утром мама и папа говорят: «С днём рождения!» Я получаю подарок — новый велосипед! Он красный и красивый. «Спасибо огромное!» — кричу я.
После обеда друзья приходят на вечеринку. Приходят Йоси, Дана, Омер и Наама. Каждый приносит подарок. Йоси дарит книгу. Дана дарит игру. Омер дарит мяч.
Мы играем во дворе. Бегаем, играем в прятки и сидим на траве.
Потом мама выносит торт. Большой шоколадный торт с восемью свечами! Все поют: «С днём рождения!» Я дую на свечи — фу-у! Все свечи гаснут.
«Что ты загадал?» — спрашивает Дана. «Секрет!» — смеюсь я.
Мы едим торт и пьём сок. В конце все говорят: «Было весело!» Это был идеальный день рождения!', '[{"he": "יום הולדת", "ru": "день рождения", "translit": "йом хулЕдет"}, {"he": "מתנות", "ru": "подарки", "translit": "матанОт"}, {"he": "מסיבה", "ru": "вечеринка", "translit": "месибА"}, {"he": "עוגה", "ru": "торт", "translit": "угА"}, {"he": "נרות", "ru": "свечи", "translit": "нерОт"}, {"he": "שרים", "ru": "поют", "translit": "шарИм"}, {"he": "מחבואים", "ru": "прятки", "translit": "махбоИм"}, {"he": "סוד", "ru": "секрет", "translit": "сод"}, {"he": "נושף", "ru": "дую", "translit": "ношЕф"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (220, 1, 'לילה טוב', 'Спокойной ночи', 'היום נגמר ואני עייף. הגיע הזמן ללכת לישון.
אני הולך לחדר האמבטיה. אני מתקלח במים חמים. המים נעימים ואני מרגיש טוב. אני מצחצח שיניים — למעלה, למטה, ימינה, שמאלה. שתי דקות.
אני לובש פיג''מה נקייה — חולצה כחולה ומכנסיים עם כוכבים.
אני נכנס למיטה. השמיכה חמה ונעימה. אני שם את הראש על הכרית.
אמא באה לחדר. "מה סיפור אתה רוצה הלילה?" היא שואלת. "את הסיפור על הנסיך הקטן!" אני אומר. אמא קוראת לי את הסיפור. הקול שלה שקט ונעים.
אני מפהק. העיניים שלי נסגרות. "לילה טוב, מותק," אומרת אמא ומנשקת אותי. "לילה טוב, אמא," אני לוחש.
היא מכבה את האור ויוצאת. בחדר חשוך ושקט. רק הירח מאיר מהחלון. אני ישן.', 'День закончился, и я устал. Пора спать.
Я иду в ванную. Принимаю горячий душ. Вода приятная, и я чувствую себя хорошо. Чищу зубы — вверх, вниз, вправо, влево. Две минуты.
Я надеваю чистую пижаму — голубую рубашку и штаны со звёздами.
Я забираюсь в кровать. Одеяло тёплое и уютное. Я кладу голову на подушку.
Мама приходит в комнату. «Какую сказку ты хочешь сегодня?» — спрашивает она. «Сказку про Маленького принца!» — говорю я. Мама читает мне сказку. Её голос тихий и приятный.
Я зеваю. Глаза закрываются. «Спокойной ночи, малыш,» — говорит мама и целует меня. «Спокойной ночи, мама,» — шепчу я.
Она выключает свет и выходит. В комнате темно и тихо. Только луна светит из окна. Я засыпаю.', '[{"he": "לילה", "ru": "ночь", "translit": "лАйла"}, {"he": "שיניים", "ru": "зубы", "translit": "шинАйим"}, {"he": "סיפור", "ru": "рассказ/сказка", "translit": "сипУр"}, {"he": "שוכב", "ru": "лежу", "translit": "шохЕв"}, {"he": "ישן", "ru": "сплю", "translit": "яшЕн"}, {"he": "כרית", "ru": "подушка", "translit": "карИт"}, {"he": "שמיכה", "ru": "одеяло", "translit": "смихА"}, {"he": "ירח", "ru": "луна", "translit": "ярЕах"}, {"he": "חשוך", "ru": "темно", "translit": "хашУх"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (221, 2, 'הדירה החדשה', 'Новая квартира', 'אנחנו עברנו לדירה חדשה בירושלים. הדירה נמצאת בקומה השלישית של בניין ישן ויפה ברחוב אגריפס, ליד השוק.
יש בדירה שלושה חדרים, מטבח גדול, סלון מרווח וחדר אמבטיה. המטבח הוא החלק האהוב עלי — יש בו חלון גדול שפונה לגינה, ובבוקר השמש נכנסת ומאירה את כל החדר.
מהמרפסת אפשר לראות את חומות העיר העתיקה ואת כיפת הזהב. בערב, כשהשמש שוקעת, הנוף מדהים — השמיים נצבעים באדום, כתום וסגול.
בשבוע הראשון באו השכנים לברך אותנו. אורלי מהקומה השנייה הביאה עוגת תפוחים. משפחת לוי מהקומה הרביעית הביאה פרחים. "ברוכים הבאים לשכונה!" הם אמרו.
אמא מאוד אוהבת את המקום. "סוף סוף יש לנו מרפסת!" היא אמרה בשמחה. אבא שמח כי בית הכנסת קרוב והשוק במרחק הליכה.
אני עדיין מתגעגע לחברים מהעיר הקודמת, אבל כבר הכרתי ילדים חדשים בבניין. אני חושב שנהיה מאושרים פה.', 'Мы переехали в новую квартиру в Иерусалиме. Квартира находится на третьем этаже старого красивого дома на улице Агриппас, рядом с рынком.
В квартире три комнаты, большая кухня, просторная гостиная и ванная. Кухня — моя любимая часть — в ней большое окно, выходящее в сад, и утром солнце заходит и освещает всю комнату.
С балкона видны стены Старого города и Золотой купол. Вечером, когда солнце садится, вид потрясающий — небо окрашивается в красный, оранжевый и фиолетовый.
В первую неделю приходили соседи поздравить нас. Орли со второго этажа принесла яблочный пирог. Семья Леви с четвёртого этажа принесла цветы. «Добро пожаловать в район!» — сказали они.
Мама очень любит это место. «Наконец-то у нас есть балкон!» — сказала она радостно. Папа рад, потому что синагога рядом и до рынка можно дойти пешком.
Я ещё скучаю по друзьям из прежнего города, но уже познакомился с новыми детьми в доме. Думаю, нам тут будет хорошо.', '[{"he": "דירה", "ru": "квартира", "translit": "дирА"}, {"he": "קומה", "ru": "этаж", "translit": "комА"}, {"he": "מרפסת", "ru": "балкон", "translit": "мирпЕсет"}, {"he": "עיר עתיקה", "ru": "Старый город", "translit": "ир атикА"}, {"he": "שכנים", "ru": "соседи", "translit": "шхенИм"}, {"he": "שכונה", "ru": "район", "translit": "шхунА"}, {"he": "מרווח", "ru": "просторный", "translit": "мервАх"}, {"he": "נוף", "ru": "вид/пейзаж", "translit": "ноф"}, {"he": "מאושרים", "ru": "счастливые", "translit": "меушарИм"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (222, 2, 'בשוק מחנה יהודה', 'На рынке Махане Иехуда', 'שוק מחנה יהודה הוא אחד המקומות הכי מיוחדים בירושלים. כל יום שישי אנחנו הולכים לקנות שם אוכל לשבת.
השוק גדול ויש בו מאות דוכנים. כשנכנסים, הריח הראשון הוא של תבלינים — כמון, כורכום, פפריקה ופלפל. הצבעים מדהימים — ערימות של ירוק, אדום, צהוב וכתום.
אנחנו הולכים קודם לדוכן הירקות של אבו חסן. הוא מוכר את הירקות הכי טריים — עגבניות אדומות, מלפפונים ירוקים, גזר כתום ופלפלים צבעוניים. "בואו בואו! הכל טרי מהבוקר!" הוא צועק.
אחר כך אנחנו עוצרים ליד דוכן הגבינות. יש גבינה צהובה, גבינה לבנה, גבינת עיזים ולבנה. אמא קונה חצי קילו גבינה צהובה ולבנה לשבת.
אבא תמיד עוצר ליד דוכן הזיתים. יש זיתים ירוקים, שחורים, גדולים וקטנים. הוא טועם ואומר: "הזיתים האלה מצוינים!" וקונה חצי קילו.
בסוף אנחנו קונים חלות טריות למוצאי שבת ועוגיות מרוקאיות. יוצאים מהשוק עם שקיות מלאות, עייפים אבל מרוצים. הארוחה של שבת תהיה מצוינת!', 'Рынок Махане Иехуда — одно из самых особенных мест в Иерусалиме. Каждую пятницу мы ходим туда покупать еду к субботе.
Рынок большой, и в нём сотни прилавков. Когда заходишь, первый запах — специй: тмин, куркума, паприка и перец. Цвета потрясающие — горы зелёного, красного, жёлтого и оранжевого.
Сначала мы идём к овощному прилавку Абу Хассана. Он продаёт самые свежие овощи — красные помидоры, зелёные огурцы, оранжевую морковь и разноцветные перцы. «Подходите! Всё свежее с утра!» — кричит он.
Потом мы останавливаемся у сырного прилавка. Есть жёлтый сыр, белый сыр, козий сыр и лабане. Мама покупает полкило жёлтого сыра и лабане на субботу.
Папа всегда останавливается у прилавка с оливками. Есть зелёные, чёрные, большие и маленькие. Он пробует и говорит: «Эти оливки превосходные!» И покупает полкило.
В конце мы покупаем свежие халы на исход субботы и марокканское печенье. Выходим с рынка с полными пакетами, уставшие, но довольные. Субботняя трапеза будет отличной!', '[{"he": "שוק", "ru": "рынок", "translit": "шук"}, {"he": "ירקות", "ru": "овощи", "translit": "еракОт"}, {"he": "טרי", "ru": "свежий", "translit": "тарИ"}, {"he": "תבלינים", "ru": "специи", "translit": "тавлинИм"}, {"he": "ריחות", "ru": "запахи", "translit": "рехОт"}, {"he": "דוכן", "ru": "прилавок", "translit": "духАн"}, {"he": "גבינה", "ru": "сыр", "translit": "гвинА"}, {"he": "זיתים", "ru": "оливки", "translit": "зейтИм"}, {"he": "חלות", "ru": "халы", "translit": "халОт"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (223, 2, 'הנסיעה לאילת', 'Поездка в Эйлат', 'בחופשת הקיץ כל המשפחה נסעה לאילת. התכוננו לטיול שבוע מראש — ארזנו בגדי ים, קרם הגנה, כובעים ומשקפי שמש.
יצאנו בארבע בבוקר כי הדרך ארוכה — ארבע שעות ברכב. אני ואחותי ישנו ברכב. כשהתעוררתי, ראיתי מדבר — חול צהוב והרים חומים. "כמעט הגענו!" אמר אבא.
אילת עיר חמה מאוד, אפילו בבוקר. מיד הלכנו לבריכה של המלון. אחרי ארוחת צהריים הלכנו לחוף הים. ים סוף כחול ושקוף — אפשר לראות דגים צבעוניים בלי לצלול.
ביום השני עשינו צלילה עם שנורקל. ראיתי דגים כתומים, כחולים וצהובים. ראיתי גם צבי ים ענק! הוא שחה לאט ליד. זה היה מדהים.
ביום השלישי הלכנו למצפה הכוכבים של רמון. בלילה, במדבר, רואים מיליוני כוכבים. אף פעם לא ראיתי שמיים כאלה.
בערב האחרון הלכנו למסעדה על חוף הים. אכלנו דגים טריים, סלט ופיתות חמות. הילדים שיחקו בחול והמבוגרים שתו קפה.
חזרנו הביתה שחורים מהשמש, עייפים ומלאי חוויות. "מתי נחזור לאילת?" שאלתי. "אולי בחנוכה," חייך אבא.', 'На летних каникулах вся семья поехала в Эйлат. Мы готовились к поездке за неделю — упаковали купальники, солнцезащитный крем, шляпы и солнечные очки.
Выехали в четыре утра, потому что дорога длинная — четыре часа на машине. Мы с сестрой спали в машине. Когда я проснулся, увидел пустыню — жёлтый песок и коричневые горы. «Почти приехали!» — сказал папа.
Эйлат — очень жаркий город, даже утром. Сразу пошли в бассейн отеля. После обеда пошли на пляж. Красное море голубое и прозрачное — можно видеть цветных рыбок, даже не ныряя.
На второй день мы ныряли со шнорклем. Я видел оранжевых, голубых и жёлтых рыб. Ещё видел огромную морскую черепаху! Она медленно проплыла рядом. Это было потрясающе.
На третий день поехали в обсерваторию Рамон. Ночью, в пустыне, видно миллионы звёзд. Никогда не видел такого неба.
В последний вечер ужинали в ресторане на берегу моря. Ели свежую рыбу, салат и горячие питы. Дети играли в песке, а взрослые пили кофе.
Вернулись домой загорелые, уставшие и полные впечатлений. «Когда поедем в Эйлат снова?» — спросил я. «Может, на Хануку,» — улыбнулся папа.', '[{"he": "נסיעה", "ru": "поездка", "translit": "несиА"}, {"he": "חופשה", "ru": "каникулы/отпуск", "translit": "хуфшА"}, {"he": "צלילה", "ru": "дайвинг/ныряние", "translit": "цлилА"}, {"he": "ים סוף", "ru": "Красное море", "translit": "ям суф"}, {"he": "דגים", "ru": "рыбы", "translit": "дагИм"}, {"he": "מסעדה", "ru": "ресторан", "translit": "мисадА"}, {"he": "מדבר", "ru": "пустыня", "translit": "мидбАр"}, {"he": "כוכבים", "ru": "звёзды", "translit": "кохавИм"}, {"he": "חוויות", "ru": "впечатления", "translit": "хавайОт"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (224, 2, 'ראיון עבודה', 'Собеседование', 'הגיע היום של הראיון. קמתי מוקדם, התלבשתי יפה — חולצה לבנה ומכנסיים שחורות. שתיתי קפה ויצאתי מהבית.
הגעתי למשרד בזמן. המזכירה חייכה ואמרה: "שלום! אתה אלכס? שב כאן, בבקשה. המנהל יהיה פנוי בעוד חמש דקות."
ישבתי בחדר ההמתנה וניסיתי להירגע. הלב שלי דפק מהר. קראתי שוב את קורות החיים שלי והכנתי תשובות.
"אלכס? בוא, בבקשה," אמר המנהל. נכנסתי לחדר וישבתי.
"ספר לי על עצמך," הוא ביקש.
"אני גר בתל אביב כבר שנתיים. עליתי מרוסיה. למדתי מדעי המחשב באוניברסיטה ואחרי זה עבדתי שנתיים בחברת הייטק קטנה. עשיתי שם פיתוח תוכנה."
"למה אתה רוצה לעבוד דווקא אצלנו?" שאל המנהל.
"כי החברה שלכם מפתחת מוצר מעניין בתחום הבינה המלאכותית. אני מתעניין בתחום הזה ורוצה ללמוד ולהתפתח."
"מה השכר שאתה מצפה לו?" שאל המנהל.
"אני גמיש. חשוב לי יותר הסביבה והאתגר המקצועי."
המנהל חייך. "מצוין. שמעתי דברים טובים עליך מהממליצים. נתקשר אליך עד סוף השבוע." יצאתי משם בתחושה טובה.', 'Настал день собеседования. Встал рано, красиво оделся — белая рубашка и чёрные брюки. Выпил кофе и вышел из дома.
Пришёл в офис вовремя. Секретарь улыбнулась: «Здравствуйте! Вы Алекс? Садитесь здесь, пожалуйста. Менеджер освободится через пять минут.»
Я сидел в приёмной и пытался успокоиться. Сердце стучало быстро. Перечитал своё резюме и подготовил ответы.
«Алекс? Заходите, пожалуйста,» — сказал менеджер. Я вошёл и сел.
«Расскажите о себе,» — попросил он.
«Я живу в Тель-Авиве уже два года. Репатриировался из России. Изучал информатику в университете, потом два года работал в маленькой хайтек-компании. Занимался разработкой ПО.»
«Почему хотите работать именно у нас?» — спросил менеджер.
«Потому что ваша компания разрабатывает интересный продукт в области ИИ. Меня интересует эта сфера, хочу учиться и развиваться.»
«Какую зарплату вы ожидаете?» — спросил менеджер.
«Я гибкий. Для меня важнее рабочая среда и профессиональный вызов.»
Менеджер улыбнулся. «Отлично. Я слышал хорошие отзывы о вас от рекомендателей. Позвоним вам до конца недели.» Я вышел с хорошим чувством.', '[{"he": "ראיון", "ru": "собеседование", "translit": "реайОн"}, {"he": "מנהל", "ru": "менеджер", "translit": "менаhЕль"}, {"he": "מדעי המחשב", "ru": "информатика", "translit": "мадаЕй хамахшЕв"}, {"he": "חברת הייטק", "ru": "хайтек-компания", "translit": "хеврАт хайтЕк"}, {"he": "מוצר", "ru": "продукт", "translit": "муцАр"}, {"he": "קורות חיים", "ru": "резюме", "translit": "корОт хаИм"}, {"he": "שכר", "ru": "зарплата", "translit": "сахАр"}, {"he": "להתפתח", "ru": "развиваться", "translit": "леhитпатЕах"}, {"he": "ממליצים", "ru": "рекомендатели", "translit": "мамлицИм"}]', NULL, 'dialogue');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (225, 2, 'חג פסח', 'Праздник Песах', 'פסח הוא אחד החגים החשובים ביותר בישראל. בחג הזה אנחנו זוכרים את יציאת עם ישראל ממצרים, מעבדות לחירות.
ההכנות מתחילות שבועות לפני החג. אמא מנקה את כל הבית — כל חדר, כל ארון, כל פינה. אנחנו מוציאים את כל החמץ — לחם, עוגיות, פסטה. במקום לחם, אנחנו אוכלים מצות.
בערב פסח כל המשפחה מתכנסת לליל הסדר. השנה באנו לסבא ולסבתא. באו גם הדודים והדודות עם הילדים — בסך הכל עשרים איש!
על השולחן יש קערת הסדר עם ביצה, זרוע, חרוסת, מרור, כרפס ולחם עוני. סבא קורא את ההגדה. הוא מספר את הסיפור של יציאת מצרים.
הילדים שואלים את ארבע השאלות: "מה נשתנה הלילה הזה מכל הלילות?" הילד הכי קטן, יואב בן חמש, שר את מה נשתנה בקול חמוד.
אחרי הקריאה בהגדה אנחנו אוכלים ארוחה גדולה — מרק עוף עם קניידלך, דג, בשר עם תפוחי אדמה, וסלטים. בסוף יש עוגת פסח ופירות.
אחרי האוכל אנחנו שרים שירים — "דיינו", "אחד מי יודע", "חד גדיא". הילדים מחפשים את האפיקומן. מי שמוצא מקבל מתנה!
החופשה נמשכת שבוע. אנחנו יוצאים לטיולים ומבלים עם המשפחה. פסח — חג של חירות, משפחה ואביב.', 'Песах — один из самых важных праздников в Израиле. В этот праздник мы вспоминаем Исход народа Израиля из Египта, от рабства к свободе.
Подготовка начинается за несколько недель. Мама убирает весь дом — каждую комнату, каждый шкаф, каждый угол. Мы выбрасываем весь хамец — хлеб, печенье, макароны. Вместо хлеба едим мацу.
В канун Песаха вся семья собирается на Седер. В этом году мы приехали к дедушке и бабушке. Приехали также дяди и тёти с детьми — всего двадцать человек!
На столе блюдо для Седера с яйцом, косточкой, харосетом, горькой зеленью, карпасом и хлебом бедности. Дедушка читает Агаду — рассказывает историю Исхода из Египта.
Дети задают четыре вопроса: «Чем эта ночь отличается от всех ночей?» Самый маленький, пятилетний Йоав, поёт «Ма Ништана» милым голосом.
После чтения Агады мы едим большой ужин — куриный бульон с кнейдлах, рыбу, мясо с картошкой и салаты. В конце пасхальный торт и фрукты.
После еды мы поём песни — «Дайену», «Эхад Ми Йодеа», «Хад Гадья». Дети ищут афикоман. Кто найдёт — получит подарок!
Каникулы длятся неделю. Мы ходим на прогулки и проводим время с семьёй. Песах — праздник свободы, семьи и весны.', '[{"he": "חג", "ru": "праздник", "translit": "хаг"}, {"he": "מצות", "ru": "маца", "translit": "мацОт"}, {"he": "ליל הסדר", "ru": "вечер Седера", "translit": "лейль хасЕдер"}, {"he": "יציאת מצרים", "ru": "Исход из Египта", "translit": "йециАт мицрАйим"}, {"he": "שרים", "ru": "поём", "translit": "шарИм"}, {"he": "הגדה", "ru": "Агада", "translit": "хагадА"}, {"he": "חירות", "ru": "свобода", "translit": "херУт"}, {"he": "חמץ", "ru": "хамец (квасное)", "translit": "хамЕц"}, {"he": "אפיקומן", "ru": "афикоман", "translit": "афикомАн"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (226, 2, 'בדואר', 'На почте', 'היום הלכתי לדואר לשלוח חבילה להורים שלי ברוסיה. לקחתי את החבילה ונכנסתי לסניף.
בדואר היה תור ארוך. עמדתי ועמדתי. בינתיים קראתי הודעות בטלפון. אחרי עשרים דקות הגיע התור שלי.
"שלום, אני רוצה לשלוח חבילה לרוסיה," אמרתי לפקיד.
"מה יש בחבילה?" שאל.
"ספרים בעברית, שוקולד ישראלי, ותמונות מהחתונה של האחות שלי."
"שים את החבילה על המשקל, בבקשה." שמתי. "שני קילו ושלוש מאות גרם," אמר הפקיד.
"כמה זה עולה?" שאלתי.
"יש שתי אפשרויות. משלוח רגיל — שמונים שקלים, מגיע בעוד שלושה שבועות. משלוח מהיר — מאה חמישים שקלים, מגיע בעוד שבוע."
"אני רוצה משלוח רגיל, בבקשה."
"בסדר. תמלא את הטופס הזה עם הכתובת של הנמען." מילאתי את הטופס בזהירות.
"הנה. יש גם מעקב?" שאלתי.
"כן, תקבל מספר מעקב ב-SMS. תוכל לראות איפה החבילה באתר." שילמתי ויצאתי. מקווה שההורים ישמחו!', 'Сегодня ходил на почту отправить посылку родителям в Россию. Взял посылку и зашёл в отделение.
На почте была длинная очередь. Стоял и стоял. Тем временем читал сообщения в телефоне. Через двадцать минут подошла моя очередь.
«Здравствуйте, хочу отправить посылку в Россию,» — сказал я клерку.
«Что в посылке?» — спросил он.
«Книги на иврите, израильский шоколад и фотографии со свадьбы моей сестры.»
«Поставьте посылку на весы, пожалуйста.» Я поставил. «Два кило триста граммов,» — сказал клерк.
«Сколько стоит?» — спросил я.
«Есть два варианта. Обычная доставка — восемьдесят шекелей, доставка через три недели. Быстрая доставка — сто пятьдесят шекелей, за неделю.»
«Обычную, пожалуйста.»
«Хорошо. Заполните этот бланк с адресом получателя.» Я аккуратно заполнил бланк.
«Вот. А есть отслеживание?» — спросил я.
«Да, получите номер отслеживания по SMS. Сможете видеть, где посылка, на сайте.» Заплатил и вышел. Надеюсь, родители будут рады!', '[{"he": "דואר", "ru": "почта", "translit": "доАр"}, {"he": "חבילה", "ru": "посылка", "translit": "хавилА"}, {"he": "לשלוח", "ru": "отправить", "translit": "лишлОах"}, {"he": "משלוח", "ru": "доставка", "translit": "мишлОах"}, {"he": "משקל", "ru": "весы", "translit": "мишкАль"}, {"he": "טופס", "ru": "бланк/форма", "translit": "тОфес"}, {"he": "נמען", "ru": "получатель", "translit": "нимАн"}, {"he": "מעקב", "ru": "отслеживание", "translit": "маакАв"}, {"he": "סניף", "ru": "отделение", "translit": "снИф"}]', NULL, 'dialogue');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (227, 2, 'יום טיול בטבע', 'День на природе', 'ביום שישי יצאנו לטיול בגליל העליון. המורה לגיאוגרפיה המליץ על שביל ליד נחל עמוד.
נסענו שעה וחצי מחיפה. חנינו את הרכב ליד הכניסה לשביל. אבא הוציא את הטיסנק עם כריכים, פירות ומים. "אל תשכחו כובעים!" אמרה אמא.
הלכנו בשביל ביער. העצים היו גבוהים ונתנו צל נעים. שמענו ציפורים שרות. ראינו פרחים סגולים וצהובים בצד השביל. "מה השם של הפרח הזה?" שאלתי. "זה רקפת," ענה אבא. "פרח החורף של ישראל."
אחרי שעה של הליכה הגענו למפל מים קטן. המים נפלו מסלע גבוה לבריכה טבעית. "אפשר להיכנס למים!" אמר אבא. נכנסנו למים — היו קרים מאוד! אבל ביום חם זה היה נהדר.
ישבנו על סלעים ליד הנחל ואכלנו כריכים. אמא חילקה תפוחים ושזיפים. שתינו מים קרים מהבקבוקים.
בדרך חזרה ראינו חמור בר ושתי ציפורי דרור. אחותי הקטנה אספה אבנים יפות וענפים מעניינים.
חזרנו לרכב אחרי ארבע שעות. "היה טיול מדהים!" אמרתי. הטבע בגליל מדהים — ירוק, שקט ומלא חיים.', 'В пятницу мы отправились на прогулку в Верхнюю Галилею. Учитель географии рекомендовал тропу у ручья Амуд.
Ехали полтора часа из Хайфы. Припарковали машину у входа на тропу. Папа достал рюкзак с бутербродами, фруктами и водой. «Не забудьте шляпы!» — сказала мама.
Мы шли по тропе в лесу. Деревья были высокие и давали приятную тень. Мы слышали пение птиц. Видели фиолетовые и жёлтые цветы у тропинки. «Как называется этот цветок?» — спросил я. «Это цикламен,» — ответил папа. «Зимний цветок Израиля.»
Через час ходьбы мы дошли до маленького водопада. Вода падала с высокой скалы в природный бассейн. «Можно залезть в воду!» — сказал папа. Мы зашли — вода была очень холодная! Но в жаркий день это было великолепно.
Мы сели на камни у ручья и ели бутерброды. Мама раздала яблоки и сливы. Пили холодную воду из бутылок.
На обратном пути видели дикого осла и двух воробьёв. Младшая сестра собирала красивые камушки и интересные веточки.
Вернулись к машине через четыре часа. «Потрясающая прогулка!» — сказал я. Природа в Галилее удивительная — зелёная, тихая и полная жизни.', '[{"he": "טיול", "ru": "поход/прогулка", "translit": "тиУль"}, {"he": "יער", "ru": "лес", "translit": "яАр"}, {"he": "שביל", "ru": "тропинка", "translit": "швиль"}, {"he": "נחל", "ru": "ручей", "translit": "нАхаль"}, {"he": "סלעים", "ru": "камни", "translit": "слаИм"}, {"he": "עייפים", "ru": "уставшие", "translit": "аефИм"}, {"he": "מפל מים", "ru": "водопад", "translit": "мапАль мАйим"}, {"he": "ציפורים", "ru": "птицы", "translit": "ципорИм"}, {"he": "צל", "ru": "тень", "translit": "цель"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (228, 2, 'לבשל שקשוקה', 'Готовим шакшуку', 'שקשוקה היא אחד המאכלים הכי פופולריים בישראל. כל ישראלי יודע להכין שקשוקה, ולכל משפחה יש מתכון קצת אחר. היום אני מלמד אתכם את המתכון של סבתא שלי.
מה צריך? שני בצלים, ארבע שיני שום, שש עגבניות בשלות (או פחית עגבניות), כפית כמון, כפית פפריקה, מלח, פלפל, שמן זית וארבע ביצים.
קודם כל, חותכים את הבצל לקוביות קטנות. שמים שמן זית במחבת גדולה ומטגנים את הבצל עד שהוא שקוף — בערך חמש דקות. מוסיפים את השום הקצוץ ומערבבים דקה.
אחר כך חותכים את העגבניות לקוביות ומוסיפים למחבת. מוסיפים מלח, פלפל, כמון ופפריקה. מערבבים ומבשלים על אש נמוכה עשר דקות. הרוטב צריך להיות סמיך.
עכשיו החלק הכי חשוב: עושים ארבעה גומות ברוטב ושוברים ביצה לתוך כל גומה. מפזרים קצת מלח ופלפל על הביצים. מכסים את המחבת ומבשלים עוד חמש-שבע דקות, עד שהביצים מוכנות.
מגישים ישר מהמחבת עם לחם טרי או פיתה חמה. טובלים את הלחם ברוטב.
הסוד של סבתא? להוסיף קצת סוכר לרוטב. זה מאזן את החמיצות של העגבניות.
בתיאבון!', 'Шакшука — одно из самых популярных блюд в Израиле. Каждый израильтянин умеет готовить шакшуку, и у каждой семьи немного другой рецепт. Сегодня я научу вас рецепту моей бабушки.
Что нужно? Две луковицы, четыре зубчика чеснока, шесть спелых помидоров (или банка консервированных), чайная ложка тмина, чайная ложка паприки, соль, перец, оливковое масло и четыре яйца.
Сначала нарезаем лук мелкими кубиками. Наливаем оливковое масло в большую сковороду и обжариваем лук, пока он не станет прозрачным — примерно пять минут. Добавляем нарезанный чеснок и перемешиваем минуту.
Потом нарезаем помидоры кубиками и добавляем на сковороду. Добавляем соль, перец, тмин и паприку. Перемешиваем и варим на слабом огне десять минут. Соус должен стать густым.
Теперь самая важная часть: делаем четыре углубления в соусе и разбиваем в каждое по яйцу. Посыпаем яйца солью и перцем. Накрываем сковороду крышкой и готовим ещё пять-семь минут, пока яйца не будут готовы.
Подаём прямо со сковороды с свежим хлебом или горячей питой. Макаем хлеб в соус.
Секрет бабушки? Добавить немного сахара в соус. Это уравновешивает кислоту помидоров.
Приятного аппетита!', '[{"he": "שקשוקה", "ru": "шакшука", "translit": "шакшукА"}, {"he": "מחבת", "ru": "сковорода", "translit": "махвАт"}, {"he": "שמן זית", "ru": "оливковое масло", "translit": "шЕмен зАйит"}, {"he": "עגבניות", "ru": "помидоры", "translit": "агваниОт"}, {"he": "רוטב", "ru": "соус", "translit": "рОтев"}, {"he": "בתיאבון", "ru": "приятного аппетита", "translit": "бетеавОн"}, {"he": "מתכון", "ru": "рецепт", "translit": "маткОн"}, {"he": "בצל", "ru": "лук", "translit": "бацАль"}, {"he": "שום", "ru": "чеснок", "translit": "шум"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (229, 2, 'שכן חדש', 'Новый сосед', 'שבוע שעבר שכן חדש עבר לדירה מול שלנו. ראיתי אותו בחדר המדרגות עם ארגזים.
"שלום! אתה צריך עזרה?" שאלתי.
"כן, בבקשה! אני אלכס. עליתי מרוסיה לפני חודש. זו הדירה הראשונה שלי."
עזרתי לו להעלות ארגזים. הדירה שלו קטנה אבל נחמדה. "יש לך רהיטים?" שאלתי. "עוד לא. רק מזרון ושולחן," הוא צחק.
סיפרתי לאלכס על השכונה. "הסופרמרקט ברחוב הבא. יש גם מכולת קטנה שפתוחה עד מאוחר. בית הכנסת בפינה ויש פארק קטן עם ספסלים ליד."
"ואיפה אפשר לקנות ריהוט בזול?" שאל.
"יש חנות שנייה-יד ברחוב אלנבי. ויש גם קבוצה בפייסבוק של השכונה — אנשים מוכרים שם דברים."
"תודה רבה, אתה ממש עוזר לי!" אמר אלכס.
"אין בעד מה. אני יוסי, אני גר פה עם אשתי וילדה. אם תצטרך משהו — תדפוק."
עכשיו, אחרי חודש, אלכס כבר חלק מהשכונה. הוא לומד עברית באולפן, עובד בהייטק ויש לו כבר רהיטים! כל ערב שישי הוא בא אלינו לאכול ארוחת שבת. הוא ואשתי מדברים רוסית ביחד, ואני מלמד אותו עברית. נהיינו חברים טובים.', 'На прошлой неделе новый сосед переехал в квартиру напротив нашей. Я увидел его в подъезде с коробками.
«Привет! Тебе нужна помощь?» — спросил я.
«Да, пожалуйста! Я Алекс. Репатриировался из России месяц назад. Это моя первая квартира.»
Я помог ему поднять коробки. Квартира маленькая, но приятная. «У тебя есть мебель?» — спросил я. «Пока нет. Только матрас и стол,» — засмеялся он.
Я рассказал Алексу о районе. «Супермаркет на следующей улице. Есть также маленький продуктовый, который открыт допоздна. Синагога на углу, и рядом маленький парк со скамейками.»
«А где можно купить мебель недорого?» — спросил он.
«Есть магазин б/у на улице Алленби. И ещё есть группа района в Фейсбуке — люди продают там вещи.»
«Большое спасибо, ты мне очень помогаешь!» — сказал Алекс.
«Не за что. Я Йоси, живу тут с женой и дочкой. Если что-то понадобится — стучи.»
Теперь, через месяц, Алекс уже часть района. Он учит иврит в ульпане, работает в хайтеке и у него уже есть мебель! Каждый пятничный вечер он приходит к нам на субботнюю трапезу. Он и моя жена говорят по-русски, а я учу его ивриту. Мы стали хорошими друзьями.', '[{"he": "שכן", "ru": "сосед", "translit": "шахЕн"}, {"he": "צעיר", "ru": "молодой", "translit": "цаИр"}, {"he": "אולפן", "ru": "ульпан", "translit": "ульпАн"}, {"he": "עזרה", "ru": "помощь", "translit": "эзрА"}, {"he": "רהיטים", "ru": "мебель", "translit": "рихитИм"}, {"he": "ארגזים", "ru": "коробки", "translit": "аргазИм"}, {"he": "מכולת", "ru": "продуктовый", "translit": "маколЕт"}, {"he": "שכונה", "ru": "район", "translit": "шхунА"}, {"he": "חברים", "ru": "друзья", "translit": "хаверИм"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (230, 2, 'באוטובוס לתל אביב', 'На автобусе в Тель-Авив', 'ביום שישי בבוקר עליתי על אוטובוס מירושלים לתל אביב. רציתי לבקר חבר שגר שם.
קניתי כרטיס ברב-קו ועליתי. האוטובוס היה כמעט מלא, אבל מצאתי מקום ליד החלון. הנסיעה לוקחת בערך שעה.
כשיצאנו מירושלים ראיתי את ההרים. הנוף היה ירוק ויפה. עברנו ליד כפרים קטנים ושדות. ראיתי עצי זית ישנים ופרות שרועות בשדה.
ליד שער הגיא ההרים נגמרו והתחיל המישור. הנוף השתנה — עכשיו יש בתים, כבישים ומפעלים. הולכים ומתקרבים לתל אביב.
באוטובוס ישבה לידי אישה מבוגרת. היא סיפרה שהיא נוסעת לראות את הנכדים. "יש לי חמישה נכדים בתל אביב!" היא אמרה בגאווה. "הנכד הגדול כבר בצבא."
דיברנו עד שהגענו לתחנה המרכזית. "נסיעה טובה!" אמרתי לה כשירדתי.
בתל אביב האוויר שונה — לח וחם. הלכתי ברחוב דיזנגוף. אנשים יושבים בבתי קפה, רוכבים על אופניים, טיילו עם כלבים. העיר חיה ותוססת, אפילו ביום שישי.
פגשתי את החבר שלי, אמיר, ליד הים. ישבנו על החול, שתינו בירה ודיברנו. "אתה צריך לעבור לגור פה!" הוא אמר. חייכתי. ירושלים או תל אביב — שתיהן ערים נהדרות, כל אחת בדרך שלה.', 'В пятницу утром я сел на автобус из Иерусалима в Тель-Авив. Хотел навестить друга, который живёт там.
Купил билет через Рав-Кав и сел. Автобус был почти полный, но я нашёл место у окна. Дорога занимает около часа.
Когда выехали из Иерусалима, я увидел горы. Вид был зелёный и красивый. Проезжали мимо маленьких деревень и полей. Видел старые оливковые деревья и коров на лугу.
У Шаар ха-Гай горы закончились и начался равнинный рельеф. Вид изменился — теперь дома, дороги и заводы. Приближаемся к Тель-Авиву.
В автобусе рядом со мной сидела пожилая женщина. Она рассказала, что едет к внукам. «У меня пять внуков в Тель-Авиве!» — сказала она с гордостью. «Старший уже в армии.»
Мы разговаривали до центральной автостанции. «Хорошей поездки!» — сказал я ей, выходя.
В Тель-Авиве воздух другой — влажный и тёплый. Я шёл по улице Дизенгоф. Люди сидят в кафе, катаются на велосипедах, гуляют с собаками. Город живой и кипучий, даже в пятницу.
Встретил друга Амира у моря. Сидели на песке, пили пиво и разговаривали. «Тебе надо переехать сюда!» — сказал он. Я улыбнулся. Иерусалим или Тель-Авив — оба замечательных города, каждый по-своему.', '[{"he": "תחנה מרכזית", "ru": "центральная станция", "translit": "таханА меркизИт"}, {"he": "עולים", "ru": "садятся (входят)", "translit": "олИм"}, {"he": "נוף", "ru": "вид/пейзаж", "translit": "ноф"}, {"he": "מישור", "ru": "равнина", "translit": "мишОр"}, {"he": "נכדים", "ru": "внуки", "translit": "нехадИм"}, {"he": "לח", "ru": "влажный", "translit": "лах"}, {"he": "תוססת", "ru": "живая/кипучая", "translit": "тосЕсет"}, {"he": "שדות", "ru": "поля", "translit": "садОт"}, {"he": "נהדרות", "ru": "замечательные", "translit": "нехедарОт"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (231, 2, 'חג חנוכה', 'Праздник Ханука', 'חנוכה הוא חג של אור ושל ניסים. החג נמשך שמונה ימים ומתחיל בכ"ה בכסלו.
הסיפור של חנוכה קרה לפני יותר מאלפיים שנה. המכבים, קבוצה קטנה של יהודים, נלחמו נגד הצבא היווני הגדול — וניצחו! כשנכנסו לבית המקדש מצאו פך שמן קטן, מספיק ליום אחד. אבל קרה נס — השמן דלק שמונה ימים!
בכל ערב של חנוכה אנחנו מדליקים נרות בחנוכייה. ביום הראשון נר אחד, ביום השני שניים, וכך עד שמונה. החנוכייה עומדת על החלון, כדי שכולם יראו את האור.
יש לחנוכה אוכל מיוחד — הכל עם שמן! סופגניות עם ריבה, סופגניות עם שוקולד, סופגניות עם קרם — יש מאות סוגים. ולביבות תפוחי אדמה, חמות וטריות, עם שמנת חמוצה.
הילדים מקבלים דמי חנוכה — כסף לחג. הם גם משחקים בסביבון — זה כמו קוביה מסתובבת עם ארבע אותיות: נ, ג, ה, פ. "נס גדול היה פה!"
השנה הדלקנו נרות עם כל המשפחה. הילדים שרו "מעוז צור" והמבוגרים צילמו. אחרי ההדלקה אכלנו סופגניות ושיחקנו בסביבון. סבתא סיפרה על חנוכה בילדותה ברוסיה.
חנוכה שמח!', 'Ханука — праздник света и чудес. Праздник длится восемь дней и начинается 25 кислева.
История Хануки произошла более двух тысяч лет назад. Маккавеи — маленькая группа евреев — сражались против большой греческой армии и победили! Когда вошли в Храм, нашли маленький кувшин масла, которого хватало на один день. Но произошло чудо — масло горело восемь дней!
Каждый вечер Хануки мы зажигаем свечи в ханукии. В первый день одну свечу, во второй две, и так до восьми. Ханукия стоит на окне, чтобы все видели свет.
У Хануки особая еда — всё в масле! Пончики с вареньем, пончики с шоколадом, пончики с кремом — есть сотни видов. И латкес — горячие картофельные оладьи со сметаной.
Дети получают ханукальные деньги — деньги к празднику. Ещё играют в дрейдл — это как вращающийся кубик с четырьмя буквами: нун, гимель, хей, пей. «Великое чудо было здесь!»
В этом году мы зажигали свечи всей семьёй. Дети пели «Маоз Цур», а взрослые фотографировали. После зажигания ели пончики и играли в дрейдл. Бабушка рассказывала о Хануке в её детстве в России.
Хануки Самеах!', '[{"he": "נרות", "ru": "свечи", "translit": "нерОт"}, {"he": "חנוכייה", "ru": "ханукия", "translit": "хануккийА"}, {"he": "סופגניות", "ru": "пончики", "translit": "суфганийОт"}, {"he": "לביבות", "ru": "латкес/оладьи", "translit": "левивОт"}, {"he": "סביבון", "ru": "дрейдл/волчок", "translit": "севивОн"}, {"he": "דמי חנוכה", "ru": "ханукальные деньги", "translit": "дмЕй хАнука"}, {"he": "נס", "ru": "чудо", "translit": "нес"}, {"he": "מכבים", "ru": "маккавеи", "translit": "макабИм"}, {"he": "שמן", "ru": "масло", "translit": "шЕмен"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (232, 2, 'ביקור אצל רופא שיניים', 'Визит к стоматологу', 'לא אהבתי ללכת לרופא שיניים. אבל כבר שלושה ימים כאב לי שן, אז לא הייתה ברירה.
התקשרתי למרפאה. "שלום, אני צריך תור דחוף. יש לי כאב שיניים חזק."
"אתה יכול לבוא היום בארבע?" שאלה המזכירה.
"כן, תודה."
הגעתי למרפאה בזמן. ישבתי בחדר ההמתנה ומילאתי טופס. אחרי כמה דקות הרופאה קראה לי.
"שלום! ספר לי מה כואב." אמרתי שכואב לי השן האחורית בצד ימין, בעיקר כשאני אוכל דברים קרים או חמים.
"בוא נבדוק. תפתח את הפה רחב, בבקשה." היא הסתכלה עם מראה קטנה ואור.
"אני רואה חור קטן בשן. צריך סתימה. זה לא נורא, אבל צריך לטפל מהר לפני שיגדל."
"זה יכאב?" שאלתי בדאגה.
"אני אתן לך זריקת הרדמה ולא תרגיש כלום. רק לחץ קל." הרופאה הייתה עדינה מאוד. אחרי הזריקה חיכינו חמש דקות.
הטיפול לקח עשרים דקות. באמת לא הרגשתי כאב. הרופאה ניקתה את החור ושמה סתימה לבנה.
"אל תאכל בצד הזה שעתיים. ותאמר לי אם יש כאב מחר." נתנה לי מרשם למשכך כאבים למקרה הצורך.
יצאתי מהמרפאה עם חיוך. "זה לא היה נורא," חשבתי. "למה פחדתי?"', 'Я не любил ходить к стоматологу. Но зуб болел уже три дня, выбора не было.
Позвонил в клинику. «Здравствуйте, мне нужна срочная запись. У меня сильная зубная боль.»
«Можете прийти сегодня в четыре?» — спросила секретарь.
«Да, спасибо.»
Пришёл в клинику вовремя. Сидел в приёмной и заполнял анкету. Через несколько минут врач позвала меня.
«Здравствуйте! Расскажите, что болит.» Я сказал, что болит задний зуб справа, особенно когда ем холодное или горячее.
«Давайте посмотрим. Откройте рот широко, пожалуйста.» Она осмотрела маленьким зеркалом и фонариком.
«Вижу маленькую дырку в зубе. Нужна пломба. Ничего страшного, но нужно лечить быстро, пока не выросла.»
«Будет больно?» — спросил я с тревогой.
«Сделаю укол анестезии, и вы ничего не почувствуете. Только лёгкое давление.» Врач была очень нежной. После укола подождали пять минут.
Лечение заняло двадцать минут. Действительно не было больно. Врач вычистила дырку и поставила белую пломбу.
«Не ешьте на этой стороне два часа. И скажите мне, если завтра будет боль.» Дала рецепт на обезболивающее на всякий случай.
Вышел из клиники с улыбкой. «Было не так уж страшно,» — подумал я. «Чего я боялся?»', '[{"he": "רופא שיניים", "ru": "стоматолог", "translit": "рофЕ шинАйим"}, {"he": "כאב", "ru": "боль", "translit": "кеЭв"}, {"he": "שן", "ru": "зуб", "translit": "шен"}, {"he": "זריקה", "ru": "укол", "translit": "зрикА"}, {"he": "טיפול", "ru": "лечение", "translit": "типУль"}, {"he": "סתימה", "ru": "пломба", "translit": "стимА"}, {"he": "הרדמה", "ru": "анестезия", "translit": "хардамА"}, {"he": "מרשם", "ru": "рецепт", "translit": "миршАм"}, {"he": "מרפאה", "ru": "клиника", "translit": "мирпаА"}]', NULL, 'dialogue');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (233, 2, 'מכתב מהאולפן', 'Письмо из ульпана', 'שלום אמא ואבא יקרים!
אני כותב לכם מהאולפן בירושלים. עברו כבר שלושה חודשים מאז שעליתי ארצה, ואני רוצה לספר לכם על החיים שלי.
אני לומד עברית כל יום מתשע בבוקר עד שתיים אחר הצהריים. המורה שלי, מיכל, מאוד סבלנית ומצחיקה. היא מסבירה הכל בעברית פשוטה ועם הרבה דוגמאות.
בכיתה יש עשרים סטודנטים — מרוסיה, צרפת, אמריקה, אתיופיה וברזיל. אנחנו מדברים ביחד רק עברית, גם כשקשה. עשיתי חברים — בעיקר עם דימה ממוסקבה ומארי מפריז.
אחרי הלימודים אני עובד במסעדה ברחוב יפו. אני מלצר שלוש פעמים בשבוע. העבודה עוזרת לי ללמוד עברית כי אני מדבר עם לקוחות כל הזמן. הטיפים לא רעים!
גר בדירה קטנה עם שני שותפים — דימה ועוד בחור מאתיופיה ששמו דניאל. הדירה פשוטה אבל נקייה. אנחנו מתחלקים בבישול.
בסופי שבוע אני מטייל. כבר הייתי בתל אביב, בחיפה ובים המלח! הארץ קטנה אבל יפה ומגוונת.
אני מתגעגע אליכם מאוד, אבל אני שמח שעליתי. כל יום אני מרגיש שהעברית שלי משתפרת. מקווה שתבואו לבקר בקרוב!
שלכם באהבה,
סשה', 'Дорогие мама и папа!
Пишу вам из ульпана в Иерусалиме. Прошло уже три месяца с тех пор, как я репатриировался, и я хочу рассказать вам о своей жизни.
Я учу иврит каждый день с девяти утра до двух дня. Моя учительница Михаль очень терпеливая и весёлая. Она объясняет всё на простом иврите и с множеством примеров.
В классе двадцать студентов — из России, Франции, Америки, Эфиопии и Бразилии. Мы говорим друг с другом только на иврите, даже когда трудно. Я подружился — особенно с Димой из Москвы и Мари из Парижа.
После учёбы я работаю в ресторане на улице Яффо. Я официант три раза в неделю. Работа помогает учить иврит, потому что я всё время разговариваю с клиентами. Чаевые неплохие!
Живу в маленькой квартире с двумя соседями — Димой и парнем из Эфиопии по имени Даниэль. Квартира простая, но чистая. Мы по очереди готовим.
По выходным я путешествую. Уже был в Тель-Авиве, в Хайфе и на Мёртвом море! Страна маленькая, но красивая и разнообразная.
Я очень скучаю по вам, но рад, что приехал. Каждый день чувствую, что мой иврит улучшается. Надеюсь, что вы скоро приедете в гости!
С любовью, ваш Саша', '[{"he": "כותב", "ru": "пишу", "translit": "котЕв"}, {"he": "סבלנית", "ru": "терпеливая", "translit": "савланИт"}, {"he": "סטודנטים", "ru": "студенты", "translit": "студЕнтим"}, {"he": "לימודים", "ru": "учёба", "translit": "лимудИм"}, {"he": "מתגעגע", "ru": "скучаю", "translit": "митгаагЕа"}, {"he": "שותפים", "ru": "соседи/сожители", "translit": "шутафИм"}, {"he": "לקוחות", "ru": "клиенты", "translit": "лекохОт"}, {"he": "מגוונת", "ru": "разнообразная", "translit": "мегувЕнет"}, {"he": "משתפרת", "ru": "улучшается", "translit": "миштапЕрет"}]', NULL, 'letter');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (234, 2, 'כדורגל בישראל', 'Футбол в Израиле', 'כדורגל הוא הספורט הפופולרי ביותר בישראל. כמעט כל ישראלי אוהד קבוצה כלשהי, ויש ויכוחים חמים על כדורגל בכל מקום — בעבודה, באוטובוס, בבית קפה.
בליגת העל הישראלית יש ארבע עשרה קבוצות. הכי מפורסמות: מכבי חיפה, הפועל באר שבע, מכבי תל אביב ובית"ר ירושלים. לכל קבוצה יש אוהדים נלהבים.
בשבת, כשיש משחק, האווירה ברחובות חשמלית. אוהדים לובשים את חולצת הקבוצה, נוסעים לאצטדיון ושרים שירי עידוד. מי שלא הולך לאצטדיון, צופה במשחק בבית עם חברים. יש צ''יפס, בירה וצעקות על השופט.
אני אוהד של מכבי חיפה. בילדות, סבא לקח אותי למשחק הראשון. האצטדיון היה מלא. הקהל צעק ושר. מכבי ניצחה 2-0 ואני התאהבתי בקבוצה.
השנה היה עונה מרגשת. מכבי ניצחה את הדרבי נגד הפועל חיפה 3-1. הייתי באצטדיון ויצאתי בלי קול מרוב צעקות.
כשהקבוצה שלך מנצחת — כולם שמחים ומחבקים. כשהיא מפסידה — כולם עצובים ומתלוננים. כדורגל הוא לא רק ספורט. זה רגש, קהילה ושייכות.
"מי תנצח הערב?" שואלים ברחוב. ובישראל, לכולם יש דעה!', 'Футбол — самый популярный вид спорта в Израиле. Почти каждый израильтянин болеет за какую-то команду, и жаркие споры о футболе повсюду — на работе, в автобусе, в кафе.
В израильской Премьер-лиге четырнадцать команд. Самые знаменитые: Маккаби Хайфа, Хапоэль Беэр-Шева, Маккаби Тель-Авив и Бейтар Иерусалим. У каждой команды — восторженные фанаты.
В субботу, когда есть матч, атмосфера на улицах электрическая. Болельщики надевают футболки команды, едут на стадион и поют кричалки. Кто не идёт на стадион — смотрит матч дома с друзьями. Чипсы, пиво и крики на судью.
Я болею за Маккаби Хайфу. В детстве дедушка взял меня на первый матч. Стадион был полным. Толпа кричала и пела. Маккаби выиграла 2-0, и я влюбился в команду.
В этом году был волнующий сезон. Маккаби выиграла дерби у Хапоэль Хайфа 3-1. Я был на стадионе и потерял голос от крика.
Когда твоя команда побеждает — все счастливы и обнимаются. Когда проигрывает — все грустят и жалуются. Футбол — это не просто спорт. Это эмоции, общность и принадлежность.
«Кто сегодня победит?» — спрашивают на улице. И в Израиле у всех есть мнение!', '[{"he": "כדורגל", "ru": "футбол", "translit": "кадурЕгель"}, {"he": "קבוצות", "ru": "команды", "translit": "квуцОт"}, {"he": "אצטדיון", "ru": "стадион", "translit": "ицтадиОн"}, {"he": "מנצחת", "ru": "побеждает", "translit": "менацАхат"}, {"he": "מפסידה", "ru": "проигрывает", "translit": "мафсидА"}, {"he": "אוהדים", "ru": "фанаты", "translit": "оhадИм"}, {"he": "ליגה", "ru": "лига", "translit": "лигА"}, {"he": "שופט", "ru": "судья", "translit": "шофЕт"}, {"he": "שייכות", "ru": "принадлежность", "translit": "шайахУт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (235, 2, 'השכרת רכב', 'Аренда машины', 'רצינו לטייל בצפון הארץ ולכן החלטנו לשכור רכב. הלכתי למשרד של חברת השכרה ליד התחנה המרכזית.
"שלום, אני רוצה לשכור רכב לשלושה ימים — מיום חמישי עד שבת בערב."
"בוודאי. יש לנו כמה אפשרויות. רכב קטן — מאה חמישים שקלים ליום. רכב בינוני — מאתיים שקלים ליום. ג''יפ — שלוש מאות חמישים שקלים ליום."
"אנחנו שני מבוגרים ושני ילדים. מספיק רכב בינוני?"
"בהחלט. יש לנו יונדאי חדש עם מזגן, רדיו ומערכת ניווט."
"מצוין. יש ביטוח?"
"ביטוח בסיסי כלול במחיר. אם אתה רוצה ביטוח מלא, בלי השתתפות עצמית, זה עוד חמישים שקלים ליום. אני ממליץ, בעיקר אם נוסעים בכבישי שטח בצפון."
"כן, ביטוח מלא, בבקשה. וגם מושב לילד."
"בסדר. אני צריך רישיון נהיגה, תעודת זהות וכרטיס אשראי." נתתי את המסמכים. הפקיד מילא טופס והסביר את התנאים.
"תחזיר את הרכב עם מיכל דלק מלא. אם לא — יש חיוב נוסף. הרכב חונה בקומה מינוס שתיים. הנה המפתחות."
"תודה! נסיעה טובה לנו."
ירדנו לחניון. הרכב היה נקי וחדש. שמתי את הכתובת בניווט ויצאנו לדרך. הטיול בצפון היה מדהים!', 'Мы хотели поездить по северу страны и решили арендовать машину. Я пошёл в офис прокатной компании рядом с центральной автостанцией.
«Здравствуйте, хочу арендовать машину на три дня — с четверга до вечера субботы.»
«Конечно. У нас несколько вариантов. Маленькая машина — сто пятьдесят шекелей в день. Средняя — двести шекелей. Джип — триста пятьдесят.»
«Нас двое взрослых и двое детей. Хватит средней?»
«Вполне. У нас новый Hyundai с кондиционером, радио и навигатором.»
«Отлично. Есть страховка?»
«Базовая страховка включена. Если хотите полную, без франшизы — ещё пятьдесят шекелей в день. Рекомендую, особенно если едете по просёлочным дорогам на севере.»
«Да, полную, пожалуйста. И детское кресло.»
«Хорошо. Нужны водительские права, удостоверение личности и кредитная карта.» Я отдал документы. Клерк заполнил бланк и объяснил условия.
«Верните машину с полным баком. Если нет — дополнительная плата. Машина на минус втором этаже парковки. Вот ключи.»
«Спасибо! Хорошей нам поездки.»
Спустились на парковку. Машина чистая и новая. Ввёл адрес в навигатор и отправились в путь. Поездка по северу была потрясающей!', '[{"he": "לשכור", "ru": "арендовать", "translit": "лисхОр"}, {"he": "רכב", "ru": "автомобиль", "translit": "рЕхев"}, {"he": "ביטוח", "ru": "страховка", "translit": "битуАх"}, {"he": "מחיר", "ru": "цена", "translit": "мехИр"}, {"he": "מפתחות", "ru": "ключи", "translit": "мафтехОт"}, {"he": "רישיון", "ru": "водительские права", "translit": "ришайОн"}, {"he": "דלק", "ru": "топливо", "translit": "дЕлек"}, {"he": "ניווט", "ru": "навигатор", "translit": "нивУт"}, {"he": "חניון", "ru": "парковка", "translit": "ханйОн"}]', NULL, 'dialogue');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (236, 2, 'סוף שבוע בכנרת', 'Выходные на Кинерете', 'בסוף השבוע נסענו לכנרת — הים של הגליל. לקחנו אוהל, שקי שינה, מצנן עם אוכל ושותים, וגיטרה.
חנינו באתר קמפינג על חוף הכנרת. שמנו את האוהל מתחת לעץ אקליפטוס גדול. האוויר היה חם ולח, אבל הייתה רוח קלה מהאגם.
אחרי שהקמנו את המחנה, רצנו למים. הכנרת חמה בקיץ — כמו מקלחת! שחינו, שיחקנו במים, ודוד הביא כדור מתנפח. לפעמים עבר סירת מפרש ונופפנו לה.
לארוחת ערב הדלקנו מנגל. אבא צלה קבבים, שיפודי עוף ונקניקיות. אמא הכינה סלט ישראלי — עגבניות, מלפפונים, בצל ופטרוזיליה. אכלנו עם פיתות חמות. "הכל יותר טעים בטבע," אמר אבא.
בלילה ישבנו ליד המדורה. אבא ניגן בגיטרה ושרנו שירים ישראליים — "ירושלים של זהב", "השירה שלך" ו"אני ואתה". אמא סיפרה בדיחות. הכוכבים באגם — מיליונים!
בבוקר קמנו מוקדם. שתינו קפה שחור חזק מהפינג''אן ואכלנו ארוחת בוקר גדולה: חומוס, טחינה, סלט, גבינות, לחם וביצה. אחר כך שחינו שוב.
אחר הצהריים פירקנו את האוהל ונסענו הביתה. ברכב כולם ישנו חוץ מאבא שנהג. היה סוף שבוע מושלם.', 'В выходные поехали на Кинерет — Галилейское море. Взяли палатку, спальные мешки, сумку-холодильник с едой и напитками, и гитару.
Остановились в кемпинге на берегу Кинерета. Поставили палатку под большим эвкалиптом. Воздух был тёплый и влажный, но с озера дул лёгкий ветерок.
Разбив лагерь, побежали к воде. Кинерет летом тёплый — как душ! Плавали, играли в воде, дядя Дуди привёз надувной мяч. Иногда проплывала парусная лодка, и мы ей махали.
На ужин разожгли мангал. Папа жарил кебабы, куриные шашлычки и сосиски. Мама приготовила израильский салат — помидоры, огурцы, лук и петрушка. Ели с горячими питами. «Всё вкуснее на природе,» — сказал папа.
Ночью сидели у костра. Папа играл на гитаре, мы пели израильские песни — «Иерусалим из золота», «Твоя песня» и «Я и ты». Мама рассказывала анекдоты. Звёзды над озером — миллионы!
Утром встали рано. Пили крепкий чёрный кофе из финджана и ели большой завтрак: хумус, тхину, салат, сыры, хлеб и яичницу. Потом снова плавали.
После обеда разобрали палатку и поехали домой. В машине все заснули, кроме папы за рулём. Идеальные выходные.', '[{"he": "כנרת", "ru": "Кинерет (озеро)", "translit": "кинЕрет"}, {"he": "אוהל", "ru": "палатка", "translit": "Охель"}, {"he": "מדורה", "ru": "костёр", "translit": "медурА"}, {"he": "אגם", "ru": "озеро", "translit": "агАм"}, {"he": "חומוס", "ru": "хумус", "translit": "хУмус"}, {"he": "מנגל", "ru": "мангал/гриль", "translit": "мангАль"}, {"he": "גיטרה", "ru": "гитара", "translit": "гитАра"}, {"he": "מחנה", "ru": "лагерь", "translit": "маханЕ"}, {"he": "כוכבים", "ru": "звёзды", "translit": "кохавИм"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (237, 2, 'בקופת חולים', 'В поликлинике', 'בישראל כל תושב חייב להיות חבר בקופת חולים. יש ארבע קופות: כללית, מכבי, מאוחדת ולאומית. אני חבר בקופת חולים כללית.
בשבוע שעבר הרגשתי לא טוב — שיעול, נזלת וכאב ראש. התקשרתי לקופה לקבוע תור.
"שלום, אני רוצה תור לרופא משפחה."
"מתי נוח לך? יש תור מחר בעשר בבוקר או ביום רביעי בארבע."
"מחר בעשר, בבקשה."
"בסדר. תביא תעודת זהות וכרטיס קופת חולים."
למחרת הגעתי לקופה. לקחתי מספר בתורומט ומתנתי. אחרי עשרים דקות הגיע התור שלי.
"שלום, דוקטור. יש לי שיעול ונזלת כבר שלושה ימים. ויש חום קל."
הרופא בדק אותי — הקשיב לריאות, בדק את הגרון ומדד לחץ דם. "יש לך הצטננות. לא צריך אנטיביוטיקה. תנוח יומיים, תשתה הרבה נוזלים ותיקח אקמול לחום."
"אני צריך אישור מחלה לעבודה."
"אני נותן לך אישור לשלושה ימים. אם לא ישתפר עד יום חמישי, תחזור אלי."
הרופא הדפיס את המרשם והאישור. ירדתי לבית מרקחת שבתוך הקופה וקניתי תרופות — אקמול, סירופ לשיעול וטיפות לאף.
אחרי שלושה ימים של מנוחה ותה חם, הרגשתי הרבה יותר טוב.', 'В Израиле каждый житель обязан быть членом больничной кассы. Их четыре: Клалит, Маккаби, Меухедет и Леумит. Я — в Клалит.
На прошлой неделе почувствовал себя плохо — кашель, насморк и головная боль. Позвонил в кассу записаться.
«Здравствуйте, хочу записаться к семейному врачу.»
«Когда вам удобно? Есть запись завтра в десять утра или в среду в четыре.»
«Завтра в десять, пожалуйста.»
«Хорошо. Принесите удостоверение личности и карточку больничной кассы.»
На следующий день пришёл. Взял номерок в автомате и ждал. Через двадцать минут — моя очередь.
«Здравствуйте, доктор. У меня кашель и насморк уже три дня. И небольшая температура.»
Врач осмотрел меня — послушал лёгкие, проверил горло, измерил давление. «У вас простуда. Антибиотики не нужны. Отдыхайте два дня, пейте много жидкости и принимайте акамол от температуры.»
«Мне нужен больничный для работы.»
«Даю вам справку на три дня. Если не станет лучше к четвергу, вернитесь.»
Врач распечатал рецепт и справку. Спустился в аптеку внутри поликлиники и купил лекарства — акамол, сироп от кашля и капли в нос.
Через три дня отдыха и горячего чая почувствовал себя намного лучше.', '[{"he": "קופת חולים", "ru": "больничная касса", "translit": "купАт холИм"}, {"he": "תור", "ru": "очередь/запись", "translit": "тор"}, {"he": "רופא משפחה", "ru": "семейный врач", "translit": "рофЕ мишпахА"}, {"he": "מרשם", "ru": "рецепт", "translit": "миршАм"}, {"he": "תרופות", "ru": "лекарства", "translit": "труфОт"}, {"he": "בית מרקחת", "ru": "аптека", "translit": "бейт миркАхат"}, {"he": "שיעול", "ru": "кашель", "translit": "шиУль"}, {"he": "הצטננות", "ru": "простуда", "translit": "хицтаненУт"}, {"he": "אישור מחלה", "ru": "больничный", "translit": "ишУр махалА"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (238, 2, 'להתקשר לשרברב', 'Вызвать сантехника', 'ביום שישי בבוקר גיליתי שיש בעיה במטבח. הברז טפטף כל הלילה ומתחת לכיור הייתה שלולית מים. ניסיתי לסגור את הברז חזק, אבל זה לא עזר.
"אנחנו חייבים שרברב," אמרה אשתי.
התקשרתי לשרברב שהשכנים המליצו. "שלום, יש לנו בעיה — הברז במטבח לא מפסיק לטפטף ויש נזילה מתחת לכיור."
"אני יכול לבוא בעוד שעה. מתאים?"
"מצוין, תודה."
השרברב הגיע בזמן. הוא היה בחור צעיר עם ארגז כלים ענק. "בוא נראה מה הבעיה," הוא אמר. הוא הסתכל מתחת לכיור ועל הברז.
"הבעיה ברורה. הצינור ישן ומחליד. והברז צריך אטם חדש. אני יכול לתקן את הברז ולהחליף את הצינור. ייקח בערך ארבעים דקות."
"כמה זה יעלה?" שאלתי.
"שלוש מאות שקלים כולל חלפים ועבודה."
"בסדר, תתקן בבקשה."
הוא עבד בשקט וביעילות. אחרי ארבעים דקות הכל היה מתוקן. הברז לא טפטף, הצינור חדש וכסוף.
"הנה. החלפתי את האטם בברז ואת הצינור מתחת לכיור. אם תהיה בעיה — תתקשר. יש אחריות של שנה על העבודה."
שילמתי ונתתי לו חמישים שקלים טיפ. "תודה רבה! שבת שלום," אמרתי. "שבת שלום," הוא חייך ויצא.', 'В пятницу утром я обнаружил проблему на кухне. Кран капал всю ночь, и под раковиной была лужа. Попробовал закрыть кран сильнее, но не помогло.
«Нам нужен сантехник,» — сказала жена.
Позвонил сантехнику, которого рекомендовали соседи. «Здравствуйте, у нас проблема — кран на кухне не перестаёт капать и есть утечка под раковиной.»
«Могу прийти через час. Подходит?»
«Отлично, спасибо.»
Сантехник пришёл вовремя. Молодой парень с огромным ящиком инструментов. «Давайте посмотрим, в чём проблема,» — сказал он. Заглянул под раковину и осмотрел кран.
«Проблема ясна. Труба старая и ржавая. А кран нуждается в новой прокладке. Могу починить кран и заменить трубу. Займёт около сорока минут.»
«Сколько будет стоить?» — спросил я.
«Триста шекелей, включая запчасти и работу.»
«Хорошо, чините.»
Он работал тихо и эффективно. Через сорок минут всё было починено. Кран не капает, труба новая и блестящая.
«Вот. Заменил прокладку в кране и трубу под раковиной. Если будет проблема — звоните. Год гарантии на работу.»
Заплатил и дал пятьдесят шекелей чаевых. «Большое спасибо! Шабат Шалом,» — сказал я. «Шабат Шалом,» — улыбнулся он и ушёл.', '[{"he": "שרברב", "ru": "сантехник", "translit": "шравраАв"}, {"he": "ברז", "ru": "кран", "translit": "бЕрез"}, {"he": "נזילה", "ru": "утечка", "translit": "незилА"}, {"he": "צינור", "ru": "труба", "translit": "цинОр"}, {"he": "לתקן", "ru": "починить", "translit": "летакЕн"}, {"he": "כלים", "ru": "инструменты", "translit": "келИм"}, {"he": "אטם", "ru": "прокладка", "translit": "Отем"}, {"he": "אחריות", "ru": "гарантия", "translit": "ахарайУт"}, {"he": "חלפים", "ru": "запчасти", "translit": "халафИм"}]', NULL, 'dialogue');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (239, 2, 'תחבורה ציבורית', 'Общественный транспорт', 'מערכת התחבורה הציבורית בישראל השתפרה מאוד בשנים האחרונות. בואו נכיר את האפשרויות.
אוטובוסים הם הדרך הנפוצה ביותר לנסוע בישראל. חברת אגד היא הגדולה ביותר, אבל יש גם דן, קווים, מטרופולין ואחרות. אוטובוסים מגיעים כל כמה דקות בקווים הראשיים. בשבת רוב האוטובוסים לא נוסעים, חוץ מחיפה ובאר שבע.
כרטיס רב-קו הוא כרטיס חכם שעובד בכל התחבורה הציבורית. אפשר לטעון אותו בתחנות, באינטרנט או בכל חנות נוחות. עם רב-קו אתה מקבל הנחה של שלושים אחוז.
הרכבת מחברת בין ערים גדולות — מנהריה בצפון עד באר שבע בדרום. הנסיעה מתל אביב לחיפה לוקחת שעה. הרכבת נוחה, מהירה, ויש בה שירותים ומזנון.
בירושלים יש רכבת קלה — קו אדום שעובר דרך מרכז העיר. נוסע מפסגת זאב בצפון עד הר הרצל בדרום. הנסיעה לוקחת ארבעים דקות. בקרוב ייפתחו עוד קווים.
בתל אביב יש קורקינטים חשמליים בכל מקום. אפשר לשכור אותם דרך אפליקציה. זה מהר ונוח, אבל צריך להיזהר בכבישים!
מוניות שירות הן אפשרות זולה לנסוע בשבת. הן נוסעות באותם קווים כמו האוטובוסים ועולות קצת יותר.
עצה חשובה: תכננו את הנסיעה מראש באפליקציית מוביט או גוגל מפות. ככה תדעו בדיוק מתי האוטובוס מגיע!', 'Система общественного транспорта в Израиле значительно улучшилась в последние годы. Давайте познакомимся с вариантами.
Автобусы — самый распространённый способ передвижения. Компания «Эгед» — крупнейшая, но есть также «Дан», «Кавим», «Метрополин» и другие. Автобусы ходят каждые несколько минут на основных маршрутах. По субботам большинство автобусов не ходит, кроме Хайфы и Беэр-Шевы.
Рав-Кав — умная карта, которая работает во всём транспорте. Можно пополнить на остановках, онлайн или в любом мини-маркете. С Рав-Кав — скидка тридцать процентов.
Поезд соединяет крупные города — от Нагарии на севере до Беэр-Шевы на юге. Дорога из Тель-Авива в Хайфу — час. Поезд удобный, быстрый, есть туалеты и буфет.
В Иерусалиме есть лёгкий трамвай — красная линия через центр города. Едет от Писгат Зеэв на севере до горы Герцля на юге. Дорога — сорок минут. Скоро откроются новые линии.
В Тель-Авиве повсюду электросамокаты. Можно взять через приложение. Быстро и удобно, но нужно быть осторожным на дорогах!
Маршрутки — дешёвый вариант в субботу. Ходят по тем же маршрутам, что и автобусы, стоят чуть дороже.
Важный совет: планируйте поездку заранее через приложение «Мовит» или Google Maps. Так вы точно будете знать, когда придёт автобус!', '[{"he": "תחבורה ציבורית", "ru": "общ. транспорт", "translit": "тахбурА цибурИт"}, {"he": "רכבת", "ru": "поезд", "translit": "ракЕвет"}, {"he": "רכבת קלה", "ru": "лёгкий трамвай", "translit": "ракЕвет калА"}, {"he": "כרטיס", "ru": "билет/карта", "translit": "картИс"}, {"he": "מוניות שירות", "ru": "маршрутки", "translit": "монийОт шерУт"}, {"he": "קורקינט", "ru": "самокат", "translit": "коркинЕт"}, {"he": "אפליקציה", "ru": "приложение", "translit": "апликАция"}, {"he": "הנחה", "ru": "скидка", "translit": "ханахА"}, {"he": "לתכנן", "ru": "планировать", "translit": "летахнЕн"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (240, 2, 'חיפוש עבודה', 'Поиск работы', 'כבר חודשיים אני מחפש עבודה. זה לא קל, אבל אני לא מוותר.
בהתחלה עדכנתי את קורות החיים שלי. כתבתי על ההשכלה — תואר ראשון בהנדסת תוכנה מאוניברסיטת ברוסיה, ועל הניסיון — שלוש שנים בחברת תוכנה.
אחר כך נרשמתי באתרים של דרושים — אולג''ובס, לינקדין וגוטפרנדס. שלחתי קורות חיים לעשרים חברות.
בשבוע הראשון קיבלתי שלוש תשובות שליליות: "תודה על העניין, אבל מצאנו מועמד מתאים יותר." קשה לקבל ''לא'', אבל זה חלק מהתהליך.
בשבוע השני קיבלתי טלפון מחברת הייטק: "ראינו את קורות החיים שלך ואנחנו רוצים להזמין אותך לראיון." שמחתי מאוד!
הכנתי את עצמי — קראתי על החברה, תרגלתי תשובות לשאלות נפוצות, הכנתי בגדים מסודרים.
הראיון הלך טוב. שאלו אותי על הניסיון, על ההשכלה ועל מה שאני רוצה להשיג. עשו לי גם מבחן טכני קצר.
אחרי שלושה ימים קיבלתי מייל: "אנחנו שמחים להודיע לך שהתקבלת לעבודה!" צעקתי משמחה. התקשרתי מיד לאמא.
"מזל טוב, בן שלי!" היא אמרה ובכתה. "ידעתי שתצליח."
בשבוע הבא אני מתחיל. העבודה בתל אביב, השכר טוב, ויש צוות בינלאומי. אני נרגש ומוכן להתחלה חדשה!', 'Уже два месяца я ищу работу. Нелегко, но я не сдаюсь.
Сначала обновил резюме. Написал об образовании — степень бакалавра по программной инженерии из российского университета — и об опыте — три года в софтверной компании.
Потом зарегистрировался на сайтах вакансий — AllJobs, LinkedIn и GotFriends. Разослал резюме в двадцать компаний.
В первую неделю получил три отказа: «Спасибо за интерес, но мы нашли более подходящего кандидата.» Тяжело слышать «нет», но это часть процесса.
На второй неделе позвонили из хайтек-компании: «Мы видели ваше резюме и хотим пригласить вас на собеседование.» Я очень обрадовался!
Подготовился — прочитал о компании, порепетировал ответы на частые вопросы, подготовил аккуратную одежду.
Собеседование прошло хорошо. Спрашивали об опыте, образовании и о том, чего я хочу добиться. Ещё был короткий технический тест.
Через три дня получил письмо: «Мы рады сообщить, что вы приняты!» Я закричал от радости. Сразу позвонил маме.
«Поздравляю, сынок!» — сказала она и заплакала. «Я знала, что у тебя получится.»
На следующей неделе начинаю. Работа в Тель-Авиве, зарплата хорошая, и есть международная команда. Я взволнован и готов к новому началу!', '[{"he": "מחפש", "ru": "ищу", "translit": "мехапЕс"}, {"he": "קורות חיים", "ru": "резюме", "translit": "корОт хаИм"}, {"he": "ניסיון", "ru": "опыт", "translit": "нисайОн"}, {"he": "השכלה", "ru": "образование", "translit": "хаскалА"}, {"he": "מקווה", "ru": "надеюсь", "translit": "мекавЕ"}, {"he": "מועמד", "ru": "кандидат", "translit": "моомАд"}, {"he": "שכר", "ru": "зарплата", "translit": "сахАр"}, {"he": "צוות", "ru": "команда", "translit": "цевЕт"}, {"he": "נרגש", "ru": "взволнован", "translit": "ниргАш"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (241, 3, 'עולים חדשים בישראל', 'Новые репатрианты в Израиле', 'כל שנה מגיעים לישראל אלפי עולים חדשים ממדינות שונות בעולם. הם באים מרוסיה, מצרפת, מאתיופיה, מארגנטינה ומעוד מקומות רבים. כל אחד מגיע עם סיפור אחר — יש שבאים בגלל הציונות, יש שבאים בגלל המשפחה, ויש שמחפשים חיים חדשים.
הצעד הראשון אחרי ההגעה הוא הלימוד בתוכנית אולפן. האולפן הוא בית ספר מיוחד ללימוד עברית לעולים. הלימודים נמשכים בדרך כלל חמישה חודשים, חמש שעות ביום. בכיתה יושבים אנשים מכל העולם — רופא מרוסיה ליד מהנדס מברזיל ומורה מצרפת. בהתחלה כולם מתקשים, אבל אחרי כמה שבועות מתחילים להבין ולדבר.
הקליטה בישראל היא לא רק שפה. צריך ללמוד את המנטליות הישראלית — אנשים ישירים מאוד, לפעמים חסרי סבלנות, אבל גם חמים ומוכנים לעזור. מזג האוויר שונה — בקיץ חם מאוד, ובחורף יש גשם. הבירוקרטיה יכולה להיות מסובכת: ביטוח לאומי, קופת חולים, פתיחת חשבון בנק — הכל דורש סבלנות ומסמכים רבים.
למרות הקשיים, רוב העולים מצליחים להשתלב. הממשלה מספקת סיוע — סל קליטה עם כסף לחודשים הראשונים, עזרה במציאת דירה ולימודים מקצועיים. ארגונים כמו הסוכנות היהודית ונפש בנפש עוזרים לעולים בכל שלב. שכנים ישראלים מזמינים את העולים לארוחות שבת, ומתנדבים מלמדים אותם עברית. אחרי שנה או שנתיים, רוב העולים כבר מרגישים בבית. הם עובדים, הילדים שלהם לומדים בבית ספר ומדברים עברית כמו ילידים.', 'Каждый год в Израиль приезжают тысячи новых репатриантов из разных стран мира. Они приезжают из России, Франции, Эфиопии, Аргентины и многих других мест. У каждого своя история — одни приезжают из-за сионизма, другие — ради семьи, третьи ищут новую жизнь.
Первый шаг после приезда — учёба в программе ульпан. Ульпан — это специальная школа для изучения иврита репатриантами. Обучение обычно длится пять месяцев, по пять часов в день. В классе сидят люди со всего мира — врач из России рядом с инженером из Бразилии и учительницей из Франции. Поначалу всем трудно, но через несколько недель начинают понимать и говорить.
Адаптация в Израиле — это не только язык. Нужно привыкнуть к израильскому менталитету — люди очень прямые, иногда нетерпеливые, но при этом тёплые и готовые помочь. Климат другой — летом очень жарко, а зимой идут дожди. Бюрократия может быть сложной: национальное страхование, больничная касса, открытие банковского счёта — всё требует терпения и множества документов.
Несмотря на трудности, большинство репатриантов успешно интегрируются. Государство предоставляет помощь — корзину абсорбции с деньгами на первые месяцы, помощь в поиске жилья и профессиональное обучение. Организации вроде Еврейского агентства и Нефеш бе-Нефеш помогают репатриантам на каждом этапе. Израильские соседи приглашают новых репатриантов на субботние трапезы, а волонтёры учат их ивриту. Через год-два большинство уже чувствуют себя дома. Они работают, их дети учатся в школе и говорят на иврите как местные.', '[{"he": "עולים חדשים", "ru": "новые репатрианты", "translit": "олИм хадашИм"}, {"he": "אולפן", "ru": "ульпан", "translit": "ульпАн"}, {"he": "קליטה", "ru": "абсорбция/адаптация", "translit": "клитА"}, {"he": "מנטליות", "ru": "менталитет", "translit": "менталиЮт"}, {"he": "בירוקרטיה", "ru": "бюрократия", "translit": "бирократйА"}, {"he": "סל קליטה", "ru": "корзина абсорбции", "translit": "саль клитА"}, {"he": "מתנדבים", "ru": "волонтёры", "translit": "митнадвИм"}, {"he": "להשתלב", "ru": "интегрироваться", "translit": "леhишталЕв"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (242, 3, 'ראיון עם שף ישראלי', 'Интервью с израильским шефом', '"מה מיוחד במטבח הישראלי?" שואלת הכתבת את השף יוסי בן-דוד, שמנהל מסעדה פופולרית בתל אביב כבר עשר שנים. "המטבח שלנו הוא שילוב מדהים של תרבויות," הוא מסביר בחיוך. "יש בו השפעות מרוקאיות, תימניות, אירופיות ומזרחיות. כל עדה הביאה את המתכונים שלה, ועם הזמן הכל התערבב ליצירה ישראלית ייחודית."
"מה המנה הכי פופולרית במסעדה שלך?" "בלי ספק השקשוקה שלנו. זו שקשוקה מסורתית עם טוויסט — אני מוסיף גבינת עיזים, פטרוזיליה טרייה ופלפל חריף. אנשים באים מכל הארץ בשביל המנה הזאת. גם החומוס שלנו מיוחד — אנחנו מכינים אותו כל בוקר טרי עם טחינה גולמית ושמן זית מהגליל."
"ומה לגבי הטרנדים החדשים?" "היום הטרנד הגדול הוא אוכל צמחוני וטבעוני. יותר ויותר ישראלים עוברים לצמחונות. ישראל היא אחת המדינות עם הכי הרבה טבעונים בעולם! זה מאתגר ומעניין מבחינה קולינרית. אני מפתח מנות חדשות כל הזמן — המבורגר מעדשים, קציצות חומוס, עוגות בלי ביצים. המטבח הצמחוני הישראלי כבר מפורסם בעולם."
"ומה לגבי אוכל רחוב?" "אוכל רחוב זה הלב של המטבח הישראלי! פלאפל, שווארמה, סביח, בורקס — אפשר למצוא דוכנים מעולים בכל עיר. אני תמיד אומר לתיירים: רוצים להכיר את ישראל? תתחילו מהשוק. שוק הכרמל בתל אביב, שוק מחנה יהודה בירושלים — שם הריחות, הצבעים והטעמים מספרים את כל הסיפור של המדינה הזאת."', '«Что особенного в израильской кухне?» — спрашивает журналистка шефа Йоси Бен-Давида, который управляет популярным рестораном в Тель-Авиве уже десять лет. «Наша кухня — это потрясающее сочетание культур,» — объясняет он с улыбкой. «В ней есть марокканские, йеменские, европейские и восточные влияния. Каждая община привезла свои рецепты, и со временем всё смешалось в уникальное израильское творение.»
«Какое самое популярное блюдо в твоём ресторане?» «Без сомнения, наша шакшука. Это традиционная шакшука с изюминкой — я добавляю козий сыр, свежую петрушку и острый перец. Люди приезжают со всей страны ради этого блюда. Наш хумус тоже особенный — мы готовим его каждое утро свежим, с сырой тхиной и оливковым маслом из Галилеи.»
«А что насчёт новых трендов?» «Сейчас большой тренд — вегетарианская и веганская кухня. Всё больше израильтян переходят на вегетарианство. Израиль — одна из стран с наибольшим числом веганов в мире! Это интересный и вызывающий кулинарный вызов. Я постоянно разрабатываю новые блюда — бургер из чечевицы, котлеты из нута, торты без яиц. Израильская вегетарианская кухня уже знаменита в мире.»
«А что насчёт уличной еды?» «Уличная еда — это сердце израильской кухни! Фалафель, шаварма, сабих, бурекас — отличные ларьки можно найти в любом городе. Я всегда говорю туристам: хотите узнать Израиль? Начните с рынка. Рынок Кармель в Тель-Авиве, рынок Махане Иегуда в Иерусалиме — там запахи, краски и вкусы рассказывают всю историю этой страны.»', '[{"he": "שף", "ru": "шеф-повар", "translit": "шеф"}, {"he": "מטבח", "ru": "кухня (кулинария)", "translit": "митбАх"}, {"he": "שילוב", "ru": "сочетание", "translit": "шилУв"}, {"he": "מתכון", "ru": "рецепт", "translit": "матхОн"}, {"he": "צמחוני", "ru": "вегетарианский", "translit": "цимхонИ"}, {"he": "טבעוני", "ru": "веганский", "translit": "тивъонИ"}, {"he": "דוכן", "ru": "ларёк/прилавок", "translit": "духАн"}, {"he": "תבלינים", "ru": "специи", "translit": "тавлинИм"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (243, 3, 'ביקורת סרט: "מבצע סבתא"', 'Рецензия на фильм: «Операция Бабушка»', 'הקומדיה הישראלית "מבצע סבתא" היא אחד הסרטים המצחיקים והמרגשים שראיתי השנה. הסרט מספר על משפחה ישראלית טיפוסית — רועשת, חמה ומלאה דרמה. הסיפור מתחיל כשהסבתא רחל, בת שמונים ושתיים, מודיעה למשפחה שהיא רוצה למכור את הבית הישן ולעבור לדיור מוגן.
הנכדים, שגדלו בבית הזה, לא מוכנים לוותר. הם מחליטים לארגן "מבצע" כדי לשכנע את סבתא להישאר. כל נכד מנסה בדרך אחרת — האחד מבשל את המאכלים האהובים עליה, השנייה מארגנת ערב משפחתי, והשלישי מביא את החברה הישנה שלה מפולין. כמובן, כל ניסיון נכשל בצורה מצחיקה.
השחקנית שמגלמת את הסבתא היא גילה אלמגור, ויא משחקת בצורה מדהימה. היא מצחיקה ומרגשת באותו הזמן. הסצנות בין הסבתא לנכדים הן הלב של הסרט. יש רגעים שצוחקים עד דמעות, ורגעים שבוכים מרוב התרגשות. הדיאלוגים כתובים נהדר — טבעיים ומלאי הומור ישראלי.
הסרט מציג נושאים חשובים: הקשר בין הדורות, פחד מזקנה, זיכרונות משפחה ושאלת מה באמת חשוב בחיים. בסוף, הסבתא מפתיעה את כולם בהחלטה שאף אחד לא ציפה לה. לא אגלה מה ההחלטה — צריך לראות את הסרט! ממליץ מאוד, במיוחד לצפייה משפחתית. ציון: ארבע וחצי כוכבים מתוך חמישה.', 'Израильская комедия «Операция Бабушка» — один из самых смешных и трогательных фильмов, которые я видел в этом году. Фильм рассказывает о типичной израильской семье — шумной, тёплой и полной драмы. История начинается, когда бабушка Рахель, восьмидесяти двух лет, сообщает семье, что хочет продать старый дом и переехать в дом престарелых.
Внуки, выросшие в этом доме, не готовы смириться. Они решают организовать «операцию», чтобы убедить бабушку остаться. Каждый внук пробует по-своему — один готовит её любимые блюда, другая устраивает семейный вечер, третий привозит её старую подругу из Польши. Разумеется, каждая попытка проваливается комично.
Актриса, играющая бабушку — Гила Альмагор, и она играет потрясающе. Она смешная и трогательная одновременно. Сцены между бабушкой и внуками — сердце фильма. Есть моменты, когда смеёшься до слёз, и моменты, когда плачешь от волнения. Диалоги написаны прекрасно — естественные и полные израильского юмора.
Фильм поднимает важные темы: связь поколений, страх старости, семейные воспоминания и вопрос о том, что действительно важно в жизни. В конце бабушка удивляет всех решением, которого никто не ожидал. Не раскрою какое — нужно посмотреть фильм! Очень рекомендую, особенно для семейного просмотра. Оценка: четыре с половиной звезды из пяти.', '[{"he": "קומדיה", "ru": "комедия", "translit": "комЕдия"}, {"he": "מרגש", "ru": "трогательный", "translit": "маргИш"}, {"he": "נכדים", "ru": "внуки", "translit": "нехадИм"}, {"he": "לשכנע", "ru": "убедить", "translit": "лешахнЕа"}, {"he": "שחקנית", "ru": "актриса", "translit": "сахканИт"}, {"he": "דיאלוגים", "ru": "диалоги", "translit": "диалОгим"}, {"he": "דיור מוגן", "ru": "дом престарелых", "translit": "диЮр мугАн"}, {"he": "ציון", "ru": "оценка", "translit": "циЮн"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (249, 3, 'מכתב תלונה למלון', 'Жалоба в отель', 'לכבוד הנהלת מלון "כנרת",
שמי אלכסנדר פטרוב, ושהיתי במלון שלכם בשבוע שעבר, מיום שני עד יום חמישי, בחדר 305. אני כותב מכתב זה כדי לדווח על חוויה מאוד לא נעימה שהייתה לי.
ראשית, המזגן בחדר לא עבד כמו שצריך. הוא עשה רעש חזק ולא קירר את החדר. הטמפרטורה בחדר הייתה שלושים ושתיים מעלות, ולא יכולתי לישון בלילה. התקשרתי לקבלה שלוש פעמים — בפעם הראשונה אמרו שישלחו טכנאי, בפעם השנייה ביקשו ממני לחכות, ובפעם השלישית אף אחד לא ענה לטלפון.
שנית, חדר האוכל נסגר מוקדם — בשמונה וחצי בערב במקום עשר כמו שכתוב באתר. הגעתי בתשע ומצאתי דלת סגורה. שום הודעה על שינוי בשעות. הייתי צריך ללכת לחפש מסעדה בעיר. שלישית, המקלחת הייתה קרה ביום השני — לא היה מים חמים במשך שעתיים בבוקר.
אני מבין שבעיות קורות, אבל הבעיה העיקרית הייתה שאף אחד מהצוות לא טיפל בבעיות שלי. ציפיתי לרמת שירות גבוהה יותר ממלון ארבעה כוכבים. אני מבקש פיצוי הולם — הנחה משמעותית על השהייה הבאה או החזר כספי חלקי. אני מקווה שתטפלו בעניין במהירות.
בכבוד רב,
אלכסנדר פטרוב
טלפון: 054-9876543
דוא"ל: alex.petrov@email.com', 'Уважаемое руководство отеля «Кинерет»,
Меня зовут Александр Петров, и я останавливался в вашем отеле на прошлой неделе, с понедельника по четверг, в номере 305. Я пишу это письмо, чтобы сообщить об очень неприятном опыте.
Во-первых, кондиционер в номере не работал как следует. Он громко шумел и не охлаждал комнату. Температура в номере была тридцать два градуса, и я не мог спать ночью. Я звонил на ресепшен три раза — в первый раз сказали, что пришлют техника, во второй попросили подождать, а в третий никто не ответил на звонок.
Во-вторых, ресторан закрылся рано — в полдевятого вечера вместо десяти, как указано на сайте. Я пришёл в девять и нашёл закрытую дверь. Никакого объявления об изменении часов. Пришлось идти искать ресторан в городе. В-третьих, душ был холодным на второй день — горячей воды не было два часа утром.
Я понимаю, что проблемы случаются, но главная проблема в том, что никто из персонала не занялся моими проблемами. Я ожидал более высокого уровня сервиса от четырёхзвёздочного отеля. Прошу надлежащую компенсацию — значительную скидку на следующее проживание или частичный возврат средств. Надеюсь, что вы быстро займётесь этим вопросом.
С уважением,
Александр Петров
Телефон: 054-9876543
Эл. почта: alex.petrov@email.com', '[{"he": "תלונה", "ru": "жалоба", "translit": "тлунА"}, {"he": "הנהלה", "ru": "руководство", "translit": "ханхалА"}, {"he": "מזגן", "ru": "кондиционер", "translit": "мазгАн"}, {"he": "קבלה", "ru": "ресепшен", "translit": "кабалА"}, {"he": "טכנאי", "ru": "техник", "translit": "технАй"}, {"he": "פיצוי", "ru": "компенсация", "translit": "пицУй"}, {"he": "החזר כספי", "ru": "возврат средств", "translit": "хехзЕр каспИ"}, {"he": "לדווח", "ru": "сообщать", "translit": "ледавЕах"}]', NULL, 'letter');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (244, 3, 'בלוג: החיים בקיבוץ', 'Блог: Жизнь в кибуце', 'לפני שנה עשיתי את הצעד הגדול — עזבתי את תל אביב ועברתי לגור בקיבוץ בצפון הארץ. חברים אמרו לי שאני משוגע, שאתגעגע לעיר, לבתי הקפה, לחיי הלילה. היום, אחרי שנה שלמה, אני יכול להגיד: עשיתי את הבחירה הנכונה.
הבוקר בקיבוץ מתחיל מוקדם. בשש אני קם, שותה קפה במרפסת ומסתכל על ההרים. אני שומע ציפורים, לא מכוניות. האוויר נקי וטרי. בשבע אני הולך לעבודה — עבדתי קודם במשרד בתל אביב, ועכשיו אני עובד בחקלאות, בגידול אבוקדו ומנגו. בהתחלה היה קשה פיזית, אבל עכשיו אני מרגיש חזק ובריא.
הקהילה כאן היא משהו מדהים. כולם מכירים את כולם. כשהמכונית שלי התקלקלה, שכן בא מיד לעזור. כשהייתי חולה, שכנה הביאה לי מרק. בקיבוץ יש חדר אוכל משותף — אני אוכל שם ארוחת צהריים כל יום עם חברים. יש גם בריכת שחייה, ספרייה, חדר כושר וגן ילדים. הכל קרוב, הכל ברגל.
כמובן, יש גם חסרונות. לפעמים מתגעגע לפיצה בשתיים בלילה או לקונצרט ספונטני. אין הרבה אנשים בגילי כאן — רוב תושבי הקיבוץ הם משפחות או קשישים. ולפעמים חסר לי הפרטיות — כשכולם מכירים את כולם, כולם גם יודעים את העסקים שלך. אבל בסך הכל, החיים כאן יותר שקטים, יותר בריאים ויותר משמעותיים. אני ממליץ לכל מי שעייף מהעיר לנסות — לפחות לחצי שנה.', 'Год назад я сделал большой шаг — уехал из Тель-Авива и переехал жить в кибуц на севере страны. Друзья говорили, что я сумасшедший, что буду скучать по городу, по кафе, по ночной жизни. Сегодня, через целый год, я могу сказать: я сделал правильный выбор.
Утро в кибуце начинается рано. В шесть я встаю, пью кофе на балконе и смотрю на горы. Я слышу птиц, а не машины. Воздух чистый и свежий. В семь иду на работу — раньше я работал в офисе в Тель-Авиве, а теперь работаю в сельском хозяйстве, выращиваю авокадо и манго. Поначалу было физически тяжело, но теперь я чувствую себя сильным и здоровым.
Община здесь — это нечто удивительное. Все знают всех. Когда моя машина сломалась, сосед сразу пришёл помочь. Когда я болел, соседка принесла суп. В кибуце есть общая столовая — я обедаю там каждый день с друзьями. Есть также бассейн, библиотека, тренажёрный зал и детский сад. Всё рядом, всё пешком.
Конечно, есть и минусы. Иногда скучаю по пицце в два часа ночи или по спонтанному концерту. Не так много людей моего возраста — большинство жителей кибуца это семьи или пожилые люди. И иногда не хватает личного пространства — когда все знают всех, все знают и твои дела. Но в целом жизнь здесь спокойнее, здоровее и осмысленнее. Рекомендую всем, кто устал от города, попробовать — хотя бы на полгода.', '[{"he": "קיבוץ", "ru": "кибуц", "translit": "кибУц"}, {"he": "חקלאות", "ru": "сельское хозяйство", "translit": "хаклаУт"}, {"he": "קהילה", "ru": "община", "translit": "кехилА"}, {"he": "מרפסת", "ru": "балкон", "translit": "мирпЕсет"}, {"he": "חדר אוכל", "ru": "столовая", "translit": "хЕдер Охель"}, {"he": "חסרונות", "ru": "минусы/недостатки", "translit": "хесронОт"}, {"he": "פרטיות", "ru": "личное пространство", "translit": "пратиЮт"}, {"he": "משמעותי", "ru": "осмысленный", "translit": "машмаутИ"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (245, 3, 'חגיגות יום העצמאות', 'Празднование Дня независимости', 'יום העצמאות הוא החג הלאומי של ישראל, ויש לו מקום מיוחד בלב של כל ישראלי. הוא נחגג בה'' באייר לפי הלוח העברי, בדרך כלל באפריל או במאי. אבל לפני שמתחילות החגיגות, יש יום מאוד שונה — יום הזיכרון לחללי מערכות ישראל.
יום הזיכרון הוא אחד הימים העצובים ביותר בישראל. בבוקר נשמעת צפירה — כל האנשים עומדים דום, המכוניות עוצרות, הכל שקט לדקה שלמה. בבתי העלמין מתקיימים טקסים, משפחות שכולות באות לקבר של היקרים שלהן. בטלוויזיה מציגים תמונות של חללים ומספרים את סיפוריהם. כל האומה עצובה יחד.
ואז, בערב, כשיום הזיכרון נגמר, המעבר הוא מדהים. תוך דקות, מעצב עובר לשמחה. מתחילות חגיגות ברחובות — מופעים, מוזיקה חיה, זיקוקים ומסיבות. בהר הרצל בירושלים מתקיים טקס הדלקת המשואות — שנים עשר אנשים שתרמו למדינה מדליקים משואות כסמל. ברחובות של תל אביב אנשים רוקדים עד הבוקר.
ביום עצמו, המסורת הגדולה היא המנגל — או "על-האש" כמו שקוראים לזה בישראל. משפחות ארוזות מזון, פחמים ושולחנות ונוסעות לפארק. בפארקים אי אפשר למצוא מקום! כולם מבשלים בשר, שותים בירה ומשחקים מטקות. יש גם מטס חיל האוויר — מטוסים עוברים מעל ערי ישראל בנתיב מיוחד, ואנשים יוצאים לגגות ולמרפסות לראות. זה יום של גאווה לאומית, שמחה ומשפחה.', 'День независимости — национальный праздник Израиля, и он занимает особое место в сердце каждого израильтянина. Он отмечается 5 ияра по еврейскому календарю, обычно в апреле или мае. Но перед началом торжеств есть совсем другой день — День памяти павших в войнах Израиля.
День памяти — один из самых грустных дней в Израиле. Утром звучит сирена — все люди замирают, машины останавливаются, всё молчит целую минуту. На кладбищах проходят церемонии, скорбящие семьи приходят на могилы своих близких. По телевизору показывают фотографии павших и рассказывают их истории. Вся нация скорбит вместе.
А потом, вечером, когда День памяти заканчивается, переход поразительный. За считанные минуты скорбь сменяется радостью. Начинаются уличные празднования — шоу, живая музыка, фейерверки и вечеринки. На горе Герцля в Иерусалиме проходит церемония зажжения факелов — двенадцать человек, внёсших вклад в государство, зажигают факелы как символ. На улицах Тель-Авива люди танцуют до утра.
В сам день главная традиция — барбекю, или «аль-хаэш», как говорят в Израиле. Семьи пакуют еду, угли и столы и едут в парк. В парках невозможно найти место! Все жарят мясо, пьют пиво и играют в мяч. Есть также воздушный парад — самолёты пролетают над городами Израиля по особому маршруту, и люди выходят на крыши и балконы смотреть. Это день национальной гордости, радости и семьи.', '[{"he": "עצמאות", "ru": "независимость", "translit": "ацмаУт"}, {"he": "זיכרון", "ru": "память", "translit": "зикарОн"}, {"he": "צפירה", "ru": "сирена", "translit": "цфирА"}, {"he": "חללים", "ru": "павшие", "translit": "халалИм"}, {"he": "זיקוקים", "ru": "фейерверки", "translit": "зикукИм"}, {"he": "משואות", "ru": "факелы", "translit": "масуОт"}, {"he": "מנגל", "ru": "барбекю", "translit": "мангАль"}, {"he": "גאווה", "ru": "гордость", "translit": "гаавА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (246, 3, 'הסיפור של הפלאפל', 'История фалафеля', 'אם שואלים ישראלי מה האוכל הלאומי של ישראל, רבים יגידו: פלאפל! כדורים קטנים ומטוגנים עשויים מחומוס או פול טחון, מתובלים בפטרוזיליה, כוסברה, כמון ושום. מגישים אותם בפיתה עם סלט ירקות טרי, טחינה, חמוצים ורוטב חריף.
המקור של הפלאפל שנוי במחלוקת. מצרים טוענת שהפלאפל שלה, והוא עשוי מפול. לבנון אומרת שזה מתכון לבנוני עתיק. הפלסטינים אומרים שזה חלק מהמטבח הפלסטיני. וישראל? ישראל אימצה את הפלאפל והפכה אותו לסמל לאומי. בשנות החמישים, הפלאפל היה האוכל של העובדים — מנה זולה, מזינה ומהירה. היום הוא עדיין אחד המאכלים הפופולריים ביותר בארץ.
כמעט בכל פינת רחוב בישראל יש דוכן פלאפל. מחיר מנה הוא בין חמש עשרה לעשרים וחמש שקלים. כל דוכן גאה במתכון הייחודי שלו — יש שמוסיפים בצל מטוגן, יש שמגישים עם חציל צלוי, ויש שעושים פלאפל ירוק מעשבי תיבול. בתל אביב ובירושלים יש תחרויות פלאפל לא רשמיות, וכל שכונה בטוחה שהפלאפל שלה הוא הכי טוב.
בשנים האחרונות הפלאפל כבש את העולם. בניו יורק, בלונדון ובברלין יש מסעדות פלאפל ישראליות מצליחות. יש גם גרסאות חדשות — פלאפל מבטטה, פלאפל עם קינואה, ואפילו פלאפל אפוי במקום מטוגן לאלה ששומרים על הבריאות. אבל הפלאפל הכי טוב? כולם יסכימו — הוא בפיתה חמה, ברחוב בישראל, עם טחינה שנוזלת על הידיים.', 'Если спросить израильтянина, какое национальное блюдо Израиля, многие скажут: фалафель! Маленькие обжаренные шарики из молотого нута или бобов, приправленные петрушкой, кориандром, кумином и чесноком. Подаются в пите со свежим овощным салатом, тхиной, соленьями и острым соусом.
Происхождение фалафеля спорно. Египет утверждает, что фалафель их, и он из бобов. Ливан говорит, что это древний ливанский рецепт. Палестинцы говорят, что это часть палестинской кухни. А Израиль? Израиль принял фалафель и превратил его в национальный символ. В пятидесятые годы фалафель был едой рабочих — дешёвое, сытное и быстрое блюдо. Сегодня он по-прежнему одно из самых популярных блюд в стране.
Почти на каждом углу в Израиле есть ларёк с фалафелем. Цена порции — от пятнадцати до двадцати пяти шекелей. Каждый ларёк гордится своим уникальным рецептом — одни добавляют жареный лук, другие подают с запечённым баклажаном, третьи делают зелёный фалафель с пряными травами. В Тель-Авиве и Иерусалиме проходят неофициальные конкурсы фалафеля, и каждый район уверен, что его фалафель лучший.
В последние годы фалафель завоевал мир. В Нью-Йорке, Лондоне и Берлине есть успешные израильские фалафельные. Появились и новые версии — фалафель из батата, фалафель с киноа и даже запечённый фалафель вместо жареного для тех, кто следит за здоровьем. Но лучший фалафель? Все согласятся — он в тёплой пите, на улице в Израиле, с тхиной, стекающей по рукам.', '[{"he": "פלאפל", "ru": "фалафель", "translit": "фалАфель"}, {"he": "חומוס", "ru": "нут/хумус", "translit": "хУмус"}, {"he": "מטוגן", "ru": "жареный", "translit": "метугАн"}, {"he": "פיתה", "ru": "пита", "translit": "пИта"}, {"he": "טחינה", "ru": "тхина", "translit": "тхинА"}, {"he": "תבלינים", "ru": "специи", "translit": "тавлинИм"}, {"he": "סמל", "ru": "символ", "translit": "сЕмель"}, {"he": "דוכן", "ru": "ларёк", "translit": "духАн"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (247, 3, 'בנק וכסף בישראל', 'Банки и деньги в Израиле', 'כשמגיעים לישראל, אחד הדברים הראשונים שצריך לעשות הוא לפתוח חשבון בנק. הבנקים הגדולים בישראל הם הפועלים, לאומי, דיסקונט, מזרחי-טפחות ובינלאומי. כדי לפתוח חשבון צריך להביא תעודת זהות או דרכון, הוכחת כתובת ולפעמים גם אישור על מקום עבודה.
המטבע בישראל הוא השקל החדש. שקל אחד שווה מאה אגורות, אבל כמעט לא משתמשים באגורות היום. השטרות הם של עשרים, חמישים, מאה ומאתיים שקלים. על השטרות מופיעים פנים של סופרים ומשוררים ישראלים — רחל המשוררת, שאול טשרניחובסקי ולאה גולדברג.
ישראל היא מדינה מאוד דיגיטלית בכל מה שקשור לכסף. כמעט בכל מקום אפשר לשלם בכרטיס אשראי או בטלפון. אפליקציות בנק מאפשרות להעביר כסף, לשלם חשבונות ולבדוק את היתרה בכל רגע. אפליקציית "ביט" מאוד פופולרית — אפשר לשלוח כסף לחברים ברגע, בלי מספר חשבון. הרבה חנויות קטנות ואפילו דוכנים בשוק מקבלים תשלום דיגיטלי.
כמה דברים חשובים לדעת על כסף בישראל: ראשית, בישראל נהוג לתת טיפ של עשרה עד חמישה עשר אחוז במסעדות — זה לא חובה, אבל זה מקובל. שנית, ישראל היא מדינה יקרה — המחירים גבוהים בהשוואה לאירופה, במיוחד דיור ומזון. שלישית, כדאי לבדוק עמלות בנק — הבנקים בישראל גובים עמלות על כל דבר, ואפשר לחסוך הרבה כסף אם משווים בין בנקים ומנהלים משא ומתן.', 'Когда приезжаешь в Израиль, одно из первых дел — открыть банковский счёт. Крупные банки в Израиле — Апоалим, Леуми, Дисконт, Мизрахи-Тфахот и Бейнлеуми. Чтобы открыть счёт, нужно принести удостоверение личности или паспорт, подтверждение адреса и иногда справку с места работы.
Валюта Израиля — новый шекель. Один шекель равен ста агорот, но агоротами почти не пользуются сегодня. Купюры — двадцать, пятьдесят, сто и двести шекелей. На купюрах изображены лица израильских писателей и поэтов — поэтесса Рахель, Шауль Черниховский и Лея Гольдберг.
Израиль — очень цифровая страна во всём, что касается денег. Почти везде можно платить кредитной картой или телефоном. Банковские приложения позволяют переводить деньги, оплачивать счета и проверять баланс в любой момент. Приложение «Бит» очень популярно — можно моментально отправить деньги друзьям, без номера счёта. Многие маленькие магазины и даже ларьки на рынке принимают цифровую оплату.
Несколько важных вещей о деньгах в Израиле: во-первых, в Израиле принято оставлять чаевые 10-15% в ресторанах — это не обязательно, но принято. Во-вторых, Израиль — дорогая страна — цены высокие по сравнению с Европой, особенно на жильё и еду. В-третьих, стоит проверять банковские комиссии — банки в Израиле берут комиссию за всё, и можно сэкономить много денег, если сравнивать банки и вести переговоры.', '[{"he": "חשבון בנק", "ru": "банковский счёт", "translit": "хешбОн банк"}, {"he": "שקל", "ru": "шекель", "translit": "шЕкель"}, {"he": "כרטיס אשראי", "ru": "кредитная карта", "translit": "картИс ашрАй"}, {"he": "יתרה", "ru": "баланс", "translit": "итрА"}, {"he": "עמלות", "ru": "комиссии", "translit": "амлОт"}, {"he": "טיפ", "ru": "чаевые", "translit": "тип"}, {"he": "תעודת זהות", "ru": "удостоверение личности", "translit": "теудАт зеhУт"}, {"he": "משא ומתן", "ru": "переговоры", "translit": "масА уматАн"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (248, 3, 'סיפור קצר: המפתח', 'Рассказ: Ключ', 'יום אחד, בדרך הביתה מהעבודה, מצאתי מפתח ישן ברחוב. הוא היה שוכב על המדרכה, ליד עץ זית גדול. המפתח היה מברזל, חלוד ומכוסה באבק. נראה שהוא ישן מאוד — אולי מאה שנה או יותר. חשבתי לזרוק אותו, אבל משהו עצר אותי. הרגשתי שהמפתח הזה חשוב. שמתי אותו בכיס ולקחתי אותו הביתה.
בלילה, חלמתי חלום מוזר וברור. הייתי עומד ברחוב צר בעיר העתיקה של ירושלים. האבנים היו זהובות מאור השקיעה. הרחוב היה ריק — אין אנשים, אין חנויות פתוחות, רק שקט מוחלט. הלכתי לאט עד שהגעתי לדלת עתיקה מעץ כהה. על הדלת היה סמל מוזר — כוכב עם עין באמצע. ידעתי, בלי לדעת למה, שהמפתח מתאים לדלת הזאת.
הכנסתי את המפתח לנעילה. הוא התאים בדיוק. סובבתי — והדלת נפתחה בשקט. מאחורי הדלת היה גן יפהפה שלא ציפיתי לו. עצי זית ישנים, שושנים אדומות, מזרקה עם מים צלולים. באמצע הגן ישב זקן על ספסל, קורא בספר. הוא הרים את הראש, הסתכל עליי וחייך. "חיכיתי לך," הוא אמר. "יש לי משהו לספר לך."
ואז התעוררתי. הלב שלי דפק מהר. רצתי לחלון — היה עוד חושך בחוץ, ארבע בבוקר. לא יכולתי לחזור לישון. מי היה הזקן? מה הוא רצה לספר? בבוקר יצאתי לעיר העתיקה לחפש את הדלת. הלכתי ברחובות צרים שעות. לא מצאתי אותה. אבל אני עדיין שומר את המפתח. אולי יום אחד אמצא את הדלת הנכונה.', 'Однажды, по дороге домой с работы, я нашёл на улице старый ключ. Он лежал на тротуаре, рядом с большим оливковым деревом. Ключ был из железа, ржавый и покрытый пылью. Выглядел очень старым — может, сто лет или больше. Хотел выбросить его, но что-то остановило меня. Я чувствовал, что этот ключ важен. Положил его в карман и взял домой.
Ночью мне приснился странный и яркий сон. Я стоял на узкой улице в Старом городе Иерусалима. Камни были золотистыми от света заката. Улица была пуста — ни людей, ни открытых лавок, только абсолютная тишина. Я медленно шёл, пока не дошёл до древней двери из тёмного дерева. На двери был странный символ — звезда с глазом посередине. Я знал, сам не понимая почему, что ключ подходит к этой двери.
Я вставил ключ в замок. Он подошёл точно. Повернул — и дверь бесшумно открылась. За дверью был прекрасный сад, которого я не ожидал. Старые оливковые деревья, красные розы, фонтан с чистой водой. В центре сада на скамейке сидел старик и читал книгу. Он поднял голову, посмотрел на меня и улыбнулся. «Я ждал тебя,» — сказал он. «Мне нужно тебе кое-что рассказать.»
И тогда я проснулся. Сердце билось быстро. Я подбежал к окну — на улице ещё было темно, четыре утра. Не мог заснуть снова. Кто был тот старик? Что он хотел рассказать? Утром я отправился в Старый город искать ту дверь. Ходил по узким улицам часами. Не нашёл её. Но я всё ещё храню ключ. Может, однажды я найду нужную дверь.', '[{"he": "מפתח", "ru": "ключ", "translit": "мафтЕах"}, {"he": "חלוד", "ru": "ржавый", "translit": "халУд"}, {"he": "חלום", "ru": "сон", "translit": "халОм"}, {"he": "עתיקה", "ru": "древняя", "translit": "атикА"}, {"he": "מזרקה", "ru": "фонтан", "translit": "мизракА"}, {"he": "נעילה", "ru": "замок", "translit": "неилА"}, {"he": "ספסל", "ru": "скамейка", "translit": "сафсАль"}, {"he": "להתעורר", "ru": "проснуться", "translit": "леhитъорЕр"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (250, 3, 'ירושלים — עיר של שלוש דתות', 'Иерусалим — город трёх религий', 'ירושלים היא אחת הערים הייחודיות ביותר בעולם. היא קדושה לשלוש דתות — יהדות, נצרות ואסלאם — וההיסטוריה שלה מתפרסת על פני אלפי שנים. כשהולכים ברחובות העיר, מרגישים את ההיסטוריה בכל צעד.
ליהודים, ירושלים היא המקום הכי קדוש בעולם. הכותל המערבי — שריד של בית המקדש השני — הוא מקום התפילה המרכזי. יהודים מכל העולם באים להתפלל שם ולשים פתקים עם בקשות בין האבנים. בשבתות וחגים, הכותל מלא באנשים.
לנוצרים, ירושלים היא המקום שבו ישו חי, מת וקם לתחייה. כנסיית הקבר, שנמצאת בעיר העתיקה, היא אחד המקומות הקדושים ביותר בנצרות. צליינים מכל העולם באים ללכת בדרך שישו הלך — ויה דולורוזה — ולבקר במקומות הקדושים.
למוסלמים, ירושלים היא העיר הקדושה השלישית אחרי מכה ומדינה. מסגד אל-אקצא וכיפת הסלע, שעל הר הבית, הם מקומות קדושים מאוד. לפי האסלאם, מכאן הנביא מוחמד עלה לשמיים.
העיר העתיקה מחולקת לארבעה רבעים: יהודי, מוסלמי, נוצרי וארמני. ברחובות הצרים אפשר למצוא חנויות תבלינים, סדנאות אומנים, מאפיות ישנות ומסעדות מסורתיות. הצבעים, הריחות והקולות יוצרים חוויה מיוחדת. ירושלים היא גם בירת ישראל — בה נמצאים הכנסת, בית הנשיא, בית המשפט העליון ומוזיאון ישראל. עיר של היסטוריה, אמונה ותקווה.', 'Иерусалим — один из самых уникальных городов в мире. Он священен для трёх религий — иудаизма, христианства и ислама — и его история насчитывает тысячи лет. Когда идёшь по улицам города, чувствуешь историю на каждом шагу.
Для евреев Иерусалим — самое святое место в мире. Стена Плача — остаток Второго Храма — центральное место молитвы. Евреи со всего мира приходят молиться там и вкладывать записки с просьбами между камнями. По субботам и праздникам Стена заполнена людьми.
Для христиан Иерусалим — место, где Иисус жил, умер и воскрес. Храм Гроба Господня, расположенный в Старом городе, — одно из самых святых мест в христианстве. Паломники со всего мира приходят пройти по пути Иисуса — Виа Долороза — и посетить святые места.
Для мусульман Иерусалим — третий священный город после Мекки и Медины. Мечеть Аль-Акса и Купол Скалы на Храмовой горе — очень важные святыни. Согласно исламу, отсюда пророк Мухаммед вознёсся на небеса.
Старый город разделён на четыре квартала: еврейский, мусульманский, христианский и армянский. На узких улочках можно найти лавки со специями, ремесленные мастерские, старые пекарни и традиционные рестораны. Цвета, запахи и звуки создают особый опыт. Иерусалим — также столица Израиля — здесь находятся Кнессет, резиденция президента, Верховный суд и Музей Израиля. Город истории, веры и надежды.', '[{"he": "קדושה", "ru": "священная", "translit": "кдушА"}, {"he": "דתות", "ru": "религии", "translit": "датОт"}, {"he": "כותל", "ru": "Стена (Плача)", "translit": "кОтель"}, {"he": "רבעים", "ru": "кварталы", "translit": "реваИм"}, {"he": "צליינים", "ru": "паломники", "translit": "цлаянИм"}, {"he": "בירה", "ru": "столица", "translit": "бирА"}, {"he": "כנסת", "ru": "Кнессет", "translit": "кнЕсет"}, {"he": "אמונה", "ru": "вера", "translit": "эмунА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (251, 3, 'טיפים לחיסכון בישראל', 'Советы по экономии в Израиле', 'ישראל נחשבת למדינה יקרה — אחת היקרות במערב. מחירי הדיור, המזון והשירותים גבוהים מאוד. אבל יש דרכים חכמות לחסוך כסף ולחיות טוב גם בתקציב מוגבל. הנה כמה טיפים שלמדתי אחרי שנים בישראל.
קודם כל, קניות מזון. כדאי מאוד לקנות בשוק ולא בסופרמרקט. בשוק הכרמל בתל אביב או בשוק מחנה יהודה בירושלים, הירקות והפירות זולים יותר — לפעמים בחמישים אחוז! חשוב ללכת לשוק אחרי הצהריים, לפני הסגירה, כי אז המוכרים מורידים מחירים. גם רשתות הזולות כמו רמי לוי ויינות ביתן זולות יותר מהרשתות הגדולות.
שנית, תחבורה. תחבורה ציבורית בישראל זולה בהרבה ממכונית פרטית. כרטיס "רב-קו" מאפשר נסיעות מוזלות באוטובוס וברכבת. גם אופניים חשמליים הפכו לפופולריים מאוד — ההשקעה הראשונית גדולה, אבל אחר כך אין הוצאות דלק וחנייה.
שלישית, דיור. מחירי הדירות במרכז — בתל אביב ובהרצלייה — גבוהים מאוד. אבל בפריפריה — בבאר שבע, בחיפה או בנצרת — המחירים נמוכים בהרבה, ולפעמים איכות החיים אפילו יותר טובה. גם שכירות משותפת עם שותפים זו דרך מצוינת לחסוך.
רביעית, בידור. הרבה אירועי תרבות בישראל הם חינם — קונצרטים בפארקים, סיורים מודרכים, מוזיאונים ביום שלישי. וכמובן, הטבע בישראל הוא חינם — הליכה בשמורת טבע, יום בים, טיול בהרים. עם תכנון נכון, אפשר לחיות חיים מלאים בישראל גם בלי להוציא הון.', 'Израиль считается дорогой страной — одной из самых дорогих на Западе. Цены на жильё, еду и услуги очень высокие. Но есть умные способы экономить и жить хорошо даже с ограниченным бюджетом. Вот несколько советов, которые я усвоил за годы в Израиле.
Прежде всего, покупка еды. Очень стоит покупать на рынке, а не в супермаркете. На рынке Кармель в Тель-Авиве или Махане Иегуда в Иерусалиме овощи и фрукты дешевле — иногда на пятьдесят процентов! Важно приходить на рынок после обеда, перед закрытием, потому что тогда продавцы снижают цены. Дешёвые сети вроде Рами Леви и Йейнот Битан тоже дешевле крупных сетей.
Во-вторых, транспорт. Общественный транспорт в Израиле намного дешевле личного автомобиля. Карта «Рав-Кав» позволяет ездить со скидкой на автобусе и поезде. Электровелосипеды тоже стали очень популярны — начальные вложения большие, но потом нет расходов на бензин и парковку.
В-третьих, жильё. Цены на квартиры в центре — в Тель-Авиве и Герцлии — очень высокие. Но на периферии — в Беэр-Шеве, Хайфе или Назарете — цены значительно ниже, а качество жизни иногда даже лучше. Совместная аренда с соседями — тоже отличный способ сэкономить.
В-четвёртых, развлечения. Многие культурные мероприятия в Израиле бесплатны — концерты в парках, экскурсии с гидом, музеи по вторникам. И конечно, природа Израиля бесплатна — прогулка в заповеднике, день на море, поход в горы. С правильным планированием можно жить полной жизнью в Израиле, не тратя целое состояние.', '[{"he": "חיסכון", "ru": "экономия", "translit": "хисахОн"}, {"he": "תקציב", "ru": "бюджет", "translit": "такцИв"}, {"he": "הנחה", "ru": "скидка", "translit": "ханахА"}, {"he": "פריפריה", "ru": "периферия", "translit": "перифЕрия"}, {"he": "שכירות", "ru": "аренда", "translit": "схирУт"}, {"he": "תחבורה ציבורית", "ru": "общественный транспорт", "translit": "тахбурА цибурИт"}, {"he": "שמורת טבע", "ru": "заповедник", "translit": "шмурАт тЕва"}, {"he": "הוצאות", "ru": "расходы", "translit": "оцаОт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (252, 3, 'הים התיכון בחורף', 'Средиземное море зимой', 'רבים חושבים שהים בישראל הוא רק לקיץ, אבל אני חושב שהחורף על החוף הוא העונה הכי יפה. אני גר בחיפה, עשר דקות מהים, ואני הולך לחוף כמעט כל שבוע גם בחורף. תנו לי לספר לכם למה.
בקיץ, החוף מלא באנשים — אלפי אנשים, מוזיקה רועשת, מציק חם ולח. אי אפשר למצוא מקום לשבת. בחורף, הכל משתנה. החוף כמעט ריק. רק אני, הים והרוח. אפשר ללכת שעה שלמה על החול בלי לפגוש אף אחד. החול רטוב ומוצק — נעים ללכת עליו.
הגלים בחורף גבוהים ועוצמתיים. צבעם אפור-ירוק, ולפעמים כחול כהה כשהשמש יוצאת מהעננים. גולשי גלים אוהבים את החורף — הגלים הטובים ביותר הם בדצמבר ובינואר. אני לא גולש, אבל אני אוהב לעמוד ולהסתכל עליהם.
השקיעות בחורף הן מדהימות. השמש שוקעת מוקדם, בערך בחמש, והשמיים נצבעים בכתום, ורוד וסגול. עננים דרמטיים יוצרים תמונות שמשתנות כל רגע. לפעמים בא גשם פתאומי, ואז מריחים את הריח המיוחד של גשם על חול חם.
אחרי ההליכה בחוף, אני נכנס לבית קפה קטן ליד הים. יושב ליד החלון, שותה שוקו חם ומסתכל על הגלים. לפעמים קורא ספר, לפעמים פשוט חולם. זה הדבר האהוב עליי בחורף — הרגע הזה של שקט, חום ונוף.', 'Многие думают, что море в Израиле — только для лета, но я считаю, что зима на побережье — самый красивый сезон. Я живу в Хайфе, в десяти минутах от моря, и хожу на пляж почти каждую неделю и зимой тоже. Позвольте рассказать почему.
Летом пляж забит людьми — тысячи людей, громкая музыка, жарко и влажно. Невозможно найти место, чтобы сесть. Зимой всё меняется. Пляж почти пуст. Только я, море и ветер. Можно целый час идти по песку, не встретив никого. Песок мокрый и плотный — приятно идти по нему.
Волны зимой высокие и мощные. Их цвет серо-зелёный, а иногда тёмно-синий, когда солнце выходит из-за облаков. Сёрферы любят зиму — лучшие волны в декабре и январе. Я не катаюсь, но люблю стоять и смотреть на них.
Закаты зимой потрясающие. Солнце садится рано, около пяти, и небо окрашивается в оранжевый, розовый и фиолетовый. Драматичные облака создают картины, которые меняются каждый миг. Иногда начинается внезапный дождь, и тогда чувствуешь особый запах дождя на тёплом песке.
После прогулки по пляжу захожу в маленькое кафе у моря. Сажусь у окна, пью горячее какао и смотрю на волны. Иногда читаю книгу, иногда просто мечтаю. Это моё любимое занятие зимой — этот момент тишины, тепла и пейзажа.', '[{"he": "גלים", "ru": "волны", "translit": "галИм"}, {"he": "רוח", "ru": "ветер", "translit": "рУах"}, {"he": "שקיעות", "ru": "закаты", "translit": "шкиОт"}, {"he": "גולשים", "ru": "сёрферы", "translit": "гольшИм"}, {"he": "עננים", "ru": "облака", "translit": "ананИм"}, {"he": "חול", "ru": "песок", "translit": "холь"}, {"he": "שקט", "ru": "тишина", "translit": "шЕкет"}, {"he": "חוף", "ru": "пляж/побережье", "translit": "хоф"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (253, 3, 'מערכת החינוך בישראל', 'Система образования в Израиле', 'מערכת החינוך בישראל מחולקת לכמה שלבים ויש לה מאפיינים ייחודיים. חוק החינוך מחייב לימודים מגיל שלוש ועד גיל שמונה עשרה. החינוך בישראל הוא חינם בבתי ספר ציבוריים, אם כי ההורים משלמים על חוגים, טיולים ואביזרים.
השלב הראשון הוא גן חובה — מגיל שלוש עד שש. בגן ילדים ישראלי לומדים דרך משחק, יוצרים אומנות ומתחילים ללמוד אותיות ומספרים. אחרי הגן מתחיל בית ספר יסודי — כיתות א'' עד ו'', מגיל שש עד שתים עשרה. הילדים לומדים עברית, מתמטיקה, אנגלית, מדעים, תנ"ך והיסטוריה.
חטיבת ביניים כוללת כיתות ז'' עד ט''. בגיל הזה מתחילים ללמוד יותר מקצועות ובצורה מעמיקה יותר. ותיכון — כיתות י'' עד י"ב — הוא השלב שבו התלמידים בוחרים מגמות: מדעים, אומנויות, מחשבים או לימודים עיוניים. בסוף התיכון, התלמידים נבחנים בבחינות בגרות — מבחנים ארציים שקובעים אם מקבלים תעודת בגרות. הבחינות האלה חשובות מאוד לקבלה לאוניברסיטה.
אחרי התיכון, רוב הצעירים הישראלים מתגייסים לצבא — בנים לשלוש שנים ובנות לשנתיים. זה מקום ללימוד מקצוע, לחברויות חדשות ולחוויות מעצבות. אחרי הצבא, רבים יוצאים לטיול גדול — להודו, לדרום אמריקה או למזרח אסיה. ורק אחרי הטיול, בגיל עשרים ושתיים עד עשרים וארבע, מתחילים ללמוד באוניברסיטה. זה שונה מאוד מאירופה, שם מתחילים ללמוד בגיל שמונה עשרה.', 'Система образования в Израиле разделена на несколько этапов и имеет уникальные особенности. Закон об образовании обязывает учиться с трёх до восемнадцати лет. Образование в государственных школах бесплатное, хотя родители платят за кружки, экскурсии и принадлежности.
Первый этап — обязательный детский сад, от трёх до шести лет. В израильском детском саду учатся через игру, занимаются творчеством и начинают изучать буквы и числа. После садика начинается начальная школа — классы 1-6, от шести до двенадцати лет. Дети изучают иврит, математику, английский, естественные науки, ТАНАХ и историю.
Средняя школа включает классы 7-9. В этом возрасте начинают изучать больше предметов и более углублённо. А старшая школа — классы 10-12 — этап, на котором ученики выбирают направления: науки, искусства, компьютеры или гуманитарные предметы. В конце школы ученики сдают экзамены на аттестат зрелости (багрут) — государственные экзамены, определяющие, получит ли ученик аттестат. Эти экзамены очень важны для поступления в университет.
После школы большинство молодых израильтян идут в армию — юноши на три года, девушки на два. Это место для получения профессии, новых дружб и формирующего опыта. После армии многие отправляются в большое путешествие — в Индию, Южную Америку или Юго-Восточную Азию. И только после путешествия, в двадцать два — двадцать четыре года, начинают учиться в университете. Это очень отличается от Европы, где начинают учиться в восемнадцать.', '[{"he": "חינוך", "ru": "образование", "translit": "хинУх"}, {"he": "יסודי", "ru": "начальный", "translit": "есодИ"}, {"he": "תיכון", "ru": "старшая школа", "translit": "тихОн"}, {"he": "בגרות", "ru": "аттестат зрелости", "translit": "багрУт"}, {"he": "מתגייסים", "ru": "призываются", "translit": "митгайсИм"}, {"he": "מגמות", "ru": "направления", "translit": "мегамОт"}, {"he": "חו\"ל", "ru": "заграница", "translit": "хуль"}, {"he": "חטיבת ביניים", "ru": "средняя школа", "translit": "хативАт бейнАйим"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (254, 3, 'דירה להשכרה — מודעה', 'Квартира в аренду — объявление', 'להשכרה: דירת 3 חדרים ברחוב דיזנגוף 120, תל אביב
דירה יפה ומרווחת בקומה רביעית עם מעלית, ברחוב אחד הרחובות הכי חיים בתל אביב. הדירה שופצה לפני שנה ונראית כמו חדשה. שטח של שבעים מטר רבוע — סלון גדול, שני חדרי שינה, מטבח מרווח, מקלחון ושירותים נפרדים.
הדירה מרוהטת במלואה ומוכנה לכניסה מיידית. במטבח: תנור, מיקרוגל, מקרר גדול ומדיח כלים. בסלון: ספה, שולחן אוכל לארבעה, טלוויזיה חכמה ומזגן. בחדרי השינה: מיטות, ארונות ומזגנים. יש גם מכונת כביסה במרפסת השירות.
מרפסת גדולה עם נוף לרחוב — מושלמת לבוקר עם קפה. הדירה שקטה למרות המיקום המרכזי, כי החלונות כפולים. קרוב לתחנת אוטובוס, לחנויות, לבתי קפה ולחוף הים — חמש דקות הליכה! חנייה ברחוב, ויש אפשרות לחנייה פרטית בתוספת תשלום.
שכירות: 5,500 ש"ח לחודש. לא כולל חשבונות — חשמל, מים, גז וועד בית (250 ש"ח בחודש). נדרש חוזה לשנה לפחות. ערבות: שיק ביטחון או ערבות בנקאית. לא מתאים לבעלי חיים. לא מתאים לסטודנטים (מקסימום שני דיירים).
ליצירת קשר: רונית, 054-1234567, בימים א''-ה'' בין 9:00 ל-19:00. ניתן לתאם סיור בדירה.', 'Сдаётся: 3-комнатная квартира, ул. Дизенгоф 120, Тель-Авив
Красивая и просторная квартира на четвёртом этаже с лифтом, на одной из самых оживлённых улиц Тель-Авива. Квартира отремонтирована год назад и выглядит как новая. Площадь семьдесят квадратных метров — большая гостиная, две спальни, просторная кухня, душевая и отдельный туалет.
Квартира полностью меблирована и готова к немедленному заселению. На кухне: духовка, микроволновка, большой холодильник и посудомоечная машина. В гостиной: диван, обеденный стол на четверых, смарт-ТВ и кондиционер. В спальнях: кровати, шкафы и кондиционеры. Есть также стиральная машина на хозяйственном балконе.
Большой балкон с видом на улицу — идеален для утра с кофе. Квартира тихая несмотря на центральное расположение, потому что окна двойные. Рядом автобусная остановка, магазины, кафе и пляж — пять минут пешком! Парковка на улице, есть возможность частной парковки за дополнительную плату.
Аренда: 5 500 шекелей в месяц. Не включая коммунальные платежи — электричество, вода, газ и ваад байт (250 шекелей в месяц). Требуется договор минимум на год. Залог: гарантийный чек или банковская гарантия. Не подходит для владельцев животных. Не подходит для студентов (максимум два жильца).
Для связи: Ронит, 054-1234567, вс-чт с 9:00 до 19:00. Можно договориться о просмотре квартиры.', '[{"he": "להשכרה", "ru": "в аренду", "translit": "леhаскарА"}, {"he": "מרוהטת", "ru": "меблированная", "translit": "мерухЕтет"}, {"he": "מאובזר", "ru": "оборудованный", "translit": "меувзАр"}, {"he": "שכירות", "ru": "аренда", "translit": "схирУт"}, {"he": "ארנונה", "ru": "муниципальный налог", "translit": "арнонА"}, {"he": "מעלית", "ru": "лифт", "translit": "маалИт"}, {"he": "ועד בית", "ru": "домовой комитет", "translit": "ваАд бАйит"}, {"he": "חוזה", "ru": "договор", "translit": "хозЕ"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (255, 3, 'סיפור: הנהג הנדיב', 'Рассказ: Щедрый водитель', 'היה יום שישי אחר הצהריים, וגשם כבד ירד על תל אביב. תמר עמדה בתחנת האוטובוס ליד הבימה, רטובה ומרגישה אומללה. היא שכחה את המטרייה בבית, התיק שלה היה רטוב, והטלפון כבר כיבה את עצמו מהמים. האוטובוס הבא — רק בעוד ארבעים דקות. בערב שבת אין הרבה אוטובוסים.
פתאום עצרה לידה מונית צהובה. הנהג, גבר בן חמישים עם שפם גדול, פתח את החלון ושאל: "לאן, גברתי?" תמר הסתכלה על המונית ואמרה בביישנות: "אני צריכה להגיע לרחוב הרצל, אבל אין לי מספיק כסף למונית. אני מחכה לאוטובוס." הנהג חייך חיוך גדול: "עלי, אני בדיוק נוסע לכיוון הזה. כנסי."
תמר היססה רגע, אבל הגשם החזק שכנע אותה. היא נכנסה למונית. בפנים היה חם ונעים. שירי עומר אדם נשמעו ברדיו. "אני מוטי," אמר הנהג. "את סטודנטית?" "כן, לומדת משפטים באוניברסיטה." "יופי! הבת שלי גם לומדת משפטים. שנה שלישית." הם דיברו על הלימודים, על החיים בעיר, על המזג אוויר המשוגע.
כשהגיעו לרחוב הרצל, תמר ביקשה: "תגיד לי כמה, אני אשלם מחר." מוטי סירב בתקיפות: "תשכחי מזה. לפני עשרים שנה, כשהגעתי לישראל מעירק בלי כלום, מישהו עזר לי ככה. הוא אמר לי: ''יום אחד תעזור למישהו אחר.'' עכשיו זה התור שלי.'' תמר הרגישה גוש בגרון. "תודה רבה, מוטי. אתה אדם מיוחד." "לילה טוב," הוא אמר, "ושבת שלום."', 'Был пятничный день, и на Тель-Авив обрушился сильный дождь. Тамар стояла на автобусной остановке возле Габимы, мокрая и несчастная. Она забыла зонтик дома, сумка была мокрой, а телефон уже выключился от воды. Следующий автобус — только через сорок минут. В канун субботы автобусов мало.
Вдруг рядом с ней остановилось жёлтое такси. Водитель, мужчина лет пятидесяти с большими усами, открыл окно и спросил: «Куда, госпожа?» Тамар посмотрела на такси и застенчиво сказала: «Мне нужно на улицу Герцля, но у меня недостаточно денег на такси. Я жду автобус.» Водитель широко улыбнулся: «За мой счёт, я как раз еду в ту сторону. Садись.»
Тамар на мгновение засомневалась, но сильный дождь убедил её. Она села в такси. Внутри было тепло и уютно. По радио играли песни Омера Адама. «Я Моти,» — сказал водитель. «Ты студентка?» «Да, изучаю юриспруденцию в университете.» «Здорово! Моя дочь тоже изучает право. Третий курс.» Они разговаривали об учёбе, о жизни в городе, о сумасшедшей погоде.
Когда доехали до улицы Герцля, Тамар попросила: «Скажи сколько, я заплачу завтра.» Моти решительно отказался: «Забудь об этом. Двадцать лет назад, когда я приехал в Израиль из Ирака без ничего, кто-то помог мне так же. Он сказал: "Однажды поможешь кому-то другому." Теперь моя очередь.» У Тамар стоял ком в горле. «Большое спасибо, Моти. Ты особенный человек.» «Спокойной ночи,» — сказал он, «и шабат шалом.»', '[{"he": "גשם", "ru": "дождь", "translit": "гЕшем"}, {"he": "מטרייה", "ru": "зонтик", "translit": "митрийА"}, {"he": "מונית", "ru": "такси", "translit": "монИт"}, {"he": "חייך", "ru": "улыбнулся", "translit": "хийЕх"}, {"he": "היסס", "ru": "засомневался", "translit": "хисЕс"}, {"he": "נדיב", "ru": "щедрый", "translit": "надИв"}, {"he": "להחזיר", "ru": "вернуть", "translit": "лехахзИр"}, {"he": "שבת שלום", "ru": "мирной субботы", "translit": "шабАт шалОм"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (256, 3, 'מדריך: איך לפתוח עסק בישראל', 'Гид: Как открыть бизнес в Израиле', 'רוצים לפתוח עסק בישראל? זה אפשרי, אבל צריך להכיר את המערכת. הנה מדריך מעשי עם הצעדים הבסיסיים שכל יזם חייב לדעת.
צעד ראשון: להחליט על סוג העסק. בישראל יש שלושה סוגים עיקריים. עוסק פטור — לעסקים קטנים עם הכנסה עד מאה ועשרים אלף שקלים בשנה, פטור ממע"מ. עוסק מורשה — לעסקים גדולים יותר, חייב לגבות מע"מ ולדווח לרשויות. חברה בע"מ — ישות משפטית נפרדת, מתאימה לעסקים גדולים ולמי שרוצה להגן על רכוש אישי.
צעד שני: רישום ברשויות. צריך להירשם במס הכנסה, ביטוח לאומי, ולפתוח תיק מע"מ. התהליך יכול לקחת כמה שבועות. כדאי להיעזר ברואה חשבון מהתחלה — הוא יחסוך לכם הרבה כאב ראש וטעויות.
צעד שלישי: תוכנית עסקית. גם אם העסק קטן, כדאי לכתוב תוכנית. מה המוצר או השירות? מי קהל היעד? כמה כסף צריך להשקיע בהתחלה? מתי צפויים להגיע לרווח? תוכנית טובה עוזרת גם לקבל מימון.
צעד רביעי: מימון. יש כמה אפשרויות — הלוואה מהבנק (עם ערבויות), משקיע פרטי, קרן ממשלתית של רשות החדשנות, או מימון המונים. בישראל יש גם תוכניות מיוחדות לעולים חדשים שרוצים לפתוח עסק.
ולבסוף, טיפ חשוב: בישראל יש הרבה מרכזי יזמות, חממות עסקיות ומאיצים שעוזרים ליזמים — הדרכה, נטוורקינג ומשרדים במחיר מוזל. כדאי לבדוק מה יש באזור שלכם.', 'Хотите открыть бизнес в Израиле? Это возможно, но нужно знать систему. Вот практический гид с базовыми шагами, которые должен знать каждый предприниматель.
Шаг первый: определить тип бизнеса. В Израиле есть три основных типа. Освобождённый предприниматель (осек патур) — для маленьких бизнесов с доходом до ста двадцати тысяч шекелей в год, освобождён от НДС. Авторизованный предприниматель (осек мурше) — для более крупных бизнесов, обязан взимать НДС и отчитываться. ООО (хевра бе-арам) — отдельное юридическое лицо, подходит для крупного бизнеса и тех, кто хочет защитить личное имущество.
Шаг второй: регистрация в органах. Нужно зарегистрироваться в налоговой, национальном страховании и открыть дело НДС. Процесс может занять несколько недель. Стоит обратиться к бухгалтеру с самого начала — он сэкономит много головной боли и ошибок.
Шаг третий: бизнес-план. Даже если бизнес маленький, стоит написать план. Какой продукт или услуга? Кто целевая аудитория? Сколько нужно вложить вначале? Когда ожидается прибыль? Хороший план помогает и получить финансирование.
Шаг четвёртый: финансирование. Есть несколько вариантов — кредит в банке (с гарантиями), частный инвестор, государственный фонд Управления инноваций или краудфандинг. В Израиле также есть специальные программы для новых репатриантов, желающих открыть бизнес.
И напоследок, важный совет: в Израиле много центров предпринимательства, бизнес-инкубаторов и акселераторов, помогающих предпринимателям — обучение, нетворкинг и офисы по сниженной цене. Стоит проверить, что есть в вашем районе.', '[{"he": "עסק", "ru": "бизнес", "translit": "Эсек"}, {"he": "יזם", "ru": "предприниматель", "translit": "язАм"}, {"he": "מימון", "ru": "финансирование", "translit": "мимОн"}, {"he": "רואה חשבון", "ru": "бухгалтер", "translit": "роЭ хешбОн"}, {"he": "מע\"מ", "ru": "НДС", "translit": "маам"}, {"he": "רווח", "ru": "прибыль", "translit": "рЕвах"}, {"he": "תוכנית עסקית", "ru": "бизнес-план", "translit": "тохнИт искИт"}, {"he": "חממות", "ru": "инкубаторы", "translit": "хамамОт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (257, 3, 'בלוג: הטיול שלי בנגב', 'Блог: Моё путешествие по Негеву', 'השבוע חזרתי מטיול של שלושה ימים בנגב, ואני עדיין מלא התרגשות. זה היה אחד הטיולים הכי יפים שעשיתי בישראל. רוצה לספר לכם על כל יום.
ביום הראשון נסעתי ממצפה רמון למכתש רמון. מכתש רמון הוא מכתש ענק — ארבעים קילומטר אורך ושמונה קילומטר רוחב — באמצע המדבר. עמדתי על שפת המכתש והנוף פשוט עצר לי את הנשימה. שכבות של סלעים בצבעים שונים — חום, אדום, צהוב, שחור. ירדתי לתוך המכתש ברגל והלכתי בשביל של שלוש שעות. ראיתי יעלים, ציפורים דורסות ואפילו עקבות של שועל.
בלילה ישנתי באוהל ביישוב בדואי קטן ליד המכתש. המשפחה הבדואית קיבלה אותי בחום מדהים. הם הכינו תה נענע על אש, אכלנו אורז עם בשר כבש ולחם טאבון טרי. אחרי האוכל ישבנו בחוץ והסתכלנו על הכוכבים. במדבר אין זיהום אור, ולכן רואים מיליוני כוכבים. הזקן של המשפחה סיפר סיפורים על המדבר — על מעיינות סודיים, על גמלים שהולכים לבד ועל סופות חול מפחידות.
ביום השני נסעתי לעין עבדת — מפל מים באמצע המדבר! מים צוננים שזורמים מהסלעים לתוך בריכה טבעית מוקפת צוקים. רחצתי בבריכה הקרה ומרגשת. ביום השלישי ביקרתי בבאר שבע — עיר מודרנית עם שוק בדואי מפורסם ביום חמישי. קניתי תבלינים, עוגיות תמר וצעיף בדואי מסורתי. חזרתי הביתה עייף, שרוף מהשמש, אבל מלא זיכרונות.', 'На этой неделе я вернулся из трёхдневного похода по Негеву и всё ещё полон впечатлений. Это был один из самых красивых походов, которые я совершал в Израиле. Хочу рассказать вам о каждом дне.
В первый день я поехал из Мицпе Рамон к Махтеш Рамон. Махтеш Рамон — огромный кратер — сорок километров в длину и восемь в ширину — посреди пустыни. Я стоял на краю кратера, и пейзаж буквально захватил дух. Слои скал разных цветов — коричневый, красный, жёлтый, чёрный. Я спустился в кратер пешком и шёл по тропе три часа. Видел козерогов, хищных птиц и даже следы лисы.
Ночью я спал в палатке в маленьком бедуинском поселении возле кратера. Бедуинская семья приняла меня с потрясающей теплотой. Они приготовили мятный чай на огне, мы ели рис с бараниной и свежий хлеб табун. После еды мы сидели на улице и смотрели на звёзды. В пустыне нет светового загрязнения, поэтому видно миллионы звёзд. Старейшина семьи рассказывал истории о пустыне — о тайных источниках, о верблюдах, которые ходят сами, и о страшных песчаных бурях.
Во второй день я поехал к Эйн-Авдат — водопад посреди пустыни! Холодная вода, текущая из скал в природный бассейн, окружённый утёсами. Я искупался в холодном и волнующем бассейне. На третий день посетил Беэр-Шеву — современный город со знаменитым бедуинским рынком по четвергам. Купил специи, финиковое печенье и традиционный бедуинский шарф. Вернулся домой уставший, обгоревший на солнце, но полный воспоминаний.', '[{"he": "מדבר", "ru": "пустыня", "translit": "мидбАр"}, {"he": "מכתש", "ru": "кратер", "translit": "махтЕш"}, {"he": "בדואים", "ru": "бедуины", "translit": "бедуИм"}, {"he": "מפל מים", "ru": "водопад", "translit": "мапАль мАйим"}, {"he": "יעלים", "ru": "козероги", "translit": "яелИм"}, {"he": "כוכבים", "ru": "звёзды", "translit": "кохавИм"}, {"he": "נענע", "ru": "мята", "translit": "наанА"}, {"he": "שביל", "ru": "тропа", "translit": "швиль"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (258, 3, 'שירות לקוחות — שיחה', 'Служба поддержки — разговор', '"שלום, שירות לקוחות של חברת סלולר ''פלאפון''. שמי גלית, במה אוכל לעזור?"
"שלום גלית, שמי אלכס. יש לי בעיה — הטלפון שלי לא מקבל אינטרנט כבר יומיים. ניסיתי לכבות ולהדליק, ניסיתי להוציא את הסים ולהכניס מחדש, שום דבר לא עוזר."
"אני מבינה, מצטערת על אי הנוחות. מה הדגם של הטלפון?"
"אייפון 14."
"תודה. אני בודקת עכשיו... אלכס, אני רואה במערכת שיש תקלה אזורית באזור שלך — בתל אביב צפון. הצוות הטכני שלנו מודע לבעיה ומטפל בה עכשיו. זה צפוי להיפתר עד מחר בצהריים."
"מחר בצהריים? אבל אני צריך את האינטרנט לעבודה! יש לי פגישות בזום, מיילים חשובים..."
"אני מבינה לחלוטין, זה ממש מתסכל. יש לי שתי הצעות בשבילך. ראשית, אני יכולה לפתוח לך חבילת נתונים זמנית ללא תשלום דרך רשת אחרת. שנית, אם הבעיה לא תיפתר עד מחר, נזכה אותך בפיצוי על הימים בלי שירות."
"אוקיי, תפתחי לי את החבילה הזמנית בבקשה."
"בוודאי. הפעלתי עכשיו חבילה של 10 גיגה. זה אמור לעבוד תוך כמה דקות. האם יש עוד משהו שאני יכולה לעזור?"
"לא, תודה רבה גלית. את ממש עזרת."
"בשמחה, אלכס. סליחה שוב על אי הנוחות. שיהיה לך יום טוב!"
"גם לך, תודה. שלום."', '«Здравствуйте, служба поддержки мобильной компании «Пелефон». Меня зовут Галит, чем могу помочь?»
«Здравствуйте, Галит, меня зовут Алекс. У меня проблема — мой телефон не получает интернет уже два дня. Пробовал выключить и включить, пробовал вытащить SIM-карту и вставить обратно — ничего не помогает.»
«Понимаю, извините за неудобства. Какая модель телефона?»
«Айфон 14.»
«Спасибо. Сейчас проверяю... Алекс, я вижу в системе, что в вашем районе — в северном Тель-Авиве — неполадка в сети. Наша техническая команда знает о проблеме и работает над ней. Ожидается устранение до завтрашнего полудня.»
«Завтра в полдень? Но мне нужен интернет для работы! У меня встречи в Зуме, важные письма...»
«Полностью понимаю, это действительно раздражает. У меня два предложения для вас. Во-первых, я могу открыть вам временный пакет данных бесплатно через другую сеть. Во-вторых, если проблема не решится до завтра, мы компенсируем вам дни без услуги.»
«Хорошо, откройте мне временный пакет, пожалуйста.»
«Конечно. Я только что активировала пакет на 10 гигабайт. Должно заработать через несколько минут. Могу ли я ещё чем-то помочь?»
«Нет, большое спасибо, Галит. Ты очень помогла.»
«Рада помочь, Алекс. Ещё раз извините за неудобства. Хорошего вам дня!»
«И тебе, спасибо. До свидания.»', '[{"he": "שירות לקוחות", "ru": "служба поддержки", "translit": "шерУт лекохОт"}, {"he": "סלולר", "ru": "мобильный", "translit": "селулАр"}, {"he": "תקלה", "ru": "неполадка", "translit": "такалА"}, {"he": "צפוי", "ru": "ожидается", "translit": "цафУй"}, {"he": "פיצוי", "ru": "компенсация", "translit": "пицУй"}, {"he": "חבילת נתונים", "ru": "пакет данных", "translit": "хавилАт нетунИм"}, {"he": "אי נוחות", "ru": "неудобства", "translit": "и нохЮт"}, {"he": "לזכות", "ru": "компенсировать", "translit": "лезакОт"}]', NULL, 'dialogue');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (265, 4, 'מערכת הבריאות הישראלית', 'Система здравоохранения Израиля', 'מערכת הבריאות בישראל נחשבת לאחת הטובות בעולם, ולא בכדי. תוחלת החיים בישראל היא כשמונים ושלוש שנים — מהגבוהות בעולם — ותמותת התינוקות נמוכה מאוד. חוק ביטוח בריאות ממלכתי, שנחקק בשנת 1995, מבטיח ביטוח רפואי לכל תושב ישראל, ללא קשר למצבו הכלכלי או הבריאותי.
המערכת מבוססת על ארבע קופות חולים: כללית (הגדולה ביותר, עם כארבעה וחצי מיליון מבוטחים), מכבי, מאוחדת ולאומית. כל תושב חייב להיות חבר באחת מהן, ויכול לעבור בין קופות פעם בשנה. המימון מגיע ממס בריאות שמנוכה מהמשכורת ומתקציב המדינה.
סל הבריאות — רשימת השירותים שהקופות חייבות לספק — כולל ביקורים אצל רופא משפחה ומומחים, בדיקות מעבדה, הדמיה, אשפוז בבתי חולים, ניתוחים, תרופות מסובסדות, טיפולים נפשיים ושיקום. הסל מתעדכן כל שנה, ומוסיפים אליו תרופות וטיפולים חדשים לפי המלצת ועדה מקצועית.
עם זאת, המערכת מתמודדת עם אתגרים רציניים. זמני ההמתנה ארוכים — לפעמים צריך לחכות שבועות לתור אצל מומחה, ובמקרים מסוימים חודשים. מחסור ברופאים ובאחיות, במיוחד בפריפריה, מוביל לעומס כבד על הצוותים הרפואיים. חדרי מיון בבתי חולים צפופים, ולפעמים מטופלים שוכבים במסדרונות.
הפער בין מרכז לפריפריה בולט גם ברפואה. בתל אביב וברמת גן נמצאים בתי חולים מהמתקדמים בעולם — איכילוב, שיבא ובילינסון — אבל בנגב ובגליל האפשרויות מוגבלות יותר. ישראלים רבים רוכשים ביטוח משלים פרטי שמכסה מומחים פרטיים, חדרים פרטיים בבית חולים ותרופות שלא נכללות בסל הבסיסי.
למרות האתגרים, המערכת הישראלית מצליחה לספק רפואה ברמה גבוהה לכל האוכלוסייה. ישראל מובילה בעולם בתחומים כמו רפואת חירום, טיפול בפוריות, השתלות איברים וחיסונים. בזמן מגפת הקורונה, ישראל הייתה מהמדינות הראשונות לחסן את האוכלוסייה ושימשה כמקרה מבחן עולמי.', 'Система здравоохранения Израиля считается одной из лучших в мире, и неспроста. Продолжительность жизни в Израиле — около восьмидесяти трёх лет, одна из самых высоких в мире, а младенческая смертность очень низкая. Закон о государственном медицинском страховании, принятый в 1995 году, гарантирует медицинскую страховку каждому жителю Израиля, независимо от экономического или медицинского состояния.
Система основана на четырёх больничных кассах: Клалит (крупнейшая, около четырёх с половиной миллионов застрахованных), Маккаби, Меухедет и Леумит. Каждый житель обязан быть членом одной из них и может менять кассу раз в год. Финансирование поступает из налога на здравоохранение, удерживаемого из зарплаты, и из государственного бюджета.
Корзина здоровья — перечень услуг, которые кассы обязаны предоставлять — включает визиты к семейному врачу и специалистам, лабораторные анализы, визуализацию, госпитализацию, операции, субсидированные лекарства, психологическую помощь и реабилитацию. Корзина обновляется ежегодно, и в неё добавляются новые лекарства и процедуры по рекомендации профессиональной комиссии.
Тем не менее система сталкивается с серьёзными вызовами. Время ожидания длительное — иногда нужно ждать недели записи к специалисту, а в некоторых случаях месяцы. Нехватка врачей и медсестёр, особенно на периферии, ведёт к тяжёлой нагрузке на медперсонал. Приёмные покои в больницах переполнены, и иногда пациенты лежат в коридорах.
Разрыв между центром и периферией заметен и в медицине. В Тель-Авиве и Рамат-Гане расположены одни из самых передовых больниц мира — Ихилов, Шиба и Бейлинсон — но в Негеве и Галилее возможности ограниченнее. Многие израильтяне покупают дополнительную частную страховку, покрывающую частных специалистов, отдельные палаты в больнице и лекарства, не входящие в базовую корзину.
Несмотря на вызовы, израильская система обеспечивает высококачественную медицину для всего населения. Израиль является мировым лидером в областях экстренной медицины, лечения бесплодия, трансплантации органов и вакцинации. Во время пандемии ковида Израиль был одной из первых стран, вакцинировавших население, и послужил мировым тестовым примером.', '[{"he": "ביטוח בריאות", "ru": "мед. страхование", "translit": "битУах бриУт"}, {"he": "קופת חולים", "ru": "больничная касса", "translit": "купАт холИм"}, {"he": "סל בריאות", "ru": "корзина здоровья", "translit": "саль бриУт"}, {"he": "אשפוז", "ru": "госпитализация", "translit": "ишпУз"}, {"he": "חדר מיון", "ru": "приёмный покой", "translit": "хЕдер миЮн"}, {"he": "תוחלת חיים", "ru": "продолжительность жизни", "translit": "тохЕлет хаИм"}, {"he": "מסובסד", "ru": "субсидированный", "translit": "месубсАд"}, {"he": "חיסונים", "ru": "вакцины", "translit": "хисунИм"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (259, 3, 'בעלי חיים בישראל', 'Животные в Израиле', 'למרות שישראל היא מדינה קטנה — רק עשרים ושניים אלף קילומטר רבוע — יש בה מגוון מפתיע של בעלי חיים. הסיבה לכך היא המיקום הגיאוגרפי: ישראל נמצאת בצומת של שלוש יבשות — אירופה, אסיה ואפריקה — ולכן יש בה חיות מכל הסוגים.
בצפון הארץ, ביערות הגליל והכרמל, אפשר לראות צבאים, חזירי בר ודרבנים. לפעמים גם תנים ושועלים מגיעים עד לשכונות ערים. בשמורת הטבע של החולה, בצפון, חיים תאואים — שוורים גדולים שהוחזרו לטבע בפרויקט שימור מוצלח.
במדבר הנגב ובערבה חיים יעלים — עזים הרריות מרשימות עם קרניים עקומות. הם מטפסים על צוקים תלולים ונראים כאילו מתגרים בכוח המשיכה. יש גם שועלים, זאבים, צבועים ובואים — נחשי ענק שיכולים להגיע לאורך של שני מטרים.
אבל הדבר המרגש ביותר בישראל הוא נדידת הציפורים. ישראל נמצאת על אחד ממסלולי הנדידה הגדולים בעולם. פעמיים בשנה — באביב ובסתיו — מאות מיליוני ציפורים עוברות דרך ישראל בדרך מאירופה לאפריקה ובחזרה. אגמון החולה בצפון הוא מקום מושלם לצפות בהן — אפשר לראות עגורים, שקנאים, חסידות ועיטים.
בים התיכון חיים דולפינים, צבי ים ולפעמים אפילו כרישים קטנים. ישראל משקיעה בשימור טבע — יש שלושים ושתיים שמורות טבע לאומיות שמגנות על בעלי חיים ועל בתי הגידול שלהם.', 'Несмотря на то что Израиль — маленькая страна, всего двадцать две тысячи квадратных километров, в ней удивительное разнообразие животных. Причина — географическое положение: Израиль находится на стыке трёх континентов — Европы, Азии и Африки — поэтому здесь встречаются животные всех типов.
На севере страны, в лесах Галилеи и Кармеля, можно увидеть оленей, кабанов и дикобразов. Иногда шакалы и лисы приходят даже в городские районы. В заповеднике Хула на севере живут буйволы — крупные быки, возвращённые в природу в рамках успешного проекта по сохранению.
В пустыне Негев и в Араве живут козероги — впечатляющие горные козы с изогнутыми рогами. Они взбираются по отвесным скалам и выглядят так, будто бросают вызов гравитации. Есть также лисы, волки, гиены и удавы — гигантские змеи длиной до двух метров.
Но самое захватывающее в Израиле — миграция птиц. Израиль расположен на одном из крупнейших миграционных маршрутов в мире. Дважды в год — весной и осенью — сотни миллионов птиц пролетают через Израиль по пути из Европы в Африку и обратно. Агамон Хула на севере — идеальное место для наблюдения за ними — можно увидеть журавлей, пеликанов, аистов и орлов.
В Средиземном море живут дельфины, морские черепахи и иногда даже небольшие акулы. Израиль вкладывает средства в охрану природы — тридцать два национальных заповедника защищают животных и их среду обитания.', '[{"he": "בעלי חיים", "ru": "животные", "translit": "баалЕй хаЙот"}, {"he": "מגוון", "ru": "разнообразие", "translit": "мигвАн"}, {"he": "יעלים", "ru": "козероги", "translit": "яелИм"}, {"he": "ציפורים נודדות", "ru": "перелётные птицы", "translit": "ципорИм нодедОт"}, {"he": "שמורת טבע", "ru": "заповедник", "translit": "шмурАт тЕва"}, {"he": "שימור", "ru": "сохранение", "translit": "шимУр"}, {"he": "נדידה", "ru": "миграция", "translit": "недидА"}, {"he": "דולפינים", "ru": "дельфины", "translit": "дольфинИм"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (260, 3, 'סיפור: הזמנה מפתיעה', 'Рассказ: Неожиданное приглашение', 'ביום שישי אחד, בשלוש אחר הצהריים, קיבלתי הודעה בווטסאפ מדני — חבר ישן מהצבא שלא ראיתי כבר שלוש שנים. "אחי, בוא לארוחת שבת אצלנו הערב. שבע וחצי. ירושלים, רחוב עמק רפאים 15. אל תגיד לא."
הופתעתי. דני ואני שירתנו יחד בגולני, אבל אחרי הצבא כל אחד הלך לדרכו. הוא נשאר בירושלים, אני עברתי לתל אביב. חשבתי רגע — ירושלים, זה שעה נסיעה, כבר מאוחר... אבל משהו בפנים אמר לי: לך. הלכתי לסופר, קניתי בקבוק יין אדום ופרחים, ונסעתי.
כשהגעתי לדירה של דני, הדלת נפתחה ומאחוריה — הפתעה. בסלון ישבו שמונה חברים מהפלוגה שלנו! יוסי, מיכאל, סיגל, ענת, רועי, שרון, עומר ואלירן. לא ראיתי את רובם שנים. הלב שלי כמעט עצר. "מה?! מה זה?!" צעקתי.
מסתבר ששרון ארגנה את הכל. היא יצרה קבוצה סודית בווטסאפ, תיאמה תאריך עם כולם ותכננה את ההפתעה למשך חודש. "רציתי לאסוף את כולנו שוב," היא אמרה, "לפני שנשכח אחד את השני."
ישבנו סביב שולחן גדול עם חלות, יין, סלטים ועוף צלוי. אכלנו, צחקנו ונזכרנו בימים ההם — בסיפורי הצבא, בלילות בשטח, בבדיחות הישנות. יוסי הביא גיטרה ושרנו שירים של שלמה ארצי ואריק איינשטיין. בחוץ ירד גשם קל, ובפנים היה חם ומלא אהבה. חזרתי הביתה בשתיים בלילה, עייף מצחוק, ומלא שמחה שגדלה עם כל קילומטר בדרך.', 'В одну пятницу, в три часа дня, я получил сообщение в WhatsApp от Дани — старого друга из армии, которого не видел уже три года. «Братан, приходи на субботний ужин к нам вечером. Полвосьмого. Иерусалим, улица Эмек Рефаим 15. Не говори нет.»
Я удивился. Мы с Дани служили вместе в Голани, но после армии каждый пошёл своей дорогой. Он остался в Иерусалиме, я переехал в Тель-Авив. Я подумал — Иерусалим, это час езды, уже поздно... Но что-то внутри сказало: поезжай. Я пошёл в магазин, купил бутылку красного вина и цветы, и поехал.
Когда я пришёл в квартиру Дани, дверь открылась и за ней — сюрприз. В гостиной сидели восемь друзей из нашей роты! Йоси, Михаэль, Сигаль, Анат, Рои, Шарон, Омер и Элиран. Большинство из них я не видел годами. Моё сердце чуть не остановилось. «Что?! Что это?!» — закричал я.
Оказалось, что Шарон организовала всё. Она создала секретную группу в WhatsApp, согласовала дату со всеми и планировала сюрприз целый месяц. «Я хотела собрать нас всех снова,» — сказала она, «пока мы не забыли друг друга.»
Мы сидели за большим столом с халами, вином, салатами и запечённой курицей. Ели, смеялись и вспоминали те дни — армейские истории, ночи в поле, старые шутки. Йоси принёс гитару, и мы пели песни Шломо Арци и Арика Айнштейна. На улице шёл лёгкий дождь, а внутри было тепло и полно любви. Я вернулся домой в два ночи, уставший от смеха, и полный радости, которая росла с каждым километром пути.', '[{"he": "הודעה", "ru": "сообщение", "translit": "одаА"}, {"he": "הופתעתי", "ru": "удивился", "translit": "уфтАти"}, {"he": "מפגש", "ru": "встреча", "translit": "мифгАш"}, {"he": "ארגנה", "ru": "организовала", "translit": "иргенА"}, {"he": "נזכרנו", "ru": "вспоминали", "translit": "низкАрну"}, {"he": "פלוגה", "ru": "рота", "translit": "плугА"}, {"he": "חלות", "ru": "халы (субботний хлеб)", "translit": "халОт"}, {"he": "שמחה", "ru": "радость", "translit": "симхА"}]', NULL, 'story');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (261, 4, 'הייטק בישראל — אומת הסטארט-אפ', 'Хайтек в Израиле — нация стартапов', 'ישראל מכונה "אומת הסטארט-אפ" ולא בכדי. למרות שמדובר במדינה קטנה עם אוכלוסייה של כתשעה מיליון, ישראל מובילה בעולם ביחס מספר הסטארט-אפים לנפש. בתל אביב לבדה פועלים כשישת אלפים סטארט-אפים, ובמחוזות הרצלייה ורעננה נמצאים מרכזי הפיתוח של חברות ענק כמו גוגל, מיקרוסופט, אפל ואמזון.
הצלחת ההייטק הישראלי מבוססת על כמה גורמים ייחודיים. ראשית, השירות הצבאי — יחידות טכנולוגיות כמו 8200, מגלן ומצ"ב מכשירות צעירים בגיל שמונה עשרה ליכולות מתקדמות בסייבר, בתקשורת ובפיתוח תוכנה. בוגרי היחידות האלה ממשיכים להקים חברות ביחד, על בסיס האמון והניסיון המשותף.
שנית, התרבות הישראלית מעודדת יזמות. המושג "חוצפה" — הנכונות לערער על סמכות ולהציע רעיונות חדשים — נתפס בעולם העסקים כמנוע של חדשנות. ישראלים לא חוששים מכישלון: אם סטארט-אפ אחד נכשל, מקימים אחר. הסובלנות לכישלון הזאת שונה מתרבויות עסקיות בעולם שבהן כישלון נתפס כסטיגמה.
שלישית, האקדמיה הישראלית. אוניברסיטאות כמו הטכניון, ויצמן, האוניברסיטה העברית ואוניברסיטת תל אביב מדורגות גבוה ברשימות בינלאומיות ומייצרות מחקר פורץ דרך שמומר לחברות מסחריות. הממשלה תומכת בתהליך דרך רשות החדשנות שמעניקה מענקים ליזמים.
אולם יש גם אתגרים משמעותיים. פער ענק קיים בין מרכז לפריפריה — רוב חברות ההייטק מרוכזות בגוש דן, בעוד שבאר שבע, חיפה וצפון הנגב רק מתחילים להתפתח. עלויות השכר והדיור הגבוהות מכבידות על חברות צעירות. ומחסור חמור בכוח אדם מוביל לייבוא עובדים מחו"ל ולתחרות קשה על מפתחים מנוסים.
שאלת המפתח היא כיצד לשמור על היתרון הטכנולוגי לאורך זמן — במיוחד כשמדינות אחרות משקיעות מיליארדים בפיתוח בינה מלאכותית, קוונטום וביוטכנולוגיה. האם ישראל הקטנה יכולה להמשיך להתחרות בסין, בהודו ובארצות הברית?', 'Израиль называют «нацией стартапов», и неспроста. Несмотря на то что это маленькая страна с населением около девяти миллионов, Израиль мировой лидер по числу стартапов на душу населения. В одном Тель-Авиве работают около шести тысяч стартапов, а в районах Герцлии и Раананы расположены центры разработки таких гигантов, как Google, Microsoft, Apple и Amazon.
Успех израильского хайтека основан на нескольких уникальных факторах. Во-первых, военная служба — технологические подразделения вроде 8200, «Маглан» и МАЦАВ обучают молодых людей в восемнадцать лет продвинутым навыкам в кибербезопасности, связи и разработке ПО. Выпускники этих подразделений продолжают создавать компании вместе, на основе доверия и общего опыта.
Во-вторых, израильская культура поощряет предпринимательство. Понятие «хуцпа» — готовность оспаривать авторитеты и предлагать новые идеи — в бизнес-мире воспринимается как двигатель инноваций. Израильтяне не боятся провала: если один стартап не удался, создают другой. Такая терпимость к неудачам отличается от деловых культур, где провал воспринимается как стигма.
В-третьих, израильская академия. Университеты — Технион, Вейцман, Еврейский университет и Тель-Авивский — высоко котируются в международных рейтингах и производят прорывные исследования, которые превращаются в коммерческие компании. Государство поддерживает этот процесс через Управление инноваций, предоставляющее гранты предпринимателям.
Однако есть и серьёзные вызовы. Огромный разрыв существует между центром и периферией — большинство хайтек-компаний сосредоточены в Гуш-Дане, тогда как Беэр-Шева, Хайфа и север Негева только начинают развиваться. Высокие расходы на зарплаты и жильё давят на молодые компании. А острая нехватка кадров ведёт к привлечению работников из-за рубежа и жёсткой конкуренции за опытных разработчиков.
Ключевой вопрос — как сохранить технологическое преимущество надолго, особенно когда другие страны инвестируют миллиарды в развитие ИИ, квантовых технологий и биотехнологий. Сможет ли маленький Израиль продолжать конкурировать с Китаем, Индией и США?', '[{"he": "סטארט-אפ", "ru": "стартап", "translit": "стартАп"}, {"he": "סייבר", "ru": "кибербезопасность", "translit": "сАйбер"}, {"he": "יזמות", "ru": "предпринимательство", "translit": "язмУт"}, {"he": "חוצפה", "ru": "хуцпа/дерзость", "translit": "хуцпА"}, {"he": "חדשנות", "ru": "инновации", "translit": "хадшанУт"}, {"he": "פער", "ru": "разрыв", "translit": "пЕар"}, {"he": "כוח אדם", "ru": "кадры", "translit": "кОах адАм"}, {"he": "מענקים", "ru": "гранты", "translit": "маанакИм"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (262, 4, 'המשבר הדמוגרפי ושוק הדיור', 'Демографический кризис и рынок жилья', 'אחד האתגרים המשמעותיים ביותר בחברה הישראלית הוא מחירי הדיור. בעשרים השנים האחרונות, מחירי הדירות עלו ביותר ממאה חמישים אחוז, בעוד שהמשכורות עלו באופן מתון בלבד — כארבעים אחוז. הפער הזה יצר משבר חברתי עמוק שמשפיע על כל שכבות האוכלוסייה.
הסיבות למשבר מגוונות ומורכבות. מצד ההיצע, הבנייה בישראל לא עמדה בקצב הגידול הדמוגרפי. ישראל היא אחת המדינות המערביות עם שיעור הילודה הגבוה ביותר — כשלושה ילדים למשפחה בממוצע, ובמגזר החרדי אף יותר. בנוסף, גלי עלייה הביאו מאות אלפי אנשים שצריכים דיור. מצד הביקוש, ישראלים רואים בדירה השקעה בטוחה, ולכן משקיעים רבים קונים דירות שנייה ושלישית, מה שמעלה את המחירים עוד יותר.
ההשלכות החברתיות חמורות. צעירים רבים — גם בעלי הכנסה טובה — אינם יכולים לרכוש דירה ונאלצים לגור בשכירות ללא ביטחון לטווח ארוך. זוגות צעירים דוחים נישואים והורות כי אין להם יציבות כלכלית. רבים עוזבים את תל אביב ואת המרכז לטובת ערי הפריפריה, אך גם שם המחירים עולים.
הממשלה ניסתה תוכניות שונות לפתור את המשבר. תוכנית "מחיר למשתכן" הציעה דירות בהנחה לזכאים באמצעות הגרלה, אך מספר הדירות היה מוגבל. הגדלת היצע הבנייה נתקלה בהתנגדות של תושבים ובבירוקרטיה ארוכה — קבלת היתר בנייה לוקחת שנים. הלוואות מסובסדות עזרו לחלק מהצעירים, אך גם העלו את המחירים כי יותר קונים נכנסו לשוק.
כלכלנים מציעים פתרונות מבניים: פיתוח תשתיות תחבורה מהירות לפריפריה שיאפשרו לאנשים לגור רחוק ולעבוד במרכז; הקלת תהליכי הרישוי והבנייה; פיקוח על מחירי השכירות כדי להגן על שוכרים; ומיסוי כבד יותר על דירות השקעה כדי לצמצם את הספקולציה. שאלת הדיור היא לא רק שאלה כלכלית — היא שאלה של צדק חברתי ושל עתיד הדור הצעיר בישראל.', 'Один из самых значительных вызовов израильского общества — цены на жильё. За последние двадцать лет цены на квартиры выросли более чем на сто пятьдесят процентов, тогда как зарплаты росли лишь умеренно — примерно на сорок процентов. Этот разрыв создал глубокий социальный кризис, затрагивающий все слои населения.
Причины кризиса разнообразны и сложны. Со стороны предложения, строительство в Израиле не поспевало за демографическим ростом. Израиль — одна из западных стран с самым высоким уровнем рождаемости — около трёх детей на семью в среднем, а в ультраортодоксальном секторе и больше. Кроме того, волны репатриации привели сотни тысяч людей, нуждающихся в жилье. Со стороны спроса, израильтяне рассматривают квартиру как надёжную инвестицию, поэтому многие инвесторы покупают вторую и третью квартиры, что ещё больше повышает цены.
Социальные последствия серьёзны. Многие молодые люди — даже с хорошим доходом — не могут купить квартиру и вынуждены снимать без долгосрочной стабильности. Молодые пары откладывают свадьбы и рождение детей из-за отсутствия экономической стабильности. Многие уезжают из Тель-Авива и центра в периферийные города, но и там цены растут.
Правительство пробовало разные программы для решения кризиса. Программа «Цена для проживающего» предлагала квартиры со скидкой через лотерею для имеющих право, но число квартир было ограничено. Увеличение объёмов строительства столкнулось с сопротивлением жителей и длительной бюрократией — получение разрешения на строительство занимает годы. Субсидированные кредиты помогли части молодёжи, но также подняли цены, так как на рынок вышло больше покупателей.
Экономисты предлагают структурные решения: развитие скоростной транспортной инфраструктуры к периферии, чтобы люди могли жить далеко и работать в центре; упрощение процессов лицензирования и строительства; контроль арендных цен для защиты арендаторов; более высокое налогообложение инвестиционных квартир для сокращения спекуляции. Жилищный вопрос — не только экономический, это вопрос социальной справедливости и будущего молодого поколения Израиля.', '[{"he": "דיור", "ru": "жильё", "translit": "диЮр"}, {"he": "משכורות", "ru": "зарплаты", "translit": "маскорОт"}, {"he": "היצע", "ru": "предложение", "translit": "hецА"}, {"he": "ביקוש", "ru": "спрос", "translit": "бикУш"}, {"he": "תשתיות", "ru": "инфраструктуры", "translit": "таштиЙот"}, {"he": "פיקוח", "ru": "контроль", "translit": "пикУах"}, {"he": "ספקולציה", "ru": "спекуляция", "translit": "спекулАция"}, {"he": "צדק חברתי", "ru": "социальная справедливость", "translit": "цЕдек хевратИ"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (263, 4, 'הפסיכולוגיה של ההחלטות', 'Психология принятия решений', 'מחקרים פסיכולוגיים מראים שבני אדם לא תמיד מקבלים החלטות רציונליות. דניאל כהנמן, הפסיכולוג הישראלי שזכה בפרס נובל לכלכלה בשנת 2002, הוכיח במחקריו המהפכניים שאנו מושפעים מהטיות קוגניטיביות רבות — דפוסי חשיבה אוטומטיים שמובילים אותנו לטעויות שיטתיות בשיפוט ובקבלת החלטות.
אחת ההטיות המפורסמות ביותר היא "אפקט העיגון". בניסוי מפורסם, כהנמן ביקש מאנשים להעריך את אחוז המדינות האפריקניות באו"ם. לפני ההערכה, הם סובבו גלגל מזל שנחת על מספר אקראי. אנשים שקיבלו מספר גבוה נתנו הערכות גבוהות יותר, ולהפך — למרות שהמספר היה אקראי לחלוטין. המוח שלנו "מעוגן" במספר הראשון שהוא רואה, גם כשאין לו שום קשר לשאלה.
הטיה נפוצה נוספת היא "הטיית האישוש" — הנטייה לחפש מידע שמאשר את מה שכבר מאמינים בו ולהתעלם ממידע סותר. אם אנחנו חושבים שתרופה מסוימת עובדת, נשים לב לכל פעם שהיא עזרה ונשכח את הפעמים שלא. ברשתות חברתיות, אלגוריתמים מחזקים את ההטיה הזאת בכך שהם מציגים לנו תוכן שמתאים לדעות הקיימות שלנו.
"הטיית הזמינות" היא עוד דוגמה חשובה. אנחנו מעריכים את הסיכון לאירוע לפי כמה קל לנו לחשוב על דוגמאות. אחרי שמיעת חדשות על תאונת מטוס, אנשים מפחדים יותר לטוס — למרות שסטטיסטית טיסה בטוחה הרבה יותר מנסיעה במכונית. המוח שלנו לא טוב בהערכת הסתברויות — הוא מסתמך על רגשות ודמיון במקום על מספרים.
כהנמן חילק את המחשבה האנושית לשתי מערכות: "מערכת 1" — מהירה, אינטואיטיבית ואוטומטית, ו"מערכת 2" — איטית, אנליטית ומכוונת. רוב ההחלטות שלנו מתקבלות על ידי מערכת 1, שחוסכת אנרגיה אך מובילה להטיות. הבנת ההטיות האלה חשובה לא רק באקדמיה — אלא גם בחיי היומיום: בקניות, בבחירות פוליטיות, בהחלטות כלכליות ובמערכות יחסים. מודעות להטיות לא מבטלת אותן, אבל מאפשרת לנו להיות זהירים יותר ברגעים קריטיים.', 'Психологические исследования показывают, что люди не всегда принимают рациональные решения. Даниэль Канеман, израильский психолог, лауреат Нобелевской премии по экономике 2002 года, доказал в своих революционных исследованиях, что на нас влияют многочисленные когнитивные искажения — автоматические паттерны мышления, которые ведут к систематическим ошибкам в суждениях и принятии решений.
Одно из самых известных искажений — «эффект якоря». В знаменитом эксперименте Канеман просил людей оценить процент африканских стран в ООН. Перед оценкой они крутили колесо фортуны, которое останавливалось на случайном числе. Люди, получившие высокое число, давали более высокие оценки, и наоборот — хотя число было совершенно случайным. Наш мозг «привязывается» к первому числу, которое видит, даже когда оно не имеет никакого отношения к вопросу.
Ещё одно распространённое искажение — «предвзятость подтверждения» — склонность искать информацию, подтверждающую то, во что мы уже верим, и игнорировать противоречащую. Если мы считаем, что определённое лекарство работает, мы замечаем каждый раз, когда оно помогло, и забываем случаи, когда нет. В социальных сетях алгоритмы усиливают это искажение, показывая нам контент, соответствующий нашим существующим взглядам.
«Эвристика доступности» — ещё один важный пример. Мы оцениваем вероятность события по тому, как легко нам вспомнить примеры. После новостей об авиакатастрофе люди больше боятся летать — хотя статистически полёт намного безопаснее поездки на машине. Наш мозг плохо оценивает вероятности — он опирается на эмоции и воображение вместо чисел.
Канеман разделил человеческое мышление на две системы: «Система 1» — быстрая, интуитивная и автоматическая, и «Система 2» — медленная, аналитическая и целенаправленная. Большинство наших решений принимаются Системой 1, которая экономит энергию, но ведёт к искажениям. Понимание этих искажений важно не только в академии, но и в повседневной жизни: в покупках, на политических выборах, в финансовых решениях и в отношениях. Осознание искажений не устраняет их, но позволяет нам быть осторожнее в критические моменты.', '[{"he": "החלטות", "ru": "решения", "translit": "хахлатОт"}, {"he": "הטיות קוגניטיביות", "ru": "когнитивные искажения", "translit": "хатаЙот когнитИвийот"}, {"he": "אקראי", "ru": "случайный", "translit": "акраИ"}, {"he": "אישוש", "ru": "подтверждение", "translit": "ишУш"}, {"he": "הסתברות", "ru": "вероятность", "translit": "хистабрУт"}, {"he": "אינטואיטיבי", "ru": "интуитивный", "translit": "интуитИви"}, {"he": "מודעות", "ru": "осознание", "translit": "мудаУт"}, {"he": "סיכון", "ru": "риск", "translit": "сикУн"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (264, 4, 'הקיבוץ — מההתחלה ועד היום', 'Кибуц — от истоков до наших дней', 'הקיבוץ הראשון בישראל, דגניה, הוקם בשנת 1910 על שפת הכנרת בידי קבוצה קטנה של חלוצים צעירים מאירופה. הרעיון שהנחה אותם היה פשוט ומהפכני בו זמנית: ליצור חברה שוויונית שבה הכל משותף — הקרקע, הרכוש, העבודה והחינוך. לא היו משכורות, לא היה רכוש פרטי, וההחלטות התקבלו באסיפה כללית.
במשך עשרות שנים, הקיבוצים היו עמוד תווך של המפעל הציוני. הם פיתחו אדמות שוממות, ייבשו ביצות, הקימו יישובים באזורים מרוחקים ותרמו לביטחון. חברי הקיבוצים שימשו כטייסים, כמפקדים צבאיים וכמנהיגים פוליטיים — למעלה מרבע מחברי הכנסת הראשונים באו מקיבוצים. בשיא, בשנות השבעים, חיו בקיבוצים כמאה שלושים אלף איש.
החיים בקיבוץ המסורתי נראו כך: בבוקר, הכל אכלו יחד בחדר אוכל גדול. ילדים גרו בבית ילדים ולא עם ההורים — רעיון שהיה שנוי במחלוקת. כולם עבדו — בחקלאות, במפעל, במטבח או בכביסה — והעבודה חולקה לפי צורכי הקהילה, לא לפי רצון הפרט. בגדים ניתנו מהמחסן המשותף. ארוחות, חינוך ורפואה היו חינם.
אולם מאז שנות השמונים חלו שינויים דרמטיים. משברים כלכליים פגעו בקיבוצים רבים. הדור הצעיר לא רצה לחיות בשוויון מוחלט — הם רצו משכורות, רכוש פרטי ובחירה. רוב הקיבוצים עברו תהליך של הפרטה: חברים מקבלים משכורות שונות לפי עבודתם, דירות הפכו לרכוש פרטי, חדר האוכל המשותף נסגר במקומות רבים, וילדים חזרו לגור עם ההורים.
היום יש כמאתיים שבעים קיבוצים בישראל, וכמעט כולם "קיבוצים מתחדשים" — שמשלבים ערכים קהילתיים עם כלכלה פרטית. השינוי מעורר דיון עד היום: האם הקיבוץ איבד את הרוח המקורית, את האידיאל של שוויון ושיתוף? או שהוא פשוט התאים את עצמו למציאות של המאה העשרים ואחת? התשובה כנראה נמצאת באמצע — הקיבוץ השתנה, אבל הוא עדיין מקום ייחודי שמציע תחושת קהילה שאין כמותה בשום מקום אחר בעולם.', 'Первый кибуц в Израиле, Дегания, был основан в 1910 году на берегу Кинерета маленькой группой молодых пионеров из Европы. Идея, которая ими руководила, была простой и революционной одновременно: создать равноправное общество, где всё общее — земля, имущество, труд и воспитание. Не было зарплат, не было частной собственности, а решения принимались на общем собрании.
На протяжении десятилетий кибуцы были опорой сионистского проекта. Они осваивали пустынные земли, осушали болота, основывали поселения в отдалённых районах и вносили вклад в безопасность. Члены кибуцев служили лётчиками, военными командирами и политическими лидерами — более четверти депутатов первого Кнессета были из кибуцев. На пике, в семидесятые годы, в кибуцах жили около ста тридцати тысяч человек.
Жизнь в традиционном кибуце выглядела так: утром все ели вместе в большой столовой. Дети жили в детском доме, а не с родителями — спорная идея. Все работали — в сельском хозяйстве, на заводе, на кухне или в прачечной — и работа распределялась по нуждам общины, а не по желанию человека. Одежду выдавали с общего склада. Питание, образование и медицина были бесплатными.
Однако с восьмидесятых годов произошли драматические изменения. Экономические кризисы ударили по многим кибуцам. Молодое поколение не хотело жить в полном равенстве — они хотели зарплаты, частную собственность и выбор. Большинство кибуцев прошли приватизацию: члены получают разные зарплаты в зависимости от работы, квартиры стали частной собственностью, общая столовая закрылась во многих местах, а дети вернулись жить к родителям.
Сегодня в Израиле около двухсот семидесяти кибуцев, и почти все — «обновлённые кибуцы», сочетающие общинные ценности с частной экономикой. Перемена вызывает дискуссию по сей день: потерял ли кибуц первоначальный дух, идеал равенства и общности? Или просто приспособился к реальности двадцать первого века? Ответ, вероятно, где-то посередине — кибуц изменился, но по-прежнему остаётся уникальным местом, предлагающим чувство общности, которого нет нигде в мире.', '[{"he": "קיבוץ", "ru": "кибуц", "translit": "кибУц"}, {"he": "שוויון", "ru": "равенство", "translit": "шивьОн"}, {"he": "הפרטה", "ru": "приватизация", "translit": "хафратА"}, {"he": "חלוצים", "ru": "пионеры", "translit": "халуцИм"}, {"he": "אסיפה כללית", "ru": "общее собрание", "translit": "асифА клалИт"}, {"he": "רכוש", "ru": "имущество", "translit": "рехУш"}, {"he": "מתחדשים", "ru": "обновлённые", "translit": "митхадшИм"}, {"he": "מציאות", "ru": "реальность", "translit": "мециУт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (266, 4, 'מסה: על חופש הביטוי', 'Эссе: О свободе слова', 'חופש הביטוי הוא ערך יסודי בחברה דמוקרטית, אך האם הוא מוחלט? שאלה זו מעסיקה פילוסופים, משפטנים ופוליטיקאים כבר מאות שנים, והתשובה עליה משתנה לפי הקשר תרבותי, היסטורי ופוליטי. בישראל, כמו בכל דמוקרטיה, הוויכוח על גבולות חופש הביטוי הוא חי ותוסס.
מצד אחד, חופש הביטוי הוא אבן יסוד של חברה חופשית. הוא מאפשר ביקורת על השלטון, חילופי דעות בציבור, יצירתיות אמנותית וחשיפת שחיתות. בלי חופש ביטוי, אין עיתונות חופשית, אין דיון ציבורי ואין אפשרות לבקר את מי שבשלטון. הפילוסוף ג''ון סטיוארט מיל טען במאה התשע עשרה שאפילו דעה שגויה צריכה לקבל במה — כי רק דרך עימות בין דעות אפשר להגיע לאמת.
מצד שני, ביטוי יכול לפגוע ולסכן. הסתה לאלימות עלולה להוביל לפעולות טרור. לשון הרע הורסת חיים של אנשים. פייק ניוז — חדשות מזויפות — מערערת את האמון בתקשורת ובמוסדות דמוקרטיים. דיבור שנאה כלפי מיעוטים יוצר אווירה של פחד ואלימות. האם חופש הביטוי כולל את הזכות לפגוע?
בישראל, חופש הביטוי מוגן כזכות יסודית, אך לא באופן מוחלט. בית המשפט העליון פסק שניתן להגביל את חופש הביטוי כאשר הוא מהווה "ודאות קרובה" לפגיעה ממשית ורצינית. לדוגמה, איסור על הסתה לגזענות קיים בחוק, וכך גם איסור על פרסום פורנוגרפית ילדים. אבל הגבול לא תמיד ברור — האם סטנד-אפ שמלעיג על קבוצה מסוימת הוא חופש ביטוי או דיבור שנאה?
בעידן הדיגיטלי, השאלה נעשית מורכבת יותר. רשתות חברתיות מאפשרות לכל אחד להפיץ מסרים למיליונים תוך שניות. אלגוריתמים מעדיפים תוכן פרובוקטיבי כי הוא מייצר מעורבות. ממשלות דורשות מחברות הטכנולוגיה לצנזר תכנים מסוכנים, אך מי מחליט מה "מסוכן"? האיזון בין חופש לאחריות הוא עדין, מורכב ומשתנה כל הזמן — והוא אחד הדילמות המרכזיות של הדמוקרטיה במאה העשרים ואחת.', 'Свобода слова — фундаментальная ценность демократического общества, но абсолютна ли она? Этот вопрос занимает философов, юристов и политиков уже сотни лет, и ответ на него меняется в зависимости от культурного, исторического и политического контекста. В Израиле, как и в любой демократии, дискуссия о границах свободы слова жива и активна.
С одной стороны, свобода слова — краеугольный камень свободного общества. Она позволяет критиковать власть, обмениваться мнениями публично, творить и разоблачать коррупцию. Без свободы слова нет свободной прессы, нет общественной дискуссии и нет возможности критиковать власть имущих. Философ Джон Стюарт Милль утверждал в девятнадцатом веке, что даже ошибочное мнение должно получить площадку — потому что только через столкновение мнений можно прийти к истине.
С другой стороны, высказывание может нанести вред и подвергнуть опасности. Подстрекательство к насилию может привести к терактам. Клевета разрушает жизни людей. Фейковые новости подрывают доверие к СМИ и демократическим институтам. Язык ненависти в адрес меньшинств создаёт атмосферу страха и насилия. Включает ли свобода слова право причинять вред?
В Израиле свобода слова защищена как основное право, но не абсолютно. Верховный суд постановил, что свободу слова можно ограничить, когда она создаёт «близкую вероятность» реального и серьёзного ущерба. Например, запрет на подстрекательство к расизму закреплён в законе, как и запрет на распространение детской порнографии. Но граница не всегда ясна — стендап, высмеивающий определённую группу, это свобода слова или язык ненависти?
В цифровую эпоху вопрос становится ещё сложнее. Социальные сети позволяют каждому распространять сообщения миллионам за секунды. Алгоритмы предпочитают провокационный контент, потому что он генерирует вовлечённость. Правительства требуют от технологических компаний цензурировать опасный контент, но кто решает, что «опасно»? Баланс между свободой и ответственностью тонок, сложен и постоянно меняется — и это одна из центральных дилемм демократии двадцать первого века.', '[{"he": "חופש הביטוי", "ru": "свобода слова", "translit": "хОфеш хабитУй"}, {"he": "דמוקרטי", "ru": "демократический", "translit": "демокрАти"}, {"he": "הסתה", "ru": "подстрекательство", "translit": "хасатА"}, {"he": "להגביל", "ru": "ограничить", "translit": "лехагбИль"}, {"he": "שחיתות", "ru": "коррупция", "translit": "шхитУт"}, {"he": "פייק ניוז", "ru": "фейковые новости", "translit": "фейк ньюс"}, {"he": "לשון הרע", "ru": "клевета", "translit": "лашОн харА"}, {"he": "איזון", "ru": "баланс", "translit": "изУн"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (267, 4, 'ההיסטוריה של תל אביב', 'История Тель-Авива', 'תל אביב הוקמה בשנת 1909 כשכונת מגורים יהודית מחוץ ליפו העתיקה. שישים ושש משפחות עמדו על חולות לבנים ושרטטו גורלות על חלקות אדמה — כל חלקה סומנה בצדף לבן. מייסדי העיר חלמו על עיר מודרנית עם רחובות רחבים, גנים ציבוריים ובתים בסגנון אירופי — שונה לחלוטין מהסמטאות הצרות של יפו.
בשנות העשרים והשלושים, גלי העלייה שהביאו מהגרים מאירופה הפכו את תל אביב לעיר אמיתית. ארכיטקטים שהגיעו מגרמניה — רבים מהם בוגרי בית הספר באוהאוס — בנו אלפי בתים בסגנון הבינלאומי: קווים ישרים, קירות לבנים, גגות שטוחים ומרפסות מעוגלות. כך נוצרה "העיר הלבנה" — האוסף הגדול ביותר של מבנים בסגנון באוהאוס בעולם, שהוכר בשנת 2003 כאתר מורשת עולמית של אונסק"ו.
ב-1948, בבניין העירייה ברחוב רוטשילד, הכריז דוד בן-גוריון על הקמת מדינת ישראל. בשנות החמישים והשישים תל אביב גדלה במהירות — שכונות חדשות נבנו, מפעלים קמו, ואוניברסיטת תל אביב הוקמה. העיר הייתה מרכז תרבותי חשוב עם תיאטראות, גלריות ובתי קפה ספרותיים.
בשנות התשעים חלה תפנית דרמטית. תהליך השלום, הכלכלה הגלובלית וענף ההייטק הפכו את תל אביב לעיר בינלאומית. שדרות רוטשילד הפכו לסמל של עירוניות חדשה — בתי קפה, אופניים, סטארט-אפים ותרבות רחוב. הנמל הישן שופץ והפך למרכז בילוי. שוק הכרמל חזר לחיים כמוקד קולינרי ותיירותי.
מיפו הערבית-יהודית ועד למטרופולין של היום — תל אביב עברה שינויים עצומים. העיר שנולדה על חולות הפכה לעיר עם אוכלוסייה של כארבע מאות חמישים אלף, מרכז עסקים, תרבות, בילויים וחדשנות. היא שומרת על אופי ייחודי של חופש, פתיחות ויצירתיות — עיר שלא ישנה, עיר שתמיד משתנה, עיר שאי אפשר להישאר כלפיה אדיש.', 'Тель-Авив был основан в 1909 году как еврейский жилой район за пределами древней Яффы. Шестьдесят шесть семей стояли на белых песках и тянули жребий на земельные участки — каждый участок был отмечен белой ракушкой. Основатели мечтали о современном городе с широкими улицами, общественными садами и домами в европейском стиле — совершенно отличном от узких переулков Яффы.
В двадцатые и тридцатые годы волны иммиграции, принёсшие переселенцев из Европы, превратили Тель-Авив в настоящий город. Архитекторы из Германии — многие из них выпускники школы Баухаус — построили тысячи зданий в интернациональном стиле: прямые линии, белые стены, плоские крыши и округлые балконы. Так возник «Белый город» — крупнейшая в мире коллекция зданий в стиле Баухаус, признанная в 2003 году объектом Всемирного наследия ЮНЕСКО.
В 1948 году в здании муниципалитета на бульваре Ротшильд Давид Бен-Гурион провозгласил создание Государства Израиль. В пятидесятые и шестидесятые Тель-Авив быстро рос — строились новые районы, появлялись заводы, был основан Тель-Авивский университет. Город стал важным культурным центром с театрами, галереями и литературными кафе.
В девяностые произошёл драматический поворот. Мирный процесс, глобальная экономика и хайтек-индустрия превратили Тель-Авив в международный город. Бульвар Ротшильд стал символом новой городской жизни — кафе, велосипеды, стартапы и уличная культура. Старый порт был отреставрирован и стал центром развлечений. Рынок Кармель ожил как кулинарный и туристический центр.
От арабо-еврейской Яффы до современного мегаполиса — Тель-Авив прошёл огромные изменения. Город, рождённый на песке, стал городом с населением около четырёхсот пятидесяти тысяч, центром бизнеса, культуры, развлечений и инноваций. Он сохраняет уникальный характер свободы, открытости и творчества — город, который не спит, город, который постоянно меняется, город, к которому невозможно остаться равнодушным.', '[{"he": "הוקמה", "ru": "была основана", "translit": "хукмА"}, {"he": "גורלות", "ru": "жребии", "translit": "горалОт"}, {"he": "באוהאוס", "ru": "Баухаус", "translit": "бАухаус"}, {"he": "מורשת", "ru": "наследие", "translit": "морЕшет"}, {"he": "מטרופולין", "ru": "мегаполис", "translit": "метропОлин"}, {"he": "חדשנות", "ru": "инновации", "translit": "хадшанУт"}, {"he": "ארכיטקטים", "ru": "архитекторы", "translit": "архитЕктим"}, {"he": "עירוניות", "ru": "городская жизнь", "translit": "иронИют"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (268, 4, 'שוק העבודה המשתנה', 'Меняющийся рынок труда', 'שוק העבודה בישראל, כמו ברחבי העולם, עובר שינויים מהותיים שמשנים את הדרך שבה אנשים עובדים, מתפרנסים ומגדירים את הקריירה שלהם. הדיגיטליזציה, הבינה המלאכותית והאוטומציה מבטלות משרות מסורתיות ויוצרות חדשות שלא היו קיימות לפני עשור.
מקצועות כמו מנתח נתונים, מפתח בינה מלאכותית, מומחה סייבר, מנהל מדיה חברתית ומעצב חוויית משתמש לא היו קיימים לפני עשרים שנה. מנגד, מקצועות מסורתיים — פקידי בנק, סוכני נסיעות, מתקני קו ייצור — הולכים ונעלמים. לפי תחזיות, כעשרים אחוז מהמשרות הנוכחיות ייעלמו בעשור הקרוב, אך ייווצרו משרות חדשות שאי אפשר עדיין לדמיין.
השינוי הגדול ביותר הוא עבודה מרחוק. מגפת הקורונה האיצה תהליך שכבר היה בדרך — עבודה מהבית הפכה לנורמה בענפים רבים. מחקרים מראים ששלישית מהעובדים בישראל מעדיפים מודל היברידי: שלושה ימים במשרד ושניים בבית, או להפך. יתרונות העבודה מרחוק ברורים: חיסכון בזמן נסיעה, גמישות, ואיזון טוב יותר בין עבודה לחיים.
אולם המעבר מעלה שאלות מורכבות. כיצד לשמור על תרבות ארגונית כשהעובדים לא נפגשים פנים אל פנים? איך למנוע שחיקה ובדידות של עובדים מרוחקים? מה יהיה עם מרכזי הערים — מגדלי המשרדים, המסעדות, החנויות — כשפחות אנשים נוסעים למשרד כל יום?
גם כלכלת הגיג צומחת. יותר ויותר ישראלים עובדים כפרילנסרים — מתכנתים, מעצבים, כותבים, מתרגמים ויועצים. הם נהנים מחופש ומגמישות, אך חסרים ביטחון תעסוקתי, ביטוח פנסיוני ותנאים סוציאליים. שאלת הזכויות של עובדי הגיג היא אחת השאלות הדוחקות ביותר בשוק העבודה.
האתגר המרכזי הוא חינוך והכשרה. המערכת צריכה להכין את הדור הבא למקצועות שעדיין לא קיימים, ולאפשר לעובדים קיימים לעבור הכשרה מחדש. ישראל, עם מערכת ההייטק החזקה שלה, נמצאת בעמדה טובה להוביל את המעבר — אם תשכיל להכשיר לא רק את עילית הטכנולוגיה אלא את כל האוכלוסייה.', 'Рынок труда в Израиле, как и во всём мире, переживает фундаментальные изменения, которые меняют способ работы, заработка и определения карьеры. Цифровизация, искусственный интеллект и автоматизация упраздняют традиционные должности и создают новые, не существовавшие десять лет назад.
Профессии вроде аналитика данных, разработчика ИИ, эксперта по кибербезопасности, менеджера социальных сетей и UX-дизайнера не существовали двадцать лет назад. С другой стороны, традиционные профессии — банковские клерки, турагенты, рабочие конвейера — исчезают. По прогнозам, около двадцати процентов нынешних должностей исчезнут в ближайшее десятилетие, но появятся новые, которые пока невозможно вообразить.
Самое большое изменение — удалённая работа. Пандемия ковида ускорила процесс, который уже шёл — работа из дома стала нормой во многих отраслях. Исследования показывают, что треть работников в Израиле предпочитает гибридную модель: три дня в офисе и два дома, или наоборот. Преимущества удалённой работы очевидны: экономия времени на дорогу, гибкость и лучший баланс работы и жизни.
Однако переход поднимает сложные вопросы. Как сохранить организационную культуру, когда сотрудники не встречаются лично? Как предотвратить выгорание и одиночество удалённых работников? Что будет с центрами городов — офисными башнями, ресторанами, магазинами — когда меньше людей ездят в офис каждый день?
Экономика подработок тоже растёт. Всё больше израильтян работают фрилансерами — программисты, дизайнеры, авторы, переводчики и консультанты. Они наслаждаются свободой и гибкостью, но лишены стабильности занятости, пенсионного страхования и социальных условий. Вопрос прав гиг-работников — один из самых насущных на рынке труда.
Главный вызов — образование и подготовка. Система должна готовить следующее поколение к профессиям, которых ещё не существует, и давать нынешним работникам возможность переобучения. Израиль, с его сильной хайтек-системой, находится в хорошей позиции для лидерства в этом переходе — если сумеет подготовить не только технологическую элиту, но и всё население.', '[{"he": "דיגיטליזציה", "ru": "цифровизация", "translit": "дигитализАция"}, {"he": "בינה מלאכותית", "ru": "искусственный интеллект", "translit": "бинА мелахутИт"}, {"he": "היברידי", "ru": "гибридный", "translit": "хибрИди"}, {"he": "שחיקה", "ru": "выгорание", "translit": "шхикА"}, {"he": "פרילנסרים", "ru": "фрилансеры", "translit": "фрилАнсерим"}, {"he": "הכשרה", "ru": "подготовка", "translit": "ахшарА"}, {"he": "תרבות ארגונית", "ru": "корпоративная культура", "translit": "тарбУт иргунИт"}, {"he": "משרות", "ru": "должности", "translit": "масрОт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (269, 4, 'חינוך דו-לשוני ערבי-יהודי', 'Двуязычное арабо-еврейское образование', 'בישראל פועלים מספר בתי ספר דו-לשוניים ייחודיים שבהם לומדים יחד ילדים ערבים ויהודים — ניסוי חברתי וחינוכי אמיץ בחברה שבה שתי הקבוצות חיות לרוב בנפרד. הרעיון שעומד מאחורי בתי הספר האלה פשוט: אם ילדים ילמדו יחד מגיל צעיר, יכירו את התרבות, השפה והנרטיב של השני, ויפתחו סובלנות והבנה הדדית.
רשת "יד ביד" מפעילה שבעה בתי ספר דו-לשוניים ברחבי הארץ — בירושלים, בגליל, בוואדי ערה, בבאר שבע ובחיפה. בכל כיתה יש שני מורים — אחד דובר עברית ואחד דובר ערבית — ושני קבוצות תלמידים, יהודים וערבים, בפרופורציה שווה ככל האפשר. השיעורים מתנהלים בשתי השפות, ותלמידים לומדים את שני הנרטיבים ההיסטוריים — למשל, את יום העצמאות ואת הנכבה.
המחקרים על תלמידי בתי ספר דו-לשוניים מראים תוצאות מעודדות. התלמידים מדווחים על חברויות חוצות מגזרים, על הבנה טובה יותר של "הצד השני" ועל פחות סטריאוטיפים. הם שולטים טוב יותר בשתי השפות ומפתחים חשיבה ביקורתית לגבי נרטיבים לאומיים. בוגרי בתי הספר האלה, לפי מחקרי מעקב, ממשיכים לשמור על קשרים חוצי מגזרים גם בחיים הבוגרים.
עם זאת, המודל מתמודד עם אתגרים רבים. ראשית, הביקוש עולה על ההיצע — יש רשימות המתנה ארוכות, אך אין מספיק מימון להקמת בתי ספר חדשים. שנית, המודל דורש מורים מיוחדים שיכולים לעבוד בסביבה דו-לשונית ודו-תרבותית, ואלה קשים למצוא. שלישית, בתי הספר קיימים בעיקר בערים מעורבות, ולא מגיעים לישובים הומוגניים שבהם הצורך בהכרות אולי גדול יותר.
המבקרים טוענים שהמודל נאיבי — שקשה לשנות מציאות פוליטית מורכבת דרך חינוך בלבד. אחרים מצביעים על כך שהמודל משרת בעיקר משפחות מבוסס עם אידיאולוגיה שלום, ולא חודר לשכבות הרחבות של האוכלוסייה. אך התומכים מאמינים שכל ילד שגדל יחד עם ילד מ"הצד השני" הוא זרע של שינוי — ושאם חיים משותפים אפשריים איפשהו, הם אפשריים בכיתת לימוד.', 'В Израиле действуют несколько уникальных двуязычных школ, где вместе учатся арабские и еврейские дети — смелый социальный и образовательный эксперимент в обществе, где две группы обычно живут раздельно. Идея, стоящая за этими школами, проста: если дети будут учиться вместе с раннего возраста, они узнают культуру, язык и нарратив друг друга и разовьют толерантность и взаимопонимание.
Сеть «Яд бе-Яд» управляет семью двуязычными школами по всей стране — в Иерусалиме, Галилее, Вади-Ара, Беэр-Шеве и Хайфе. В каждом классе два учителя — ивритоязычный и арабоязычный — и две группы учеников, евреи и арабы, в максимально равной пропорции. Уроки ведутся на обоих языках, и ученики изучают оба исторических нарратива — например, День независимости и Накбу.
Исследования учеников двуязычных школ показывают обнадёживающие результаты. Ученики отмечают дружбу через секторальные границы, лучшее понимание «другой стороны» и меньше стереотипов. Они лучше владеют обоими языками и развивают критическое мышление по отношению к национальным нарративам. Выпускники этих школ, по данным исследований, продолжают поддерживать межсекторальные связи и во взрослой жизни.
Тем не менее модель сталкивается с многочисленными вызовами. Во-первых, спрос превышает предложение — очереди длинные, но недостаточно финансирования для открытия новых школ. Во-вторых, модель требует особых учителей, способных работать в двуязычной и двукультурной среде, а их трудно найти. В-третьих, школы существуют в основном в смешанных городах и не достигают однородных поселений, где потребность в знакомстве, возможно, ещё больше.
Критики утверждают, что модель наивна — что трудно изменить сложную политическую реальность только через образование. Другие указывают, что модель обслуживает в основном обеспеченные семьи с мирной идеологией и не проникает в широкие слои населения. Но сторонники верят, что каждый ребёнок, выросший рядом с ребёнком с «другой стороны», — это семя перемен, и что если совместная жизнь возможна где-то, она возможна в школьном классе.', '[{"he": "דו-לשוני", "ru": "двуязычный", "translit": "ду-лешонИ"}, {"he": "סובלנות", "ru": "толерантность", "translit": "совланУт"}, {"he": "נרטיב", "ru": "нарратив", "translit": "наратИв"}, {"he": "מגזרים", "ru": "секторы", "translit": "мигзарИм"}, {"he": "סטריאוטיפים", "ru": "стереотипы", "translit": "стереотИпим"}, {"he": "חיים משותפים", "ru": "совместная жизнь", "translit": "хаИм мешутафИм"}, {"he": "ביקורתי", "ru": "критический", "translit": "бикортИ"}, {"he": "נכבה", "ru": "Накба", "translit": "нАкба"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (270, 4, 'ים המלח — פלא טבע בסכנה', 'Мёртвое море — чудо природы в опасности', 'ים המלח הוא המקום הנמוך ביותר בעולם — כארבע מאות שלושים מטרים מתחת לפני הים. מימיו מלוחים פי עשרה מהאוקיינוס, ולכן גוף האדם צף בהם ללא כל מאמץ — חוויה שמושכת מיליוני תיירים מכל העולם. הבוץ השחור של ים המלח מפורסם בתכונותיו הריפויות ומשמש בתעשיית הקוסמטיקה הישראלית.
אולם ים המלח נמצא בסכנה אמיתית. מפלס המים יורד במטר ומחצה בשנה בממוצע — ירידה מתמשכת שנמשכת כבר חמישים שנה. השטח התכווץ בכשליש מגודלו המקורי. חופים שהיו מכוסים במים לפני עשרים שנה הם היום שטחי יובש. מלונות שנבנו על שפת הים נמצאים היום מאות מטרים ממנו.
הסיבות לירידה ידועות. ראשית, שאיבת מים מנהר הירדן — מקור המים העיקרי של ים המלח — לצרכי חקלאות ומי שתייה. ישראל, ירדן וסוריה שואבות כתשעים וחמישה אחוז מזרימת הירדן לפני שהמים מגיעים לים המלח. שנית, מפעלי ים המלח — של ישראל ושל ירדן — מאיידים כמויות עצומות של מים לצורך הפקת אשלג ומינרלים אחרים. שלישית, שינויי אקלים מפחיתים את כמות הגשמים באזור.
תופעה מפחידה נוספת היא הבולענות — בורות שנפתחים פתאום באדמה כתוצאה מהמסת שכבות מלח תת-קרקעיות. מאז שנות התשעים נוצרו למעלה משישת אלפים בולענות לאורך חופי ים המלח. בולענות בלעו כבישים, חניונים ואפילו מבנים. האזור הפך למסוכן, וחופים שלמים נסגרו לציבור.
מדענים ומהנדסים מציעים פתרונות. הרעיון הגדול ביותר הוא "תעלת הימים" — צינור שיוביל מים מהים האדום לים המלח, ובדרך ייצר חשמל מהתפלת מים. הפרויקט, שנדון כבר עשרות שנים, ידרוש שיתוף פעולה בין ישראל, ירדן והרשות הפלסטינית, ועלותו מוערכת במיליארדי דולרים. אחרים טוענים שהפתרון פשוט יותר — להחזיר מים לנהר הירדן ולצמצם את הפקת המינרלים. מה שבטוח: אם לא יינקטו צעדים דרסטיים, ים המלח — אחד מפלאי הטבע של העולם — עלול להיעלם תוך עשורים ספורים.', 'Мёртвое море — самое низкое место на Земле, около четырёхсот тридцати метров ниже уровня моря. Его воды в десять раз солонее океана, поэтому тело человека держится на поверхности без всяких усилий — опыт, привлекающий миллионы туристов со всего мира. Чёрная грязь Мёртвого моря известна целебными свойствами и используется в израильской косметической индустрии.
Однако Мёртвое море находится в реальной опасности. Уровень воды падает в среднем на полтора метра в год — непрерывное снижение, продолжающееся уже пятьдесят лет. Площадь сократилась примерно на треть от первоначального размера. Берега, покрытые водой двадцать лет назад, сегодня — сухая земля. Отели, построенные на берегу моря, сейчас находятся в сотнях метров от него.
Причины снижения известны. Во-первых, откачка воды из реки Иордан — главного источника воды Мёртвого моря — для нужд сельского хозяйства и питьевой воды. Израиль, Иордания и Сирия откачивают около девяноста пяти процентов стока Иордана до того, как вода достигает Мёртвого моря. Во-вторых, заводы Мёртвого моря — израильские и иорданские — испаряют огромные объёмы воды для добычи поташа и других минералов. В-третьих, изменение климата уменьшает количество осадков в регионе.
Ещё одно пугающее явление — воронки (провалы), внезапно открывающиеся в земле из-за растворения подземных слоёв соли. С девяностых годов вдоль побережья Мёртвого моря образовалось более шести тысяч воронок. Воронки поглощали дороги, парковки и даже здания. Район стал опасным, и целые пляжи закрыты для публики.
Учёные и инженеры предлагают решения. Самый масштабный проект — «Канал морей» — трубопровод, который доставит воду из Красного моря в Мёртвое, а по пути будет вырабатывать электроэнергию из опреснения. Проект, обсуждаемый уже десятилетия, потребует сотрудничества Израиля, Иордании и Палестинской автономии и обойдётся в миллиарды долларов. Другие утверждают, что решение проще — вернуть воду в реку Иордан и сократить добычу минералов. Одно несомненно: если не предпринять решительных мер, Мёртвое море — одно из чудес природы мира — может исчезнуть через несколько десятилетий.', '[{"he": "ים המלח", "ru": "Мёртвое море", "translit": "ям хамЕлах"}, {"he": "מפלס", "ru": "уровень (воды)", "translit": "мифлАс"}, {"he": "שאיבה", "ru": "откачка", "translit": "шеивА"}, {"he": "מינרלים", "ru": "минералы", "translit": "минерАлим"}, {"he": "בולענות", "ru": "воронки/провалы", "translit": "больанОт"}, {"he": "אשלג", "ru": "поташ", "translit": "ашлАг"}, {"he": "תעלת הימים", "ru": "Канал морей", "translit": "таалАт хаямИм"}, {"he": "דרסטי", "ru": "решительный", "translit": "драстИ"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (271, 4, 'ספרות ישראלית עכשווית', 'Современная израильская литература', 'הספרות הישראלית העכשווית מציגה מגוון רחב של קולות, סגנונות ונושאים. דור חדש של סופרים כותב על נושאים שונים מהדור הקודם ומביא לספרות העברית נקודות מבט שלא נשמעו קודם. אם עמוס עוז ויהודית קציר כתבו על הקיבוץ, על הקונפליקט ועל הזהות הלאומית, הסופרים הצעירים עוסקים בחיי העיר, בזהות אישית, ביחסים רומנטיים ובטכנולוגיה.
אשכול נבו, מחברו של הרומן "שלוש קומות", הוא אחד הסופרים הפופולריים ביותר. ספריו מציגים משפחות ישראליות רגילות המתמודדות עם אהבה, אובדן ותקווה. עינת יקיר כותבת על ילדות, על טראומה ועל מערכות יחסים מורכבות בפרוזה אינטימית ומרגשת. דורית רביניאן, מחברת "גדר חיה", עוררה סערה עם סיפור אהבה בין ישראלית לפלסטיני שהוצא מרשימת הקריאה של בתי ספר.
הספרות המזרחית — כתיבה של סופרים ממוצא מזרחי — תופסת מקום חשוב יותר ויותר. רונית מטלון חקרה את חוויית המהגרים מעירק, ואלמוג בהר כותב על הקהילה היהודית בבגדאד. הסופרים הערבים-ישראלים כמו סייד קשוע מציגים את החוויה הערבית בישראל מנקודת מבט אישית ומורכבת. ספרו "גוף שני יחיד" התורגם לשפות רבות.
בשנים האחרונות צומחת גם ספרות בז''אנרים שנחשבו "פחות רציניים" — מדע בדיוני, פנטזיה, ספרות ילדים ונוער, רומנים גרפיים. הגבולות בין "ספרות גבוהה" ל"ספרות פופולרית" מיטשטשים. פסטיבלים ספרותיים כמו שבוע הספר ופסטיבל הסופרים בירושלים מושכים קהל רחב, וספרים ישראליים מתורגמים ליותר ויותר שפות.
הספרות הישראלית היום — מגוונת, אישית ובינלאומית. היא לא עוד "ספרות קטנה של מדינה קטנה" אלא חלק מהשיח הספרותי העולמי, שמציעה לקוראים בכל מקום חלון לחברה מורכבת, מרתקת ומלאת סתירות.', 'Современная израильская литература представляет широкое разнообразие голосов, стилей и тем. Новое поколение писателей пишет о других темах, чем предыдущее, и привносит в ивритскую литературу ранее неслышанные точки зрения. Если Амос Оз и Иегудит Кацир писали о кибуце, конфликте и национальной идентичности, молодые писатели занимаются городской жизнью, личной идентичностью, романтическими отношениями и технологиями.
Эшколь Нево, автор романа «Три этажа», — один из самых популярных писателей. Его книги показывают обычные израильские семьи, сталкивающиеся с любовью, утратой и надеждой. Эйнат Якир пишет о детстве, травме и сложных отношениях в интимной и трогательной прозе. Дорит Рабинян, автор «Живой изгороди», вызвала бурю историей любви израильтянки и палестинца, исключённой из школьного списка для чтения.
Мизрахийская литература — творчество писателей восточного происхождения — занимает всё более важное место. Ронит Маталон исследовала опыт иммигрантов из Ирака, а Альмог Бехар пишет о еврейской общине Багдада. Арабо-израильские писатели, такие как Саид Кашуа, представляют арабский опыт в Израиле с личной и сложной точки зрения. Его роман «Второе лицо единственного числа» переведён на многие языки.
В последние годы растёт литература в жанрах, считавшихся «менее серьёзными» — научная фантастика, фэнтези, детская и подростковая литература, графические романы. Границы между «высокой» и «популярной» литературой размываются. Литературные фестивали вроде Недели книги и Фестиваля писателей в Иерусалиме привлекают широкую аудиторию, а израильские книги переводятся на всё больше языков.
Израильская литература сегодня — разнообразная, личная и международная. Это уже не «маленькая литература маленькой страны», а часть мирового литературного дискурса, предлагающая читателям повсюду окно в сложное, захватывающее и полное противоречий общество.', '[{"he": "ספרות", "ru": "литература", "translit": "сифрУт"}, {"he": "עכשווי", "ru": "современный", "translit": "ахшавИ"}, {"he": "סופרים", "ru": "писатели", "translit": "софрИм"}, {"he": "זהות", "ru": "идентичность", "translit": "зеhУт"}, {"he": "פרוזה", "ru": "проза", "translit": "прОза"}, {"he": "מהגרים", "ru": "иммигранты", "translit": "меhагрИм"}, {"he": "תורגם", "ru": "переведён", "translit": "тургАм"}, {"he": "ז''אנרים", "ru": "жанры", "translit": "жАнрим"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (272, 4, 'הערבה — חקלאות במדבר', 'Арава — сельское хозяйство в пустыне', 'הערבה, העמק המדברי הארוך שמשתרע כמאה שבעים קילומטר בין ים המלח לאילת, היא אחת הדוגמאות המרשימות ביותר לניצחון של טכנולוגיה על הטבע. באזור שבו כמות הגשם השנתית היא פחות מחמישים מילימטר, שהטמפרטורות מגיעות לחמש וארבעים מעלות בקיץ ושהקרקע מלוחה ולא פורייה, חקלאים ישראלים מגדלים יבולים שמיוצאים לאירופה ומתחרים באיכותם עם תוצרת מהמדינות המפותחות ביותר.
הסוד הוא טכנולוגיה חקלאית מתקדמת. הבסיס הוא השקיה בטפטוף — המצאה ישראלית פורצת דרך שפיתח שמחה בלאס בשנות השישים. במקום להשקות שדה שלם, טפטפות קטנות מזרימות כמויות מדויקות של מים ישירות לשורשי הצמח. השיטה חוסכת שישים עד שבעים אחוז מים בהשוואה להשקיה מסורתית.
חממות מתקדמות מאפשרות שליטה מלאה בתנאי הגידול — טמפרטורה, לחות, אור ואוורור מפוקחים על ידי מחשבים. חקלאים משתמשים במים מליחים ממקורות תת-קרקעיים, שעוברים טיפול מיוחד. אנרגיה סולארית מפעילה את המשאבות ואת מערכות האוורור. חיישנים בקרקע מודדים לחות ומזינים נתונים למערכות אוטומטיות.
חקלאי הערבה מגדלים עגבניות שרי, פלפלים צבעוניים, חציל, עשבי תיבול, תמרים מזן מג''הול ופרחים — בעיקר ורדים ועטרניות. התוצרת מיוצאת בעיקר לאירופה, שמקבלת ירקות טריים באמצע החורף כשהשדות שלה קפואים. ענף הפרחים הישראלי הוא אחד הגדולים בעולם — ישראל מייצאת פרחים לשווי של כמאה חמישים מיליון דולר בשנה.
הטכנולוגיה החקלאית הישראלית מיוצאת למדינות רבות באפריקה ובאסיה — מקומות שסובלים ממחסור במים ומקרקע לא פורייה. חברות ישראליות מלמדות חקלאים באתיופיה, בהודו ובסין את שיטות ההשקיה והגידול בחממות. המודל הישראלי מוכיח שגם במדבר אפשר להצמיח חיים — בעזרת ידע, טכנולוגיה ונחישות.', 'Арава, длинная пустынная долина, протянувшаяся на около ста семидесяти километров между Мёртвым морем и Эйлатом, — один из самых впечатляющих примеров победы технологий над природой. В регионе, где годовое количество осадков менее пятидесяти миллиметров, температура достигает сорока пяти градусов летом, а почва солёная и неплодородная, израильские фермеры выращивают урожай, экспортируемый в Европу и конкурирующий по качеству с продукцией развитых стран.
Секрет — передовые агротехнологии. Основа — капельное орошение, израильское прорывное изобретение, разработанное Симхой Бласом в шестидесятые годы. Вместо полива всего поля маленькие капельницы подают точные количества воды прямо к корням растения. Метод экономит шестьдесят-семьдесят процентов воды по сравнению с традиционным орошением.
Передовые теплицы обеспечивают полный контроль условий выращивания — температура, влажность, свет и вентиляция управляются компьютерами. Фермеры используют солёную воду из подземных источников, проходящую специальную обработку. Солнечная энергия питает насосы и вентиляционные системы. Датчики в почве измеряют влажность и передают данные автоматическим системам.
Фермеры Аравы выращивают помидоры черри, цветные перцы, баклажаны, пряные травы, финики сорта маджуль и цветы — в основном розы и герберы. Продукция экспортируется главным образом в Европу, которая получает свежие овощи посреди зимы, когда собственные поля замёрзшие. Израильская цветочная отрасль — одна из крупнейших в мире: Израиль экспортирует цветы на сумму около ста пятидесяти миллионов долларов в год.
Израильские агротехнологии экспортируются во многие страны Африки и Азии — места, страдающие от нехватки воды и неплодородной почвы. Израильские компании обучают фермеров в Эфиопии, Индии и Китае методам орошения и тепличного выращивания. Израильская модель доказывает, что даже в пустыне можно вырастить жизнь — с помощью знаний, технологий и решимости.', '[{"he": "ערבה", "ru": "Арава (долина)", "translit": "аравА"}, {"he": "חקלאות", "ru": "сельское хозяйство", "translit": "хаклаУт"}, {"he": "השקיה בטפטוף", "ru": "капельное орошение", "translit": "ашкаЯ бетифтУф"}, {"he": "חממות", "ru": "теплицы", "translit": "хамамОт"}, {"he": "תמרים", "ru": "финики", "translit": "тмарИм"}, {"he": "ייצוא", "ru": "экспорт", "translit": "йецУ"}, {"he": "חיישנים", "ru": "датчики", "translit": "хайшанИм"}, {"he": "נחישות", "ru": "решимость", "translit": "нехишУт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (273, 4, 'האתגרים של החברה הרב-תרבותית', 'Вызовы мультикультурного общества', 'ישראל היא חברה רב-תרבותית במהותה. אוכלוסייתה כוללת יהודים ממוצאים שונים — אשכנזים שהגיעו ממזרח אירופה, מזרחים מארצות ערב ומצפון אפריקה, אתיופים שעלו בשנות השמונים והתשעים, ורוסים שהגיעו בגל העלייה הגדול של שנות התשעים. לצד היהודים חיים ערבים מוסלמים ונוצרים, דרוזים, צ''רקסים ובדואים. הגיוון הזה מביא עשירות תרבותית אך גם מתחים.
במשך שנים היו פערים כלכליים ותרבותיים משמעותיים בין קבוצות שונות. יהודים ממוצא אשכנזי שלטו במוסדות המדינה, בכלכלה ובתרבות, בעוד שיהודים ממוצא מזרחי הרגישו מופלים. התנועה המזרחית של שנות השבעים — בעיקר הפנתרים השחורים הישראלים — העלתה את הנושא לסדר היום הציבורי. היום הפערים קטנו, אך לא נעלמו.
אפליה על רקע עדתי, דתי ולאומי עדיין קיימת. ערבים ישראלים מתמודדים עם אפליה בשוק העבודה ובמערכת החינוך. יהודים אתיופים נתקלים בגזענות. חרדים ונשים דתיות מתמודדים עם חסמים בהשתלבות בשוק העבודה הכללי. הממשלה מנסה לקדם שילוב דרך חינוך, שירות צבאי ואזרחי, ותוכניות תעסוקה.
אירועים תרבותיים משותפים מפגישים קהילות שונות. פסטיבל הערבסק בחיפה מציג אמנות ערבית-יהודית משותפת. לילות התרבות בערים שונות פותחים מוסדות תרבות לכל הציבור. מוזיקה מזרחית — שפעם הייתה שולית — הפכה למיינסטרים ומחברת ישראלים מכל הרקעים.
האתגר המרכזי הוא ליצור זהות ישראלית משותפת שמכבדת את הייחודיות של כל קבוצה. לא "כור היתוך" שמוחק הבדלים, אלא "סלט" צבעוני שבו כל רכיב שומר על הטעם שלו ותורם לשלם. זו אינה משימה פשוטה, אבל הגיוון של ישראל הוא גם הכוח שלה — מקור של יצירתיות, חוסן וייחודיות שאין כמותה בעולם.', 'Израиль — мультикультурное общество по сути. Его население включает евреев разного происхождения — ашкеназов из Восточной Европы, мизрахим из арабских стран и Северной Африки, эфиопов, прибывших в восьмидесятые и девяностые, и русских, приехавших в большой волне репатриации девяностых. Рядом с евреями живут арабы-мусульмане и христиане, друзы, черкесы и бедуины. Это разнообразие приносит культурное богатство, но и напряжённость.
Годами существовали значительные экономические и культурные разрывы между группами. Евреи ашкеназского происхождения доминировали в государственных институтах, экономике и культуре, тогда как евреи мизрахийского происхождения чувствовали себя дискриминированными. Мизрахийское движение семидесятых — прежде всего израильские «Чёрные пантеры» — вывело тему в публичную повестку. Сегодня разрывы сократились, но не исчезли.
Дискриминация по этническому, религиозному и национальному признаку всё ещё существует. Израильские арабы сталкиваются с дискриминацией на рынке труда и в системе образования. Евреи-эфиопы встречают расизм. Ультраортодоксы и религиозные женщины сталкиваются с барьерами интеграции на общем рынке труда. Правительство пытается продвигать интеграцию через образование, военную и гражданскую службу и программы трудоустройства.
Совместные культурные события сводят разные общины. Фестиваль «Арабеск» в Хайфе представляет совместное арабско-еврейское искусство. Ночи культуры в разных городах открывают культурные учреждения для всей публики. Мизрахийская музыка — когда-то маргинальная — стала мейнстримом и объединяет израильтян всех происхождений.
Главный вызов — создать общую израильскую идентичность, уважающую уникальность каждой группы. Не «плавильный котёл», стирающий различия, а красочный «салат», где каждый ингредиент сохраняет свой вкус и вносит вклад в целое. Это непростая задача, но разнообразие Израиля — также его сила: источник творчества, стойкости и уникальности, не имеющей аналогов в мире.', '[{"he": "רב-תרבותי", "ru": "мультикультурный", "translit": "рав-тарбутИ"}, {"he": "גיוון", "ru": "разнообразие", "translit": "гивУн"}, {"he": "אפליה", "ru": "дискриминация", "translit": "афлаЯ"}, {"he": "עדתי", "ru": "этнический", "translit": "адатИ"}, {"he": "שילוב", "ru": "интеграция", "translit": "шилУв"}, {"he": "קהילות", "ru": "общины", "translit": "кехилОт"}, {"he": "גזענות", "ru": "расизм", "translit": "газанУт"}, {"he": "חוסן", "ru": "стойкость", "translit": "хОсен"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (274, 4, 'מדע ומחקר — מוסדות מובילים', 'Наука и исследования — ведущие учреждения', 'ישראל משקיעה כחמישה אחוז מהתמ"ג במחקר ופיתוח — אחד השיעורים הגבוהים בעולם, הרבה מעל הממוצע של מדינות ה-OECD. ההשקעה הזאת מניבה תוצאות מרשימות: שנים עשר ישראלים זכו בפרס נובל, ופריצות דרך מדעיות ישראליות משנות את העולם בתחומים כמו ביוטכנולוגיה, ננו-טכנולוגיה, מדעי המוח ומתמטיקה.
שבע אוניברסיטאות מחקר פועלות בישראל, וכולן מדורגות גבוה ברשימות בינלאומיות. מכון ויצמן למדע ברחובות נחשב לאחד המוסדות המובילים בעולם במחקר בסיסי — בכימיה, בפיזיקה ובביולוגיה. הטכניון בחיפה מוביל בהנדסה ובמדעי המחשב — בוגריו ייסדו חברות שמוערכות במיליארדים. האוניברסיטה העברית בירושלים הוקמה בשנת 1925 ומובילה במדעי הרוח, ברפואה ובחקלאות.
אוניברסיטת תל אביב, הגדולה בישראל עם למעלה משלושים אלף סטודנטים, מובילה במגוון תחומים מרפואה ועד אמנויות. אוניברסיטת בן-גוריון בנגב מתמחה במחקר מדבר, באנרגיה סולארית ובמים. אוניברסיטת בר-אילן מחברת מחקר מדעי עם לימודי יהדות. אוניברסיטת חיפה בולטת במדעי הים ובלימודי חברה.
מנגנון המימון למחקר כולל קרנות ממשלתיות — בעיקר דרך הוועדה לתכנון ותקצוב של המועצה להשכלה גבוהה — מענקי מחקר בינלאומיים, ושיתופי פעולה הדוקים עם תעשיית ההייטק. הקשר בין אקדמיה לתעשייה הוא אחד היתרונות הברורים של מערכת המחקר הישראלית: חברות חולקות נתונים עם חוקרים, ומחקר אקדמי מומר לפטנטים ולמוצרים מסחריים.
אתגרי המערכת כוללים מימון לא מספיק לנוכח הגידול במספר החוקרים, ניסיונות של מוחות מבריקים לעבור לעבודה בחו"ל — "בריחת מוחות" — ופער בין מוסדות במרכז לבין אלה בפריפריה. למרות זאת, ישראל ממשיכה להוכיח שגודל אינו קובע — מדינה קטנה עם אוכלוסייה מחונכת ומוטיבציה יכולה להתחרות בענקיות העולם.', 'Израиль инвестирует около пяти процентов ВВП в исследования и разработки — один из самых высоких показателей в мире, значительно выше среднего по странам ОЭСР. Эти инвестиции приносят впечатляющие результаты: двенадцать израильтян получили Нобелевскую премию, а израильские научные прорывы меняют мир в областях биотехнологий, нанотехнологий, нейронаук и математики.
В Израиле действуют семь исследовательских университетов, все высоко котирующиеся в международных рейтингах. Институт Вейцмана в Реховоте считается одним из ведущих мировых учреждений в фундаментальных исследованиях — химии, физике и биологии. Технион в Хайфе лидирует в инженерии и компьютерных науках — его выпускники основали компании стоимостью в миллиарды. Еврейский университет в Иерусалиме основан в 1925 году и лидирует в гуманитарных науках, медицине и сельском хозяйстве.
Тель-Авивский университет, крупнейший в Израиле с более чем тридцатью тысячами студентов, лидирует в различных областях от медицины до искусств. Университет Бен-Гуриона в Негеве специализируется на пустынных исследованиях, солнечной энергии и воде. Бар-Иланский университет сочетает научные исследования с иудаикой. Хайфский университет выделяется морскими науками и социальными исследованиями.
Механизм финансирования исследований включает государственные фонды — прежде всего через Комитет по планированию и бюджетированию Совета по высшему образованию — международные исследовательские гранты и тесное сотрудничество с хайтек-индустрией. Связь между академией и промышленностью — одно из явных преимуществ израильской исследовательской системы: компании делятся данными с исследователями, а академические исследования превращаются в патенты и коммерческие продукты.
Вызовы системы включают недостаточное финансирование при росте числа исследователей, попытки талантливых умов уехать работать за рубеж — «утечка мозгов» — и разрыв между учреждениями в центре и на периферии. Несмотря на это, Израиль продолжает доказывать, что размер не определяющий фактор — маленькая страна с образованным и мотивированным населением может конкурировать с мировыми гигантами.', '[{"he": "מחקר ופיתוח", "ru": "исследования и разработки", "translit": "мехкАр уфитУах"}, {"he": "פריצת דרך", "ru": "прорыв", "translit": "прицАт дЕрех"}, {"he": "ביוטכנולוגיה", "ru": "биотехнология", "translit": "биотехнолОгия"}, {"he": "מענקים", "ru": "гранты", "translit": "маанакИм"}, {"he": "תעשייה", "ru": "промышленность", "translit": "таасийА"}, {"he": "בריחת מוחות", "ru": "утечка мозгов", "translit": "брихАт мохОт"}, {"he": "פטנטים", "ru": "патенты", "translit": "патЕнтим"}, {"he": "מנגנון", "ru": "механизм", "translit": "манганОн"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (297, 5, 'מערכת החינוך הישראלית — ארבעה זרמים', 'Система образования Израиля — четыре потока', 'מערכת החינוך בישראל מחולקת לארבעה זרמים עיקריים: ממלכתי, ממלכתי-דתי, חרדי וערבי. חלוקה זו, שנקבעה בחוק חינוך ממלכתי (1953), משקפת את הפיצול העמוק של החברה הישראלית — ולמעשה, ילד ישראלי גדל בסביבה חינוכית שנקבעת על פי מוצאו הדתי והאתני, ולא על פי בחירתו.
החינוך הממלכתי הוא הזרם החילוני, ובו לומדים רוב התלמידים היהודים — כ-40% מכלל התלמידים. תוכנית הלימודים כוללת מקצועות כלליים: מתמטיקה, מדעים, אנגלית, עברית, היסטוריה ותנ"ך. החינוך הממלכתי-דתי משלב לימודי קודש — גמרא, הלכה, מחשבת ישראל — עם תוכנית לימודים כללית מלאה. תלמידי הזרם הדתי-לאומי מגיעים להישגים דומים למגזר החילוני במקצועות כלליים, ורבים מהם משרתים בצבא.
מערכת החינוך החרדית היא האתגר הגדול ביותר. בתי ספר חרדיים — ''חדרים'' לבנים ובתי ''יעקב'' לבנות — זוכים לאוטונומיה נרחבת ומתמקדים בלימודי תורה. במערכת הבנים, לימודי ליבה כמו מתמטיקה ואנגלית מקבלים משקל מועט או אינם נלמדים כלל. מצב זה מעורר ביקורת חריפה: ללא השכלה בסיסית, בוגרים חרדיים מתקשים להשתלב בשוק העבודה, מה שמוביל לשיעורי עוני גבוהים במגזר. רפורמות שניסו להכניס לימודי ליבה נתקלו בהתנגדות פוליטית ודתית.
החינוך הערבי מתמודד עם פערי תקצוב ותשתיות. מחקרים מראים שההוצאה לתלמיד ערבי נמוכה מזו של תלמיד יהודי, ושמבנים וציוד בבתי ספר ערביים נחותים. תוצאות מבחני PISA (הבינלאומיים) מראות פערים משמעותיים בין הזרמים: תלמידים חרדים וערבים מפגרים אחרי ממלכתי וממלכתי-דתי.
הוויכוח על ''חינוך משותף'' — האם לחנך יהודים וערבים יחד — נותר סוגיה פתוחה. בתי ספר דו-לשוניים כמו ''יד ביד'' מוכיחים שזה אפשרי, אך נותרים החריג ולא הכלל. מערכת החינוך המפוצלת היא מראה של חברה מפולגת — ויש הטוענים שהיא גם מנציחה את הפילוג.', 'Система образования Израиля делится на четыре потока: государственный, государственно-религиозный, ультраортодоксальный и арабский. Это разделение отражает глубокий раскол общества — ребёнок растёт в образовательной среде, определяемой его религиозным и этническим происхождением.
Государственное образование — светское, с полной общей программой. Государственно-религиозное сочетает религиозные и общие предметы. Ультраортодоксальная система — главный вызов: мальчики почти не изучают базовые предметы, что затрудняет интеграцию в рынок труда.
Арабское образование сталкивается с разрывами в финансировании и инфраструктуре. Тесты PISA показывают значительные разрывы между потоками. Дискуссия о совместном обучении евреев и арабов остаётся открытой. Двуязычные школы вроде «Яд бе-Яд» доказывают, что это возможно, но остаются исключением. Разделённая система — зеркало разделённого общества.', '[{"he": "זרמים", "ru": "потоки", "translit": "зрамИм"}, {"he": "ממלכתי", "ru": "государственный", "translit": "мамлахтИ"}, {"he": "חרדי", "ru": "ультраортодоксальный", "translit": "харедИ"}, {"he": "אוטונומיה", "ru": "автономия", "translit": "отонОмия"}, {"he": "לימודי ליבה", "ru": "базовые предметы", "translit": "лимудЕй либА"}, {"he": "מפולגת", "ru": "разделённая", "translit": "мефулЕгет"}, {"he": "דו-לשוני", "ru": "двуязычный", "translit": "ду-лешонИ"}, {"he": "תקצוב", "ru": "финансирование", "translit": "такцУв"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (275, 4, 'אתגר המים בישראל', 'Водный вызов Израиля', 'ישראל היא אחת המדינות היבשות בעולם — כשישים אחוז משטחה הוא מדבר, והגשם יורד רק בחורף. ובכל זאת, ישראל מצליחה לא רק להתמודד עם מחסור במים אלא גם לייצא מים. ההצלחה הזאת מבוססת על שלושה עמודי תווך: התפלה, מיחזור וחיסכון.
היום, כשמונים אחוז ממי השתייה בישראל מגיעים ממתקני התפלה לאורך חוף הים התיכון. חמישה מתקני התפלה גדולים — בחדרה, בפלמחים, באשדוד, בשורק ובאשקלון — מייצרים כשש מאות מיליון מטר מעוקב של מים מתוקים בשנה. התהליך פשוט בעיקרון: מים מלוחים מהים עוברים דרך ממברנות שמסננות את המלח. העלות ירדה דרמטית בעשרים השנים האחרונות.
מיחזור שפכים הוא ההישג השני. ישראל ממחזרת כתשעים אחוז מהשפכים שלה — שיא עולמי מוחלט. ספרד, במקום השני, ממחזרת רק כעשרים אחוז. המים המטופלים משמשים בעיקר לחקלאות — מה שמשחרר את המים המתוקים לצריכה ביתית. מאות מתקני טיהור שפכים פזורים ברחבי הארץ.
העמוד השלישי הוא חיסכון וניהול חכם. טכנולוגיית ההשקיה בטפטוף, שהמציא שמחה בלאס בשנות השישים, חוללה מהפכה בחקלאות ברחבי העולם. היום, חיישנים דיגיטליים, מערכות בקרה ממוחשבות ובינה מלאכותית מנהלים את רשת המים הארצית ומזהים דליפות תוך דקות.
ישראל מייצאת את הידע הזה למדינות רבות. חברות ישראליות בונות מתקני התפלה בקליפורניה, באוסטרליה ובמדינות ערב. מומחי מים ישראליים מייעצים לממשלות באפריקה ובאסיה. הטכנולוגיה הישראלית מציעה פתרון לאחד האתגרים הגדולים של המאה העשרים ואחת — מחסור במים שצפוי להשפיע על מיליארדי אנשים בעולם.
עם זאת, גם בישראל יש בעיות. הכנרת — מאגר המים ההיסטורי — ירד למפלסים מסוכנים פעמים רבות. נחלים רבים מזוהמים ממפעלים ומשפכים. ושינויי האקלים צפויים להפחית את כמות הגשם עוד יותר. מהפכת המים הישראלית מרשימה, אבל המלחמה על כל טיפה עדיין לא נגמרה.', 'Израиль — одна из самых засушливых стран мира: около шестидесяти процентов его территории — пустыня, а дождь идёт только зимой. И тем не менее Израиль не только справляется с нехваткой воды, но и экспортирует её. Этот успех основан на трёх столпах: опреснение, переработка и экономия.
Сегодня около восьмидесяти процентов питьевой воды в Израиле поступает с опреснительных установок вдоль средиземноморского побережья. Пять крупных опреснительных заводов — в Хадере, Пальмахим, Ашдоде, Сореке и Ашкелоне — производят около шестисот миллионов кубометров пресной воды в год. Процесс прост в принципе: солёная морская вода проходит через мембраны, фильтрующие соль. Стоимость резко снизилась за последние двадцать лет.
Переработка сточных вод — второе достижение. Израиль перерабатывает около девяноста процентов сточных вод — абсолютный мировой рекорд. Испания, на втором месте, перерабатывает лишь около двадцати процентов. Очищенная вода используется в основном для сельского хозяйства, что освобождает пресную воду для бытового потребления. Сотни очистных сооружений расположены по всей стране.
Третий столп — экономия и умное управление. Технология капельного орошения, изобретённая Симхой Бласом в шестидесятые годы, произвела революцию в сельском хозяйстве по всему миру. Сегодня цифровые датчики, компьютеризированные системы управления и ИИ управляют национальной водной сетью и обнаруживают утечки за минуты.
Израиль экспортирует эти знания во многие страны. Израильские компании строят опреснительные установки в Калифорнии, Австралии и арабских странах. Израильские эксперты по воде консультируют правительства в Африке и Азии. Израильские технологии предлагают решение одного из величайших вызовов двадцать первого века — нехватки воды, которая может затронуть миллиарды людей.
Тем не менее и в Израиле есть проблемы. Кинерет — исторический водный резервуар — неоднократно опускался до опасных уровней. Многие ручьи загрязнены заводами и стоками. А изменение климата, как ожидается, ещё больше сократит количество осадков. Израильская водная революция впечатляет, но борьба за каждую каплю ещё не окончена.', '[{"he": "התפלה", "ru": "опреснение", "translit": "хатпалА"}, {"he": "מיחזור", "ru": "переработка", "translit": "михзУр"}, {"he": "שפכים", "ru": "сточные воды", "translit": "шфахИм"}, {"he": "השקיה", "ru": "орошение", "translit": "ашкаЯ"}, {"he": "טפטוף", "ru": "капельный", "translit": "тифтУф"}, {"he": "ממברנות", "ru": "мембраны", "translit": "мембрАнот"}, {"he": "דליפות", "ru": "утечки", "translit": "длифОт"}, {"he": "מהפכה", "ru": "революция", "translit": "маhапехА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (276, 4, 'הקולנוע הישראלי', 'Израильское кино', 'הקולנוע הישראלי חווה תנופה יוצאת דופן בשני העשורים האחרונים. סרטים ישראליים מוצגים בפסטיבלים הבינלאומיים החשובים ביותר — קאן, ברלין, ונציה וטורונטו — ומשיגים הצלחה ביקורתית ומסחרית. הקולנוע הישראלי הפך ממותג מקומי לתופעה עולמית.
"ואלס עם באשיר" של ארי פולמן, סרט אנימציה תיעודי על מלחמת לבנון הראשונה, היה מועמד לאוסקר בשנת 2009. "הערת שוליים" של יוסף סידר זכה בפרס בקאן ב-2011. "לימונים" של ערן ריקליס סיפר את הקונפליקט דרך עיני אישה פלסטינית. "עג''מי" של סקאנדר קופטי ויארון שני צולם עם שחקנים לא מקצועיים מיפו והיה מועמד לאוסקר.
הנושאים המרכזיים בקולנוע הישראלי עדיין כוללים את הקונפליקט, חיי הצבא, יחסי משפחה ושאלות של זהות ושייכות. אולם בשנים האחרונות עולות יצירות שעוסקות גם בנושאים אוניברסליים — אהבה, בדידות, הזדקנות, מגדר ומיניות. סרטים כמו "הבועה" של איתן פוקס ו"חוץ מאלוהים" חקרו נושאים שנחשבו טאבו בקולנוע הישראלי הקלאסי.
אולם הפריצה הגדולה ביותר היא בתחום הטלוויזיה. סדרות ישראליות כמו "פאודה", "שטיסל", "בני אור, בני חושך" ו"טהרן" הפכו להצלחה בינלאומית אדירה. "פאודה" נצפתה ביותר ממאה שבעים מדינות. "שטיסל" הפכה לסדרה המוכרת ביותר על עולם החרדי בכל הזמנים. הצלחת הסדרות פתחה דלת רחבה לייצוא תוכן ישראלי לפלטפורמות סטרימינג — נטפליקס, אפל טי-וי והבו.
קרן הקולנוע הישראלית, שתומכת ביצירה ישראלית עצמאית, ממלאת תפקיד מרכזי. היא מממנת כשלושים סרטים בשנה ותומכת בבמאים צעירים. בתי ספר לקולנוע — כמו סם שפיגל בירושלים ותל-חי — מכשירים את הדור הבא. הקולנוע הישראלי מוכיח שיצירתיות, אותנטיות וסיפורים מקוריים יכולים לנצח גם בלי תקציבי ענק של הוליווד.', 'Израильское кино переживает небывалый подъём в последние два десятилетия. Израильские фильмы показывают на важнейших международных фестивалях — Канны, Берлин, Венеция и Торонто — и добиваются критического и коммерческого успеха. Израильское кино превратилось из местного бренда в мировое явление.
«Вальс с Баширом» Ари Фольмана, анимационный документальный фильм о Первой ливанской войне, был номинирован на Оскар в 2009 году. «Сноска» Йосефа Сидара получила приз в Каннах в 2011. «Лимоны» Эрана Риклиса рассказали о конфликте глазами палестинской женщины. «Аджами» Скандара Копти и Ярона Шани, снятый с непрофессиональными актёрами из Яффы, был номинирован на Оскар.
Центральные темы израильского кино по-прежнему включают конфликт, армейскую жизнь, семейные отношения и вопросы идентичности и принадлежности. Однако в последние годы появляются произведения на универсальные темы — любовь, одиночество, старение, гендер и сексуальность. Фильмы вроде «Пузыря» Эйтана Фокса и «Не считая Бога» исследовали темы, считавшиеся табу в классическом израильском кино.
Однако главный прорыв — в телевидении. Израильские сериалы вроде «Фауда», «Штисель», «Дети света, дети тьмы» и «Тегеран» стали огромным международным успехом. «Фауда» просматривалась более чем в ста семидесяти странах. «Штисель» стал самым известным сериалом об ультраортодоксальном мире в истории. Успех сериалов широко открыл дверь для экспорта израильского контента на стриминговые платформы — Netflix, Apple TV и HBO.
Израильский кинофонд, поддерживающий независимое израильское кино, играет ключевую роль. Он финансирует около тридцати фильмов в год и поддерживает молодых режиссёров. Киношколы — как Сам Шпигель в Иерусалиме и Тель-Хай — готовят следующее поколение. Израильское кино доказывает, что творчество, аутентичность и оригинальные истории могут побеждать и без голливудских бюджетов.', '[{"he": "קולנוע", "ru": "кино", "translit": "кольнОа"}, {"he": "במאים", "ru": "режиссёры", "translit": "бамаИм"}, {"he": "פסטיבלים", "ru": "фестивали", "translit": "фестивалИм"}, {"he": "מועמד", "ru": "номинант", "translit": "муамАд"}, {"he": "ייצוא", "ru": "экспорт", "translit": "йецУ"}, {"he": "תוכן", "ru": "контент", "translit": "тОхен"}, {"he": "סדרות", "ru": "сериалы", "translit": "сидрОт"}, {"he": "אותנטיות", "ru": "аутентичность", "translit": "отентиЮт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (277, 4, 'אנרגיה ירוקה בישראל', 'Зелёная энергия в Израиле', 'ישראל מתחילה לעבור לאנרגיה מתחדשת, אם כי לאט יותר ממדינות אירופיות רבות. כיום, כשנים עשר אחוז מייצור החשמל בישראל מגיע ממקורות מתחדשים — בעיקר אנרגיה סולארית. המטרה הממשלתית היא להגיע לשלושים אחוז עד שנת 2030, אך מומחים חוששים שהקצב הנוכחי לא מספיק.
הנגב, עם כשלוש מאות ימי שמש בשנה וכמויות ענקיות של שטח פנוי, הוא מקום אידיאלי לאנרגיה סולארית. שדות סולאריים ענקיים כבר נבנו ליד אשלים, דימונה ובאר שבע. תחנת הכוח הסולארית באשלים היא אחת הגדולות בעולם — מגדל שמש גבוה של מאה ארבעים מטרים מוקף באלפי מראות שמרכזות את אור השמש.
אולם סולאר הוא לא הפתרון היחיד. פרויקטים של אנרגיית רוח פועלים ברמת הגולן ובגליל. יש תוכניות לפיתוח אנרגיית גלים בים התיכון — ניצול תנועת הגלים לייצור חשמל. ומחקרים באוניברסיטאות ישראליות עוסקים באנרגיה הידרוגנית ובאגירת אנרגיה בסוללות מתקדמות.
הגז הטבעי, שהתגלה בכמויות עצומות מול חופי ישראל — בעיקר בשדות "לוויתן" ו"תמר" — הפחית את התלות בפחם ושיפר את איכות האוויר. אולם גז הוא עדיין דלק פוסילי שפולט פחמן דו-חמצני. ארגוני סביבה מתנגדים להמשך הסתמכות על גז וטוענים שישראל צריכה לעבור ישירות לאנרגיה נקייה.
האתגר המרכזי הוא אגירת אנרגיה. שמש יש רק ביום, אבל חשמל צריך גם בלילה. סוללות ענק שמאחסנות אנרגיה סולארית הן חלק מהפתרון, אבל הטכנולוגיה עדיין יקרה. ישראל, עם יכולות החדשנות שלה, יכולה להוביל בתחום הזה. השאלה היא האם הרצון הפוליטי יהיה מספיק חזק כדי לעשות את המעבר בזמן — לפני שהמשבר האקלימי יהפוך לבלתי הפיך.', 'Израиль начинает переходить на возобновляемую энергию, хотя медленнее многих европейских стран. Сейчас около двенадцати процентов производства электроэнергии поступает из возобновляемых источников — в основном солнечной энергии. Правительственная цель — достичь тридцати процентов к 2030 году, но эксперты опасаются, что нынешние темпы недостаточны.
Негев, с примерно тремястами солнечными днями в году и огромными площадями свободной территории, идеальное место для солнечной энергетики. Гигантские солнечные поля уже построены возле Ашалим, Димоны и Беэр-Шевы. Солнечная электростанция в Ашалим — одна из крупнейших в мире: солнечная башня высотой сто сорок метров окружена тысячами зеркал, концентрирующих солнечный свет.
Однако солнечная энергия — не единственное решение. Проекты ветровой энергии работают на Голанских высотах и в Галилее. Есть планы развития волновой энергии в Средиземном море — использование движения волн для производства электричества. Исследования в израильских университетах посвящены водородной энергии и хранению энергии в передовых батареях.
Природный газ, обнаруженный в огромных количествах у берегов Израиля — прежде всего на месторождениях «Левиафан» и «Тамар» — снизил зависимость от угля и улучшил качество воздуха. Однако газ — по-прежнему ископаемое топливо, выделяющее углекислый газ. Экологические организации выступают против продолжения опоры на газ и утверждают, что Израиль должен перейти напрямую к чистой энергии.
Главный вызов — хранение энергии. Солнце есть только днём, но электричество нужно и ночью. Гигантские батареи, накапливающие солнечную энергию, — часть решения, но технология пока дорогая. Израиль с его инновационными возможностями может стать лидером в этой области. Вопрос — будет ли политическая воля достаточно сильной, чтобы совершить переход вовремя, до того как климатический кризис станет необратимым.', '[{"he": "אנרגיה מתחדשת", "ru": "возобновляемая энергия", "translit": "энЕргия митхадЕшет"}, {"he": "סולארי", "ru": "солнечный", "translit": "солАри"}, {"he": "גז טבעי", "ru": "природный газ", "translit": "газ тивъИ"}, {"he": "פחם", "ru": "уголь", "translit": "пехАм"}, {"he": "דלק פוסילי", "ru": "ископаемое топливо", "translit": "дЕлек фосИли"}, {"he": "אגירת אנרגיה", "ru": "хранение энергии", "translit": "агирАт энЕргия"}, {"he": "ייצור חשמל", "ru": "производство электроэнергии", "translit": "йецУр хашмАль"}, {"he": "בלתי הפיך", "ru": "необратимый", "translit": "бильтИ хафИх"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (278, 4, 'הרכבת הקלה בירושלים', 'Лёгкий трамвай в Иерусалиме', 'הרכבת הקלה בירושלים החלה לפעול בשנת 2011, אחרי עשור של עבודות בנייה ועיכובים שהפכו את הפרויקט לאחד השנויים ביותר במחלוקת בתולדות התחבורה הישראלית. הקו הראשון, הקו האדום, חוצה את העיר ממזרח למערב לאורך ארבעה עשר קילומטרים ועשרים ושלוש תחנות, ומחבר שכונות שלא היו מחוברות קודם.
המסלול עובר דרך חלק מהנקודות המרכזיות ביותר של ירושלים: מהר הרצל דרך שוק מחנה יהודה, רחוב יפו ושער שכם, לשכונות שועפאט ופסגת זאב במזרח העיר. הרכבת עוברת דרך שכונות ערביות ויהודיות כאחד, ויוצרת מרחב משותף שבו יושבים זה לצד זה תושבים שבדרך כלל לא נפגשים.
מבחינה תחבורתית, הרכבת שינתה את ירושלים. היא הפחיתה את העומס ברחובות המרכזיים, קיצרה זמני נסיעה והציעה אלטרנטיבה נוחה לנסיעה ברכב פרטי. כמאה שלושים אלף נוסעים משתמשים ברכבת כל יום. אבל תקופת הבנייה הארוכה — כמעט עשר שנים — פגעה קשות בעסקים לאורך המסלול. חנויות ומסעדות ברחוב יפו נסגרו בגלל שלא יכלו לשרוד שנים של חפירות.
כיום נבנים קווים נוספים. הקו הירוק, שאמור להתחיל לפעול בשנים הקרובות, יחבר בין גילה בדרום לרמות באזור הצפוני. הקו הכחול יחבר בין תלפיות לגבעת שאול. ההערכה היא שכשכל הקווים יהיו מוכנים, הרכבת הקלה תשרת כמעט את כל אזורי העיר.
הפרויקט הוא גם סמל פוליטי. הרכבת חוצה את הקו הירוק ומחברת שכונות ישראליות מעבר לקו הירוק לעיר. לפלסטינים זה סמל של כיבוש; לישראלים זה חיבור טבעי של חלקי העיר. הרכבת הקלה היא דוגמה מושלמת לכך שבירושלים, גם תחבורה ציבורית היא נושא פוליטי. ובכל זאת, בקרון הרכבת עצמה, ערבים ויהודים יושבים זה לצד זה בדרך לעבודה — ואולי זו בדיוק הנקודה.', 'Лёгкий трамвай в Иерусалиме начал работать в 2011 году, после десятилетия строительных работ и задержек, превративших проект в один из самых спорных в истории израильского транспорта. Первая линия, Красная, пересекает город с востока на запад на протяжении четырнадцати километров и двадцати трёх станций, соединяя районы, которые раньше не были связаны.
Маршрут проходит через некоторые из центральных точек Иерусалима: от горы Герцля через рынок Махане Иегуда, улицу Яффо и Шхемские ворота к районам Шуафат и Писгат Зеэв на востоке города. Трамвай проходит через арабские и еврейские районы, создавая общее пространство, где сидят рядом жители, обычно не встречающиеся.
С транспортной точки зрения трамвай изменил Иерусалим. Он уменьшил нагрузку на центральных улицах, сократил время в пути и предложил удобную альтернативу личному автомобилю. Около ста тридцати тысяч пассажиров пользуются трамваем ежедневно. Но длительный период строительства — почти десять лет — тяжело ударил по бизнесам вдоль маршрута. Магазины и рестораны на улице Яффо закрылись, не выдержав лет раскопок.
Сейчас строятся дополнительные линии. Зелёная линия, которая должна заработать в ближайшие годы, соединит Гило на юге с Рамот в северной части. Синяя линия соединит Тальпийот с Гиват Шауль. Ожидается, что когда все линии будут готовы, трамвай будет обслуживать почти все районы города.
Проект также политический символ. Трамвай пересекает Зелёную линию и соединяет израильские районы за Зелёной линией с городом. Для палестинцев это символ оккупации; для израильтян — естественное соединение частей города. Лёгкий трамвай — идеальный пример того, что в Иерусалиме даже общественный транспорт — политическая тема. И всё же в самом вагоне арабы и евреи сидят рядом по дороге на работу — и, возможно, в этом и есть суть.', '[{"he": "רכבת קלה", "ru": "лёгкий трамвай", "translit": "ракЕвет калА"}, {"he": "חוצה", "ru": "пересекает", "translit": "хоцЕ"}, {"he": "מסלול", "ru": "маршрут", "translit": "маслУль"}, {"he": "עומס", "ru": "нагрузка", "translit": "Омес"}, {"he": "תושבים", "ru": "жители", "translit": "тошавИм"}, {"he": "עיכובים", "ru": "задержки", "translit": "икувИм"}, {"he": "הקו הירוק", "ru": "Зелёная линия", "translit": "хакАв хаярОк"}, {"he": "מרחב", "ru": "пространство", "translit": "мерхАв"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (279, 4, 'תזונה ובריאות — מיתוסים ועובדות', 'Питание и здоровье — мифы и факты', 'בתחום התזונה יש הרבה מיתוסים — אמונות שנשמעות הגיוניות אבל אינן מבוססות על מדע מוצק. בעידן שבו כולם מומחי תזונה ברשתות החברתיות, חשוב להבדיל בין מה שמוכח מדעית לבין מה שהוא טרנד חולף.
מיתוס ראשון: "פחמימות גורמות להשמנה." לא נכון. עודף קלוריות גורם להשמנה, לא מקור הקלוריות. לחם, אורז ופסטה אינם "שמנים" בעצמם — הכמות שאנחנו אוכלים היא מה שקובע. דיאטות דלות פחמימות יכולות לעזור בטווח הקצר, אבל מחקרים ארוכי טווח מראים שאין הבדל משמעותי בינן לבין דיאטות מאוזנות.
מיתוס שני: "מזונות אורגניים בריאים יותר." המחקרים לא מוצאים הבדל תזונתי משמעותי בין מוצר אורגני ללא-אורגני — אותו כמות ויטמינים ומינרלים. היתרון של אורגני הוא פחות חומרי הדברה, מה שטוב לסביבה ואולי לבריאות לטווח ארוך, אבל זה לא הופך תפוח אורגני ל"בריא יותר" מבחינה תזונתית.
מיתוס שלישי: "צריך לשתות שמונה כוסות מים ביום." אין לכך בסיס מדעי מוצק. צורכי המים משתנים מאוד לפי אדם, אקלים, פעילות גופנית ותזונה. הכלל הפשוט ביותר: שתו כשאתם צמאים. צבע השתן הוא אינדיקטור טוב — צהוב בהיר אומר שאתם מספיק מתוזלים.
מיתוס רביעי: "גלוטן מזיק לכולם." גלוטן מזיק רק לאנשים עם צליאק — כאחוז אחד מהאוכלוסייה — או עם רגישות מאומתת לגלוטן. לשאר האוכלוסייה, אין סיבה מדעית להימנע מגלוטן, ומוצרים "ללא גלוטן" הם לפעמים פחות בריאים כי מכילים יותר סוכר ושומן כדי לפצות על הטעם.
מה כן ידוע בוודאות? תזונה מאוזנת עם ירקות, פירות, חלבונים, שומנים בריאים ודגנים מלאים היא הבסיס לבריאות. אין "סופרפוד" אחד שמרפא הכל, ואין מזון אחד שהורס את הבריאות. חשוב להקשיב לגוף ולא לטרנדים. וכמובן, פעילות גופנית סדירה — שלושים דקות ביום — חשובה לא פחות מתזונה נכונה, ואולי אפילו יותר.', 'В сфере питания много мифов — убеждений, которые звучат логично, но не основаны на твёрдой науке. В эпоху, когда все эксперты по питанию в соцсетях, важно отличать научно доказанное от проходящего тренда.
Миф первый: «Углеводы вызывают ожирение.» Неправда. Ожирение вызывает избыток калорий, а не их источник. Хлеб, рис и паста сами по себе не «жирные» — количество, которое мы едим, имеет значение. Низкоуглеводные диеты могут помочь краткосрочно, но долгосрочные исследования показывают, что нет значительной разницы между ними и сбалансированными диетами.
Миф второй: «Органические продукты полезнее.» Исследования не находят значительной пищевой разницы между органическим и неорганическим продуктом — одинаковое количество витаминов и минералов. Преимущество органики — меньше пестицидов, что хорошо для окружающей среды и, возможно, для здоровья в долгосрочной перспективе, но это не делает органическое яблоко «полезнее» с точки зрения питательной ценности.
Миф третий: «Нужно пить восемь стаканов воды в день.» Для этого нет твёрдой научной основы. Потребность в воде сильно зависит от человека, климата, физической активности и питания. Простейшее правило: пейте, когда хотите пить. Цвет мочи — хороший индикатор: светло-жёлтый означает достаточную гидратацию.
Миф четвёртый: «Глютен вреден для всех.» Глютен вреден только людям с целиакией — около одного процента населения — или с подтверждённой чувствительностью к глютену. Для остального населения нет научных оснований избегать глютена, а безглютеновые продукты иногда менее полезны, потому что содержат больше сахара и жира для компенсации вкуса.
Что точно известно? Сбалансированное питание с овощами, фруктами, белками, полезными жирами и цельными злаками — основа здоровья. Нет одного «суперфуда», который всё лечит, и нет одного продукта, который разрушает здоровье. Важно слушать тело, а не тренды. И конечно, регулярная физическая активность — тридцать минут в день — не менее важна, чем правильное питание, а может, и более.', '[{"he": "תזונה", "ru": "питание", "translit": "тзунА"}, {"he": "פחמימות", "ru": "углеводы", "translit": "пахмимОт"}, {"he": "השמנה", "ru": "ожирение", "translit": "хашманА"}, {"he": "אורגני", "ru": "органический", "translit": "оргАни"}, {"he": "קלוריות", "ru": "калории", "translit": "калорийОт"}, {"he": "מאוזנת", "ru": "сбалансированная", "translit": "меузЕнет"}, {"he": "גלוטן", "ru": "глютен", "translit": "глЮтен"}, {"he": "מיתוסים", "ru": "мифы", "translit": "митОсим"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (280, 4, 'הצבא והחברה בישראל', 'Армия и общество в Израиле', 'צה"ל — צבא ההגנה לישראל — הוא צבא חובה, ומקומו בחברה הישראלית חורג הרבה מעבר לתפקיד הביטחוני. כמעט כל צעיר ישראלי יהודי משרת: בנים שלוש שנים, בנות שנתיים. השירות מתחיל בגיל שמונה עשרה, מיד אחרי התיכון, ומהווה חוויה מעצבת שמשפיעה על כל תחום בחיים.
הצבא נתפס בישראל לא רק כמוסד ביטחוני אלא גם כ"כור היתוך" — מקום שבו נפגשים צעירים מרקעים שונים: דתיים וחילונים, אשכנזים ומזרחים, עירוניים ופריפריאליים. בצבא, בן של רופא משרון מתגורר באוהל עם בן של נגר מדימונה. ההנחה היא שהשירות המשותף יוצר חברות, אחריות הדדית ותחושת שייכות לאומית.
בצבא רבים רוכשים מיומנויות מקצועיות שמשרתות אותם בחיים האזרחיים. יחידות טכנולוגיות כמו 8200, מצ"ב ולהב מכשירות מתכנתים, מנתחי מידע ומומחי סייבר שהופכים ליזמי הייטק אחרי השחרור. יחידות רפואיות מכשירות חובשים ואחיות. יחידות לוגיסטיות מלמדות ניהול שרשרת אספקה.
עם זאת, השירות הצבאי מעורר דיון ציבורי סוער. חרדים — הקהילה האולטרא-אורתודוקסית — פטורים מטעמי לימוד תורה, אם כי חלקם מתגייסים לנח"ל חרדי או לשירות אזרחי. אזרחים ערבים פטורים מחובת שירות, אם כי דרוזים וחלק מהבדואים משרתים. הפטור יוצר מתח חברתי עמוק — רבים טוענים שכולם צריכים לשאת בנטל השווה.
יש גם ביקורת על ההשפעה של הצבא על החברה. ארגוני שמאל טוענים שהמיליטריזם חודר יותר מדי לתרבות הישראלית — שילדים גדלים עם נשק, שגיבורים הם תמיד חיילים, ושהחברה מעריכה כוח על פני דיאלוג. מנגד, רבים מאמינים שבמציאות הביטחונית של ישראל, צבא חזק הוא תנאי הכרחי לקיום המדינה.
הצבא משפיע על כל תחום בחיים הישראליים — מהתרבות ומהשפה ועד הכלכלה והפוליטיקה. ביטויים צבאיים כמו "יאללה", "סבבה" ו"חפיף" הפכו לחלק מהעברית היומיומית. ראשי ממשלה רבים היו גנרלים לשעבר. והשאלה "איפה שירתת?" היא עדיין אחת השאלות הראשונות שישראלים שואלים כשנפגשים.', 'ЦАХАЛ — Армия обороны Израиля — это армия по призыву, и её место в израильском обществе выходит далеко за рамки оборонной функции. Почти каждый молодой еврейский израильтянин служит: юноши три года, девушки два. Служба начинается в восемнадцать лет, сразу после школы, и является формирующим опытом, влияющим на все сферы жизни.
Армия воспринимается в Израиле не только как институт безопасности, но и как «плавильный котёл» — место, где встречаются молодые люди из разных слоёв: религиозные и светские, ашкеназы и мизрахим, городские и периферийные. В армии сын врача из Шарона живёт в палатке с сыном плотника из Димоны. Предполагается, что совместная служба создаёт дружбу, взаимную ответственность и чувство национальной принадлежности.
В армии многие приобретают профессиональные навыки, служащие им в гражданской жизни. Технологические подразделения вроде 8200, МАЦАВ и «Лаhав» готовят программистов, аналитиков данных и экспертов по кибербезопасности, которые после демобилизации становятся хайтек-предпринимателями. Медицинские подразделения готовят фельдшеров и медсестёр. Логистические подразделения обучают управлению цепочками поставок.
Тем не менее военная служба вызывает бурную общественную дискуссию. Харедим — ультраортодоксальная община — освобождены по причине изучения Торы, хотя часть из них призывается в харедимный НАХАЛЬ или на гражданскую службу. Арабские граждане освобождены от обязательной службы, хотя друзы и часть бедуинов служат. Освобождение создаёт глубокую социальную напряжённость — многие утверждают, что все должны нести равное бремя.
Есть и критика влияния армии на общество. Левые организации утверждают, что милитаризм слишком глубоко проникает в израильскую культуру — дети растут с оружием, герои всегда солдаты, общество ценит силу выше диалога. С другой стороны, многие считают, что в условиях безопасности Израиля сильная армия — необходимое условие существования государства.
Армия влияет на все сферы израильской жизни — от культуры и языка до экономики и политики. Военные выражения вроде «яла», «сабаба» и «хафиф» стали частью повседневного иврита. Многие премьер-министры были бывшими генералами. А вопрос «Где ты служил?» по-прежнему один из первых, которые израильтяне задают при знакомстве.', '[{"he": "צבא חובה", "ru": "армия по призыву", "translit": "цавА ховА"}, {"he": "כור היתוך", "ru": "плавильный котёл", "translit": "кур хаитУх"}, {"he": "מיומנויות", "ru": "навыки", "translit": "меюманЮйот"}, {"he": "חרדים", "ru": "ультраортодоксы", "translit": "харедИм"}, {"he": "גיבוש", "ru": "сплочение", "translit": "гибУш"}, {"he": "מיליטריזם", "ru": "милитаризм", "translit": "милитарИзм"}, {"he": "התנדבות", "ru": "добровольчество", "translit": "хитнадвУт"}, {"he": "נטל", "ru": "бремя", "translit": "нЕтель"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (281, 5, 'חידוש השפה העברית', 'Возрождение иврита', 'תחיית השפה העברית היא אחד ההישגים הייחודיים ביותר בהיסטוריה הלשונית של האנושות. במשך כאלפיים שנה שימשה העברית כשפת קודש ולמדנות בלבד — לתפילה, ללימוד תורה, לכתיבת פיוטים ולהתכתבות בין חכמים. היא לא הייתה שפת אם של אף קהילה, ואף ילד לא גדל כשהוא שומע אותה בבית כשפה יומיומית. המצב הזה, שנמשך דורות רבים, הפך את העברית ל''שפה מתה'' בעיני בלשנים רבים — בדומה ללטינית או לסנסקריט.
אליעזר בן-יהודה, שעלה לארץ ישראל מליטא ב-1881, האמין בכל ליבו כי עם שחוזר לארצו ההיסטורית חייב לדבר בשפתו העתיקה. הוא לא הסתפק ברעיון — הוא יישם אותו בצורה קיצונית: כפה על אשתו ובנו לדבר רק עברית, גם כשלא היו מילים למושגים יומיומיים. בנו, בן-ציון בן-יהודה (שלימים כונה איתמר בן-אב"י), נחשב לילד הראשון ששפת אמו הייתה עברית מודרנית. בן-יהודה יצר אלפי מילים חדשות — מילון, עיתון, גלידה, מגבת, אופנה — על ידי חיפוש שורשים מקראיים ותלמודיים והתאמתם לצרכי החיים המודרניים.
אך בן-יהודה לא פעל בחלל ריק. התהליך לא היה פשוט ולא חד-כיווני. היו ויכוחים נוקבים בין תומכי העברית לתומכי היידיש, ששימשה כשפת היומיום של מיליוני יהודים באירופה. ''מלחמת השפות'' ב-1913, שהתנהלה סביב שאלת שפת ההוראה בטכניון בחיפה, הייתה נקודת מפנה — העברית ניצחה, והטכניון אימץ אותה כשפת הוראה. במקביל, מורים כמו דוד ילין ויוסף אזרחי פיתחו שיטות הוראה חדשניות: ''עברית בעברית'', ללא תרגום, כדי לטבול את התלמידים בשפה החיה.
רק בשנות העשרים של המאה העשרים, עם גל העלייה השלישית מאירופה, הפכה העברית לשפת הרוב בקרב היישוב היהודי בארץ ישראל. ועד הלשון העברית, שייסד בן-יהודה, המשיך לפעול גם אחרי מותו ב-1922, והתפתח ב-1953 לאקדמיה ללשון העברית. האקדמיה ממשיכה עד היום להחליט על מילים חדשות, כללי כתיב ודקדוק.
היום, כתשעה מיליון אנשים דוברים עברית כשפת אם או כשפה שנייה — עובדה שנראתה בלתי אפשרית לפני מאה וחמישים שנה. תחיית העברית אינה רק הישג לשוני — היא ביטוי של רצון קולקטיבי ליצור זהות לאומית חדשה, מבוססת על שורשים עתיקים אך פונה אל העתיד. בלשנים בכל העולם לומדים את המקרה הישראלי כדוגמה ייחודית, ולעיתים אף כהשראה לתחיית שפות אחרות — כמו הוולשית, הבאסקית או המאורית.', 'Возрождение иврита — одно из уникальнейших достижений в лингвистической истории человечества. На протяжении примерно двух тысяч лет иврит служил лишь языком святости и учёности — для молитвы, изучения Торы, написания литургической поэзии и переписки между мудрецами. Он не был родным языком ни одной общины, ни один ребёнок не вырастал, слыша его дома как повседневный язык. Это положение, длившееся многие поколения, превратило иврит в «мёртвый язык» в глазах многих лингвистов — подобно латыни или санскриту.
Элиэзер Бен-Иехуда, репатриировавшийся из Литвы в 1881 году, всем сердцем верил, что народ, возвращающийся на свою историческую родину, должен говорить на своём древнем языке. Он не ограничился идеей — реализовал её радикально: заставил жену и сына говорить только на иврите, даже когда не было слов для повседневных понятий. Его сын считается первым ребёнком, чьим родным языком стал современный иврит. Бен-Иехуда создал тысячи новых слов — словарь, газета, мороженое, полотенце, мода — находя библейские и талмудические корни и адаптируя их к нуждам современной жизни.
Однако Бен-Иехуда действовал не в вакууме. Процесс не был простым и однонаправленным. Шли острые дебаты между сторонниками иврита и сторонниками идиша, служившего повседневным языком миллионов евреев Европы. «Война языков» 1913 года, разгоревшаяся вокруг вопроса о языке преподавания в Технионе в Хайфе, стала переломным моментом — иврит победил. Параллельно учителя разработали инновационные методики: «иврит на иврите», без перевода, чтобы погрузить учеников в живой язык.
Только в 1920-х, с третьей волной алии из Европы, иврит стал языком большинства еврейского населения. Комитет языка иврит, основанный Бен-Иехудой, продолжил работу и в 1953 году стал Академией языка иврит. Сегодня около девяти миллионов человек говорят на иврите — факт, казавшийся невозможным полтора века назад. Возрождение иврита — не только лингвистическое достижение, но выражение коллективной воли создать новую национальную идентичность, основанную на древних корнях, но обращённую в будущее.', '[{"he": "תחייה", "ru": "возрождение", "translit": "тхийА"}, {"he": "למדנות", "ru": "учёность", "translit": "ламданУт"}, {"he": "וועד הלשון", "ru": "Комитет языка", "translit": "ваАд халашОн"}, {"he": "נוקב", "ru": "резкий/острый", "translit": "нокЕв"}, {"he": "עלייה", "ru": "алия (репатриация)", "translit": "алийА"}, {"he": "שפת אם", "ru": "родной язык", "translit": "сфат эм"}, {"he": "פיוט", "ru": "литургическая поэзия", "translit": "пиЮт"}, {"he": "כתיב", "ru": "орфография", "translit": "ктИв"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (282, 5, 'על שירתו של יהודה עמיחי', 'О поэзии Иехуды Амихая', 'יהודה עמיחי (1924-2000) נחשב לאחד המשוררים החשובים ביותר בשפה העברית ולקול השירי המרכזי של הדור שלו. הוא נולד בגרמניה בשם לודוויג פפויפר, ועלה לארץ ישראל ב-1936 עם משפחתו. הוא שירת בבריגדה היהודית במלחמת העולם השנייה ובמלחמת העצמאות, חוויות שעיצבו את שירתו בצורה עמוקה. לאחר המלחמה למד ספרות ותנ"ך באוניברסיטה העברית, ושם החל לפרסם את שיריו הראשונים.
שירתו של עמיחי מתאפיינת בשילוב ייחודי של הנשגב והיומיומי, של הפרטי והלאומי. בשיר ''אלוהים מרחם על ילדי הגן'' הוא כותב על ילדים, על חיילים ועל האהבה, תוך שימוש בשפה פשוטה אך עמוקה. הוא לוקח ביטויים מקראיים ומכניס אותם לתוך הקשרים חדשים ומפתיעים: ''כאן ישבנו. ישבנו מגדל / ושם ירדנו בלשון'' — הוא מהפך את סיפור מגדל בבל לחוויה אינטימית. הטכניקה הזו — שימוש בלשון המקרא כחומר גלם לשירה מודרנית — הפכה לסימן ההיכר שלו.
עמיחי שבר את המוסכמות של השירה העברית בדרכים רבות. ראשית, הוא הכניס את השפה הדבורה — את העברית של הרחוב, של השוק, של צה"ל — לתוך השיר. בעוד שמשוררים קודמים, כמו אלתרמן ושלונסקי, כתבו בעברית גבוהה ומליצית, עמיחי כתב כמו שאנשים מדברים. שנית, הוא השתמש באירוניה ובהומור — כלים שהיו נדירים בשירה העברית הרצינית. שלישית, הוא איחד מטאפורות מקראיות עם תמונות מחיי היומיום: חנות ירקות ליד כותל המערבי, מכונת כביסה ותפילה, טופס מס ופסוק מתהילים.
''ירושלים היא עיר שבה כולם זוכרים / שהם שכחו משהו / אבל לא זוכרים מה'' — דוגמה טיפוסית לסגנונו: משפט שנשמע פשוט, אך חושף אמת עמוקה על העיר ועל תושביה. השירה שלו על ירושלים, על המלחמות ועל האהבה נגעה בקוראים מכל העולם. עמיחי תורגם ליותר מארבעים שפות, ושיריו נכללו באנתולוגיות של השירה הטובה ביותר במאה העשרים. הוא היה מועמד לפרס נובל כמה פעמים, ואף שלא זכה בו, הוא הוכיח שאפשר לכתוב שירה גדולה בעברית החדשה.
המשורר טד יוז, בן זמנו הבריטי, אמר עליו: ''עמיחי מביא לשפה האנגלית מסורת שירית עשירה שלא הכרנו.'' הביקורת הספרותית רואה בעמיחי את מי שהפך את השירה העברית מלאומית-קולקטיבית לאישית-אוניברסלית, מבלי לוותר על ההקשר הישראלי. מותו ב-2000 סימן את סוף תקופה בשירה העברית — אך השפעתו ממשיכה להדהד בדורות המשוררים שבאו אחריו.', 'Иехуда Амихай (1924-2000) считается одним из важнейших поэтов на иврите и главным поэтическим голосом своего поколения. Он родился в Германии под именем Людвиг Пфойфер и репатриировался в 1936 году. Служил в Еврейской бригаде во Второй мировой войне и в Войне за независимость — опыт, глубоко сформировавший его поэзию.
Поэзия Амихая характеризуется уникальным сочетанием возвышенного и повседневного, личного и национального. Он берёт библейские выражения и помещает их в новые, неожиданные контексты. Эта техника — использование библейского языка как сырья для современной поэзии — стала его визитной карточкой.
Амихай разрушил каноны ивритской поэзии несколькими способами. Во-первых, внёс разговорный язык в стих. Во-вторых, использовал иронию и юмор — редкие инструменты в серьёзной ивритской поэзии. В-третьих, соединил библейские метафоры с образами повседневности: овощная лавка у Стены Плача, стиральная машина и молитва.
«Иерусалим — город, где все помнят / что забыли что-то / но не помнят что» — типичный пример его стиля: фраза, звучащая просто, но раскрывающая глубокую истину о городе и его жителях. Амихай был переведён на более чем сорок языков и номинировался на Нобелевскую премию. Его смерть в 2000 году ознаменовала конец эпохи — но его влияние продолжает звучать в поколениях поэтов, пришедших после него.', '[{"he": "משורר", "ru": "поэт", "translit": "мешорЕр"}, {"he": "שירה", "ru": "поэзия", "translit": "ширА"}, {"he": "הנשגב", "ru": "возвышенное", "translit": "ханисгАв"}, {"he": "מוסכמות", "ru": "каноны/конвенции", "translit": "мускамОт"}, {"he": "אירוניה", "ru": "ирония", "translit": "иронийА"}, {"he": "מטאפורה", "ru": "метафора", "translit": "метАфора"}, {"he": "אנתולוגיה", "ru": "антология", "translit": "антолОгия"}, {"he": "מליצי", "ru": "высокопарный", "translit": "мелицИ"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (283, 5, 'האתגר הדמוגרפי — זקנה בישראל', 'Демографический вызов — старение в Израиле', 'בעוד שישראל נהנית משיעור ילודה גבוה ביחס למדינות מפותחות אחרות — כ-3.0 ילדים לאישה בממוצע, לעומת 1.6 באירופה — גם היא מתמודדת עם מגמת הזדקנות האוכלוסייה. מגמה זו, שהיא תופעה עולמית, מקבלת בישראל ממדים מיוחדים בשל המבנה הדמוגרפי המורכב של החברה: הפערים בין המגזרים — חילוני, דתי-לאומי, חרדי וערבי — יוצרים מציאות דמוגרפית שאין לה אח ורע במדינות אחרות.
תוחלת החיים בישראל עלתה משמעותית בעשורים האחרונים: 82.6 שנים בממוצע, מהגבוהות בעולם. זוהי הצלחה רפואית מרשימה, אך היא מציבה אתגרים חדשים. כ-12% מהאוכלוסייה הם בני 65 ומעלה, ושיעור זה צפוי לעלות ל-15% בתוך עשור. כמות הקשישים מעל גיל 80 הכפילה את עצמה ב-20 השנים האחרונות, ואיתה גדלה הדרישה לשירותי סיעוד, טיפול ביתי ומוסדות לטיפול ממושך.
הדבר מציב אתגרים כבדים בתחומי הפנסיה, הבריאות והשירותים החברתיים. מערכת הבריאות נדרשת להתמודד עם עלייה חדה במחלות כרוניות — סוכרת, לחץ דם, דמנציה ואלצהיימר. בתי אבות אינם מספיקים לביקוש, ורבים מהקיימים סובלים מתחזוקה ירודה ומתנאים שאינם ראויים. חוק ביטוח סיעודי, שנכנס לתוקף ב-2018, נועד להבטיח טיפול הולם, אך תקציבו נחשב לבלתי מספיק.
מנגד, ישראל מפתחת טכנולוגיות חדשניות בתחום הגריאטריה. חברות סטארט-אפ ישראליות מפתחות רובוטים מלווים שמסייעים לקשישים בפעולות יומיומיות, מערכות טלה-רפואה שמאפשרות ביקור רופא מרחוק, ופתרונות דיגיטליים כמו אפליקציות לניהול תרופות ולמניעת נפילות. מרכז המחקר בבית חולים שיבא פיתח תוכניות שיקום ייחודיות לגיל הזהב.
הדילמה החברתית עמוקה: כיצד לשלב את האוכלוסייה המבוגרת בחברה הטכנולוגית המהירה, תוך שמירה על כבודה ועל זכויותיה? כיצד למנוע בדידות חברתית אצל קשישים שילדיהם עסוקים מדי? כיצד לחלק את הנטל הכלכלי בין הדורות? שאלות אלה אינן רק שאלות של מדיניות — הן שאלות מוסריות שקובעות איזו חברה אנחנו רוצים להיות.', 'Хотя Израиль наслаждается высоким уровнем рождаемости по сравнению с другими развитыми странами — около 3,0 ребёнка на женщину против 1,6 в Европе — он тоже сталкивается с тенденцией старения населения. Эта тенденция приобретает в Израиле особые масштабы из-за сложной демографической структуры: разрывы между секторами — светским, национально-религиозным, ультраортодоксальным и арабским — создают уникальную демографическую реальность.
Продолжительность жизни в Израиле значительно выросла: 82,6 года в среднем, одна из самых высоких в мире. Это впечатляющий медицинский успех, но он создаёт новые вызовы. Около 12% населения — старше 65 лет, и этот показатель ожидаемо вырастет до 15% в ближайшее десятилетие. Число пожилых старше 80 лет удвоилось за последние 20 лет.
Система здравоохранения должна справляться с резким ростом хронических заболеваний — диабета, гипертонии, деменции и болезни Альцгеймера. Домов престарелых не хватает, многие из существующих страдают от плохого содержания. С другой стороны, Израиль разрабатывает инновационные технологии в области гериатрии — роботы-компаньоны, телемедицина и цифровые решения для пожилых.
Социальная дилемма глубока: как интегрировать пожилое население в быстро развивающееся технологическое общество, сохраняя их достоинство и права? Эти вопросы — не только вопросы политики, но моральные вопросы, определяющие, каким обществом мы хотим быть.', '[{"he": "הזדקנות", "ru": "старение", "translit": "издакнУт"}, {"he": "תוחלת חיים", "ru": "продолжительность жизни", "translit": "тохЕлет хаИм"}, {"he": "כרוני", "ru": "хронический", "translit": "хронИ"}, {"he": "גריאטריה", "ru": "гериатрия", "translit": "гериатрийА"}, {"he": "טלה-רפואה", "ru": "телемедицина", "translit": "теле-рефуА"}, {"he": "דילמה", "ru": "дилемма", "translit": "дилЕма"}, {"he": "סיעוד", "ru": "уход за больными", "translit": "сиУд"}, {"he": "בדידות", "ru": "одиночество", "translit": "бдидУт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (284, 5, 'הפילוסופיה של מרטין בובר', 'Философия Мартина Бубера', 'מרטין בובר (1878-1965) הוא אחד ההוגים היהודיים המשפיעים ביותר במאה העשרים, ורעיונותיו חרגו מגבולות הפילוסופיה היהודית והשפיעו על תיאולוגיה נוצרית, פסיכותרפיה, חינוך ואפילו מדע המדינה. הוא נולד בווינה, גדל אצל סבו שלמה בובר — חוקר מדרשים ידוע — ומשם ספג את האהבה לטקסטים יהודיים קלאסיים. בצעירותו היה פעיל בתנועה הציונית, אך בהדרגה התרחק מהציונות הפוליטית לטובת חזון של תחייה רוחנית ותרבותית.
ספרו המרכזי ''אני ואתה'' (1923) הציג תפיסה פילוסופית ייחודית שהפכה לאבן יסוד בפילוסופיה של הדיאלוג. לפי בובר, העולם נחווה בשני מודוסים יסודיים: ''אני-אתה'' ו''אני-זה''. ביחס ''אני-אתה'' אנו פוגשים את הזולת כישות שלמה, בדיאלוג אמיתי, ללא ניסיון לנצל או לשלוט. ביחס ''אני-זה'' אנו מתייחסים לאחר כאל אובייקט — דבר שאפשר למדוד, לנתח ולהשתמש בו. בובר לא טען שהיחס ''אני-זה'' הוא רע כשלעצמו — הוא הכרחי לקיום בעולם — אלא שחיים שכולם ''אני-זה'' הם חיים חסרי משמעות.
הרעיון המפתיע ביותר של בובר הוא שהקשר עם האלוהי מתרחש דרך ''אני-אתה'' — כל מפגש אמיתי עם אדם, עם טבע, עם אמנות, הוא מפגש עם האינסופי. אלוהים, לפי בובר, אינו עצם מופשט אלא ה''אתה הנצחי'' שניתן לפגוש בכל רגע של דיאלוג אמיתי. תפיסה זו השפיעה עמוקות על תיאולוגים נוצרים כמו פאול טיליך וקרל ראנר, ועל פסיכותרפיסטים כמו קארל רוג''רס, שראה ביחס ''אני-אתה'' הטיפולי את הבסיס לריפוי.
בובר היגר לירושלים ב-1938, לאחר עליית הנאצים, ולימד אנתרופולוגיה חברתית באוניברסיטה העברית. בישראל הוא דגל בדו-לאומיות ובדיאלוג ערבי-יהודי — עמדה שהייתה שנויה במחלוקת חריפה בתקופתו. הוא היה חבר בקבוצת ''איחוד'' שקראה למדינה דו-לאומית, ולאחר הקמת המדינה המשיך לקרוא לשלום ולפיוס. ב-1963 זכה בפרס ארסמוס בהולנד, ונאומו שם היה קריאה לדיאלוג אמיתי בין עמים.
מורשתו של בובר רלוונטית היום יותר מתמיד. בעולם שבו התקשורת הדיגיטלית מאפשרת חיבור ללא מפגש אמיתי, ובחברה הישראלית שבה קבוצות חיות זו לצד זו מבלי לנהל דיאלוג, הקריאה ל''אני-אתה'' אינה רק פילוסופיה — היא דרישה מוסרית ופוליטית.', 'Мартин Бубер (1878-1965) — один из влиятельнейших еврейских мыслителей XX века, чьи идеи вышли далеко за границы еврейской философии и повлияли на христианскую теологию, психотерапию, педагогику и политологию. Он родился в Вене, вырос у деда — известного исследователя мидрашей — и впитал любовь к классическим еврейским текстам.
Его центральная книга «Я и Ты» (1923) представила уникальную философскую концепцию, ставшую краеугольным камнем философии диалога. По Буберу, мир переживается в двух модусах: «Я-Ты» и «Я-Оно». В отношении «Я-Ты» мы встречаем другого как целостное существо, в настоящем диалоге. В отношении «Я-Оно» мы относимся к другому как к объекту. Бубер не считал отношение «Я-Оно» злом — оно необходимо, но жизнь, состоящая только из «Я-Оно», лишена смысла.
Самая поразительная идея Бубера: связь с божественным происходит через «Я-Ты» — каждая подлинная встреча с человеком, природой, искусством есть встреча с бесконечным. Эта концепция глубоко повлияла на теологов и психотерапевтов вроде Карла Роджерса.
Бубер эмигрировал в Иерусалим в 1938 году и преподавал в Еврейском университете. Он выступал за бинационализм и арабо-еврейский диалог — позиция, вызывавшая острые споры. Его наследие актуальнее, чем когда-либо: в мире цифровых коммуникаций без подлинных встреч призыв к «Я-Ты» — не только философия, но моральное и политическое требование.', '[{"he": "הוגה", "ru": "мыслитель", "translit": "огЕ"}, {"he": "תפיסה", "ru": "концепция", "translit": "тфисА"}, {"he": "מודוס", "ru": "модус", "translit": "модУс"}, {"he": "דיאלוג", "ru": "диалог", "translit": "диалОг"}, {"he": "אינסופי", "ru": "бесконечный", "translit": "эйнсофИ"}, {"he": "דו-לאומיות", "ru": "бинационализм", "translit": "ду-леумиЮт"}, {"he": "פיוס", "ru": "примирение", "translit": "пиЮс"}, {"he": "אנתרופולוגיה", "ru": "антропология", "translit": "антрополОгия"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (285, 5, 'הבלשנות העברית — מבנה השורש', 'Лингвистика иврита — структура корня', 'אחת התכונות המרתקות ביותר של השפה העברית היא מערכת השורשים — מבנה מורפולוגי ייחודי שמאפיין את השפות השמיות. רוב המילים בעברית נגזרות משורש תלת-עיצורי (ולעיתים דו-עיצורי או רבע-עיצורי), וכל שורש נושא משמעות בסיסית שמתפרשת לכיוונים שונים באמצעות תבניות ומשקלים.
למשל, השורש כ-ת-ב, שמשמעותו הבסיסית קשורה לכתיבה, מניב עשרות מילים: כָּתַב (כתב), כּוֹתֵב (כותב), מִכְתָּב (מכתב), כַּתָּב (כתב/עיתונאי), כַּתָּבָה (כתבה), כְּתוֹבֶת (כתובת), כְּתָב יָד (כתב יד), מַכְתֵּבָה (מכתבה), תַּכְתּוֹבֶת (תכתובת), הַכְתָּבָה (הכתבה). כל מילה שומרת על הקשר לשורש הבסיסי, אך מקבלת גוון שונה בזכות התבנית שבה היא מופיעה.
מערכת הבניינים — פעל, נפעל, פיעל, פועל, הפעיל, הופעל, התפעל — היא כלי מרכזי בדקדוק העברי. כל בניין מעניק לשורש תפקוד דקדוקי שונה: פעל הוא פעיל פשוט (כתב — כתב), פיעל הוא אינטנסיבי או סיבתי (כיתב — כתב בצורה מסוימת), הפעיל הוא גורם (הכתיב — גרם לאחר לכתוב), נפעל הוא סביל (נכתב — נכתב על ידי מישהו), והתפעל הוא רפלקסיבי (התכתב — כתב הלוך ושוב). כך, מהשורש ל-מ-ד: לָמַד (למד), לִימֵּד (לימד), נִלְמַד (נלמד), הִתְלַמֵּד (התלמד — למד בכוחות עצמו).
שיטה זו מאפשרת ליצור מילים חדשות בקלות יחסית. אליעזר בן-יהודה ניצל את מערכת השורשים כדי לחדש אלפי מילים לעברית המודרנית. גם האקדמיה ללשון העברית ממשיכה להשתמש בשיטה זו: המילה ''מחשב'' נוצרה מהשורש ח-ש-ב (חשב), ''סלולרי'' מ-ס-ל-ל (סלל), ''מסרון'' (SMS) מ-ס-ר (מסר). היכולת ליצור מילים חדשות מתוך מערכת קיימת היא אחת הסיבות שהעברית הצליחה להתחדש ולשרוד.
עם זאת, לא כל המילים בעברית מודרנית נשמעות למערכת השורשים. מילים שאולות כמו ''טלפון'', ''אוטובוס'', ''אינטרנט'' ו''פיצה'' אינן מבוססות על שורש עברי. בלשנים מתווכחים עד כמה דוברי עברית צעירים עדיין מרגישים את הקשר בין מילים מאותו שורש — או שמא מערכת השורשים הולכת ונחלשת בעידן הגלובליזציה. מחקרים פסיכובלשניים מראים שהשורש עדיין פעיל בעיבוד המנטלי של מילים, אך ההשפעה שלו פוחתת ככל שהמילה נדירה יותר.', 'Одно из самых захватывающих свойств иврита — система корней, уникальная морфологическая структура, характерная для семитских языков. Большинство слов происходят от трёхбуквенного корня, несущего базовое значение, которое разветвляется в разных направлениях через шаблоны и модели.
Например, корень к-т-б, связанный с письмом, даёт десятки слов: катав (писал), котев (пишет), михтав (письмо), катав (журналист), катава (статья), ктовет (адрес), ктав яд (почерк). Каждое слово сохраняет связь с корнем, но получает разный оттенок благодаря модели.
Система биньянов — Пааль, Нифъаль, Пиэль, Пуаль, Хифъиль, Хуфъаль, Хитпаэль — центральный инструмент грамматики. Каждый биньян придаёт корню разную грамматическую функцию: активную, каузативную, пассивную или рефлексивную. Эта система позволяет легко создавать новые слова.
Однако не все слова современного иврита подчиняются системе корней. Заимствования вроде «телефон», «интернет», «пицца» не основаны на ивритском корне. Лингвисты спорят, насколько молодые носители иврита ещё чувствуют связь между однокоренными словами. Психолингвистические исследования показывают, что корень всё ещё активен в ментальной обработке слов, но его влияние уменьшается для редких слов.', '[{"he": "שורש", "ru": "корень", "translit": "шОреш"}, {"he": "תלת-עיצורי", "ru": "трёхбуквенный", "translit": "тлат-ицурИ"}, {"he": "בניינים", "ru": "биньяны (глагольные модели)", "translit": "биньянИм"}, {"he": "נגזרות", "ru": "производные", "translit": "нигзарОт"}, {"he": "שאולות", "ru": "заимствованные", "translit": "шеулОт"}, {"he": "גוונים", "ru": "оттенки", "translit": "гванИм"}, {"he": "מורפולוגי", "ru": "морфологический", "translit": "морфолОги"}, {"he": "פסיכובלשני", "ru": "психолингвистический", "translit": "психо-балшанИ"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (286, 5, 'האתיקה של הבינה המלאכותית', 'Этика искусственного интеллекта', 'התפתחות הבינה המלאכותית מעלה שאלות אתיות שהאנושות טרם התמודדה עימן — שאלות שנוגעות לעצם ההגדרה של מה זה להיות אדם, מה זו קבלת החלטות, ומי אחראי כשמכונה טועה. בניגוד לטכנולוגיות קודמות שהחליפו עבודה פיזית, הבינה המלאכותית מתחילה להחליף תהליכים שנחשבו ייחודיים לאדם: שיפוט, יצירתיות, ואפילו אמפתיה.
כאשר מכונה מקבלת החלטות שמשפיעות על חיי אדם — ברכב אוטונומי שצריך לבחור בין פגיעה בנוסע לפגיעה בהולך רגל, בשפיטה אלגוריתמית שקובעת את גובה הערבות של נאשם, ברפואה שבה AI מאבחן מחלות — מי נושא באחריות? היצרן? המתכנת? הרופא שהסתמך על המלצת המערכת? השאלה המשפטית והמוסרית עדיין אינה פתורה, ומדינות שונות מנסות גישות שונות.
הטיות אלגוריתמיות הן בעיה חמורה נוספת. מערכות AI לומדות מנתונים היסטוריים — ואם הנתונים משקפים דעות קדומות ואפליה, גם התוצאות יהיו מוטות. בארצות הברית נמצא שמערכת COMPAS לחיזוי סיכון חזרה לפשע הפלתה לרעה אפרו-אמריקנים. בגיוס עובדים, AI שלמד מהחלטות גיוס קודמות העדיף גברים לבנים. הבעיה אינה בטכנולוגיה עצמה, אלא בנתונים שאנו מזינים אותה.
שאלת הפרטיות מחריפה כאשר מערכות AI מנתחות כמויות עצומות של מידע אישי. זיהוי פנים ברחובות, ניתוח רגשות מתנועות גוף, חיזוי התנהגות מדפוסי גלישה — כל אלה מאיימים על החופש האישי. סין מיישמת ''ציון חברתי'' שמדרג אזרחים על פי התנהגותם, ומדינות דמוקרטיות חוששות מזחילה בכיוון דומה.
בתחום התעסוקה, אוטומציה חכמה צפויה להחליף לא רק עבודות פשוטות אלא גם מקצועות שנחשבו ''בטוחים'' — רואי חשבון, עורכי דין, רדיולוגים ואפילו מתכנתים. מחקרים מעריכים ש-30%-40% מהמשרות הנוכחיות ייעלמו או ישתנו מהותית עד 2040. ישראל, כמובילה טכנולוגית, נמצאת בחזית הדיון הזה. האקדמיה הישראלית למדעים פרסמה המלצות לפיתוח AI אחראי, ומספר סטארט-אפים ישראליים מתמחים ב''AI אתי'' — מערכות שמתוכננות להיות שקופות, הוגנות וניתנות להסבר. אולם השאלה היסודית נותרת: האם ניתן לתכנת מוסר?', 'Развитие искусственного интеллекта поднимает этические вопросы, с которыми человечество ещё не сталкивалось — вопросы, затрагивающие само определение человека, принятия решений и ответственности. В отличие от прежних технологий, заменявших физический труд, ИИ начинает заменять процессы, считавшиеся уникально человеческими: суждение, творчество и даже эмпатию.
Когда машина принимает решения, влияющие на жизни людей — в автономном автомобиле, алгоритмическом правосудии, медицинской диагностике — кто несёт ответственность? Алгоритмические искажения — серьёзная проблема: системы ИИ учатся на исторических данных, и если данные отражают предрассудки, результаты тоже будут предвзятыми.
Вопрос приватности обостряется, когда системы ИИ анализируют огромные объёмы личной информации. Распознавание лиц, анализ эмоций, прогнозирование поведения — всё это угрожает личной свободе. В сфере занятости умная автоматизация заменит не только простые работы, но и «безопасные» профессии.
Израиль, как технологический лидер, находится на переднем крае дискуссии. Израильская академия наук опубликовала рекомендации по ответственному развитию ИИ. Но фундаментальный вопрос остаётся: можно ли запрограммировать мораль?', '[{"he": "בינה מלאכותית", "ru": "искусственный интеллект", "translit": "бинА мелахутИт"}, {"he": "אתיקה", "ru": "этика", "translit": "Этика"}, {"he": "אוטונומי", "ru": "автономный", "translit": "отонОми"}, {"he": "הטיות", "ru": "искажения/предвзятость", "translit": "хатаЙот"}, {"he": "פרטיות", "ru": "приватность", "translit": "пратиЮт"}, {"he": "אחראי", "ru": "ответственный", "translit": "ахраИ"}, {"he": "אלגוריתם", "ru": "алгоритм", "translit": "алгорИтм"}, {"he": "שקיפות", "ru": "прозрачность", "translit": "шкифУт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (287, 5, 'מבט על הפרוזה של עמוס עוז', 'Взгляд на прозу Амоса Оза', 'עמוס עוז (1939-2018) הוא אולי הסופר הישראלי המוכר ביותר בעולם, ויצירותיו, שתורגמו ליותר מ-45 שפות, הפכו חלון שדרכו העולם מביט על ישראל — לא דרך כותרות חדשות ותמונות מלחמה, אלא דרך סיפורים אנושיים מורכבים ורגישים. עוז נולד בירושלים כעמוס קלאוזנר, למשפחה של אינטלקטואלים ציוניים-רביזיוניסטים, ובגיל 14 עזב את הבית והצטרף לקיבוץ חולדה — מרד שכנגד מסורת משפחתו.
ב''סיפור על אהבה וחושך'', רומן אוטוביוגרפי שפורסם ב-2002, הוא מתאר את ילדותו בירושלים של שנות הארבעים והחמישים — עיר קטנה ועניה, חמה ומחנקת, שבה גדל בין ספרים ובין חלומות. הספר מתאר את התפוררות משפחתו, את הדיכאון של אמו פניה ואת התאבדותה כשעמוס היה בן 12 — אירוע שהטביע חותם בל-יימחה על כל יצירתו. הספר הוסב לסרט בבימויה של נטלי פורטמן ב-2015.
הסגנון של עוז מתאפיין בתשומת לב מדוקדקת לפרטים — ריחות, קולות, מרקמים — ובניתוח פסיכולוגי עדין שחודר לנבכי נפשם של הדמויות. הלשון העברית שלו עשירה ומדויקת, משלבת את הגבוה והנמוך: משפטי מקרא ליד סלנג צבאי, דיון פילוסופי ליד תיאור ארוחת ערב. ב''מיכאל שלי'' (1968) הוא מתאר אישה ירושלמית שנפשה הולכת ומתפוררת, ומבטה המסונוור על העולם הופך את הרומן לחוויה לא-נוחה ומרתקת.
עוז ידע לכתוב על הקונפליקט הלאומי דרך יחסים בין-אישיים. ב''ארצות התן'' (1965) כל סכסוך שכנים בקיבוץ הוא מיקרוקוסמוס של הסכסוך הגדול יותר — הפחד, החשד, הרצון לשלוט, הכישלון לתקשר. הוא האמין שכל קונפליקט — גם בין ישראל לפלסטין — הוא בסופו של דבר טרגדיה: שני צדדים שכל אחד מהם צודק באופן חלקי.
עוז היה גם איש ציבור בולט: דגל בפתרון שתי מדינות, היה ממייסדי ''שלום עכשיו'', וכתב מאות מאמרי דעה. עמדתו המדינית עוררה גם ביקורת — מימין ראו בו ''שמאלני'', ומשמאל ביקרו אותו על כך שלא הלך מספיק רחוק. עם מותו ב-2018, רבים הרגישו שנסגר פרק בספרות הישראלית ובשיח הציבורי.', 'Амос Оз (1939-2018) — возможно, самый известный в мире израильский писатель. Его произведения, переведённые на более чем 45 языков, стали окном, через которое мир смотрит на Израиль — не через заголовки и фотографии войны, а через сложные и чувствительные человеческие истории. Оз родился в Иерусалиме и в 14 лет ушёл из дома в кибуц Хульда.
В «Повести о любви и тьме» (2002), автобиографическом романе, он описывает детство в Иерусалиме сороковых-пятидесятых — маленьком и бедном городе. Книга описывает распад семьи, депрессию матери и её самоубийство, когда Амосу было 12 лет — событие, наложившее неизгладимый отпечаток на всё его творчество.
Стиль Оза отличается скрупулёзным вниманием к деталям и тонким психологическим анализом. Его иврит богат и точен, сочетает высокое и низкое: библейские фразы рядом с армейским сленгом. Он умел писать о национальном конфликте через межличностные отношения: каждая соседская ссора — микрокосм большого конфликта. Он верил, что каждый конфликт — в конечном счёте трагедия: две стороны, каждая из которых частично права.
Оз был также выдающимся общественным деятелем: выступал за решение двух государств, был одним из основателей «Шалом Ахшав». С его смертью в 2018 году многие почувствовали, что закрылась глава в израильской литературе и общественном дискурсе.', '[{"he": "פרוזה", "ru": "проза", "translit": "прОза"}, {"he": "אוטוביוגרפי", "ru": "автобиографический", "translit": "отобиографИ"}, {"he": "התפוררות", "ru": "распад", "translit": "хитпоререрУт"}, {"he": "פסיכולוגי", "ru": "психологический", "translit": "психолОги"}, {"he": "מיקרוקוסמוס", "ru": "микрокосмос", "translit": "микрокОсмос"}, {"he": "סכסוך", "ru": "конфликт", "translit": "сихсУх"}, {"he": "דיכאון", "ru": "депрессия", "translit": "дикаОн"}, {"he": "מאמר דעה", "ru": "статья-мнение", "translit": "маамАр деА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (288, 5, 'הסוציולוגיה של החברה הישראלית', 'Социология израильского общества', 'החברה הישראלית מאופיינת במתחים מבניים ייחודיים שהופכים אותה לאחת המורכבות בעולם המערבי. סוציולוגים מזהים מספר קווי שבר מרכזיים שחותכים את החברה לאורכה ולרוחבה: חילונים מול דתיים, אשכנזים מול מזרחים, יהודים מול ערבים, מרכז מול פריפריה, ותיקים מול עולים. כל אחד מקווים אלה יוצר זהויות קבוצתיות, תחרות על משאבים ועל הכרה, ודפוסים שונים של הצבעה, צריכה תרבותית וניידות חברתית.
ברוך קימרלינג, סוציולוג מהאוניברסיטה העברית, כינה את ישראל ''חברה של שבטים'' — קבוצות שונות החיות זו לצד זו, משתפות מרחב גיאוגרפי ופוליטי משותף, אך שומרות על גבולות חדים ביניהן. הן אינן מתמזגות באמת ל''עם אחד'', אלא מתקיימות בהסדרים של כוח וממסד. לפי קימרלינג, הצבא הוא המוסד היחיד שיוצר חוויה משותפת — אך גם הוא מוציא מכלל את הערבים ואת החרדים.
הפער בין אשכנזים למזרחים הוא אחד העמוקים ביותר. ''הפנתרים השחורים'', תנועת מחאה של צעירים ממוצא מזרחי בשנות השבעים, חשפו אפליה שיטתית בשיכון, בחינוך ובתעסוקה. אף שהפערים הצטמצמו מאז — מזרחים נמצאים היום בכל רובדי החברה, כולל עליונים — הם לא נעלמו לגמרי. מחקרים מראים שמוצא עדתי עדיין משפיע על הכנסה, השכלה ומגורים.
הקו בין יהודים לערבים הוא אולי החד ביותר. אזרחים ערבים, המהווים כ-21% מאוכלוסיית ישראל, נהנים מזכויות אזרח מלאות על הנייר, אך מתמודדים עם פערים בתקצוב, בתשתיות ובייצוג. מחקרי עדנה לומסקי-פדר הראו כיצד מערכת החינוך מייצרת נרטיבים לאומיים שונים — ילד יהודי וילד ערבי לומדים היסטוריות שונות של אותם אירועים.
הזהות הישראלית נותרת שסועה ורב-שכבתית — מה שהופך אותה למעניינת ומורכבת כאחד. הסוציולוגים מתלבטים: האם ישראל תצליח ליצור זהות אזרחית משותפת שחוצה את קווי השבר, או שמא הפיצול הולך ומעמיק?', 'Израильское общество характеризуется уникальными структурными напряжённостями, делающими его одним из самых сложных в западном мире. Социологи выделяют несколько основных линий разлома: светские против религиозных, ашкеназы против мизрахим, евреи против арабов, центр против периферии, старожилы против репатриантов.
Барух Кимерлинг назвал Израиль «обществом племён» — разные группы, живущие бок о бок, разделяющие географическое и политическое пространство, но сохраняющие чёткие границы между собой. Они не сливаются по-настоящему в «единый народ», а сосуществуют в рамках властных и институциональных договорённостей.
Разрыв между ашкеназами и мизрахим — один из глубочайших. «Чёрные пантеры» семидесятых обнажили системную дискриминацию. Хотя разрывы сократились, они не исчезли полностью. Линия между евреями и арабами — возможно, самая резкая: арабские граждане (21% населения) имеют полные гражданские права на бумаге, но сталкиваются с разрывами в финансировании и инфраструктуре.
Израильская идентичность остаётся расколотой и многослойной. Социологи сомневаются: сможет ли Израиль создать общую гражданскую идентичность, или раскол углубляется?', '[{"he": "סוציולוגיה", "ru": "социология", "translit": "социолОгия"}, {"he": "קווי שבר", "ru": "линии разлома", "translit": "кавЕй шЕвер"}, {"he": "משאבים", "ru": "ресурсы", "translit": "машавИм"}, {"he": "הכרה", "ru": "признание", "translit": "хакарА"}, {"he": "שסועה", "ru": "расколотая", "translit": "шесуА"}, {"he": "התמזג", "ru": "сливаться", "translit": "хитмазЕг"}, {"he": "ניידות חברתית", "ru": "социальная мобильность", "translit": "наядУт хевратИт"}, {"he": "תקצוב", "ru": "финансирование", "translit": "такцУв"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (289, 5, 'הארכיטקטורה הישראלית — מבאוהאוס לבני', 'Израильская архитектура — от Баухауса к бетону', 'הארכיטקטורה הישראלית משקפת את ההיסטוריה של המדינה בצורה ויזואלית מרשימה: כל תקופה הותירה את חותמה על המרחב הבנוי, וכל סגנון אדריכלי מספר סיפור על החברה שבנתה אותו. מי שמטייל ברחובות ישראל יכול לקרוא את ההיסטוריה דרך הקירות.
בשנות השלושים הגיעו ארכיטקטים יהודים מגרמניה שלמדו בבית הספר באוהאוס או הושפעו מהסגנון הבינלאומי. הם בנו את תל אביב — ובמיוחד את מרכז העיר — בסגנון מודרניסטי: מבנים לבנים עם גגות שטוחים, מרפסות מעוגלות, חלונות צרים ופסי-שמש אופקיים. הסגנון הותאם לאקלים המקומי: הקירות העבים הגנו מהחום, המרפסות יצרו צל, והעמודים הגביהו את המבנים מהקרקע כדי לאפשר אוורור. תל אביב הוכרזה כאתר מורשת עולמית של אונסק"ו ב-2003, בזכות ריכוז המבנים הבאוהאוסיים הגדול ביותר בעולם — כ-4,000 מבנים.
בשנות החמישים, עם גלי העלייה המוניים — שהכפילו את אוכלוסיית המדינה תוך שלוש שנים — הממשלה נאלצה לבנות במהירות ובזול. שיכונים פשוטים מבטון, המכונים ''שיכוני עולים'', צצו בכל רחבי הארץ: מבנים תועלתניים בני 3-4 קומות, עם דירות קטנות ומפרטים בסיסיים. ארכיטקטורה פונקציונלית אך חסרת חן, שיצרה שכונות אפורות ומונוטוניות. ערי הפיתוח שנבנו בתקופה זו — דימונה, ירוחם, קריית שמונה — סובלות עד היום מתדמית של פריפריה מוזנחת.
בשנות השבעים והשמונים, הברוטליזם — סגנון שמציג בטון חשוף בצורתו הגולמית — הגיע לישראל. בניינים ממשלתיים, אוניברסיטאות ומרכזי תרבות נבנו בסגנון הזה. בנייני האומה בירושלים ומגדל שלום בתל אביב הם דוגמאות מובהקות. הסגנון עורר חילוקי דעות — חלק ראו בו עוצמה, אחרים ראו אפרוריות.
בעשורים האחרונים חל שינוי דרמטי: אדריכלים ישראליים מתכננים מבנים ירוקים ובני-קיימא, המשלבים טכנולוגיה ואסתטיקה. מוזיאון תל אביב לאמנות (שדרכת רון ארד), בית המשפט העליון (רם כרמי ואדה כרמי-מלמד), ומרכז פרס לשלום (מאסימיליאנו פוקסאס) הם דוגמאות לארכיטקטורה ישראלית מובילה שזוכה להכרה בינלאומית. הדיאלוג בין ישן לחדש, בין מזרח למערב, בין מדבר לים, מאפיין את הבנייה בישראל.', 'Израильская архитектура впечатляюще отражает историю государства: каждая эпоха оставила свой след на застроенном пространстве, и каждый архитектурный стиль рассказывает историю общества, которое его создало.
В тридцатые прибыли еврейские архитекторы из Германии, построившие Тель-Авив в модернистском стиле: белые здания с плоскими крышами, закруглёнными балконами и узкими окнами. Тель-Авив был объявлен объектом Всемирного наследия ЮНЕСКО в 2003 году — крупнейшее скопление зданий Баухауса в мире (~4000 зданий).
В пятидесятые, с массовыми волнами алии, правительство строило быстро и дёшево: простые бетонные жилмассивы — функциональная, но безликая архитектура. Города развития, построенные в ту эпоху, по сей день страдают от имиджа заброшенной периферии.
В последние десятилетия произошёл драматический сдвиг: израильские архитекторы проектируют зелёные и устойчивые здания, сочетающие технологию и эстетику. Музей Тель-Авива, Верховный суд и Центр Переса — примеры ведущей израильской архитектуры. Диалог между старым и новым, между Востоком и Западом характеризует строительство в Израиле.', '[{"he": "ארכיטקטורה", "ru": "архитектура", "translit": "архитектУра"}, {"he": "שיכונים", "ru": "жилмассивы", "translit": "шикунИм"}, {"he": "בטון", "ru": "бетон", "translit": "бетОн"}, {"he": "בני-קיימא", "ru": "устойчивые", "translit": "бнЕй-каямА"}, {"he": "אסתטיקה", "ru": "эстетика", "translit": "эстЕтика"}, {"he": "אדריכלים", "ru": "архитекторы", "translit": "адрихалИм"}, {"he": "מורשת עולמית", "ru": "Всемирное наследие", "translit": "морЕшет оламИт"}, {"he": "ברוטליזם", "ru": "брутализм", "translit": "бруталИзм"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (290, 5, 'הזיכרון הקולקטיבי — יום השואה בישראל', 'Коллективная память — День Холокоста в Израиле', 'יום הזיכרון לשואה ולגבורה הוא אחד הימים המשמעותיים ביותר בלוח השנה הישראלי — יום שבו המדינה כולה עוצרת, מתייחדת עם הזיכרון, ומתמודדת מחדש עם השאלה כיצד להמשיך לחיות אחרי הטרגדיה הגדולה ביותר בהיסטוריה היהודית. התאריך נקבע ל-27 בניסן — שבוע לפני יום הזיכרון לחללי מערכות ישראל, ושבועיים לפני יום העצמאות — רצף שאינו מקרי: מחורבן, דרך זיכרון, ועד תקומה.
בשעה עשר בבוקר נשמעת צפירה בת שתי דקות ברחבי המדינה. הכל עוצר: מכוניות עומדות באמצע הכביש, אנשים יוצאים מהרכבים ועומדים בדומייה, הולכי רגל קופאים על מקומם, המדינה כולה מתייחדת עם זכר ששת המיליונים. זוהי חוויה ייחודית — מעט מדינות בעולם מכירות רגע קולקטיבי כזה של שתיקה מוחלטת. תיירים שנמצאים בישראל ביום זה מתארים תחושה של קדושה חילונית — משהו שאי אפשר לתאר במילים.
בבתי ספר נערכים טקסים ייחודיים. תלמידים לומדים על השואה, צופים בעדויות של ניצולים, ולעיתים פוגשים ניצולים בכבודם ובעצמם. פרויקט ''כל אדם יש לו שם'' מקריא את שמות הנספים ברחבי הארץ — ברחבות ערים, בכנסת, באוניברסיטאות. ''מצעד החיים'' מוביל אלפי צעירים ישראליים למחנות ההשמדה בפולין, חוויה רגשית עמוקה שגם עוררה ביקורת: האם היא מחזקת זהות לאומית או מטפחת פחד ושנאה?
אולם ככל שהניצולים הולכים ומתמעטים — בתחילת שנות ה-2020 נותרו כ-150,000 ניצולים בישראל, רובם מעל גיל 85 — עולה השאלה הכואבת: כיצד להנחיל את הזיכרון לדור שלישי ורביעי שלא הכיר אף ניצול? הדיון על צורות ההנצחה מתחדש בכל שנה. מוזיאון ''יד ושם'' מפתח פרויקטים דיגיטליים: עדויות בטכנולוגיית הולוגרמה שמאפשרות ''שיחה'' עם ניצול שכבר נפטר, ארכיונים דיגיטליים שמנגישים מיליוני מסמכים, ותוכניות חינוכיות מקוונות.
יש גם קולות שקוראים לשילוב השואה בהקשר אוניברסלי של זכויות אדם ומניעת רצח עם — לא כאירוע יהודי בלעדי, אלא כלקח לכלל האנושות. מנגד, אחרים חוששים שאוניברסליזציה של השואה תטשטש את ייחודיותה ותפחית את המחויבות לזיכרון היהודי הספציפי. המתח הזה — בין פרטיקולריזם לאוניברסליזם — הוא אחד הדיונים המרתקים ביותר בתרבות הישראלית.', 'День памяти Холокоста и героизма — один из важнейших дней в израильском календаре, когда вся страна останавливается и заново осмысляет вопрос: как продолжать жить после величайшей трагедии в еврейской истории. Дата выбрана не случайно: за неделю до Дня памяти павших, за две недели до Дня независимости — от разрушения через память к возрождению.
В десять утра звучит двухминутная сирена. Всё останавливается: машины замирают посреди шоссе, люди выходят из автомобилей и стоят в молчании. Это уникальное переживание — немногие страны знают подобный коллективный момент абсолютной тишины.
В школах проводятся церемонии: ученики изучают Холокост, смотрят свидетельства выживших. Проект «У каждого человека есть имя» зачитывает имена погибших по всей стране. «Марш живых» ведёт тысячи молодых израильтян в лагеря уничтожения в Польше.
По мере того как выживших становится всё меньше — к началу 2020-х в Израиле осталось около 150 000, большинству за 85 — встаёт мучительный вопрос: как передать память третьему и четвёртому поколению? Музей «Яд Вашем» разрабатывает цифровые проекты: свидетельства в голограммной технологии, цифровые архивы. Есть и голоса, призывающие к включению Холокоста в универсальный контекст прав человека. Напряжение между партикуляризмом и универсализмом — одна из самых захватывающих дискуссий в израильской культуре.', '[{"he": "שואה", "ru": "Холокост", "translit": "шоА"}, {"he": "צפירה", "ru": "сирена", "translit": "цфирА"}, {"he": "דומייה", "ru": "молчание", "translit": "думийА"}, {"he": "ניצולים", "ru": "выжившие", "translit": "ницолИм"}, {"he": "הנצחה", "ru": "увековечивание", "translit": "ханцахА"}, {"he": "להנחיל", "ru": "передать (наследие)", "translit": "леханхИль"}, {"he": "אוניברסליזם", "ru": "универсализм", "translit": "универсалИзм"}, {"he": "רצח עם", "ru": "геноцид", "translit": "рЕцах ам"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (291, 5, 'המוסיקה הישראלית — מזרח ומערב', 'Израильская музыка — Восток и Запад', 'המוסיקה הישראלית היא מיקס ייחודי של מזרח ומערב, של מסורת ומודרניות, המשקף את ריבוי התרבויות שמרכיבות את החברה הישראלית. כמו המטבח, השפה והארכיטקטורה, גם המוסיקה בישראל היא סיפור של קבוצות מגוונות שמביאות את קולן לאותו מרחב — לעיתים בהרמוניה, ולעיתים בחיכוך.
בשנות החמישים שלטו ''שירי ארץ ישראל'' — שירים לאומיים שביטאו את חלום הציונות, את אהבת הנוף ואת חיי הקולקטיב. נעמי שמר, עם ''ירושלים של זהב'' ו''לו יהי'', הפכה לקול של דור שלם. השירים נכתבו בעיקר בסגנון מערבי — מלודי, פשוט, עם השפעות רוסיות ואירופיות. זה היה ''הקנון'' של המוסיקה הישראלית, שהוזמן לרוב בידי מוסדות ממלכתיים.
בשנות השבעים הופיע הרוק הישראלי. להקת ''כוורת'', בהובלת דני סנדרסון ואריק איינשטיין, יצרה מוסיקה ישראלית שהייתה שובבה, הומוריסטית ומקורית. שלמה ארצי, יהודית רביץ ומתי כספי הביאו את הרוק הלירי. זו הייתה תקופה שבה המוסיקה הישראלית החלה להשתחרר מהכפיתות הלאומית ולדבר בקול אישי.
בשנות השמונים חלה ''המהפכה המזרחית'' — שינוי תרבותי עמוק שעדיין מעורר ויכוחים. זמרים כמו זוהר ארגוב, עופרה חזה וחיים משה הביאו את המוסיקה המזרחית — עם הסקאלות המזרחיות, כלי הנגינה הערביים והרגש הגולמי — מהשוליים אל המיינסטרים. ארגוב, ''מלך המוסיקה המזרחית'', סבל מהתעלמות של הממסד התרבותי, מהתמכרות לסמים ומחיים טרגיים שהסתיימו במותו ב-1987. רק עשרות שנים אחרי מותו הוכר כאחד הזמרים הגדולים בישראל.
היום, המוסיקה הישראלית מגוונת כמו החברה עצמה: ראפ בעברית ובערבית (סאבלימינל, תמר נפתלי), פופ אלקטרוני, ג''אז ייחודי (אבישי כהן), מוסיקה אתיופית-ישראלית (אסתר רדא), פיוזון יצירתי ו''ים-תיכוני חדש''. אמנים כמו עידן רייכל, שמשלב מוסיקה אתיופית עם אלקטרוניקה, נטע ברזילי שזכתה באירוויזיון 2018, ואומר אדם שהפך לתופעה — כולם הגיעו לקהל בינלאומי. המוסיקה הישראלית מוכיחה שאפשר ליצור משהו מקורי ומרגש מתוך ריבוי תרבויות — כשמפסיקים לפחד מההבדלים.', 'Израильская музыка — уникальный микс Востока и Запада, традиции и современности, отражающий многообразие культур, составляющих израильское общество. Как кухня, язык и архитектура, музыка в Израиле — история разных групп, привносящих свой голос в общее пространство.
В пятидесятые доминировали «песни Эрец-Исраэль» — национальные песни, выражавшие сионистскую мечту. Наоми Шемер с «Золотым Иерусалимом» стала голосом поколения. В семидесятые появился израильский рок: группа Кавэрет создала игривую и оригинальную музыку.
В восьмидесятые произошла «мизрахийская революция»: певцы вроде Зоар Аргов, Офра Хаза и Хаим Моше принесли восточную музыку — с восточными ладами, арабскими инструментами и сырой эмоцией — из маргинального пространства в мейнстрим. Аргов, «король восточной музыки», страдал от игнорирования культурного истеблишмента и трагически погиб в 1987.
Сегодня израильская музыка разнообразна: рэп, электронный поп, джаз, эфиопско-израильская музыка, фьюжн. Артисты вроде Идан Райхель, Нетта Барзилай (победительница Евровидения-2018) и Омер Адам достигли международной аудитории. Израильская музыка доказывает, что можно создать нечто оригинальное из множества культур.', '[{"he": "מוסיקה", "ru": "музыка", "translit": "мУзика"}, {"he": "מזרחי", "ru": "восточный/мизрахийский", "translit": "мизрахИ"}, {"he": "מיינסטרים", "ru": "мейнстрим", "translit": "мЕйнстрим"}, {"he": "פיוזון", "ru": "фьюжн", "translit": "фьЮжон"}, {"he": "ריבוי", "ru": "множество", "translit": "рибУй"}, {"he": "אמנים", "ru": "артисты", "translit": "оманИм"}, {"he": "סקאלות", "ru": "лады/гаммы", "translit": "скалОт"}, {"he": "ממסד", "ru": "истеблишмент", "translit": "мимсАд"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (292, 5, 'השפעת ההגירה על הזהות הישראלית', 'Влияние иммиграции на израильскую идентичность', 'ישראל היא מדינת הגירה מייסודה — לא רק כעובדה דמוגרפית, אלא כרעיון מכונן. הציונות עצמה מבוססת על הגעת יהודים מכל קצוות העולם לארץ ישראל, והמדינה הוקמה בידי עולים שהביאו עימם שפות שונות, מנהגים שונים ותפיסות עולם שונות. ''חוק השבות'' (1950) מעניק לכל יהודי בעולם את הזכות לעלות לישראל ולקבל אזרחות — חוק שאין לו מקבילה במדינות אחרות.
כל גל עלייה הביא עימו תרבות, שפה ומנהגים שעיצבו את הזהות הישראלית. העלייה הראשונה והשנייה (1882-1914) הביאו צעירים אידיאליסטיים מרוסיה ומאירופה המזרחית, שהקימו קיבוצים ומושבות. העלייה מגרמניה בשנות השלושים (''יקים'') הביאה אינטלקטואלים, רופאים ומוסיקאים. העלייה מארצות ערב בשנות החמישים — מתימן, מעיראק, ממרוקו — הביאה יותר ממחצית מאוכלוסיית המדינה הצעירה, אך נקלטה בתנאים קשים ובאפליה.
העלייה מרוסיה ומברית המועצות בשנות התשעים — כמיליון איש — שינתה את הנוף הדמוגרפי, התרבותי והכלכלי: היא הביאה מדענים, מהנדסים, מוסיקאים ושחמטאים שהעצימו את ההון האנושי של המדינה. אך גם הציבה אתגרי קליטה: שפה, הכרה בתארים, זהות יהודית. העלייה מאתיופיה — שהחלה ב''מבצע משה'' (1984) ו''מבצע שלמה'' (1991) — הציבה שאלות על גזענות ושילוב: עולים אתיופיים נתקלו באפליה בשיכון, בחינוך ובתעסוקה.
כל קבוצה הביאה את מאכליה, מוסיקתה ומילותיה — ואלה נספגו בתרבות הכללית. המילים ''באבושקה'', ''קוסקוס'' ו''אינג''רה'' הפכו חלק מהעברית היומיומית. מוסיקה מזרחית, אוכל רוסי, מנהגי אתיופיה — כולם חלק מהמרקם הישראלי. התוצאה היא זהות ישראלית שהיא כמו תבשיל: אי אפשר להפריד בין הרכיבים, כי הם כבר נטמעו זה בזה.
השאלה האם מדובר ב''כור היתוך'' שטשטש הבדלים, או ב''פסיפס'' ששומר על ייחודיות כל חלק, מלווה את השיח הישראלי מאז ימי המדינה. בשנים האחרונות הגישה המועדפת היא ''רב-תרבותיות'' — הכרה בכך שכל קבוצה שומרת על זהותה המיוחדת, ושהשונות היא עושר ולא איום.', 'Израиль — иммиграционное государство по своей сути — не только демографически, но и идейно. Сам сионизм основан на прибытии евреев со всего мира. «Закон о возвращении» (1950) даёт каждому еврею право репатриироваться — закон, не имеющий аналогов.
Каждая волна алии приносила культуру, язык и обычаи. Первые волны привели идеалистов из России, основавших кибуцы. Алия из Германии в тридцатые привела интеллектуалов. Алия из арабских стран в пятидесятые — более половины населения молодого государства, но абсорбция проходила в тяжёлых условиях.
Алия из России в девяностых — около миллиона человек — изменила демографический ландшафт: принесла учёных, инженеров, музыкантов. Алия из Эфиопии поставила вопросы о расизме и интеграции. Каждая группа принесла свою еду, музыку и слова — и они впитались в общую культуру.
Результат — израильская идентичность как рагу: невозможно разделить компоненты. Вопрос — «плавильный котёл» или «мозаика» — сопровождает израильский дискурс с основания государства. В последние годы предпочтительный подход — мультикультурализм: признание, что каждая группа сохраняет свою идентичность, и разнообразие — богатство.', '[{"he": "הגירה", "ru": "иммиграция", "translit": "хагирА"}, {"he": "קליטה", "ru": "абсорбция", "translit": "клитА"}, {"he": "גזענות", "ru": "расизм", "translit": "газъанУт"}, {"he": "פסיפס", "ru": "мозаика", "translit": "псифАс"}, {"he": "רכיבים", "ru": "компоненты", "translit": "рехивИм"}, {"he": "ייחודיות", "ru": "уникальность", "translit": "йихудиЮт"}, {"he": "חוק השבות", "ru": "Закон о возвращении", "translit": "хОк хашвУт"}, {"he": "רב-תרבותיות", "ru": "мультикультурализм", "translit": "рав-тарбутиЮт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (293, 5, 'הנרטיב הפלסטיני בספרות הישראלית', 'Палестинский нарратив в израильской литературе', 'בעשורים האחרונים, סופרים ישראליים החלו להכניס את הנרטיב הפלסטיני ליצירותיהם — תהליך שמשקף שינוי תרבותי עמוק בחברה הישראלית. בעוד שבספרות הישראלית המוקדמת הערבי היה כמעט בלתי נראה, או שהופיע כ''אויב'' חסר פנים ברקע, בספרות העכשווית הוא מקבל קול, שם ופנים.
א.ב. יהושע, ב''מר מאני'' (1990), יצר רומן רב-דורי שבו דמויות יהודיות וערביות מתקיימות זו לצד זו דרך מאתיים שנה של היסטוריה. עמוס עוז, ב''מנוחה נכונה'' ובסיפורים מ''ארצות התן'', הציג דמויות ערביות מורכבות שאינן רק רקע לדרמה היהודית. דוד גרוסמן, ב''חיוך הגדי'' (1983), כתב רומן שמנסה לחדור לעולם הפנימי של ילד פלסטיני בגדה המערבית — ניסיון אמפתי שעורר גם הערכה וגם ביקורת.
אולם הקולות המעניינים ביותר הם של סופרים ערבים-ישראלים הכותבים בעברית. סייד קשוע, שנולד בטירה, מציג את המבט הפנימי של ערבי בחברה הישראלית — מבט מלא סתירות, הומור מר וכאב. ברומן ''גוף שני, יחיד'' (2010) הוא מתאר צעיר ערבי המנסה להיטמע בחברה היהודית עד כדי גניבת זהותו של אדם אחר. הרומן בוחן את המחיר של ההסוואה ואת השאלה מה נותר מהזהות כשמוותרים על כל סימני ההיכר.
ביקורת ספרותית בוחנת כיצד הייצוג של הפלסטיני השתנה בספרות הישראלית: מ''אויב'' ליטרלי ביצירות מוקדמות, דרך ''אחר'' מופשט ומסתורי בשנות השישים והשבעים, ועד אדם בשר ודם ביצירות עכשוויות. החוקרת חנן חבר כינתה את התהליך ''הופעת הגוף הערבי'' בספרות העברית. אך גם כיום, יש הטוענים שרוב הייצוגים עדיין מתבצעים מנקודת מבט יהודית — הערבי מדבר, אך את הדיבור כותב סופר יהודי.
השינוי הזה בספרות משקף תהליכים רחבים יותר בחברה — הכרה הדרגתית במורכבות של הסכסוך, ובכך שלצד השני יש סיפור שראוי להישמע. זו אינה רק שאלה ספרותית — היא שאלה מוסרית ופוליטית שנוגעת ללב הקיום בישראל.', 'В последние десятилетия израильские писатели начали включать палестинский нарратив в свои произведения — процесс, отражающий глубокий культурный сдвиг. Если в ранней израильской литературе араб был почти невидим или появлялся как безликий «враг», то в современной литературе он получает голос, имя и лицо.
А.Б. Йехошуа в «Мистере Мани» создал многопоколенческий роман, где еврейские и арабские персонажи сосуществуют через двести лет истории. Давид Гроссман в «Улыбке козлёнка» попытался проникнуть во внутренний мир палестинского ребёнка на Западном берегу.
Но самые интересные голоса — арабо-израильские писатели, пишущие на иврите. Саид Кашуа показывает внутренний взгляд араба в израильском обществе — полный противоречий, горького юмора и боли. В романе «Второе лицо, единственное число» он описывает молодого араба, ассимилирующегося до кражи чужой идентичности.
Литературная критика исследует, как изменилось изображение палестинца: от буквального «врага» через абстрактного «другого» к живому человеку. Это изменение отражает постепенное признание сложности конфликта — и того, что у другой стороны есть история, достойная быть услышанной.', '[{"he": "נרטיב", "ru": "нарратив", "translit": "наратИв"}, {"he": "ייצוג", "ru": "представление", "translit": "йицУг"}, {"he": "להיטמע", "ru": "ассимилироваться", "translit": "лехиталЕа"}, {"he": "ביקורת ספרותית", "ru": "лит. критика", "translit": "бикОрет сифрутИт"}, {"he": "מופשט", "ru": "абстрактный", "translit": "муфшАт"}, {"he": "הדרגתי", "ru": "постепенный", "translit": "хадрагатИ"}, {"he": "אמפתי", "ru": "эмпатический", "translit": "эмпАти"}, {"he": "הסוואה", "ru": "маскировка", "translit": "хасваА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (294, 5, 'הכלכלה הישראלית — מקיבוץ לסטארט-אפ', 'Израильская экономика — от кибуца к стартапу', 'הכלכלה הישראלית עברה מהפך דרמטי בשישים שנות קיומה — מכלכלה ריכוזית מתוכננת בהשפעת סוציאליזם, לאחת הכלכלות החדשניות והדינמיות ביותר בעולם. סיפור הכלכלה הישראלית הוא סיפור של משברים, רפורמות ותעוזה.
בעשורים הראשונים שלטה כלכלה ריכוזית עם השפעה חזקה של ההסתדרות והמגזר הציבורי. ההסתדרות לא הייתה רק ארגון עובדים — היא הפעילה חברות ענק כמו סולל בונה, תנובה וכור, והייתה המעסיק הגדול ביותר במשק. הממשלה שלטה על חלוקת מטבע חוץ, על ייבוא ויצוא, ועל מחירי מוצרים בסיסיים.
משבר האינפלציה הגדול של שנות השמונים היה נקודת מפנה דרמטית. כאשר האינפלציה הגיעה ל-450% בשנה — מחירים הוכפלו כל כמה חודשים, שכר עובדים נשחק מדי יום, ואנשים רצו לקנות מוצרים מיד כי מחר הם יהיו יקרים יותר — הממשלה השיקה את תוכנית הייצוב של 1985. התוכנית כללה הקפאת שכר ומחירים, קיצוץ חד בתקציב, ופיחות שער החליפין. היא הצליחה באופן מפתיע, והפכה למודל שנלמד בבתי ספר לכלכלה ברחבי העולם.
מאז החלה ליברליזציה מואצת: הפרטה של חברות ממשלתיות, פתיחת השוק ליבוא, ומעבר לכלכלת שוק. בשנות האלפיים הפכה ישראל ל''אומת הסטארט-אפ'': יותר חברות הנסחרות בנאסד"ק מכל מדינה מלבד ארצות הברית וסין, יותר הוצאה על מחקר ופיתוח (כאחוז מהתמ"ג) מכל מדינה בעולם, ויצוא טכנולוגיה שמניע את הצמיחה.
אולם הצלחה זו מלווה באי-שוויון גובר. מקדם ג''יני של ישראל גבוה מהממוצע ב-OECD, ויוקר המחיה — במיוחד דיור — הוא מהגבוהים בעולם המפותח. מחאת הדיור של 2011, כשמאות אלפים יצאו לרחובות, חשפה את הפער בין הישגי המקרו-כלכלה לחוויה היומיומית של אזרחים רגילים. הדילמה נותרת: כיצד לשמור על חדשנות כלכלית תוך צמצום פערים חברתיים.', 'Израильская экономика претерпела драматические изменения — от централизованной плановой экономики с социалистическим влиянием до одной из самых инновационных и динамичных экономик мира. Это история кризисов, реформ и дерзости.
В первые десятилетия доминировала централизованная экономика с сильным влиянием Гистадрута, управлявшего гигантскими компаниями. Великий инфляционный кризис восьмидесятых стал драматическим поворотом: при инфляции 450% в год правительство запустило Программу стабилизации 1985 года, ставшую моделью для изучения в экономических школах мира.
С тех пор началась ускоренная либерализация. В нулевые Израиль стал «нацией стартапов»: больше компаний на NASDAQ, чем у любой страны кроме США и Китая, самые высокие расходы на R&D в мире.
Однако успех сопровождается растущим неравенством. Коэффициент Джини выше среднего по ОЭСР, стоимость жизни — особенно жильё — одна из самых высоких. Жилищный протест 2011 года обнажил разрыв между макроэкономическими достижениями и повседневным опытом обычных граждан.', '[{"he": "אינפלציה", "ru": "инфляция", "translit": "инфлАция"}, {"he": "ליברליזציה", "ru": "либерализация", "translit": "либерализАция"}, {"he": "הפרטה", "ru": "приватизация", "translit": "хафратА"}, {"he": "חדשנות", "ru": "инновационность", "translit": "хадшанУт"}, {"he": "מקדם ג''יני", "ru": "коэффициент Джини", "translit": "мекадЕм джИни"}, {"he": "יוקר המחיה", "ru": "стоимость жизни", "translit": "Йокер хамихъЯ"}, {"he": "תמ\"ג", "ru": "ВВП", "translit": "тамАг"}, {"he": "ייצוב", "ru": "стабилизация", "translit": "йицУв"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (295, 5, 'המדבר הירוק — חקלאות בנגב', 'Зелёная пустыня — сельское хозяйство в Негеве', 'הנגב מהווה יותר ממחצית משטחה של ישראל — כ-13,000 קמ"ר של מדבר, ערבות ומכתשים. אך רק כ-8% מאוכלוסייתה חיים בו. דוד בן-גוריון, מייסד המדינה, האמין שעתידה של ישראל טמון בנגב. הוא עצמו הלך לגור בקיבוץ שדה בוקר לאחר פרישתו, ומשם הטיף ליישוב המדבר. ''מי שלא מאמין בנסים אינו ריאליסט'', אמר — והנגב החקלאי הוא הוכחה לכך.
למרות התנאים הקשים — פחות מ-200 מ"מ גשם בשנה (לעומת 600 מ"מ במרכז הארץ), טמפרטורות שמגיעות ל-45 מעלות בקיץ ויורדות לאפס בלילות חורף, קרקע מדברית דלילה ומלוחה — חקלאים ישראליים הצליחו להפוך חלקים מהנגב לאזור חקלאי פורח.
המפתח היה טכנולוגיה חדשנית. טכנולוגיית הטפטוף, שפותחה בישראל בשנות השישים על ידי שמחה בלאס, חוללה מהפכה בחקלאות העולמית. במקום להציף שדות ולבזבז עד 70% מהמים להתאדות, מטפטפים מים ישירות לשורשי הצמח, עם דשנים מדויקים. החיסכון במים מגיע ל-50%-70%. הטכנולוגיה הזו מיוצאת היום ליותר מ-100 מדינות, כולל אזורים מדבריים באפריקה ובאסיה.
חממות הנגב מייצרות תוצרת חקלאית איכותית: עגבניות שרי, פלפלים צבעוניים, תבלינים, פרחים ותמרים שמיוצאים לאירופה. הערבה — עמק צר בין ים המלח לאילת — הפך ליצרן החקלאי המרשים ביותר: בתנאי מדבר קיצוניים גדלים שם ירקות ופרחים שנמכרים בסופרמרקטים בלונדון ובפריז.
מחקרים באוניברסיטת בן-גוריון בוחנים גידולי מדבר עתידיים: אצות לייצור דלק ביולוגי ותוספי מזון, צמחי מלח (הלופיטים) שגדלים על מים מליחים ואינם מתחרים על מים מתוקים, ומערכות אקוופוניקס שמשלבות גידול דגים וירקות. הנגב מוכיח שחדשנות יכולה לנצח גם את תנאי הטבע הקשים ביותר — ואולי להציע פתרונות לאתגרי המזון העולמיים.', 'Негев составляет более половины территории Израиля — около 13 000 км² пустыни, степей и кратеров, но лишь 8% населения живёт здесь. Давид Бен-Гурион верил, что будущее Израиля — в Негеве, и сам поселился в кибуце Сде-Бокер.
Несмотря на суровые условия — менее 200 мм осадков, температуры до 45°C летом, бедная и засолённая почва — израильские фермеры превратили части Негева в процветающий сельскохозяйственный район. Ключ — инновационные технологии.
Технология капельного полива, разработанная Симхой Бласом в шестидесятые, произвела мировую сельскохозяйственную революцию: вместо затопления полей вода капает прямо к корням, экономя 50-70% воды. Технология экспортируется в более чем 100 стран.
Теплицы Негева производят черри-томаты, цветные перцы, специи, цветы и финики на экспорт в Европу. Арава — узкая долина между Мёртвым морем и Эйлатом — стала впечатляющим сельхозпроизводителем: овощи и цветы, выращенные в экстремальных условиях, продаются в лондонских и парижских супермаркетах. Университет Бен-Гуриона исследует будущие пустынные культуры: водоросли для биотоплива, галофиты, аквапонику. Негев доказывает, что инновации побеждают даже самые суровые условия.', '[{"he": "טפטוף", "ru": "капельный полив", "translit": "тифтУф"}, {"he": "חממות", "ru": "теплицы", "translit": "хамамОт"}, {"he": "קרקע", "ru": "почва", "translit": "каркА"}, {"he": "אצות", "ru": "водоросли", "translit": "ацОт"}, {"he": "מליחים", "ru": "солёные", "translit": "мелухИм"}, {"he": "מדברי", "ru": "пустынный", "translit": "мидбарИ"}, {"he": "התאדות", "ru": "испарение", "translit": "хитадУт"}, {"he": "מכתש", "ru": "кратер", "translit": "махтЕш"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (296, 5, 'התיאטרון הישראלי — במה למציאות', 'Израильский театр — сцена для реальности', 'התיאטרון הישראלי נולד עוד לפני המדינה. תיאטרון ''הבימה'' נוסד במוסקבה ב-1917, בימי המהפכה, ועלה לארץ ישראל ב-1928. הוא הפך לתיאטרון הלאומי ולסמל של תחיית העברית על הבמה — לראשונה מזה אלפיים שנה, הצגה שלמה הועלתה בעברית. ההצגה הראשונה בארץ, ''הדיבוק'' מאת ש. אנ-סקי, עוסקת ברוח מתים ובאהבה אסורה — נושאים שחיברו בין המסורת היהודית לעולם הדרמה האירופית.
בשנות החמישים והשישים שלט הריאליזם על הבמה. מחזות עסקו בחיי הקיבוץ, בהקמת המדינה ובהתמודדות עם הפרט מול הקולקטיב. ''הוא הלך בשדות'' של משה שמיר, ו''ילדי הצל'' של בן-ציון תומר, ביטאו את המתחים של הדור המייסד. התיאטרון הקאמרי, שנוסד ב-1944, הציע אלטרנטיבה אינטימית יותר להבימה המונומנטלי.
בשנות השבעים חל שינוי טקטוני: חנוך לוין פרץ על הבמה עם מחזות סאטיריים חריפים שביקרו את החברה הישראלית בצורה חסרת רחמים. ''מלכת האמבטיה'' (1970) עורר שערורייה: הצופים ניסו לעצור את ההצגה, פוליטיקאים גינו אותה, ותיאטרון ''הבימה'' הוריד אותה אחרי 19 הצגות בלבד. לוין כתב על הישראלי הקטן — רודף כסף, פחדן, גזען — ופגע באגו הלאומי. עם השנים הוכר כמחזאי הגדול ביותר שיצרה ישראל.
כיום, התיאטרון הישראלי מגוון ועשיר: מיצירות פוליטיות של תיאטרון יפו ערבי-עברי ותיאטרון ''חאלב'' (בערבית), דרך מחזות אישיים-פסיכולוגיים בתיאטרון הקאמרי, ועד הצגות ילדים חדשניות. הפרינג'' בעכו (הפסטיבל הישראלי לתיאטרון אלטרנטיבי) הוא חלון ראווה לתיאטרון מקורי, ניסיוני ופרובוקטיבי. פסטיבל ישראל בירושלים מביא את הטוב ביותר מהתיאטרון הישראלי והעולמי. ובכל מקרה, התיאטרון הישראלי אינו מפחד לגעת בנושאים כואבים — הכיבוש, הגזענות, הדת — וזו אולי הסיבה שהוא כל כך חי ורלוונטי.', 'Израильский театр родился ещё до государства. Театр «Габима», основанный в Москве в 1917, прибыл в Палестину в 1928 и стал национальным театром — символом возрождения иврита на сцене. В пятидесятые-шестидесятые доминировал реализм: пьесы о жизни кибуца и становлении государства.
В семидесятые произошёл тектонический сдвиг: Ханох Левин ворвался на сцену с беспощадными сатирическими пьесами. «Королева ванной» вызвала скандал и была снята после 19 спектаклей. Левин писал о маленьком израильтянине — жадном, трусливом, расисте — и ранил национальное эго. Со временем он был признан величайшим драматургом Израиля.
Сегодня израильский театр разнообразен: от политических произведений арабо-еврейского театра Яффо до личных психологических пьес и инновационных детских спектаклей. Фринж в Акко — витрина оригинального и провокационного театра. Израильский театр не боится болезненных тем — и потому остаётся живым и актуальным.', '[{"he": "תיאטרון", "ru": "театр", "translit": "теАтрон"}, {"he": "במה", "ru": "сцена", "translit": "бамА"}, {"he": "מחזה", "ru": "пьеса", "translit": "махазЕ"}, {"he": "סאטירי", "ru": "сатирический", "translit": "сатИри"}, {"he": "שערורייה", "ru": "скандал", "translit": "саарурийА"}, {"he": "חלון ראווה", "ru": "витрина", "translit": "халОн раавА"}, {"he": "מחזאי", "ru": "драматург", "translit": "махазАй"}, {"he": "ניסיוני", "ru": "экспериментальный", "translit": "нисйонИ"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (298, 5, 'המטבח הישראלי — זהות על הצלחת', 'Израильская кухня — идентичность на тарелке', 'המטבח הישראלי הוא כור היתוך קולינרי — או, ליתר דיוק, פסיפס קולינרי, כי הרכיבים עדיין שומרים על צבעם וטעמם הייחודי. על אותה שולחן יכולים לעמוד חומוס, בורקס, שניצל, קוסקוס, חריימה ואינג''רה — כל מנה מייצגת קהילת מוצא שונה, וכולן יחד יוצרות את מה שנקרא ''האוכל הישראלי''.
החומוס, שמקורו במטבח הערבי-לבנטיני, הפך לסמל לאומי ולא-רשמי של ישראל — וגם לזירת ויכוח: מי ''המציא'' את החומוס? הפלסטינים, הלבנונים או הישראלים? שאלה שנשמעת קלילה, אך נוגעת לשאלות עמוקות של נכיסה תרבותית וזהות. שקשוקה, ממוצא צפון-אפריקאי, היא ארוחת הבוקר הישראלית ללא-ספק. הפלאפל, שהגיע ממצרים, הפך ל''מאכל הלאומי'' — גם כשכולם יודעים שהוא לא ישראלי במקור.
בשנים האחרונות חלה ''מהפכת שפים'' שהעלתה את האוכל הישראלי לגבהים חדשים. שפים כמו ערל ויזל (מסעדת ''מחנה יהודה''), אסף גרניט ומאיר אדוני שילבו טכניקות מסעדנות עולמיות עם חומרי גלם מקומיים — תבלינים מהשוק, ירקות מהערבה, גבינות מהגולן. יותם אוטולנגי, שף ישראלי-בריטי, הפך את האוכל הישראלי-פלסטיני לטרנד עולמי עם ספרי הבישול שלו.
הביקורת הפוסט-קולוניאלית שואלת שאלות לא נוחות: האם ''המטבח הישראלי'' מנכס מאכלים פלסטיניים וערביים? האם שיווק חומוס, שקשוקה וזעתר כ''ישראליים'' הוא מחיקה תרבותית? מצד שני, אחרים טוענים שכל מטבח בעולם הוא תוצר של השפעות הדדיות — הפיצה האיטלקית מקורה בסין, והטומטו — מאמריקה. ברור שהאוכל בישראל הוא הרבה יותר מתזונה — הוא זירה של פוליטיקה, זיכרון, נוסטלגיה וזהות. כשאתה אוכל סביח בת"א, אתה אוכל היסטוריה.', 'Израильская кухня — кулинарный плавильный котёл, или, точнее, кулинарная мозаика, где ингредиенты сохраняют свой цвет и вкус. На одном столе могут стоять хумус, бурекас, шницель, кускус, хриме и инджера — каждое блюдо представляет другую общину происхождения.
Хумус, происходящий из арабско-левантийской кухни, стал неофициальным национальным символом — и предметом спора: кто «изобрёл» хумус? Шакшука — бесспорный израильский завтрак. Фалафель, пришедший из Египта, стал «национальным блюдом».
В последние годы произошла «шефская революция»: повара вроде Эяля Шани, Асафа Гранита, Йотама Оттоленги соединили мировые техники с местными продуктами. Постколониальная критика задаёт неудобные вопросы: присваивает ли «израильская кухня» палестинские блюда? Является ли маркетинг хумуса как «израильского» культурным стиранием?
Ясно, что еда в Израиле — гораздо больше, чем питание: это арена политики, памяти, ностальгии и идентичности.', '[{"he": "קולינרי", "ru": "кулинарный", "translit": "кулинАри"}, {"he": "חומוס", "ru": "хумус", "translit": "хУмус"}, {"he": "שקשוקה", "ru": "шакшука", "translit": "шакшУка"}, {"he": "חומרי גלם", "ru": "сырьё", "translit": "хомрЕй гЕлем"}, {"he": "פוסט-קולוניאלי", "ru": "постколониальный", "translit": "пост-колониАли"}, {"he": "מנכס", "ru": "присваивает", "translit": "менакЕс"}, {"he": "נכיסה תרבותית", "ru": "культурная апроприация", "translit": "нехисА тарбутИт"}, {"he": "שף", "ru": "шеф-повар", "translit": "шеф"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (299, 5, 'התקשורת בישראל — בין חופש לאחריות', 'СМИ в Израиле — между свободой и ответственностью', 'ישראל נהנית מעיתונות חופשית יחסית — היא מדורגת במקום גבוה במדד חופש העיתונות של ''כתבים ללא גבולות'' ביחס לאזור — אך מערכת התקשורת שלה מתמודדת עם אתגרים ייחודיים שאינם קיימים ברוב הדמוקרטיות המערביות.
הצנזורה הצבאית, שרידה מתקופת המנדט הבריטי, עדיין קיימת ופעילה. עורכים חייבים להגיש חומרים הנוגעים לביטחון לאישור הצנזור הצבאי לפני פרסום. ברוב המקרים, הצנזורה אינה חוסמת — היא מסמנת מידע רגיש. אך עצם קיומה מעלה שאלות על חופש הביטוי. בעידן האינטרנט, הצנזורה הצבאית הפכה פחות אפקטיבית — מידע שנחסם בישראל מתפרסם באתרים זרים.
שוק העיתונות הכתובה קרס כלכלית בשני העשורים האחרונים. ''מעריב'', שהיה העיתון הפופולרי ביותר, נסגר ב-2014 (והפך לאתר אינטרנט). ''הארץ'', העיתון האיכותי-ליברלי, ו''ידיעות אחרונות'', הפופולרי, הצטמצמו משמעותית. במקומם צמח ''ישראל היום'', המחולק בחינם, שנתפס כקרוב לראש הממשלה נתניהו — מצב שעורר חקיקה מוצעת (''חוק ישראל היום'') ודיון ציבורי נרחב על ריכוז תקשורתי.
המדיה הדיגיטלית שינתה את כללי המשחק לגמרי: בלוגרים, פודקאסטרים, עיתונאי רשת ומשפיענים הפכו לשחקנים משמעותיים. ערוצי יוטיוב ועמודי אינסטגרם משפיעים על דעת הקהל לא פחות מעיתונים. אך עם המעבר לדיגיטל גברו גם תופעות שליליות: חדשות מזויפות (fake news) המופצות ברשתות חברתיות, שיח שנאה שמתפשט ללא בקרה, ופגיעה באמון הציבור בתקשורת המסורתית.
השאלה כיצד לשמור על חופש העיתונות תוך הבטחת דיווח אחראי ומדויק היא רלוונטית יותר מתמיד — בישראל ובעולם כולו.', 'Израиль пользуется относительно свободной прессой, но его медиасистема сталкивается с уникальными вызовами. Военная цензура, наследие британского мандата, всё ещё существует: редакторы обязаны подавать материалы по безопасности цензору.
Рынок печатной прессы экономически рухнул. «Маарив» закрылся в 2014, «Хаарец» и «Едиот Ахронот» сокращаются. На их месте вырос «Исраэль ХаЙом», бесплатная газета, воспринимаемая как близкая к премьеру.
Цифровые медиа изменили правила: блогеры, подкастеры и онлайн-журналисты стали значимыми игроками. Но усилились и фейковые новости, язык ненависти в соцсетях и подрыв доверия к традиционным СМИ. Вопрос баланса между свободой прессы и ответственной журналистикой актуальнее, чем когда-либо.', '[{"he": "תקשורת", "ru": "СМИ/медиа", "translit": "тикшОрет"}, {"he": "צנזורה", "ru": "цензура", "translit": "цензУра"}, {"he": "ריכוז", "ru": "концентрация", "translit": "рикУз"}, {"he": "חדשות מזויפות", "ru": "фейковые новости", "translit": "хадашОт мезуйафОт"}, {"he": "שיח שנאה", "ru": "язык ненависти", "translit": "сИах синА"}, {"he": "דיווח", "ru": "освещение/репортаж", "translit": "дивУах"}, {"he": "משפיענים", "ru": "инфлюэнсеры", "translit": "машпиянИм"}, {"he": "חופש ביטוי", "ru": "свобода слова", "translit": "хОфеш битУй"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (300, 5, 'הספורט הישראלי — מעבר למשחק', 'Израильский спорт — больше, чем игра', 'הספורט בישראל הוא הרבה יותר מבידור — הוא משמש זירה של זהות, פוליטיקה ושייכות. בעוד שבמדינות אחרות הספורט יכול להיות הפסקה מהפוליטיקה, בישראל הוא חלק בלתי נפרד ממנה. שמות קבוצות, צבעי חולצות ושירי אוהדים מספרים סיפורים על מעמדות חברתיים, מפלגות פוליטיות ומתחים עדתיים.
כדורגל הוא הענף הפופולרי ביותר. הדרבי בין מכבי תל אביב להפועל תל אביב משקף מתחים מעמדיים היסטוריים: מכבי נתפסה כ''בורגנית'', הקשורה לתנועה הרביזיוניסטית (ימין), והפועל כ''עממית'', הקשורה להסתדרות ולמפלגת העבודה (שמאל). אף שהזיקות הפוליטיות נחלשו עם השנים, ההרגשות נותרו חזקות.
ביתר ירושלים, עם קהל האוהדים הימני הקיצוני שלה — קבוצת ''לה פמיליה'' — הפכה לסמל של פוליטיקה בספורט. אוהדים קראו קריאות גזעניות כנגד שחקנים ערבים, ואף ניסו למנוע חתימה על שחקנים מוסלמים. הקבוצה הפכה למראה של הקיצוניות בחברה הישראלית.
בכדורסל, מכבי תל אביב זכתה שש פעמים באליפות אירופה (היורוליג) — הישג יוצא דופן למדינה קטנה של תשעה מיליון. האולימפיאדה נושאת משמעות מיוחדת: הזיכרון של הטבח של 11 הספורטאים הישראלים במינכן 1972 — שנרצחו על ידי מחבלי ''ספטמבר השחור'' — מלווה כל משלחת ישראלית עד היום.
אתלטים ישראליים בולטים הוכיחו שגם מדינה קטנה יכולה להתחרות: גל פרידמן (זהב ברוח גלשנים, אתונה 2004), לינוי אשרם (זהב בהתעמלות אמנותית, טוקיו 2020), וארטם דולגופיאט (זהב בהתעמלות קרקע). כל מדליה ישראלית מעוררת חגיגה לאומית שחורגת הרבה מעבר לספורט. הספורט הישראלי מגלם את הרוח של ''יכול להיות'' — אופטימיות ותעוזה על אף הקשיים.', 'Спорт в Израиле — гораздо больше, чем развлечение: он служит ареной идентичности, политики и принадлежности. Названия команд, цвета маек и фанатские песни рассказывают истории о классах, партиях и этнических напряжениях.
Футбол — самый популярный вид. Дерби Маккаби — Хапоэль отражает исторические классовые напряжения. Бейтар Иерусалим с ультраправыми болельщиками стал символом политики в спорте.
В баскетболе Маккаби Тель-Авив шесть раз выигрывал Евролигу — выдающееся достижение для маленькой страны. Олимпийские игры несут особое значение: память о расстреле 11 спортсменов в Мюнхене 1972 сопровождает каждую делегацию.
Выдающиеся атлеты — Гал Фридман, Линой Ашрам, Артём Долгопят — доказали, что маленькая страна может конкурировать. Каждая медаль вызывает национальное празднование, выходящее далеко за рамки спорта.', '[{"he": "ספורט", "ru": "спорт", "translit": "спОрт"}, {"he": "דרבי", "ru": "дерби", "translit": "дЕрби"}, {"he": "מעמדי", "ru": "классовый", "translit": "маамадИ"}, {"he": "אליפות", "ru": "чемпионат", "translit": "алифУт"}, {"he": "משלחת", "ru": "делегация", "translit": "мишлАхат"}, {"he": "אתלטים", "ru": "атлеты", "translit": "атлетИм"}, {"he": "אוהדים", "ru": "болельщики", "translit": "охадИм"}, {"he": "מדליה", "ru": "медаль", "translit": "медАлья"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (301, 6, 'חוק יסוד: כבוד האדם וחירותו — ניתוח משפטי', 'Основной закон: Достоинство и свобода человека — правовой анализ', 'חוק יסוד: כבוד האדם וחירותו, שנחקק ב-1992, מהווה אבן יסוד במשפט החוקתי הישראלי ומסמן את תחילתה של מהפכה חוקתית שהשלכותיה מורגשות עד היום. החוק נחקק בלילה, בהעדר רוב חברי הכנסת, ובלי שרבים הבינו את משמעותו המלאה — עובדה שמעוררת שאלות על הלגיטימיות הדמוקרטית שלו.
החוק מעגן את הזכות לחיים, לגוף, לכבוד, לקניין, לחירות אישית ולצנעת הפרט. סעיף 1 מכריז: ''זכויות היסוד של האדם בישראל מושתתות על ההכרה בערך האדם, בקדושת חייו ובהיותו בן-חורין''. אולם בניגוד לחוקות מלאות, חוק היסוד הישראלי אינו כולל זכויות מפורשות לשוויון ולחופש הביטוי — השמטה שאינה מקרית, אלא משקפת את הפשרות הפוליטיות של השעה. זכויות אלה הוכרו בפסיקת בית המשפט העליון, שפירש את ''כבוד האדם'' פירוש רחב שכולל שוויון, חופש ביטוי, חופש מדת וחופש תנועה.
נקודת המפנה המשפטית הגדולה הגיעה בפרשת בנק המזרחי (1995). בפסק דין תקדימי, קבע הנשיא אהרן ברק שחוקי יסוד עליונים על חקיקה רגילה — כלומר, בית המשפט יכול לבטל חוקים רגילים הסותרים חוקי יסוד. זו הייתה ''המהפכה החוקתית'' של ברק: בלי שהכנסת החליטה במפורש לאמץ חוקה, בית המשפט יצר למעשה משטר חוקתי. ברק כתב: ''הכנסת שינתה את ה-DNA החוקתי של המדינה''.
ביקורת על הפסיקה מגיעה מכמה כיוונים. מהימין הפוליטי טוענים שבית המשפט נטל לעצמו סמכות שלא הוענקה לו, ושהמחוקק — ולא השופטים — צריך להגדיר את הזכויות. השופט משה לנדוי הזהיר מפני ''אקטיביזם שיפוטי'' שחותר תחת הדמוקרטיה. מצד שני, שמרנים משפטיים טוענים שהפרשנות הרחבה של ''כבוד האדם'' היא שרירותית — איך שופט אחד מחליט שכבוד האדם כולל חופש ביטוי אך לא זכות לדיור?
הדיון הזה נמצא בלב המתח בין הרשות השופטת לרשות המחוקקת בישראל — מתח שהגיע לשיאו במשבר הרפורמה המשפטית של 2023, כאשר מאות אלפים יצאו לרחובות במחאה על ניסיון לצמצם את סמכות בית המשפט. חוק היסוד הקצר — 12 סעיפים בלבד — הפך למגילת זכויות דה-פקטו, לשדה קרב פוליטי ולמראה של הוויכוח הישראלי על טיבה של הדמוקרטיה.', 'Основной закон: Достоинство и свобода человека, принятый в 1992 году, является краеугольным камнем конституционного права Израиля и знаменует начало конституционной революции. Закон был принят ночью, в отсутствие большинства депутатов Кнессета — факт, вызывающий вопросы о его демократической легитимности.
Закон закрепляет право на жизнь, тело, достоинство, собственность, свободу и неприкосновенность частной жизни. Однако он не включает явных прав на равенство и свободу слова — они были признаны через судебную практику, расширительно толкующую «достоинство человека».
Переломным стало дело Банк Мизрахи (1995): председатель суда Аарон Барак постановил, что Основные законы имеют приоритет над обычным законодательством — «конституционная революция». Критика приходит с разных сторон: правые утверждают, что суд присвоил полномочия, консерваторы — что расширительное толкование произвольно.
Этот спор в центре напряжения между судебной и законодательной властью — напряжения, достигшего пика в 2023 году. Короткий закон (12 статей) стал де-факто Биллем о правах, политическим полем битвы и зеркалом израильских дебатов о природе демократии.', '[{"he": "חוק יסוד", "ru": "Основной закон", "translit": "хОк йесОд"}, {"he": "חוקתי", "ru": "конституционный", "translit": "хукатИ"}, {"he": "פסיקה", "ru": "судебная практика", "translit": "псикА"}, {"he": "סמכות", "ru": "полномочия", "translit": "самхУт"}, {"he": "רשות שופטת", "ru": "судебная власть", "translit": "рашУт шофЕтет"}, {"he": "מחוקק", "ru": "законодатель", "translit": "мехокЕк"}, {"he": "אקטיביזם שיפוטי", "ru": "судебный активизм", "translit": "активИзм шифутИ"}, {"he": "צנעת הפרט", "ru": "частная жизнь", "translit": "цинъАт хапрАт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (302, 6, 'בראשית — קריאה ספרותית', 'Бытие — литературное прочтение', 'ספר בראשית, הראשון בחמשת חומשי תורה, מציג את סיפורי היסוד של התרבות היהודית והמערבית — סיפורים שעיצבו את הדרך שבה האנושות חושבת על בריאה, על חטא, על משפחה ועל ייעוד. בריאת העולם בששה ימים, גן עדן ועץ הדעת, קין והבל, המבול ותיבת נוח, מגדל בבל, ואבות האומה — אברהם, יצחק ויעקב — כל אלה אינם רק סיפורים דתיים, אלא טקסטים ספרותיים מורכבים ורבי-שכבות.
קריאה ספרותית-ביקורתית של בראשית חושפת מבנים נרטיביים מתוחכמים שלא היו מביישים רומן מודרני. ראשית, ההקבלות: הסיפור של קין והבל — שני אחים, אחד מועדף ואחד נדחה, שמתח ביניהם מוביל לרצח — חוזר בצורות שונות: יעקב ועשו, יוסף ואחיו, ראובן ויהודה. כל חזרה מוסיפה שכבה חדשה: אם קין רצח מתוך קנאה עיוורת, יוסף ואחיו מגיעים לסליחה.
מוטיבים חוזרים שוזרים את הספר: הבכורה (יצחק ולא ישמעאל, יעקב ולא עשו, אפרים ולא מנשה), הברכה (הברכה הגנובה, ברכת יעקב), הגלות (אברהם גולה מאור כשדים, יעקב בורח לחרן, יוסף יורד למצרים) והשיבה. מתח מתמיד שורר בין חסד לדין — אלוהים בורא עולם אך גם משמיד אותו במבול, בוחר באברהם אך גם מנסה אותו בעקידת יצחק.
הסגנון המקראי עצמו הוא מופת ספרותי. הוא תמציתי — משפטים קצרים, מעט תיאורים, כמעט ללא ביטויי רגש. ''וירא אלהים את כל אשר עשה והנה טוב מאד'' — משפט שמסכם את כל הבריאה בשש מילים. הסגנון ריב-משמעי: כל מילה נושאת כמה פירושים, וכל דור מפרש מחדש. הוא חסכני במילים ועשיר בעומק — מה שהפילוסוף אריך אוארבך כינה ''הסגנון שטעון רקע''.
רוברט אלטר, בפירושו הספרותי למקרא, הראה כיצד התנ"ך משתמש בטכניקות סיפוריות מתקדמות: דיאלוג כחשיפת אופי (מילותיו של עשו שונות ממילותיו של יעקב — גסות מול חלקלקות), חזרות עם שינויים (כל פעם שסיפור חוזר, משהו משתנה — וה''משתנה'' הוא המסר), ורווחים שהקורא ממלא (מה חשב אברהם בדרך אל הר המוריה? הטקסט שותק, והשתיקה מדברת).
בראשית הוא טקסט שלא מפסיק לחשוף שכבות חדשות בכל קריאה — הוא ספר שגיל האנושות לא הצליח למצות.', 'Книга Бытия, первая из Пятикнижия, представляет основополагающие рассказы еврейской и западной культуры — истории, сформировавшие образ мышления человечества о творении, грехе, семье и предназначении. Все они — не только религиозные тексты, но сложные многослойные литературные произведения.
Литературно-критическое прочтение обнаруживает изощрённые нарративные структуры. Параллели: история Каина и Авеля — двух братьев, одного избранного и одного отвергнутого — повторяется в разных формах: Иаков и Исав, Иосиф и братья. Повторяющиеся мотивы: первородство, благословение, изгнание и возвращение.
Библейский стиль — литературный шедевр: лаконичный, многозначный, скупой на слова и богатый глубиной. Роберт Олтер показал, как Танах использует передовые нарративные техники: диалог как раскрытие характера, повторы с вариациями и пробелы, заполняемые читателем.
Бытие — текст, который при каждом прочтении раскрывает новые слои. Книга, которую человечество за тысячелетия не смогло исчерпать.', '[{"he": "בראשית", "ru": "Бытие", "translit": "берешИт"}, {"he": "חומשי תורה", "ru": "Пятикнижие", "translit": "хумшЕй торА"}, {"he": "הקבלות", "ru": "параллели", "translit": "хакбалОт"}, {"he": "מוטיבים", "ru": "мотивы", "translit": "мотивИм"}, {"he": "ריב-משמעי", "ru": "многозначный", "translit": "рав-машмаИ"}, {"he": "פירוש", "ru": "комментарий", "translit": "перУш"}, {"he": "תמציתי", "ru": "лаконичный", "translit": "тамцитИ"}, {"he": "עקידה", "ru": "жертвоприношение Исаака", "translit": "акедА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (303, 6, 'הרמב"ם — בין הלכה לפילוסופיה', 'Маймонид — между Халахой и философией', 'משה בן מימון, הרמב"ם (1138-1204), הוא אחת הדמויות המשפיעות ביותר בהיסטוריה היהודית — רופא, פילוסוף, פוסק הלכה ומנהיג קהילתי שמורשתו מעצבת את היהדות עד היום. הוא נולד בקורדובה שבספרד, נמלט עם משפחתו לפני רדיפות האלמוחדים, חי במרוקו ובארץ ישראל, ולבסוף התיישב בפוסטאט (קהיר הישנה) שבמצרים. חייו עצמם — גלות, נדודים, אובדן — מייצגים את גורל היהודי בימי הביניים.
ב''משנה תורה'' (1180), מפעלו ההלכתי המונומנטלי, סידר הרמב"ם את כל ההלכה היהודית בצורה שיטתית — ארבעה עשר ספרים (''ספר המדע'', ''ספר אהבה'', ''ספר זמנים'' וכו'') המכסים כל תחום בחיים: מתפילה ועד נזיקין, מכשרות ועד שבת. הוא כתב בעברית ברורה ומדויקת — לא בארמית כמו התלמוד — כדי שכל יהודי יוכל ללמוד את ההלכה ללא מתווכים. הגישה הזו היתה מהפכנית: במקום ללמוד את הדיון התלמודי המסובך, אפשר לקרוא את הפסיקה ישירות.
ב''מורה הנבוכים'' (1190), יצירתו הפילוסופית, ניסה הרמב"ם ליישב בין הפילוסופיה האריסטוטלית — שנחשבה לפסגת ההגות הרציונלית — לבין האמונה היהודית. הוא טען שהתורה ניתנת לפרשנות רציונלית, ושאין סתירה בין שכל לבין אמונה — אלא שהם שני דרכים להגיע לאותה אמת. הוא טען שהאלוהות אינה ניתנת לתיאור חיובי — אפשר לומר רק מה שאלוהים אינו: ''אלוהים אינו גוף, אינו מוגבל, אינו משתנה''. גישה זו, הידועה כ''תיאולוגיה שלילית'', עדיין משפיעה על הגות דתית.
עמדתו עוררה מחלוקת חריפה ונמשכת. מצד אחד, הוא הואשם בכפירה על ידי רבנים שמרניים: הם ראו בפירוש הרציונלי של המקרא ובטיעון שאלוהים אינו גוף התרסה כנגד המסורת. ב-1232, שרפו רבני צרפת את ''מורה הנבוכים'' בפומבי — אחד הרגעים הכואבים ביותר בהיסטוריה האינטלקטואלית היהודית. מצד שני, מעריציו אמרו עליו: ''ממשה עד משה, לא קם כמשה''.
הרמב"ם שימש גם כרופא בחצרו של הסולטן צלאח א-דין במצרים — אחד המנהיגים המוסלמים החשובים ביותר בהיסטוריה. מכתביו הרפואיים נשמרו עד היום, וכוללים עצות על תזונה, שינה ובריאות הנפש שמפתיעות במודרניות שלהן. הוא כתב שרופא חייב לטפל בכל אדם — יהודי, מוסלמי או נוצרי — ללא הבחנה. דמותו של הרמב"ם מגלמת את השאיפה ליישב בין עולמות: בין קודש לחול, בין שכל לאמונה, בין יהדות לאוניברסליות.', 'Моше бен Маймон, Рамбам (1138-1204), — одна из влиятельнейших фигур еврейской истории: врач, философ, галахический авторитет и общинный лидер, чьё наследие формирует иудаизм по сей день. Его жизнь — изгнание, скитания, потери — воплощает еврейскую судьбу Средневековья.
В «Мишне Тора» (1180) он систематизировал всю еврейскую Халаху — 14 книг, покрывающих все сферы жизни. Он писал на ясном иврите, а не на арамейском, чтобы каждый еврей мог изучать закон без посредников — революционный подход.
В «Путеводителе растерянных» (1190) он попытался примирить аристотелевскую философию с еврейской верой, утверждая, что разум и вера — два пути к одной истине. Его позиция вызвала острые споры: консервативные раввины обвиняли его в ереси, в 1232 году его книгу публично сожгли. Но почитатели говорили: «от Моше до Моше не было подобного Моше».
Рамбам служил врачом при дворе Саладина и лечил всех — евреев, мусульман, христиан — без различия. Его фигура воплощает стремление примирить миры: святое и мирское, разум и веру, иудаизм и универсальность.', '[{"he": "הלכה", "ru": "Халаха (еврейский закон)", "translit": "халахА"}, {"he": "מורה הנבוכים", "ru": "Путеводитель растерянных", "translit": "морЕ хановухИм"}, {"he": "פרשנות", "ru": "интерпретация", "translit": "паршанУт"}, {"he": "רציונלי", "ru": "рациональный", "translit": "рационАли"}, {"he": "כפירה", "ru": "ересь", "translit": "кфирА"}, {"he": "שמרני", "ru": "консервативный", "translit": "шамранИ"}, {"he": "תיאולוגיה שלילית", "ru": "негативная теология", "translit": "теолОгия шлилИт"}, {"he": "פוסק הלכה", "ru": "галахический авторитет", "translit": "посЕк халахА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (304, 6, 'גרשם שלום והקבלה', 'Гершом Шолем и Каббала', 'גרשם שלום (1897-1982) חולל מהפכה אינטלקטואלית בחקר היהדות כאשר הפך את המיסטיקה היהודית — הקבלה — מתחום שולי, מביך כמעט, לתחום אקדמי מרכזי שחשף ממדים לא-ידועים של ההיסטוריה היהודית. לפניו, חוקרי יהדות מתנועת ''חכמת ישראל'' (הוויסנשאפט) ניסו להציג את היהדות כדת רציונלית, נאורה ו''מערבית''. הם התביישו בקבלה ובמיסטיקה וניסו להתעלם מהן. שלום הראה שההתעלמות הזו מוציאה מהתמונה זרם מרכזי ביהדות.
במחקרו המונומנטלי ''זרמים עיקריים במיסטיקה היהודית'' (1941), שלום הראה כיצד הקבלה התפתחה לאורך מאות שנים: מתנועות גנוסטיות קדומות ומספרות ההיכלות (מרכבה) של ראשית הספירה, דרך ספר ה''בהיר'' ו''ספר היצירה'', והגיעה לשיאה בשני ציוני דרך מרכזיים. הראשון — ספר הזוהר (המאה ה-13), שנכתב ככל הנראה על ידי משה דה-לאון בספרד, אך מיוחס לרבי שמעון בר יוחאי. הזוהר מציג מערכת מיסטית שלמה: עשר ספירות (אלוהיות) שדרכן מתגלה האלוהות בעולם, מגוון שער האדם ועד אין-סוף. השני — קבלת האר"י (רבי יצחק לוריא) בצפת (המאה ה-16), שהציגה את מושגי הצמצום (אלוהים ''צמצם'' עצמו כדי ליצור מקום לעולם), שבירת הכלים (הניצוצות האלוהיים נפלו לתוך הקליפות — הרוע) ותיקון העולם (משימת האדם להעלות את הניצוצות ולתקן).
שלום טען שהקבלה אינה רק מיסטיקה אישית — היא תנועה היסטורית שעיצבה את היהדות. מושג ''תיקון עולם'', שהפך לסיסמא של יהדות ליברלית בארצות הברית, מקורו בקבלת האר"י. המושגים המיסטיים חלחלו לתפילה, למנהגים ולתרבות היהודית כולה — גם אצל מי שאינם יודעים את מקורם.
שבתאי צבי, המשיח המדומה של המאה ה-17, הוא דוגמה לכוח ההרסני של מיסטיקה שיוצאת משליטה. שלום הקדיש לו ביוגרפיה ענקית (''שבתאי צבי — המשיח המיסטי'', 1957) והראה כיצד משיחיות מיסטית יכולה לשטוף קהילות שלמות ולמוטט אותן כשהחלום מתנפץ. כאשר שבתאי צבי המיר לאסלאם ב-1666, הטראומה פגעה ביהדות כולה ושינתה את יחסה למיסטיקה ולמשיחיות.
מורשתו של שלום ממשיכה להשפיע. תלמידיו — יוסף דן, משה אידל, חביבה פדיה — פיתחו את המחקר לכיוונים חדשים. אידל, למשל, חלק על שלום וטען שהקבלה אינה תגובה היסטורית לאירועים, אלא מסורת מיסטית רציפה שמעבירה חוויות מדור לדור. הוויכוח הזה — האם הקבלה היא היסטוריה או חוויה — ממשיך לתת פירות במחקר.', 'Гершом Шолем (1897-1982) произвёл интеллектуальную революцию, превратив еврейскую мистику — Каббалу — из маргинальной и почти смущающей области в центральную академическую дисциплину. До него исследователи иудаизма пытались представить его рациональной религией и стеснялись мистики. Шолем показал, что это игнорирование искажает картину.
В монументальном труде «Основные течения в еврейской мистике» (1941) он проследил развитие Каббалы от ранних гностических движений через Книгу Зоар (XIII в.) до Каббалы Ари в Цфате (XVI в.). Зоар представляет цельную мистическую систему: десять сфирот, через которые божество проявляется в мире. Каббала Ари ввела понятия цимцум, разбиения сосудов и тиккун олам.
Шолем утверждал, что Каббала — не только личная мистика, но историческое движение, сформировавшее иудаизм. Шабтай Цви — пример разрушительной силы мистики, вышедшей из-под контроля. Наследие Шолема продолжает влиять: его ученики развивают исследования в новых направлениях.', '[{"he": "קבלה", "ru": "Каббала", "translit": "кабалА"}, {"he": "מיסטיקה", "ru": "мистика", "translit": "мИстика"}, {"he": "ספירות", "ru": "сфирот (эманации)", "translit": "сфирОт"}, {"he": "צמצום", "ru": "цимцум (сжатие)", "translit": "цимцУм"}, {"he": "זוהר", "ru": "Зоар", "translit": "зОhар"}, {"he": "גנוסטי", "ru": "гностический", "translit": "гнОсти"}, {"he": "תיקון עולם", "ru": "тиккун олам (исправление мира)", "translit": "тикУн олАм"}, {"he": "משיחיות", "ru": "мессианизм", "translit": "мешихиЮт"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (305, 6, 'הכרזת העצמאות — מסמך מייסד', 'Декларация независимости — основополагающий документ', 'מגילת העצמאות של מדינת ישראל, שהוקראה על ידי דוד בן-גוריון ב-14 במאי 1948 במוזיאון תל אביב, היא יותר ממסמך היסטורי — היא מצפן ערכי שמנחה את השיח הציבורי בישראל עד היום. בדומה להכרזת העצמאות האמריקנית, היא מנסחת את העקרונות שעליהם מבוססת המדינה — אך בניגוד לחוקה, אין לה מעמד משפטי מחייב. הפרדוקס הזה — מסמך שכולם מכבדים אך אינו אוכף — מלווה את ישראל מיום הקמתה.
המגילה משלבת שלושה נרטיבים. הנרטיב ההיסטורי: ''בארץ ישראל קם העם היהודי. בה עוצבה דמותו הרוחנית, הדתית והמדינית'' — קביעה שמקשרת את עם ישראל לארצו ההיסטורית. הנרטיב הבינלאומי: הצהרת בלפור (1917), הכרת חבר הלאומים ב''קשר ההיסטורי'' של העם היהודי, ובמיוחד החלטת האו"ם מנובמבר 1947 על חלוקת ארץ ישראל — שמעניקה לגיטימציה משפטית בינלאומית. והנרטיב הערכי: חזון של חברה צודקת.
המגילה מבטיחה ''שוויון זכויות חברתי ומדיני גמור לכל אזרחיה בלי הבדל דת, גזע ומין; חופש דת, מצפון, לשון, חינוך ותרבות''. הבטחה זו נותרה נתונה במחלוקת עמוקה: תומכי המיעוט הערבי טוענים שהיא לא מומשה במלואה, ותומכי ''מדינה יהודית'' טוענים שהיא חייבת להיקרא לצד ''חוק הלאום'' (2018) שקובע ש''ישראל היא מדינת הלאום של העם היהודי''. המתח בין שני המרכיבים — מדינה יהודית ומדינה דמוקרטית — הוא אולי הקונפליקט הפנימי העמוק ביותר של ישראל.
מבחינה משפטית, בית המשפט העליון התייחס למגילה כ''אמנת יסוד'' המנחה את פרשנות החוק — בדומה לפסיקות של בית המשפט העליון בארצות הברית שמסתמכות על ''רוח'' ההכרזה. השופט ברק כתב ש''ערכיה של מדינת ישראל כמדינה יהודית ודמוקרטית'' — ביטוי המופיע בחוקי יסוד — נשאבים ממגילת העצמאות.
השאלה כיצד לממש את הערכים שנוסחו ב-1948 מלווה את החברה הישראלית עד היום. האם המגילה היא מפת דרכים לעתיד, או תיאור אידיאלי שמעולם לא התכוונו ליישם? כאשר מגילת העצמאות מוקראת בטקסים רשמיים ביום העצמאות, יש הנרגשים מהחזון — ויש השואלים מדוע הוא עדיין לא מומש.', 'Декларация независимости Государства Израиль, зачитанная Бен-Гурионом 14 мая 1948 года, — больше чем исторический документ: это ценностный компас, направляющий израильский дискурс по сей день. Подобно американской Декларации, она формулирует основополагающие принципы — но в отличие от конституции, не имеет обязательной силы.
Декларация сочетает три нарратива: историческую связь еврейского народа с Землёй Израиля, международное признание и видение справедливого общества. Она обещает «полное равноправие всем гражданам без различия религии, расы и пола» — обещание, остающееся предметом споров.
Напряжение между «еврейским государством» и «демократическим государством» — возможно, глубочайший внутренний конфликт Израиля. Верховный суд рассматривает Декларацию как «основную хартию», направляющую интерпретацию закона. Вопрос реализации ценностей 1948 года сопровождает израильское общество по сей день.', '[{"he": "מגילת העצמאות", "ru": "Декларация независимости", "translit": "мегилАт хаацмаУт"}, {"he": "מצפן", "ru": "компас", "translit": "мацпЕн"}, {"he": "נרטיב", "ru": "нарратив", "translit": "наратИв"}, {"he": "אמנה", "ru": "хартия", "translit": "аманА"}, {"he": "פרשנות", "ru": "интерпретация", "translit": "паршанУт"}, {"he": "מחייב", "ru": "обязательный", "translit": "мехаЕв"}, {"he": "חוק הלאום", "ru": "Закон о национальности", "translit": "хОк халеОм"}, {"he": "לגיטימציה", "ru": "легитимация", "translit": "легитимАция"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (306, 6, 'עקרון המידתיות בדין הישראלי', 'Принцип соразмерности в израильском праве', 'עקרון המידתיות הוא אחד העקרונות החשובים ביותר במשפט החוקתי הישראלי — ובמשפט החוקתי הבינלאומי בכלל. הוא משמש כמנגנון לאיזון בין זכויות הפרט לבין אינטרסים ציבוריים, ומספק כלי לבית המשפט לבחון האם הגבלת זכויות מוצדקת או חורגת מהנדרש.
בדין הישראלי, העיקרון מעוגן בפסקת ההגבלה של חוק יסוד: כבוד האדם וחירותו (סעיף 8): ''אין פוגעים בזכויות שלפי חוק יסוד זה אלא בחוק ההולם את ערכיה של מדינת ישראל, שנועד לתכלית ראויה, ובמידה שאינה עולה על הנדרש''. שלוש הדרישות האחרונות — חוק הולם, תכלית ראויה ומידתיות — מהוות את ''מבחן המידתיות''.
בפסיקת בית המשפט העליון, העיקרון פורט לשלושה מבחני משנה. מבחן הקשר הרציונלי: האם האמצעי שנבחר באמת מקדם את התכלית? למשל, האם איסור על הפגנות באמת מגן על ביטחון הציבור, או שזה תירוץ? מבחן האמצעי שפגיעתו פחותה: האם ניתן להשיג את אותה תכלית באמצעי שפוגע פחות בזכויות? למשל, האם אפשר להגביל הפגנה במקום לאסור אותה? ומבחן המידתיות במובן הצר: האם התועלת מן הפגיעה עולה על הנזק שהיא גורמת? כאן בית המשפט שוקל — תרתי משמע — את האינטרסים מול הזכויות.
עיקרון המידתיות מיושם בהכרעות מגוונות ורגישות: הגבלת הפגנות בזמן מלחמה, מעצר מנהלי (מעצר ללא משפט מטעמי ביטחון), הריסת בתים של משפחות מחבלים, חיפושים משטרתיים ופרופילינג. כל אחד מהמקרים האלה מציב דילמות אמיתיות: כיצד לאזן בין ביטחון לחירות? בין הגנה על הציבור לכבוד הפרט?
ביקורת על השימוש במבחן המידתיות מגיעה משני כיוונים. מימין טוענים שבית המשפט משתמש בעיקרון כדי להחליש את כלי הביטחון של המדינה. משמאל טוענים שהמבחן מאפשר לבית המשפט ''להכשיר'' פגיעות בזכויות בטענה שהן ''מידתיות''. המשפטן דוד קרצמר טען שהמידתיות היא ''מושג ריק'' שבית המשפט ממלא בתוכן על פי שיקוליו — ולכן הוא אינו מגביל באמת את השלטון.', 'Принцип соразмерности — один из важнейших в конституционном праве Израиля и международном праве в целом. Он служит механизмом баланса между правами личности и общественными интересами.
В израильском праве принцип закреплён в ограничительной оговорке Основного закона: права нельзя нарушать иначе как законом, соответствующим ценностям государства, предназначенным для достойной цели и в необходимой мере.
Судебная практика разбила принцип на три подтеста: рациональная связь (продвигает ли средство цель?), наименее ущемляющее средство (можно ли достичь цели менее вредным способом?) и соразмерность в узком смысле (превышает ли польза вред?).
Принцип применяется к ограничению демонстраций, административному задержанию, сносу домов и полицейским обыскам. Критика приходит с обеих сторон: правые считают, что суд ослабляет безопасность, левые — что суд легитимизирует нарушения прав.', '[{"he": "מידתיות", "ru": "соразмерность", "translit": "мидатиЮт"}, {"he": "פסקת הגבלה", "ru": "ограничительная оговорка", "translit": "пискАт хагбалА"}, {"he": "תכלית", "ru": "цель", "translit": "тахлИт"}, {"he": "מבחן", "ru": "тест/критерий", "translit": "мивхАн"}, {"he": "מעצר מנהלי", "ru": "административное задержание", "translit": "маацАр минхалИ"}, {"he": "הכרעות", "ru": "решения/постановления", "translit": "хахраОт"}, {"he": "פרופילינג", "ru": "профилирование", "translit": "профАйлинг"}, {"he": "פסקת הגבלה", "ru": "ограничительная клауза", "translit": "пискАт хагбалА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (307, 6, 'חנה ארנדט ומשפט אייכמן', 'Ханна Арендт и процесс Эйхмана', 'כאשר חנה ארנדט, פילוסופית יהודית-גרמנית-אמריקנית ותלמידתו של מרטין היידגר, הגיעה לירושלים ב-1961 כדי לסקר את משפט אדולף אייכמן עבור ה''ניו יורקר'', היא לא ידעה שתטבע מונח שייכנס להיסטוריה ויעורר סערה שלא שככה עד היום: ''הבנאליות של הרוע''.
אייכמן, קצין SS שהיה אחראי על לוגיסטיקת ''הפתרון הסופי'' — הסעת מיליוני יהודים למחנות ההשמדה — נחטף על ידי המוסד מארגנטינה ב-1960 והועמד לדין בירושלים. ארנדט ציפתה לראות מפלצת — רוצח אידיאולוגי מונע שנאה. במקום זאת, היא ראתה בירוקרט אפור ומשעמם: אדם שלא חשב עצמאית, לא שפט מוסרית, רק ביצע פקודות ודאג לקידום בקריירה. ''הוא לא היה טיפש'', כתבה ארנדט, ''אלא חסר מחשבה'' — ובחוסר המחשבה הזה נמצא הרוע.
טענתה עוררה זעם עצום, מכמה כיוונים. ראשית, רבים ראו בה הקטנה של השואה: אם אייכמן הוא רק בירוקרט, איפה הרוע המוחלט? הביקורת הייתה שארנדט מנרמלת את הפושעים ומחלישה את ייחודיות השואה. שנית, ארנדט ביקרה את המנהיגות היהודית באירופה — את ''היודנראטים'' (מועצות היהודים) — על שיתוף פעולה עם הנאצים, טענה שזיעזעה את הניצולים ועוררה כעס רב בישראל.
אך ארנדט התכוונה להפך ממה שרבים הבינו: לא להקטין את הרוע, אלא להתריע שרוע אינו דורש אידיאולוגיה שטנית או שנאה מיוחדת — הוא עשוי לנבוע מחוסר מחשבה, מצייתנות עיוורת, מסירוב לחשוב על משמעות המעשים. המסר היה מפחיד יותר מ''מפלצת'': כל אדם, בנסיבות מסוימות, עלול להפוך לאייכמן.
הביקורת על ארנדט מגיעה מכמה כיוונים אקדמיים. היסטוריונים כמו דוד צזרני הראו שאייכמן היה אנטישמי נלהב יותר ממה שארנדט תיארה — הוא לא רק ''ביצע פקודות'' אלא יזם ודחף לקצב מהיר יותר של רצח. הפילוסופית בטינה שטנת, בספרה ''אייכמן לפני ירושלים'' (2011), חשפה ראיונות שאייכמן נתן בארגנטינה שבהם הוא מביע גאווה בתפקידו ושנאה ליהודים — ההפך מהדמות ה''בנאלית'' שארנדט תיארה.
למרות המחלוקות, ''הבנאליות של הרוע'' נותר מושג יסוד בפילוסופיה המוסרית — אזהרה מפני הסכנות של ציות עיוור ושל ''חוסר מחשבה''. ב-2012 הוסרט סרט על ארנדט בירושלים (בימוי מרגרטה פון טרוטה), שהחזיר את הוויכוח לשיח הציבורי.', 'Когда Ханна Арендт, еврейско-немецко-американский философ и ученица Хайдеггера, прибыла в Иерусалим в 1961 году освещать суд над Эйхманом для «Нью-Йоркера», она не знала, что создаст термин, вошедший в историю: «банальность зла».
Эйхман, офицер SS, ответственный за логистику «окончательного решения», был похищен Моссадом из Аргентины. Арендт ожидала монстра — увидела серого бюрократа: человека, не думавшего самостоятельно, не судившего морально, лишь выполнявшего приказы. «Он не был глуп — он был бездумен».
Тезис вызвал гнев: многие увидели умаление Холокоста. Арендт также критиковала еврейское руководство — юденраты — за сотрудничество с нацистами. Но её замысел был иным: предупредить, что зло может проистекать из бездумности, слепого подчинения. Любой человек при определённых обстоятельствах может стать Эйхманом.
Историки показали, что Эйхман был более ревностным антисемитом, чем Арендт его описала. Несмотря на споры, «банальность зла» остаётся фундаментальным понятием моральной философии — предупреждением об опасностях слепого подчинения.', '[{"he": "בנאליות", "ru": "банальность", "translit": "бэналиЮт"}, {"he": "בירוקרט", "ru": "бюрократ", "translit": "бирокрАт"}, {"he": "להתריע", "ru": "предупредить", "translit": "лехатрИа"}, {"he": "אנטישמי", "ru": "антисемитский", "translit": "антишемИ"}, {"he": "אידיאולוגיה", "ru": "идеология", "translit": "идеолОгия"}, {"he": "מוסרי", "ru": "моральный", "translit": "мусарИ"}, {"he": "צייתנות", "ru": "конформизм/послушание", "translit": "цайтанУт"}, {"he": "מנרמל", "ru": "нормализует", "translit": "менармЕль"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (308, 6, 'הטקסט התלמודי — מבנה ולוגיקה', 'Талмудический текст — структура и логика', 'התלמוד הוא אחד הטקסטים המורכבים ביותר שנוצרו אי פעם — גוף ספרותי ענק בן אלפי דפים שעוסק בכל תחום בחיים: מתפילה ועד נזיקין, מטומאה וטהרה ועד עסקאות מסחריות, מדיני שבת ועד ויכוחים פילוסופיים על טבע האלוהות. הוא נלמד ברצף של כ-1,500 שנה, ועד היום יותר מ-100,000 אנשים ברחבי העולם לומדים ''דף יומי'' — עמוד תלמוד אחד ביום.
מבנית, התלמוד מורכב משני שכבות עיקריות: המשנה — הקודיפיקציה של ההלכה שבעל-פה, שנערכה על ידי רבי יהודה הנשיא בסביבות שנת 200 לספירה, ומאורגנת בשישה ''סדרים'' ו-63 מסכתות — והגמרא — הדיון הנרחב על המשנה בבתי המדרש של בבל (התלמוד הבבלי) ושל ארץ ישראל (התלמוד הירושלמי), עד המאה ה-5. הגמרא אינה פרשנות ליניארית למשנה: היא קופצת בין נושאים, מביאה מקורות ממקומות מפתיעים, ולעיתים סוטה לדיונים שנראים לא-קשורים — אך תמיד חוזרת.
מבנה הדף התלמודי ייחודי ומוכר: במרכז — הטקסט המקורי (משנה וגמרא), מימין — פירוש רש"י (רבי שלמה יצחקי, צרפת, המאה ה-11), שמפשט את הטקסט; ומשמאל — התוספות (פרשנים צרפתיים-גרמניים מהמאות ה-12-13), שמקשים ומעמיקים. כך, כל דף מכיל לפחות שלושה קולות מתקופות שונות — מעין דיאלוג חוצה-זמנים.
הלוגיקה התלמודית מבוססת על מחלוקת מובנית. כל טענה נבחנת מכל הכיוונים: מועלות קושיות (''איתיביה'' — הקשו עליו), מובאים מקורות סותרים, ומנוסחים תירוצים. לעיתים הדיון נשאר ללא הכרעה — ''תיקו'' (תשבי יתרץ קושיות ובעיות — כלומר, אליהו הנביא יפתור בבוא היום). ההשלמה עם חוסר הכרעה היא ערך בפני עצמו: לא כל שאלה חייבת תשובה.
השיטה הזו השפיעה עמוקות על אופן החשיבה היהודי: פלורליזם רעיוני (מחלוקת לשם שמיים — ''אלו ואלו דברי אלהים חיים''), הערכה של ויכוח מנומק, וההבנה שאין תשובה אחת לכל שאלה. חוקרי תלמוד מודרניים כמו דוד הלבני בחנו את שכבות העריכה בגמרא, וחיים סולובייצ''יק חקר כיצד דפוסי למידה השתנו עם המעבר מתרבות בעל-פה לתרבות כתובה.', 'Талмуд — один из сложнейших текстов, когда-либо созданных: гигантский корпус из тысяч страниц, охватывающий все сферы жизни. Его изучают непрерывно уже 1500 лет, и сегодня более 100 000 человек по всему миру учат «даф йоми» — страницу Талмуда в день.
Структурно Талмуд состоит из Мишны (кодификация устного закона, ок. 200 г. н.э.) и Гемары (обсуждение Мишны в домах учения Вавилона и Палестины). Гемара — не линейный комментарий: она скачет между темами, привлекает неожиданные источники и порой уходит в кажущиеся несвязанными дискуссии.
Структура талмудической страницы уникальна: в центре — оригинальный текст, справа — комментарий Раши, слева — Тосафот. Каждая страница содержит минимум три голоса из разных эпох — своего рода диалог сквозь время.
Талмудическая логика основана на институционализированном споре: каждое утверждение проверяется со всех сторон, иногда обсуждение остаётся без решения («тейку»). Этот метод повлиял на еврейское мышление: плюрализм, спор во имя небес, понимание, что не на каждый вопрос существует единственный ответ.', '[{"he": "תלמוד", "ru": "Талмуд", "translit": "талмУд"}, {"he": "משנה", "ru": "Мишна", "translit": "мишнА"}, {"he": "גמרא", "ru": "Гемара", "translit": "гмарА"}, {"he": "קושיות", "ru": "возражения", "translit": "кушиЙот"}, {"he": "פלורליזם", "ru": "плюрализм", "translit": "плуралИзм"}, {"he": "עריכה", "ru": "редактирование", "translit": "арихА"}, {"he": "מסכתות", "ru": "трактаты", "translit": "масехтОт"}, {"he": "תירוצים", "ru": "ответы/решения", "translit": "тируцИм"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (309, 6, 'לוינס — האתיקה כפילוסופיה ראשונה', 'Левинас — этика как первая философия', 'עמנואל לוינס (1906-1995), הוגה יהודי-צרפתי שנולד בקובנה שבליטא ושרד את השואה כשבוי מלחמה, הציע תפיסה פילוסופית רדיקלית שמציבה את האתיקה — ולא את האונטולוגיה — כפילוסופיה ראשונה. המהלך הזה, שנראה טכני, הוא למעשה מהפכני: במשך 2,500 שנה, הפילוסופיה המערבית שאלה ''מה קיים?'' (אונטולוגיה). לוינס אומר: השאלה הראשונה היא לא ''מה קיים?'' אלא ''מה אני חייב לאחר?''
לפי לוינס, המפגש עם פניו של האחר הוא האירוע המכונן של הקיום האנושי. הפנים של הזולת — לא כמראה חיצוני, אלא כנוכחות שקוראת לי — קוראות ''לא תרצח''. הן מטילות עליי אחריות אינסופית: לא רק שלא לפגוע, אלא לדאוג, להאכיל, לשמוע, להגן. ואני לא יכול לברוח מהאחריות הזו, גם אם לא ביקשתי אותה — היא קודמת לכל בחירה.
תפיסה זו עומדת בניגוד חד לפילוסופיה המערבית מדקארט ועד היידגר, שמתחילה מה''אני'' — ה''קוגיטו'', התודעה, הדאזיין. לוינס טען שה''אני'' נבנה רק דרך המפגש עם ה''אתה'': בלי האחר, אין לי משמעות. הזהות שלי נוצרת מהתגובה שלי לקריאה של האחר — לא מהרהורים עצמיים.
הרעיונות של לוינס השפיעו על תחומים מגוונים: תיאולוגיה (כיצד לחשוב על האלוהי אחרי השואה?), אתיקה רפואית (החולה כ''פנים'' שמחייבות), משפט (זכויות האדם כמבוססות על אחריות לאחר) ותיאוריה פוליטית. ז''אק דרידה, שהושפע עמוקות מלוינס, שאל האם ניתן באמת לחשוב על ''אחרות'' מוחלטת — או שכל ניסיון לתאר את האחר כבר מכיל אותו בתוך ה''אני''. ביקורת נוספת: לוינס לא הרחיב את האתיקה שלו מספיק מעבר ליחסים בין-אישיים לתחום הפוליטי — כיצד מתנהגת אתיקה של ''פנים'' כשיש מיליונים של פנים?
ובהקשר הישראלי: לוינס עצמו התקשה ליישם את הפילוסופיה שלו על הקונפליקט הישראלי-פלסטיני. בראיון מפורסם אחרי טבח סברא ושתילה (1982), כשנשאל אם הפלסטיני הוא ''האחר'' שאליו הוא מתכוון, תשובתו הייתה מתחמקת. הפער בין התיאוריה לפרקטיקה הוא חלק מהמורשת המורכבת שלו.', 'Эммануэль Левинас (1906-1995), еврейско-французский мыслитель, переживший Холокост как военнопленный, предложил радикальную философию: этика — а не онтология — является первой философией. На протяжении 2500 лет философия спрашивала «что существует?». Левинас говорит: первый вопрос — «что я должен другому?»
Встреча с лицом Другого — основополагающее событие существования. Лицо обращается ко мне «не убий» и налагает бесконечную ответственность, от которой невозможно уклониться. «Я» строится только через встречу с «ты».
Идеи Левинаса повлияли на теологию, медицинскую этику, право и политическую теорию. Деррида спрашивал, можно ли мыслить абсолютную «инаковость». Критики указывают, что Левинас не распространил этику за пределы межличностных отношений.
В израильском контексте: сам Левинас затруднялся применить свою философию к израильско-палестинскому конфликту. Разрыв между теорией и практикой — часть его сложного наследия.', '[{"he": "אתיקה", "ru": "этика", "translit": "Этика"}, {"he": "אונטולוגיה", "ru": "онтология", "translit": "онтолОгия"}, {"he": "פנים", "ru": "лицо", "translit": "панИм"}, {"he": "אחריות", "ru": "ответственность", "translit": "ахраЮт"}, {"he": "אחרות", "ru": "инаковость", "translit": "ахерУт"}, {"he": "תיאולוגיה", "ru": "теология", "translit": "теолОгия"}, {"he": "קוגיטו", "ru": "когито", "translit": "когИто"}, {"he": "מכונן", "ru": "основополагающий", "translit": "мехонЕн"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (310, 6, 'שירו של ביאליק "בעיר ההריגה" — ניתוח', 'Поэма Бялика «В городе резни» — анализ', 'חיים נחמן ביאליק (1873-1934), שכונה ''המשורר הלאומי'', כתב את ''בעיר ההריגה'' (1903) בעקבות פוגרום קישינב — אחד הפוגרומים הקשים ביותר ברוסיה הצארית, שבו נרצחו 49 יהודים, נפצעו מאות ונהרסו בתים רבים. ביאליק נשלח לקישינב על ידי ועד חובבי ציון כדי לתעד את מה שקרה — אך במקום דו"ח עובדתי, הוא כתב שיר שנכנס להיסטוריה.
השיר, שנכתב בלשון מקראית-נבואית, אינו מתאר רק את הזוועה — הוא מפנה את הזעם לכמה כיוונים בו-זמנית. כלפי הפוגרומצ''יקים — ברור. אך בצורה מפתיעה ומכאיבה, גם כלפי הקורבנות שלא התגוננו: ''ובבואך מחר אל המחבוא / ומצאת שם את המנמרים אשר נחבאו / בחורים ואבות, ארבעים ושמונה נפשות / נפשות מתות שלא ידעו למה''. הביקורת כלפי הפאסיביות היהודית בגלות — ההשלמה עם התפקיד של קורבן — הפכה למניע רעיוני מרכזי של התנועה הציונית. ''לא נהיה עוד כבשים לטבח'' — זה המסר שהתנועה הציונית קראה מהשיר.
מבחינה פואטית, השיר מציג ניגודים חדים: שמיים אדישים מול זוועה ארצית (''השמש זרחה, השיטה פרחה, והשוחט שחט''), יופי הטבע מול אכזריות האדם, קדושת החיים מול חוסר-אונים מוחלט. ביאליק משתמש בלשון מקראית ונבואית — הוא עצמו כנביא המוכיח את עמו, כירמיהו שמתריע על חורבן. אך בניגוד לנביאי המקרא, הוא אינו מבטיח גאולה — רק מאשים.
הביקורת הספרותית המודרנית חשפה שכבות נוספות בשיר. החוקר חנן הבר הראה כיצד ביאליק מבנה ''מסע'' — הקורא נכנס לעיר ההרוגה כמו מבקר, ומגלה בהדרגה את מלוא הזוועה. דן מירון ניתח את המתח בין הקול האישי של המשורר לקול הקולקטיבי-הלאומי שמוטל עליו.
''בעיר ההריגה'' שינה את מקומו של המשורר בתרבות העברית: מאמן ליטרלי — כותב שירים יפים — לקול מוסרי ולאומי. ביאליק הפך ל''מוסד'', למשורר-נביא שדבריו מצוטטים בטקסים, בנאומים ובבתי ספר. השאלה האם שיר יכול לשנות את ההיסטוריה — ביאליק הוכיח שכן.', 'Хаим Нахман Бялик (1873-1934), «национальный поэт», написал «В городе резни» (1903) после кишинёвского погрома — одного из тяжелейших в царской России. Бялик был послан документировать произошедшее, но вместо отчёта написал поэму, вошедшую в историю.
Поэма, написанная библейско-пророческим языком, направляет гнев не только на погромщиков, но и на жертв, не оборонявшихся. Критика еврейской пассивности стала идейным двигателем сионизма: «мы больше не будем овцами на заклание».
Поэтически произведение представляет резкие контрасты: равнодушное небо против ужаса, красота природы против жестокости. Бялик использует пророческий язык — но в отличие от библейских пророков не обещает избавления, лишь обвиняет.
«В городе резни» изменила роль поэта в ивритской культуре: от литератора к моральному и национальному голосу. Может ли стихотворение изменить историю? Бялик доказал, что да.', '[{"he": "פוגרום", "ru": "погром", "translit": "погрОм"}, {"he": "זוועה", "ru": "ужас", "translit": "заваА"}, {"he": "פאסיביות", "ru": "пассивность", "translit": "пасивиЮт"}, {"he": "נבואי", "ru": "пророческий", "translit": "невуИ"}, {"he": "מכוננת", "ru": "основополагающая", "translit": "мехонЕнет"}, {"he": "גלות", "ru": "диаспора/изгнание", "translit": "галУт"}, {"he": "חוסר-אונים", "ru": "бессилие", "translit": "хОсер-онИм"}, {"he": "פוגרומצ''יקים", "ru": "погромщики", "translit": "погромчикИм"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (311, 6, 'הפלורליזם המשפטי בישראל', 'Правовой плюрализм в Израиле', 'ישראל מתנהלת תחת מערכת משפטית מרובדת שמקורותיה בתקופות שונות ובמסורות משפטיות שונות — מצב שנקרא ''פלורליזם משפטי''. שורשי המערכת נמצאים במשפט העות''מאני (שאימץ את חוק ה''מג''לה''), במשפט המנדט הבריטי (שהשאיר חוקים רבים שעדיין תקפים), במשפט העברי (ההלכה), ובחקיקה ישראלית עצמאית שנוספה מאז 1948. התוצאה היא שכבות חוקיות שלעיתים סותרות זו את זו.
בתחום דיני המעמד האישי — נישואין, גירושין וירושה — שולטים בתי דין דתיים, בהתאם לעיקרון שישראל ירשה מהבריטים: כל עדה דתית דנה את חבריה. הרבנות הראשית שולטת בענייני נישואין וגירושין של יהודים, בתי דין שרעיים — למוסלמים, בתי דין עדתיים — לנוצרים ולדרוזים. מצב זה יוצר מציאות אבסורדית: אזרחים שונים באותה מדינה כפופים לדינים שונים לחלוטין, בהתאם לדתם — ולא בהתאם לבחירתם.
ההשלכות הפרקטיות חמורות. זוגות חסרי דת — שאינם שייכים לשום עדה — אינם יכולים להינשא בישראל כלל. זוגות מעורבים (יהודי-נוצרי, יהודי-מוסלמי) — לא. בני אותו מין — ודאי שלא. עשרות אלפי ישראלים נוסעים בכל שנה לקפריסין, לפראג או לניו יורק כדי להתחתן בנישואין אזרחיים — שישראל מכירה בהם אך אינה מאפשרת לקיים בשטחה.
הוויכוח על נישואין אזרחיים נמשך עשרות שנים. מצד אחד, רוב הציבור היהודי (כ-70% בסקרים) תומך בנישואין אזרחיים. מצד שני, המפלגות הדתיות — שהן שותפות קואליציוניות הכרחיות כמעט תמיד — מתנגדות בתוקף. הפרדוקס: הרוב רוצה שינוי, אך המערכת הפוליטית אינה מסוגלת לייצר אותו.
פרופ'' מנחם מאוטנר מהפקולטה למשפטים בתל אביב כתב רבות על ''ירידת הפורמליזם'' במשפט הישראלי ועל המעבר מגישה פוזיטיביסטית — החוק הוא מה שכתוב — לגישות ערכיות שבהן בית המשפט שוקל ערכים מוסריים ולא רק טקסטים. הוויכוח על מקומם של הדין הדתי והמשפט האזרחי בישראל משקף את המתח העמוק ביותר: בין מדינה דמוקרטית למדינה יהודית.', 'Израиль действует в многослойной правовой системе из разных эпох и традиций — «правовой плюрализм». Корни — в османском, британском мандатном, еврейском религиозном и собственно израильском праве.
В сфере личного статуса — брак, развод, наследство — господствуют религиозные суды: раввинат для евреев, шариатские для мусульман, общинные для христиан и друзов. Это создаёт абсурдную реальность: граждане одного государства подчиняются разным законам в зависимости от религии.
Нерелигиозные, смешанные и однополые пары не могут вступить в брак в Израиле — десятки тысяч ежегодно едут на Кипр. Дискуссия о гражданском браке длится десятилетия: 70% населения за, но религиозные партии блокируют. Парадокс: большинство хочет изменений, но политическая система не может их произвести.
Спор о месте религиозного и гражданского права отражает глубочайшее напряжение между демократическим и еврейским государством.', '[{"he": "פלורליזם משפטי", "ru": "правовой плюрализм", "translit": "плуралИзм мишпатИ"}, {"he": "מעמד אישי", "ru": "личный статус", "translit": "маамАд ишИ"}, {"he": "גירושין", "ru": "развод", "translit": "герушИн"}, {"he": "נישואין אזרחיים", "ru": "гражданский брак", "translit": "нисуИн эзрахиИм"}, {"he": "פורמליזם", "ru": "формализм", "translit": "формалИзм"}, {"he": "בתי דין", "ru": "суды", "translit": "батЕй дИн"}, {"he": "פוזיטיביזם", "ru": "позитивизм", "translit": "позитивИзм"}, {"he": "קואליציוני", "ru": "коалиционный", "translit": "коалициОни"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (312, 6, 'הזיכרון והנשייה — שיח זיכרון בישראל', 'Память и забвение — дискурс памяти в Израиле', 'התרבות הישראלית חדורה בפולחן הזיכרון. ימי זיכרון רשמיים, אנדרטאות במרחב הציבורי, מוזיאונים, עדויות מוסרטות, קריאת שמות ומצעדים — כל אלה מהווים רשת צפופה של הנצחה שקשה למצוא כמותה בדמוקרטיות אחרות. לוח השנה הישראלי רצוף ימי זיכרון: יום השואה, יום הזיכרון לחללי צה"ל, יום ירושלים, יום הנכבה (שמציינים הערבים), ימי זיכרון לטבח קפר קאסם, לרצח רבין.
ההיסטוריון יוסי זרטל בחן כיצד טקסי זיכרון לחללי מלחמות ישראל יוצרים נרטיב לאומי שמעצב את ההווה ומשמש כלי לגיטימציה פוליטית. המוות בקרב מקבל משמעות קדושה — ''קדושי צה"ל'' — והזיכרון הופך למחויבות לאומית. מנגד, הפילוסופית אדית זרטל (ללא קשר משפחתי) טענה בספרה ''אומה והמוות'' שישראל משתמשת בזיכרון השואה כמכשיר פוליטי המצדיק מדיניות ביטחון ומנטרל ביקורת: ''מי שמבקר את ישראל — מזלזל בזיכרון השואה''.
המתח בין ''לזכור'' ל''להמשיך הלאה'' מתבטא גם ברמה האישית. ילדי הניצולים (''דור שני'') גדלו בצל הטראומה: הורים שלא דיברו, או שדיברו יותר מדי, על מה שעברו. הפסיכולוגית דינה ורדי חקרה כיצד הטראומה עוברת מדור לדור — לא רק דרך סיפורים, אלא דרך דפוסי התנהגות, חרדות ויחסים. ''דור שלישי'' — נכדי הניצולים — מתמודדים עם שאלות אחרות: מה המשמעות של זיכרון שלא חוויתי? האם אני ''רשאי'' לסבול מטראומה שלא הייתה שלי?
הספרות הישראלית משקפת את הדילמה. מאיר שלו, ב''רומן רוסי'', ועמוס עוז, ב''סיפור על אהבה וחושך'', תיארו כיצד זיכרונות משפחתיים חודרים לכל שכבה של הזהות, כמו מים שחודרים לסלע — לאט, אך בלתי נמנע. ספרות ''הדור השני'' — דוד גרוסמן (''עיין ערך: אהבה''), סביון ליברכט, נאוה סמל — בונה עולמות ספרותיים שבהם העבר אינו עובר לעולם.
השאלה המרכזית נותרת פתוחה: האם אפשר לבנות עתיד בריא על יסודות של זיכרון טראומטי? או שמא הזיכרון הוא לא רק מחויבות מוסרית, אלא גם נטל שמונע התקדמות? ואולי, כפי שטוען הפילוסוף אבישי מרגלית ב''אתיקה של הזיכרון'', הזיכרון עצמו הוא ערך מוסרי — ולשכוח הוא לבגוד.', 'Израильская культура пронизана культом памяти: официальные дни памяти, мемориалы, музеи, свидетельства, зачитывание имён. Израильский календарь насыщен днями памяти: Холокоста, павших ЦАХАЛа, Иерусалима, Накбы.
Историк Йоси Зертал исследовал, как церемонии памяти создают национальный нарратив. Философ Идит Зертал утверждала, что Израиль использует память о Холокосте как политический инструмент.
Напряжение проявляется и на личном уровне: «второе поколение» выросло в тени травмы, «третье» задаёт вопросы: что значит память о том, чего я не пережил? Литература отражает дилемму: Шалев, Оз, Гроссман, Либрехт описали, как семейные воспоминания проникают в каждый слой идентичности.
Можно ли построить здоровое будущее на фундаменте травматической памяти? Философ Авишай Маргалит утверждает в «Этике памяти»: сама память — моральная ценность, а забвение — предательство.', '[{"he": "פולחן", "ru": "культ/ритуал", "translit": "пулхАн"}, {"he": "הנצחה", "ru": "увековечивание", "translit": "ханцахА"}, {"he": "טראומה בין-דורית", "ru": "межпоколенческая травма", "translit": "трАума бЕйн-дорИт"}, {"he": "נרטיב לאומי", "ru": "национальный нарратив", "translit": "наратИв леумИ"}, {"he": "מכשיר פוליטי", "ru": "политический инструмент", "translit": "махшИр полИти"}, {"he": "נשייה", "ru": "забвение", "translit": "нашиЯ"}, {"he": "אנדרטה", "ru": "мемориал", "translit": "андартА"}, {"he": "דור שני", "ru": "второе поколение", "translit": "дОр шенИ"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (313, 6, 'דת ומדינה — הסדר שלא הושלם', 'Религия и государство — незавершённое устройство', 'היחסים בין דת למדינה בישראל מעוצבים על ידי מה שכונה ''הסטטוס קוו'' — הסדר בלתי כתוב שנקבע ב-1947 במכתבו של בן-גוריון לאגודת ישראל, עוד לפני הקמת המדינה. ההסדר נועד להבטיח את תמיכת הציבור הדתי בהקמת מדינה יהודית, וכלל ארבעה עקרונות: שבת כיום מנוחה רשמי, כשרות במוסדות מדינה, אוטונומיה לחינוך דתי, ושליטת הרבנות בענייני נישואין.
מאז, ההסדר גם נשחק וגם התבצר — בו-זמנית. מצד אחד, חילוניות זוחלת: מסחר בשבת גובר בערים רבות, יותר ישראלים מגדירים עצמם כ''חילונים'' (כ-45% בסקרים), ותחבורה ציבורית בשבת — שהייתה טאבו — מתחילה לפעול בחלק מהערים. מצד שני, המפלגות החרדיות — ש"ס ויהדות התורה — ממנפות את כוחן הקואליציוני כדי להרחיב את השפעתן: תקציבים לישיבות, פטור מגיוס, השפעה על ענייני כשרות ונישואין.
בג"ץ (בית המשפט הגבוה לצדק) נכנס לתמונה בהכרעות שנויות במחלוקת: הכרה בגיור רפורמי וקונסרבטיבי, חיוב תחבורה ציבורית בשבת בערים מסוימות, פסילת הדרת נשים במרחב הציבורי. כל פסיקה כזו מעוררת סערה — הדתיים רואים בה התערבות בענייני דת, החילוניים — מימוש של חופש הדת (שכולל חופש מדת).
זיו שטרנהל, ההיסטוריון של הימין הצרפתי שהפך לאנליסט של הפוליטיקה הישראלית, טען שישראל לעולם לא תכריע בסוגיה הזו: ההכרעה עצמה מאיימת לפורר את הלכידות הלאומית. אם ישראל תהפוך למדינה חילונית לגמרי — הדתיים ירגישו מנוכרים. אם תהפוך לתיאוקרטיה — החילונים יעזבו. ה''סטטוס קוו'' הוא פשרה עלובה שאף צד לא מרוצה ממנה — אך כל אלטרנטיבה נראית גרועה יותר.
הפרדוקס העמוק ביותר: ישראל היא מדינה שאין בה חוקה — בין היתר בשל חוסר ההסכמה על מקום הדת. כל ניסיון לכתוב חוקה ייתקל בשאלה: מה עדיף, חוקי תורה או חוקי מדינה? ובלי תשובה לשאלה הזו, אין חוקה.', 'Отношения религии и государства в Израиле формируются «статус-кво» — неписаным соглашением 1947 года в письме Бен-Гуриона к Агудат Исраэль. Соглашение включало: шаббат как день отдыха, кашрут в госучреждениях, автономию религиозного образования, контроль раввината над браками.
С тех пор соглашение и размывается, и укрепляется одновременно. С одной стороны, ползучая секуляризация. С другой, ультраортодоксальные партии используют коалиционный ресурс для расширения влияния.
БАГАЦ вмешивается: признание реформистского гиюра, общественный транспорт по субботам. Штернхель утверждал, что Израиль никогда не решит этот вопрос: решение угрожает разрушить единство.
Глубочайший парадокс: у Израиля нет конституции — в том числе из-за отсутствия согласия о месте религии. Любая попытка написать конституцию упрётся в вопрос: что важнее — законы Торы или законы государства?', '[{"he": "סטטוס קוו", "ru": "статус-кво", "translit": "стАтус квО"}, {"he": "כשרות", "ru": "кашрут", "translit": "кашрУт"}, {"he": "חילוניות", "ru": "светскость", "translit": "хилониЮт"}, {"he": "קואליציוני", "ru": "коалиционный", "translit": "коалициОни"}, {"he": "גיור", "ru": "гиюр (обращение в иудаизм)", "translit": "гиЮр"}, {"he": "לכידות", "ru": "сплочённость", "translit": "лехидУт"}, {"he": "תיאוקרטיה", "ru": "теократия", "translit": "теокрАтия"}, {"he": "פשרה", "ru": "компромисс", "translit": "пшарА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (314, 6, 'פרשנות המקרא — מן הפשט אל הדרש', 'Библейская герменевтика — от буквального к аллегорическому', 'מסורת הפרשנות היהודית מבחינה בארבע רמות של קריאת טקסט, הידועות בראשי התיבות פרד"ס: פשט (המשמעות המילולית), רמז (הרמיזה או הסמליות), דרש (הפרשנות ההלכתית או האגדית) וסוד (המשמעות המיסטית-קבלית). ארבע הרמות אינן סותרות — הן מתקיימות בו-זמנית, כמו שכבות של פירוש שכל אחת מהן חושפת ממד אחר של הטקסט.
רש"י (רבי שלמה יצחקי, 1040-1105), מגדולי הפרשנים, נטה לפשט אך שילב מדרשים כשראה שהם מבהירים את הטקסט. סגנונו תמציתי — כל מילה נשקלה — ופירושו הפך לטקסט שנלמד יחד עם התורה עצמה. רש"י חי בטרואה שבצרפת, וחלק מפירושיו מכילים מילים בצרפתית עתיקה — ''לעז'' — שמהוות מקור חשוב לבלשנות הצרפתית.
אברהם אבן-עזרא (1089-1167), משורר ומתמטיקאי ספרדי, דגל בגישה רציונלית ורמז — בזהירות, כדי לא לעורר התנגדות — שחלקים מהתורה נכתבו מאוחר ולא על ידי משה. ב''סוד השנים-עשר'' הוא רומז שפסוקי הסיום של דברים (המתארים את מות משה) לא יכלו להיכתב על ידי משה עצמו — רמז שזיכה אותו בביקורת חריפה אך גם הפך אותו למבשר הביקורת המקראית המודרנית.
רמב"ן (רבי משה בן נחמן, 1194-1270), מגדולי חכמי ספרד, שילב פשט עם מיסטיקה. הוא חלק על רש"י ועל אבן-עזרא בצורה מכבדת אך חדה, ופירושו מכיל רמזים קבליים שרק יודעי סוד יכולים לפענח.
הביקורת המקראית המודרנית, שהחלה עם ברוך שפינוזה ב''מאמר תיאולוגי-פוליטי'' (1670), בחנה את הטקסט בכלים היסטוריים ובלשניים. שפינוזה טען שהתורה אינה דבר אלוהים המילולי, אלא טקסט שנכתב ונערך על ידי בני אדם. תיאוריית המקורות של יוליוס ולהאוזן (1878) זיהתה ארבעה מקורות בתורה — J (יהוויסט), E (אלוהיסט), D (דברים) ו-P (כוהני) — שנשזרו יחד על ידי עורך מאוחר.
כיום, חוקרים משלבים שיטות מסורתיות ומודרניות — מה שיוצר שדה פרשני עשיר ורב-קולי. החוקר ישראלי ירון זקוביץ, למשל, מנתח סיפורי מקרא בכלים ספרותיים מודרניים תוך כבוד למסורת הפרשנית. התוצאה היא שהמקרא נקרא היום ביותר דרכים מאי-פעם — והוא חי יותר מתמיד.', 'Еврейская экзегетическая традиция различает четыре уровня прочтения: ПАРДЕС — Пшат (буквальное), Ремез (намёк), Драш (интерпретация), Сод (мистическое). Они не противоречат, а сосуществуют как слои.
Раши (1040-1105) склонялся к пшату, но включал мидраши. Ибн-Эзра (1089-1167) придерживался рационализма и намекал, что части Торы написаны позднее — предтеча современной библейской критики. Рамбан (1194-1270) сочетал пшат с каббалистической мистикой.
Современная библейская критика началась со Спинозы (1670): Тора — текст, написанный людьми. Документарная гипотеза Велльгаузена выделила четыре источника. Сегодня учёные совмещают традиционные и современные методы, создавая богатое полифоническое поле интерпретации. Библия читается сегодня больше способами, чем когда-либо.', '[{"he": "פרשנות", "ru": "герменевтика/толкование", "translit": "паршанУт"}, {"he": "פשט", "ru": "пшат (буквальный смысл)", "translit": "пшАт"}, {"he": "דרש", "ru": "драш (интерпретация)", "translit": "дрАш"}, {"he": "מדרש", "ru": "мидраш", "translit": "мидрАш"}, {"he": "ביקורת המקרא", "ru": "библейская критика", "translit": "бикОрет хамикрА"}, {"he": "רב-קולי", "ru": "полифонический", "translit": "рав-колИ"}, {"he": "קודיפיקציה", "ru": "кодификация", "translit": "кодификАция"}, {"he": "לעז", "ru": "иноязычное слово", "translit": "лаАз"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (315, 6, 'וולטר בנימין — השפה כמדיום', 'Вальтер Беньямин — язык как медиум', 'וולטר בנימין (1892-1940), הוגה יהודי-גרמני שמת בבריחה מהנאצים על גבול ספרד, פיתח תפיסה ייחודית של השפה שמשלבת תיאולוגיה יהודית, מרקסיזם ואסתטיקה מודרנית — שילוב שנראה בלתי-אפשרי, אך ביצירתו של בנימין הוא הופך לאחדות מרתקת.
במסה ''על השפה בכלל ועל שפת האדם בפרט'' (1916), שנכתבה כשבנימין היה בן 24, הוא הציג תפיסה שמאתגרת את ההבנה המקובלת של שפה. לפי התפיסה המקובלת (שסוסיר כינה ''שרירותיות הסימן''), הקשר בין מילה לדבר שהיא מציינת הוא מוסכמה חברתית — אין סיבה שהצליל ''כלב'' יציין כלב, ובצרפתית באמת אומרים ''שיאן''. בנימין דחה זאת: הוא טען שהשפה אינה רק כלי לתקשורת, אלא מדיום שבו מתגלה עצם מהות הדברים.
הרעיון הזה שואב ישירות מהמסורת היהודית: בבראשית, אדם הראשון נותן שמות לבעלי החיים — ולפי הפירוש הקבלי, השמות אינם שרירותיים אלא חושפים את מהותם הפנימית. בנימין טען שכל שפה אנושית שומרת בתוכה שריד של ''שפת האדם'' הקדומה — היכולת לקרוא בשם, לחשוף מהות.
בנימין הרחיב את תורת השפה לתחום התרגום. ב''משימת המתרגם'' (1923), הקדמה לתרגום שלו של סונטות של בודלר, הוא טען שתרגום אינו העתקה מדויקת — הוא חשיפה של ''השפה הטהורה'' הנסתרת בין כל השפות. כל שפה אומרת את אותו דבר באופן שונה, והתרגום חושף את ''הדבר'' שמעבר לכל השפות — כמו שברי כלי שכל אחד מהם שונה, אך יחד הם מרכיבים את השלם.
רעיונותיו של בנימין על השפה השפיעו עמוקות על ז''אק דרידה, שפיתח את ה''דקונסטרוקציה'' — שיטה שמראה כיצד כל טקסט מכיל סתירות פנימיות שחותרות תחת המשמעות ה''רשמית''. פול דה-מאן, חוקר ספרות בייל, המשיך את בנימין בכיוון של ''אלגוריה'' — קריאה שמראה שהטקסט תמיד אומר יותר (ואחרת) ממה שהוא נראה שאומר. כל תיאוריית הספרות של המחצית השנייה של המאה ה-20 עומדת, כך או אחרת, בצלו של בנימין.', 'Вальтер Беньямин (1892-1940), еврейско-немецкий мыслитель, погибший при бегстве от нацистов, развил уникальную концепцию языка, сочетающую еврейскую теологию, марксизм и модернистскую эстетику.
В эссе «О языке вообще и о языке человека» (1916) он утверждал: язык — не просто инструмент коммуникации, а медиум, в котором обнаруживается сущность вещей. Идея черпает из еврейской традиции: Адам даёт имена животным, раскрывая их внутреннюю суть.
В «Задаче переводчика» (1923) Беньямин утверждал: перевод — не копирование, а обнаружение «чистого языка», скрытого между всеми языками. Каждый язык говорит одно и то же по-разному, а перевод обнаруживает то, что за ними.
Идеи Беньямина повлияли на Деррида (деконструкция), де Мана (аллегория) и всю литературную теорию второй половины XX века.', '[{"he": "מדיום", "ru": "медиум", "translit": "мЕдиум"}, {"he": "מהות", "ru": "сущность", "translit": "махУт"}, {"he": "שרירותי", "ru": "произвольный", "translit": "шрирутИ"}, {"he": "תרגום", "ru": "перевод", "translit": "таргУм"}, {"he": "מסה", "ru": "эссе", "translit": "масА"}, {"he": "אסתטיקה", "ru": "эстетика", "translit": "эстЕтика"}, {"he": "דקונסטרוקציה", "ru": "деконструкция", "translit": "деконструкцийА"}, {"he": "אלגוריה", "ru": "аллегория", "translit": "алегорийА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (316, 6, 'הקיבוץ — ניסוי אוטופי ומשברו', 'Кибуц — утопический эксперимент и его кризис', 'תנועת הקיבוץ היא אחד הניסויים החברתיים המרתקים ביותר במאה העשרים — ניסיון לממש אוטופיה חברתית בקנה מידה של מאות קהילות, על פני עשרות שנים. הקיבוצים הראשונים — דגניה (1910), כנרת, עין חרוד — הוקמו על ידי צעירים אידיאליסטים מאירופה המזרחית ששאפו ליצור ''אדם חדש'' וחברה חדשה, חופשיה מנגעי הקפיטליזם.
העקרונות היו מהפכניים: קניין משותף — אין בעלות פרטית על כלום, מעבודת האדמה ועד מברשת השיניים. חינוך קולקטיבי — ילדים גדלים ב''בית הילדים'', ישנים יחד ולא עם הוריהם, כדי לשחרר את האם לעבודה ולמנוע יחסי תלות משפחתיים. עבודה עצמית — ללא עובדים שכירים, כדי למנוע ניצול. קבלת החלטות דמוקרטית באסיפה הכללית — כל חבר שווה. מכל אדם לפי יכולתו, לכל אדם לפי צרכיו.
ברטרנד ראסל, הפילוסוף הבריטי, ביקר בקיבוץ וכינה אותו ''הניסוי המוצלח ביותר בחיים שיתופיים שהאנושות ידעה''. מרטין בובר, שהעריך את הקיבוץ אך גם ביקר אותו, ראה גם את הסכנות: היעלמות הפרט בתוך הקבוצה, לחץ חברתי מחניק, ו''דיקטטורה של הרוב'' שלא מותירה מקום לשונות.
בשנות השמונים-תשעים חל משבר כפול: כלכלי ורעיוני. כלכלית, קיבוצים רבים צברו חובות אדירים בעקבות השקעות כושלות ואינפלציה גבוהה. רעיונית, הדורות הצעירים כבר לא האמינו בשיתופיות מלאה — הם רצו פרטיות, שכר דיפרנציאלי, חופש לבחור את מקצועם. ב''שינוי'' (המונח העדין ל''הפרטה''), קיבוצים רבים עברו למודל ''קיבוץ מתחדש'': דירות הפכו לרכוש פרטי, חברים מקבלים שכר על פי תרומתם, ומהקומוניזם נותרה בעיקר הקהילתיות.
כיום, רק מעט קיבוצים נותרו ''שיתופיים'' באמת — כ-60 מתוך 270. השאר עברו ''שינוי''. הסוציולוגית שלהבת בראל-לחמן בחנה כיצד דור הנכדים מתמודד עם מורשת שהם מוקירים אך אינם מוכנים לחיות בה. הם גאים ב''סבא שהקים קיבוץ'', אך גרים בתל אביב ועובדים בהייטק. הניסוי הקיבוצי לא נכשל — הוא שינה צורה. השאלה היא מה נשאר מהחלום כשהחלום מתפשר עם המציאות.', 'Движение кибуцев — один из самых захватывающих социальных экспериментов XX века: попытка реализовать утопию в масштабе сотен общин. Первые кибуцы основали молодые идеалисты, стремившиеся создать «нового человека».
Принципы: общая собственность, коллективное воспитание, самостоятельный труд, демократическое принятие решений. Рассел назвал кибуц «самым успешным экспериментом коллективной жизни». Бубер видел и опасности: исчезновение личности в группе.
В восьмидесятые-девяностые — двойной кризис: экономический (долги) и идейный (молодёжь хотела приватности и дифференцированной оплаты). Многие кибуцы перешли к модели «обновлённого кибуца»: частное жильё, зарплата по вкладу.
Сегодня лишь ~60 из 270 кибуцев остаются коллективными. Эксперимент не провалился — он изменил форму. Вопрос: что остаётся от мечты, когда мечта идёт на компромисс с реальностью.', '[{"he": "אוטופיה", "ru": "утопия", "translit": "утОпия"}, {"he": "שיתופי", "ru": "коллективный", "translit": "шитуфИ"}, {"he": "אסיפה כללית", "ru": "общее собрание", "translit": "асифА клалИт"}, {"he": "הופרטו", "ru": "были приватизированы", "translit": "хуфрЕту"}, {"he": "דיפרנציאלי", "ru": "дифференцированный", "translit": "диференциАли"}, {"he": "מורשת", "ru": "наследие", "translit": "морЕшет"}, {"he": "קהילתיות", "ru": "коммунальность", "translit": "кехилатиЮт"}, {"he": "קומוניזם", "ru": "коммунизм", "translit": "комунИзм"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (317, 6, 'עגנון — סיפורת בין אמונה לאירוניה', 'Агнон — проза между верой и иронией', 'שמואל יוסף עגנון (1887-1970), חתן פרס נובל לספרות (1966, יחד עם נלי זקס), יצר עולם ספרותי שאין לו אח ורע בעברית. עגנון נולד בבוצ''אץ'' שבגליציה (היום אוקראינה), עלה לארץ ישראל ב-1908, חזר לגרמניה ב-1912, ושב סופית ב-1924. חייו עצמם — בין אירופה לארץ ישראל, בין גלות לגאולה, בין עולם ישן לעולם חדש — משקפים את הנושאים המרכזיים ביצירתו.
בסיפוריו משתלבות שכבות לשוניות ותרבותיות: השפה התלמודית-מדרשית — עגנון כותב עברית שנשמעת כמו טקסט קדום, עם תחביר ואוצר מילים שמזכירים את ספרי המוסר והאגדה — עולם הגלות האירופי עם שטטלאות, רבנים, שידוכים ובתי כנסת, ומציאות ארץ ישראל עם חלוצים, מלריה ובניית בית.
''הכנסת כלה'' (1931) מתאר את הזעזועים של קהילת בוצ''אץ'' — עולם שהולך ומתפורר, אך עדיין שומר על שלד של סדר וקדושה. ''תמול שלשום'' (1945), שנחשב ליצירתו הגדולה, עוקב אחר יצחק קומר, עולה מגליציה לארץ ישראל, המתלבט בין חילוניות לדתיות, בין יפו לירושלים — ובסופו של דבר, כלב שנכתב על גבו ''כלב משוגע'' (במעשה שנראה שולי אך מתברר כמרכזי) נושך אותו והוא מת. הסיום האבסורדי-טרגי הוא סימן ההיכר של עגנון.
הטכניקה הנרטיבית של עגנון מורכבת ומטעה. המספר נשמע תמים, מאמין, פשוט — כמו יהודי ירא שמיים שמספר סיפור ליד השולחן. אך מתחת לפני השטח שורה אירוניה חותכת: הסיפורים ''התמימים'' מלאים סתירות, רמזים ומשמעויות כפולות. גרשון שקד, מגדולי חוקרי עגנון, זיהה ''דובר אמין בלתי אמין'' — הקורא חייב לפענח מה באמת מתרחש מאחורי הפאסדה של תמימות. זו אינה אירוניה זדונית — זו אירוניה של מי שאוהב את עולמו אך רואה אותו בעיניים פקוחות.
ביקורת פמיניסטית, כגון עבודותיה של אן פוקס ושל ענת פלדמן, חשפה את ייצוג הנשים הבעייתי ביצירתו: נשים הן לרוב חפצי חשק או סמלי פחד, ולעיתים רחוקות דמויות מורכבות כשלעצמן. עגנון נותר אתגר לכל קורא — ומעניק גילויים חדשים בכל קריאה חוזרת.', 'Шмуэль Йосеф Агнон (1887-1970), нобелевский лауреат (1966), создал уникальный литературный мир на иврите. Родился в Бучаче (Галиция), его жизнь между Европой и Палестиной отражает центральные темы творчества: диаспора и возвращение, старое и новое.
В его прозе переплетаются слои: талмудически-мидрашистский язык, мир европейской диаспоры и реальность Палестины. «Вчера-позавчера» — главное произведение: репатриант из Галиции разрывается между светскостью и религиозностью, и абсурдно-трагический финал — визитная карточка Агнона.
Нарративная техника сложна и обманчива: рассказчик звучит простодушно, но под поверхностью — режущая ирония. Шакед определил «ненадёжного простодушного рассказчика». Феминистская критика обнажила проблемное изображение женщин. Агнон остаётся вызовом для каждого читателя.', '[{"he": "סיפורת", "ru": "проза/нарратив", "translit": "сифорЕт"}, {"he": "אירוניה", "ru": "ирония", "translit": "иронИя"}, {"he": "נרטיבי", "ru": "нарративный", "translit": "наратИви"}, {"he": "תמים", "ru": "простодушный", "translit": "тамИм"}, {"he": "לפענח", "ru": "расшифровать", "translit": "лефаанЕах"}, {"he": "פאסדה", "ru": "фасад", "translit": "фасАда"}, {"he": "שטטלה", "ru": "штетл", "translit": "штетЛ"}, {"he": "אגדה", "ru": "агада (сказание)", "translit": "агадА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (318, 6, 'דיני המלחמה — "טוהר הנשק" בדין הישראלי', 'Законы войны — «чистота оружия» в израильском праве', 'ישראל מתמודדת עם מתח מובנה בין ביטחון למוסר — מתח שמתבטא בדוקטרינת ''טוהר הנשק'', עיקרון הקובע שצה"ל לא ישתמש בכוח מעבר לנדרש ויגן על אוכלוסייה אזרחית גם במהלך לחימה. הדוקטרינה אינה רק סיסמא — היא מעוגנת בפקודות צבאיות, בחקיקה ובפסיקת בית המשפט.
הבסיס המשפטי כפול. ראשית, דיני המלחמה הבינלאומיים: אמנות ג''נבה (1949) והפרוטוקולים הנוספים (1977) קובעים עקרונות של הבחנה (בין לוחמים לאזרחים), מידתיות (כוח שאינו חורג מהנדרש) ומניעת סבל מיותר. שנית, עקרונות ייחודיים מהמשפט העברי: הרמב"ם כתב שלפני מלחמה יש להציע שלום, ושאין להרוס עצי פרי — עקרון ''בל תשחית''.
בפרקטיקה, המתח חד. בפרשת הריגת מחבל מנוטרל (חברון, 2016), חייל ירה בפלסטיני שכבר היה חסר הכרה ושוכב על הארץ — מעשה שצולם ופורסם. בית המשפט הצבאי פסק שהירי מהווים הפרה של כללי הפתיחה באש ושל עקרון ''טוהר הנשק''. החייל הורשע — אך חלק גדול מהציבור ראה בו ''גיבור'' והתנגד לעונש.
הדיון על פגיעה באזרחים בעזה — במבצע ''צוק איתן'' (2014) ובמבצעים אחרים — עורר ביקורת בינלאומית קשה ובדיקות של ועדות האו"ם. ישראל טענה שחמאס משתמש באזרחים כ''מגנים אנושיים'', מה שמטשטש את ההבחנה בין לוחמים לאזרחים. המבקרים טענו שתגובת ישראל לא הייתה מידתית.
פרופ'' אסא כשר, מאוניברסיטת תל אביב, וגנרל עמוס ידלין, ראש אמ"ן לשעבר, פיתחו ''קוד אתי ללחימה'' שמנסה לאזן בין שני ערכים: הגנה על חיי חיילי צה"ל (שהמדינה חייבת להגן עליהם) לבין מזעור פגיעה באזרחים (שהמוסר מחייב). הקוד עורר ביקורת מכל הצדדים: צבאיים טענו שהוא מסכן חיילים, ואנשי מוסר טענו שהוא מתיר יותר מדי. המחלוקת האקדמית והציבורית על הנושא משקפת את הדילמות העמוקות ביותר של חברה החיה בסכסוך מתמשך.', 'Израиль сталкивается со структурным напряжением между безопасностью и моралью, выражающимся в доктрине «чистоты оружия»: ЦАХАЛ не применяет силу сверх необходимого и защищает гражданских.
Правовая база двойная: международное гуманитарное право (Женевские конвенции) и еврейское право (Рамбам: перед войной предложить мир, не уничтожать фруктовые деревья). На практике напряжение острое.
Дискуссия о потерях среди мирного населения в Газе вызвала международную критику. Израиль утверждает, что ХАМАС использует «живые щиты». Критики — что ответ непропорционален.
Проф. Кашер и генерал Ядлин разработали этический кодекс, пытающийся уравновесить защиту солдат и минимизацию вреда гражданским. Спор отражает глубочайшие дилеммы общества в затяжном конфликте.', '[{"he": "טוהר הנשק", "ru": "чистота оружия", "translit": "тОхар ханЕшек"}, {"he": "דיני מלחמה", "ru": "законы войны", "translit": "динЕй милхамА"}, {"he": "אמנות ג''נבה", "ru": "Женевские конвенции", "translit": "аманОт женЕва"}, {"he": "מנוטרל", "ru": "нейтрализованный", "translit": "менутрАл"}, {"he": "מזעור", "ru": "минимизация", "translit": "мизъУр"}, {"he": "דוקטרינה", "ru": "доктрина", "translit": "доктрИна"}, {"he": "מגנים אנושיים", "ru": "живые щиты", "translit": "маганИм эношиИм"}, {"he": "הבחנה", "ru": "различение", "translit": "хавханА"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (319, 6, 'פרנץ רוזנצווייג — "הכוכב של הגאולה"', 'Франц Розенцвейг — «Звезда избавления»', 'פרנץ רוזנצווייג (1886-1929) כתב את ''כוכב הגאולה'' בגלויות ובפתקים שנשלחו מהחזית בזמן מלחמת העולם הראשונה — עובדה שמעניקה לטקסט עוצמה קיומית מיוחדת. הספר, שנכתב תחת צל המוות, מציע מערכת פילוסופית שלמה שמתחרה בהגל ובהיידגר בשאפתנותה.
רוזנצווייג מציע שהמציאות מורכבת משלושה יסודות שאינם ניתנים לצמצום לאחד: אלוהים, עולם ואדם. הפילוסופיה המערבית מדקארט ועד הגל ניסתה להחזיר את הכל למערכת אחת — ל''אני'' (דקארט), ל''רוח'' (הגל). רוזנצווייג דחה את ה''טוטליות'' הזו: כל אחד משלושת היסודות קיים בפני עצמו, ורק ביחסים ביניהם — בריאה (יחס אלוהים-עולם), התגלות (יחס אלוהים-אדם) וגאולה (יחס אדם-עולם) — נוצרת משמעות.
הפגישה בין אדם לאלוהים אינה מופשטת אלא מתרחשת בחוויה הדתית הקונקרטית — בתפילה, בצום, בחג, בשירה. רוזנצווייג מתאר את לוח השנה היהודי כ''ביטוי ממשי של הזמן המקודש'': כל שבת היא מעין גאולה קטנה, כל חג מחבר את ההווה לנצח. היהדות, לפי רוזנצווייג, חיה ''מחוץ להיסטוריה'' — היא אינה תלויה בתהליכים היסטוריים כי היא כבר ''הגיעה אל האמת'' דרך הטקסים והלוח.
רוזנצווייג ייסד את ''בית המדרש החופשי'' (Freies Jüdisches Lehrhaus) בפרנקפורט ב-1920, יחד עם מרטין בובר. שם לימדו השניים — ורבים אחרים, כולל ארנסט סימון וגרשם שלום — באופן שונה מהאקדמיה: דרך דיאלוג, ללא מבחנים, ועם פתיחות לחילונים שרצו ללמוד יהדות. המודל השפיע על בתי מדרש חופשיים שנוסדו מאוחר יותר בישראל ובארצות הברית.
ב-1922, בגיל 36, חלה רוזנצווייג ב-ALS (טרשת צדית אמיוטרופית). תוך שנים ספורות איבד את היכולת לדבר ולנוע. אך הוא המשיך לכתוב — תחילה ביד רועדת, ואחר כך באמצעות מערכת שבה אשתו אדית הצביעה על אותיות והוא מרמז בתנועת עיניים. הוא תרגם, יחד עם בובר, את התנ"ך לגרמנית — פרויקט שרבים רואים כתרגום הגדול ביותר של המקרא לגרמנית. הוא מת ב-1929, בן 43, אך מורשתו — ובמיוחד ההתעקשות על כך ש''החיים גדולים מהפילוסופיה'' — ממשיכה להשפיע.', 'Франц Розенцвейг (1886-1929) написал «Звезду избавления» на открытках с фронта Первой мировой — текст, написанный в тени смерти.
Он предлагает, что реальность состоит из трёх несводимых элементов: Бог, мир, человек. Связь между ними — творение, откровение и избавление — создаёт смысл. Встреча с Богом происходит в конкретном религиозном опыте: молитве, посте, празднике.
Розенцвейг основал «Свободный дом учения» во Франкфурте вместе с Бубером — модель, повлиявшую на образовательные институции. В 1922 заболел ALS, но продолжал писать с помощью движений глаз. Перевёл Библию на немецкий вместе с Бубером.
Умер в 43 года, но его наследие — и особенно настойчивость, что «жизнь больше философии» — продолжает влиять.', '[{"he": "גאולה", "ru": "избавление", "translit": "геулА"}, {"he": "התגלות", "ru": "откровение", "translit": "хитгалУт"}, {"he": "הגליאני", "ru": "гегелевский", "translit": "хегелиАни"}, {"he": "צמצום", "ru": "редукция/сведение", "translit": "цимцУм"}, {"he": "קיומי", "ru": "экзистенциальный", "translit": "киюмИ"}, {"he": "בית מדרש", "ru": "дом учения", "translit": "бЕйт мидрАш"}, {"he": "טוטליות", "ru": "тотальность", "translit": "тоталиЮт"}, {"he": "קונקרטי", "ru": "конкретный", "translit": "конкрЕти"}]', NULL, 'article');
INSERT INTO public.reading_texts (id, level_id, title_he, title_ru, content_he, content_ru, vocabulary_json, audio_url, category) VALUES (320, 6, 'השירה העברית הצעירה — קולות חדשים', 'Молодая ивритская поэзия — новые голоса', 'בעשורים הראשונים של המאה ה-21 צמח דור חדש של משוררים עבריים שמאתגר את המסורת, שובר קונבנציות ומביא קולות שלא נשמעו קודם. השירה העברית, שנשלטה במשך עשרות שנים על ידי קולות אשכנזיים-חילוניים-גבריים, נפתחת לקולות מזרחיים, פמיניסטיים, ערביים, אתיופיים וקווירים.
אגי משעול, מגדולות המשוררות העבריות בנות דורנו, כותבת שירה שמשלבת ערבית ועברית, חושפת את המרחב הדו-לשוני של יהודי ארצות ערב. שירתה מאירה עולם שנמחק כמעט — הזיכרון הלשוני של יהודים שדיברו ערבית, שרו בערבית, ושעברו למציאות עברית שבה השפה הראשונה שלהם הפכה ל''שפת האויב''.
אלמוג בהר, ממוצא עיראקי, כותב על הזהות המזרחית בשפה שמפרקת את ההיררכיה האשכנזית-מזרחית. בשירו ''אנא מין אל-יהוד'' (''אני מהיהודים'' בערבית) הוא חושף את הפרדוקס של יהודי ערבי: ישראלי שהמולדת של אבותיו היא ''מדינת אויב'', שהשפה שלו מזוהה עם מי שנלחם בו. בהר דורש מקום בשיח הישראלי לא כ''מוזמן'' אלא כבעל בית.
רוי חסן מציגה קול פמיניסטי-מזרחי חדש — שירה שמדברת על גוף, על כעס, על מעמד, ועל הצומת בין מגדר למוצא. שירתה אינה ''יפה'' במובן הקלאסי — היא חדה, ישירה ואגרסיבית. תאל בן צבי פירש כותבת שירה שחוצה גבולות בין ישראל לפלסטין, בין עברית לערבית, בין ''שלנו'' ל''שלהם''. מרסלו סנדמן, ממוצא ארגנטינאי, מביא את הפריפריה הגיאוגרפית לספרות — שירים על באר שבע, על נגב, על מקומות שהמרכז מתעלם מהם.
השירה החדשה אינה ביישנית: היא עוסקת בגזענות, בעוני, בכיבוש ובגוף ללא עטיפות ספרותיות מנומסות. היא לא מבקשת רשות לדבר — היא דורשת. הביקורת הספרותית שואלת: האם מדובר בשירה ''פוליטית מדי'' שמקריבה את האמנות על מזבח המסר? או שאולי כל שירה גדולה היא פוליטית מעצם טיבה — משהו שידעו הומרוס, דנטה וביאליק?
ברור שהשירה העברית הצעירה כבר לא מסתפקת בנוף ובנוסטלגיה — היא דורשת מקום על הבמה וזכות לדבר בקול מלא. ''אם השירה שלך לא מפריעה לאף אחד'', כתבה רוי חסן, ''למה בכלל לכתוב?'' — שאלה שמגדירה את הרוח של הדור החדש.', 'В первые десятилетия XXI века выросло поколение ивритских поэтов, бросающих вызов традиции и привносящих неслышанные голоса. Ивритская поэзия, десятилетиями управлявшаяся ашкеназскими, светскими, мужскими голосами, открывается мизрахийским, феминистским, арабским, эфиопским и квир-голосам.
Аги Мишоль смешивает арабский и иврит, обнажая языковую память евреев арабских стран. Алмог Бехар деконструирует ашкеназско-мизрахийскую иерархию. Рой Хасан представляет новый феминистско-мизрахийский голос — острый и агрессивный.
Новая поэзия не стесняется: расизм, бедность, оккупация, тело. Критика спрашивает: это «слишком политично»? Или вся великая поэзия политична — что знали Гомер, Данте и Бялик?
«Если твоя поэзия никому не мешает, зачем вообще писать?» — вопрос, определяющий дух нового поколения.', '[{"he": "משוררים", "ru": "поэты", "translit": "мешорерИм"}, {"he": "דו-לשוני", "ru": "двуязычный", "translit": "ду-лешонИ"}, {"he": "היררכיה", "ru": "иерархия", "translit": "хиерАрхия"}, {"he": "פמיניסטי", "ru": "феминистский", "translit": "феминИсти"}, {"he": "כיבוש", "ru": "оккупация", "translit": "кибУш"}, {"he": "נוסטלגיה", "ru": "ностальгия", "translit": "ностАлгия"}, {"he": "קונבנציות", "ru": "конвенции", "translit": "конвенциЙот"}, {"he": "פריפריה", "ru": "периферия", "translit": "перифЕрия"}]', NULL, 'article');
